"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { 
    Zap, 
    ArrowLeft, 
    BarChart3, 
    Plus, 
    Minus, 
    Play, 
    Edit3, 
    Trash2, 
    X, 
    Sparkles,
    Brain,
    DraftingCompass,
    RefreshCcw
} from "lucide-react";
import ConfirmationModal from "@/components/common/ConfirmationModal";

interface Scenario {
    id: string;
    title: string;
    description: string;
    category: string;
    character_name: string;
    character_role: string;
    system_prompt: string;
    initial_message: string;
    difficulty: string;
}

interface Employee {
    id: string;
    first_name: string;
    last_name: string;
    designation: string;
}

export default function ScenarioManagement() {
    const { token, canAccess, role } = useAuth();
    const router = useRouter();
    const [scenarios, setScenarios] = useState<Scenario[]>([]);
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [loading, setLoading] = useState(true);
    const [isCreating, setIsCreating] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [submitting, setSubmitting] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const [statusFilter, setStatusFilter] = useState("all");

    const filteredScenarios = scenarios.filter(sc => 
        (statusFilter === "all" || sc.difficulty === statusFilter) &&
        (sc.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
         sc.category.toLowerCase().includes(searchQuery.toLowerCase()))
    );
    const [isAiGenerating, setIsAiGenerating] = useState(false);
    const [aiPrompt, setAiPrompt] = useState("");
    const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);
    
    // Deletion Consistency
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [scenarioToDelete, setScenarioToDelete] = useState<string | null>(null);

    // Assignment State
    const [isAssigningId, setIsAssigningId] = useState<string | null>(null);
    const [selectedEmployees, setSelectedEmployees] = useState<string[]>([]);
    const [assigning, setAssigning] = useState(false);

    const [form, setForm] = useState({
        title: "",
        description: "",
        category: "CONFLICT",
        character_name: "",
        character_role: "",
        system_prompt: "",
        initial_message: "",
        difficulty: "Intermediate"
    });

    useEffect(() => {
        if (token) {
            fetchScenarios();
            fetchEmployees();
        }
    }, [token]);

    const showToast = (msg: string, type: "success" | "error" = "success") => {
        setToast({ msg, type });
        setTimeout(() => setToast(null), 3000);
    };

    const fetchScenarios = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/scenarios`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            setScenarios(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error(error);
        } finally {
            setTimeout(() => setLoading(false), 600);
        }
    };

    const fetchEmployees = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/employees/`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            setEmployees(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error(error);
        }
    };

    const handleAiGenerate = async () => {
        if (!aiPrompt.trim()) return;
        setIsAiGenerating(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/scenarios/ai-generate`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ prompt: aiPrompt })
            });
            const data = await res.json();
            if (res.ok) {
                setForm({
                    title: data.title,
                    description: data.description,
                    category: data.category,
                    character_name: data.character_name,
                    character_role: data.character_role,
                    system_prompt: data.system_prompt,
                    initial_message: data.initial_message,
                    difficulty: data.difficulty
                });
                setAiPrompt("");
                showToast("Scenario generated.");
            }
        } catch (error) {
            console.error("AI Generation Error:", error);
            showToast("Generation failed.", "error");
        } finally {
            setIsAiGenerating(false);
        }
    };

    const handleAction = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);
        const method = editingId ? 'PUT' : 'POST';
        const url = editingId 
            ? `${BACKEND_URL}/api/v1/enterprise/simulations/scenarios/${editingId}`
            : `${BACKEND_URL}/api/v1/enterprise/simulations/scenarios`;

        try {
            const res = await fetch(url, {
                method: method,
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(form)
            });
            if (res.ok) {
                setIsCreating(false);
                setEditingId(null);
                fetchScenarios();
                showToast(editingId ? "Scenario updated." : "Scenario saved.");
            }
        } catch (error) {
            console.error(error);
            showToast("Server sync error.", "error");
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async () => {
        if (!scenarioToDelete) return;
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/scenarios/${scenarioToDelete}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                showToast("Scenario deleted.");
                fetchScenarios();
            }
        } catch (error) {
            console.error(error);
        } finally {
            setIsDeleteModalOpen(false);
            setScenarioToDelete(null);
        }
    };

    const handleAssign = async () => {
        if (selectedEmployees.length === 0 || !isAssigningId) return;
        setAssigning(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/assignments`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    scenario_id: isAssigningId,
                    employee_ids: selectedEmployees
                })
            });
            if (res.ok) {
                setIsAssigningId(null);
                setSelectedEmployees([]);
                showToast("Assignment successful.");
            }
        } catch (error) {
            console.error(error);
            showToast("Assignment failed.", "error");
        } finally {
            setAssigning(false);
        }
    };

    const toggleEmployeeSelection = (id: string) => {
        setSelectedEmployees(prev => 
            prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
        );
    };

    if (loading) {
        return (
            <div className="p-8 lg:p-12 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-500">
                <div className="h-32 bg-slate-900 rounded-2xl relative overflow-hidden flex items-center px-10 border-b-4 border-slate-800 shadow-2xl shadow-indigo-100/10">
                    <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-white/5 rounded-xl animate-pulse" />
                        <div className="space-y-2">
                            <div className="w-48 h-6 bg-white/10 rounded-xl animate-pulse" />
                            <div className="w-32 h-3 bg-white/5 rounded-xl animate-pulse" />
                        </div>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="bg-white h-64 rounded-2xl border border-slate-100 animate-pulse shadow-sm" />
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pb-20 animate-in fade-in duration-700 relative">
            {/* Toast */}
            <AnimatePresence>
                {toast && (
                    <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className={`fixed top-10 right-10 z-[500] px-6 py-4 rounded-xl shadow-2xl font-black text-[10px]  tracking-[0.2em] flex items-center gap-3 ${toast.type === "success" ? "bg-slate-900 text-white" : "bg-rose-500 text-white"}`}>
                        <span className="material-symbols-rounded text-lg text-emerald-400">{toast.type === "success" ? "verified" : "error"}</span>
                        {toast.msg}
                    </motion.div>
                )}
            </AnimatePresence>

            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <button 
                        onClick={() => router.push('/enterprise/dashboard')} 
                        className="w-9 h-9 bg-slate-50 text-slate-400 rounded-xl flex items-center justify-center hover:bg-slate-100 transition-all active:scale-95"
                    >
                        <ArrowLeft className="w-4 h-4" />
                    </button>
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">architecture</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Scenario Configuration</h1>
                        <p className="text-slate-500 text-[10px] font-medium   ">Training Scenario Design</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => router.push('/enterprise/ai-training/results')}
                        className="px-4 py-2 text-slate-500 hover:text-slate-900 transition-all font-black text-[9px]   flex items-center gap-2"
                    >
                        <BarChart3 className="w-4 h-4" />
                        Intelligence
                    </button>
                    {(canAccess("scenarios:moderate") || role === "ADMIN") && (
                        <button 
                            onClick={() => {
                                setEditingId(null);
                                setForm({
                                    title: "", description: "", category: "CONFLICT", 
                                    character_name: "", character_role: "", 
                                    system_prompt: "", initial_message: "", 
                                    difficulty: "Intermediate"
                                });
                                setIsCreating(true);
                            }}
                            className="px-6 py-2.5 bg-[#7C3AED] text-white rounded-xl hover:bg-[#6D28D9] transition-all font-black text-[9px]   flex items-center gap-2 shadow-xl shadow-indigo-100"
                        >
                            <span className="material-symbols-rounded text-base">add</span>
                            New Scenario
                        </button>
                    )}
                    <button 
                        onClick={fetchScenarios}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 hover:border-violet-100 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>
            <div className="flex flex-col md:flex-row items-center gap-4">
                <div className="flex-1 relative w-full group">
                    <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg transition-colors group-focus-within:text-[#7C3AED]">search</span>
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search scenarios by title or category..."
                        className="w-full h-12 bg-white border border-slate-100 rounded-xl pl-12 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none shadow-sm"
                    />
                </div>
                
                <div className="flex items-center gap-2 bg-white p-1.5 rounded-xl border border-slate-100 shadow-sm min-w-[200px]">
                    <span className="material-symbols-rounded text-slate-400 ml-2 text-lg">filter_list</span>
                    <select
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        className="w-full bg-transparent border-none text-[11px] font-black text-slate-700 focus:outline-none focus:ring-0 cursor-pointer uppercase tracking-wider"
                    >
                        <option value="all">All Difficulties</option>
                        <option value="Beginner">Beginner</option>
                        <option value="Intermediate">Intermediate</option>
                        <option value="Advanced">Advanced</option>
                    </select>
                </div>
            </div>

            {/* Content Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {filteredScenarios.length > 0 ? filteredScenarios.map((sc) => (
                    <motion.div 
                        layout
                        key={sc.id} 
                        className="bg-white rounded-2xl border border-slate-100 p-1.5 shadow-sm relative overflow-hidden"
                    >
                        <div className="p-8 pb-4 space-y-6">
                            <div className="flex justify-between items-start">
                                <div className="w-12 h-12 bg-[#7C3AED] text-white rounded-xl flex items-center justify-center shadow-sm">
                                    <Brain className="w-6 h-6" />
                                </div>
                                <div className="flex items-center gap-1">
                                    {(canAccess("scenarios:moderate") || role === "ADMIN") && (
                                        <button 
                                            onClick={() => {
                                                setEditingId(sc.id);
                                                setForm({...sc});
                                                setIsCreating(true);
                                            }}
                                            className="p-1.5 text-slate-400 hover:text-indigo-600 transition-colors"
                                        >
                                            <span className="material-symbols-rounded text-[20px]">edit</span>
                                        </button>
                                    )}
                                    {(canAccess("scenarios:delete") || role === "ADMIN") && (
                                        <button 
                                            onClick={() => { setScenarioToDelete(sc.id); setIsDeleteModalOpen(true); }}
                                            className="p-1.5 text-slate-400 hover:text-rose-600 transition-colors"
                                        >
                                            <span className="material-symbols-rounded text-[20px]">delete</span>
                                        </button>
                                    )}
                                </div>
                            </div>

                            <div className="space-y-2">
                                <div className="flex items-center justify-between">
                                    <div className="inline-flex items-center gap-1.5 px-2 py-0.5 bg-violet-50 border border-violet-100 rounded-lg">
                                        <span className="w-1 h-1 rounded-full bg-[#7C3AED]" />
                                        <span className="text-[8px] font-black text-[#7C3AED] uppercase tracking-widest">{sc.category}</span>
                                    </div>
                                    <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{sc.difficulty}</span>
                                </div>
                                <h3 className="text-lg font-black text-slate-900 tracking-tight leading-tight line-clamp-1">{sc.title}</h3>
                                <p className="text-[10px] font-medium text-slate-500 leading-relaxed tracking-tight line-clamp-2 h-10">
                                    {sc.description || "Experimental training framework for advanced skill acquisition."}
                                </p>
                            </div>
                        </div>
                        
                        {(canAccess("scenarios:moderate") || role === "ADMIN") && (
                            <div className="px-8 py-5 flex items-center gap-4 bg-slate-50/50 border-t border-slate-50 rounded-b-2xl">
                                <button 
                                    onClick={() => setIsAssigningId(sc.id)}
                                    className="flex-1 h-11 bg-[#7C3AED] hover:bg-[#6D28D9] text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 group/btn"
                                >
                                    <Play className="w-3.5 h-3.5" />
                                    Assign Scenario
                                </button>
                            </div>
                        )}
                    </motion.div>
                )) : (
                    <div className="col-span-full py-32 text-center bg-white rounded-2xl border border-dashed border-slate-100">
                        <div className="w-20 h-20 bg-slate-50 rounded-2xl flex items-center justify-center mx-auto mb-6">
                            <span className="material-symbols-rounded text-4xl text-slate-200">psychology</span>
                        </div>
                        <h3 className="text-xl font-black text-slate-800 tracking-tight">No Scenarios Detected</h3>
                        <p className="text-xs text-slate-400 font-medium max-w-xs mx-auto mt-2">Initialize a new simulation framework or use the AI Neural Assistant to generate one.</p>
                    </div>
                )}
            </div>

            {/* Blueprint Drawer */}
            <AnimatePresence>
                {isCreating && (
                    <div className="fixed inset-0 z-[200] flex justify-end overflow-hidden">
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/40 backdrop-blur-md" onClick={() => { setIsCreating(false); setEditingId(null); }} />
                        <motion.div initial={{ x: "100%" }} animate={{ x: 0 }} exit={{ x: "100%" }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="relative w-full max-w-2xl bg-white shadow-2xl h-full flex flex-col pointer-events-auto border-l border-slate-100">
                            
                            {/* Drawer Header */}
                            <div className="flex items-center justify-between px-10 py-8 border-b border-slate-50 shrink-0">
                                <div className="flex items-center gap-6">
                                    <div className="w-14 h-14 rounded-xl bg-slate-900 flex items-center justify-center shadow-2xl">
                                        <DraftingCompass className="w-8 h-8 text-indigo-400" />
                                    </div>
                                    <div>
                                        <h2 className="text-2xl font-black text-slate-800 tracking-tighter   leading-none">{editingId ? "Edit Scenario" : "New Scenario"}</h2>
                                        <p className="text-[10px] font-black text-slate-300   mt-2">Scenario Design System</p>
                                    </div>
                                </div>
                                <button onClick={() => { setIsCreating(false); setEditingId(null); }} className="w-12 h-12 rounded-xl hover:bg-slate-50 flex items-center justify-center text-slate-400 transition-colors">
                                    <X className="w-6 h-6" />
                                </button>
                            </div>

                            {/* Drawer Body - Scrollable */}
                            <div className="flex-1 overflow-y-auto px-10 py-10 space-y-12 no-scrollbar">
                                
                                {/* Neural Assistant HUD */}
                                {!editingId && (canAccess("scenarios:moderate") || role === "ADMIN") && (
                                    <div className="bg-slate-950 rounded-2xl p-8 border border-white/5 relative overflow-hidden group/hud">
                                        <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/10 to-transparent opacity-50" />
                                        <div className="relative z-10 space-y-6">
                                            <div className="flex items-center justify-between">
                                                <div className="flex items-center gap-3">
                                                    <Sparkles className="w-5 h-5 text-indigo-400 animate-pulse" />
                                                    <span className="text-[10px] font-black text-indigo-400  tracking-[0.3em]">AI Generation Interface</span>
                                                </div>
                                            </div>
                                            <div className="flex gap-4">
                                                <textarea 
                                                    className="flex-1 bg-white/5 border border-white/10 rounded-xl px-6 py-5 text-sm font-bold text-white outline-none focus:bg-white/10 focus:border-indigo-400/50 transition-all placeholder:text-white/20 min-h-[100px] shadow-inner"
                                                    placeholder="CONCEPT: e.g. Negotiating a high-stakes supply line under crisis..."
                                                    value={aiPrompt}
                                                    onChange={(e) => setAiPrompt(e.target.value)}
                                                />
                                                <button 
                                                    onClick={handleAiGenerate}
                                                    disabled={isAiGenerating || !aiPrompt.trim()}
                                                    className="w-28 bg-white hover:bg-indigo-400 hover:text-white text-slate-950 rounded-xl font-black text-[9px]   flex flex-col items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-20 shadow-2xl"
                                                >
                                                    {isAiGenerating ? (
                                                        <div className="w-6 h-6 border-2 border-slate-950/20 border-t-slate-950 rounded-full animate-spin" />
                                                    ) : (
                                                        <Zap className="w-6 h-6" />
                                                    )}
                                                    {isAiGenerating ? "Generating" : "Generate"}
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {/* Main Form Inputs */}
                                <form id="architect-form" onSubmit={handleAction} className="space-y-10">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                        <div className="space-y-3 group">
                                            <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] ml-2 group-focus-within:text-slate-900 transition-colors">Scenario Title</label>
                                            <input 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-4 text-sm font-black text-slate-800 outline-none focus:bg-white focus:border-slate-900 transition-all shadow-inner"
                                                placeholder="e.g. Crisis Negotiation Alpha"
                                                value={form.title}
                                                onChange={e => setForm({...form, title: e.target.value})}
                                                required
                                            />
                                        </div>
                                        <div className="space-y-3 group">
                                            <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] ml-2 group-focus-within:text-slate-900 transition-colors">Difficulty Level</label>
                                            <select 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-4 text-[10px] font-black text-slate-800   outline-none focus:bg-white focus:border-slate-900 transition-all shadow-inner"
                                                value={form.difficulty}
                                                onChange={e => setForm({...form, difficulty: e.target.value})}
                                            >
                                                <option value="Beginner">Level_01: Beginner</option>
                                                <option value="Intermediate">Level_02: Intermediate</option>
                                                <option value="Advanced">Level_03: Advanced</option>
                                            </select>
                                        </div>
                                    </div>

                                    <div className="space-y-3 group">
                                        <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] ml-2 group-focus-within:text-slate-900 transition-colors">Participant Role & Persona</label>
                                        <div className="grid grid-cols-2 gap-4">
                                            <input 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-4 text-sm font-black text-slate-800 outline-none focus:bg-white focus:border-slate-900 transition-all shadow-inner"
                                                placeholder="Name: Jordan X"
                                                value={form.character_name}
                                                onChange={e => setForm({...form, character_name: e.target.value})}
                                                required
                                            />
                                            <input 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-4 text-sm font-black text-slate-800 outline-none focus:bg-white focus:border-slate-900 transition-all shadow-inner"
                                                placeholder="Role: Senior Operative"
                                                value={form.character_role}
                                                onChange={e => setForm({...form, character_role: e.target.value})}
                                                required
                                            />
                                        </div>
                                    </div>

                                    <div className="space-y-3 group">
                                        <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] ml-2 group-focus-within:text-slate-900 transition-colors">System Prompt Instructions</label>
                                        <textarea 
                                            className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-6 text-sm font-bold text-slate-700 outline-none focus:bg-white focus:border-slate-900 transition-all min-h-[150px] shadow-inner leading-relaxed"
                                            placeholder="Provide instructions for the AI character..."
                                            value={form.system_prompt}
                                            onChange={e => setForm({...form, system_prompt: e.target.value})}
                                            required
                                        />
                                    </div>

                                    <div className="space-y-3 group">
                                        <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] ml-2 group-focus-within:text-slate-900 transition-colors">Initial Message</label>
                                        <input 
                                            className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-4 text-sm font-black text-slate-800 outline-none focus:bg-white focus:border-slate-900 transition-all shadow-inner "
                                            placeholder="'I don't think we have the capacity for this delay...'"
                                            value={form.initial_message}
                                            onChange={e => setForm({...form, initial_message: e.target.value})}
                                            required
                                        />
                                    </div>
                                </form>
                            </div>

                             {/* Drawer Footer */}
                             {(canAccess("scenarios:moderate") || role === "ADMIN") && (
                                <div className="p-10 border-t border-slate-50 bg-slate-50/30 flex items-center justify-between gap-6 shrink-0">
                                    <p className="text-[9px] font-black text-slate-300   leading-none max-w-[200px]">Save this scenario to make it available for training.</p>
                                    <button 
                                        form="architect-form"
                                        type="submit"
                                        disabled={submitting}
                                        className="px-10 h-14 bg-[#7C3AED] text-white rounded-xl font-black text-[10px]  tracking-[0.3em] hover:bg-[#6D28D9] transition-all active:scale-95 shadow-2xl flex items-center gap-3"
                                    >
                                        {submitting && <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin" />}
                                        {submitting ? 'Saving' : editingId ? 'Update Scenario' : 'Save Scenario'}
                                    </button>
                                </div>
                            )}
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            {/* Deletion confirmation handled locally by standard modal pattern */}
            <ConfirmationModal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                onConfirm={handleDelete}
                title="Delete Scenario?"
                message="Are you sure you want to permanently delete this scenario? This action is irreversible."
                confirmLabel="Yes, Delete"
                cancelLabel="No"
                isDestructive={true}
            />

            {/* Deployment Overlay - To be standardized next */}
            <AnimatePresence>
                {isAssigningId && (
                    <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 sm:p-12 overflow-hidden">
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/40 backdrop-blur-md" onClick={() => setIsAssigningId(null)} />
                        <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="relative bg-white rounded-2xl w-full max-w-2xl max-h-full overflow-hidden shadow-2xl flex flex-col border border-slate-100">
                             <div className="p-10 border-b border-slate-50 flex items-center justify-between">
                                <div>
                                    <h2 className="text-2xl font-black text-slate-900 tracking-tight   ">Assign Scenario</h2>
                                    <p className="text-[10px] font-black text-indigo-500   mt-1">Select participants</p>
                                </div>
                                <X className="w-8 h-8 text-slate-300 cursor-pointer hover:text-rose-500 transition-colors" onClick={() => setIsAssigningId(null)} />
                             </div>
                             <div className="flex-1 overflow-y-auto p-10 space-y-3 no-scrollbar">
                                {employees.map(emp => (
                                    <div 
                                        key={emp.id} 
                                        onClick={() => toggleEmployeeSelection(emp.id)}
                                        className={`group p-5 rounded-xl border transition-all cursor-pointer flex items-center justify-between ${
                                            selectedEmployees.includes(emp.id) 
                                            ? 'bg-slate-900 border-slate-900 text-white shadow-2xl scale-[1.02]' 
                                            : 'bg-white border-slate-100 hover:bg-slate-50'
                                        }`}
                                    >
                                        <div className="flex items-center gap-6">
                                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black ${
                                                selectedEmployees.includes(emp.id) ? 'bg-white/10' : 'bg-slate-50 text-indigo-600'
                                            }`}>
                                                {emp.first_name?.[0]}{emp.last_name?.[0]}
                                            </div>
                                            <div>
                                                <p className="text-sm font-black tracking-tighter  ">{emp.first_name} {emp.last_name}</p>
                                                <p className={`text-[8px] font-black   mt-1 ${selectedEmployees.includes(emp.id) ? 'text-slate-400' : 'text-slate-300'}`}>
                                                    {emp.designation} • {emp.id.slice(0,8)}
                                                </p>
                                            </div>
                                        </div>
                                        <div className={`w-6 h-6 rounded-xl border-2 flex items-center justify-center transition-all ${
                                            selectedEmployees.includes(emp.id) ? 'bg-indigo-500 border-indigo-500 text-white' : 'border-slate-200'
                                        }`}>
                                            {selectedEmployees.includes(emp.id) && <Plus className="w-4 h-4 rotate-45" />}
                                        </div>
                                    </div>
                                ))}
                             </div>
                             <div className="p-10 border-t border-slate-50 bg-slate-50/30">
                                <button 
                                    onClick={handleAssign}
                                    disabled={assigning || selectedEmployees.length === 0}
                                    className="w-full h-16 bg-[#7C3AED] text-white rounded-xl font-black text-[11px]  tracking-[0.3em] hover:bg-[#6D28D9] transition-all shadow-2xl disabled:opacity-30 active:scale-95 flex items-center justify-center gap-4"
                                >
                                    {assigning && <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" />}
                                    {assigning ? 'Assigning' : 'Assign Scenario'}
                                </button>
                             </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient, BACKEND_URL } from "@/utils/api";

interface Question {
    id: string;
    text: string;
    type: "RATING" | "TEXT";
    category: string;
}

interface TemplateQuestion {
    question: Question;
    order: number;
}

interface Assignment {
    id: string;
    relation: string;
    status: string;
    ratee: {
        first_name: string;
        last_name: string;
    };
    cycle: {
        name: string;
    };
}

export default function X360FillAssessment() {
    const { token } = useAuth();
    const router = useRouter();
    const params = useParams();
    const assignmentId = params.id as string;

    const [assignment, setAssignment] = useState<Assignment | null>(null);
    const [questions, setQuestions] = useState<Question[]>([]);
    const [responses, setResponses] = useState<Record<string, { answer_value?: number, answer_text?: string }>>({});
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);

    const [showSuccess, setShowSuccess] = useState(false);
    const [pendingTasks, setPendingTasks] = useState<Assignment[]>([]);

    const fetchPendingTasks = async (raterId: string) => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/portal/assignments-by-rater/${raterId}`);
            if (res.ok) {
                const data = await res.json();
                setPendingTasks(data.filter((t: Assignment) => t.id !== assignmentId));
            }
        } catch (error) {
            console.error("Error fetching pending tasks:", error);
        }
    };

    useEffect(() => {
        const fetchDetails = async () => {
            try {
                // Always try portal endpoint first for public users or if not logged in
                let res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/portal/assessments/${assignmentId}`);

                // Fallback to standard recruiter endpoint only if portal fails and token exists
                if (!res.ok && token) {
                    res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/assessments/${assignmentId}`, {
                        headers: { 'Authorization': `Bearer ${token}` }
                    });
                }

                if (res && res.ok) {
                    const data = await res.json();
                    setAssignment(data.assignment);
                    const sortedQuestions = data.template.questions
                        .sort((a: TemplateQuestion, b: TemplateQuestion) => a.order - b.order)
                        .map((tq: TemplateQuestion) => tq.question);
                    setQuestions(sortedQuestions);
                    
                    // Initialize responses
                    const initialRes: Record<string, { answer_value?: number, answer_text?: string }> = {};
                    sortedQuestions.forEach((q: Question) => {
                        initialRes[q.id] = q.type === 'RATING' ? { answer_value: 3 } : { answer_text: "" };
                    });
                    setResponses(initialRes);

                    // Fetch other pending tasks for this rater
                    if (data.assignment.rater_id) {
                        fetchPendingTasks(data.assignment.rater_id);
                    }
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchDetails();
    }, [assignmentId, token]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            const payload = {
                responses: Object.entries(responses).map(([qId, val]) => ({
                    question_id: qId,
                    ...val
                }))
            };
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/portal/assessments/${assignmentId}/submit`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(payload)
            });
            if (res.ok) {
                setShowSuccess(true);
                window.scrollTo({ top: 0, behavior: 'smooth' });
            } else {
                alert("Failed to submit assessment");
            }
        } catch (error) {
            console.error(error);
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) return (
        <div className="min-h-screen bg-[#fafafa] flex items-center justify-center p-8 text-center">
            <div className="flex flex-col items-center gap-6">
                <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin shadow-xl shadow-indigo-100"></div>
                <p className="text-slate-500 font-black  tracking-[0.2em] text-xs">Authenticating Assignment...</p>
            </div>
        </div>
    );
    if (!assignment) return <div className="p-8 text-center text-rose-500 font-bold">Assessment not found.</div>;

    if (showSuccess) {
        return (
            <div className="min-h-screen bg-[#fafafa] py-20 px-6 selection:bg-indigo-100">
                <div className="max-w-[1000px] mx-auto">
                    <div className="bg-white rounded-2xl shadow-2xl shadow-slate-200/50 p-12 md:p-20 border border-white text-center space-y-12 animate-in zoom-in-95 duration-700">
                        <div className="w-32 h-32 rounded-full bg-emerald-500 text-white flex items-center justify-center mx-auto shadow-2xl shadow-emerald-200 animate-in fade-in slide-in-from-bottom-4 duration-1000">
                            <span className="material-symbols-rounded text-6xl">check_circle</span>
                        </div>
                        
                        <div className="space-y-4">
                            <h2 className="text-5xl font-black text-slate-900 tracking-tight">Feedback Transmitted</h2>
                            <p className="text-slate-500 text-xl font-medium max-w-2xl mx-auto leading-relaxed">
                                Thank you for providing your feedback for <span className="text-indigo-600 font-bold">{assignment.ratee.first_name}</span>. Your insights are essential for their professional development.
                            </p>
                        </div>

                        {pendingTasks.length > 0 ? (
                            <div className="space-y-8 pt-8 border-t border-slate-50">
                                <div className="bg-indigo-50 py-3 px-6 rounded-full inline-block border border-indigo-100">
                                    <p className="text-[10px] font-black text-indigo-600   leading-none">Action Required</p>
                                </div>
                                <h3 className="text-xl font-black text-slate-900">You have {pendingTasks.length} other pending assessments</h3>
                                
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 text-left">
                                    {pendingTasks.map((task) => (
                                        <button
                                            key={task.id}
                                            onClick={() => {
                                                setShowSuccess(false);
                                                router.push(`/enterprise/assessments-360/${task.id}`);
                                            }}
                                            className="bg-slate-50 p-8 rounded-2xl border border-transparent hover:border-indigo-200 hover:bg-white transition-all group hover:shadow-xl hover:shadow-slate-100/50 text-left"
                                        >
                                            <div className="flex justify-between items-start mb-4">
                                                <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center text-slate-400 group-hover:text-indigo-600 shadow-sm border border-slate-100 transition-colors">
                                                    <span className="material-symbols-rounded">person</span>
                                                </div>
                                                <span className="text-[10px] font-black text-slate-400  ">{task.relation}</span>
                                            </div>
                                            <p className="text-lg font-black text-slate-900 mb-1">{task.ratee.first_name} {task.ratee.last_name}</p>
                                            <p className="text-xs text-slate-400 font-bold  ">{task.cycle.name}</p>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        ) : (
                            <div className="pt-12 border-t border-slate-50 space-y-8">
                                <p className="text-slate-400 font-bold   text-xs flex items-center justify-center gap-2">
                                    <span className="material-symbols-rounded text-emerald-500">verified</span>
                                    All assignments complete for this cycle
                                </p>
                                <button
                                    onClick={() => router.push('/enterprise/assessments-360/portal')}
                                    className="px-12 py-5 bg-slate-900 text-white rounded-xl font-black text-sm  tracking-[0.3em] hover:bg-indigo-600 transition-all active:scale-95"
                                >
                                    Return to Portal
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#fafafa] py-16 px-6 md:px-12 animate-in fade-in duration-700">
            <div className="max-w-[1400px] mx-auto space-y-12">
                <header className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-12 border-b border-slate-100">
                    <div className="space-y-4">
                        <div className="flex items-center gap-3">
                            <button onClick={() => router.back()} className="w-10 h-10 rounded-full bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all flex items-center justify-center">
                                <span className="material-symbols-rounded">arrow_back</span>
                            </button>
                            <span className="text-[10px] font-black  tracking-[0.2em] text-indigo-600 bg-indigo-50 px-4 py-1.5 rounded-full border border-indigo-100">
                                {assignment.relation} ASSESSMENT
                            </span>
                        </div>
                        <h1 className="text-5xl font-black text-slate-900 tracking-tight">
                            {assignment.ratee.first_name} {assignment.ratee.last_name}
                        </h1>
                        <p className="text-slate-400 font-bold   text-xs flex items-center gap-2">
                            <span className="material-symbols-rounded text-base">event_repeat</span>
                            {assignment.cycle.name}
                        </p>
                    </div>
                    
                    <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/50 flex items-center gap-6">
                        <div className="text-right">
                            <p className="text-[10px] font-black text-slate-400  ">Progress</p>
                            <p className="text-lg font-black text-slate-900">{Math.round((Object.keys(responses).length / questions.length) * 100) || 0}% Complete</p>
                        </div>
                        <div className="w-16 h-16 rounded-full border-4 border-slate-50 border-t-indigo-600 rotate-45 flex items-center justify-center">
                            <span className="material-symbols-rounded text-indigo-600 -rotate-45">bolt</span>
                        </div>
                    </div>
                </header>

                <form onSubmit={handleSubmit} className="grid grid-cols-1 lg:grid-cols-12 gap-12 pb-32">
                    {/* Left Column: Questions */}
                    <div className="lg:col-span-8 space-y-8">
                        {questions.map((q, idx) => (
                            <div key={q.id} className="bg-white p-8 md:p-12 rounded-2xl border border-slate-100 shadow-xl shadow-slate-100/20 group hover:border-indigo-100 transition-all duration-500 animate-in fade-in" style={{ animationDelay: `${idx * 100}ms` }}>
                                <div className="flex flex-col md:flex-row md:items-start gap-8">
                                    <div className="shrink-0 w-14 h-14 rounded-xl bg-slate-50 text-slate-300 flex items-center justify-center font-black text-xl group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500">
                                        {idx + 1}
                                    </div>
                                    <div className="flex-1 space-y-8">
                                        <div className="space-y-2">
                                            <span className="text-[10px] font-black text-indigo-400  tracking-[0.2em]">{q.category}</span>
                                            <h3 className="text-2xl font-bold text-slate-800 leading-tight">{q.text}</h3>
                                        </div>

                                        {q.type === 'RATING' ? (
                                            <div className="space-y-6">
                                                <div className="grid grid-cols-5 gap-4">
                                                    {[1, 2, 3, 4, 5].map((val) => (
                                                        <button
                                                            key={val}
                                                            type="button"
                                                            onClick={() => setResponses({...responses, [q.id]: { answer_value: val }})}
                                                            className={`aspect-square rounded-xl font-black transition-all flex flex-col items-center justify-center gap-1 border-4 ${
                                                                responses[q.id]?.answer_value === val 
                                                                ? 'bg-slate-900 border-indigo-600 text-white shadow-2xl shadow-indigo-200 -translate-y-2 scale-105' 
                                                                : 'bg-slate-50 border-transparent text-slate-300 hover:border-slate-200 hover:bg-white'
                                                            }`}
                                                        >
                                                            <span className="text-2xl">{val}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                                <div className="flex justify-between px-2 text-[10px] font-black text-slate-300  ">
                                                    <span>Needs Improvement</span>
                                                    <span>Exceptional Performance</span>
                                                </div>
                                            </div>
                                        ) : (
                                            <textarea
                                                className="w-full px-8 py-6 bg-slate-50 border-none rounded-xl focus:ring-4 focus:ring-indigo-500/10 focus:bg-white outline-none transition-all font-medium min-h-[200px] text-slate-700 text-lg placeholder:text-slate-200"
                                                placeholder="Share your detailed observations..."
                                                value={responses[q.id]?.answer_text || ""}
                                                onChange={(e) => setResponses({...responses, [q.id]: { answer_text: e.target.value }})}
                                                required
                                            />
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Right Column: Dynamic Summary / Footer Sticky */}
                    <div className="lg:col-span-4 h-fit lg:sticky lg:top-8 space-y-6">
                        <div className="bg-slate-900 p-10 rounded-2xl text-white shadow-2xl shadow-slate-200">
                            <h4 className="text-xl font-black  tracking-tight mb-8">Submission Summary</h4>
                            
                            <div className="space-y-6 mb-10">
                                <div className="flex justify-between items-center py-4 border-b border-white/10">
                                    <span className="text-[10px] font-bold text-white/40  ">Questions Noted</span>
                                    <span className="text-lg font-black">{Object.keys(responses).length} / {questions.length}</span>
                                </div>
                                <p className="text-xs text-white/50 leading-relaxed font-medium ">
                                    {assignment.relation === 'PEER' || assignment.relation === 'REPORT' ? 
                                        "🔒 Your responses are end-to-end encrypted and will be aggregated anonymously to help your colleague grow." : 
                                        "📢 Your feedback will be shared directly with the employee as part of their development plan."
                                    }
                                </p>
                            </div>

                            <button
                                type="submit"
                                disabled={submitting || Object.keys(responses).length < questions.length}
                                className="w-full py-6 bg-indigo-600 text-white rounded-xl font-black text-sm  tracking-[0.3em] shadow-xl shadow-indigo-900/40 hover:bg-white hover:text-indigo-600 transition-all active:scale-95 disabled:opacity-30 disabled:grayscale"
                            >
                                {submitting ? 'Transmitting...' : 'Confirm Submission'}
                            </button>
                        </div>
                        
                        <div className="bg-indigo-50 p-8 rounded-2xl border border-indigo-100/50">
                            <p className="text-[10px] font-black text-indigo-400   mb-3">Support</p>
                            <p className="text-xs text-indigo-900/60 font-medium leading-relaxed">
                                Need help with the assessment? Contact the HR Business Partner team via the corporate internal helpdesk.
                            </p>
                        </div>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface ProgressBreakdown {
    rater_relation: string;
    status: string;
}

interface RateeProgress {
    ratee_id: string;
    ratee_name: string;
    total: number;
    completed: number;
    ai_score?: number;
    breakdown: ProgressBreakdown[];
}

export default function X360CycleProgress() {
    const { token } = useAuth();
    const router = useRouter();
    const params = useParams();
    const cycleId = params.id as string;
    
    const [progress, setProgress] = useState<RateeProgress[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchProgress = async () => {
            try {
                const res = await apiClient.get(`/api/v1/enterprise/x360/cycles/${cycleId}/progress`);
                if (res.ok) {
                    setProgress(await res.json());
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchProgress();
    }, [cycleId]);

    const getRelationIcon = (rel: string) => {
        switch(rel) {
            case 'SELF': return 'person';
            case 'MANAGER': return 'supervisor_account';
            case 'PEER': return 'groups';
            case 'REPORT': return 'assignment_ind';
            default: return 'help';
        }
    };

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center p-8 bg-slate-50">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    return (
        <div className="p-6 max-w-6xl mx-auto space-y-8 animate-in fade-in duration-700">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-6 border-b border-slate-100">
                <div className="space-y-2">
                    <div className="flex items-center gap-3">
                        <button onClick={() => router.back()} className="w-10 h-10 rounded-xl bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all flex items-center justify-center">
                            <span className="material-symbols-rounded text-xl">arrow_back</span>
                        </button>
                        <h1 className="text-2xl font-black text-slate-900 tracking-tight">Cycle Progress Tracker</h1>
                    </div>
                    <p className="text-slate-400 font-black   text-[10px] flex items-center gap-2">
                        <span className="material-symbols-rounded text-sm text-indigo-500">monitoring</span>
                        Detailed Breakdown by Employee
                    </p>
                </div>
            </div>

            <div className="grid grid-cols-1 gap-6">
                {progress.length > 0 ? progress.map((ratee, idx) => {
                    const pct = Math.round((ratee.completed / ratee.total) * 100);
                    return (
                        <div 
                            key={ratee.ratee_id} 
                            className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/10 hover:shadow-2xl hover:shadow-slate-200/20 transition-all group animate-in slide-in-from-bottom-4 duration-700"
                            style={{ animationDelay: `${idx * 100}ms` }}
                        >
                            <div className="flex flex-col lg:flex-row lg:items-center gap-8">
                                {/* Employee Identity */}
                                <div className="lg:w-1/4 space-y-2">
                                    <div className="flex items-center gap-3">
                                        <div className="w-12 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500 overflow-hidden">
                                            <span className="material-symbols-rounded text-2xl">account_circle</span>
                                        </div>
                                        <div>
                                            <h3 className="text-lg font-black text-slate-900 tracking-tight">{ratee.ratee_name}</h3>
                                            <p className="text-[9px] font-black text-slate-400   leading-none">Project Ratee</p>
                                        </div>
                                    </div>
                                </div>

                                {/* Rater Breakdown */}
                                <div className="flex-1">
                                    <div className="flex flex-wrap gap-3">
                                        {ratee.breakdown.map((b, bIdx) => (
                                            <div key={bIdx} className={`px-3 py-2 rounded-xl border flex items-center gap-2.5 transition-all shrink-0 ${
                                                b.status === 'COMPLETED' 
                                                ? 'bg-emerald-50 border-emerald-100 text-emerald-700' 
                                                : 'bg-slate-50/50 border-slate-100 text-slate-400 opacity-60'
                                            }`}>
                                                <span className="material-symbols-rounded text-base leading-none shrink-0">{getRelationIcon(b.rater_relation)}</span>
                                                <div className="text-left min-w-0">
                                                    <p className="text-[6px] font-black   leading-none mb-0.5 truncate">{b.rater_relation}</p>
                                                    <p className="text-[9px] font-black leading-none truncate">{b.status === 'COMPLETED' ? 'Done' : 'Pending'}</p>
                                                </div>
                                                {b.status === 'COMPLETED' && (
                                                    <span className="material-symbols-rounded text-[10px] shrink-0">verified</span>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                {/* Progress Bar & Stats */}
                                <div className="lg:w-1/3 space-y-4">
                                    <div className="flex justify-between items-end">
                                        <div className="flex items-center gap-4">
                                            <div className="space-y-0.5">
                                                <p className="text-[9px] font-black text-slate-400   leading-none">Status</p>
                                                <p className="text-xl font-black text-slate-900 leading-none">{pct}% Complete</p>
                                            </div>
                                            {ratee.ai_score !== null && ratee.ai_score !== undefined && (
                                                <div className="bg-indigo-600 px-4 py-2 rounded-xl text-white shadow-lg shadow-indigo-100 animate-in zoom-in duration-500">
                                                    <p className="text-[8px] font-black   leading-none mb-1 opacity-80">AI Perf Score</p>
                                                    <p className="text-lg font-black leading-none">{ratee.ai_score} <span className="text-[10px] opacity-60">/ 10</span></p>
                                                </div>
                                            )}
                                        </div>
                                        <p className="text-xs font-black text-slate-400 leading-none mb-1">{ratee.completed} / {ratee.total}</p>
                                    </div>
                                    <div className="h-2.5 bg-slate-50 rounded-full overflow-hidden border border-slate-100 p-0.5">
                                        <div 
                                            className={`h-full rounded-full transition-all duration-1000 ${pct === 100 ? 'bg-emerald-500' : 'bg-indigo-600'}`}
                                            style={{ width: `${pct}%` }}
                                        ></div>
                                    </div>
                                    
                                    {pct === 100 && (
                                        <button 
                                            onClick={() => router.push(`/enterprise/assessments-360/reports/${ratee.ratee_id}/${cycleId}`)}
                                            className="w-full py-3 bg-slate-900 text-white rounded-xl font-black text-[9px]   hover:bg-emerald-600 transition-all flex items-center justify-center gap-2"
                                        >
                                            Full Insight Report
                                            <span className="material-symbols-rounded text-base">analytics</span>
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                }) : (
                    <div className="py-20 text-center bg-white rounded-xl border border-dashed border-slate-200">
                        <span className="material-symbols-rounded text-4xl text-slate-200 mb-4">group_off</span>
                        <p className="text-slate-400 font-bold   text-[10px]">No project ratees found for this cycle</p>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface Cycle {
    id: string;
    name: string;
    start_date: string;
    end_date: string;
    status: string;
}

export default function X360CyclesList() {
    const { token } = useAuth();
    const router = useRouter();
    const [cycles, setCycles] = useState<Cycle[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchCycles = async () => {
            try {
                const res = await apiClient.get('/api/v1/enterprise/x360/cycles');
                if (res.ok) {
                    setCycles(await res.json());
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchCycles();
    }, []);

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center p-8 bg-slate-50">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    return (
        <div className="p-6 max-w-6xl mx-auto space-y-8 animate-in fade-in duration-700">
            <div className="flex justify-between items-end pb-6 border-b border-slate-100">
                <div className="space-y-1">
                    <div className="flex items-center gap-3">
                        <button onClick={() => router.back()} className="w-10 h-10 rounded-xl bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all flex items-center justify-center">
                            <span className="material-symbols-rounded text-xl">arrow_back</span>
                        </button>
                        <h1 className="text-2xl font-black text-slate-900 tracking-tight">Assessment Cycles</h1>
                    </div>
                    <p className="text-slate-400 font-black   text-[10px] flex items-center gap-2">
                        <span className="material-symbols-rounded text-sm text-indigo-500">sync</span>
                        Manage performance reviews and comprehensive feedback
                    </p>
                </div>
                <Link href="/enterprise/assessments-360/new" className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black text-xs   hover:bg-indigo-600 transition-all shadow-xl shadow-slate-100">
                    New Cycle
                </Link>
            </div>

            <div className="bg-white rounded-xl border border-slate-100 shadow-2xl shadow-slate-200/20 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-50/50">
                                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Cycle Name</th>
                                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Timeline</th>
                                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Status</th>
                                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                            {cycles.length > 0 ? cycles.map((cycle, idx) => (
                                <tr key={cycle.id} className="group hover:bg-slate-50/50 transition-all duration-300 animate-in slide-in-from-bottom-2" style={{ animationDelay: `${idx * 50}ms` }}>
                                    <td className="px-8 py-6">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500">
                                                <span className="material-symbols-rounded text-xl">refresh</span>
                                            </div>
                                            <div>
                                                <p className="font-black text-slate-900 leading-none mb-1">{cycle.name}</p>
                                                <p className="text-[10px] font-bold text-slate-400  tracking-tight ">360° Assessment</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-8 py-6">
                                        <div className="flex items-center gap-2 text-slate-600">
                                            <span className="material-symbols-rounded text-sm opacity-40">calendar_month</span>
                                            <span className="text-xs font-bold font-mono tracking-tighter">
                                                {new Date(cycle.start_date).toLocaleDateString()}
                                                <span className="mx-2 text-slate-300">→</span>
                                                {new Date(cycle.end_date).toLocaleDateString()}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="px-8 py-6">
                                        <span className={`px-4 py-1.5 rounded-full text-[9px] font-black   inline-flex items-center gap-2 ${
                                            cycle.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 
                                            cycle.status === 'DRAFT' ? 'bg-amber-50 text-amber-600 border border-amber-100' : 
                                            'bg-slate-50 text-slate-500 border border-slate-100'
                                        }`}>
                                            <span className={`w-1.5 h-1.5 rounded-full ${
                                                cycle.status === 'ACTIVE' ? 'bg-emerald-500 animate-pulse' : 
                                                cycle.status === 'DRAFT' ? 'bg-amber-500' : 'bg-slate-400'
                                            }`}></span>
                                            {cycle.status}
                                        </span>
                                    </td>
                                    <td className="px-8 py-6 text-right">
                                        <button 
                                            onClick={() => router.push(`/enterprise/assessments-360/cycles/${cycle.id}`)}
                                            className="px-6 py-2.5 bg-white border border-slate-100 text-slate-900 rounded-xl font-black text-[10px]   hover:bg-slate-900 hover:text-white hover:border-slate-900 transition-all shadow-sm flex items-center gap-2 ml-auto"
                                        >
                                            Track Progress
                                            <span className="material-symbols-rounded text-sm">trending_up</span>
                                        </button>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={4} className="py-20 text-center">
                                        <div className="flex flex-col items-center gap-4">
                                            <div className="w-16 h-16 bg-slate-50 rounded-xl flex items-center justify-center text-slate-200">
                                                <span className="material-symbols-rounded text-4xl">folder_off</span>
                                            </div>
                                            <p className="text-slate-400 font-bold   text-[10px]">No active cycles found in repository</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface Employee {
    first_name: string;
    last_name: string;
}

interface Assignment {
    id: string;
    relation: string;
    status: 'PENDING' | 'COMPLETED';
    ratee: Employee;
    cycle: {
        name: string;
    };
}

export default function X360MyAssessments() {
    const { token } = useAuth();
    const [assignments, setAssignments] = useState<Assignment[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchMyAssessments();
    }, []);

    const fetchMyAssessments = async () => {
        try {
            const res = await apiClient.get("/api/v1/enterprise/x360/my-assessments");
            if (res.ok) {
                const data = await res.json();
                setAssignments(Array.isArray(data) ? data : []);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    if (loading) return <div className="p-8 text-center text-slate-500 font-medium">Loading...</div>;

    const pending = assignments.filter(a => a.status === 'PENDING');
    const completed = assignments.filter(a => a.status === 'COMPLETED');

    return (
        <div className="p-8 max-w-5xl mx-auto space-y-10 animate-in fade-in duration-500">
            <div>
                <h1 className="text-3xl font-black text-slate-900 tracking-tight">My Assessments</h1>
                <p className="text-slate-500 font-medium mt-1">Provide feedback for yourself and your colleagues.</p>
            </div>

            <section className="space-y-4">
                <h3 className="text-xs font-black text-slate-400   pl-2">Action Required</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {pending.length === 0 ? (
                        <div className="col-span-full bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl p-12 text-center">
                            <span className="material-symbols-rounded text-4xl text-slate-300 mb-2">done_all</span>
                            <p className="text-slate-500 font-bold">You&apos;re all caught up!</p>
                            <p className="text-slate-400 text-xs mt-1">No pending feedback requests for you.</p>
                        </div>
                    ) : (
                        pending.map((ass) => (
                            <div key={ass.id} className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex justify-between items-center group hover:border-indigo-200 transition-all">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center font-black">
                                        {ass.ratee.first_name?.[0]}{ass.ratee.last_name?.[0]}
                                    </div>
                                    <div className="min-w-0">
                                        <p className="text-sm font-bold text-slate-900 truncate">{ass.ratee.first_name} {ass.ratee.last_name}</p>
                                        <div className="flex gap-2 mt-1">
                                            <span className="text-[10px] font-black  text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{ass.relation}</span>
                                        </div>
                                    </div>
                                </div>
                                <Link 
                                    href={`/enterprise/assessments-360/${ass.id}`}
                                    className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
                                >
                                    Start
                                </Link>
                            </div>
                        ))
                    )}
                </div>
            </section>

            {completed.length > 0 && (
                <section className="space-y-4 pt-4 border-t border-slate-50">
                    <h3 className="text-xs font-black text-slate-400   pl-2">Completed</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {completed.map((ass) => (
                            <div key={ass.id} className="bg-slate-50 p-4 rounded-xl flex items-center gap-4 border border-transparent">
                                <div className="w-10 h-10 bg-white text-slate-400 border border-slate-100 rounded-xl flex items-center justify-center font-bold text-xs">
                                    {ass.ratee.first_name?.[0]}{ass.ratee.last_name?.[0]}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-xs font-bold text-slate-700 truncate">{ass.ratee.first_name} {ass.ratee.last_name}</p>
                                    <p className="text-[10px] text-emerald-600 font-bold  tracking-tight">Completed</p>
                                </div>
                                <span className="material-symbols-rounded text-emerald-500 text-lg">check_circle</span>
                            </div>
                        ))}
                    </div>
                </section>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface Template {
    id: string;
    name: string;
    description: string;
}

interface Employee {
    id: string;
    first_name: string;
    last_name: string;
    designation?: string;
}

export default function X360NewCycle() {
    const { token } = useAuth();
    const router = useRouter();
    const [templates, setTemplates] = useState<Template[]>([]);
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    
    // Form State
    const [formData, setFormData] = useState({
        name: "",
        start_date: new Date().toISOString().split('T')[0],
        end_date: "",
        template_id: "",
        ratee_ids: [] as string[]
    });

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [tplRes, empRes] = await Promise.all([
                    apiClient.get("/api/v1/enterprise/x360/templates"),
                    apiClient.get("/api/v1/enterprise/employees/")
                ]);
                
                if (tplRes.ok) {
                    const data = await tplRes.json();
                    setTemplates(Array.isArray(data) ? data : []);
                }
                if (empRes.ok) {
                    const data = await empRes.json();
                    setEmployees(Array.isArray(data) ? data : []);
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            const res = await apiClient.post("/api/v1/enterprise/x360/cycles", formData);
            if (res.ok) {
                router.push("/enterprise/assessments-360");
            } else {
                alert("Failed to start cycle");
            }
        } catch (error) {
            console.error(error);
        } finally {
            setSubmitting(false);
        }
    };

    const toggleRatee = (id: string) => {
        setFormData(prev => ({
            ...prev,
            ratee_ids: prev.ratee_ids.includes(id)
                ? prev.ratee_ids.filter(rid => rid !== id)
                : [...prev.ratee_ids, id]
        }));
    };

    if (loading) return <div className="p-8 text-center text-slate-500 font-medium">Loading...</div>;

    return (
        <div className="p-6 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700">
            <header className="flex justify-between items-center pb-6 border-b border-slate-100">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.push('/enterprise/assessments-360')} className="w-10 h-10 rounded-xl bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all flex items-center justify-center">
                        <span className="material-symbols-rounded text-xl">arrow_back</span>
                    </button>
                    <div>
                        <h1 className="text-2xl font-black text-slate-900 tracking-tight">Start New 360 Cycle</h1>
                        <p className="text-slate-400 font-black   text-[10px] flex items-center gap-2">
                            <span className="material-symbols-rounded text-sm text-indigo-500">add_task</span>
                            Configure and launch a new feedback round
                        </p>
                    </div>
                </div>
            </header>

            <form onSubmit={handleSubmit} className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
                <div className="lg:col-span-4 space-y-6">
                    <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/10 space-y-6">
                        <h3 className="text-[10px] font-black text-slate-400  tracking-[0.2em] px-1">Cycle Configuration</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-[9px] font-black text-slate-400  mb-2  px-1">Cycle Name</label>
                                <input 
                                    className="w-full px-5 py-3 bg-slate-50 border border-transparent rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all font-bold text-sm text-slate-700 placeholder:text-slate-300"
                                    value={formData.name}
                                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                                    placeholder="e.g. Q1 Leadership Review"
                                    required
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-[9px] font-black text-slate-400  mb-2  px-1">Start Date</label>
                                    <input 
                                        type="date"
                                        className="w-full px-4 py-3 bg-slate-50 border border-transparent rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all font-bold text-xs text-slate-600"
                                        value={formData.start_date}
                                        onChange={(e) => setFormData({...formData, start_date: e.target.value})}
                                        required
                                    />
                                </div>
                                <div>
                                    <label className="block text-[9px] font-black text-slate-400  mb-2  px-1">End Date</label>
                                    <input 
                                        type="date"
                                        className="w-full px-4 py-3 bg-slate-50 border border-transparent rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all font-bold text-xs text-slate-600"
                                        value={formData.end_date}
                                        onChange={(e) => setFormData({...formData, end_date: e.target.value})}
                                        required
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 border-t border-slate-50">
                            <label className="block text-[9px] font-black text-slate-400  mb-4  px-1">Select Template</label>
                            <div className="space-y-3">
                                {templates.map(tpl => (
                                    <div 
                                        key={tpl.id}
                                        onClick={() => setFormData(prev => ({
                                            ...prev, 
                                            template_id: prev.template_id === tpl.id ? "" : tpl.id
                                        }))}
                                        className={`p-4 border-2 rounded-xl cursor-pointer transition-all flex items-center justify-between gap-4 ${formData.template_id === tpl.id ? 'border-indigo-600 bg-indigo-50/30' : 'border-slate-50 bg-slate-50 hover:border-slate-200'}`}
                                    >
                                        <div className="min-w-0">
                                            <h4 className="font-black text-slate-900 text-xs truncate leading-tight mb-0.5">{tpl.name}</h4>
                                            <p className="text-[9px] text-slate-400 line-clamp-1  font-medium">{tpl.description || "Active Framework"}</p>
                                        </div>
                                        {formData.template_id === tpl.id && (
                                            <div className="w-5 h-5 rounded-full bg-indigo-600 text-white flex items-center justify-center shrink-0">
                                                <span className="material-symbols-rounded text-[14px]">check</span>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>

                        <button 
                            type="submit"
                            disabled={submitting || !formData.template_id || formData.ratee_ids.length === 0}
                            className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px]  tracking-[0.3em] shadow-xl shadow-slate-200 hover:bg-indigo-600 transition-all active:scale-[0.98] disabled:opacity-30 disabled:grayscale"
                        >
                            {submitting ? 'Transmitting...' : 'Launch Cycle'}
                        </button>
                    </div>
                </div>

                <div className="lg:col-span-8 bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/10">
                    <div className="flex justify-between items-center mb-6 px-1">
                        <h3 className="text-[10px] font-black text-slate-400  tracking-[0.2em]">Select Target Employees</h3>
                        <span className="bg-indigo-600 text-white text-[9px] font-black px-3 py-1 rounded-full">{formData.ratee_ids.length} SELECTIONS noted</span>
                    </div>
                    <div className="grid grid-cols-2 lg:grid-cols-3 gap-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                        {employees.map(emp => (
                            <div 
                                key={emp.id}
                                onClick={() => toggleRatee(emp.id)}
                                className={`p-4 border-2 rounded-xl cursor-pointer transition-all flex items-center gap-3 ${formData.ratee_ids.includes(emp.id) ? 'border-indigo-600 bg-indigo-50/30 shadow-lg shadow-indigo-100/50' : 'border-slate-50 bg-slate-50/50 hover:border-slate-200'}`}
                            >
                                <div className={`shrink-0 w-8 h-8 rounded-xl flex items-center justify-center font-black text-[10px] transition-all ${formData.ratee_ids.includes(emp.id) ? 'bg-indigo-600 text-white' : 'bg-white text-slate-300 border border-slate-100'}`}>
                                    {formData.ratee_ids.includes(emp.id) ? (
                                        <span className="material-symbols-rounded text-sm">check</span>
                                    ) : (
                                        emp.first_name[0]
                                    )}
                                </div>
                                <div className="min-w-0">
                                    <p className="text-[11px] font-black text-slate-900 truncate leading-tight mb-0.5">{emp.first_name} {emp.last_name}</p>
                                    <p className="text-[9px] font-bold text-slate-400  tracking-tighter truncate">{emp.designation || 'Specialist'}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </form>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import SimulationChat from "@/app/enterprise/components/SimulationChat";
import { BACKEND_URL } from "@/utils/api";

interface Assessment {
    id: string;
    ratee_name: string;
    relation: string;
}

interface Survey {
    id: string;
    instance_name: string;
    template_title: string;
    token: string;
}

interface SimulationAssignment {
    id: string;
    scenario_id: string;
    title: string;
    description: string;
    character: string;
}

interface Employee {
    id: string;
    first_name: string;
}

export default function UnifiedEmployeePortal() {
    const router = useRouter();
    const [step, setStep] = useState<'login' | 'list'>('login');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    
    const [credentials, setCredentials] = useState({
        employee_id: "",
        email: ""
    });
    
    const [assessments, setAssessments] = useState<Assessment[]>([]);
    const [surveys, setSurveys] = useState<Survey[]>([]);
    const [simulationAssignments, setSimulationAssignments] = useState<SimulationAssignment[]>([]);
    const [employee, setEmployee] = useState<Employee | null>(null);

    // Simulation Session State
    const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
    const [activeAssignmentId, setActiveAssignmentId] = useState<string | null>(null);

    const handleLogin = async (e?: React.FormEvent) => {
        if (e) e.preventDefault();
        setLoading(true);
        setError("");
        
        const trimmedId = credentials.employee_id.trim();
        const trimmedEmail = credentials.email.trim();
        
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/surveys/portal/login?employee_id=${trimmedId}&email=${trimmedEmail}`, {
                method: 'POST'
            });
            const data = await res.json();
            if (res.ok) {
                setEmployee(data.employee);
                setAssessments(data.x360_assignments || []);
                setSurveys(data.survey_invites || []);
                setSimulationAssignments(data.simulation_assignments || []);
                setStep('list');
            } else {
                setError(data.detail || "Invalid ID or Email. Please check and try again.");
            }
        } catch (err) {
            setError("Connection error. Please try again later.");
        } finally {
            setLoading(false);
        }
    };

    const startSimulation = async (scenarioId: string, assignmentId: string) => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/sessions`, {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    scenario_id: scenarioId,
                    employee_id: employee.id,
                    assignment_id: assignmentId
                })
            });
            const data = await res.json();
            if (res.ok) {
                setActiveSessionId(data.id);
                setActiveAssignmentId(assignmentId);
            }
        } catch (error) {
            console.error(error);
        }
    };

    const totalTasks = assessments.length + surveys.length + simulationAssignments.length;

    if (activeSessionId) {
        return (
            <div className="fixed inset-0 bg-white z-[100] animate-in fade-in duration-500 overflow-hidden">
                <SimulationChat 
                    sessionId={activeSessionId} 
                    onClose={() => {
                        setActiveSessionId(null);
                        // Refresh data after completion
                        handleLogin();
                    }} 
                />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#fafafa] flex flex-col items-center justify-start py-20 px-6 selection:bg-indigo-100 overflow-x-hidden">
            {/* Background Accents */}
            <div className="fixed top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
                <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-indigo-50/50 rounded-full blur-[150px] opacity-40"></div>
                <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-violet-50/50 rounded-full blur-[150px] opacity-40"></div>
            </div>

            <div className={`w-full z-10 transition-all duration-1000 ease-in-out ${step === 'login' ? 'max-w-[550px]' : 'max-w-[1400px]'}`}>
                {step === 'login' ? (
                    <div className="bg-white rounded-2xl shadow-2xl shadow-slate-200/50 p-10 md:p-14 border border-white animate-in fade-in slide-in-from-bottom-8 duration-700">
                        <header className="text-center mb-12">
                            <div className="mb-6 tracking-tighter">
                                <span className="text-5xl font-black bg-gradient-to-r from-[#7C3AED] to-[#D946EF] bg-clip-text text-transparent ">CROAR.AI</span>
                            </div>
                            <h1 className="text-2xl font-black text-slate-400 tracking-[0.1em] mb-2 ">Employee Experience Hub</h1>
                            <p className="text-slate-300 font-bold  text-[10px] tracking-[0.3em]">Growth, Feedback & Behavioral Training</p>
                        </header>

                        <form onSubmit={handleLogin} className="space-y-6">
                            <div className="space-y-2">
                                <label className="block text-[10px] font-black text-slate-400   ml-1">Employee UUID / ID</label>
                                <input 
                                    className="w-full px-7 py-5 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-600 outline-none text-slate-800 font-bold placeholder:text-slate-300 transition-all text-sm"
                                    placeholder="Enter your unique ID..."
                                    value={credentials.employee_id}
                                    onChange={(e) => setCredentials({...credentials, employee_id: e.target.value})}
                                    required
                                />
                            </div>

                            <div className="space-y-2">
