"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";

interface Question {
    id: string;
    text: string;
    type: string;
    category: string;
    active_flag: boolean;
}

export default function CategoryDedicatedView({ params }: { params: Promise<{ category: string }> }) {
    const { category: categorySlug } = use(params);
    const category = categorySlug.toUpperCase().replace(/-/g, '_');
    const { token } = useAuth();
    const router = useRouter();
    const [questions, setQuestions] = useState<Question[]>([]);
    const [loading, setLoading] = useState(true);
    
    // Manual Form State - Dedicated to this category
    const [newQuestion, setNewQuestion] = useState({
        text: "",
        type: "RATING",
        category: category
    });

    useEffect(() => {
        fetchQuestions();
    }, [category, token]);

    const fetchQuestions = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            if (Array.isArray(data)) {
                // Filter for this specific category
                setQuestions(data.filter(q => q.category === category));
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleAdd = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(newQuestion)
            });
            if (res.ok) {
                setNewQuestion({ ...newQuestion, text: "" });
                fetchQuestions();
            }
        } catch (error) {
            console.error(error);
        }
    };

    const categoryIcons: Record<string, string> = {
        'PERFORMANCE': 'trending_up',
        'ENGAGEMENT': 'favorite',
        'CORE_VALUES': 'verified_user',
        'LEADERSHIP': 'shield_person',
        'TECHNICAL_SKILLS': 'code_blocks',
        'SOFT_SKILLS': 'psychology',
        'COMMUNICATION': 'forum',
        'TEAMWORK': 'groups',
        'ADAPTABILITY': 'published_with_changes'
    };

    const icon = categoryIcons[category] || 'folder';

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50">
            <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50/50">
            <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200 py-4 px-8 flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.push('/enterprise/assessments-360/questions')} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">
                        <span className="material-symbols-rounded">arrow_back</span>
                    </button>
                    <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-lg">
                            <span className="material-symbols-rounded text-xl">{icon}</span>
                        </div>
                        <div>
                            <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none">{category.replace(/_/g, ' ')}</h1>
                            <p className="text-slate-500 text-[10px] font-black  tracking-[0.2em] mt-1">Dedicated Competency View</p>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <span className="text-[10px] font-black text-slate-400   bg-white border border-slate-100 px-4 py-2 rounded-full shadow-sm">
                        {questions.length} Items
                    </span>
                </div>
            </header>

            <main className="max-w-[1600px] mx-auto p-12 grid grid-cols-12 gap-10">
                {/* Sidebar - Category Specific Form */}
                <aside className="col-span-12 lg:col-span-4 space-y-8">
                    <section className="bg-white p-10 rounded-2xl border border-slate-100 shadow-2xl shadow-slate-200/50 relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-full blur-3xl -mr-16 -mt-16"></div>
                        <div className="relative z-10">
                            <div className="flex items-center gap-4 mb-8">
                                <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
                                    <span className="material-symbols-rounded text-2xl">add_circle</span>
                                </div>
                                <div>
                                    <h2 className="text-2xl font-black text-slate-800 tracking-tight">Add Skill</h2>
                                    <p className="text-slate-400 text-[9px] font-bold   mt-0.5">Define new competency rules</p>
                                </div>
                            </div>
                            
                            <form onSubmit={handleAdd} className="space-y-8">
                                <div className="space-y-3">
                                    <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] px-1">Evaluation Metric</label>
                                    <textarea 
                                        className="w-full px-8 py-6 bg-slate-50 border-2 border-transparent rounded-xl focus:border-indigo-500 focus:bg-white focus:ring-4 focus:ring-indigo-100 outline-none text-sm font-bold text-slate-700 placeholder:text-slate-300 transition-all min-h-[160px] leading-relaxed"
                                        value={newQuestion.text}
                                        onChange={(e) => setNewQuestion({...newQuestion, text: e.target.value})}
                                        required
                                        placeholder={`e.g. How effectively does the person demonstrate ${category.toLowerCase().replace(/_/g, ' ')}...`}
                                    />
                                </div>
                                <div className="space-y-3">
                                    <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] px-1">Metric Architecture</label>
                                    <div className="relative">
                                        <select 
                                            className="w-full px-8 py-4 bg-slate-50 border-2 border-transparent rounded-xl focus:border-indigo-500 focus:bg-white outline-none text-sm font-black text-slate-700 appearance-none cursor-pointer transition-all"
                                            value={newQuestion.type}
                                            onChange={(e) => setNewQuestion({...newQuestion, type: e.target.value})}
                                        >
                                            <option value="RATING">Rating Interface (1-5)</option>
                                            <option value="TEXT">Exploratory Text Only</option>
                                        </select>
                                        <span className="material-symbols-rounded absolute right-6 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">expand_more</span>
                                    </div>
                                </div>
                                <button 
                                    type="submit"
                                    className="w-full h-16 bg-slate-900 text-white rounded-xl font-black text-[11px]  tracking-[0.25em] shadow-xl hover:bg-indigo-600 hover:shadow-indigo-100 transition-all hover:-translate-y-1 active:translate-y-0"
                                >
                                    Inject Competency
                                </button>
                            </form>
                        </div>
                    </section>
                </aside>

                {/* Main List */}
                <main className="col-span-12 lg:col-span-8">
                    <div className="bg-white rounded-2xl border border-slate-100 shadow-2xl shadow-slate-200/40 overflow-hidden">
                        <div className="p-10 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
                            <div>
                                <h2 className="text-xl font-black text-slate-900 tracking-tight">Competency Inventory</h2>
                                <p className="text-slate-400 text-[10px] font-bold  tracking-[0.2em] mt-1">Repository for {category.replace(/_/g, ' ')}</p>
                            </div>
                            <div className="flex items-center gap-3">
                                <button className="w-10 h-10 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:border-indigo-100 transition-all">
                                    <span className="material-symbols-rounded text-xl">search</span>
                                </button>
                                <button className="w-10 h-10 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:border-indigo-100 transition-all">
                                    <span className="material-symbols-rounded text-xl">filter_list</span>
                                </button>
                            </div>
                        </div>

                        <div className="overflow-x-auto">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-white">
                                        <th className="px-10 py-6 text-[10px] font-black text-slate-400  tracking-[0.25em] border-b border-slate-50">Content Archetype</th>
                                        <th className="px-10 py-6 text-[10px] font-black text-slate-400  tracking-[0.25em] border-b border-slate-50">Metric</th>
                                        <th className="px-10 py-6 text-[10px] font-black text-slate-400  tracking-[0.25em] border-b border-slate-50 text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {questions.length === 0 ? (
                                        <tr>
                                            <td colSpan={3} className="px-10 py-32 text-center">
                                                <div className="flex flex-col items-center">
                                                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-6 text-slate-200">
                                                        <span className="material-symbols-rounded text-4xl">folder_off</span>
                                                    </div>
                                                    <p className="text-slate-400 text-sm font-bold">This folder is currently empty.</p>
                                                    <p className="text-slate-300 text-[10px] font-black  mt-2">Add manual entries or use the AI Generator on the main page.</p>
                                                </div>
                                            </td>
                                        </tr>
                                    ) : (
                                        questions.map((q) => (
                                            <tr key={q.id} className="group hover:bg-slate-50/50 transition-all">
                                                <td className="px-10 py-10">
                                                    <p className="text-sm font-bold text-slate-700 leading-relaxed max-w-xl">{q.text}</p>
                                                </td>
                                                <td className="px-10 py-10">
                                                    <span className="text-[10px] font-black  px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl border border-indigo-100 ">
                                                        {q.type}
                                                    </span>
                                                </td>
                                                <td className="px-10 py-10 text-right">
                                                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                        <button className="p-3 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all shadow-md active:scale-95">
                                                            <span className="material-symbols-rounded text-xl">edit</span>
                                                        </button>
                                                        <button className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all shadow-md active:scale-95">
                                                            <span className="material-symbols-rounded text-xl">delete</span>
                                                        </button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </main>
            </main>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";

interface Question {
    id: string;
    text: string;
    type: string;
    category: string;
    active_flag: boolean;
}

interface GeneratedQuestion {
    text: string;
    type: string;
    category: string;
}

export default function X360QuestionBank() {
    const { token } = useAuth();
    const router = useRouter();
    const [questions, setQuestions] = useState<Question[]>([]);
    const [loading, setLoading] = useState(true);
    
    // Manual Form State
    const [newQuestion, setNewQuestion] = useState({
        text: "",
        type: "RATING",
        category: "PERFORMANCE"
    });

    // AI Generator State
    const [aiConfig, setAiConfig] = useState({
        categories: ["PERFORMANCE"] as string[],
        count: 5,
        context: "",
        customCategory: ""
    });
    const [isGenerating, setIsGenerating] = useState(false);
    const [generatedQuestions, setGeneratedQuestions] = useState<GeneratedQuestion[]>([]);
    const suggestionsRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (generatedQuestions.length > 0 && suggestionsRef.current) {
            suggestionsRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
        }
    }, [generatedQuestions]);

    useEffect(() => {
        fetchQuestions();
    }, []);

    const fetchQuestions = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            if (Array.isArray(data)) {
                setQuestions(data);
            } else {
                setQuestions([]);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleAdd = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(newQuestion)
            });
            if (res.ok) {
                setNewQuestion({ text: "", type: "RATING", category: "PERFORMANCE" });
                fetchQuestions();
            }
        } catch (error) {
            console.error(error);
        }
    };

    const handleAIGenerate = async () => {
        if (aiConfig.categories.length === 0) return;
        setIsGenerating(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions/ai-generate`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    categories: aiConfig.categories,
                    count: aiConfig.count,
                    additional_context: aiConfig.context,
                    custom_category: aiConfig.customCategory
                })
            });
            const data = await res.json();
            if (Array.isArray(data)) {
                setGeneratedQuestions(data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setIsGenerating(false);
        }
    };

    const saveGenerated = async () => {
        try {
            for (const q of generatedQuestions) {
                await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                    method: 'POST',
                    headers: { 
                        'Authorization': `Bearer ${token}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify(q)
                });
            }
            setGeneratedQuestions([]);
            fetchQuestions();
        } catch (error) {
            console.error(error);
        }
    };

    const toggleAiCategory = (cat: string) => {
        setAiConfig(prev => ({
            ...prev,
            categories: prev.categories.includes(cat) 
                ? prev.categories.filter(c => c !== cat)
                : [...prev.categories, cat]
        }));
    };

    const categories = [
        { id: 'PERFORMANCE', label: 'Performance' },
        { id: 'ENGAGEMENT', label: 'Engagement' },
        { id: 'CORE_VALUES', label: 'Core Values' },
        { id: 'LEADERSHIP', label: 'Leadership' },
        { id: 'TECHNICAL_SKILLS', label: 'Technical Skills' },
        { id: 'SOFT_SKILLS', label: 'Soft Skills' },
        { id: 'COMMUNICATION', label: 'Communication' },
        { id: 'TEAMWORK', label: 'Teamwork' },
        { id: 'ADAPTABILITY', label: 'Adaptability' }
    ];

    return (
        <div className="p-4 max-w-[1600px] mx-auto animate-in fade-in duration-500">
            <header className="mb-5 flex items-center gap-3">
                <button onClick={() => router.push('/enterprise/assessments-360')} className="w-7 h-7 rounded-xl bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-[#7C3AED] transition-all flex items-center justify-center">
                    <span className="material-symbols-rounded text-base">arrow_back</span>
                </button>
                <div>
                    <h1 className="text-lg font-black text-slate-900 tracking-tight leading-none">Question Bank</h1>
                    <p className="text-slate-500 mt-1 text-[10px] font-black uppercase tracking-widest opacity-70">Build and manage your feedback framework with AI assistance.</p>
                </div>
            </header>

            <div className="grid grid-cols-1 gap-6">
                {/* AI Generator - Now Full Width */}
                <section className="bg-gradient-to-br from-[#7C3AED] to-indigo-700 p-6 rounded-xl text-white shadow-2xl shadow-indigo-100 overflow-hidden relative">
                    {/* Decorative Background Elements */}
                    <div className="absolute top-0 right-0 w-48 h-48 bg-white/5 rounded-full blur-3xl -mr-10 -mt-20"></div>
                    <div className="absolute bottom-0 left-0 w-32 h-32 bg-indigo-400/10 rounded-full blur-2xl -ml-20 -mb-10"></div>
                    
                    <div className="relative z-10">
                        <div className="flex items-center justify-between mb-6">
                            <div className="flex items-center gap-3">
                                <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-xl flex items-center justify-center border border-white/30 shadow-xl">
                                    <span className="material-symbols-rounded text-white text-xl animate-pulse">auto_awesome</span>
                                </div>
                                <div>
                                    <h2 className="text-xl font-black leading-none tracking-tight">Scenario Architect</h2>
                                    <p className="text-violet-100 text-[9px]  font-black tracking-[0.2em] mt-1.5 opacity-80 ">GPT-4 Organizational AI</p>
                                </div>
                            </div>
                            <button 
                                onClick={() => router.push('/enterprise/assessments-360/questions/new')}
                                className="px-6 py-2.5 bg-white/10 hover:bg-white/20 border border-white/20 rounded-xl text-[9px] font-black   transition-all flex items-center gap-2 group"
                            >
                                <span className="material-symbols-rounded text-base group-hover:rotate-90 transition-transform">add</span>
                                Create Manual
                            </button>
                        </div>

                        <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                            {/* Categories Selection - More Space */}
                            <div>
                                <label className="block text-[10px] font-black text-violet-100   mb-4 px-1 opacity-70">Target Competencies & Categories</label>
                                <div className="flex flex-wrap gap-2">
                                    {/* Standard Categories */}
                                    {categories.map(cat => (
                                        <button
                                            key={cat.id}
                                            onClick={() => toggleAiCategory(cat.id)}
                                            className={`flex items-center gap-2 px-3.5 py-2 rounded-xl text-[10px] font-bold transition-all border whitespace-nowrap shadow-sm ${
                                                aiConfig.categories.includes(cat.id) 
                                                ? 'bg-white text-[#7C3AED] border-white scale-105 shadow-violet-500/20' 
                                                : 'bg-white/5 text-violet-50 border-white/10 hover:border-white/30 hover:bg-white/10'
                                            }`}
                                        >
                                            <span className="material-symbols-rounded text-base shrink-0">
                                                {aiConfig.categories.includes(cat.id) ? 'check_circle' : 'circle'}
                                            </span>
                                            {cat.label}
                                        </button>
                                    ))}
                                    
                                    {/* Custom Categories already added */}
                                    {aiConfig.categories.filter(c => !categories.find(base => base.id === c)).map(cat => (
                                            <button
                                            key={cat}
                                            onClick={() => toggleAiCategory(cat)}
                                            className="flex items-center gap-2 px-3.5 py-2 rounded-xl text-[10px] font-bold transition-all border whitespace-nowrap shadow-sm bg-white text-[#7C3AED] border-white scale-105"
                                        >
                                            <span className="material-symbols-rounded text-base shrink-0 text-amber-500">new_releases</span>
                                            {cat}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Configuration & Action */}
                            <div className="xl:col-span-5 flex flex-col justify-between gap-6">
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-[9px] font-black text-violet-100   mb-2 px-1 opacity-70">Quantity</label>
                                        <div className="relative">
                                            <input 
                                                type="number"
                                                min="1" max="20"
                                                className="w-full px-4 py-3 bg-white/10 border border-white/10 rounded-xl focus:ring-2 focus:ring-white outline-none text-xs font-bold placeholder:text-violet-200 transition-all hover:bg-white/15"
                                                value={aiConfig.count}
                                                onChange={(e) => setAiConfig({...aiConfig, count: parseInt(e.target.value)})}
                                            />
                                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[9px] font-black text-violet-200 ">Items</span>
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-black text-violet-100   mb-2 px-1 opacity-70">Business Context</label>
                                        <input 
                                            type="text"
                                            placeholder="e.g. Sales, Health..."
                                            className="w-full px-4 py-3 bg-white/10 border border-white/10 rounded-xl focus:ring-2 focus:ring-white outline-none text-xs font-bold placeholder:text-violet-200 transition-all hover:bg-white/15"
                                            value={aiConfig.context}
                                            onChange={(e) => setAiConfig({...aiConfig, context: e.target.value})}
                                        />
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <div>
                                        <label className="block text-[9px] font-black text-violet-100   mb-2 px-1 opacity-70">Add New Category</label>
                                        <div className="flex gap-2">
                                            <input 
                                                type="text"
                                                placeholder="Type and hit + to add..."
                                                className="flex-1 px-4 py-3 bg-white/10 border border-white/10 rounded-xl focus:ring-2 focus:ring-white outline-none text-xs font-bold placeholder:text-violet-200 transition-all hover:bg-white/15"
                                                value={aiConfig.customCategory}
                                                onChange={(e) => setAiConfig({...aiConfig, customCategory: e.target.value})}
                                                onKeyDown={(e) => {
                                                    if (e.key === 'Enter' && aiConfig.customCategory) {
                                                        e.preventDefault();
                                                        toggleAiCategory(aiConfig.customCategory.toUpperCase().replace(/\s+/g, '_'));
                                                        setAiConfig(prev => ({ ...prev, customCategory: "" }));
                                                    }
                                                }}
                                            />
                                            <button 
                                                onClick={() => {
                                                    if (aiConfig.customCategory) {
                                                        toggleAiCategory(aiConfig.customCategory.toUpperCase().replace(/\s+/g, '_'));
                                                        setAiConfig(prev => ({ ...prev, customCategory: "" }));
                                                    }
                                                }}
                                                className="w-14 h-[52px] bg-white text-[#7C3AED] rounded-xl flex items-center justify-center hover:scale-105 active:scale-95 transition-all shadow-lg"
                                            >
                                                <span className="material-symbols-rounded font-black">add</span>
                                            </button>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={handleAIGenerate}
                                        disabled={isGenerating || aiConfig.categories.length === 0}
                                        className="w-full py-4 bg-white text-[#7C3AED] rounded-xl font-black text-xs hover:scale-[1.02] active:scale-95 transition-all shadow-2xl shadow-indigo-900/40 disabled:opacity-50 disabled:scale-100  tracking-[0.2em] flex items-center justify-center gap-3 group"
                                    >
                                        {isGenerating ? (
                                            <>
                                                <div className="w-4 h-4 border-2 border-[#7C3AED] border-t-transparent rounded-full animate-spin"></div>
                                                <span>Synthesizing...</span>
                                            </>
                                        ) : (
                                            <>
                                                <span className="material-symbols-rounded text-lg group-hover:rotate-12 transition-transform">bolt</span>
                                                <span>Generate Questions</span>
                                            </>
                                        )}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </section>

                <div className="grid grid-cols-12 gap-8 items-start">
                    {/* Sidebar */}
                    <aside className="col-span-12 lg:col-span-4 space-y-8 sticky top-8">
                        {/* Manual Form */}
                        <section className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-200/50">
                            <div className="flex items-center gap-3 mb-6">
                                <div className="w-10 h-10 bg-violet-50 rounded-xl flex items-center justify-center text-[#7C3AED]">
                                    <span className="material-symbols-rounded text-xl">edit_note</span>
                                </div>
                                <h2 className="text-lg font-bold text-slate-800 tracking-tight">New Question</h2>
                            </div>
                            <form onSubmit={handleAdd} className="space-y-5">
                                <div>
                                    <label className="block text-[9px] font-black text-slate-400   mb-2 px-1 opacity-70">Question Content</label>
                                    <textarea 
                                        className="w-full px-5 py-4 bg-slate-50 border-2 border-transparent rounded-xl focus:border-[#7C3AED] focus:bg-white focus:ring-4 focus:ring-violet-500/10 outline-none min-h-[120px] text-xs text-slate-700 placeholder:text-slate-300 transition-all font-medium leading-relaxed"
                                        value={newQuestion.text}
                                        onChange={(e) => setNewQuestion({...newQuestion, text: e.target.value})}
                                        required
                                        placeholder="e.g. Handle stress..."
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-[10px] font-black text-slate-400   mb-2.5 px-1 opacity-70">Response Type</label>
                                        <div className="relative">
                                            <select 
                                                className="w-full px-6 py-4 bg-slate-50 border-2 border-transparent rounded-xl focus:border-[#7C3AED] focus:bg-white outline-none text-sm font-bold text-slate-600 appearance-none transition-all cursor-pointer"
                                                value={newQuestion.type}
                                                onChange={(e) => setNewQuestion({...newQuestion, type: e.target.value})}
                                            >
                                                <option value="RATING">Rating (1-5)</option>
                                                <option value="TEXT">Open Text</option>
                                            </select>
                                            <span className="material-symbols-rounded absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">unfold_more</span>
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-[10px] font-black text-slate-400   mb-2.5 px-1 opacity-70">Core Category</label>
                                        <div className="relative">
                                            <select 
                                                className="w-full px-6 py-4 bg-slate-50 border-2 border-transparent rounded-xl focus:border-[#7C3AED] focus:bg-white outline-none text-sm font-bold text-slate-600 appearance-none transition-all cursor-pointer"
                                                value={newQuestion.category}
                                                onChange={(e) => setNewQuestion({...newQuestion, category: e.target.value})}
                                            >
                                                {categories.map(c => <option key={c.id} value={c.id}>{c.label}</option>)}
                                            </select>
                                            <span className="material-symbols-rounded absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">unfold_more</span>
                                        </div>
                                    </div>
                                </div>
                                <button 
                                    type="submit"
                                    className="w-full py-4 bg-[#7C3AED] text-white rounded-xl font-black text-[10px] hover:bg-slate-900 hover:shadow-2xl hover:shadow-violet-200 hover:-translate-y-0.5 transition-all active:translate-y-0  tracking-[0.2em] mt-2 block shadow-lg"
                                >
                                    Save to Bank
                                </button>
                            </form>
                        </section>
                    </aside>

                    {/* Main Area */}
                    <main className="col-span-12 lg:col-span-8 space-y-8">
                    {/* AI Preview */}
                    {generatedQuestions.length > 0 && (
                        <section ref={suggestionsRef} className="bg-amber-50/50 rounded-2xl p-8 border-2 border-amber-200 animate-in fade-in slide-in-from-top-4 duration-500 shadow-2xl shadow-amber-100/50">
                            <div className="flex justify-between items-center mb-8 bg-white/50 p-6 rounded-xl border border-amber-100/50">
                                <div className="flex items-center gap-4">
                                    <div className="w-14 h-14 bg-amber-100 rounded-xl flex items-center justify-center text-amber-600 shadow-inner border border-amber-200/50">
                                        <span className="material-symbols-rounded text-3xl animate-bounce">auto_awesome</span>
                                    </div>
                                    <div>
                                        <h3 className="text-2xl font-black text-amber-900 tracking-tight">AI Suggestions Ready</h3>
                                        <p className="text-amber-700/70 text-sm font-medium">Review, refine, and add these AI-curated questions.</p>
                                    </div>
                                </div>
                                <div className="flex gap-4">
                                    <button 
                                        onClick={() => setGeneratedQuestions([])}
                                        className="px-6 py-3 text-amber-700 font-black text-[10px]   hover:bg-amber-100 rounded-xl transition-all border border-amber-200"
                                    >
                                        Discard All
                                    </button>
                                    <button 
                                        onClick={saveGenerated}
                                        className="px-8 py-3 bg-amber-600 text-white font-black text-[10px] rounded-xl shadow-xl shadow-amber-200 hover:bg-amber-700 transition-all  tracking-[0.2em] flex items-center gap-2"
                                    >
                                        <span className="material-symbols-rounded text-lg">library_add</span>
                                        Add to Library ({generatedQuestions.length})
                                    </button>
                                </div>
                            </div>
                            <div className="space-y-3">
                                {generatedQuestions.map((q, i) => (
                                    <div key={i} className="bg-white p-5 rounded-xl border border-amber-100 flex items-start gap-4 shadow-sm">
                                        <div className="w-8 h-8 rounded-full bg-amber-50 flex items-center justify-center text-amber-600 font-bold text-xs shrink-0">{i+1}</div>
                                        <div className="flex-1">
                                            <p className="text-sm font-medium text-slate-800">{q.text}</p>
                                            <div className="flex gap-2 mt-2">
                                                <span className="text-[9px] font-black  px-2 py-0.5 bg-slate-50 text-slate-500 rounded-xl border border-slate-100">{q.category}</span>
                                                <span className="text-[9px] font-black  px-2 py-0.5 bg-slate-50 text-slate-500 rounded-xl border border-slate-100">{q.type}</span>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </section>
                    )}

                    {/* Question List Grouped by Category - Directory View */}
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                        {/* Manual Create Card - THE "CREA" BUTTON */}
                        <div 
                            onClick={() => router.push('/enterprise/assessments-360/questions/new')}
                            className="bg-violet-50/30 p-5 rounded-xl border-2 border-dashed border-violet-200 hover:border-violet-400 hover:bg-violet-50 transition-all cursor-pointer flex flex-col items-center justify-center text-center group"
                        >
                            <div className="w-16 h-16 bg-white rounded-xl flex items-center justify-center text-[#7C3AED] shadow-xl group-hover:scale-110 transition-transform mb-4 border border-violet-100">
                                <span className="material-symbols-rounded text-2xl">add_circle</span>
                            </div>
                            <h3 className="text-base font-black text-violet-900 tracking-tight mb-1">Create Competency</h3>
                            <p className="text-violet-400 text-[8px] font-black  ">Manual Entry</p>
                        </div>

                        {Array.from(new Set([
                            ...categories.map(c => c.id),
                            ...questions.map(q => q.category)
                        ])).sort().map(cat => {
                            const catQuestions = questions.filter(q => q.category === cat);
                            const categoryIcons: Record<string, string> = {
                                'PERFORMANCE': 'trending_up',
                                'ENGAGEMENT': 'favorite',
                                'CORE_VALUES': 'verified_user',
                                'LEADERSHIP': 'shield_person',
                                'TECHNICAL_SKILLS': 'code_blocks',
                                'SOFT_SKILLS': 'psychology',
                                'COMMUNICATION': 'forum',
                                'TEAMWORK': 'groups',
                                'ADAPTABILITY': 'published_with_changes'
                            };
                            const icon = categoryIcons[cat] || 'folder';
                            const label = categories.find(c => c.id === cat)?.label || cat.replace(/_/g, ' ');

                            return (
                                <div 
                                    key={cat} 
                                    onClick={() => router.push(`/enterprise/assessments-360/questions/${cat.toLowerCase().replace(/_/g, '-')}`)}
                                    className="group bg-white p-5 rounded-xl border border-slate-100 shadow-lg shadow-slate-200/20 hover:shadow-2xl hover:shadow-indigo-100 hover:-translate-y-1 transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center animate-in zoom-in duration-500"
                                >
                                    <div className="absolute top-0 right-0 w-20 h-20 bg-indigo-50/50 rounded-full blur-2xl -mr-10 -mt-10 group-hover:bg-indigo-100 transition-colors"></div>
                                    
                                    <div className="w-16 h-16 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-xl group-hover:scale-110 transition-transform mb-4">
                                        <span className="material-symbols-rounded text-2xl">{icon}</span>
                                    </div>
                                    
                                    <h3 className="text-base font-black text-slate-800 tracking-tight mb-1">{label}</h3>
                                    <p className="text-slate-400 text-[8px] font-black   mb-4">Competencies</p>
                                    
                                    <div className="flex items-center gap-2">
                                        <div className="px-5 py-1.5 bg-slate-50 border border-slate-100 rounded-full text-[10px] font-black text-slate-600 transition-all group-hover:bg-indigo-600 group-hover:text-white group-hover:border-indigo-600">
                                            {catQuestions.length} Items
                                        </div>
                                    </div>
                                    
                                    <div className="absolute bottom-4 right-6 opacity-0 group-hover:opacity-100 transition-all translate-x-3 group-hover:translate-x-0">
                                        <span className="material-symbols-rounded text-indigo-600 text-xl font-black">arrow_right_alt</span>
                                    </div>
                                </div>
                            );
                        })}

                        {/* Blank Slate for Library */}
                        {questions.length === 0 && (
                            <div className="col-span-full bg-white rounded-2xl p-24 text-center border-2 border-dashed border-slate-100 shadow-inner">
                                <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                                    <span className="material-symbols-rounded text-slate-300 text-5xl">inventory_2</span>
                                </div>
                                <h3 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Vast Knowledge Base Initializing</h3>
                                <p className="text-slate-400 text-sm font-medium mb-12 max-w-sm mx-auto leading-relaxed">Your professional framework library is currently dormant. Use the AI generator above to populate it with high-fidelity questions.</p>
                            </div>
                        )}
                    </div>
                </main>
            </div>
        </div>
    </div>
);
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";
import { 
    Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, 
    ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, 
    Tooltip, Legend 
} from 'recharts';

interface CategoryScore {
    category: string;
    self_score: number | null;
    manager_score: number | null;
    peer_score: number | null;
    overall_average: number;
}

interface TextResponse {
    category: string;
    relation: string;
    question: string;
    answer: string;
}

interface Report {
    template_name: string;
    completed_assignments: number;
    total_assignments: number;
    category_scores: CategoryScore[];
    text_responses: TextResponse[];
}

interface ChartDataItem {
    subject: string;
    Self: number;
    Manager: number;
    Peers: number;
    Average: number;
    fullMark: number;
}

export default function X360ReportPage() {
    const { token } = useAuth();
    const router = useRouter();
    const params = useParams();
    const employeeId = params.employeeId as string;
    const cycleId = params.cycleId as string;

    const [report, setReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchReport = async () => {
            try {
                const res = await apiClient.get(`/api/v1/enterprise/x360/reports/${employeeId}/${cycleId}`);
                if (res.ok) {
                    setReport(await res.json());
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchReport();
    }, [employeeId, cycleId]);

    if (loading) return <div className="p-12 text-center text-slate-500 font-bold">Generating report...</div>;
    if (!report) return <div className="p-12 text-center text-rose-500 font-bold">Report not found.</div>;

    const chartData: ChartDataItem[] = report.category_scores.map((cs) => ({
        subject: cs.category,
        Self: cs.self_score || 0,
        Manager: cs.manager_score || 0,
        Peers: cs.peer_score || 0,
        Average: cs.overall_average || 0,
        fullMark: 5
    }));

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700">
            <div className="flex justify-between items-start">
                <div className="space-y-1">
                    <button onClick={() => router.back()} className="text-slate-400 hover:text-slate-600 transition-colors mb-2">
                        <span className="material-symbols-rounded">arrow_back</span>
                    </button>
                    <h1 className="text-4xl font-black text-slate-900 tracking-tight">360° Feedback Report</h1>
                    <p className="text-slate-500 font-bold  text-[10px] tracking-[0.2em]">Cycle: {report.template_name}</p>
                </div>
                <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl flex items-center gap-4">
                    <div className="text-right">
                        <p className="text-[10px] font-black text-emerald-600  ">Completion</p>
                        <p className="text-2xl font-black text-emerald-700">{Math.round((report.completed_assignments / report.total_assignments) * 100)}%</p>
                    </div>
                    <div className="w-px h-10 bg-emerald-200"></div>
                    <div>
                        <p className="text-xs font-bold text-slate-600">{report.completed_assignments} / {report.total_assignments}</p>
                        <p className="text-[10px] font-bold text-slate-400  tracking-tighter">Assignments</p>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Radar Chart */}
                <div className="bg-white p-8 rounded-xl border border-slate-100 shadow-sm h-[500px] flex flex-col">
                    <h3 className="font-black text-slate-800  text-xs  mb-6">Competency Overview</h3>
                    <div className="flex-1 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={chartData}>
                                <PolarGrid stroke="#e2e8f0" />
                                <PolarAngleAxis dataKey="subject" tick={{ fontSize: 10, fontWeight: 'bold' }} stroke="#64748b" />
                                <PolarRadiusAxis angle={30} domain={[0, 5]} stroke="#94a3b8" />
                                <Radar name="Self" dataKey="Self" stroke="#7C3AED" fill="#7C3AED" fillOpacity={0.4} />
                                <Radar name="Manager" dataKey="Manager" stroke="#F59E0B" fill="#F59E0B" fillOpacity={0.3} />
                                <Radar name="Average" dataKey="Average" stroke="#10B981" fill="#10B981" fillOpacity={0.3} />
                                <Legend wrapperStyle={{ paddingTop: '20px', fontSize: '10px', fontWeight: 'bold' }} />
                                <Tooltip />
                            </RadarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Score Summary Table */}
                <div className="bg-white p-8 rounded-xl border border-slate-100 shadow-sm flex flex-col">
                    <h3 className="font-black text-slate-800  text-xs  mb-6">Aggregate Scores</h3>
                    <div className="flex-1 overflow-x-auto">
                        <table className="w-full text-left">
                            <thead>
                                <tr className="text-[10px] font-black text-slate-400   border-b border-slate-50">
                                    <th className="py-4 px-2">Category</th>
                                    <th className="py-4 px-2 text-center">Self</th>
                                    <th className="py-4 px-2 text-center">Manager</th>
                                    <th className="py-4 px-2 text-center">Peers</th>
                                    <th className="py-4 px-2 text-center">Avg</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {report.category_scores.map((cs) => (
                                    <tr key={cs.category} className="hover:bg-slate-50 transition-colors">
                                        <td className="py-5 px-2 text-xs font-black text-slate-700  tracking-tighter">{cs.category}</td>
                                        <td className="py-5 px-2 text-center font-bold text-sm text-indigo-600">{cs.self_score?.toFixed(1) || '-'}</td>
                                        <td className="py-5 px-2 text-center font-bold text-sm text-orange-600">{cs.manager_score?.toFixed(1) || '-'}</td>
                                        <td className="py-5 px-2 text-center font-bold text-sm text-slate-600">{cs.peer_score?.toFixed(1) || '-'}</td>
                                        <td className="py-5 px-2 text-center font-black text-sm text-emerald-600">{cs.overall_average?.toFixed(1)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            {/* Qualitative Feedback */}
            <section className="space-y-6">
                <h2 className="text-2xl font-black text-slate-900 tracking-tight">Qualitative Insights</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {report.text_responses.length === 0 ? (
                        <p className="col-span-2 text-slate-400 font-bold  py-10 bg-white rounded-xl border border-dashed text-center">
                            No qualitative responses yet.
                        </p>
                    ) : (
                        report.text_responses.map((resp, idx) => (
                            <div key={idx} className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm space-y-3 hover:border-indigo-100 transition-all">
                                <div className="flex justify-between items-start">
                                    <span className="text-[10px] font-black  text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full">{resp.category}</span>
                                    <span className="text-[10px] font-black  text-slate-400 ">{resp.relation}</span>
                                </div>
                                <p className="text-[11px] font-black text-slate-400  tracking-tighter">Question: {resp.question}</p>
                                <p className="text-sm font-medium text-slate-700 leading-relaxed ">&quot;{resp.answer}&quot;</p>
                            </div>
                        ))
                    )}
                </div>
            </section>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";

interface Question {
    id: string;
    text: string;
    type: string;
    category: string;
}

interface AIQuestion {
    text: string;
    type: string;
    category: string;
}

export default function CreateX360Template() {
    const { token } = useAuth();
    const router = useRouter();
    const [questions, setQuestions] = useState<Question[]>([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    
    // AI Wizard State
    const [isAiWizardOpen, setIsAiWizardOpen] = useState(false);
    const [industryNature, setIndustryNature] = useState("");
    const [generatingAi, setGeneratingAi] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        name: "",
        description: "",
        question_ids: [] as string[]
    });

    useEffect(() => {
        fetchQuestions();
    }, []);

    const fetchQuestions = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            if (Array.isArray(data)) {
                setQuestions(data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const generateWithAi = async () => {
        if (!industryNature) return;
        setGeneratingAi(true);
        try {
            const genRes = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions/ai-generate`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    categories: ["PERFORMANCE", "LEADERSHIP", "CULTURE"],
                    count: 5,
                    additional_context: industryNature
                })
            });
            
            if (genRes.ok) {
                const aiQuestions: AIQuestion[] = await genRes.json();
                const newQuestionIds: string[] = [];
                
                for (const q of aiQuestions) {
                    const saveRes = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/questions`, {
                        method: 'POST',
                        headers: { 
                            'Authorization': `Bearer ${token}`,
                            'Content-Type': 'application/json'
                        },
                        body: JSON.stringify({
                            text: q.text,
                            type: q.type,
                            category: q.category
                        })
                    });
                    if (saveRes.ok) {
                        const savedQ = await saveRes.json();
                        newQuestionIds.push(savedQ.id);
                    }
                }
                
                setFormData(prev => ({
                    ...prev,
                    question_ids: [...new Set([...prev.question_ids, ...newQuestionIds])]
                }));
                fetchQuestions();
                setIsAiWizardOpen(false);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setGeneratingAi(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/x360/templates`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(formData)
            });
            if (res.ok) {
                router.push('/enterprise/assessments-360/templates');
            }
        } catch (error) {
            console.error(error);
        } finally {
            setSubmitting(false);
        }
    };

    const toggleQuestion = (id: string) => {
        setFormData(prev => {
            const ids = prev.question_ids.includes(id) 
                ? prev.question_ids.filter(q => q !== id)
                : [...prev.question_ids, id];
            return { ...prev, question_ids: ids };
        });
    };

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50">
            <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50/50">
            <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200 py-4 px-8 flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.push('/enterprise/assessments-360/templates')} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">
                        <span className="material-symbols-rounded">arrow_back</span>
                    </button>
                    <div>
                        <h1 className="text-xl font-bold text-slate-900 tracking-tight leading-none mb-1">Construct 360 Framework</h1>
                        <p className="text-slate-500 text-xs font-medium">Design professional competencies for organizational feedback</p>
                    </div>
                </div>
                <div className="flex gap-3">
                    <button 
                        onClick={() => router.push('/enterprise/assessments-360/templates')}
                        className="px-5 py-2.5 text-slate-600 font-semibold text-xs hover:bg-slate-100 rounded-xl transition-all"
                    >
                        Discard
                    </button>
                    <button 
                        onClick={handleSave}
                        disabled={submitting || formData.question_ids.length === 0}
                        className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-semibold text-xs hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100 disabled:opacity-50 disabled:shadow-none"
                    >
                        {submitting ? 'Deploying...' : 'Deploy Framework'}
                    </button>
                </div>
            </header>

            <main className="max-w-6xl mx-auto p-8 lg:p-12 space-y-12 animate-in fade-in duration-700">
                {/* Meta Config */}
                <section className="bg-white p-10 rounded-2xl border border-slate-100 shadow-2xl shadow-slate-200/50 space-y-10 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-full blur-3xl -mr-16 -mt-16"></div>
                    <div className="relative z-10 grid grid-cols-1 md:grid-cols-2 gap-10">
                        <div className="space-y-3">
                            <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] px-1">Framework Designation</label>
                            <input 
                                className="w-full px-6 py-4 bg-slate-50 border-2 border-transparent rounded-xl focus:border-indigo-500 focus:bg-white focus:ring-4 focus:ring-indigo-100 outline-none text-sm font-bold text-slate-700 placeholder:text-slate-300 transition-all h-[60px]"
                                value={formData.name}
                                onChange={(e) => setFormData({...formData, name: e.target.value})}
                                required
                                placeholder="e.g. Executive Leadership Quarterly"
                            />
                        </div>
                        <div className="space-y-3">
                            <label className="text-[10px] font-black text-slate-400  tracking-[0.2em] px-1">Strategic Objective</label>
                            <input 
                                className="w-full px-6 py-4 bg-slate-50 border-2 border-transparent rounded-xl focus:border-indigo-500 focus:bg-white focus:ring-4 focus:ring-indigo-100 outline-none text-sm font-bold text-slate-700 placeholder:text-slate-300 transition-all h-[60px]"
                                value={formData.description}
                                onChange={(e) => setFormData({...formData, description: e.target.value})}
                                placeholder="Define the core purpose of this assessment..."
                            />
                        </div>
                    </div>
                </section>

                {/* Selection Pool - Grouped by Category */}
                <section className="space-y-10">
                    <div className="flex justify-between items-center px-2">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-xl">
                                <span className="material-symbols-rounded">account_tree</span>
                            </div>
                            <div>
                                <h3 className="text-xl font-black text-slate-900 tracking-tight">Competency Architecture</h3>
                                <p className="text-slate-500 text-[10px] font-bold   mt-0.5">Select questions by category for a balanced assessment</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4">
                            <div className="flex flex-col items-end">
                                <span className="text-[10px] font-black text-indigo-600   leading-none mb-1">Total Selected</span>
                                <span className="text-2xl font-black text-slate-900 leading-none">{formData.question_ids.length}</span>
                            </div>
                            <button 
                                type="button"
                                onClick={() => setIsAiWizardOpen(true)}
                                className="h-14 bg-indigo-600 text-white text-[11px] font-black  tracking-[0.15em] flex items-center gap-3 hover:bg-slate-900 px-8 rounded-xl transition-all shadow-xl shadow-indigo-100 group"
                            >
                                <span className="material-symbols-rounded text-xl group-hover:rotate-12 transition-transform">psychology</span>
                                Strategy Wizard
                            </button>
                        </div>
                    </div>
                    
                    <div className="space-y-16">
                        {Array.from(new Set(questions.map(q => q.category))).sort().map(cat => {
                            const catQuestions = questions.filter(q => q.category === cat);
                            const selectedInCat = catQuestions.filter(q => formData.question_ids.includes(q.id)).length;
                            
                            return (
                                <div key={cat} className="space-y-6">
                                    <div className="sticky top-20 z-20 flex justify-between items-end pb-4 border-b-2 border-slate-100 bg-[#f8fafc]/80 backdrop-blur-sm -mx-4 px-4 pt-2">
                                        <div className="flex items-center gap-4">
                                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-xs transition-all ${selectedInCat > 0 ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'bg-slate-100 text-slate-400'}`}>
                                                {selectedInCat}
                                            </div>
                                            <div>
                                                <h4 className="text-lg font-black text-slate-800 tracking-tight">{cat.replace(/_/g, ' ')}</h4>
                                                <p className="text-slate-400 text-[9px] font-bold  tracking-[0.2em]">{catQuestions.length} Total Options</p>
                                            </div>
                                        </div>
                                        {selectedInCat > 0 && (
                                            <span className="text-[10px] font-black text-indigo-600   animate-in fade-in slide-in-from-right-2">
                                                {selectedInCat} Competencies Chosen
                                            </span>
                                        )}
                                    </div>
                                    
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                        {catQuestions.map(q => (
                                            <div 
                                                key={q.id} 
                                                onClick={() => toggleQuestion(q.id)}
                                                className={`p-6 rounded-xl cursor-pointer transition-all flex flex-col gap-4 border-2 relative group animate-in slide-in-from-bottom-2 duration-500 overflow-hidden ${
                                                    formData.question_ids.includes(q.id) 
                                                    ? 'border-indigo-600 bg-white shadow-2xl shadow-indigo-100' 
                                                    : 'border-white bg-white shadow-sm hover:border-slate-200 hover:shadow-xl'
                                                }`}
                                            >
                                                {formData.question_ids.includes(q.id) && (
                                                    <div className="absolute top-0 right-0 w-16 h-16 bg-indigo-600 flex items-center justify-center translate-x-8 -translate-y-8 rotate-45 shadow-lg">
                                                        <span className="material-symbols-rounded text-white -rotate-45 mt-6 mr-1 text-sm font-black">check</span>
                                                    </div>
                                                )}
                                                <div className="flex-1">
                                                    <p className={`text-sm font-bold leading-relaxed transition-colors ${formData.question_ids.includes(q.id) ? 'text-indigo-900' : 'text-slate-600'}`}>
                                                        {q.text}
                                                    </p>
                                                </div>
                                                <div className="flex justify-between items-center pt-2 border-t border-slate-50 mt-auto">
                                                    <span className="text-[9px] font-black  text-slate-400 ">{q.type}</span>
                                                    <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${formData.question_ids.includes(q.id) ? 'bg-indigo-50 border-indigo-200 text-indigo-600' : 'bg-slate-50 border-slate-100 text-transparent group-hover:border-slate-300'}`}>
                                                        <span className="material-symbols-rounded text-base font-black">check</span>
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </section>

                <div className="pt-20 flex flex-col items-center border-t border-slate-200 pb-32">
                    <div className="flex flex-col items-center mb-10 text-center max-w-sm">
                        <p className="text-[10px] font-black text-slate-400  tracking-[0.3em] mb-4">Framework Readiness</p>
                        <h4 className="text-2xl font-black text-slate-900 mb-2">{formData.question_ids.length} Questions Selected</h4>
                        <p className="text-slate-500 text-xs font-medium">Review your competency mix above before deploying to your organization.</p>
                    </div>
                    <button 
                        onClick={handleSave}
                        disabled={submitting || formData.question_ids.length === 0}
                        className="h-20 px-24 bg-indigo-600 text-white rounded-2xl font-black text-sm  tracking-[0.25em] shadow-[0_20px_50px_rgba(79,70,229,0.3)] hover:bg-slate-900 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-30 disabled:shadow-none flex items-center justify-center gap-4"
                    >
                        {submitting ? (
                            <>
                                <div className="w-5 h-5 border-3 border-white border-t-transparent rounded-full animate-spin"></div>
                                Sequencing...
                            </>
                        ) : (
                            <>
                                <span className="material-symbols-rounded text-2xl">rocket_launch</span>
                                Deploy Assessment Framework
                            </>
                        )}
                    </button>
                </div>
            </main>

            {/* AI Wizard Modal */}
            {isAiWizardOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white rounded-xl w-full max-w-md shadow-2xl overflow-hidden animate-in zoom-in duration-200">
                        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                            <div className="flex items-center gap-3">
                                <span className="material-symbols-rounded text-indigo-600">psychology</span>
                                <h2 className="text-lg font-bold text-slate-900">AI Strategy Wizard</h2>
                            </div>
                            <button onClick={() => setIsAiWizardOpen(false)} className="text-slate-400 hover:text-rose-500 transition-colors">
                                <span className="material-symbols-rounded">close</span>
                            </button>
                        </div>
                        <div className="p-8 space-y-6">
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-400   px-1">Industry for Context</label>
                                <input 
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-semibold text-slate-700 transition-all h-[52px]"
                                    value={industryNature}
                                    onChange={(e) => setIndustryNature(e.target.value)}
                                    placeholder="e.g. Fintech, Manufacturing..."
                                    autoFocus
                                />
                                <p className="text-[10px] text-slate-400 font-medium px-1 ">Generated items will be calibrated for this segment.</p>
                            </div>
                            <button 
                                onClick={generateWithAi}
                                disabled={generatingAi || !industryNature}
                                className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold text-xs   flex items-center justify-center gap-2 hover:bg-indigo-600 transition-all disabled:opacity-30 shadow-md"
                            >
                                {generatingAi ? (
                                    <>
                                        <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                        Generating...
                                    </>
                                ) : (
                                    <>
                                        <span className="material-symbols-rounded text-lg">magic_button</span>
                                        Inject AI Insights
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import React, { useState, useEffect, useMemo, useCallback } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { AnimatePresence, motion } from "framer-motion";

interface WorkflowStage {
  name: string;
  stage?: number;
  order?: number;
}

interface Job {
  id: string;
  title: string;
  workflow_stages?: WorkflowStage[] | null;
}

interface Question {
  id?: string;
  type?: string;
  question?: string;
  options?: string[];
  correct_answer?: string;
  explanation?: string;
  title?: string;
  problem_statement?: string;
  difficulty?: string;
}

interface FormState {
  job_requirement_id: string;
  stage_index: number;
  stage_name: string;
  is_enabled: boolean;
  auto_move: boolean;
  is_immediate: boolean;
  send_at: string;
  criteria: string;
  template_id: string;
  email_template_id: string;
  assessment_type: string;
  topic: string;
  question_count: number;
  test_duration: number;
  generated_questions: Question[] | null;
  start_time: string;
  end_time: string;
  duration: string;
  daily_limit: number;
  interviewer_email: string;
  time_slots: string[];
  start_date: string;
  end_date: string;
  google_meet_link: string;
  interview_type: string;
  interview_template_id: string;
}

interface Template {
  id: string;
  name: string;
}

interface AutomationNodeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: () => void;
  jobId: string;
  jobs: Job[];
  type: "mail" | "assessment" | "interview" | "onboarding";
  editingId?: string | null;
  initialData?: Partial<FormState> | null;
}

export default function AutomationNodeModal({
  isOpen,
  onClose,
  onSave,
  jobId,
  jobs,
  type,
  editingId = null,
  initialData = null,
}: AutomationNodeModalProps) {
  const { token } = useAuth();
  const authHeaders = useMemo(() => ({
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  }), [token]);

  const EMPTY_FORM: FormState = {
    job_requirement_id: jobId,
    stage_index: 0,
    stage_name: "",
    is_enabled: true,
    auto_move: false,
    is_immediate: true,
    send_at: "",
    criteria: "",
    template_id: "",
    email_template_id: "",
    assessment_type: "APTITUDE",
    topic: "",
    question_count: 10,
    test_duration: 30,
    generated_questions: null,
    start_time: "09:00",
    end_time: "17:00",
    duration: "30",
    daily_limit: 5,
    interviewer_email: "",
    time_slots: [],
    start_date: "",
    end_date: "",
    google_meet_link: "",
    interview_type: "GMEET",
    interview_template_id: "",
  };

  // Unified Form State
  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [activeTab, setActiveTab] = useState<"config" | "sub">("config");

  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  // Template States
  const [emailTemplates, setEmailTemplates] = useState<Template[]>([]);
  const [onboardingTemplates, setOnboardingTemplates] = useState<Template[]>([]);
  const [assessmentTemplates, setAssessmentTemplates] = useState<Template[]>([]);
  const [interviewTemplates, setInterviewTemplates] = useState<Template[]>([]);

  const fetchMeta = useCallback(async () => {
    if (!token) return;
    try {
      const eRes = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates/`, { headers: authHeaders });
      if (eRes.ok) setEmailTemplates(await eRes.json());

      if (type === "onboarding") {
        const oRes = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/`, { headers: authHeaders });
        if (oRes.ok) setOnboardingTemplates(await oRes.json());
      }
      if (type === "assessment") {
        const aRes = await fetch(`${BACKEND_URL}/api/v1/enterprise/assessment-templates/`, { headers: authHeaders });
        if (aRes.ok) setAssessmentTemplates(await aRes.json());
      }
      if (type === "interview") {
        const iRes = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-templates/`, { headers: authHeaders });
        if (iRes.ok) setInterviewTemplates(await iRes.json());
      }
    } catch (err) {
      console.error("Meta fetch error:", err);
    }
  }, [token, authHeaders, type]);

  useEffect(() => {
    if (isOpen) {
      if (editingId && initialData) {
        setForm({
          ...EMPTY_FORM,
          ...initialData,
          job_requirement_id: initialData.job_requirement_id,
          // If it's an assessment, 'type' contains 'APTITUDE', 'CODING', etc.
          assessment_type: initialData.type || "APTITUDE",
          send_at: initialData.send_at ? new Date(initialData.send_at).toISOString().slice(0, 16) : "",
          template_id: initialData.template_id || "",
          email_template_id: initialData.email_template_id || "",
          criteria: initialData.criteria || "",
          generated_questions: initialData.generated_questions || null,
          time_slots: initialData.time_slots || [],
        });
      } else {
        setForm({ ...EMPTY_FORM, job_requirement_id: jobId });
      }
      setActiveTab("config");
      fetchMeta();
    }
  }, [isOpen, editingId, initialData, jobId, fetchMeta]);

  // Assessment Question Generation
  const handleGeneratePreview = async () => {
    if (!form.topic?.trim()) {
      showToast("Please enter a topic for the assessment.", "error");
      return;
    }

    if (!form.is_immediate && form.send_at) {
      if (new Date(form.send_at) < new Date()) {
        showToast("Scheduled time cannot be in the past.", "error");
        return;
      }
    }
    setLoading(true);
    try {
      const qs = `type=${form.assessment_type}&topic=${encodeURIComponent(form.topic)}&count=${form.question_count}`;
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/assessment/generate-preview?${qs}`, {
        method: "POST",
        headers: authHeaders,
      });
      if (res.ok) {
        const questions = await res.json();
        setForm((f: FormState) => ({ ...f, generated_questions: questions }));
        setActiveTab("sub"); // Switch to questions tab
        showToast("Questions generated! Please review questions.");
      } else {
        showToast("Failed to generate questions.", "error");
      }
    } finally {
      setLoading(false);
    }
  };

  // Interview Slot Generation
  const handleGenerateTimeSlots = () => {
    const limit = Number(form.daily_limit);
    if (!limit || limit <= 0) {
      showToast("Please set a daily limit > 0", "error");
      return;
    }
    const [sh, sm] = form.start_time.split(":").map(Number);
    const [eh, em] = form.end_time.split(":").map(Number);
    const startMins = sh * 60 + sm;
    const endMins = eh * 60 + em;
    if (startMins >= endMins) {
      showToast("End time must be after start time", "error");
      return;
    }
    const interval = Number(form.duration) || 30;
    const slots: string[] = [];
    for (let i = 0; i < limit; i++) {
        const slotMins = startMins + i * interval;
        if (slotMins + interval > endMins) break;
        const h = Math.floor(slotMins / 60).toString().padStart(2, "0");
        const m = (slotMins % 60).toString().padStart(2, "0");
        slots.push(`${h}:${m}`);
    }
    setForm((f: FormState) => ({ ...f, time_slots: slots }));
    setActiveTab("sub"); // Switch to slots tab
    showToast("Time slots generated!");
  };

  const showToast = (msg: string, type: "success" | "error" = "success") => {
    let finalMsg = "";
    if (typeof msg === "string") {
      finalMsg = msg;
    } else if (Array.isArray(msg)) {
      finalMsg = msg.map((e: { msg?: string } | string) => (typeof e === 'object' ? e.msg : e) || JSON.stringify(e)).join(", ");
    } else if (msg && typeof msg === "object") {
      finalMsg = msg.msg || msg.detail || JSON.stringify(msg);
    } else {
      finalMsg = String(msg || "An error occurred");
    }
    setToast({ msg: finalMsg, type });
    setTimeout(() => setToast(null), 5000);
  };

  const selectedJob = jobs.find((j) => j.id === form.job_requirement_id);
  const jobRounds: WorkflowStage[] = selectedJob?.workflow_stages ?? [];

  const roundValue = useMemo(() => {
    if (!form.stage_index) return "";
    const currentName = form.stage_name || "";
    const match = jobRounds.find((r, i) => (i + 1) === Number(form.stage_index) && r.name === currentName);
    if (match) return `${form.stage_index}|${currentName}`;
    const indexMatch = jobRounds.find((r, i) => (i + 1) === Number(form.stage_index));
    if (indexMatch) return `${form.stage_index}|${indexMatch.name}`;
    return "";
  }, [form.stage_index, form.stage_name, jobRounds]);

  const handleRoundSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    if (!val) {
      setForm((f: FormState) => ({ ...f, stage_index: 0, stage_name: "" }));
      return;
    };
    const [idxStr, ...nameParts] = val.split("|");
    setForm((f: FormState) => ({ ...f, stage_index: Number(idxStr), stage_name: nameParts.join("|") }));
  };

  const handleSave = async () => {
    if (!form.job_requirement_id || form.job_requirement_id === "undefined") {
      showToast("Please select a target job.", "error");
      return;
    }

    if (type !== 'onboarding' && (!form.criteria || !form.criteria.trim())) {
      showToast("Please fill in trigger condition.", "error");
      return;
    }
    if (type === "interview") {
      const now = new Date();
      now.setHours(0, 0, 0, 0);
      if (new Date(form.start_date) < now) {
        showToast("Start date cannot be in the past.", "error");
        return;
      }
      if (new Date(form.start_date) > new Date(form.end_date)) {
        showToast("Available To date must be equal or after Available From date.", "error");
        return;
      }
      if (form.interview_type === "AI" && !form.interview_template_id) {
        showToast("Please select an AI template.", "error");
        return;
      }
      if (form.interview_type === "GMEET" && !form.interviewer_email?.trim()) {
        showToast("Please provide interviewer email for Google Meet.", "error");
        return;
      }
    }

    if (!form.is_immediate && form.send_at) {
      if (new Date(form.send_at) < new Date()) {
        showToast("Scheduled time cannot be in the past.", "error");
        return;
      }
    }

    setSaving(true);
    try {
      let endpoint = "";
      let payload: Record<string, unknown> = {
        job_requirement_id: form.job_requirement_id,
        stage_index: Number(form.stage_index),
        stage_name: form.stage_name.trim() || null,
        is_enabled: form.is_enabled,
      };

      if (type === "mail") {
        if (!form.template_id) throw new Error("Template is required.");
        endpoint = editingId ? `/api/v1/enterprise/automation/mail/${editingId}` : "/api/v1/enterprise/automation/mail/";
        payload = { 
          ...payload, 
          criteria: form.criteria, 
          template_id: form.template_id, 
          auto_move: form.auto_move, 
          is_immediate: form.is_immediate, 
          send_at: form.is_immediate || !form.send_at ? null : new Date(form.send_at).toISOString() 
        };
      } 
      else if (type === "assessment") {
        if (!form.topic.trim()) throw new Error("Topic is required.");
        endpoint = editingId ? `/api/v1/enterprise/assessment/${editingId}` : "/api/v1/enterprise/assessment/";
        payload = { 
          ...payload, 
          criteria: form.criteria || "Assessment Trigger", 
          type: form.assessment_type, 
          topic: form.topic, 
          question_count: Number(form.question_count), 
          test_duration: Number(form.test_duration), 
          email_template_id: form.email_template_id || null, 
          is_immediate: form.is_immediate, 
          auto_move: form.auto_move, 
          send_at: form.is_immediate || !form.send_at ? null : new Date(form.send_at).toISOString(),
          template_id: form.template_id || null,
          generated_questions: form.generated_questions || null 
        };
      } 
      else if (type === "interview") {
        let finalTimeSlots = form.time_slots || [];
        if (finalTimeSlots.length === 0) {
          const limit = Number(form.daily_limit);
          if (limit > 0 && form.start_time && form.end_time) {
            const [sh, sm] = form.start_time.split(":").map(Number);
            const [eh, em] = form.end_time.split(":").map(Number);
            const startMins = sh * 60 + sm;
            const endMins = eh * 60 + em;
            const interval = Number(form.duration) || 30;
            
            if (startMins < endMins) {
              const generated: string[] = [];
              for (let i = 0; i < limit; i++) {
                const slotMins = startMins + i * interval;
                if (slotMins + interval > endMins) break;
                const h = Math.floor(slotMins / 60).toString().padStart(2, "0");
                const m = (slotMins % 60).toString().padStart(2, "0");
                generated.push(`${h}:${m}`);
              }
              finalTimeSlots = generated;
            }
          }
        }

        endpoint = editingId ? `/api/v1/enterprise/interview-automation/${editingId}` : "/api/v1/enterprise/interview-automation/";
        payload = { 
          ...payload, 
          criteria: form.criteria || "Interview Trigger", 
          email_template_id: form.email_template_id || null, 
          auto_move: form.auto_move, 
          duration: Number(form.duration) || 30, 
          daily_limit: Number(form.daily_limit), 
          interviewer_email: form.interviewer_email?.trim() || null, 
          google_meet_link: form.google_meet_link?.trim() || null, 
          start_date: form.start_date || null, 
          end_date: form.end_date || null, 
          start_time: form.start_time,
          end_time: form.end_time,
          time_slots: finalTimeSlots.length > 0 ? finalTimeSlots : null,
          interview_type: form.interview_type, 
          interview_template_id: form.interview_type === "AI" ? form.interview_template_id : null 
        };
      } 
      else if (type === "onboarding") {
        if (!form.template_id) throw new Error("Onboarding Template is required.");
        endpoint = editingId ? `/api/v1/enterprise/onboarding-automation/${editingId}` : "/api/v1/enterprise/onboarding-automation/";
        payload = { 
          ...payload, 
          template_id: form.template_id, 
          email_template_id: form.email_template_id || null,
          auto_move: form.auto_move
        };
      }

      const res = await fetch(`${BACKEND_URL}${endpoint}`, {
        method: editingId ? "PATCH" : "POST",
        headers: authHeaders,
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        showToast(editingId ? "Automation Updated!" : "Automation Created!");
        setTimeout(() => {
          onSave();
          onClose();
        }, 800);
      } else {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.detail || "Failed to create automation.");
      }
    } catch (err) {
      const error = err as Error;
      showToast(error.message || "An error occurred", "error");
    } finally {
      setSaving(false);
    }
  };

  const headerMeta = useMemo(() => {
    switch (type) {
      case "mail": return { title: "Mail Action", icon: "mark_email_unread", color: "#6366f1", bg: "#eef2ff" };
      case "assessment": return { title: "Assessment Action", icon: "psychology", color: "#f59e0b", bg: "#fffbeb" };
      case "interview": return { title: "Interview Action", icon: "event_available", color: "#10b981", bg: "#ecfdf5" };
      case "onboarding": return { title: "Onboarding Action", icon: "person_add", color: "#a855f7", bg: "#faf5ff" };
    }
  }, [type]);

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[200] flex justify-end">
          {toast && (
            <div className={`fixed top-5 right-5 z-[500] flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg text-sm font-semibold transition-all duration-300 ${toast.type === "success" ? "bg-emerald-500 text-white" : "bg-red-500 text-white"}`}>
              <span className="material-symbols-rounded text-base">{toast.type === "success" ? "check_circle" : "error"}</span>
              {String(toast.msg)}
            </div>
          )}
          
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px]" onClick={onClose} />
          <motion.div initial={{ x: "100%" }} animate={{ x: 0 }} exit={{ x: "100%" }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="relative w-full max-w-lg bg-white shadow-2xl h-full flex flex-col pointer-events-auto">
            
            {/* Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 shrink-0 bg-white">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm" style={{ backgroundColor: headerMeta.bg, color: headerMeta.color }}>
                  <span className="material-symbols-rounded text-xl">{headerMeta.icon}</span>
                </div>
                <div>
                  <h2 className="text-lg font-black text-slate-800 leading-tight">{editingId ? "Edit Action" : "Create Action"}</h2>
                  <p className="text-[10px] font-bold   mt-0.5" style={{ color: headerMeta.color }}>{headerMeta.title}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={onClose} className="w-9 h-9 rounded-xl hover:bg-slate-100 flex items-center justify-center text-slate-400 transition-colors">
                  <span className="material-symbols-rounded text-xl">close</span>
                </button>
              </div>
            </div>

            {/* Tabs (Only for Assessment/Interview) */}
            {(type === "assessment" || type === "interview") && (
              <div className="flex border-b border-slate-100 shrink-0 bg-white px-6">
                <button
                  onClick={() => setActiveTab("config")}
                  className={`px-6 py-3 text-[10px] font-black   transition-all border-b-2 ${activeTab === "config" ? "border-[#7C3AED] text-[#7C3AED]" : "border-transparent text-slate-400 hover:text-slate-600"}`}
                >
                  1. Configuration
                </button>
                <button
                  onClick={() => setActiveTab("sub")}
                  className={`px-6 py-3 text-[10px] font-black   transition-all border-b-2 ${activeTab === "sub" ? "border-[#7C3AED] text-[#7C3AED]" : "border-transparent text-slate-400 hover:text-slate-600"}`}
                >
                  2. {type === "assessment" ? `Questions (${form.generated_questions?.length || 0})` : `Time Slots (${form.time_slots?.length || 0})`}
                </button>
              </div>
            )}

            <div className="relative flex-1 overflow-y-auto px-6 py-6 space-y-6 custom-scrollbar bg-white">
              <AnimatePresence mode="wait">
                <motion.div
                  key={activeTab}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.2 }}
                  className="space-y-6"
                >
              {activeTab === "config" ? (
                <>
                  {loading && (
                    <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-[1px] flex items-center justify-center">
                      <div className="flex flex-col items-center gap-2">
                        <div className="w-8 h-8 border-4 border-slate-200 border-t-[#7C3AED] rounded-full animate-spin" />
                        <p className="text-[10px] font-black text-slate-400  ">Loading data...</p>
                      </div>
                    </div>
                  )}
                  {/* Job Info */}
                  <div className="opacity-70">
                    <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Target Job</label>
                    <div className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold text-slate-600">
                      {selectedJob?.title || "No Job Selected"}
                    </div>
                  </div>

                  {/* Round Selection */}
                  <div>
                    <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Connect to Round <span className="text-red-400">*</span></label>
                    {jobRounds.length > 0 ? (
                      <select 
                        value={roundValue} 
                        onChange={handleRoundSelect} 
                        className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all shadow-sm"
                      >
                        <option value="" className="text-slate-900 bg-white">Select a stage...</option>
                        {jobRounds.map((r, i) => <option key={i} value={`${i + 1}|${r.name}`} className="text-slate-900 bg-white">Stage {i + 1}: {r.name}</option>)}
                      </select>
                    ) : (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="number" min={1} value={form.stage_index || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, stage_index: Number(e.target.value) }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold" placeholder="Idx" />
                        <input type="text" value={form.stage_name || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, stage_name: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold" placeholder="Stage Name" />
                      </div>
                    )}
                  </div>

                  {/* Trigger Criteria */}
                  {type !== "onboarding" && (
                    <div>
                      <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Trigger Condition {type === "mail" && <span className="text-red-400">*</span>}</label>
                      <textarea 
                        value={form.criteria || ""} 
                        onChange={(e) => setForm((f: FormState) => ({ ...f, criteria: e.target.value }))} 
                        className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 transition-all resize-none" 
                        rows={3}
                        placeholder="e.g. 'Score > 80' or 'Shortlisted'" 
                      />
                      <p className="text-[10px] text-slate-400 mt-1.5 ml-1">Clear conditions help trigger the automation correctly.</p>
                    </div>
                  )}

                  {/* ACTION SPECIFIC FIELDS */}
                  <div className="space-y-6 pt-2">
                    
                    {/* MAIL Action */}
                    {type === "mail" && (
                      <div>
                        <label className="block text-[10px] font-black text-indigo-500   mb-1.5 ml-1">Email Template <span className="text-red-400">*</span></label>
                        <select value={form.template_id || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, template_id: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white shadow-sm">
                          <option value="" className="text-slate-900 bg-white">Select template…</option>
                          {emailTemplates.map((t: Template) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                        </select>
                      </div>
                    )}

                    {/* ASSESSMENT Action */}
                    {type === "assessment" && (
                      <>
                        <div className="bg-amber-50/50 p-4 rounded-xl border border-amber-100 shadow-sm">
                          <label className="block text-[10px] font-black text-amber-600   mb-2 ml-1">Use Template (Optional)</label>
                          <select 
                            value={form.template_id || ""}
                            onChange={(e) => {
                              const templateId = e.target.value;
                              if (templateId) {
                                const templ = assessmentTemplates.find(t => t.id === templateId);
                                if (templ) {
                                  setForm((f: FormState) => ({ ...f, template_id: templateId, assessment_type: templ.type as string, topic: templ.topic as string, question_count: templ.question_count as number, test_duration: templ.test_duration as number }));
                                } else {
                                  setForm((f: FormState) => ({ ...f, template_id: "" }));
                                }
                              } else {
                                setForm((f: FormState) => ({ ...f, template_id: "" }));
                              }
                            }}
                            className="w-full border border-amber-200 rounded-xl px-4 py-2 text-sm font-bold text-slate-700 bg-white"
                          >
                            <option value="" className="text-slate-900 bg-white">-- Custom Config --</option>
                            {assessmentTemplates.map((t) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                          </select>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Type</label>
                            <select value={form.assessment_type || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, assessment_type: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm font-bold text-slate-900 bg-white">
                              <option value="APTITUDE" className="text-slate-900 bg-white">Aptitude</option>
                              <option value="CODING" className="text-slate-900 bg-white">Coding</option>
                              <option value="BOTH" className="text-slate-900 bg-white">Both</option>
                            </select>
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Topic <span className="text-red-400">*</span></label>
                            <input type="text" value={form.topic || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, topic: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm font-bold text-slate-700" placeholder="e.g. Python, SQL" />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Questions</label>
                            <input type="number" value={form.question_count || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, question_count: Number(e.target.value) }))} className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Duration (Min)</label>
                            <input type="number" value={form.test_duration || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, test_duration: Number(e.target.value) }))} className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm" />
                          </div>
                        </div>

                        <div>
                          <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Invite Email Template</label>
                          <select value={form.email_template_id || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, email_template_id: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white">
                            <option value="" className="text-slate-900 bg-white">Default Invite Email</option>
                            {emailTemplates.map((t: Template) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                          </select>
                        </div>

                        <div className="pt-2">
                          <button
                            onClick={handleGeneratePreview}
                            disabled={loading}
                            className="w-full py-3 bg-[#7C3AED] text-white rounded-xl text-[10px] font-black   hover:bg-[#6d28d9] shadow-lg shadow-[#7C3AED]/20 active:scale-95 transition-all flex items-center justify-center gap-2 border border-[#7C3AED]/20 disabled:opacity-50"
                          >
                             {loading ? (
                               <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                             ) : (
                               <span className="material-symbols-rounded text-lg">auto_awesome</span>
                             )}
                             {form.generated_questions?.length ? "Regenerate Draft with AI" : "Draft Questions with AI"}
                          </button>
                        </div>
                      </>
                    )}

                    {/* INTERVIEW Action */}
                    {type === "interview" && (
                      <>
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-emerald-600   mb-1.5 ml-1">Interview Type</label>
                            <select value={form.interview_type || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, interview_type: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white">
                              <option value="GMEET" className="text-slate-900 bg-white">Google Meet</option>
                              <option value="AI" className="text-slate-900 bg-white">AI Interview</option>
                            </select>
                          </div>
                          {form.interview_type === "AI" && (
                            <div>
                               <div className="flex items-center justify-between mb-1.5 ml-1">
                                 <label className="block text-[10px] font-black text-emerald-600  ">AI Template</label>
                                 <button 
                                   onClick={() => window.open('/enterprise/settings/interview-templates', '_blank')}
                                   className="text-[10px] font-bold text-[#7C3AED] hover:underline "
                                 >
                                   + Create New
                                 </button>
                               </div>
                              <select value={form.interview_template_id || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, interview_template_id: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white">
                                <option value="" className="text-slate-900 bg-white">Select AI Template</option>
                                {interviewTemplates.map((t: Template) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                              </select>
                            </div>
                          )}
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Available From <span className="text-red-400">*</span></label>
                            <input type="date" value={form.start_date || ""} min={new Date().toISOString().split('T')[0]} onChange={(e) => setForm((f: FormState) => ({ ...f, start_date: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-[#7C3AED]/20 focus:border-[#7C3AED]" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Available To <span className="text-red-400">*</span></label>
                            <input type="date" value={form.end_date || ""} min={form.start_date || new Date().toISOString().split('T')[0]} onChange={(e) => setForm((f: FormState) => ({ ...f, end_date: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-[#7C3AED]/20 focus:border-[#7C3AED]" />
                          </div>
                        </div>

                        <div className="grid grid-cols-4 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Start Time <span className="text-red-400">*</span></label>
                            <input type="time" value={form.start_time || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, start_time: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-3 py-3 text-sm focus:ring-[#7C3AED]/20 focus:border-[#7C3AED]" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">End Time <span className="text-red-400">*</span></label>
                            <input type="time" value={form.end_time || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, end_time: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-3 py-3 text-sm focus:ring-[#7C3AED]/20 focus:border-[#7C3AED]" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Duration <span className="text-red-400">*</span></label>
                            <select value={form.duration || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, duration: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-2 py-3 text-sm font-bold text-slate-900 bg-white focus:ring-[#7C3AED]/20 focus:border-[#7C3AED]">
                              <option value="15" className="text-slate-900 bg-white">15m</option>
                              <option value="30" className="text-slate-900 bg-white">30m</option>
                              <option value="45" className="text-slate-900 bg-white">45m</option>
                              <option value="60" className="text-slate-900 bg-white">60m</option>
                            </select>
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Daily Limit <span className="text-red-400">*</span></label>
                            <input type="number" min={1} value={form.daily_limit || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, daily_limit: Number(e.target.value) }))} className="w-full border border-slate-200 rounded-xl px-3 py-3 text-sm focus:ring-[#7C3AED]/20 focus:border-[#7C3AED]" />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Interviewer Email</label>
                            <input 
                              type="email" 
                              value={form.interviewer_email || ""} 
                              onChange={(e) => setForm((f: FormState) => ({ ...f, interviewer_email: e.target.value }))} 
                              className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm" 
                              placeholder="johndoe@email.com" 
                            />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Invite Template</label>
                            <select value={form.email_template_id || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, email_template_id: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white">
                              <option value="" className="text-slate-900 bg-white">Default Invite</option>
                              {emailTemplates.map((t: Template) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                            </select>
                          </div>
                        </div>
                        <div className="pt-2">
                           <button
                             onClick={handleGenerateTimeSlots}
                             className="w-full py-3 bg-[#7C3AED] text-white rounded-xl text-[10px] font-black   hover:bg-[#6d28d9] shadow-lg shadow-[#7C3AED]/20 active:scale-95 transition-all flex items-center justify-center gap-2 border border-[#7C3AED]/20"
                           >
                              <span className="material-symbols-rounded text-lg">schedule</span>
                              Next: Configure Time Slots
                           </button>
                        </div>
                      </>
                    )}

                    {/* ONBOARDING Action */}
                    {type === "onboarding" && (
                      <>
                        <div>
                          <label className="block text-[10px] font-black text-purple-600   mb-1.5 ml-1">Onboarding Template <span className="text-red-400">*</span></label>
                          <select value={form.template_id || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, template_id: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white">
                            <option value="" className="text-slate-900 bg-white">Select template…</option>
                            {onboardingTemplates.map((t: Template) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                          </select>
                        </div>
                        <div>
                          <label className="block text-[10px] font-black text-purple-600   mb-1.5 ml-1">Intro Email Template</label>
                          <select value={form.email_template_id || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, email_template_id: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-900 bg-white">
                            <option value="" className="text-slate-900 bg-white">No Intro Email</option>
                            {emailTemplates.map((t: Template) => <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>)}
                          </select>
                        </div>
                      </>
                    )}
                  </div>

                  {/* AUTOMATION SETTINGS (Common) */}
                  <div className="pt-8 border-t border-slate-100 flex flex-col gap-4">
                    <span className="block text-[10px] font-black text-slate-400   mb-2 ml-1">Automation Logic</span>
                    
                    <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-xl">
                        <div>
                          <p className="text-sm font-bold text-slate-800">Enabled Status</p>
                          <p className="text-[10px] text-slate-400">This action will trigger automations</p>
                        </div>
                        <button onClick={() => setForm((f: FormState) => ({ ...f, is_enabled: !f.is_enabled }))} className={`relative w-11 h-6 rounded-full transition-all duration-300 ${form.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"}`}>
                          <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-md transition-all duration-300 ${form.is_enabled ? "translate-x-5" : ""}`} />
                        </button>
                    </div>

                    {(type === "mail" || type === "assessment" || type === "interview" || type === "onboarding") && (
                      <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-xl">
                          <div>
                            <p className="text-sm font-bold text-slate-800">Auto-Move Candidate</p>
                            <p className="text-[10px] text-slate-400">Automatically advance candidate after trigger</p>
                          </div>
                          <button onClick={() => setForm((f: FormState) => ({ ...f, auto_move: !f.auto_move }))} className={`relative w-11 h-6 rounded-full transition-all duration-300 ${form.auto_move ? "bg-[#7C3AED]" : "bg-slate-200"}`}>
                            <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-md transition-all duration-300 ${form.auto_move ? "translate-x-5" : ""}`} />
                          </button>
                      </div>
                    )}

                    {(type === "mail" || type === "assessment") && (
                      <div className="space-y-4">
                        <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-xl">
                            <div>
                              <p className="text-sm font-bold text-slate-800">Schedule Mode</p>
                              <p className="text-[10px] text-slate-400">{form.is_immediate ? "Immediate execution" : "Scheduled execution"}</p>
                            </div>
                            <button onClick={() => setForm((f: FormState) => ({ ...f, is_immediate: !f.is_immediate }))} className={`relative w-11 h-6 rounded-full transition-all duration-300 ${form.is_immediate ? "bg-[#7C3AED]" : "bg-slate-200"}`}>
                              <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-md transition-all duration-300 ${form.is_immediate ? "translate-x-5" : ""}`} />
                            </button>
                        </div>

                        {!form.is_immediate && (
                          <div className="px-1 animate-in slide-in-from-top-2 duration-300">
                              <label className="block text-[10px] font-black text-slate-500   mb-1.5 ml-1">Send Date & Time</label>
                              <input type="datetime-local" value={form.send_at || ""} onChange={(e) => setForm((f: FormState) => ({ ...f, send_at: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm font-medium" />
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                </>
) : (
                <div className="space-y-6">
                   {type === "assessment" && (
                     <div className="space-y-4">
                        <div className="flex items-center justify-between mb-2">
                           <h3 className="text-xs font-black text-slate-800  ">Question Bank</h3>
                           <button 
                              onClick={() => {
                                const newQ = form.assessment_type === 'CODING' ? {
                                  id: crypto.randomUUID(),
                                  type: 'CODING',
                                  title: 'New Coding Task',
                                  problem_statement: '',
                                  difficulty: 'Medium'
                                } : {
                                  id: crypto.randomUUID(),
                                  type: 'APTITUDE',
                                  question: 'New Question',
                                  options: ['', '', '', ''],
                                  correct_answer: '',
                                  explanation: ''
                                };
                                setForm((f: FormState) => ({ ...f, generated_questions: [...(f.generated_questions || []), newQ] }));
                              }}
                              className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-xl text-[10px] font-black   text-[#7C3AED] hover:bg-[#7C3AED] hover:text-white transition-all shadow-sm"
                            >
                              <span className="material-symbols-rounded text-sm">add</span>
                              Add Question
                            </button>
                        </div>
                        {(!form.generated_questions || form.generated_questions.length === 0) ? (
                          <div className="py-12 flex flex-col items-center justify-center bg-slate-50 rounded-xl border-2 border-dashed border-slate-200">
                             <span className="material-symbols-rounded text-slate-300 text-4xl mb-2">auto_awesome</span>
                             <p className="text-xs font-bold text-slate-400">No questions generated yet.</p>
                             <button onClick={() => setActiveTab("config")} className="mt-2 text-[10px] text-[#7C3AED] font-black  hover:underline">Go to Config to Generate</button>
                          </div>
                        ) : (
                          <div className="space-y-6">
                             {form.generated_questions.map((q: Question, i: number) => (
                               <div key={q.id || i} className="bg-white border border-slate-100 rounded-xl p-6 shadow-sm hover:shadow-md transition-all relative group">
                                  <div className="absolute -top-2 -left-2 w-7 h-7 bg-[#7C3AED] text-white rounded-xl flex items-center justify-center font-black  shadow-md text-xs">#{i + 1}</div>
                                  
                                  <div className="flex justify-between gap-2 mb-4">
                                     <span className="text-[10px] font-black text-slate-300   ml-6">
                                       {q.type || form.assessment_type} Task
                                     </span>
                                     <button 
                                       onClick={() => {
                                         setForm((f: FormState) => ({ ...f, generated_questions: (f.generated_questions || []).filter((_: Question, idx: number) => idx !== i) }));
                                       }}
                                       className="w-8 h-8 rounded-xl flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100"
                                     >
                                        <span className="material-symbols-rounded text-base">delete</span>
                                     </button>
                                  </div>

                                  <div className="space-y-4">
                                    {(q.type === 'APTITUDE' || (!q.type && form.assessment_type === 'APTITUDE')) ? (
                                      <>
                                        <div>
                                          <label className="text-[10px] font-black text-slate-400   mb-1.5 block ml-1">Question Text</label>
                                          <textarea 
                                            value={q.question} 
                                            onChange={(e) => {
                                              const newQs = [...form.generated_questions];
                                              newQs[i].question = e.target.value;
                                              setForm((f: FormState) => ({ ...f, generated_questions: newQs }));
                                            }}
                                            className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm font-bold text-slate-800 focus:ring-2 focus:ring-[#7C3AED]/20 transition-all h-20 resize-none font-medium text-slate-700"
                                            placeholder="Enter question text..."
                                          />
                                        </div>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                          {(q.options || []).map((opt: string, optIdx: number) => (
                                            <div key={optIdx} className="relative">
                                              <input 
                                                value={opt} 
                                                onChange={(e) => {
                                                  const newQs = [...form.generated_questions];
                                                  newQs[i].options[optIdx] = e.target.value;
                                                  setForm((f: FormState) => ({ ...f, generated_questions: newQs }));
                                                }}
                                                className={`w-full bg-slate-50 border-2 rounded-xl pl-10 pr-4 py-2.5 text-xs font-bold transition-all ${q.correct_answer === opt ? "border-[#7C3AED] bg-[#7C3AED]/5 text-[#7C3AED]" : "border-transparent text-slate-600"}`}
                                                placeholder={`Option ${optIdx + 1}`}
                                              />
                                              <button 
                                                onClick={() => {
                                                  const newQs = [...form.generated_questions];
                                                  newQs[i].correct_answer = opt;
                                                  setForm((f: FormState) => ({ ...f, generated_questions: newQs }));
                                                }}
                                                className={`absolute left-2.5 top-2.5 w-5 h-5 rounded-xl flex items-center justify-center transition-all ${q.correct_answer === opt ? "bg-[#7C3AED] text-white" : "bg-slate-200 text-slate-400 hover:bg-slate-300"}`}
                                              >
                                                <span className="material-symbols-rounded text-xs">{q.correct_answer === opt ? "check" : "circle"}</span>
                                              </button>
                                            </div>
                                          ))}
                                        </div>
                                      </>
                                    ) : (
                                      <>
                                        <div>
                                          <label className="text-[10px] font-black text-slate-400   mb-1.5 block ml-1">Problem Title</label>
                                          <input 
                                            type="text"
                                            value={q.title || ''} 
                                            onChange={(e) => {
                                              const newQs = [...form.generated_questions];
                                              newQs[i].title = e.target.value;
                                              setForm((f: FormState) => ({ ...f, generated_questions: newQs }));
                                            }}
                                            className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm font-black text-slate-800 focus:ring-2 focus:ring-[#7C3AED]/20 transition-all"
                                            placeholder="e.g. Implement a Binary Search"
                                          />
                                        </div>
                                        <div>
                                          <label className="text-[10px] font-black text-slate-400   mb-1.5 block ml-1">Problem Statement</label>
                                          <textarea 
                                            value={q.problem_statement || ''} 
                                            onChange={(e) => {
                                              const newQs = [...form.generated_questions];
                                              newQs[i].problem_statement = e.target.value;
                                              setForm((f: FormState) => ({ ...f, generated_questions: newQs }));
                                            }}
                                            className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm font-bold text-slate-800 focus:ring-2 focus:ring-[#7C3AED]/20 transition-all h-32 resize-none font-medium"
                                            placeholder="Enter the problem details..."
                                          />
                                        </div>
                                      </>
                                    )}
                                  </div>
                               </div>
                             ))}
                          </div>
                        )}
                     </div>
                   )}

                   {type === "interview" && (
                     <div className="space-y-4">
                        <div className="flex items-center justify-between mb-2">
                           <h3 className="text-xs font-black text-slate-800  ">Time Slots</h3>
                           <button 
                             onClick={() => {
                               const limit = Number(form.daily_limit) || 0;
                               if (limit > 0 && form.time_slots?.length >= limit) {
                                  showToast(`Daily limit of ${limit} slots reached.`, "error");
                                  return;
                               }
                               setForm((f: FormState) => ({ ...f, time_slots: [...(f.time_slots || []), "09:00"] }));
                             }}
                             disabled={Number(form.daily_limit) > 0 && form.time_slots?.length >= Number(form.daily_limit)}
                             className="text-[10px] font-bold text-[#7C3AED] hover:underline  disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:no-underline"
                           >
                             + Add Slot
                           </button>
                        </div>
                        {(!form.time_slots || form.time_slots.length === 0) ? (
                          <div className="py-12 flex flex-col items-center justify-center bg-slate-50 rounded-xl border-2 border-dashed border-slate-200">
                             <span className="material-symbols-rounded text-slate-300 text-4xl mb-2">schedule</span>
                             <p className="text-xs font-bold text-slate-400">No time slots generated.</p>
                             <button onClick={handleGenerateTimeSlots} className="mt-2 text-[10px] text-[#7C3AED] font-black  hover:underline">Auto-Generate Slots</button>
                          </div>
                        ) : (
                          <div className="grid grid-cols-3 gap-3">
                             {form.time_slots.map((slot: string, i: number) => (
                               <div key={i} className="flex items-center gap-2 bg-slate-50 border border-slate-200 rounded-xl p-2 group">
                                  <input 
                                    type="time" 
                                    value={slot} 
                                    onChange={(e) => {
                                      const newSlots = [...form.time_slots];
                                      newSlots[i] = e.target.value;
                                      setForm((f: FormState) => ({ ...f, time_slots: newSlots }));
                                    }}
                                    className="bg-transparent border-none p-0 text-xs font-bold text-slate-700 focus:ring-0 flex-1"
                                  />
                                  <button 
                                    onClick={() => {
                                      setForm((f: FormState) => ({ ...f, time_slots: (f.time_slots || []).filter((_: string, idx: number) => idx !== i) }));
                                    }}
                                    className="text-slate-300 hover:text-red-500 transition-colors"
                                  >
                                     <span className="material-symbols-rounded text-sm">close</span>
                                  </button>
                               </div>
                             ))}
                          </div>
                        )}
                        <div className="pt-4 mt-4 border-t border-slate-100">
                           <button 
                             onClick={handleGenerateTimeSlots}
                             className="w-full py-3 bg-slate-900 text-white rounded-xl text-[10px] font-black   hover:bg-slate-800 transition-all shadow-md"
                           >
                              Refresh / Regenerate Slots
                           </button>
                        </div>
                     </div>
                    )}
                  </div>
                )}
                </motion.div>
              </AnimatePresence>
            </div>

            {/* Footer */}
            <div className="p-6 border-t border-slate-100 bg-slate-50 shrink-0">
              <button
                onClick={handleSave}
                disabled={saving}
                className="w-full h-12 flex items-center justify-center gap-2 text-white rounded-xl text-sm font-black transition-all active:scale-[0.98] disabled:opacity-60 shadow-lg"
                style={{ backgroundColor: headerMeta.color, boxShadow: `0 8px 16px -4px ${headerMeta.color}60` }}
              >
                {saving ? (
                  <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <>
                    <span className="material-symbols-rounded text-lg">{editingId ? "save" : "add_circle"}</span>
                    {editingId ? "UPDATE" : "ADD"} {type.toUpperCase()} NODE
                  </>
                )}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useAuth } from "@/context/AuthContext";

interface Question {
  id: string;
  question: string;
  type: string;
  expected_answer_points: string[];
  difficulty: string;
}

interface Template {
  id?: string;
  title: string;
  topic: string;
  duration: number;
  difficulty: string;
  require_video: boolean;
  plan: {
    questions: Question[];
  };
}

interface TemplateBuilderProps {
  onClose: () => void;
  onSave: (template: Template) => void;
  initialData?: Template | null;
  token: string;
  backendUrl: string;
}

export default function TemplateBuilder({
  onClose,
  onSave,
  initialData,
  token,
  backendUrl,
}: TemplateBuilderProps) {
  const { canAccess } = useAuth();
  const [title, setTitle] = useState(initialData?.title || "");
  const [topic, setTopic] = useState(initialData?.topic || "");
  const [duration, setDuration] = useState(initialData?.duration || 30);
  const [difficulty, setDifficulty] = useState(initialData?.difficulty || "Intermediate");
  const [requireVideo, setRequireVideo] = useState(initialData?.require_video ?? true);
  const [questions, setQuestions] = useState<Question[]>(initialData?.plan?.questions || []);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const authHeaders = {
    "Content-Type": "application/json",
    Authorization: `Bearer ${token}`,
  };

  const handleGenerate = async () => {
    if (!topic) return;
    setIsGenerating(true);
    try {
      const res = await fetch(
        `${backendUrl}/api/v1/enterprise/interview-templates/generate-questions?topic=${encodeURIComponent(
          topic
        )}&duration=${duration}&difficulty=${difficulty}`,
        {
          method: "POST",
          headers: authHeaders,
        }
      );
      if (res.ok) {
        const data = await res.json();
        setQuestions([...questions, ...(data.questions || [])]);
      }
    } catch (error) {
      console.error("Error generating questions:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = async () => {
    if (!title || !topic) return;
    
    // Validate that all questions have non-empty text
    const hasEmptyQuestions = questions.some(q => !q.question || q.question.trim() === "");
    if (hasEmptyQuestions) {
      alert("Please ensure all questions have content before saving.");
      return;
    }
    setIsSaving(true);
    try {
      const payload = {
        title,
        description: `AI Interview for ${topic}`,
        topic,
        duration: Number(duration),
        difficulty,
        require_video: requireVideo,
        type: "VIDEO",
        plan: { questions },
      };

      const url = initialData?.id
        ? `${backendUrl}/api/v1/enterprise/interview-templates/${initialData.id}`
        : `${backendUrl}/api/v1/enterprise/interview-templates/`;
      
      const method = initialData?.id ? "PATCH" : "POST";
      
      const res = await fetch(url, {
        method,
        headers: authHeaders,
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        const savedTemplate = await res.json();
        onSave(savedTemplate);
      }
    } catch (error) {
      console.error("Error saving template:", error);
    } finally {
      setIsSaving(false);
    }
  };

  const addQuestion = () => {
    const newQ: Question = {
      id: Math.random().toString(36).substr(2, 9),
      question: "",
      type: "TECHNICAL",
      expected_answer_points: [],
      difficulty: difficulty,
    };
    setQuestions([...questions, newQ]);
  };

  const removeQuestion = (id: string) => {
    setQuestions(questions.filter((q) => q.id !== id));
  };

  const updateQuestion = (id: string, updates: Partial<Question>) => {
    setQuestions(questions.map((q) => (q.id === id ? { ...q, ...updates } : q)));
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 md:p-8">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" 
        onClick={onClose} 
      />
      
      <motion.div
        initial={{ scale: 0.95, opacity: 0, y: 20 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        exit={{ scale: 0.95, opacity: 0, y: 20 }}
        className="relative w-full max-w-4xl h-[90vh] bg-white rounded-xl shadow-2xl overflow-hidden flex flex-col md:flex-row"
      >
        {/* Sidebar */}
        <div className="w-full md:w-80 bg-slate-50 border-r border-slate-100 p-6 overflow-y-auto shrink-0">
          <div className="flex items-center gap-3 mb-8">
            <div className="w-10 h-10 rounded-xl bg-[#7C3AED] flex items-center justify-center shadow-lg shadow-[#7C3AED]/20">
              <span className="material-symbols-rounded text-white">psychology</span>
            </div>
            <div>
              <h2 className="text-lg font-black text-slate-800 leading-tight">AI Builder</h2>
              <p className="text-[10px] font-bold text-slate-400   mt-0.5">Template Config</p>
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Template Title
              </label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                placeholder="e.g. Senior Frontend Dev"
                readOnly={!canAccess("interviews:moderate")}
              />
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Interview Topic
              </label>
              <input
                type="text"
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                placeholder="e.g. React & TypeScript"
                readOnly={!canAccess("interviews:moderate")}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  Duration (m)
                </label>
                <input
                  type="number"
                  min={5}
                  max={90}
                  step={5}
                  value={duration}
                  onChange={(e) => setDuration(Number(e.target.value))}
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  Difficulty
                </label>
                <select
                  value={difficulty}
                  onChange={(e) => setDifficulty(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                  disabled={!canAccess("interviews:moderate")}
                >
                  <option value="Beginner">Beginner</option>
                  <option value="Intermediate">Intermediate</option>
                  <option value="Advanced">Advanced</option>
                  <option value="Expert">Expert</option>
                </select>
              </div>
            </div>

            <div className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-xl shadow-sm">
              <div>
                <p className="text-xs font-bold text-slate-700">Require Video</p>
                <p className="text-[10px] text-slate-400 font-medium">Enforce camera</p>
              </div>
              <button
                onClick={() => setRequireVideo(!requireVideo)}
                disabled={!canAccess("interviews:moderate")}
                className={`relative w-9 h-5 rounded-full transition-colors duration-200 focus:outline-none ${requireVideo ? "bg-[#7C3AED]" : "bg-slate-200"} ${!canAccess("interviews:moderate") ? "opacity-50 cursor-not-allowed" : ""}`}
              >
                <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform duration-200 ${requireVideo ? "translate-x-4" : "translate-x-0"}`} />
              </button>
            </div>

            <div className="pt-4">
              <button
                onClick={handleGenerate}
                disabled={isGenerating || !topic || !canAccess("interviews:moderate")}
                className="w-full py-4 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-200 text-white rounded-xl font-black text-xs   transition-all flex items-center justify-center gap-2 shadow-lg shadow-slate-200"
              >
                {isGenerating ? (
                   <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <span className="material-symbols-rounded text-base">magic_button</span>
                )}
                Generate with AI
              </button>
            </div>
          </div>

          <div className="mt-auto pt-10">
            <button
              onClick={onClose}
              className="w-full py-3 text-slate-400 hover:text-slate-600 font-bold text-[10px]   transition-colors"
            >
              Cancel
            </button>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 flex flex-col bg-white overflow-hidden">
          <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between shrink-0">
            <div>
              <h3 className="text-sm font-black text-slate-800  ">Interview Questions</h3>
              <p className="text-[10px] text-slate-400 font-medium mt-1">Review and customize the generated questions</p>
            </div>
            {canAccess("interviews:moderate") && (
              <button
                onClick={addQuestion}
                className="flex items-center gap-2 px-4 py-2 bg-[#7C3AED]/10 text-[#7C3AED] hover:bg-[#7C3AED] hover:text-white rounded-xl text-[10px] font-black   transition-all"
              >
                <span className="material-symbols-rounded text-sm">add</span>
                Add Question
              </button>
            )}
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-4 custom-scrollbar">
            {questions.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center space-y-4 max-w-sm mx-auto">
                <div className="w-16 h-16 rounded-xl bg-slate-50 flex items-center justify-center">
                  <span className="material-symbols-rounded text-slate-300 text-3xl">chat_bubble</span>
                </div>
                <div>
                  <h4 className="text-sm font-black text-slate-400  ">No questions yet</h4>
                  <p className="text-xs text-slate-400 leading-relaxed mt-1">
                    Enter a topic on the left and click &quot;Generate with AI&quot; or add questions manually.
                  </p>
                </div>
              </div>
            ) : (
              questions.map((q, idx) => (
                <motion.div
                  key={q.id}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: idx * 0.05 }}
                  className="group bg-white border border-slate-100 rounded-xl p-6 transition-all hover:border-[#7C3AED]/20 hover:shadow-xl hover:shadow-[#7C3AED]/5 relative"
                >
                  {canAccess("interviews:moderate") && (
                    <div className="absolute top-6 right-6 flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => removeQuestion(q.id)}
                        className="w-8 h-8 rounded-xl bg-red-50 text-red-400 hover:bg-red-500 hover:text-white transition-all flex items-center justify-center"
                      >
                        <span className="material-symbols-rounded text-base">delete</span>
                      </button>
                    </div>
                  )}

                  <div className="flex gap-4">
                    <div className="w-8 h-8 shrink-0 rounded-xl bg-slate-50 flex items-center justify-center text-[10px] font-black text-slate-400 border border-slate-100">
                      {idx + 1}
                    </div>
                    <div className="flex-1 space-y-4">
                      <textarea
                        value={q.question}
                        onChange={(e) => updateQuestion(q.id, { question: e.target.value })}
                        rows={2}
                        className="w-full text-sm font-bold text-slate-800 placeholder-slate-300 border-none focus:ring-0 resize-none p-0 bg-transparent"
                        placeholder="Type question here..."
                        readOnly={!canAccess("interviews:moderate")}
                      />
                      
                      <div className="flex flex-wrap items-center gap-4">
                         <div className="flex items-center gap-2">
                           <span className="text-[9px] font-black text-slate-400  ">Type:</span>
                           <select
                             value={q.type}
                             onChange={(e) => updateQuestion(q.id, { type: e.target.value })}
                             className="text-[10px] font-bold text-[#7C3AED] bg-[#7C3AED]/5 border-none focus:ring-0 rounded-xl px-2 py-1"
                             disabled={!canAccess("interviews:moderate")}
                           >
                             <option value="TECHNICAL">TECHNICAL</option>
                             <option value="BEHAVIORAL">BEHAVIORAL</option>
                             <option value="SITUATIONAL">SITUATIONAL</option>
                           </select>
                         </div>
                         <div className="flex items-center gap-2">
                           <span className="text-[9px] font-black text-slate-400  ">Difficulty:</span>
                           <select
                             value={q.difficulty}
                             onChange={(e) => updateQuestion(q.id, { difficulty: e.target.value })}
                             className="text-[10px] font-bold text-slate-600 bg-slate-50 border-none focus:ring-0 rounded-xl px-2 py-1"
                             disabled={!canAccess("interviews:moderate")}
                           >
                             <option value="Beginner">Beginner</option>
                             <option value="Intermediate">Intermediate</option>
                             <option value="Advanced">Advanced</option>
                             <option value="Expert">Expert</option>
                           </select>
                         </div>
                      </div>

                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400   ml-1">Key Evaluation Points</label>
                        <div className="flex flex-wrap gap-2">
                          {q.expected_answer_points.map((point, pIdx) => (
                            <div key={pIdx} className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 rounded-xl border border-slate-100 group/point">
                              <input
                                value={point}
                                onChange={(e) => {
                                  const newPoints = [...q.expected_answer_points];
                                  newPoints[pIdx] = e.target.value;
                                  updateQuestion(q.id, { expected_answer_points: newPoints });
                                }}
                                className="text-[10px] font-bold text-slate-600 bg-transparent border-none focus:ring-0 p-0 w-32"
                                readOnly={!canAccess("interviews:moderate")}
                              />
                                {canAccess("interviews:moderate") && (
                                  <button 
                                    onClick={() => {
                                      const newPoints = q.expected_answer_points.filter((_, i) => i !== pIdx);
                                      updateQuestion(q.id, { expected_answer_points: newPoints });
                                    }}
                                    className="text-slate-300 hover:text-red-400 transition-colors"
                                  >
                                    <span className="material-symbols-rounded text-xs">close</span>
                                  </button>
                                )}
                            </div>
                          ))}
                          {canAccess("interviews:moderate") && (
                            <button 
                              onClick={() => {
                                 updateQuestion(q.id, { expected_answer_points: [...q.expected_answer_points, "New point..."] });
                              }}
                              className="px-3 py-1.5 border border-dashed border-slate-200 rounded-xl text-[10px] font-bold text-slate-400 hover:border-[#7C3AED] hover:text-[#7C3AED] transition-all"
                            >
                              + Add Point
                            </button>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                </motion.div>
              ))
            )}
          </div>

          <div className="px-8 py-6 border-t border-slate-100 bg-slate-50/30 flex justify-end shrink-0">
            {canAccess("interviews:moderate") && (
              <button
                onClick={handleSave}
                disabled={isSaving || !title || !topic || questions.length === 0 || questions.some(q => !q.question || q.question.trim() === "")}
                className="flex items-center gap-2 px-8 py-4 bg-[#7C3AED] hover:bg-[#6D28D9] disabled:bg-slate-200 text-white rounded-xl text-xs font-black   transition-all shadow-xl shadow-[#7C3AED]/20"
              >
                {isSaving ? (
                   <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <span className="material-symbols-rounded text-base">save</span>
                )}
                {initialData ? "Update Template" : "Save Template"}
              </button>
            )}
          </div>
        </div>
      </motion.div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useMemo } from "react";
import { useAuth } from "@/context/AuthContext";
import { format } from "date-fns";
import { AnimatePresence } from "framer-motion";
import { BACKEND_URL } from "@/utils/api";
import ConfirmationModal from "@/components/common/ConfirmationModal";
import TemplateBuilder from "./TemplateBuilder";

// ─── Types ────────────────────────────────────────────────────────────────────

interface WorkflowStage {
  name: string;
  stage?: number;
  order?: number;
}

interface Job {
  id: string;
  title: string;
  workflow_stages?: WorkflowStage[] | null;
}

interface Template {
  id: string;
  name: string;
  subject: string;
}

interface Automation {
  id: string;
  job_requirement_id: string;
  stage_index: number;
  stage_name: string | null;
  criteria: string;
  email_template_id: string | null;
  auto_move: boolean;
  is_enabled: boolean;
  start_time: string;
  end_time: string;
  duration: number;
  daily_limit: number;
  interviewer_email: string | null;
  time_slots: string[] | null;
  start_date: string | null;
  end_date: string | null;
  google_meet_link: string | null;
  created_at: string;
}

interface FormState {
  job_requirement_id: string;
  stage_index: number | string;
  stage_name: string;
  criteria: string;
  email_template_id: string;
  auto_move: boolean;
  is_enabled: boolean;
  start_time: string;
  end_time: string;
  duration: number | string;
  daily_limit: number | string;
  interviewer_email: string;
  time_slots: string[];
  start_date: string | null;
  end_date: string | null;
  google_meet_link: string;
  interview_type: "GMEET" | "AI";
  interview_template_id: string | null;
}

const EMPTY_FORM: FormState = {
  job_requirement_id: "",
  stage_index: 0,
  stage_name: "",
  criteria: "",
  email_template_id: "",
  auto_move: false,
  is_enabled: true,
  start_time: "09:00",
  end_time: "17:00",
  duration: 30,
  daily_limit: 5,
  interviewer_email: "",
  time_slots: [] as string[],
  start_date: "",
  end_date: "",
  google_meet_link: "",
  interview_type: "GMEET" as "GMEET" | "AI",
  interview_template_id: "",
};

// ─── Main Page ────────────────────────────────────────────────────────────────

export default function InterviewAutomationPage() {
  const { token, canAccess } = useAuth();

  const authHeaders = useMemo(() => ({
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  }), [token]);

  const [jobs, setJobs] = useState<Job[]>([]);
  const [templates, setTemplates] = useState<Template[]>([]);
  const [automations, setAutomations] = useState<Automation[]>([]);
  const [selectedJobId, setSelectedJobId] = useState<string>("");
  const [searchQuery, setSearchQuery] = useState("");
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const [togglingId, setTogglingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [automationToDelete, setAutomationToDelete] = useState<Automation | null>(null);
  const [interviewTemplates, setInterviewTemplates] = useState<Template[]>([]);
  const [showTemplateBuilder, setShowTemplateBuilder] = useState(false);
  const [selectedTemplateForEdit, setSelectedTemplateForEdit] = useState<Template | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);
  
  const [activeTab, setActiveTab] = useState<"config" | "times">("config");

  const showToast = (msg: string | string[] | { msg?: string; detail?: string } | null, type: "success" | "error" = "success") => {
    let finalMsg = "";
    if (typeof msg === "string") {
      finalMsg = msg;
    } else if (Array.isArray(msg)) {
      finalMsg = msg.map((e: string | { msg?: string }) => (typeof e === 'string' ? e : (e.msg || JSON.stringify(e)))).join(", ");
    } else if (msg && typeof msg === "object") {
      const obj = msg as { msg?: string; detail?: string };
      finalMsg = obj.msg || obj.detail || JSON.stringify(msg);
    } else {
      finalMsg = String(msg || "An error occurred");
    }
    setToast({ msg: finalMsg, type });
    setTimeout(() => setToast(null), 5000); // Increased duration for complex errors
  };

  // Fetch jobs & templates on mount (wait for token)
  useEffect(() => {
    if (!token) return;
    const fetchMeta = async () => {
      try {
        const [jRes, tRes] = await Promise.all([
          fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, { headers: authHeaders }),
          fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates/`, { headers: authHeaders }),
        ]);
        const jData = jRes.ok ? await jRes.json() : [];
        const tData = tRes.ok ? await tRes.json() : [];
        setJobs(Array.isArray(jData) ? jData : []);
        setTemplates(Array.isArray(tData) ? tData : []);
      } catch (e) {
        console.error("Failed to load meta:", e);
      }
    };
    fetchMeta();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  // Fetch automations when job selection changes
  const fetchAutomations = useCallback(async (jobId?: string) => {
    if (!token) return;
    setLoading(true);
    try {
      const qs = jobId ? `?job_id=${jobId}` : "";
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-automation/${qs}`, {
        headers: authHeaders,
      });
      if (res.ok) {
        const data = await res.json();
        setAutomations(Array.isArray(data) ? data : []);
      }
    } finally {
      setLoading(false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  const fetchInterviewTemplates = useCallback(async () => {
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-templates/`, {
        headers: authHeaders
      });
      if (res.ok) {
        const data = await res.json();
        setInterviewTemplates(data);
      }
    } catch (error) {
      console.error("Error fetching interview templates:", error);
    }
  }, [authHeaders]);

  useEffect(() => {
    if (showModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [showModal]);

  useEffect(() => {
    if (token) {
      fetchInterviewTemplates();
    }
  }, [token, fetchInterviewTemplates]);

  useEffect(() => {
    if (token) {
      fetchAutomations(selectedJobId || undefined);
    }
  }, [token, selectedJobId, fetchAutomations]);

  // Rounds extracted from the selected job's workflow_stages
  const selectedJob = jobs.find((j) => j.id === form.job_requirement_id);
  const jobRounds: WorkflowStage[] = selectedJob?.workflow_stages ?? [];

  // ── Modal helpers ────────────────────────────────────────────────────────────

  const openCreate = () => {
    setEditingId(null);
    setForm({ ...EMPTY_FORM, job_requirement_id: selectedJobId });
    setActiveTab("config");
    setShowModal(true);
  };

  const openEdit = (a: Automation) => {
    setEditingId(a.id);
    setForm({
      job_requirement_id: a.job_requirement_id,
      stage_index: a.stage_index,
      stage_name: a.stage_name ?? "",
      criteria: a.criteria,
      email_template_id: a.email_template_id ?? "",
      auto_move: a.auto_move,
      is_enabled: a.is_enabled,
      start_time: a.start_time,
      end_time: a.end_time,
      duration: a.duration ?? 30,
      daily_limit: a.daily_limit,
      interviewer_email: a.interviewer_email ?? "",
      time_slots: a.time_slots ?? [],
      start_date: a.start_date ?? "",
      end_date: a.end_date ?? "",
      google_meet_link: a.google_meet_link ?? "",
      interview_type: (a as Automation & { interview_type?: string }).interview_type || "GMEET",
      interview_template_id: (a as Automation & { interview_template_id?: string }).interview_template_id || "",
    });
    setActiveTab("config");
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingId(null);
    setForm(EMPTY_FORM);
    setActiveTab("config");
  };

  // ── Save ─────────────────────────────────────────────────────────────────────

  const handleSave = async () => {
    if (!form.job_requirement_id || !form.criteria.trim()) {
      showToast("Please fill in all required fields.", "error");
      return;
    }
    if (form.start_date && new Date(form.start_date) < new Date(new Date().setHours(0,0,0,0))) {
      showToast("Start date cannot be in the past.", "error");
      return;
    }
    setSaving(true);
    try {
      let finalTimeSlots = form.time_slots;
      
      // Auto-generate slots if empty before saving
      if (finalTimeSlots.length === 0) {
        const limit = Number(form.daily_limit);
        if (limit > 0) {
          const [sh, sm] = form.start_time.split(":").map(Number);
          const [eh, em] = form.end_time.split(":").map(Number);
          const startMins = sh * 60 + sm;
          const endMins = eh * 60 + em;
          const interval = Number(form.duration) || 30;
          
          if (startMins < endMins) {
            const generated: string[] = [];
            for (let i = 0; i < limit; i++) {
                const slotMins = startMins + i * interval;
                if (slotMins + interval > endMins) break;
                const h = Math.floor(slotMins / 60).toString().padStart(2, "0");
                const m = (slotMins % 60).toString().padStart(2, "0");
                generated.push(`${h}:${m}`);
            }
            finalTimeSlots = generated;
          }
        }
      }

      const payload = {
        ...form,
        job_requirement_id: form.job_requirement_id || null,
        stage_index: Number(form.stage_index),
        stage_name: form.stage_name.trim() || null,
        email_template_id: form.email_template_id || null,
        duration: Number(form.duration) || 30,
        daily_limit: Number(form.daily_limit),
        interviewer_email: form.interviewer_email?.trim() || null,
        google_meet_link: form.google_meet_link?.trim() || null,
        time_slots: finalTimeSlots.length > 0 ? finalTimeSlots : null,
        start_date: form.start_date || null,
        end_date: form.end_date || null,
        interview_type: form.interview_type,
        interview_template_id: form.interview_type === "AI" ? (form.interview_template_id || null) : null,
      };
      const url = editingId
        ? `${BACKEND_URL}/api/v1/enterprise/interview-automation/${editingId}`
        : `${BACKEND_URL}/api/v1/enterprise/interview-automation/`;
      const method = editingId ? "PATCH" : "POST";
      const res = await fetch(url, {
        method,
        headers: authHeaders,
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        showToast(editingId ? "Automation updated!" : "Automation created!");
        closeModal();
        fetchAutomations(selectedJobId || undefined);
      } else {
        const err = await res.json().catch(() => ({}));
        showToast((err as { detail?: string })?.detail || "Failed to save automation.", "error");
      }
    } finally {
      setSaving(false);
    }
  };

  // ── Toggle ───────────────────────────────────────────────────────────────────

  const handleToggle = async (a: Automation) => {
    setTogglingId(a.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-automation/${a.id}`, {
        method: "PATCH",
        headers: authHeaders,
        body: JSON.stringify({ is_enabled: !a.is_enabled }),
      });
      if (res.ok) {
        setAutomations((prev) =>
          prev.map((item) => (item.id === a.id ? { ...item, is_enabled: !a.is_enabled } : item))
        );
      } else {
        showToast("Failed to update status.", "error");
      }
    } finally {
      setTogglingId(null);
    }
  };

  // ── Delete ────────────────────────────────────────────────────────────────────

  const handleDelete = async () => {
    if (!automationToDelete) return;
    setDeletingId(automationToDelete.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-automation/${automationToDelete.id}`, {
        method: "DELETE",
        headers: authHeaders,
      });
      if (res.ok) {
        showToast("Automation deleted.");
        setAutomations((prev) => prev.filter((a) => a.id !== automationToDelete.id));
      } else {
        showToast("Failed to delete.", "error");
      }
    } finally {
      setDeletingId(null);
      setIsDeleteModalOpen(false);
      setAutomationToDelete(null);
    }
  };

  // ── Helpers ──────────────────────────────────────────────────────────────────

  const jobTitle = (id: string) => jobs.find((j) => j.id === id)?.title ?? "—";
  const templateName = (id: string) => templates.find((t) => t.id === id)?.name ?? "—";

  // ── When user picks a round from dropdown, auto-fill stage_index + stage_name
  const handleRoundSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    if (val === "") return;
    const [idxStr, ...nameParts] = val.split("|");
    setForm((f) => ({
      ...f,
      stage_index: Number(idxStr),
      stage_name: nameParts.join("|"),
    }));
  };

  const handleGenerateTimeSlots = () => {
    const limit = Number(form.daily_limit);
    if (!limit || limit <= 0) return;
    
    const [sh, sm] = form.start_time.split(":").map(Number);
    const [eh, em] = form.end_time.split(":").map(Number);
    
    const startMins = sh * 60 + sm;
    const endMins = eh * 60 + em;
    
    if (startMins >= endMins) {
      showToast("End time must be after start time", "error");
      return;
    }
    
    const interval = Number(form.duration) || 30;
    
    const slots: string[] = [];
    for (let i = 0; i < limit; i++) {
        const slotMins = startMins + i * interval;
        if (slotMins + interval > endMins) break;
        const h = Math.floor(slotMins / 60).toString().padStart(2, "0");
        const m = (slotMins % 60).toString().padStart(2, "0");
        slots.push(`${h}:${m}`);
    }
    
    setForm(f => ({ ...f, time_slots: slots }));
  };

  // ─── Computed ───────────────────────────────────────────────────────────────
  const filteredAutomations = automations.filter(a => {
    const term = searchQuery.toLowerCase();
    return a.criteria.toLowerCase().includes(term) ||
           jobTitle(a.job_requirement_id).toLowerCase().includes(term) ||
           (a.stage_name && a.stage_name.toLowerCase().includes(term)) ||
           (a.interviewer_email && a.interviewer_email.toLowerCase().includes(term));
  });

  // ─── Render ────────────────────────────────────────────────────────────────

  return (
    <div className="min-h-screen bg-[#F8FAFC] p-6 animate-in fade-in duration-500">
      {/* Toast */}
      {toast && (
        <div
          className={`fixed top-5 right-5 z-[200] flex items-center gap-2 px-4 py-3 rounded-lg shadow-lg text-sm font-semibold transition-all duration-300 ${
            toast.type === "success" ? "bg-[#7C3AED] text-white" : "bg-red-500 text-white"
          }`}
        >
          <span className="material-symbols-rounded text-base">
            {toast.type === "success" ? "check_circle" : "error"}
          </span>
          {String(toast.msg)}
        </div>
      )}

      {/* Header */}
      <div className="mb-10">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-start gap-4">
            <div className="w-12 h-12 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center shrink-0 shadow-sm shadow-[#7C3AED]/5">
              <span className="material-symbols-rounded text-[#7C3AED] text-2xl">event_available</span>
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">Interview Automation</h1>
              <p className="text-slate-500 text-[13px] font-medium mt-1">
                Automatically schedule AI or human technical interviews based on your hiring criteria.
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3">
             {canAccess("automation:moderate") && (
                <button
                  onClick={openCreate}
                  className="flex items-center gap-2 px-5 h-11 bg-[#7C3AED] text-white rounded-lg text-xs font-black hover:bg-[#6d28d9] transition-all shadow-lg shadow-[#7C3AED]/20 active:scale-95"
                >
                  <span className="material-symbols-rounded text-lg">add</span>
                  NEW AUTOMATION
                </button>
              )}
          </div>
        </div>

        {/* Stats Section */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { label: "Total Rules", value: automations.length, icon: "rule", color: "indigo" },
            { label: "Active Rules", value: automations.filter(a => a.is_enabled).length, icon: "bolt", color: "emerald" },
            { label: "Auto-Move Rules", value: automations.filter(a => a.auto_move).length, icon: "double_arrow", color: "amber" },
            { label: "Configured Slots", value: automations.reduce((acc, a) => acc + (a.time_slots?.length || 0), 0), icon: "event_upcoming", color: "purple" }
          ].map((stat, i) => (
            <div key={i} className="group bg-white p-5 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-[#7C3AED]/20 transition-all duration-300">
              <div className="flex items-start justify-between mb-4">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center transition-transform group-hover:scale-110 ${
                  stat.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
                  stat.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
                  stat.color === 'amber' ? 'bg-amber-50 text-amber-600' :
                  'bg-purple-50 text-purple-600'
                }`}>
                  <span className="material-symbols-rounded text-xl">{stat.icon}</span>
                </div>
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Live</span>
              </div>
              <p className="text-2xl font-black text-slate-900 mb-0.5 tracking-tight">{stat.value}</p>
              <p className="text-[11px] font-bold text-slate-400 capitalize">{stat.label}</p>
            </div>
          ))}
        </div>

        {/* Interaction Bar */}
        <div className="mt-8 flex flex-col md:flex-row items-center gap-4">
           <div className="flex-1 relative w-full">
              <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg">search</span>
              <input 
                type="text"
                placeholder="Search by rules, jobs, or interviewers..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full h-11 bg-white border border-slate-200 rounded-lg pl-11 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none"
              />
           </div>

           <div className="flex items-center gap-3 w-full md:w-auto">
              {(searchQuery || selectedJobId) && (
                <button 
                  onClick={() => { setSearchQuery(""); setSelectedJobId(""); }}
                  className="text-[11px] font-black text-[#7C3AED] hover:underline px-2 tracking-tight"
                >
                  RESET FILTERS
                </button>
              )}
              <div className="relative w-full md:w-64">
                <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">work</span>
                <select
                  value={selectedJobId}
                  onChange={(e) => setSelectedJobId(e.target.value)}
                  className="w-full h-11 border border-slate-200 rounded-lg pl-10 pr-10 text-xs font-bold text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/5 focus:border-[#7C3AED] shadow-sm appearance-none cursor-pointer"
                >
                  <option value="">All Job Requirements</option>
                  {jobs.map((j) => (
                    <option key={j.id} value={j.id}>{j.title}</option>
                  ))}
                </select>
                <span className="material-symbols-rounded absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">expand_more</span>
              </div>
           </div>
        </div>
      </div>

      {/* List */}
      {loading ? (
        <div className="flex justify-center py-20">
          <div className="w-8 h-8 border-4 border-[#7C3AED] border-t-transparent rounded-full animate-spin" />
        </div>
      ) : filteredAutomations.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <div className="w-16 h-16 rounded-lg bg-[#7C3AED]/5 flex items-center justify-center mb-4">
            <span className="material-symbols-rounded text-[#7C3AED] text-4xl">event_available</span>
          </div>
          <p className="text-slate-700 font-bold text-lg">{searchQuery ? 'No matching rules' : 'No automations yet'}</p>
          <p className="text-slate-400 text-sm mt-1 max-w-xs">
            {searchQuery ? `We couldn&apos;t find any results for &quot;${searchQuery}&quot;` : 'Create your first interview automation to auto-schedule interviews.'}
          </p>
          {!searchQuery && (
            <button
              onClick={openCreate}
              className="mt-5 flex items-center gap-2 px-4 py-2 bg-[#7C3AED] text-white rounded-lg text-sm font-bold hover:bg-[#6d28d9] transition-colors"
            >
              <span className="material-symbols-rounded text-base">add</span>
              Create Automation
            </button>
          )}
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Rule Configuration</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Job</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Schedule Logic</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredAutomations.map((a) => (
                  <tr key={a.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-2">
                          <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[9px] font-black uppercase">
                            Round {a.stage_index}
                          </span>
                          {a.stage_name && (
                            <span className="text-[10px] font-bold text-slate-400">{a.stage_name}</span>
                          )}
                        </div>
                        <p className="text-xs font-bold text-slate-800 line-clamp-1">
                          <span className="text-slate-400 font-medium italic mr-1">If:</span>
                          {a.criteria}
                        </p>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-1.5 text-xs font-bold text-slate-700">
                        <span className="material-symbols-rounded text-sm text-slate-400">work</span>
                        {jobTitle(a.job_requirement_id)}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-1.5 text-[11px] font-bold text-slate-700">
                          <span className="material-symbols-rounded text-sm text-slate-400">schedule</span>
                          {a.start_time} - {a.end_time} ({a.duration}m)
                        </div>
                        {a.auto_move && (
                          <div className="flex items-center gap-1 text-[9px] font-black text-[#7C3AED] uppercase">
                            <span className="material-symbols-rounded text-xs">keyboard_double_arrow_right</span>
                            Auto-Move Active
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <button
                        onClick={() => handleToggle(a)}
                        disabled={togglingId === a.id || !canAccess("automation:moderate")}
                        className={`relative w-9 h-5 rounded-full transition-colors duration-200 focus:outline-none ${a.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"} ${togglingId === a.id || !canAccess("automation:moderate") ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}`}
                      >
                        <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform duration-200 ${a.is_enabled ? "translate-x-4" : "translate-x-0"}`} />
                      </button>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-1">
                        {canAccess("automation:moderate") && (
                          <button onClick={() => openEdit(a)} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 text-slate-400 hover:text-[#7C3AED] transition-colors">
                            <span className="material-symbols-rounded text-base">edit</span>
                          </button>
                        )}
                        {canAccess("automation:moderate") && (
                          <button onClick={() => {
                            setAutomationToDelete(a);
                            setIsDeleteModalOpen(true);
                          }} disabled={deletingId === a.id} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-red-50 text-slate-400 hover:text-red-500 transition-colors">
                            <span className="material-symbols-rounded text-base">delete</span>
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      )}

      {/* ── Side Panel (Drawer) ───────────────────────────────────────────────── */}
      <div className={`fixed inset-0 z-[100] transition-opacity duration-300 ${showModal ? "opacity-100 pointer-events-auto" : "opacity-0 pointer-events-none"}`}>
        <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px]" onClick={closeModal} />
        <div className={`absolute top-0 right-0 h-full w-full max-w-md bg-white shadow-2xl transform transition-transform duration-300 ease-out flex flex-col ${showModal ? "translate-x-0" : "translate-x-full"}`}>
          {/* Header */}
          <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100 shrink-0">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-[#7C3AED]/10 flex items-center justify-center">
                <span className="material-symbols-rounded text-[#7C3AED] text-xl">event_available</span>
              </div>
              <div>
                <h2 className="text-lg font-black text-slate-800 leading-tight">
                  {editingId ? "Edit Automation" : "New Automation"}
                </h2>
                <p className="text-[10px] font-bold text-slate-400   mt-0.5">Interview Configuration</p>
              </div>
            </div>
            <button onClick={closeModal} className="w-9 h-9 rounded-lg hover:bg-slate-100 flex items-center justify-center text-slate-400 transition-colors">
              <span className="material-symbols-rounded text-xl">close</span>
            </button>
          </div>
          
          {/* Tabs */}
          <div className="flex border-b border-slate-100 shrink-0">
            <button
              onClick={() => setActiveTab("config")}
              className={`flex-1 py-3 text-xs font-bold   relative transition-colors ${
                activeTab === "config" ? "text-[#7C3AED]" : "text-slate-400 hover:text-slate-600"
              }`}
            >
              Config
              {activeTab === "config" && (
                <div className="absolute bottom-0 left-0 w-full h-[2px] bg-[#7C3AED]" />
              )}
            </button>
            <button
              onClick={() => setActiveTab("times")}
              className={`flex-1 py-3 text-xs font-bold   relative transition-colors ${
                activeTab === "times" ? "text-[#7C3AED]" : "text-slate-400 hover:text-slate-600"
              }`}
            >
              Time Slots
              {activeTab === "times" && (
                <div className="absolute bottom-0 left-0 w-full h-[2px] bg-[#7C3AED]" />
              )}
            </button>
          </div>

          {/* Body */}
          <div className="flex-1 overflow-y-auto px-6 py-6 space-y-6 custom-scrollbar">
            {activeTab === "config" ? (
             <div className="space-y-6">
            {/* Job */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Job Requirement <span className="text-red-400">*</span>
              </label>
              <select
                value={form.job_requirement_id}
                onChange={(e) => setForm((f) => ({ ...f, job_requirement_id: e.target.value, stage_index: 1, stage_name: "" }))}
                className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
              >
                <option value="">Select job…</option>
                {jobs.map((j) => (
                  <option key={j.id} value={j.id}>{j.title}</option>
                ))}
              </select>
            </div>

            {/* Round */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Hiring Round <span className="text-red-400">*</span>
              </label>
              {jobRounds.length > 0 ? (
                <select
                  onChange={handleRoundSelect}
                  defaultValue=""
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                >
                  <option value="">Pick round…</option>
                  {jobRounds.map((r, i) => (
                    <option key={i} value={`${i + 1}|${r.name}`}>
                      Round {i + 1}: {r.name}
                    </option>
                  ))}
                </select>
              ) : (
                <div className="grid grid-cols-5 gap-3">
                  <input
                    type="number"
                    min={1}
                    value={form.stage_index}
                    onChange={(e) => setForm((f) => ({ ...f, stage_index: e.target.value }))}
                    className="col-span-2 border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    placeholder="No."
                  />
                  <input
                    type="text"
                    value={form.stage_name}
                    onChange={(e) => setForm((f) => ({ ...f, stage_name: e.target.value }))}
                    className="col-span-3 border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    placeholder="Label"
                  />
                </div>
              )}
              {jobRounds.length > 0 && (form.stage_name || Number(form.stage_index) > 1) && (
                <div className="mt-2 flex items-center gap-2 px-3 py-1.5 bg-[#7C3AED]/5 rounded-lg border border-[#7C3AED]/10">
                  <span className="material-symbols-rounded text-xs text-[#7C3AED]">check_circle</span>
                  <p className="text-[10px] text-[#7C3AED] font-bold  tracking-tight">
                    Selected: Round {form.stage_index} — {form.stage_name}
                  </p>
                </div>
              )}
            </div>

            {/* Criteria */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Trigger Criteria <span className="text-red-400">*</span>
              </label>
              <textarea
                rows={4}
                value={form.criteria}
                onChange={(e) => setForm((f) => ({ ...f, criteria: e.target.value }))}
                className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all resize-none"
                placeholder="Describe the condition, e.g. 'AI score > 80' or 'Interview cleared'…"
              />
              <p className="text-[10px] text-slate-400 mt-2 px-1">
                Set conditions for when this interview should be scheduled.
              </p>
            </div>

            {/* Dates (Optional) */}
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  Start Date (Optional)
                </label>
                <input
                  type="date"
                  value={form.start_date || ""}
                  onChange={(e) => setForm((f) => ({ ...f, start_date: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  End Date (Optional)
                </label>
                <input
                  type="date"
                  value={form.end_date || ""}
                  onChange={(e) => setForm((f) => ({ ...f, end_date: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                />
              </div>
            </div>

            {/* Timings and Caps */}
            <div className="grid grid-cols-3 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  Start Time <span className="text-red-400">*</span>
                </label>
                <input
                  type="time"
                  value={form.start_time}
                  onChange={(e) => setForm((f) => ({ ...f, start_time: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  End Time <span className="text-red-400">*</span>
                </label>
                <input
                  type="time"
                  value={form.end_time}
                  onChange={(e) => setForm((f) => ({ ...f, end_time: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                  Duration <span className="text-red-400">*</span>
                </label>
                <select
                  value={form.duration}
                  onChange={(e) => setForm((f) => ({ ...f, duration: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                >
                  <option value="15">15 mins</option>
                  <option value="30">30 mins</option>
                  <option value="45">45 mins</option>
                  <option value="60">60 mins</option>
                  <option value="90">90 mins</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Daily Limit (Max Interviews/Day) <span className="text-red-400">*</span>
              </label>
              <input
                type="number"
                min={1}
                value={form.daily_limit}
                onChange={(e) => setForm((f) => ({ ...f, daily_limit: e.target.value }))}
                className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
              />
            </div>

            {/* Template (Optional) */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Email Template (Optional)
              </label>
              {templates.length === 0 ? (
                <div className="bg-slate-50 rounded-lg p-4 border border-dashed border-slate-200">
                  <p className="text-xs text-slate-400 text-center">
                    No templates found. <a href="/enterprise/settings/templates" className="text-[#7C3AED] font-bold hover:underline" target="_blank">Create one</a> first.
                  </p>
                </div>
              ) : (
                <select
                  value={form.email_template_id}
                  onChange={(e) => setForm((f) => ({ ...f, email_template_id: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                >
                  <option value="">No template (use default invite)</option>
                  {templates.map((t) => (
                    <option key={t.id} value={t.id}>{t.name}</option>
                  ))}
                </select>
              )}
            </div>

            {/* Interview Type Selection */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-3 ml-1">
                Interview Type <span className="text-red-400">*</span>
              </label>
              <div className="grid grid-cols-2 gap-3">
                <button
                  onClick={() => setForm(f => ({ ...f, interview_type: "GMEET" }))}
                  className={`flex flex-col items-center gap-2 p-4 rounded-lg border-2 transition-all ${
                    form.interview_type === "GMEET" 
                      ? "border-[#7C3AED] bg-[#7C3AED]/5" 
                      : "border-slate-100 bg-white hover:border-slate-200"
                  }`}
                >
                  <span className={`material-symbols-rounded ${form.interview_type === "GMEET" ? "text-[#7C3AED]" : "text-slate-400"}`}>videocam</span>
                  <span className={`text-[11px] font-bold   ${form.interview_type === "GMEET" ? "text-[#7C3AED]" : "text-slate-500"}`}>Google Meet</span>
                </button>
                <button
                  onClick={() => setForm(f => ({ ...f, interview_type: "AI" }))}
                  className={`flex flex-col items-center gap-2 p-4 rounded-lg border-2 transition-all ${
                    form.interview_type === "AI" 
                      ? "border-[#7C3AED] bg-[#7C3AED]/5" 
                      : "border-slate-100 bg-white hover:border-slate-200"
                  }`}
                >
                  <span className={`material-symbols-rounded ${form.interview_type === "AI" ? "text-[#7C3AED]" : "text-slate-400"}`}>psychology</span>
                  <span className={`text-[11px] font-bold   ${form.interview_type === "AI" ? "text-[#7C3AED]" : "text-slate-500"}`}>AI Interview</span>
                </button>
              </div>
            </div>

            {form.interview_type === "AI" ? (
              <div className="space-y-4 pt-2">
                <div>
                  <div className="flex items-center justify-between mb-2">
                    <label className="text-[10px] font-black text-slate-500   ml-1">
                      AI Interview Template <span className="text-red-400">*</span>
                    </label>
                    <button 
                      onClick={() => {
                        setSelectedTemplateForEdit(null);
                        setShowTemplateBuilder(true);
                      }}
                      className="text-[10px] font-bold text-[#7C3AED] hover:underline flex items-center gap-1"
                    >
                      <span className="material-symbols-rounded text-xs">add_circle</span>
                      Create New
                    </button>
                  </div>
                  {interviewTemplates.length === 0 ? (
                    <div className="bg-slate-50 rounded-lg p-4 border border-dashed border-slate-200">
                      <p className="text-xs text-slate-400 text-center">
                        No AI templates found. 
                      </p>
                    </div>
                  ) : (
                    <select
                      value={form.interview_template_id || ""}
                      onChange={(e) => setForm(f => ({ ...f, interview_template_id: e.target.value }))}
                      className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    >
                      <option value="">Select template…</option>
                      {interviewTemplates.map((t) => (
                        <option key={t.id} value={t.id}>{t.title}</option>
                      ))}
                    </select>
                  )}
                </div>
              </div>
            ) : (
              <div className="space-y-4 pt-2">
                {/* Interviewer Email */}
                <div>
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Interviewer Email (Optional)
                  </label>
                  <input
                    type="email"
                    value={form.interviewer_email}
                    onChange={(e) => setForm((f) => ({ ...f, interviewer_email: e.target.value }))}
                    className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    placeholder="e.g. recruiter@company.com"
                  />
                  <p className="text-[10px] text-slate-400 mt-2 px-1">
                    If blank, system sends to your account email.
                  </p>
                </div>

                {/* Google Meet Link */}
                <div>
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Personal Google Meet Link (Real Room)
                  </label>
                  <input
                    type="url"
                    value={form.google_meet_link}
                    onChange={(e) => setForm((f) => ({ ...f, google_meet_link: e.target.value }))}
                    className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    placeholder="e.g. https://meet.google.com/abc-defg-hij"
                  />
                  <p className="text-[10px] text-slate-400 mt-2 px-1">
                    Paste your own real link here to skip automated generation.
                  </p>
                </div>
              </div>
            )}

            {/* Toggles Group */}
            <div className="space-y-3 pt-2">
              <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-lg transition-all hover:border-slate-200">
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-lg bg-white shadow-sm flex items-center justify-center">
                    <span className="material-symbols-rounded text-emerald-500 text-lg">check_circle</span>
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800">Enable Automation</p>
                    <p className="text-[10px] text-slate-400 font-medium">Turn rules on/off</p>
                  </div>
                </div>
                <button
                  onClick={() => setForm((f) => ({ ...f, is_enabled: !f.is_enabled }))}
                  className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none cursor-pointer ${form.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                >
                  <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.is_enabled ? "translate-x-5" : "translate-x-0"}`} />
                </button>
              </div>

              <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-lg transition-all hover:border-slate-200">
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-lg bg-white shadow-sm flex items-center justify-center">
                    <span className="material-symbols-rounded text-slate-600 text-lg">double_arrow</span>
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800">Auto-Move</p>
                    <p className="text-[10px] text-slate-400 font-medium">Advance to next round</p>
                  </div>
                </div>
                <button
                  onClick={() => setForm((f) => ({ ...f, auto_move: !f.auto_move }))}
                  className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none cursor-pointer ${form.auto_move ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                >
                  <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.auto_move ? "translate-x-5" : "translate-x-0"}`} />
                </button>
              </div>
            </div>
          </div>
          ) : (
            // TIME SLOTS TAB
            <div className="space-y-6">
              <div className="bg-slate-50 border border-slate-100 rounded-lg p-4">
                <p className="text-sm font-bold text-slate-800 mb-1">Pre-Generated Time Slots</p>
                <p className="text-xs text-slate-500 mb-4">
                  Instead of automatic scheduling, explicitly define exactly which {form.daily_limit} times per day the scheduler should use.
                </p>
                <div className="flex items-center gap-2">
                  <button
                    onClick={handleGenerateTimeSlots}
                    className="flex-1 flex justify-center items-center gap-2 py-2.5 bg-white border border-[#7C3AED] text-[#7C3AED] rounded-lg text-sm font-bold hover:bg-[#7C3AED]/5 transition-colors"
                  >
                    <span className="material-symbols-rounded text-base">magic_button</span>
                    Auto-Generate ({form.daily_limit} slots)
                  </button>
                  <button
                    onClick={() => setForm(f => ({ ...f, time_slots: [...f.time_slots, "12:00"] }))}
                    className="w-10 h-10 flex border border-slate-200 items-center justify-center rounded-lg hover:bg-slate-200 text-slate-400 transition-colors"
                    title="Add Slot manually"
                  >
                    <span className="material-symbols-rounded text-lg text-slate-600">add</span>
                  </button>
                </div>
              </div>

              {form.time_slots.length > 0 && (
                <div className="space-y-2">
                  {form.time_slots.map((ts, idx) => (
                    <div key={idx} className="flex flex-col mb-4">
                      <div className="flex items-center gap-2 relative">
                        <span className="absolute left-3 text-[10px] font-black  text-slate-400  leading-none pt-0.5 pointer-events-none">
                          Slot {idx + 1}
                        </span>
                        <div className="flex-1 flex items-center bg-slate-50 border border-slate-200 rounded-lg px-2 focus-within:ring-2 focus-within:ring-[#7C3AED]/50 transition-all">
                          <input
                            type="time"
                            value={ts}
                            onChange={(e) => {
                              const newSlots = [...form.time_slots];
                              newSlots[idx] = e.target.value;
                              setForm((f) => ({ ...f, time_slots: newSlots }));
                            }}
                            className="w-full bg-transparent pl-12 pr-2 py-3 text-sm font-bold text-slate-700 focus:outline-none font-mono"
                          />
                          <span className="text-xs text-slate-400 font-medium px-2 shrink-0 border-l border-slate-200 flex items-center h-8">
                            End: {(() => {
                               const [h, m] = ts.split(':').map(Number);
                               if (isNaN(h)) return "--:--";
                               const total = h * 60 + m + (Number(form.duration) || 30);
                               const eh = Math.floor(total / 60).toString().padStart(2, '0');
                               const em = (total % 60).toString().padStart(2, '0');
                               return `${eh}:${em}`;
                            })()}
                          </span>
                        </div>
                        <button
                          onClick={() => {
                            const newSlots = form.time_slots.filter((_, i) => i !== idx);
                            setForm((f) => ({ ...f, time_slots: newSlots }));
                          }}
                          className="w-11 h-11 shrink-0 bg-red-50 text-red-500 rounded-lg flex items-center justify-center hover:bg-red-500 hover:text-white transition-colors border border-red-100"
                        >
                          <span className="material-symbols-rounded text-[20px]">delete</span>
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
          </div>

          {/* Footer */}
          <div className="p-6 border-t border-slate-100 bg-slate-50/50 shrink-0">
            <button
              onClick={handleSave}
              disabled={saving}
              className="w-full flex items-center justify-center gap-2 h-12 bg-[#7C3AED] text-white rounded-lg text-sm font-black hover:bg-[#6d28d9] transition-all active:scale-[0.98] disabled:opacity-60 shadow-lg shadow-[#7C3AED]/20"
            >
              {saving ? (
                <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <>
                  <span className="material-symbols-rounded text-lg">save</span>
                  {editingId ? "SAVE CHANGES" : "CREATE AUTOMATION"}
                </>
              )}
            </button>
            <button 
              onClick={closeModal}
              className="w-full mt-3 h-10 text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors  "
            >
              Cancel
            </button>
          </div>
        </div>
      </div>

      {/* Template Builder Modal */}
      <AnimatePresence>
        {showTemplateBuilder && (
          <TemplateBuilder
            backendUrl={BACKEND_URL}
            token={token || ""}
            initialData={selectedTemplateForEdit}
            onClose={() => {
              setShowTemplateBuilder(false);
              setSelectedTemplateForEdit(null);
            }}
            onSave={(newTemplate) => {
              fetchInterviewTemplates();
              setShowTemplateBuilder(false);
              setSelectedTemplateForEdit(null);
              setForm(f => ({ ...f, interview_template_id: newTemplate.id }));
              showToast("Interview template saved!");
            }}
          />
        )}
      </AnimatePresence>
      <ConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => {
          setIsDeleteModalOpen(false);
          setAutomationToDelete(null);
        }}
        onConfirm={handleDelete}
        title="Delete Interview Automation?"
        message={`Are you sure you want to delete this interview automation for ${automationToDelete ? jobTitle(automationToDelete.job_requirement_id) : 'this job'}? This action is irreversible.`}
        confirmLabel="Yes, Delete"
        cancelLabel="No"
        isDestructive={true}
      />
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import ConfirmationModal from "@/components/common/ConfirmationModal";

// ─── Types ────────────────────────────────────────────────────────────────────

interface WorkflowStage {
  name: string;
  stage?: number;
  order?: number;
}

interface Job {
  id: string;
  title: string;
  workflow_stages?: WorkflowStage[] | null;
}

interface Template {
  id: string;
  name: string;
  subject: string;
}

interface Automation {
  id: string;
  job_requirement_id: string;
  stage_index: number;
  stage_name: string | null;
  criteria: string;
  template_id: string;
  auto_move: boolean;
  is_enabled: boolean;
  is_immediate: boolean;
  send_at: string | null;
  created_at: string;
}

interface FormState {
  job_requirement_id: string;
  stage_index: number | string;
  stage_name: string;
  criteria: string;
  template_id: string;
  auto_move: boolean;
  is_enabled: boolean;
  is_immediate: boolean;
  send_at: string;
}

const EMPTY_FORM: FormState = {
  job_requirement_id: "",
  stage_index: 1,
  stage_name: "",
  criteria: "",
  template_id: "",
  auto_move: false,
  is_enabled: true,
  is_immediate: true,
  send_at: "",
};

// ─── Main Page ────────────────────────────────────────────────────────────────

export default function MailAutomationPage() {
  const { token, canAccess } = useAuth();

  const authHeaders = {
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };

  const [jobs, setJobs] = useState<Job[]>([]);
  const [templates, setTemplates] = useState<Template[]>([]);
  const [automations, setAutomations] = useState<Automation[]>([]);
  const [selectedJobId, setSelectedJobId] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const [togglingId, setTogglingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [automationToDelete, setAutomationToDelete] = useState<Automation | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const showToast = (msg: string | string[] | { msg?: string; detail?: string } | null, type: "success" | "error" = "success") => {
    let finalMsg = "";
    if (typeof msg === "string") {
      finalMsg = msg;
    } else if (Array.isArray(msg)) {
      finalMsg = msg.map((e: string | { msg?: string }) => (typeof e === 'string' ? e : (e.msg || JSON.stringify(e)))).join(", ");
    } else if (msg && typeof msg === "object") {
      const obj = msg as { msg?: string; detail?: string };
      finalMsg = obj.msg || obj.detail || JSON.stringify(msg);
    } else {
      finalMsg = String(msg || "An error occurred");
    }
    setToast({ msg: finalMsg, type });
    setTimeout(() => setToast(null), 5000);
  };

  // Fetch jobs & templates on mount (wait for token)
  useEffect(() => {
    if (!token) return;
    const fetchMeta = async () => {
      try {
        const [jRes, tRes] = await Promise.all([
          fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, { headers: authHeaders }),
          fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, { headers: authHeaders }),
        ]);
        const jData = jRes.ok ? await jRes.json() : [];
        const tData = tRes.ok ? await tRes.json() : [];
        setJobs(Array.isArray(jData) ? jData : []);
        setTemplates(Array.isArray(tData) ? tData : []);
      } catch (e) {
        console.error("Failed to load meta:", e);
      }
    };
    fetchMeta();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  // Fetch automations when job selection changes
  const fetchAutomations = useCallback(async (jobId?: string) => {
    if (!token) return;
    setLoading(true);
    try {
      const qs = jobId ? `?job_id=${jobId}` : "";
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/automation/mail${qs}`, {
        headers: authHeaders,
      });
      if (res.ok) {
        const data = await res.json();
        setAutomations(Array.isArray(data) ? data : []);
      }
    } finally {
      setLoading(false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  useEffect(() => {
    if (showModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [showModal]);

  useEffect(() => {
    fetchAutomations(selectedJobId || undefined);
  }, [selectedJobId, fetchAutomations]);

  // Rounds extracted from the selected job's workflow_stages
  const selectedJob = jobs.find((j) => j.id === form.job_requirement_id);
  const jobRounds: WorkflowStage[] = selectedJob?.workflow_stages ?? [];

  // ── Modal helpers ────────────────────────────────────────────────────────────

  const openCreate = () => {
    setEditingId(null);
    setForm({ ...EMPTY_FORM, job_requirement_id: selectedJobId });
    setShowModal(true);
  };

  const openEdit = (a: Automation) => {
    setEditingId(a.id);
    setForm({
      job_requirement_id: a.job_requirement_id,
      stage_index: a.stage_index,
      stage_name: a.stage_name ?? "",
      criteria: a.criteria,
      template_id: a.template_id,
      auto_move: a.auto_move,
      is_enabled: a.is_enabled,
      is_immediate: a.is_immediate,
      send_at: a.send_at ? a.send_at.replace(' ', 'T').split('.')[0].slice(0, 16) : "", // Format for datetime-local input
    });
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingId(null);
    setForm(EMPTY_FORM);
  };

  // ── Save ─────────────────────────────────────────────────────────────────────

  const handleSave = async () => {
    if (!form.job_requirement_id || !form.criteria.trim() || !form.template_id) {
      showToast("Please fill in all required fields.", "error");
      return;
    }
    if (!form.is_immediate && form.send_at) {
      const scheduledDate = new Date(form.send_at);
      if (scheduledDate < new Date()) {
        showToast("Scheduled time cannot be in the past.", "error");
        return;
      }
    }
    setSaving(true);
    try {
      const payload = {
        ...form,
        stage_index: Number(form.stage_index),
        stage_name: form.stage_name.trim() || null,
        send_at: form.is_immediate ? null : (form.send_at ? new Date(form.send_at).toISOString() : null),
      };
      const url = editingId
        ? `${BACKEND_URL}/api/v1/enterprise/automation/mail/${editingId}`
        : `${BACKEND_URL}/api/v1/enterprise/automation/mail`;
      const method = editingId ? "PATCH" : "POST";
      const res = await fetch(url, {
        method,
        headers: authHeaders,
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        showToast(editingId ? "Automation updated!" : "Automation created!");
        closeModal();
        fetchAutomations(selectedJobId || undefined);
      } else {
        const err = await res.json().catch(() => ({}));
        showToast(err, "error");
      }
    } finally {
      setSaving(false);
    }
  };

  // ── Toggle ───────────────────────────────────────────────────────────────────

  const handleToggle = async (a: Automation) => {
    setTogglingId(a.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/automation/mail/${a.id}`, {
        method: "PATCH",
        headers: authHeaders,
        body: JSON.stringify({ is_enabled: !a.is_enabled }),
      });
      if (res.ok) {
        setAutomations((prev) =>
          prev.map((item) => (item.id === a.id ? { ...item, is_enabled: !a.is_enabled } : item))
        );
      } else {
        showToast("Failed to update status.", "error");
      }
    } finally {
      setTogglingId(null);
    }
  };

  // ── Delete ────────────────────────────────────────────────────────────────────

  const handleDelete = async () => {
    if (!automationToDelete) return;
    setDeletingId(automationToDelete.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/automation/mail/${automationToDelete.id}`, {
        method: "DELETE",
        headers: authHeaders,
      });
      if (res.ok) {
        showToast("Automation deleted.");
        setAutomations((prev) => prev.filter((a) => a.id !== automationToDelete.id));
      } else {
        showToast("Failed to delete.", "error");
      }
    } finally {
      setDeletingId(null);
      setIsDeleteModalOpen(false);
      setAutomationToDelete(null);
    }
  };

  // ── Helpers ──────────────────────────────────────────────────────────────────

  const jobTitle = (id: string) => jobs.find((j) => j.id === id)?.title ?? "—";
  const templateName = (id: string) => templates.find((t) => t.id === id)?.name ?? "—";

  // ── When user picks a round from dropdown, auto-fill stage_index + stage_name
  const handleRoundSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    if (val === "") return;
    const [idxStr, ...nameParts] = val.split("|");
    setForm((f) => ({
      ...f,
      stage_index: Number(idxStr),
      stage_name: nameParts.join("|"),
    }));
  };

  // ─── Computed ───────────────────────────────────────────────────────────────
  const filteredAutomations = automations.filter(a => {
    const term = searchQuery.toLowerCase();
    return a.criteria.toLowerCase().includes(term) ||
           jobTitle(a.job_requirement_id).toLowerCase().includes(term) ||
           templateName(a.template_id).toLowerCase().includes(term) ||
           (a.stage_name && a.stage_name.toLowerCase().includes(term));
  });

  // ─── Render ────────────────────────────────────────────────────────────────

  return (
    <div className="min-h-screen bg-[#F8FAFC] p-6 animate-in fade-in duration-500">
      {/* Toast */}
      {toast && (
        <div
          className={`fixed top-5 right-5 z-[200] flex items-center gap-2 px-4 py-3 rounded-lg shadow-lg text-sm font-semibold transition-all duration-300 ${
            toast.type === "success" ? "bg-[#7C3AED] text-white" : "bg-red-500 text-white"
          }`}
        >
          <span className="material-symbols-rounded text-base">
            {toast.type === "success" ? "check_circle" : "error"}
          </span>
          {String(toast.msg)}
        </div>
      )}

      {/* Header */}
      <div className="mb-10">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-start gap-4">
            <div className="w-12 h-12 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center shrink-0 shadow-sm shadow-[#7C3AED]/5">
              <span className="material-symbols-rounded text-[#7C3AED] text-2xl">mark_email_unread</span>
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">Mail Automation</h1>
              <p className="text-slate-500 text-[13px] font-medium mt-1">
                Configure automated emails for specific jobs and hiring rounds.
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3">
              {canAccess("communications:moderate") && (
                <button
                  onClick={openCreate}
                  className="flex items-center gap-2 px-5 h-11 bg-[#7C3AED] text-white rounded-lg text-xs font-black hover:bg-[#6d28d9] transition-all shadow-lg shadow-[#7C3AED]/20 active:scale-95"
                >
                  <span className="material-symbols-rounded text-lg">add</span>
                  NEW AUTOMATION
                </button>
              )}
          </div>
        </div>

        {/* Stats Section */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { label: "Total Rules", value: automations.length, icon: "rule", color: "indigo" },
            { label: "Active Rules", value: automations.filter(a => a.is_enabled).length, icon: "bolt", color: "emerald" },
            { label: "Immediate Trigger", value: automations.filter(a => a.is_immediate).length, icon: "flash_on", color: "amber" },
            { label: "Auto-Move Rules", value: automations.filter(a => a.auto_move).length, icon: "double_arrow", color: "purple" }
          ].map((stat, i) => (
            <div key={i} className="group bg-white p-5 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-[#7C3AED]/20 transition-all duration-300">
              <div className="flex items-start justify-between mb-4">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center transition-transform group-hover:scale-110 ${
                  stat.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
                  stat.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
                  stat.color === 'amber' ? 'bg-amber-50 text-amber-600' :
                  'bg-purple-50 text-purple-600'
                }`}>
                  <span className="material-symbols-rounded text-xl">{stat.icon}</span>
                </div>
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Live</span>
              </div>
              <p className="text-2xl font-black text-slate-900 mb-0.5 tracking-tight">{stat.value}</p>
              <p className="text-[11px] font-bold text-slate-400 capitalize">{stat.label}</p>
            </div>
          ))}
        </div>

        {/* Interaction Bar */}
        <div className="mt-8 flex flex-col md:flex-row items-center gap-4">
           <div className="flex-1 relative w-full">
              <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg">search</span>
              <input 
                type="text"
                placeholder="Search by rules, jobs, or templates..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full h-11 bg-white border border-slate-200 rounded-lg pl-11 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none"
              />
           </div>

           <div className="flex items-center gap-3 w-full md:w-auto">
              <div className="relative w-full md:w-64">
                <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">work</span>
                <select
                  value={selectedJobId}
                  onChange={(e) => setSelectedJobId(e.target.value)}
                  className="w-full h-11 border border-slate-200 rounded-lg pl-10 pr-10 text-xs font-bold text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/5 focus:border-[#7C3AED] shadow-sm appearance-none cursor-pointer"
                >
                  <option value="">All Job Requirements</option>
                  {jobs.map((j) => (
                    <option key={j.id} value={j.id}>{j.title}</option>
                  ))}
                </select>
                <span className="material-symbols-rounded absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">expand_more</span>
              </div>
           </div>
        </div>
      </div>

      {/* List */}
      {loading ? (
        <div className="flex justify-center py-20">
          <div className="w-8 h-8 border-4 border-[#7C3AED] border-t-transparent rounded-full animate-spin" />
        </div>
      ) : filteredAutomations.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <div className="w-16 h-16 rounded-lg bg-[#7C3AED]/5 flex items-center justify-center mb-4">
            <span className="material-symbols-rounded text-[#7C3AED] text-4xl">mark_email_unread</span>
          </div>
          <p className="text-slate-700 font-bold text-lg">{searchQuery ? 'No matching rules' : 'No automations yet'}</p>
          <p className="text-slate-400 text-sm mt-1 max-w-xs">
            {searchQuery ? `We couldn't find any results for "${searchQuery}"` : 'Create your first mail automation to automatically trigger emails when your criteria are met.'}
          </p>
          {!searchQuery && canAccess("communications:moderate") && (
            <button
              onClick={openCreate}
              className="mt-5 flex items-center gap-2 px-4 py-2 bg-[#7C3AED] text-white rounded-lg text-sm font-bold hover:bg-[#6d28d9] transition-colors"
            >
              <span className="material-symbols-rounded text-base">add</span>
              Create Automation
            </button>
          )}
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Rule Configuration</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Job & Template</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Trigger/Schedule</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredAutomations.map((a) => (
                  <tr key={a.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-2">
                          <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[9px] font-black uppercase">
                            Round {a.stage_index}
                          </span>
                          {a.stage_name && (
                            <span className="text-[10px] font-bold text-slate-400">{a.stage_name}</span>
                          )}
                        </div>
                        <p className="text-xs font-bold text-slate-800 line-clamp-1">
                          <span className="text-slate-400 font-medium italic mr-1">If:</span>
                          {a.criteria}
                        </p>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-slate-700">
                          <span className="material-symbols-rounded text-sm text-slate-400">work</span>
                          {jobTitle(a.job_requirement_id)}
                        </div>
                        <div className="flex items-center gap-1.5 text-[10px] font-medium text-slate-400">
                          <span className="material-symbols-rounded text-sm text-slate-300">description</span>
                          {templateName(a.template_id)}
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-slate-700">
                          <span className="material-symbols-rounded text-sm text-slate-400">schedule</span>
                          {a.is_immediate ? "Immediate" : new Date(a.send_at!).toLocaleString()}
                        </div>
                        {a.auto_move && (
                          <div className="flex items-center gap-1 text-[9px] font-black text-emerald-600 uppercase">
                            <span className="material-symbols-rounded text-xs">keyboard_double_arrow_right</span>
                            Auto-Move Active
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <button
                        onClick={() => handleToggle(a)}
                        disabled={togglingId === a.id}
                        className={`relative w-9 h-5 rounded-full transition-colors duration-200 focus:outline-none ${a.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"} ${togglingId === a.id ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}`}
                      >
                        <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform duration-200 ${a.is_enabled ? "translate-x-4" : "translate-x-0"}`} />
                      </button>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-1">
                        {canAccess("communications:moderate") && (
                          <button onClick={() => openEdit(a)} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 text-slate-400 hover:text-[#7C3AED] transition-colors">
                            <span className="material-symbols-rounded text-base">edit</span>
                          </button>
                        )}
                        {canAccess("communications:delete") && (
                          <button onClick={() => {
                            setAutomationToDelete(a);
                            setIsDeleteModalOpen(true);
                          }} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-red-50 text-slate-400 hover:text-red-500 transition-colors">
                            <span className="material-symbols-rounded text-base">delete</span>
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── Side Panel (Drawer) ───────────────────────────────────────────────── */}
      <div className={`fixed inset-0 z-[100] transition-opacity duration-300 ${showModal ? "opacity-100 pointer-events-auto" : "opacity-0 pointer-events-none"}`}>
        <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px]" onClick={closeModal} />
        <div className={`absolute top-0 right-0 h-full w-full max-w-md bg-white shadow-2xl transform transition-transform duration-300 ease-out flex flex-col ${showModal ? "translate-x-0" : "translate-x-full"}`}>
          {/* Header */}
          <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100 shrink-0">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-[#7C3AED]/10 flex items-center justify-center">
                <span className="material-symbols-rounded text-[#7C3AED] text-xl">mark_email_unread</span>
              </div>
              <div>
                <h2 className="text-lg font-black text-slate-800 leading-tight">
                  {editingId ? "Edit Automation" : "New Automation"}
                </h2>
                <p className="text-[10px] font-bold text-slate-400   mt-0.5">Mail Configuration</p>
              </div>
            </div>
            <button onClick={closeModal} className="w-9 h-9 rounded-lg hover:bg-slate-100 flex items-center justify-center text-slate-400 transition-colors">
              <span className="material-symbols-rounded text-xl">close</span>
            </button>
          </div>

          {/* Body */}
          <div className="flex-1 overflow-y-auto px-6 py-6 space-y-6 custom-scrollbar">
            {/* Job */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Job Requirement <span className="text-red-400">*</span>
              </label>
              <select
                value={form.job_requirement_id}
                onChange={(e) => setForm((f) => ({ ...f, job_requirement_id: e.target.value, stage_index: 1, stage_name: "" }))}
                className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
              >
                <option value="">Select job…</option>
                {jobs.map((j) => (
                  <option key={j.id} value={j.id}>{j.title}</option>
                ))}
              </select>
            </div>

            {/* Round */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Hiring Round <span className="text-red-400">*</span>
              </label>
              {jobRounds.length > 0 ? (
                <select
                  onChange={handleRoundSelect}
                  defaultValue=""
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                >
                  <option value="">Pick round…</option>
                  {jobRounds.map((r, i) => (
                    <option key={i} value={`${i + 1}|${r.name}`}>
                      Round {i + 1}: {r.name}
                    </option>
                  ))}
                </select>
              ) : (
                <div className="grid grid-cols-5 gap-3">
                  <input
                    type="number"
                    min={1}
                    value={form.stage_index}
                    onChange={(e) => setForm((f) => ({ ...f, stage_index: e.target.value }))}
                    className="col-span-2 border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    placeholder="No."
                  />
                  <input
                    type="text"
                    value={form.stage_name}
                    onChange={(e) => setForm((f) => ({ ...f, stage_name: e.target.value }))}
                    className="col-span-3 border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    placeholder="Label"
                  />
                </div>
              )}
              {jobRounds.length > 0 && (form.stage_name || Number(form.stage_index) > 1) && (
                <div className="mt-2 flex items-center gap-2 px-3 py-1.5 bg-[#7C3AED]/5 rounded-lg border border-[#7C3AED]/10">
                  <span className="material-symbols-rounded text-xs text-[#7C3AED]">check_circle</span>
                  <p className="text-[10px] text-[#7C3AED] font-bold  tracking-tight">
                    Selected: Round {form.stage_index} — {form.stage_name}
                  </p>
                </div>
              )}
            </div>

            {/* Criteria */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Trigger Criteria <span className="text-red-400">*</span>
              </label>
              <textarea
                rows={4}
                value={form.criteria}
                onChange={(e) => setForm((f) => ({ ...f, criteria: e.target.value }))}
                className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all resize-none"
                placeholder="Describe the condition, e.g. 'AI score > 80' or 'Interview cleared'…"
              />
              <p className="text-[10px] text-slate-400 mt-2 px-1">
                Clear plain-language conditions help your team know when to send.
              </p>
            </div>

            {/* Template */}
            <div>
              <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                Email Template <span className="text-red-400">*</span>
              </label>
              {templates.length === 0 ? (
                <div className="bg-slate-50 rounded-lg p-4 border border-dashed border-slate-200">
                  <p className="text-xs text-slate-400 text-center">
                    No templates found. <a href="/enterprise/settings/templates" className="text-[#7C3AED] font-bold hover:underline" target="_blank">Create one</a> first.
                  </p>
                </div>
              ) : (
                <select
                  value={form.template_id}
                  onChange={(e) => setForm((f) => ({ ...f, template_id: e.target.value }))}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                >
                  <option value="">Select template…</option>
                  {templates.map((t) => (
                    <option key={t.id} value={t.id}>{t.name}</option>
                  ))}
                </select>
              )}
            </div>

            {/* Toggles Group */}
            <div className="space-y-3 pt-2">
              <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-lg transition-all hover:border-slate-200">
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-lg bg-white shadow-sm flex items-center justify-center">
                    <span className="material-symbols-rounded text-emerald-500 text-lg">check_circle</span>
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800">Enable Automation</p>
                    <p className="text-[10px] text-slate-400 font-medium">Turn rules on/off</p>
                  </div>
                </div>
                <button
                  onClick={() => setForm((f) => ({ ...f, is_enabled: !f.is_enabled }))}
                  className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none cursor-pointer ${form.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                >
                  <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.is_enabled ? "translate-x-5" : "translate-x-0"}`} />
                </button>
              </div>

              <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-lg transition-all hover:border-slate-200">
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-lg bg-white shadow-sm flex items-center justify-center">
                    <span className="material-symbols-rounded text-slate-600 text-lg">bolt</span>
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800">Send Immediately</p>
                    <p className="text-[10px] text-slate-400 font-medium">Auto-send on round change</p>
                  </div>
                </div>
                <button
                  onClick={() => setForm((f) => ({ ...f, is_immediate: !f.is_immediate }))}
                  className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none cursor-pointer ${form.is_immediate ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                >
                  <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.is_immediate ? "translate-x-5" : "translate-x-0"}`} />
                </button>
              </div>

              {!form.is_immediate && (
                <div className="animate-in slide-in-from-top-2 duration-200 px-1">
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Scheduled Date & Time <span className="text-red-400">*</span>
                  </label>
                  <input
                    type="datetime-local"
                    value={form.send_at}
                    onChange={(e) => setForm((f) => ({ ...f, send_at: e.target.value }))}
                    className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                  />
                </div>
              )}

              <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-lg transition-all hover:border-slate-200">
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-lg bg-white shadow-sm flex items-center justify-center">
                    <span className="material-symbols-rounded text-slate-600 text-lg">double_arrow</span>
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800">Auto-Move</p>
                    <p className="text-[10px] text-slate-400 font-medium">Advance to next round</p>
                  </div>
                </div>
                <button
                  onClick={() => setForm((f) => ({ ...f, auto_move: !f.auto_move }))}
                  className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none cursor-pointer ${form.auto_move ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                >
                  <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.auto_move ? "translate-x-5" : "translate-x-0"}`} />
                </button>
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="p-6 border-t border-slate-100 bg-slate-50/50 shrink-0">
            <button
              onClick={handleSave}
              disabled={saving}
              className="w-full flex items-center justify-center gap-2 h-12 bg-[#7C3AED] text-white rounded-lg text-sm font-black hover:bg-[#6d28d9] transition-all active:scale-[0.98] disabled:opacity-60 shadow-lg shadow-[#7C3AED]/20"
            >
              {saving ? (
                <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <>
                  <span className="material-symbols-rounded text-lg">save</span>
                  {editingId ? "SAVE CHANGES" : "CREATE AUTOMATION"}
                </>
              )}
            </button>
            <button 
              onClick={closeModal}
              className="w-full mt-3 h-10 text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors  "
            >
              Cancel
            </button>
          </div>
        </div>
      </div>
      <ConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => {
          setIsDeleteModalOpen(false);
          setAutomationToDelete(null);
        }}
        onConfirm={handleDelete}
        title="Delete Mail Automation?"
        message={`Are you sure you want to delete this mail automation for ${automationToDelete ? jobTitle(automationToDelete.job_requirement_id) : 'this job'}? This action is irreversible.`}
        confirmLabel="Yes, Delete"
        cancelLabel="No"
        isDestructive={true}
      />
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useMemo } from "react";
import { useAuth } from "@/context/AuthContext";
import { motion, AnimatePresence } from "framer-motion";
import { BACKEND_URL } from "@/utils/api";
import ConfirmationModal from "@/components/common/ConfirmationModal";

// --- Types ---

interface WorkflowStage {
  name: string;
  stage?: number;
  order?: number;
}

interface Job {
  id: string;
  title: string;
  workflow_stages?: WorkflowStage[] | null;
}

interface OnboardingTemplate {
  id: string;
  name: string;
  description?: string;
}

interface EmailTemplate {
  id: string;
  name: string;
  subject: string;
}

interface OnboardingAutomation {
  id: string;
  job_requirement_id: string;
  stage_index: number;
  stage_name: string | null;
  template_id: string;
  email_template_id: string | null;
  is_enabled: boolean;
  auto_move: boolean;
  created_at: string;
  template?: OnboardingTemplate;
  email_template?: EmailTemplate;
}

interface FormState {
  job_requirement_id: string;
  stage_index: number | string;
  stage_name: string;
  template_id: string;
  email_template_id: string;
  is_enabled: boolean;
  auto_move: boolean;
}

const EMPTY_FORM: FormState = {
  job_requirement_id: "",
  stage_index: 0,
  stage_name: "",
  template_id: "",
  email_template_id: "",
  is_enabled: true,
  auto_move: false,
};

export default function OnboardingAutomationPage() {
  const { token, canAccess } = useAuth();

  const authHeaders = useMemo(() => ({
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  }), [token]);

  const [jobs, setJobs] = useState<Job[]>([]);
  const [onboardingTemplates, setOnboardingTemplates] = useState<OnboardingTemplate[]>([]);
  const [emailTemplates, setEmailTemplates] = useState<EmailTemplate[]>([]);
  const [automations, setAutomations] = useState<OnboardingAutomation[]>([]);
  const [selectedJobId, setSelectedJobId] = useState<string>("");
  const [searchQuery, setSearchQuery] = useState("");
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const [togglingId, setTogglingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [automationToDelete, setAutomationToDelete] = useState<OnboardingAutomation | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const showToast = (msg: string | string[] | { msg?: string; detail?: string } | null, type: "success" | "error" = "success") => {
    let finalMsg = "";
    if (typeof msg === "string") {
      finalMsg = msg;
    } else if (Array.isArray(msg)) {
      finalMsg = msg.map((e: string | { msg?: string }) => (typeof e === 'string' ? e : (e.msg || JSON.stringify(e)))).join(", ");
    } else if (msg && typeof msg === "object") {
      const obj = msg as { msg?: string; detail?: string };
      finalMsg = obj.msg || obj.detail || JSON.stringify(msg);
    } else {
      finalMsg = String(msg || "An error occurred");
    }
    setToast({ msg: finalMsg, type });
    setTimeout(() => setToast(null), 5000);
  };

  // Fetch metadata
  useEffect(() => {
    if (!token) return;
    const fetchMeta = async () => {
      try {
        const [jRes, tRes, eRes] = await Promise.all([
          fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, { headers: authHeaders }),
          fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/`, { headers: authHeaders }),
          fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, { headers: authHeaders }),
        ]);
        const jData = jRes.ok ? await jRes.json() : [];
        const tData = tRes.ok ? await tRes.json() : [];
        const eData = eRes.ok ? await eRes.json() : [];
        setJobs(Array.isArray(jData) ? jData : []);
        setOnboardingTemplates(Array.isArray(tData) ? tData : []);
        setEmailTemplates(Array.isArray(eData) ? eData : []);
      } catch (e) {
        console.error("Failed to load meta:", e);
      }
    };
    fetchMeta();
  }, [token, authHeaders]);

  // Fetch automations
  const fetchAutomations = useCallback(async (jobId?: string) => {
    if (!token) return;
    setLoading(true);
    try {
      const qs = jobId ? `?job_id=${jobId}` : "";
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding-automation/${qs}`, {
        headers: authHeaders,
      });
      if (res.ok) {
        const data = await res.json();
        setAutomations(Array.isArray(data) ? data : []);
      }
    } finally {
      setLoading(false);
    }
  }, [token, authHeaders]);

  useEffect(() => {
    if (token) {
      fetchAutomations(selectedJobId || undefined);
    }
  }, [token, selectedJobId, fetchAutomations]);

  const selectedJob = jobs.find((j) => j.id === form.job_requirement_id);
  const jobRounds: WorkflowStage[] = selectedJob?.workflow_stages ?? [];

  const openCreate = () => {
    setEditingId(null);
    setForm({ ...EMPTY_FORM, job_requirement_id: selectedJobId });
    setShowModal(true);
  };

  const openEdit = (a: OnboardingAutomation) => {
    setEditingId(a.id);
    setForm({
      job_requirement_id: a.job_requirement_id,
      stage_index: a.stage_index,
      stage_name: a.stage_name ?? "",
      template_id: a.template_id,
      email_template_id: a.email_template_id || "",
      is_enabled: a.is_enabled,
      auto_move: a.auto_move || false,
    });
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingId(null);
    setForm(EMPTY_FORM);
  };

  const handleSave = async () => {
    if (!form.job_requirement_id || !form.template_id) {
      showToast("Please select a job and an onboarding template.", "error");
      return;
    }
    setSaving(true);
    try {
      const payload: Record<string, any> = {
        stage_index: Number(form.stage_index),
        stage_name: form.stage_name?.trim() || null,
        template_id: form.template_id,
        email_template_id: form.email_template_id || null,
        is_enabled: form.is_enabled,
        auto_move: form.auto_move,
      };
      
      if (!editingId) {
        payload.job_requirement_id = form.job_requirement_id;
      }
      const url = editingId
        ? `${BACKEND_URL}/api/v1/enterprise/onboarding-automation/${editingId}`
        : `${BACKEND_URL}/api/v1/enterprise/onboarding-automation/`;
      const method = editingId ? "PATCH" : "POST";
      const res = await fetch(url, {
        method,
        headers: authHeaders,
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        showToast(editingId ? "Automation updated!" : "Automation created!");
        closeModal();
        fetchAutomations(selectedJobId || undefined);
      } else {
        const err = await res.json().catch(() => ({}));
        showToast(err, "error");
      }
    } finally {
      setSaving(false);
    }
  };

  const handleToggle = async (a: OnboardingAutomation) => {
    setTogglingId(a.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding-automation/${a.id}`, {
        method: "PATCH",
        headers: authHeaders,
        body: JSON.stringify({ is_enabled: !a.is_enabled }),
      });
      if (res.ok) {
        setAutomations((prev) =>
          prev.map((item) => (item.id === a.id ? { ...item, is_enabled: !a.is_enabled } : item))
        );
      } else {
        showToast("Failed to update status.", "error");
      }
    } finally {
      setTogglingId(null);
    }
  };

  const handleDelete = async () => {
    if (!automationToDelete) return;
    setDeletingId(automationToDelete.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding-automation/${automationToDelete.id}`, {
        method: "DELETE",
        headers: authHeaders,
      });
      if (res.ok) {
        showToast("Automation deleted.");
        setAutomations((prev) => prev.filter((a) => a.id !== automationToDelete.id));
      } else {
        showToast("Failed to delete.", "error");
      }
    } finally {
      setDeletingId(null);
      setIsDeleteModalOpen(false);
      setAutomationToDelete(null);
    }
  };

  const handleRoundSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    if (val === "") return;
    const [idxStr, ...nameParts] = val.split("|");
    setForm((f) => ({
      ...f,
      stage_index: Number(idxStr),
      stage_name: nameParts.join("|"),
    }));
  };

  const getJobTitle = (id: string) => jobs.find((j) => j.id === id)?.title ?? "—";
  const getTemplateName = (id: string) => onboardingTemplates.find((t) => t.id === id)?.name ?? "—";
  const getEmailTemplateName = (id: string | null) => id ? (emailTemplates.find((t) => t.id === id)?.name ?? "—") : "None";

  // ─── Computed ───────────────────────────────────────────────────────────────
  const filteredAutomations = automations.filter(a => {
    const term = searchQuery.toLowerCase();
    return getTemplateName(a.template_id).toLowerCase().includes(term) ||
           getJobTitle(a.job_requirement_id).toLowerCase().includes(term) ||
           (a.stage_name && a.stage_name.toLowerCase().includes(term));
  });

  return (
    <div className="min-h-screen bg-[#F8FAFC] p-6 animate-in fade-in duration-500">
      {/* Toast */}
      {toast && (
        <div
          className={`fixed top-5 right-5 z-[200] flex items-center gap-2 px-4 py-3 rounded-lg shadow-lg text-sm font-semibold transition-all duration-300 ${
            toast.type === "success" ? "bg-[#7C3AED] text-white" : "bg-red-500 text-white"
          }`}
        >
          <span className="material-symbols-rounded text-base">
            {toast.type === "success" ? "check_circle" : "error"}
          </span>
          {String(toast.msg)}
        </div>
      )}

      {/* Header */}
      <div className="mb-10">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-start gap-4">
            <div className="w-12 h-12 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center shrink-0 shadow-sm shadow-[#7C3AED]/5">
              <span className="material-symbols-rounded text-[#7C3AED] text-2xl">person_add</span>
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">Onboarding Automation</h1>
              <p className="text-slate-500 text-[13px] font-medium mt-1">
                Automatically trigger onboarding processes when candidates reach specific hiring stages.
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3">
             {canAccess("automation:moderate") && (
                <button
                  onClick={openCreate}
                  className="flex items-center gap-2 px-5 h-11 bg-[#7C3AED] text-white rounded-lg text-xs font-black hover:bg-[#6d28d9] transition-all shadow-lg shadow-[#7C3AED]/20 active:scale-95"
                >
                  <span className="material-symbols-rounded text-lg">add</span>
                  NEW AUTOMATION
                </button>
              )}
          </div>
        </div>

        {/* Stats Section */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { label: "Total Rules", value: automations.length, icon: "rule", color: "indigo" },
            { label: "Active Rules", value: automations.filter(a => a.is_enabled).length, icon: "bolt", color: "emerald" },
            { label: "Auto-Move Rules", value: automations.filter(a => a.auto_move).length, icon: "double_arrow", color: "amber" },
            { label: "Templates Used", value: new Set(automations.map(a => a.template_id)).size, icon: "description", color: "purple" }
          ].map((stat, i) => (
            <div key={i} className="group bg-white p-5 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-[#7C3AED]/20 transition-all duration-300">
              <div className="flex items-start justify-between mb-4">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center transition-transform group-hover:scale-110 ${
                  stat.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
                  stat.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
                  stat.color === 'amber' ? 'bg-amber-50 text-amber-600' :
                  'bg-purple-50 text-purple-600'
                }`}>
                  <span className="material-symbols-rounded text-xl">{stat.icon}</span>
                </div>
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Live</span>
              </div>
              <p className="text-2xl font-black text-slate-900 mb-0.5 tracking-tight">{stat.value}</p>
              <p className="text-[11px] font-bold text-slate-400 capitalize">{stat.label}</p>
            </div>
          ))}
        </div>

        {/* Interaction Bar */}
        <div className="mt-8 flex flex-col md:flex-row items-center gap-4">
           <div className="flex-1 relative w-full">
              <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg">search</span>
              <input 
                type="text"
                placeholder="Search by rules, jobs, or templates..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full h-11 bg-white border border-slate-200 rounded-lg pl-11 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none"
              />
           </div>

           <div className="flex items-center gap-3 w-full md:w-auto">
              {(searchQuery || selectedJobId) && (
                <button 
                  onClick={() => { setSearchQuery(""); setSelectedJobId(""); }}
                  className="text-[11px] font-black text-[#7C3AED] hover:underline px-2 tracking-tight"
                >
                  RESET FILTERS
                </button>
              )}
              <div className="relative w-full md:w-64">
                <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">work</span>
                <select
                  value={selectedJobId}
                  onChange={(e) => setSelectedJobId(e.target.value)}
                  className="w-full h-11 border border-slate-200 rounded-lg pl-10 pr-10 text-xs font-bold text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/5 focus:border-[#7C3AED] shadow-sm appearance-none cursor-pointer"
                >
                  <option value="">All Job Requirements</option>
                  {jobs.map((j) => (
                    <option key={j.id} value={j.id}>{j.title}</option>
                  ))}
                </select>
                <span className="material-symbols-rounded absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">expand_more</span>
              </div>
           </div>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-20">
          <div className="w-8 h-8 border-4 border-[#7C3AED] border-t-transparent rounded-full animate-spin" />
        </div>
      ) : filteredAutomations.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <div className="w-16 h-16 rounded-lg bg-[#7C3AED]/5 flex items-center justify-center mb-4">
            <span className="material-symbols-rounded text-[#7C3AED] text-4xl">person_add</span>
          </div>
          <p className="text-slate-700 font-bold text-lg">{searchQuery ? 'No matching rules' : 'No onboarding automations'}</p>
          <p className="text-slate-400 text-sm mt-1 max-w-xs">
            {searchQuery ? `We couldn't find any results for "${searchQuery}"` : 'Set up an automation to auto-start onboarding when a candidate reaches a certain stage.'}
          </p>
          {!searchQuery && (
            <button
              onClick={openCreate}
              className="mt-5 flex items-center gap-2 px-4 py-2 bg-[#7C3AED] text-white rounded-lg text-sm font-bold hover:bg-[#6d28d9] transition-colors"
            >
              <span className="material-symbols-rounded text-base">add</span>
              Create Automation
            </button>
          )}
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Automation Details</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Job</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Onboarding Template</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                  <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredAutomations.map((a) => (
                  <tr key={a.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-2">
                          <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[9px] font-black uppercase">
                            Stage {a.stage_index}
                          </span>
                          {a.stage_name && (
                            <span className="text-[10px] font-bold text-slate-400">{a.stage_name}</span>
                          )}
                        </div>
                        <p className="text-xs font-bold text-slate-800 line-clamp-1">
                          <span className="text-slate-400 font-medium italic mr-1">Trigger:</span>
                          Move to stage
                        </p>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-1.5 text-xs font-bold text-slate-700">
                        <span className="material-symbols-rounded text-sm text-slate-400">work</span>
                        {getJobTitle(a.job_requirement_id)}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-slate-700">
                          <span className="material-symbols-rounded text-sm text-slate-400">description</span>
                          {getTemplateName(a.template_id)}
                        </div>
                        {a.email_template_id && (
                          <div className="flex items-center gap-1.5 text-[10px] font-medium text-[#7C3AED]">
                            <span className="material-symbols-rounded text-sm">mail</span>
                            Welcome Email Active
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <button
                        onClick={() => handleToggle(a)}
                        disabled={togglingId === a.id || !canAccess("automation:moderate")}
                        className={`relative w-9 h-5 rounded-full transition-colors duration-200 focus:outline-none ${a.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"} ${togglingId === a.id || !canAccess("automation:moderate") ? "opacity-30 cursor-not-allowed" : "cursor-pointer"}`}
                      >
                        <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform duration-200 ${a.is_enabled ? "translate-x-4" : "translate-x-0"}`} />
                      </button>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-1">
                        {canAccess("automation:moderate") && (
                          <button onClick={() => openEdit(a)} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 text-slate-400 hover:text-[#7C3AED] transition-colors">
                            <span className="material-symbols-rounded text-base">edit</span>
                          </button>
                        )}
                        {canAccess("automation:moderate") && (
                          <button onClick={() => {
                            setAutomationToDelete(a);
                            setIsDeleteModalOpen(true);
                          }} disabled={deletingId === a.id} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-red-50 text-slate-400 hover:text-red-500 transition-colors">
                            <span className="material-symbols-rounded text-base">delete</span>
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal / Drawer */}
      <AnimatePresence>
        {showModal && (
          <div className="fixed inset-0 z-[100] flex justify-end">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px]"
              onClick={closeModal}
            />
            <motion.div
              initial={{ x: "100%" }}
              animate={{ x: 0 }}
              exit={{ x: "100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 200 }}
              className="relative w-full max-w-md bg-white shadow-2xl h-full flex flex-col"
            >
              <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100 shrink-0">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-lg bg-[#7C3AED]/10 flex items-center justify-center">
                    <span className="material-symbols-rounded text-[#7C3AED] text-xl">person_add</span>
                  </div>
                  <div>
                    <h2 className="text-lg font-black text-slate-800 leading-tight">
                      {editingId ? "Edit Automation" : "New Automation"}
                    </h2>
                    <p className="text-[10px] font-bold text-slate-400   mt-0.5">Onboarding Config</p>
                  </div>
                </div>
                <button onClick={closeModal} className="w-9 h-9 rounded-lg hover:bg-slate-100 flex items-center justify-center text-slate-400 transition-colors">
                  <span className="material-symbols-rounded text-xl">close</span>
                </button>
              </div>

              <div className="flex-1 overflow-y-auto px-6 py-6 space-y-6">
                {/* Job */}
                <div>
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Job Requirement <span className="text-red-400">*</span>
                  </label>
                  <select
                    value={form.job_requirement_id}
                    onChange={(e) => setForm((f) => ({ ...f, job_requirement_id: e.target.value, stage_index: 0, stage_name: "" }))}
                    disabled={!!editingId}
                    className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] disabled:bg-slate-50 disabled:text-slate-400 transition-all"
                  >
                    <option value="">Select job…</option>
                    {jobs.map((j) => (
                      <option key={j.id} value={j.id}>{j.title}</option>
                    ))}
                  </select>
                </div>

                {/* Round */}
                <div>
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Trigger Stage <span className="text-red-400">*</span>
                  </label>
                  {jobRounds.length > 0 ? (
                    <select
                      onChange={(e) => {
                        const idx = Number(e.target.value);
                        if (idx === 0) {
                          setForm(f => ({ ...f, stage_index: 0, stage_name: "" }));
                          return;
                        }
                        const round = jobRounds[idx - 1];
                        setForm(f => ({ ...f, stage_index: idx, stage_name: round?.name || "" }));
                      }}
                      value={form.stage_index}
                      className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                    >
                      <option value={0}>Pick stage…</option>
                      {jobRounds.map((r, i) => (
                        <option key={i} value={i + 1}>
                          Stage {i + 1}: {r.name}
                        </option>
                      ))}
                    </select>
                  ) : (
                    <div className="grid grid-cols-5 gap-3">
                      <input
                        type="number"
                        min={1}
                        value={form.stage_index}
                        onChange={(e) => setForm((f) => ({ ...f, stage_index: e.target.value }))}
                        className="col-span-2 border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                        placeholder="Idx"
                      />
                      <input
                        type="text"
                        value={form.stage_name}
                        onChange={(e) => setForm((f) => ({ ...f, stage_name: e.target.value }))}
                        className="col-span-3 border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:ring-4 focus:ring-[#4f46e5]/10 focus:border-[#4f46e5] transition-all"
                        placeholder="Stage Name"
                      />
                    </div>
                  )}
                </div>

                {/* Onboarding Template */}
                <div>
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Onboarding Template <span className="text-red-400">*</span>
                  </label>
                  <select
                    value={form.template_id}
                    onChange={(e) => setForm((f) => ({ ...f, template_id: e.target.value }))}
                    className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                  >
                    <option value="">Select template…</option>
                    {onboardingTemplates.map((t) => (
                      <option key={t.id} value={t.id}>{t.name}</option>
                    ))}
                  </select>
                </div>

                {/* Email Template */}
                <div>
                  <label className="block text-[10px] font-black text-slate-500   mb-2 ml-1">
                    Introduction Email Template
                  </label>
                  <select
                    value={form.email_template_id}
                    onChange={(e) => setForm((f) => ({ ...f, email_template_id: e.target.value }))}
                    className="w-full border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/10 focus:border-[#7C3AED] transition-all"
                  >
                    <option value="">No email (Manual send)</option>
                    {emailTemplates.map((t) => (
                      <option key={t.id} value={t.id}>{t.name}</option>
                    ))}
                  </select>
                </div>

                {/* Status */}
                <div className="flex items-center justify-between p-4 bg-slate-50 rounded-lg border border-slate-100">
                  <div>
                    <p className="text-xs font-bold text-slate-700">Enable Automation</p>
                    <p className="text-[10px] text-slate-400">Trigger onboarding when criteria is met</p>
                  </div>
                  <button
                    onClick={() => setForm((f) => ({ ...f, is_enabled: !f.is_enabled }))}
                    className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none ${form.is_enabled ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                  >
                    <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.is_enabled ? "translate-x-5" : "translate-x-0"}`} />
                  </button>
                </div>
                
                {/* Auto-Move Toggle */}
                <div className="flex items-center justify-between p-4 bg-slate-50 rounded-lg border border-slate-100">
                  <div>
                    <p className="text-xs font-bold text-slate-700">Auto-Move Candidate</p>
                    <p className="text-[10px] text-slate-400">Automatically advance candidate after trigger</p>
                  </div>
                  <button
                    onClick={() => setForm((f) => ({ ...f, auto_move: !f.auto_move }))}
                    className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none ${form.auto_move ? "bg-[#7C3AED]" : "bg-slate-200"}`}
                  >
                    <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200 ${form.auto_move ? "translate-x-5" : "translate-x-0"}`} />
                  </button>
                </div>
              </div>

              <div className="p-6 border-t border-slate-100 mt-auto bg-slate-50/50 shrink-0">
                <button
                  onClick={handleSave}
                  disabled={saving}
                  className="w-full h-12 bg-[#7C3AED] hover:bg-[#6d28d9] text-white rounded-lg font-black text-xs   transition-all flex items-center justify-center gap-2 shadow-lg shadow-[#7C3AED]/20 active:scale-[0.98]"
                >
                   {saving && <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
                  {editingId ? "SAVE CHANGES" : "CREATE AUTOMATION"}
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
      <ConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => {
          setIsDeleteModalOpen(false);
          setAutomationToDelete(null);
        }}
        onConfirm={handleDelete}
        title="Delete Onboarding Automation?"
        message={`Are you sure you want to delete this onboarding automation for ${automationToDelete ? getJobTitle(automationToDelete.job_requirement_id) : 'this job'}? This action is irreversible.`}
        confirmLabel="Yes, Delete"
        cancelLabel="No"
        isDestructive={true}
      />
    </div>
  );
}

"use client";

import React, { useState, useEffect, useCallback, useMemo } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import ReactFlow, {
  Background,
  Controls,
  Edge,
  Node,
  useNodesState,
  useEdgesState,
  MarkerType,
} from "reactflow";
import "reactflow/dist/style.css";
import AutomationNodeModal from "./AutomationNodeModal";

// ─── Interfaces ─────────────────────────────────────────────────────────────

interface WorkflowStage {
  name: string;
  stage?: number;
  order?: number;
}

interface Job {
  id: string;
  title: string;
  workflow_stages?: WorkflowStage[] | null;
}

interface Automation {
  id: string;
  job_requirement_id: string;
  stage_index: number;
  stage_name: string | null;
  criteria: string;
  is_enabled: boolean;
  type: "mail" | "assessment" | "interview" | "onboarding";
  action_type?: "mail" | "assessment" | "interview" | "onboarding";
  template_id?: string;
  is_immediate?: boolean;
  topic?: string;
  generated_questions?: any[];
  interview_type?: string;
  time_slots?: any[];
}

// ─── Page Component ─────────────────────────────────────────────────────────

export default function AutomationCanvasPage() {
  const { token, canAccess } = useAuth();
  const authHeaders = useMemo(() => ({
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  }), [token]);

  const [jobs, setJobs] = useState<Job[]>([]);
  const [selectedJobId, setSelectedJobId] = useState<string>("");
  const [loading, setLoading] = useState(false);

  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const [automations, setAutomations] = useState<Automation[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeNodeType, setActiveNodeType] = useState<"mail" | "assessment" | "interview" | "onboarding">("mail");
  const [editingId, setEditingId] = useState<string | null>(null);

  const initialData = useMemo(() => {
    if (!editingId) return null;
    return automations.find(a => a.id === editingId) || null;
  }, [editingId, automations]);

  // Fetch jobs on mount
  useEffect(() => {
    if (!token) return;
    const fetchJobs = async () => {
      try {
        const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, { headers: authHeaders });
        if (res.ok) {
          const data = await res.json();
          const jobList = Array.isArray(data) ? data : [];
          setJobs(jobList);
          if (jobList.length > 0) {
            setSelectedJobId(jobList[0].id);
          }
        }
      } catch (e) {
        console.error("Failed to load jobs:", e);
      }
    };
    fetchJobs();
  }, [token, authHeaders]);

  // Fetch automations when a job is selected
  const fetchAutomations = useCallback(async (jobId: string) => {
    if (!token || !jobId) return;
    setLoading(true);
    try {
      const endpoints = [
        { type: "mail", url: `${BACKEND_URL}/api/v1/enterprise/automation/mail/?job_id=${jobId}` },
        { type: "assessment", url: `${BACKEND_URL}/api/v1/enterprise/assessment/?job_id=${jobId}` },
        { type: "interview", url: `${BACKEND_URL}/api/v1/enterprise/interview-automation/?job_id=${jobId}` },
        { type: "onboarding", url: `${BACKEND_URL}/api/v1/enterprise/onboarding-automation/?job_id=${jobId}` },
      ];

      const responses = await Promise.all(
        endpoints.map(ep => fetch(ep.url, { headers: authHeaders }).then(r => r.ok ? r.json() : []).catch(() => []))
      );

      let allAutomations: (Automation & { action_type: string })[] = [];
      endpoints.forEach((ep, idx) => {
        const data = responses[idx];
        if (Array.isArray(data)) {
          allAutomations = [
            ...allAutomations,
            ...data
              .filter((d: Automation) => !d.job_requirement_id || String(d.job_requirement_id) === String(jobId))
              .map((d: Automation) => ({ ...d, action_type: ep.type as "mail" | "assessment" | "interview" | "onboarding" })),
          ];
        }
      });

      const job = jobs.find(j => j.id === jobId);
      const rounds: WorkflowStage[] = job?.workflow_stages ?? [];
      
      if (rounds.length === 0) {
        setNodes([]);
        setEdges([]);
        return;
      }

      const newNodes: Node[] = [];
      const newEdges: Edge[] = [];

      const HORIZONTAL_SPACING = 350;
      const VERTICAL_SPACING = 150;

      rounds.forEach((round, rIdx) => {
        const roundNodeId = `round-${rIdx + 1}`;
        
        // Create Round Node (Horizontal Flow)
        newNodes.push({
          id: roundNodeId,
          type: 'default',
          position: { x: rIdx * HORIZONTAL_SPACING, y: 100 },
          data: { 
            label: (
              <div className="flex flex-col items-center p-2">
                <span className="text-[10px]  font-bold text-[#7C3AED]">Round {rIdx + 1}</span>
                <span className="font-bold text-slate-800">{round.name}</span>
              </div>
            ) 
          },
          style: {
            background: '#fff',
            border: '2px solid #7C3AED',
            borderRadius: '12px',
            boxShadow: '0 4px 14px 0 rgba(124, 58, 237, 0.1)',
            width: 180,
          },
          sourcePosition: 'right' as const,
          targetPosition: 'left' as const,
        });

        // Connect to previous round
        if (rIdx > 0) {
          newEdges.push({
            id: `edge-round-${rIdx}-to-${rIdx + 1}`,
            source: `round-${rIdx}`,
            target: roundNodeId,
            type: 'smoothstep',
            style: { stroke: '#cbd5e1', strokeWidth: 2 },
            markerEnd: { type: MarkerType.ArrowClosed, color: '#cbd5e1' },
          });
        }

        // Find automations for this round
        const roundIndex = rIdx + 1;
        const roundAutomations = allAutomations.filter(a => a.stage_index === roundIndex);

        roundAutomations.forEach((auto, aIdx) => {
          const autoNodeId = `auto-${auto.action_type}-${auto.id}`;
          
          let icon = "mail";
          let color = "#3b82f6";
          let bg = "#eff6ff";
          if (auto.action_type === "mail") { icon = "mark_email_unread"; color = "#6366f1"; bg = "#eef2ff"; }
          if (auto.action_type === "assessment") { icon = "psychology"; color = "#f59e0b"; bg = "#fffbeb"; }
          if (auto.action_type === "interview") { icon = "event_available"; color = "#10b981"; bg = "#ecfdf5"; }
          if (auto.action_type === "onboarding") { icon = "person_add"; color = "#a855f7"; bg = "#faf5ff"; }

          if (!auto.is_enabled) {
            bg = "#f8fafc";
            color = "#94a3b8";
          }

          newNodes.push({
            id: autoNodeId,
            type: 'default',
            position: { x: rIdx * HORIZONTAL_SPACING, y: 100 + ((aIdx + 1) * VERTICAL_SPACING) },
            data: { 
              label: (
                <div className="flex flex-col items-start text-left p-1">
                  <div className="flex items-center justify-between w-full mb-1">
                    <div className="flex items-center gap-1.5">
                      <span className="material-symbols-rounded text-base" style={{ color }}>{icon}</span>
                      <span className="text-[9px]  font-black " style={{ color }}>
                        {auto.action_type}
                      </span>
                    </div>
                    {!auto.is_enabled && (
                      <span className="text-[8px] font-bold text-slate-400  tracking-tight bg-slate-100 px-1 rounded">Disabled</span>
                    )}
                  </div>
                  
                  <div className="text-[11px] font-bold text-slate-800 leading-tight mb-1 truncate w-full">
                    {auto.criteria || "Any trigger"}
                  </div>

                  {auto.action_type === "assessment" && (
                    <div className="text-[9px] text-slate-500 font-medium flex items-center gap-1">
                      <span className="material-symbols-rounded text-[10px]">topic</span>
                      {auto.topic || "No topic"} ({auto.generated_questions?.length || 0} Qs)
                    </div>
                  )}

                  {auto.action_type === "interview" && (
                     <div className="text-[9px] text-slate-500 font-medium flex items-center gap-1">
                        <span className="material-symbols-rounded text-[10px]">event</span>
                        {auto.interview_type} • {auto.time_slots?.length || 0} slots
                     </div>
                  )}

                  {auto.action_type === "mail" && auto.template_id && (
                    <div className="text-[9px] text-slate-500 font-medium flex items-center gap-1">
                        <span className="material-symbols-rounded text-[10px]">description</span>
                        Template Action
                    </div>
                  )}
                </div>
              ) 
            },
            style: {
              background: bg,
              border: `1px solid ${color}40`,
              borderRadius: '8px',
              width: 190,
              opacity: auto.is_enabled ? 1 : 0.6,
              cursor: 'pointer',
            },
            sourcePosition: 'bottom' as const,
            targetPosition: 'top' as const,
          });

          newEdges.push({
            id: `edge-${roundNodeId}-${autoNodeId}`,
            source: roundNodeId,
            target: autoNodeId,
            type: 'smoothstep',
            animated: auto.is_enabled,
            style: { stroke: color, strokeWidth: 1.5, strokeDasharray: '4' },
            sourceHandle: 'bottom',
          });
        });
      });

      setNodes(newNodes);
      setEdges(newEdges);
      setAutomations(allAutomations);

    } finally {
      setLoading(false);
    }
  }, [token, authHeaders, jobs, setNodes, setEdges]);

  const onNodeClick = useCallback((event: React.MouseEvent, node: Node) => {
    if (node.id.startsWith("auto-") && canAccess("automation:moderate")) {
      // Correct ID extraction: skip "auto-" and the next segment (type)
      const parts = node.id.split("-");
      const type = parts[1] as "mail" | "assessment" | "interview" | "onboarding";
      const id = node.id.replace(`auto-${type}-`, "");
      
      setActiveNodeType(type);
      setEditingId(id);
      setIsModalOpen(true);
    }
  }, [canAccess]);

  const openCreateModal = (type: "mail" | "assessment" | "interview" | "onboarding") => {
    setEditingId(null);
    setActiveNodeType(type);
    setIsModalOpen(true);
  };

  useEffect(() => {
    if (selectedJobId) {
      fetchAutomations(selectedJobId);
    } else {
      setNodes([]);
      setEdges([]);
      setAutomations([]);
    }
  }, [selectedJobId, fetchAutomations, setNodes, setEdges]);

  return (
    <div className="w-full h-full flex flex-col bg-[#FDFDFF]">
      {/* Header */}
      <div className="px-6 py-5 border-b border-slate-100 flex-shrink-0 bg-white shadow-sm z-10 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-start gap-3">
          <div className="w-10 h-10 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center shrink-0">
            <span className="material-symbols-rounded text-[#7C3AED] text-xl">account_tree</span>
          </div>
          <div>
            <h1 className="text-lg font-black text-slate-900 leading-tight">Automation Canvas</h1>
            <p className="text-slate-500 text-[11px] font-medium leading-relaxed">
              Visualize and build your automated hiring pipelines.
            </p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => selectedJobId && fetchAutomations(selectedJobId)}
            disabled={loading || !selectedJobId}
            className="flex items-center gap-2 px-5 h-11 rounded-xl border border-slate-200 text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-all font-black text-xs bg-white shadow-sm disabled:opacity-50 active:scale-95"
          >
            <span className={`material-symbols-rounded text-lg ${loading ? 'animate-spin' : ''}`}>refresh</span>
            SYNC
          </button>

          <div className="flex items-center gap-2 relative">
            <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg pointer-events-none">work</span>
            <select
              value={selectedJobId}
              onChange={(e) => setSelectedJobId(e.target.value)}
              className="w-64 h-11 border border-slate-200 rounded-xl pl-10 pr-4 text-xs font-bold text-slate-700 bg-white focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/5 focus:border-[#7C3AED] shadow-sm appearance-none cursor-pointer"
            >
              <option value="">Select a Job to view flow...</option>
              {jobs.map((j) => (
                <option key={j.id} value={j.id}>{j.title}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Canvas Area */}
      <div className="flex-1 w-full bg-slate-50/50 relative">
        {!selectedJobId ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center">
            <div className="w-16 h-16 rounded-xl bg-[#7C3AED]/5 flex items-center justify-center mb-4">
              <span className="material-symbols-rounded text-[#7C3AED] text-4xl">account_tree</span>
            </div>
            <p className="text-slate-700 font-bold text-lg">No job selected</p>
            <p className="text-slate-400 text-sm mt-1">Select a job from the dropdown to view its automation canvas.</p>
          </div>
        ) : loading ? (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="flex flex-col items-center gap-3">
              <div className="w-8 h-8 border-4 border-[#7C3AED] border-t-transparent rounded-full animate-spin" />
              <p className="text-sm font-semibold text-slate-500">Loading pipelines...</p>
            </div>
          </div>
        ) : nodes.length === 0 ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center">
            <p className="text-slate-500 font-bold">This job has no hiring rounds configured.</p>
          </div>
        ) : (
          <>
            <ReactFlow
              nodes={nodes}
              edges={edges}
              onNodesChange={onNodesChange}
              onEdgesChange={onEdgesChange}
              onNodeClick={onNodeClick}
              fitView
              minZoom={0.2}
              className="bg-slate-50"
              defaultEdgeOptions={{ type: 'smoothstep' }}
            >
              <Background color="#cbd5e1" gap={24} size={2} />
              <Controls className="bg-white shadow-md border-none rounded-xl overflow-hidden" />
            </ReactFlow>

            {/* Floating Actions */}
            {canAccess("automation:moderate") && (
              <div className="absolute top-6 right-6 z-10 flex flex-col items-end gap-2 pointer-events-none">
                <span className="text-[10px] font-black text-slate-500   bg-white/80 px-2 py-1 rounded backdrop-blur-sm pointer-events-auto shadow-sm">
                  Add Action
                </span>
                <div className="flex bg-white shadow-xl border border-slate-100 rounded-xl p-1 gap-1 pointer-events-auto">
                  <button onClick={() => openCreateModal("mail")} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-indigo-50 text-indigo-500 transition-colors" title="Add Mail Automation">
                    <span className="material-symbols-rounded text-[20px]">mark_email_unread</span>
                  </button>
                  <button onClick={() => openCreateModal("assessment")} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-amber-50 text-amber-500 transition-colors" title="Add Assessment Automation">
                    <span className="material-symbols-rounded text-[20px]">psychology</span>
                  </button>
                  <button onClick={() => openCreateModal("interview")} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-emerald-50 text-emerald-500 transition-colors" title="Add Interview Automation">
                    <span className="material-symbols-rounded text-[20px]">event_available</span>
                  </button>
                  <button onClick={() => openCreateModal("onboarding")} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-purple-50 text-purple-500 transition-colors" title="Add Onboarding Automation">
                    <span className="material-symbols-rounded text-[20px]">person_add</span>
                  </button>
                </div>
              </div>
            )}

            <AutomationNodeModal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
              onSave={() => fetchAutomations(selectedJobId)}
              jobId={selectedJobId}
              jobs={jobs}
              type={activeNodeType}
              editingId={editingId}
              initialData={initialData}
            />
          </>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useMemo } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { AnimatePresence, motion } from "framer-motion";
import ConfirmationModal from "@/components/common/ConfirmationModal";

// ─── Types ────────────────────────────────────────────────────────────────────

interface WorkflowStage {
  name: string;
  stage?: number;
  order?: number;
}

interface Job {
  id: string;
  title: string;
  workflow_stages?: WorkflowStage[] | null;
}

interface Template {
  id: string;
  name: string;
  subject: string;
}

interface Automation {
  id: string;
  job_requirement_id: string;
  stage_index: number;
  stage_name: string | null;
  criteria: string;
  template_id: string;
  auto_move: boolean;
  is_enabled: boolean;
  is_immediate: boolean;
  send_at: string | null;
  created_at: string;
}

interface FormState {
  job_requirement_id: string;
  stage_index: number | string;
  stage_name: string;
  criteria: string;
  template_id: string;
  auto_move: boolean;
  is_enabled: boolean;
  is_immediate: boolean;
  send_at: string;
}

const EMPTY_FORM: FormState = {
  job_requirement_id: "",
  stage_index: 1,
  stage_name: "",
  criteria: "",
  template_id: "",
  auto_move: false,
  is_enabled: true,
  is_immediate: true,
  send_at: "",
};

// ─── Main Page ────────────────────────────────────────────────────────────────

export default function ScreeningAutomationPage() {
  const { token } = useAuth();

  const authHeaders = useMemo(() => ({
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  }), [token]);

  const [jobs, setJobs] = useState<Job[]>([]);
  const [templates, setTemplates] = useState<Template[]>([]);
  const [automations, setAutomations] = useState<Automation[]>([]);
  const [selectedJobId, setSelectedJobId] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  
  // Consistency State
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [automationToDelete, setAutomationToDelete] = useState<string | null>(null);
  const [togglingId, setTogglingId] = useState<string | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const showToast = (msg: string | string[] | Record<string, any> | null, type: "success" | "error" = "success") => {
    let finalMsg = "";
    if (typeof msg === "string") {
      finalMsg = msg;
    } else if (Array.isArray(msg)) {
      finalMsg = msg.map((e: string | { msg?: string }) => (typeof e === 'string' ? e : (e.msg || JSON.stringify(e)))).join(", ");
    } else if (msg && typeof msg === "object") {
      finalMsg = (msg as { msg?: string; detail?: string }).msg || (msg as { msg?: string; detail?: string }).detail || JSON.stringify(msg);
    } else {
      finalMsg = String(msg || "An error occurred");
    }
    setToast({ msg: finalMsg, type });
    setTimeout(() => setToast(null), 3000);
  };

  // Fetch jobs & templates
  useEffect(() => {
    if (!token) return;
    const fetchMeta = async () => {
      try {
        const [jRes, tRes] = await Promise.all([
          fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, { headers: authHeaders }),
          fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, { headers: authHeaders }),
        ]);
        const jData = jRes.ok ? await jRes.json() : [];
        const tData = tRes.ok ? await tRes.json() : [];
        setJobs(Array.isArray(jData) ? jData : []);
        setTemplates(Array.isArray(tData) ? tData : []);
      } catch (e) {
        console.error("Failed to load meta:", e);
      }
    };
    fetchMeta();
  }, [token, authHeaders]);

  // Fetch automations
  const fetchAutomations = useCallback(async (jobId?: string) => {
    if (!token) return;
    setLoading(true);
    try {
      const qs = jobId ? `?job_id=${jobId}` : "";
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/automation/mail${qs}`, {
        headers: authHeaders,
      });
      if (res.ok) {
        const data = await res.json();
        setAutomations(Array.isArray(data) ? data : []);
      }
    } finally {
      setLoading(false);
    }
  }, [token, authHeaders]);

  useEffect(() => {
    fetchAutomations(selectedJobId || undefined);
  }, [selectedJobId, fetchAutomations]);

  const selectedJob = jobs.find((j) => j.id === form.job_requirement_id);
  const jobRounds: WorkflowStage[] = selectedJob?.workflow_stages ?? [];

  const openCreate = () => {
    setEditingId(null);
    setForm({ ...EMPTY_FORM, job_requirement_id: selectedJobId });
    setShowModal(true);
  };

  const openEdit = (a: Automation) => {
    setEditingId(a.id);
    setForm({
      job_requirement_id: a.job_requirement_id,
      stage_index: a.stage_index,
      stage_name: a.stage_name ?? "",
      criteria: a.criteria,
      template_id: a.template_id,
      auto_move: a.auto_move,
      is_enabled: a.is_enabled,
      is_immediate: a.is_immediate,
      send_at: a.send_at ? a.send_at.replace(' ', 'T').split('.')[0].slice(0, 16) : "",
    });
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingId(null);
    setForm(EMPTY_FORM);
  };

  const handleSave = async () => {
    if (!form.job_requirement_id || !form.criteria.trim() || !form.template_id) {
      showToast("Please fill in all required fields.", "error");
      return;
    }
    if (!form.is_immediate && form.send_at) {
      if (new Date(form.send_at) < new Date()) {
        showToast("Scheduled time cannot be in the past.", "error");
        return;
      }
    }
    setSaving(true);
    try {
      const payload = {
        ...form,
        stage_index: Number(form.stage_index),
        stage_name: form.stage_name.trim() || null,
        send_at: form.is_immediate ? null : (form.send_at ? new Date(form.send_at).toISOString() : null),
      };
      const url = editingId
        ? `${BACKEND_URL}/api/v1/enterprise/automation/mail/${editingId}`
        : `${BACKEND_URL}/api/v1/enterprise/automation/mail`;
      const method = editingId ? "PATCH" : "POST";
      const res = await fetch(url, {
        method,
        headers: authHeaders,
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        showToast(editingId ? "Automation updated!" : "Automation created!");
        closeModal();
        fetchAutomations(selectedJobId || undefined);
      } else {
        const err = await res.json().catch(() => ({}));
        showToast((err as { detail?: string })?.detail || "Failed to save automation.", "error");
      }
    } finally {
      setSaving(false);
    }
  };

  const handleToggle = async (a: Automation) => {
    setTogglingId(a.id);
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/automation/mail/${a.id}`, {
        method: "PATCH",
        headers: authHeaders,
        body: JSON.stringify({ is_enabled: !a.is_enabled }),
      });
      if (res.ok) {
        setAutomations((prev) =>
          prev.map((item) => (item.id === a.id ? { ...item, is_enabled: !a.is_enabled } : item))
        );
        showToast(a.is_enabled ? "Disabled" : "Enabled");
      }
    } finally {
      setTogglingId(null);
    }
  };

  const handleDelete = async () => {
    if (!automationToDelete) return;
    try {
      const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/automation/mail/${automationToDelete}`, {
        method: "DELETE",
        headers: authHeaders,
      });
      if (res.ok) {
        showToast("Automation deleted.");
        setAutomations((prev) => prev.filter((a) => a.id !== automationToDelete));
      }
    } finally {
      setIsDeleteModalOpen(false);
      setAutomationToDelete(null);
    }
  };

  const jobTitle = (id: string) => jobs.find((j) => j.id === id)?.title ?? "—";
  const templateName = (id: string) => templates.find((t) => t.id === id)?.name ?? "—";

  return (
    <div className="min-h-screen bg-[#FDFDFF] p-4 md:p-6 lg:p-8 pt-4 animate-in fade-in duration-500">
      {/* Toast */}
      <AnimatePresence>
        {toast && (
          <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className={`fixed top-5 right-5 z-[500] flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg text-sm font-semibold ${toast.type === "success" ? "bg-emerald-500 text-white" : "bg-rose-500 text-white"}`}>
            <span className="material-symbols-rounded text-base">{toast.type === "success" ? "check_circle" : "error"}</span>
            {toast.msg}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Header */}
      <div className="mb-8">
        <div className="flex items-center gap-3 mb-1">
          <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center shadow-sm">
            <span className="material-symbols-rounded text-indigo-600 text-xl">fact_check</span>
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">Screening Automation</h1>
            <p className="text-[10px] font-black text-indigo-500   mt-0.5">Rules-Based Candidate Filtering</p>
          </div>
        </div>
      </div>

      {/* Command Bar */}
      <div className="bg-white rounded-xl border border-slate-100 p-3 shadow-xl shadow-slate-200/40 mb-8 flex flex-col sm:flex-row items-center gap-4">
        <div className="flex items-center gap-3 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 flex-1 w-full sm:w-auto transition-all focus-within:bg-white focus-within:border-indigo-100 focus-within:ring-4 focus-within:ring-indigo-500/5 group">
          <span className="material-symbols-rounded text-slate-400 group-focus-within:text-indigo-500 transition-colors">work</span>
          <select
            value={selectedJobId}
            onChange={(e) => setSelectedJobId(e.target.value)}
            className="bg-transparent border-none outline-none text-xs font-black text-slate-700 w-full cursor-pointer"
          >
            <option value="">All Job Requirements</option>
            {jobs.map((j) => (
              <option key={j.id} value={j.id}>{j.title}</option>
            ))}
          </select>
        </div>
        <button
          onClick={openCreate}
          className="w-full sm:w-auto flex items-center justify-center gap-2.5 px-6 py-3 bg-[#0F172A] text-white rounded-xl text-[10px] font-black   hover:bg-slate-800 transition-all active:scale-95 shadow-lg shadow-slate-200"
        >
          <span className="material-symbols-rounded text-lg">add_circle</span>
          Add Rule
        </button>
      </div>

      {/* List */}
      {loading ? (
        <div className="flex flex-col items-center justify-center py-32 gap-4">
          <div className="w-10 h-10 border-4 border-slate-100 border-t-indigo-600 rounded-full animate-spin" />
          <p className="text-[10px] font-black text-slate-400  tracking-[0.2em]">Synchronizing Rules...</p>
        </div>
      ) : automations.length === 0 ? (
        <div className="bg-white rounded-2xl border border-dashed border-slate-200 p-20 text-center">
          <div className="w-20 h-20 bg-slate-50 rounded-xl flex items-center justify-center mx-auto mb-6">
            <span className="material-symbols-rounded text-4xl text-slate-200">fact_check</span>
          </div>
          <h3 className="text-lg font-black text-slate-800  tracking-tight">No Screening Rules</h3>
          <p className="text-xs text-slate-400 font-medium max-w-xs mx-auto mt-2">Deploy your first automated screening rule to streamline your recruitment pipeline.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
          {automations.map((a) => (
            <motion.div
              layout
              key={a.id}
              className={`group bg-white rounded-xl border p-1.5 transition-all duration-300 hover:shadow-2xl hover:shadow-slate-200/50 ${
                a.is_enabled ? "border-slate-100" : "border-slate-100 opacity-60 grayscale-[0.5]"
              }`}
            >
              <div className="p-5 space-y-4">
                <div className="flex justify-between items-start">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${a.is_enabled ? "bg-indigo-50 text-indigo-600 shadow-sm" : "bg-slate-50 text-slate-400"}`}>
                    <span className="material-symbols-rounded text-xl">rule</span>
                  </div>
                  <button onClick={() => handleToggle(a)} disabled={togglingId === a.id} className={`relative w-10 h-5 rounded-full transition-all duration-300 ${a.is_enabled ? "bg-indigo-500 shadow-lg shadow-indigo-100" : "bg-slate-200"}`}>
                    <div className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow-sm transition-all duration-300 ${a.is_enabled ? "translate-x-5" : ""}`} />
                  </button>
                </div>
                
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-slate-400  ">Round {a.stage_index}</span>
                    <span className="w-1 h-3 rounded-full bg-slate-100" />
                    <span className="text-[10px] font-black text-indigo-500   truncate max-w-[120px]">{a.stage_name || "SCREENING"}</span>
                  </div>
                  <p className="text-sm font-black text-slate-800 tracking-tight line-clamp-2 md:h-10 leading-tight">
                    <span className="text-slate-400 font-medium">IF: </span>{a.criteria}
                  </p>
                </div>

                <div className="space-y-2 pt-2 border-t border-slate-50">
                  <div className="flex items-center gap-2.5">
                    <span className="material-symbols-rounded text-slate-300 text-sm">work</span>
                    <span className="text-[11px] font-bold text-slate-500 truncate">{jobTitle(a.job_requirement_id)}</span>
                  </div>
                  <div className="flex items-center gap-2.5">
                    <span className="material-symbols-rounded text-slate-300 text-sm">mail</span>
                    <span className="text-[11px] font-bold text-slate-500 truncate">{templateName(a.template_id)}</span>
                  </div>
                </div>
              </div>

              <div className="bg-slate-50/50 rounded-xl p-2 flex items-center justify-between gap-2 overflow-hidden border border-slate-50">
                <div className="flex gap-2 pl-2">
                  {a.auto_move && (
                    <span className="px-2.5 py-1 bg-white border border-slate-200 rounded-xl text-[8px] font-black text-indigo-500  tracking-tight shadow-sm">Auto-Move</span>
                  )}
                  <span className={`px-2.5 py-1 bg-white border border-slate-200 rounded-xl text-[8px] font-black  tracking-tight shadow-sm ${a.is_immediate ? "text-emerald-500" : "text-slate-500"}`}>
                    {a.is_immediate ? "Immediate" : "Scheduled"}
                  </span>
                </div>
                <div className="flex gap-1.5 pr-1 translate-x-2 group-hover:translate-x-0 transition-transform duration-300">
                  <button onClick={() => openEdit(a)} className="w-8 h-8 rounded-xl bg-white border border-slate-200 text-slate-400 hover:text-indigo-600 hover:border-indigo-100 hover:bg-indigo-50 transition-all flex items-center justify-center group/btn shadow-sm">
                    <span className="material-symbols-rounded text-base">edit</span>
                  </button>
                  <button onClick={() => { setAutomationToDelete(a.id); setIsDeleteModalOpen(true); }} className="w-8 h-8 rounded-xl bg-white border border-slate-200 text-slate-400 hover:text-rose-500 hover:border-rose-100 hover:bg-rose-50 transition-all flex items-center justify-center shadow-sm">
                    <span className="material-symbols-rounded text-base">delete</span>
                  </button>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      )}

      {/* Side Drawer */}
      <AnimatePresence>
        {showModal && (
          <div className="fixed inset-0 z-[200] flex justify-end overflow-hidden">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px]" onClick={closeModal} />
            <motion.div initial={{ x: "100%" }} animate={{ x: 0 }} exit={{ x: "100%" }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="relative w-full max-w-lg bg-white shadow-2xl h-full flex flex-col pointer-events-auto">
              
              {/* Drawer Header */}
              <div className="flex items-center justify-between px-8 py-6 border-b border-slate-50">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 rounded-xl bg-indigo-50 flex items-center justify-center shadow-inner">
                    <span className="material-symbols-rounded text-indigo-600 text-2xl">settings_input_component</span>
                  </div>
                  <div>
                    <h2 className="text-xl font-black text-slate-800 leading-tight   tracking-tight">{editingId ? "Edit Rule" : "Configure Rule"}</h2>
                    <p className="text-[10px] font-black text-slate-300   mt-0.5">Automation Action</p>
                  </div>
                </div>
                <button onClick={closeModal} className="w-10 h-10 rounded-xl hover:bg-slate-50 flex items-center justify-center text-slate-400 transition-colors">
                  <span className="material-symbols-rounded text-xl">close</span>
                </button>
              </div>

              {/* Drawer Body */}
              <div className="flex-1 overflow-y-auto px-8 py-8 space-y-8 custom-scrollbar">
                <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400   ml-1">Target Job Requirement*</label>
                    <select
                      value={form.job_requirement_id}
                      onChange={(e) => setForm((f) => ({ ...f, job_requirement_id: e.target.value, stage_index: 1, stage_name: "" }))}
                      className="w-full bg-slate-50 border border-slate-100 rounded-xl px-5 py-3.5 text-sm font-bold text-slate-700 focus:bg-white focus:border-indigo-500 outline-none transition-all"
                    >
                      <option value="">Select requirement...</option>
                      {jobs.map((j) => <option key={j.id} value={j.id}>{j.title}</option>)}
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400   ml-1">Connect to Hiring Round</label>
                    <div className="grid grid-cols-5 gap-3">
                      <input type="number" min={1} value={form.stage_index} onChange={(e) => setForm((f) => ({ ...f, stage_index: e.target.value }))} className="col-span-1 bg-slate-50 border border-slate-100 rounded-xl px-3 py-3.5 text-sm font-bold text-center outline-none focus:border-indigo-500 focus:bg-white" placeholder="Idx" />
                      <input type="text" value={form.stage_name} onChange={(e) => setForm((f) => ({ ...f, stage_name: e.target.value }))} className="col-span-4 bg-slate-50 border border-slate-100 rounded-xl px-5 py-3.5 text-sm font-bold outline-none focus:border-indigo-500 focus:bg-white" placeholder="Round Name (e.g. Technical Interview)" />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400   ml-1">Trigger Condition*</label>
                    <textarea rows={4} value={form.criteria} onChange={(e) => setForm((f) => ({ ...f, criteria: e.target.value }))} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-5 py-4 text-sm font-medium text-slate-700 outline-none focus:border-indigo-500 focus:bg-white transition-all resize-none" placeholder="IF candidate meets this criteria (e.g. 'Shortlisted' or 'Score > 80')..." />
                  </div>

                  <div className="space-y-4 pt-4 border-t border-slate-50">
                    <div className="flex items-center justify-between p-4 bg-slate-50 rounded-xl">
                      <div>
                        <p className="text-sm font-black text-slate-800 tracking-tight  ">Active Status</p>
                        <p className="text-[10px] font-bold text-slate-400  ">Rule is currently operational</p>
                      </div>
                      <button onClick={() => setForm((f) => ({ ...f, is_enabled: !f.is_enabled }))} className={`relative w-11 h-6 rounded-full transition-all duration-300 ${form.is_enabled ? "bg-indigo-500" : "bg-slate-200"}`}>
                        <div className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-sm transition-all duration-300 ${form.is_enabled ? "translate-x-5" : ""}`} />
                      </button>
                    </div>

                    <div className="flex items-center justify-between p-4 bg-slate-50 rounded-xl">
                      <div>
                        <p className="text-sm font-black text-slate-800 tracking-tight  ">Auto-Move Candidate</p>
                        <p className="text-[10px] font-bold text-slate-400  ">Advance workflow on trigger</p>
                      </div>
                      <button onClick={() => setForm((f) => ({ ...f, auto_move: !f.auto_move }))} className={`relative w-11 h-6 rounded-full transition-all duration-300 ${form.auto_move ? "bg-indigo-500" : "bg-slate-200"}`}>
                        <div className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-sm transition-all duration-300 ${form.auto_move ? "translate-x-5" : ""}`} />
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              {/* Drawer Footer */}
              <div className="p-8 border-t border-slate-50 bg-slate-50/30">
                <button
                  onClick={handleSave}
                  disabled={saving}
                  className="w-full py-4 bg-[#0F172A] text-white rounded-xl text-[11px] font-black  tracking-[0.2em] hover:bg-slate-800 transition-all active:scale-95 disabled:opacity-50 shadow-xl shadow-slate-200"
                >
                  {saving ? "SAVING..." : editingId ? "UPDATE RULE" : "SAVE RULE"}
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      <ConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDelete}
        title="Delete Automation Rule?"
        message="Are you sure you want to delete this screening rule?"
        confirmLabel="Yes, Delete"
        cancelLabel="No"
        isDestructive={true}
      />
    </div>
  );
}

"use client";

import React, { useState, useEffect, useMemo } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation"; // Added
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { formatDistanceToNow } from "date-fns";
import SendEmailModal from "@/components/enterprise/SendEmailModal";
import SendAssessmentModal from "@/components/enterprise/SendAssessmentModal";
import SendOnboardingModal from "@/components/enterprise/SendOnboardingModal";

// --- Interfaces ---

interface Candidate {
    id: string;
    full_name: string;
    email: string;
    skills: string[];
    phone?: string;
    profile_image?: string;
    parsed_data?: Record<string, any>;
}

interface AIFeedback {
    fit_reason?: string;
    not_fit_reason?: string;
    highlights?: string[];
}

interface Application {
    id: string;
    candidate_id: string;
    current_stage: number;
    ai_match_score?: number;
    assessment_score?: number;
    aptitude_score?: number;
    coding_score?: number;
    ai_interview_score?: number;
    ai_feedback?: AIFeedback;
    applied_at?: string;
    candidate: Candidate;
    job_requirement_id: string;
    onboarding_id?: string; // Added
}

interface Company {
    id: string;
    name: string;
}

interface Stage {
    id: number | string;
    name: string;
    color: string;
}

interface Job {
    id: string;
    title: string;
    company_id?: string;
    location?: string;
}

interface OnboardingTemplate {
    id: string;
    name: string;
}

// --- Helpers ---
const STAGE_COLORS = [
    'border-indigo-500',
    'border-purple-500',
    'border-pink-500',
    'border-rose-500',
    'border-orange-500',
    'border-amber-500',
    'border-emerald-500',
    'border-teal-500',
    'border-cyan-500',
    'border-blue-500'
];

const getScoreStyles = (score: number) => {
    if (score >= 80) return "bg-emerald-50 text-emerald-700 border-emerald-200";
    if (score >= 60) return "bg-amber-50 text-amber-700 border-amber-200";
    return "bg-rose-50 text-rose-700 border-rose-200";
};

// --- Modal Component ---

interface CandidateModalProps {
    application: Application;
    isOpen: boolean;
    onClose: () => void;
    onStatusUpdate: (appId: string, statusId: number | string) => void;
    onRefresh: () => void;
    onboardingTemplates: OnboardingTemplate[];
    stages: Stage[];
}

function CandidateModal({ application, isOpen, onClose, onStatusUpdate, onRefresh, onboardingTemplates, stages }: CandidateModalProps) {
    const { token, canAccess } = useAuth();
    const [selectedTemplate, setSelectedTemplate] = useState<string>("");
    if (!isOpen || !application) return null;

    const { candidate, ai_match_score, ai_feedback } = application;
    const details = candidate.parsed_data || {};
    const feedback = ai_feedback || {};

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-end bg-black/40 backdrop-blur-sm" onClick={onClose}>
            <motion.div
                initial={{ x: "100%" }}
                animate={{ x: 0 }}
                exit={{ x: "100%" }}
                transition={{ type: "spring", damping: 30, stiffness: 300 }}
                className="w-full max-w-xl h-full bg-white shadow-2xl overflow-y-auto"
                onClick={(e) => e.stopPropagation()}
            >
                {/* Header */}
                <div className="sticky top-0 bg-white z-10 border-b border-slate-100 px-6 py-5 flex items-start justify-between">
                    <div>
                        <h2 className="text-lg font-bold text-slate-900">{candidate.full_name}</h2>
                        <div className="flex flex-col gap-1 mt-1 text-xs text-slate-500">
                            {/* ... existing info ... */}
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        {application.onboarding_id ? (
                            canAccess("onboarding:read") && (
                                <button 
                                    onClick={() => {
                                        window.location.href = `/enterprise/onboarding/${application.onboarding_id}`;
                                    }}
                                    className="px-3 py-1.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg text-[10px] font-bold  tracking-wide transition-all shadow-md shadow-emerald-100 flex items-center gap-2"
                                >
                                    <span className="material-icons-outlined text-[16px]">visibility</span>
                                    View Onboarding
                                </button>
                            )
                        ) : (
                            canAccess("onboarding:moderate") && (
                                <div className="flex items-center gap-2">
                                    <select 
                                        className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-1.5 text-[10px] font-bold text-slate-600 outline-none focus:border-indigo-500"
                                        value={selectedTemplate}
                                        onChange={(e) => setSelectedTemplate(e.target.value)}
                                    >
                                        <option value="">Select Template</option>
                                        {onboardingTemplates.map(t => (
                                            <option key={t.id} value={t.id}>{t.name}</option>
                                        ))}
                                    </select>
                                    <button 
                                        onClick={async () => {
                                            if (!selectedTemplate) {
                                                alert("Please select an onboarding template first.");
                                                return;
                                            }
                                            if (!token) {
                                                alert("Your session has expired. Please log in again.");
                                                return;
                                            }
                                            try {
                                                const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/initiate`, {
                                                    method: "POST",
                                                    headers: {
                                                        "Content-Type": "application/json",
                                                        "Authorization": `Bearer ${token}`
                                                    },
                                                    body: JSON.stringify({ 
                                                        application_id: application.id,
                                                        template_id: selectedTemplate
                                                    })
                                                });
                                                if (res.ok) {
                                                    alert("Onboarding initiated successfully!");
                                                    onRefresh();
                                                    onClose();
                                                } else {
                                                    const err = await res.json();
                                                    alert(err.detail || "Failed to initiate onboarding");
                                                }
                                            } catch (e) {
                                                console.error(e);
                                                alert("Error initiating onboarding");
                                            }
                                        }}
                                        className="px-3 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-[10px] font-bold  tracking-wide transition-all shadow-md shadow-indigo-100 flex items-center gap-2"
                                    >
                                        <span className="material-icons-outlined text-[16px]">person_add</span>
                                        Initiate
                                    </button>
                                </div>
                            )
                        )}
                        <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors">
                            <span className="material-icons-outlined">close</span>
                        </button>
                    </div>
                </div>

                {/* Body */}
                <div className="p-6 space-y-6">
                    {/* Score Section */}
                    {ai_match_score !== undefined && (
                        <div className="bg-slate-50 rounded-xl p-5 border border-slate-200">
                            <div className="flex items-center justify-between mb-3">
                                <h3 className="font-bold text-slate-800 text-sm flex items-center gap-2">
                                    <span className="material-icons-outlined text-indigo-600 text-lg">psychology</span>
                                    AI Fit Analysis
                                </h3>
                                <div className={`px-2.5 py-1 rounded-md text-xs font-bold border ${getScoreStyles(ai_match_score)}`}>
                                    Score: {ai_match_score}/100
                                </div>
                            </div>
                            
                            {( (application.aptitude_score != null && application.aptitude_score > 0) || (application.coding_score != null && application.coding_score > 0) || (application.ai_interview_score != null && application.ai_interview_score > 0) ) && (
                                <div className="grid grid-cols-2 lg:grid-cols-3 gap-3 mb-4">
                                    {application.aptitude_score != null && application.aptitude_score > 0 && (
                                        <div className="bg-white border border-slate-200 p-2.5 rounded-lg">
                                            <h4 className="text-[9px] font-black text-slate-400   mb-1">Aptitude</h4>
                                            <div className="text-sm font-bold text-slate-900">{application.aptitude_score}%</div>
                                        </div>
                                    )}
                                    {application.coding_score != null && application.coding_score > 0 && (
                                        <div className="bg-white border border-slate-200 p-2.5 rounded-lg">
                                            <h4 className="text-[9px] font-black text-slate-400   mb-1">Coding</h4>
                                            <div className="text-sm font-bold text-slate-900">{application.coding_score}%</div>
                                        </div>
                                    )}
                                    {application.ai_interview_score != null && application.ai_interview_score > 0 && (
                                        <div className="bg-white border border-slate-200 p-2.5 rounded-lg">
                                            <h4 className="text-[9px] font-black text-slate-400   mb-1">AI Interview</h4>
                                            <div className="text-sm font-bold text-slate-900">{Math.round(application.ai_interview_score)}%</div>
                                        </div>
                                    )}
                                </div>
                            )}

                            <div className="space-y-3">
                                {feedback.fit_reason && (
                                    <div className="bg-white border border-emerald-100 p-3 rounded-lg">
                                        <h4 className="text-[10px] font-bold text-emerald-700  tracking-wide mb-1">Why Fit</h4>
                                        <p className="text-xs text-slate-600 leading-relaxed">{feedback.fit_reason}</p>
                                    </div>
                                )}
                                {feedback.not_fit_reason && (
                                    <div className="bg-white border border-red-100 p-3 rounded-lg">
                                        <h4 className="text-[10px] font-bold text-red-700  tracking-wide mb-1">Gap Analysis</h4>
                                        <p className="text-xs text-slate-600 leading-relaxed">{feedback.not_fit_reason}</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Highlights */}
                    {feedback.highlights && feedback.highlights.length > 0 && (
                        <div>
                            <h3 className="font-bold text-slate-800 text-sm mb-3 flex items-center gap-2">
                                <span className="material-icons-outlined text-amber-500 text-lg">star</span>
                                Key Highlights
                            </h3>
                            <ul className="space-y-2">
                                {feedback.highlights.map((h: string, i: number) => (
                                    <li key={i} className="flex items-start gap-2 text-xs text-slate-600">
                                        <span className="material-icons-outlined text-emerald-500 text-[16px] mt-0.5">check_circle</span>
                                        {h}
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}

                    {/* Skills */}
                    {candidate.skills && candidate.skills.length > 0 && (
                        <div>
                            <h3 className="font-bold text-slate-800 text-sm mb-3 flex items-center gap-2">
                                <span className="material-icons-outlined text-blue-500 text-lg">code</span>
                                Skills
                            </h3>
                            <div className="flex flex-wrap gap-1.5">
                                {candidate.skills.map((skill, i) => (
                                    <span key={i} className="px-2.5 py-1 bg-white border border-slate-200 rounded-md text-xs text-slate-600 font-medium shadow-sm">
                                        {skill}
                                    </span>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </motion.div>
        </div>
    );
}

export default function KanbanBoardPage() {
    const { token, canAccess } = useAuth();
    const [applications, setApplications] = useState<Application[]>([]);
    const [stages, setStages] = useState<Stage[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedApps, setSelectedApps] = useState<Set<string>>(new Set());
    const [searchQuery, setSearchQuery] = useState("");
    const [viewApplication, setViewApplication] = useState<Application | null>(null);
    const [onboardingTemplates, setOnboardingTemplates] = useState<OnboardingTemplate[]>([]);

    // Drag and Drop State
    const [draggedAppId, setDraggedAppId] = useState<string | null>(null);
    const [dragOverStageId, setDragOverStageId] = useState<number | string | null>(null);

    // Job Fetching & Filtering
    const [jobs, setJobs] = useState<Job[]>([]);
    const [companies, setCompanies] = useState<Company[]>([]);
    const [selectedJobId, setSelectedJobId] = useState<string>("");
    const [selectedCompanyId, setSelectedCompanyId] = useState<string>("");
    const [selectedLocation, setSelectedLocation] = useState<string>("ALL");
    const [minMatchScore, setMinMatchScore] = useState<number>(0);
    const [appliedPeriod, setAppliedPeriod] = useState<string>("ALL");
    const [isFilterExpanded, setIsFilterExpanded] = useState(false);

    // Email Modal
    const [isEmailModalOpen, setIsEmailModalOpen] = useState(false);
    const [isAssessmentModalOpen, setIsAssessmentModalOpen] = useState(false);
    const [isOnboardingModalOpen, setIsOnboardingModalOpen] = useState(false);

    // --- Fetch Data ---
    useEffect(() => {
        const loadInitialData = async () => {
            if (token) {
                await fetchCompanies();
                await fetchJobs();
            }
        };
        loadInitialData();
    }, [token]);

    useEffect(() => {
        if (token) {
            fetchStages();
            fetchApplications();
            fetchTemplates();
        }
    }, [token, selectedJobId]);

    const fetchTemplates = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setOnboardingTemplates(data);
            }
        } catch (e) {
            console.error("Error fetching templates:", e);
        }
    };

    const fetchCompanies = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/company/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setCompanies(data);
            }
        } catch (e) {
            console.error("Error fetching companies:", e);
        }
    };

    const fetchJobs = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setJobs(data);
                // Auto-select latest job if none active
                if (data.length > 0 && (!selectedJobId || selectedJobId === "")) {
                    setSelectedJobId(data[0].id);
                }
            }
        } catch (e) {
            console.error("Error fetching jobs:", e);
        }
    };

    const fetchStages = async () => {
        try {
            const url = new URL(`${BACKEND_URL}/api/v1/enterprise/applications/stages`);
            if (selectedJobId) {
                url.searchParams.append("job_id", selectedJobId);
            }
            const res = await fetch(url.toString(), {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setStages(data);
            }
        } catch (e) {
            console.error(e);
        }
    };

    const fetchApplications = async () => {
        setIsLoading(true);
        try {
            const url = new URL(`${BACKEND_URL}/api/v1/enterprise/applications/`);
            if (selectedJobId) {
                url.searchParams.append("job_id", selectedJobId);
            }
            const res = await fetch(url.toString(), {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                console.log("Fetched applications with scores:", data.map((a: Application) => ({ name: a.candidate.full_name, ai: a.ai_match_score, inter: a.ai_interview_score })));
                setApplications(data);
            }
        } catch (error) {
            console.error("Error fetching applications:", error);
        } finally {
            setIsLoading(false);
        }
    };

    // --- Actions ---

    const handleStageChange = async (appId: string, newStage: number | string) => {
        const originalApps = [...applications];
        const stagePayload = parseInt(String(newStage));

        setApplications(prev => prev.map(app =>
            app.id === appId ? { ...app, current_stage: stagePayload } : app
        ));

        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/applications/${appId}/stage`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({ new_stage: stagePayload })
            });

            if (!res.ok) throw new Error("Failed to update");
        } catch (error) {
            setApplications(originalApps);
            alert("Failed to move candidate.");
        }
    };

    const handleSelection = (appId: string) => {
        const newSelected = new Set(selectedApps);
        if (newSelected.has(appId)) {
            newSelected.delete(appId);
        } else {
            newSelected.add(appId);
        }
        setSelectedApps(newSelected);
    };

    const handleSelectAllInStage = (stageId: number | string, isSelected: boolean) => {
        const stageApps = getStageApps(stageId);
        const newSelected = new Set(selectedApps);
        stageApps.forEach(app => {
            if (isSelected) newSelected.add(app.id);
            else newSelected.delete(app.id);
        });
        setSelectedApps(newSelected);
    };

    const handleDragStart = (e: React.DragEvent, appId: string) => {
        setDraggedAppId(appId);
        e.dataTransfer.effectAllowed = "move";
        const el = e.target as HTMLElement;
        el.style.opacity = '0.5';
    };

    const handleDragEnd = (e: React.DragEvent) => {
        const el = e.target as HTMLElement;
        el.style.opacity = '1';
        setDraggedAppId(null);
    };

    const handleDragOver = (e: React.DragEvent, stageId: number | string) => {
        e.preventDefault();
        if (dragOverStageId !== stageId) {
            setDragOverStageId(stageId);
        }
    };

    const handleDrop = (e: React.DragEvent, stageId: number | string) => {
        e.preventDefault();
        setDragOverStageId(null);

        if (!canAccess("candidates:update")) {
            console.warn("Permission denied: cannot move candidate.");
            return;
        }

        if (draggedAppId && draggedAppId !== stageId) {
            handleStageChange(draggedAppId, stageId);
        }
        setDraggedAppId(null);
    };

    const handleBulkMove = async () => {
        if (selectedApps.size === 0) return;

        const updates: { appId: string; newStage: number }[] = [];

        selectedApps.forEach(appId => {
            const app = applications.find(a => a.id === appId);
            if (!app) return;

            const currentIndex = stages.findIndex(s => String(s.id) === String(app.current_stage));
            if (currentIndex !== -1 && currentIndex < stages.length - 1) {
                const nextStage = stages[currentIndex + 1];
                updates.push({ appId: appId, newStage: Number(nextStage.id) });
            }
        });

        if (updates.length > 0) {
            // Optimistic update
            setApplications(prev => prev.map(app => {
                const update = updates.find(u => u.appId === app.id);
                return update ? { ...app, current_stage: update.newStage } : app;
            }));

            setSelectedApps(new Set()); // Clear selection

            // API calls
            await Promise.all(updates.map(u =>
                fetch(`${BACKEND_URL}/api/v1/enterprise/applications/${u.appId}/stage`, {
                    method: "PATCH",
                    headers: {
                        "Content-Type": "application/json",
                        "Authorization": `Bearer ${token}`
                    },
                    body: JSON.stringify({ new_stage: u.newStage })
                }).catch(err => console.error("Failed to move app", u.appId, err))
            ));
        }
    };

    const handleBulkDelete = async () => {
        if (selectedApps.size === 0) return;
        if (!confirm(`Are you sure you want to delete ${selectedApps.size} applications? This action cannot be undone.`)) return;

        const idsToDelete = Array.from(selectedApps);

        // Optimistic update
        setApplications(prev => prev.filter(app => !selectedApps.has(app.id)));
        setSelectedApps(new Set());

        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/applications/bulk`, {
                method: "DELETE",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify(idsToDelete)
            });

            if (!res.ok) throw new Error("Delete failed");
        } catch (error) {
            console.error("Bulk delete error:", error);
            alert("Failed to delete some applications. Please refresh.");
            fetchApplications(); // Refresh to get actual state
        }
    };


    // --- Computed ---
    const filteredApplications = useMemo(() => {
        return applications.filter(app => {
            const matchesSearch = app.candidate.full_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                app.candidate.email.toLowerCase().includes(searchQuery.toLowerCase());

            const job = jobs.find(j => j.id === app.job_requirement_id);

            const matchesJob = !selectedJobId || app.job_requirement_id === selectedJobId;
            const matchesCompany = !selectedCompanyId || (job && job.company_id === selectedCompanyId);
            const matchesLocation = selectedLocation === "ALL" || (job && job.location === selectedLocation);
            const matchesScore = (app.ai_match_score || 0) >= minMatchScore;

            let matchesPeriod = true;
            if (appliedPeriod !== "ALL" && app.applied_at) {
                const appliedDate = new Date(app.applied_at);
                const now = new Date();
                const diffDays = (now.getTime() - appliedDate.getTime()) / (1000 * 3600 * 24);
                if (appliedPeriod === "TODAY") matchesPeriod = diffDays <= 1;
                else if (appliedPeriod === "7D") matchesPeriod = diffDays <= 7;
                else if (appliedPeriod === "30D") matchesPeriod = diffDays <= 30;
            }

            return matchesSearch && matchesJob && matchesCompany && matchesLocation && matchesScore && matchesPeriod;
        });
    }, [applications, searchQuery, selectedJobId, selectedCompanyId, selectedLocation, minMatchScore, appliedPeriod, jobs]);

    const getStageApps = (stageId: number | string) => filteredApplications.filter(app => String(app.current_stage) === String(stageId));

    const locations = Array.from(new Set(jobs.map(j => j.location).filter(Boolean)));

    const selectedJobTitle = jobs.find(j => j.id === selectedJobId)?.title || "SELECT A JOB";

    if (isLoading && stages.length === 0) {
        return (
            <div className="flex items-center justify-center h-screen bg-white">
                <div className="w-8 h-8 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
        );
    }

    const activeFiltersCount = [
        selectedJobId && selectedJobId !== "ALL" && selectedJobId !== "",
        selectedCompanyId && selectedCompanyId !== "ALL" && selectedCompanyId !== "",
        selectedLocation !== "ALL" && selectedLocation !== "",
        minMatchScore > 0,
        appliedPeriod !== "ALL" && appliedPeriod !== ""
    ].filter(Boolean).length;

    return (
        <div className="h-screen flex flex-col bg-white font-sans text-slate-800">
            {/* NEW: Dual-Line Command Center */}
            <div className="flex flex-col bg-white border-b border-slate-100 z-30 transition-all duration-300">

                {/* Line 1: Main Controls */}
                <header className="px-6 py-5 flex items-center gap-4">
                    <div className="flex items-center gap-3 mr-4">
                        <button
                            onClick={() => setIsFilterExpanded(!isFilterExpanded)}
                            title="Toggle Filters"
                            className={`flex items-center gap-2 px-4 h-11 rounded-xl transition-all ${isFilterExpanded ? 'bg-[#7C3AED] text-white shadow-lg shadow-indigo-100' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}
                        >
                            <span className="material-icons-outlined text-xl">{isFilterExpanded ? 'filter_list_off' : 'filter_list'}</span>
                            <span className="text-[11px] font-black tracking-tight">Filters</span>
                        </button>
                        <div className="hidden xl:flex flex-col">
                            <h1 className="text-lg font-black text-slate-900 tracking-tighter leading-none">Pipeline</h1>
                            <span className="text-[10px] text-indigo-600 font-bold mt-1 truncate max-w-[250px]">
                                {selectedJobId && selectedJobId !== "ALL" ? selectedJobTitle : "All Job Requirements"}
                            </span>
                        </div>
                    </div>

                    {/* Global Search - Wide Anchor */}
                    <div className="relative group flex-1 max-w-2xl">
                        <span className="material-icons-outlined absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg group-focus-within:text-indigo-500 transition-colors">search</span>
                        <input
                            type="text"
                            placeholder="Search candidates, emails, skills..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3.5 pl-11 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:bg-white focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none"
                        />
                    </div>

                    <div className="flex-1 flex justify-end items-center gap-4">


                        <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>

                        <div className="flex items-center gap-2 px-4 h-11 bg-emerald-50 text-emerald-600 rounded-xl text-[10px] font-black border border-emerald-100 shadow-sm shadow-emerald-50">
                            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                            Live Analytics
                        </div>
                    </div>
                </header>

                {/* Line 2: Advanced Filters (Expandable) */}
                <AnimatePresence>
                    {isFilterExpanded && (
                        <motion.div
                            initial={{ height: 0, opacity: 0 }}
                            animate={{ height: 'auto', opacity: 1 }}
                            exit={{ height: 0, opacity: 0 }}
                            className="overflow-hidden bg-slate-50/50"
                        >
                            <div className="px-6 py-4 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4 items-end">

                                {/* Company Filter */}
                                <div className="space-y-1.5">
                                    <label className="text-[9px] font-black text-slate-400   ml-1">Enterprise Client</label>
                                    <div className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-xl hover:border-indigo-200 transition-all">
                                        <span className="material-icons-outlined text-slate-400 text-lg">corporate_fare</span>
                                        <select
                                            value={selectedCompanyId}
                                            onChange={(e) => setSelectedCompanyId(e.target.value)}
                                            className="bg-transparent text-[11px] font-bold text-slate-700 outline-none w-full cursor-pointer"
                                        >
                                            <option value="">All Clients</option>
                                            {companies.length === 0 ? (
                                                <option disabled>No clients available</option>
                                            ) : (
                                                companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)
                                            )}
                                        </select>
                                    </div>
                                </div>

                                {/* Role Filter */}
                                <div className="space-y-1.5">
                                    <label className="text-[9px] font-black text-slate-400   ml-1">Target Requisition</label>
                                    <div className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-xl hover:border-indigo-200 transition-all">
                                        <span className="material-icons-outlined text-slate-400 text-lg">work</span>
                                        <select
                                            value={selectedJobId}
                                            onChange={(e) => setSelectedJobId(e.target.value)}
                                            className="bg-transparent text-[11px] font-bold text-slate-700 outline-none w-full cursor-pointer truncate"
                                        >
                                            <option value="">All Job Requirements</option>
                                            {jobs.length === 0 ? (
                                                <option disabled>No jobs available</option>
                                            ) : (
                                                jobs.map(job => <option key={job.id} value={job.id}>{job.title}</option>)
                                            )}
                                        </select>
                                    </div>
                                </div>

                                {/* Location Filter */}
                                <div className="space-y-1.5">
                                    <label className="text-[9px] font-black text-slate-400   ml-1">Geographic Focus</label>
                                    <div className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-xl hover:border-indigo-200 transition-all">
                                        <span className="material-icons-outlined text-slate-400 text-lg">location_on</span>
                                        <select
                                            value={selectedLocation}
                                            onChange={(e) => setSelectedLocation(e.target.value)}
                                            className="bg-transparent text-[11px] font-bold text-slate-700 outline-none w-full cursor-pointer"
                                        >
                                            <option value="ALL">Global Workforce</option>
                                            {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
                                        </select>
                                    </div>
                                </div>

                                {/* Match Score Filter */}
                                <div className="space-y-1.5">
                                    <label className="text-[9px] font-black text-slate-400   ml-1">AI Match Accuracy</label>
                                    <div className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-xl hover:border-indigo-200 transition-all">
                                        <span className="material-icons text-indigo-500 text-lg">bolt</span>
                                        <select
                                            value={minMatchScore}
                                            onChange={(e) => setMinMatchScore(Number(e.target.value))}
                                            className="bg-transparent text-[11px] font-bold text-slate-700 outline-none w-full cursor-pointer font-sans"
                                        >
                                            <option value={0}>Any Score</option>
                                            <option value={60}>High Match (60%+)</option>
                                            <option value={80}>Elite Match (80%+)</option>
                                        </select>
                                    </div>
                                </div>

                                {/* Application Period */}
                                <div className="space-y-1.5">
                                    <label className="text-[9px] font-black text-slate-400   ml-1">Application Recency</label>
                                    <div className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-xl hover:border-indigo-200 transition-all">
                                        <span className="material-icons-outlined text-slate-400 text-lg">calendar_today</span>
                                        <select
                                            value={appliedPeriod}
                                            onChange={(e) => setAppliedPeriod(e.target.value)}
                                            className="bg-transparent text-[11px] font-bold text-slate-700 outline-none w-full cursor-pointer"
                                        >
                                            <option value="ALL">Lifetime Activity</option>
                                            <option value="TODAY">Joined Today</option>
                                            <option value="7D">Last 7 Days</option>
                                            <option value="30D">Last 30 Days</option>
                                        </select>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Board */}
            <div className="flex-1 overflow-x-auto overflow-y-hidden bg-white p-6">
                <div 
                    className={`flex h-full gap-2 ${stages.length <= 6 ? 'w-full' : 'min-w-max'}`}
                    style={{ 
                        display: 'grid', 
                        gridTemplateColumns: `repeat(${stages.length}, minmax(${stages.length <= 6 ? '0' : '320px'}, 1fr))` 
                    }}
                >
                    {stages.map((stage, index) => {
                        const stageApps = getStageApps(stage.id);
                        const isAllSelected = stageApps.length > 0 && stageApps.every(app => selectedApps.has(app.id));
                        const borderColor = STAGE_COLORS[index % STAGE_COLORS.length];
                        const headerColor = borderColor.replace('border-', 'text-');

                        return (
                            <div
                                key={stage.id}
                                className="relative flex flex-col h-full rounded-xl border border-slate-200 bg-slate-50/50 min-w-0"
                                onDragOver={(e) => handleDragOver(e, stage.id)}
                                onDrop={(e) => handleDrop(e, stage.id)}
                            >


                                {/* Column Header */}
                                <div className="px-4 pt-5 pb-3 flex flex-col gap-2">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-2 overflow-hidden">
                                            <h3 className="text-[13px] font-bold text-slate-800  tracking-wide truncate">
                                                {stage.name}
                                            </h3>
                                            <span className="bg-white border border-slate-200 text-slate-500 text-[10px] font-bold px-2 py-0.5 rounded-full shadow-sm">
                                                {stageApps.length}
                                            </span>
                                        </div>

                                    </div>

                                    {/* Selection Tool */}
                                    {stageApps.length > 0 && (
                                        <div className="flex items-center gap-2 px-1">
                                            <input
                                                type="checkbox"
                                                checked={isAllSelected}
                                                onChange={(e) => handleSelectAllInStage(stage.id, e.target.checked)}
                                                className={`w-3.5 h-3.5 rounded border-slate-300 focus:ring-0 cursor-pointer ${headerColor}`}
                                            />
                                            <span className="text-xs font-bold text-slate-500">
                                                SELECT ALL
                                            </span>
                                        </div>
                                    )}
                                </div>

                                {/* Cards Container */}
                                <div className="flex-1 overflow-y-auto px-3 pb-4 space-y-3 [&::-webkit-scrollbar]:hidden [-ms-overflow-style:'none'] [scrollbar-width:'none']">
                                    <AnimatePresence>
                                        {stageApps.map((app) => (
                                            <motion.div
                                                key={app.id}
                                                layout
                                                draggable
                                                onDragStart={(e) => handleDragStart(e as any, app.id)}
                                                onDragEnd={(e) => handleDragEnd(e as any)}
                                                initial={{ opacity: 0, scale: 0.95 }}
                                                animate={{ opacity: 1, scale: 1 }}
                                                exit={{ opacity: 0, scale: 0.95 }}
                                                onClick={() => setViewApplication(app)}
                                                whileHover={{ y: -2 }}
                                                className={`
                                                    group relative bg-white border p-3.5 cursor-grab active:cursor-grabbing transition-all shadow-sm
                                                    ${selectedApps.has(app.id) ? `border-indigo-500 shadow-indigo-100 ring-1 ring-indigo-500` : `border-slate-200/60 hover:border-indigo-300 hover:shadow-md`}
                                                    ${draggedAppId === app.id ? 'opacity-40 grayscale border-dashed border-slate-400' : ''}
                                                `}
                                            >

                                                <div className="flex items-start gap-3 pointer-events-none">
                                                    <div className="pt-0.5">
                                                        <input
                                                            type="checkbox"
                                                            checked={selectedApps.has(app.id)}
                                                            onChange={() => {
                                                                handleSelection(app.id);
                                                            }}
                                                            onClick={(e) => e.stopPropagation()}
                                                            className="w-4 h-4 rounded border-slate-300 text-indigo-600 focus:ring-0 cursor-pointer pointer-events-auto transition-all"
                                                        />
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex justify-between items-start mb-1.5">
                                                            <h4 className="text-[13px] font-bold text-slate-800 leading-snug truncate pr-2 group-hover:text-indigo-700 transition-colors">
                                                                {app.candidate.full_name}
                                                            </h4>
                                                            <div className="flex flex-col gap-1 items-end shrink-0">
                                                                {app.ai_interview_score != null && (
                                                                    <div className="flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold leading-none bg-emerald-50 text-emerald-700 border border-emerald-200 shadow-sm transition-all animate-in fade-in zoom-in duration-300">
                                                                        <span className="material-icons text-[10px]">psychology</span>
                                                                        Int: {Math.round(app.ai_interview_score)}%
                                                                    </div>
                                                                )}
                                                                {app.ai_match_score !== undefined && (
                                                                    <div className={`flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold leading-none ${getScoreStyles(app.ai_match_score)}`}>
                                                                        <span className="material-icons text-[10px]">bolt</span>
                                                                        AI: {Math.round(app.ai_match_score)}%
                                                                    </div>
                                                                )}
                                                                {app.aptitude_score != null && app.aptitude_score > 0 && (
                                                                    <div className="flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold leading-none bg-blue-50 text-blue-700 border border-blue-200 shadow-sm">
                                                                        <span className="material-icons text-[10px]">psychology</span>
                                                                        Apt: {app.aptitude_score}%
                                                                    </div>
                                                                )}
                                                                {app.coding_score != null && app.coding_score > 0 && (
                                                                    <div className="flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold leading-none bg-emerald-50 text-emerald-700 border border-emerald-200 shadow-sm">
                                                                        <span className="material-icons text-[10px]">code</span>
                                                                        Cod: {app.coding_score}%
                                                                    </div>
                                                                )}
                                                                {app.assessment_score != null && app.aptitude_score == null && app.coding_score == null && (
                                                                    <div className="flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold leading-none bg-indigo-50 text-indigo-700 border border-indigo-200 shadow-sm">
                                                                        <span className="material-icons text-[10px]">quiz</span>
                                                                        Test: {app.assessment_score}%
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </div>

                                                        {/* Candidate Details Snippet */}
                                                        <div className="flex flex-col gap-1">
                                                            <div className="flex items-center gap-1.5 text-[11px] text-slate-500">

                                                                {app.applied_at ? formatDistanceToNow(new Date(app.applied_at), { addSuffix: true })
                                                                    .replace("about ", "") : "Recently"}
                                                            </div>


                                                        </div>
                                                    </div>
                                                </div>
                                            </motion.div>
                                        ))}
                                    </AnimatePresence>

                                    {stageApps.length === 0 && (
                                        <div className="h-32 rounded-xl bg-slate-100/50 border border-dashed border-slate-200 flex flex-col gap-2 items-center justify-center text-slate-400">
                                            <span className="material-icons-outlined text-2xl opacity-20">inbox</span>
                                            <span className="text-[11px] font-bold   opacity-60">No Candidates</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <AnimatePresence>
                {viewApplication && (
                    <CandidateModal 
                        application={viewApplication} 
                        isOpen={!!viewApplication}
                        onClose={() => setViewApplication(null)} 
                        onStatusUpdate={handleStageChange}
                        onRefresh={fetchApplications}
                        onboardingTemplates={onboardingTemplates}
                        stages={stages}
                    />
                )}
            </AnimatePresence>

            <AnimatePresence>
                {selectedApps.size > 0 && (
                    <div className="fixed bottom-10 left-[calc(50%+60px)] -translate-x-1/2 z-50">
                        <motion.div
                            initial={{ y: 50, opacity: 0, scale: 0.95 }}
                            animate={{ y: 0, opacity: 1, scale: 1 }}
                            exit={{ y: 50, opacity: 0, scale: 0.95 }}
                            className="bg-white shadow-xl rounded-xl p-2 flex items-center gap-2 border border-slate-100 ring-4 ring-slate-50/50"
                        >
                            {canAccess("candidates:update") && (
                                <button
                                    onClick={handleBulkMove}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-[11px] font-bold  tracking-wide transition-all shadow-lg shadow-indigo-200"
                                >
                                    <span className="material-icons text-[16px]">arrow_forward</span>
                                    Move to Next Round
                                </button>
                            )}

                            {canAccess("communications:read") && (
                                <button
                                    onClick={() => setIsEmailModalOpen(true)}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 hover:bg-slate-800 text-white rounded-xl text-[11px] font-bold  tracking-wide transition-all shadow-lg shadow-slate-200"
                                >
                                    <span className="material-icons text-[16px]">email</span>
                                    Send Email
                                </button>
                            )}

                            {canAccess("assessments:moderate") && (
                                <button
                                    onClick={() => setIsAssessmentModalOpen(true)}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-[11px] font-bold  tracking-wide transition-all shadow-lg shadow-indigo-200"
                                >
                                    <span className="material-icons text-[16px]">psychology</span>
                                    Send Assessment
                                </button>
                            )}

                            {canAccess("candidates:delete") && (
                                <button
                                    onClick={handleBulkDelete}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-white border border-rose-100 hover:bg-rose-50 text-rose-600 rounded-xl text-[11px] font-bold  tracking-wide transition-all"
                                >
                                    <span className="material-icons text-[16px]">delete</span>
                                    Delete
                                </button>
                            )}

                            {canAccess("onboarding:moderate") && (
                                <button
                                    onClick={() => setIsOnboardingModalOpen(true)}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-indigo-50 border border-indigo-100 hover:bg-indigo-100 text-indigo-700 rounded-xl text-[11px] font-bold  tracking-wide transition-all shadow-sm"
                                >
                                    <span className="material-icons-outlined text-[16px]">person_add</span>
                                    Initiate Onboarding
                                </button>
                            )}

                            <div className="px-3 text-xs font-bold text-slate-400 border-l border-slate-100 ml-1">
                                {selectedApps.size} Selected
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            <SendEmailModal
                isOpen={isEmailModalOpen}
                onClose={() => setIsEmailModalOpen(false)}
                candidateIds={Array.from(selectedApps).map(id => applications.find(a => a.id === id)?.candidate.id || "").filter(Boolean)}
                jobId={selectedJobId === "ALL" ? null : selectedJobId}
                token={token || ""}
            />

            <SendAssessmentModal
                isOpen={isAssessmentModalOpen}
                onClose={() => setIsAssessmentModalOpen(false)}
                applicationIds={Array.from(selectedApps)}
                token={token || ""}
            />

            <SendOnboardingModal
                isOpen={isOnboardingModalOpen}
                onClose={() => setIsOnboardingModalOpen(false)}
                applicationIds={Array.from(selectedApps)}
                token={token || ""}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";

import { 
    Search, 
    FileText, 
    ArrowRight, 
    Users, 
    Zap, 
    Star, 
    CheckCircle2, 
    ChevronDown, 
    Building2,
    X,
    Filter,
    LayoutGrid,
    List,
    Download,
    Mail
} from "lucide-react";

interface Job {
    id: string;
    title: string;
}

interface Candidate {
    id: string;
    full_name: string;
    email: string;
    phone: string;
    skills: string[];
    created_at: string;
    resume_url?: string;
    applied_jobs?: { id: string; title: string }[];
    parsed_data?: Record<string, unknown>;
}

interface Application {
    id: string;
    job_requirement_id: string;
    candidate: Candidate;
}

const CandidateProfileModal = ({ candidate, onClose }: { candidate: Candidate; onClose: () => void }) => {
    const details = candidate.parsed_data || {};

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-end bg-black/40 backdrop-blur-sm" onClick={onClose}>
            <motion.div
                initial={{ x: "100%" }}
                animate={{ x: 0 }}
                exit={{ x: "100%" }}
                transition={{ type: "spring", damping: 30, stiffness: 300 }}
                className="w-full max-w-xl h-full bg-white shadow-2xl overflow-y-auto"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="sticky top-0 bg-white z-10 border-b border-slate-100 px-6 py-5 flex items-start justify-between">
                    <div>
                        <h2 className="text-xl font-black text-slate-900 tracking-tight">{candidate.full_name}</h2>
                        <div className="flex flex-col gap-1.5 mt-2 text-xs text-slate-500">
                            <div className="flex items-center gap-2">
                                <Mail className="w-4 h-4 text-slate-400" />
                                {candidate.email}
                            </div>
                            {candidate.phone && (
                                <div className="flex items-center gap-2">
                                    <Zap className="w-4 h-4 text-slate-400" />
                                    {candidate.phone}
                                </div>
                            )}
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Body */}
                <div className="p-6 space-y-8">
                    {/* Resume Action */}
                    {candidate.resume_url && (
                        <div className="bg-slate-50 rounded-2xl p-5 border border-slate-200/60 flex items-center justify-between">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-rose-500 shadow-sm">
                                    <FileText className="w-6 h-6" />
                                </div>
                                <div>
                                    <h3 className="text-sm font-black text-slate-900">Resume Document</h3>
                                    <p className="text-xs font-medium text-slate-400 mt-0.5">Uploaded {new Date(candidate.created_at).toLocaleDateString()}</p>
                                </div>
                            </div>
                            <button
                                onClick={() => window.open(candidate.resume_url, '_blank')}
                                className="px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-xs font-black text-slate-700 hover:bg-slate-50 hover:border-slate-300 transition-all shadow-sm"
                            >
                                View Resume
                            </button>
                        </div>
                    )}

                    {/* Applied Jobs */}
                    <div>
                        <h3 className="font-black text-slate-900 text-sm mb-4 flex items-center gap-2">
                            <LayoutGrid className="w-4 h-4 text-indigo-500" />
                            Target Positions
                        </h3>
                        {candidate.applied_jobs && candidate.applied_jobs.length > 0 ? (
                            <div className="flex flex-wrap gap-2">
                                {candidate.applied_jobs.map((job, idx) => (
                                    <span key={idx} className="inline-flex items-center gap-2 px-3 py-1.5 rounded-xl bg-indigo-50 text-indigo-700 text-[10px] font-black border border-indigo-100">
                                        {job.title}
                                        <div className="w-1 h-1 rounded-full bg-indigo-400"></div>
                                    </span>
                                ))}
                            </div>
                        ) : (
                            <div className="p-4 rounded-xl border border-dashed border-slate-200 text-slate-400 text-[11px] font-medium">
                                No specific jobs linked (General Talent Pool)
                            </div>
                        )}
                    </div>

                    {/* Skills */}
                    {candidate.skills && candidate.skills.length > 0 && (
                        <div>
                            <h3 className="font-black text-slate-900 text-sm mb-4 flex items-center gap-2">
                                <Zap className="w-4 h-4 text-emerald-500" />
                                Verified Skills
                            </h3>
                            <div className="flex flex-wrap gap-2">
                                {candidate.skills.map((skill, i) => (
                                    <span key={i} className="px-3 py-1.5 bg-white border border-slate-200 rounded-xl text-[10px] text-slate-600 font-black shadow-sm uppercase tracking-wider">
                                        {skill}
                                    </span>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </motion.div>
        </div>
    );
};

export default function AllCandidatesPage() {
    const { token } = useAuth();
    const [candidates, setCandidates] = useState<Candidate[]>([]);
    const [jobs, setJobs] = useState<Job[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [selectedJobId, setSelectedJobId] = useState<string>("ALL");
    const [viewCandidate, setViewCandidate] = useState<Candidate | null>(null);

    useEffect(() => {
        if (token) {
            fetchData();
        }
    }, [token]);

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const [appsRes, jobsRes] = await Promise.all([
                fetch(`${BACKEND_URL}/api/v1/enterprise/applications/`, {
                    headers: { "Authorization": `Bearer ${token}` }
                }),
                fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, {
                    headers: { "Authorization": `Bearer ${token}` }
                })
            ]);

            if (appsRes.ok) {
                const appsData = await appsRes.json();
                let currentJobs: Job[] = [];
                if (jobsRes.ok) {
                    currentJobs = await jobsRes.json();
                    setJobs(currentJobs);
                }

                const jobsMap = new Map(currentJobs.map((j: Job) => [j.id, j]));
                const candidateMap = new Map<string, Candidate>();

                appsData.forEach((app: Application) => {
                    const cand = app.candidate;
                    if (!candidateMap.has(cand.id)) {
                        candidateMap.set(cand.id, {
                            ...cand,
                            applied_jobs: []
                        });
                    }

                    const jobId = app.job_requirement_id;
                    if (jobId && jobsMap.has(jobId)) {
                        const jobInfo = jobsMap.get(jobId);
                        const candidateEntry = candidateMap.get(cand.id);
                        if (candidateEntry && !candidateEntry.applied_jobs?.some(j => j.id === jobId)) {
                            candidateEntry.applied_jobs?.push({
                                id: jobId,
                                title: jobInfo.title
                            });
                        }
                    }
                });

                setCandidates(Array.from(candidateMap.values()));
            }
        } catch (error) {
            console.error("Error fetching data:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const filteredCandidates = candidates.filter(candidate => {
        const matchesSearch = candidate.full_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            candidate.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            candidate.skills?.some(skill => skill.toLowerCase().includes(searchQuery.toLowerCase()));

        const matchesJob = selectedJobId === "ALL" || candidate.applied_jobs?.some(job => job.id === selectedJobId);

        return matchesSearch && matchesJob;
    });

    const stats = {
        total: candidates.length,
        fastTrack: candidates.filter((c: Candidate) => c.applied_jobs && c.applied_jobs.length > 1).length,
        topTalent: candidates.filter((c: Candidate) => c.skills && c.skills.length > 5).length,
        qualified: candidates.filter((c: Candidate) => c.resume_url).length
    };

    return (
        <div className="p-8 space-y-8 animate-in fade-in duration-500">
            {/* Header Section */}
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight leading-none mb-2">Candidate Bank</h1>
                    <p className="text-sm font-medium text-slate-400">Discover and manage qualified talent across your organization</p>
                </div>
            </div>

            {/* Stat Cards Section */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                    { label: "Total Profiles", value: stats.total, icon: Users, color: "text-indigo-500", bg: "bg-indigo-50/50", hoverBg: "bg-indigo-50" },
                    { label: "Active Pipeline", value: stats.fastTrack, icon: Zap, color: "text-emerald-500", bg: "bg-emerald-50/50", hoverBg: "bg-emerald-50" },
                    { label: "Highly Skilled", value: stats.topTalent, icon: Star, color: "text-amber-500", bg: "bg-amber-50/50", hoverBg: "bg-amber-50" },
                    { label: "Qualified Repos", value: stats.qualified, icon: CheckCircle2, color: "text-rose-500", bg: "bg-rose-50/50", hoverBg: "bg-rose-50" },
                ].map((card, i) => (
                    <motion.div 
                        key={i}
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ delay: i * 0.1 }}
                        className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                    >
                        <div className="flex justify-between items-start">
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{card.label}</span>
                            <div className={`w-12 h-12 rounded-xl ${card.bg} ${card.color} flex items-center justify-center transition-all group-hover:scale-110 group-hover:${card.hoverBg}`}>
                                <card.icon className="w-6 h-6" />
                            </div>
                        </div>
                        <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                            {card.value}
                        </div>
                    </motion.div>
                ))}
            </div>

            {/* Filter Bar */}
            <div className="flex items-center gap-4">
                <div className="flex-1 relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-[#7C3AED] transition-colors" />
                    <input 
                        type="text" 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search by name, email, or skills..."
                        className="w-full bg-white border border-slate-100 rounded-2xl py-3.5 pl-12 pr-4 text-sm font-semibold text-slate-700 placeholder:text-slate-400 focus:outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-[#7C3AED] transition-all shadow-sm"
                    />
                </div>

                <div className="flex items-center gap-2">
                    <div className="relative">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                            <Building2 className="w-4 h-4" />
                        </div>
                        <select 
                            value={selectedJobId}
                            onChange={(e) => setSelectedJobId(e.target.value)}
                            className="bg-slate-50 border border-slate-100 rounded-2xl py-3 pl-9 pr-10 text-xs font-bold text-slate-600 outline-none appearance-none cursor-pointer hover:bg-white transition-all shadow-sm min-w-[160px]"
                        >
                            <option value="ALL">All Applications</option>
                            {jobs.map(j => <option key={j.id} value={j.id}>{j.title}</option>)}
                        </select>
                        <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                    </div>

                    <div className="flex items-center p-1.5 bg-slate-50 border border-slate-100 rounded-2xl">
                        <div className="w-10 h-10 flex items-center justify-center rounded-xl bg-white text-[#7C3AED] shadow-sm">
                            <LayoutGrid className="w-5 h-5" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/10 overflow-hidden min-h-[500px]">
                {isLoading ? (
                    <div className="p-8 space-y-4">
                        {[1, 2, 3, 4, 5].map(i => (
                            <div key={i} className="h-16 bg-slate-50 rounded-2xl animate-pulse" />
                        ))}
                    </div>
                ) : filteredCandidates.length === 0 ? (
                    <div className="flex flex-col items-center justify-center p-20 text-center">
                        <div className="w-20 h-20 bg-slate-50 rounded-3xl flex items-center justify-center mb-6">
                            <Users className="w-10 h-10 text-slate-300" />
                        </div>
                        <h3 className="text-xl font-black text-slate-900 mb-2">No candidates matched</h3>
                        <p className="text-slate-500 max-w-xs mx-auto mb-8">Refine your search parameters to discover other talent in your pool.</p>
                        <button onClick={() => { setSearchQuery(""); setSelectedJobId("ALL"); }} className="px-6 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm">Reset Search</button>
                    </div>
                ) : (
                    <table className="w-full border-collapse">
                        <thead>
                            <tr className="bg-slate-50/50">
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Candidate</th>
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Target Pipeline</th>
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Top Skills</th>
                                <th className="px-6 py-4 text-right text-[11px] font-black text-slate-400 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                            {filteredCandidates.map((candidate, index) => (
                                <tr key={candidate.id} className="hover:bg-slate-50/30 transition-all group">
                                    <td className="px-6 py-5">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-100 to-slate-50 text-[#7C3AED] flex items-center justify-center font-black text-xs border border-indigo-100 shadow-sm">
                                                {candidate.full_name?.charAt(0)}
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-sm font-black text-slate-900 group-hover:text-[#7C3AED] transition-colors">{candidate.full_name}</span>
                                                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{candidate.email}</span>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-5">
                                        {candidate.applied_jobs && candidate.applied_jobs.length > 0 ? (
                                            <div className="flex flex-wrap gap-1.5">
                                                {candidate.applied_jobs.slice(0, 2).map((job, idx) => (
                                                    <span key={idx} className="inline-flex items-center px-3 py-1.5 rounded-xl bg-slate-100 text-slate-600 text-[10px] font-black border border-slate-200">
                                                        {job.title}
                                                    </span>
                                                ))}
                                                {candidate.applied_jobs.length > 2 && (
                                                    <span className="text-[10px] font-black text-slate-300">+{candidate.applied_jobs.length - 2}</span>
                                                )}
                                            </div>
                                        ) : (
                                            <span className="text-[10px] font-black text-slate-400 uppercase italic">General Pool</span>
                                        )}
                                    </td>
                                    <td className="px-6 py-5">
                                        <div className="flex flex-wrap gap-1.5">
                                            {candidate.skills?.slice(0, 3).map((s, idx) => (
                                                <span key={idx} className="inline-flex items-center px-2 py-1 rounded-lg bg-indigo-50 text-indigo-600 text-[9px] font-black border border-indigo-100 uppercase tracking-wider">
                                                    {s}
                                                </span>
                                            ))}
                                            {candidate.skills && candidate.skills.length > 3 && (
                                                <span className="text-[10px] font-black text-slate-300">+{candidate.skills.length - 3}</span>
                                            )}
                                        </div>
                                    </td>
                                    <td className="px-6 py-5 text-right">
                                        <div className="flex items-center justify-end gap-3">
                                            {candidate.resume_url && (
                                                <button
                                                    onClick={() => window.open(candidate.resume_url, '_blank')}
                                                    className="w-10 h-10 flex items-center justify-center rounded-xl bg-slate-50 text-slate-400 hover:bg-rose-50 hover:text-rose-600 hover:border-rose-100 transition-all border border-transparent shadow-sm"
                                                    title="View Resume"
                                                >
                                                    <FileText className="w-5 h-5" />
                                                </button>
                                            )}
                                            <button
                                                onClick={() => setViewCandidate(candidate)}
                                                className="h-10 px-4 rounded-xl bg-[#7C3AED]/10 text-[#7C3AED] text-[11px] font-black hover:bg-[#7C3AED] hover:text-white transition-all flex items-center gap-2 active:scale-95 shadow-sm"
                                            >
                                                Open Profile
                                                <ArrowRight className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>
            
            <AnimatePresence>
                {viewCandidate && (
                    <CandidateProfileModal candidate={viewCandidate} onClose={() => setViewCandidate(null)} />
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import {
    Mail, Send, Inbox, Trash2, Search, Filter,
    RotateCcw, MoreVertical, Star, Reply,
    ChevronRight, Brain, Clock, ChevronLeft, X
} from 'lucide-react';
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { Button } from '../../../components/ui/button';
import { Input } from '../../../components/ui/input';
import { Badge } from '../../../components/ui/badge';

interface Email {
    id: string;
    sender_email: string;
    recipient_email: string;
    subject: string;
    body: string;
    direction: "INBOUND" | "OUTBOUND";
    status: string;
    is_read: boolean;
    sent_at: string;
    candidate_name?: string;
}

const MailboxPage = () => {
    const { token, canAccess } = useAuth();
    const [activeTab, setActiveTab] = useState<'INBOUND' | 'OUTBOUND' | 'FAVORITE' | 'TRASH'>('INBOUND');
    const [emails, setEmails] = useState<Email[]>([]);
    const [selectedEmail, setSelectedEmail] = useState<Email | null>(null);
    const [searchQuery, setSearchQuery] = useState('');
    const [isLoading, setIsLoading] = useState(true);
    const [smartReply, setSmartReply] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [isComposeOpen, setIsComposeOpen] = useState(false);
    const [composeData, setComposeData] = useState({ to: '', subject: '', body: '' });
    const [isSending, setIsSending] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [statusMsg, setStatusMsg] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    const fetchEmails = async (direction: string) => {
        if (!token) return;
        if (direction === 'FAVORITE' || direction === 'TRASH') {
            setEmails([]);
            setIsLoading(false);
            return;
        }
        setIsLoading(true);
        try {
            const resp = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/logs?direction=${direction}`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            const data = await resp.json();
            setEmails(Array.isArray(data) ? data : []);
        } catch (err) {
            console.error("Failed to fetch emails", err);
            setEmails([]);
        } finally {
            setIsLoading(false);
        }
    };

    const syncEmails = async () => {
        if (!token) return;
        setIsSyncing(true);
        try {
            const resp = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/sync-imap`, {
                method: 'POST',
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            const data = await resp.json();
            if (data.status === "success") {
                setStatusMsg({ type: 'success', text: `Sync complete! Fetched ${data.synced_count} new emails.` });
                fetchEmails(activeTab);
            } else {
                setStatusMsg({ type: 'error', text: data.status || "Sync failed" });
            }
            setTimeout(() => setStatusMsg(null), 5000);
        } catch (err) {
            console.error("Sync failed", err);
            setStatusMsg({ type: 'error', text: "Sync connection error" });
            setTimeout(() => setStatusMsg(null), 5000);
        } finally {
            setIsSyncing(false);
        }
    };

    const markAsRead = async (logId: string) => {
        if (!token) return;
        try {
            await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/read/${logId}`, {
                method: 'PATCH',
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            // Update local state to show as read
            setEmails(prev => prev.map(e => e.id === logId ? { ...e, is_read: true } : e));
        } catch (err) {
            console.error("Failed to mark as read", err);
        }
    };

    const handleSmartReply = async () => {
        if (!selectedEmail || !token) return;
        setIsGenerating(true);
        try {
            const resp = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/smart-reply/${selectedEmail.id}`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            const data = await resp.json();
            setSmartReply(data.reply);
        } catch (err) {
            console.error("Failed to generate smart reply", err);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleSendEmail = async () => {
        if (!composeData.to || !composeData.subject || !composeData.body || !token) return;
        setIsSending(true);
        try {
            // Fetch candidate ID by email first if possible, or just send directly
            // For now, our /send endpoint expects candidate IDs. 
            // In a real mailbox, we might need a generic send. 
            // Let's use a simpler approach: if it's a candidate, find them. 
            // Otherwise, we'll need a generic send-direct endpoint.

            // For this implementation, let's assume we are sending to a candidate's email directly
            const resp = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/send`, {
                method: 'POST',
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({
                    recipient_emails: [composeData.to], // Supporting direct emails if the backend allows
                    subject: composeData.subject,
                    body: composeData.body
                })
            });

            if (resp.ok) {
                setIsComposeOpen(false);
                setComposeData({ to: '', subject: '', body: '' });
                setStatusMsg({ type: 'success', text: 'Email sent successfully!' });
                if (activeTab === 'OUTBOUND') fetchEmails('OUTBOUND');
                setTimeout(() => setStatusMsg(null), 3000);
            } else {
                const errData = await resp.json();
                setStatusMsg({ type: 'error', text: errData.detail || 'Failed to send email' });
                setTimeout(() => setStatusMsg(null), 5000);
            }
        } catch (err) {
            console.error("Failed to send email", err);
            setStatusMsg({ type: 'error', text: 'Connection error. Please try again.' });
            setTimeout(() => setStatusMsg(null), 5000);
        } finally {
            setIsSending(false);
        }
    };

    const openReply = () => {
        if (!selectedEmail) return;
        setComposeData({
            to: selectedEmail.direction === 'INBOUND' ? selectedEmail.sender_email : selectedEmail.recipient_email,
            subject: `Re: ${selectedEmail.subject}`,
            body: `<br><br>---<br>${selectedEmail.body}`
        });
        setIsComposeOpen(true);
    };

    useEffect(() => {
        if (token) {
            fetchEmails(activeTab);
        }
        setSmartReply('');
    }, [activeTab, token]);

    useEffect(() => {
        if (selectedEmail && !selectedEmail.is_read && selectedEmail.direction === 'INBOUND') {
            markAsRead(selectedEmail.id);
        }
        setSmartReply('');
    }, [selectedEmail]);

    const filteredEmails = Array.isArray(emails) ? emails.filter((e: Email) =>
        (e.subject?.toLowerCase() || "").includes(searchQuery.toLowerCase()) ||
        (e.sender_email?.toLowerCase() || "").includes(searchQuery.toLowerCase()) ||
        (e.recipient_email?.toLowerCase() || "").includes(searchQuery.toLowerCase())
    ) : [];

    return (
        <div className="flex h-full bg-white overflow-hidden border-t border-slate-100 shadow-sm animate-in fade-in duration-500">
            {/* Mailbox Sidebar */}
            <div className="w-64 bg-white border-r border-slate-200 flex flex-col p-4 gap-2">
                {canAccess("communications:create") && (
                    <button
                        className="w-full h-11 mb-6 bg-[#7C3AED] text-white rounded-xl font-black text-xs hover:bg-[#6D28D9] shadow-xl shadow-indigo-100 transition-all flex items-center justify-center gap-2 active:scale-95"
                        onClick={() => {
                            setComposeData({ to: '', subject: '', body: '' });
                            setIsComposeOpen(true);
                        }}
                    >
                        <Send className="w-4 h-4" /> Compose Message
                    </button>
                )}

                <SidebarItem
                    icon={<Inbox className="w-4 h-4" />}
                    label="Inbox"
                    active={activeTab === 'INBOUND'}
                    onClick={() => setActiveTab('INBOUND')}
                    count={emails.filter(e => e.direction === 'INBOUND' && !e.is_read).length}
                />
                <SidebarItem
                    icon={<Send className="w-4 h-4" />}
                    label="Sent"
                    active={activeTab === 'OUTBOUND'}
                    onClick={() => setActiveTab('OUTBOUND')}
                />
                <SidebarItem
                    icon={<Star className="w-4 h-4" />}
                    label="Favorites"
                    active={activeTab === 'FAVORITE'}
                    onClick={() => setActiveTab('FAVORITE')}
                />
                <SidebarItem
                    icon={<Trash2 className="w-4 h-4" />}
                    label="Trash"
                    active={activeTab === 'TRASH'}
                    onClick={() => setActiveTab('TRASH')}
                />
            </div>

            {/* Email List */}
            <div className="w-96 bg-white border-r border-slate-200 flex flex-col">
                <div className="p-4 border-b border-slate-100 relative">
                    {statusMsg && (
                        <div className={`absolute top-0 left-0 right-0 p-2 text-center text-xs font-bold animate-in slide-in-from-top duration-300 z-50 ${statusMsg.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-red-500 text-white'}`}>
                            {statusMsg.text}
                        </div>
                    )}
                    <h2 className="text-xl font-bold text-slate-800 mb-4">
                        {activeTab === 'INBOUND' ? 'Inbox' : 
                         activeTab === 'OUTBOUND' ? 'Sent' :
                         activeTab === 'FAVORITE' ? 'Favorites' : 'Trash'}
                    </h2>
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <Input
                            placeholder="Search conversations..."
                            className="pl-10 bg-slate-50 border-none rounded-xl"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto">
                    {isLoading ? (
                        <div className="p-8 text-center text-slate-400">Loading...</div>
                    ) : filteredEmails.length === 0 ? (
                        <div className="p-12 text-center text-slate-300">
                            <Mail className="w-12 h-12 mb-4 mx-auto opacity-10" />
                            <p className="text-sm font-medium">No messages found here</p>
                        </div>
                    ) : filteredEmails.map((email: Email) => (
                        <div
                            key={email.id}
                            onClick={() => setSelectedEmail(email)}
                            className={`p-4 border-b border-slate-50 cursor-pointer transition-all hover:bg-indigo-50/30 ${selectedEmail?.id === email.id ? 'bg-indigo-50 border-l-4 border-l-indigo-500' : ''}`}
                        >
                            <div className="flex justify-between items-start mb-1">
                                <span className={`text-sm font-semibold flex items-center gap-2 ${!email.is_read && email.direction === 'INBOUND' ? 'text-slate-900' : 'text-slate-600'}`}>
                                    {email.direction === 'INBOUND' ? email.sender_email : email.recipient_email}
                                    {!email.is_read && email.direction === 'INBOUND' && (
                                        <span className="w-2 h-2 bg-indigo-600 rounded-full"></span>
                                    )}
                                </span>
                                <span className="text-[10px] text-slate-400 flex items-center">
                                    <Clock className="w-3 h-3 mr-1" />
                                    {new Date(email.sent_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                </span>
                            </div>
                            <h3 className={`text-sm mb-1 truncate ${!email.is_read && email.direction === 'INBOUND' ? 'font-bold' : 'font-medium'}`}>
                                {email.subject}
                            </h3>
                            <p className="text-xs text-slate-400 line-clamp-2">
                                {email.body.replace(/<[^>]*>/g, '')}
                            </p>
                        </div>
                    ))}
                </div>
            </div>

            {/* Email View */}
            <div className="flex-1 flex flex-col bg-white">
                {selectedEmail ? (
                    <>
                        <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                            <div className="flex gap-2">
                                {canAccess("communications:create") && (
                                    <Button variant="outline" size="sm" className="rounded-full" onClick={openReply}><Reply className="w-3 h-3 mr-2" /> Reply</Button>
                                )}
                                <Button variant="outline" size="sm" className="rounded-full" onClick={() => setStatusMsg({ type: 'success', text: "Added to Favorites (Local Only)" })}><Star className="w-3 h-3" /></Button>
                                {canAccess("communications:delete") && (
                                    <Button variant="outline" size="sm" className="rounded-full text-red-500 hover:text-red-600" onClick={() => setStatusMsg({ type: 'error', text: "Moved to Trash (Local Only)" })}><Trash2 className="w-3 h-3" /></Button>
                                )}
                            </div>
                            <div className="flex gap-2">
                                <Button 
                                    variant="ghost" 
                                    size="sm" 
                                    onClick={() => {
                                        const idx = filteredEmails.findIndex(e => e.id === selectedEmail?.id);
                                        if (idx > 0) setSelectedEmail(filteredEmails[idx - 1]);
                                    }}
                                    disabled={filteredEmails.findIndex(e => e.id === selectedEmail?.id) <= 0}
                                >
                                    <ChevronLeft className="w-4 h-4" />
                                </Button>
                                <Button 
                                    variant="ghost" 
                                    size="sm"
                                    onClick={() => {
                                        const idx = filteredEmails.findIndex(e => e.id === selectedEmail?.id);
                                        if (idx !== -1 && idx < filteredEmails.length - 1) setSelectedEmail(filteredEmails[idx + 1]);
                                    }}
                                    disabled={filteredEmails.findIndex(e => e.id === selectedEmail?.id) >= filteredEmails.length - 1}
                                >
                                    <ChevronRight className="w-4 h-4" />
                                </Button>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-8">
                            <div className="max-w-3xl mx-auto">
                                <div className="mb-8">
                                    <h1 className="text-2xl font-bold text-slate-800 mb-6">{selectedEmail.subject}</h1>
                                    <div className="flex items-center justify-between mb-8">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold">
                                                {selectedEmail.direction === 'INBOUND' ? selectedEmail.sender_email[0].toUpperCase() : 'Y'}
                                            </div>
                                            <div>
                                                <div className="text-sm font-semibold text-slate-900">{selectedEmail.direction === 'INBOUND' ? selectedEmail.sender_email : 'Me'}</div>
                                                <div className="text-xs text-slate-500">to {selectedEmail.direction === 'INBOUND' ? 'Me' : selectedEmail.recipient_email}</div>
                                            </div>
                                        </div>
                                        <div className="text-xs text-slate-400">
                                            {new Date(selectedEmail.sent_at).toLocaleString()}
                                        </div>
                                    </div>
                                </div>

                                <div
                                    className="prose prose-slate max-w-none text-slate-700 leading-relaxed"
                                    dangerouslySetInnerHTML={{ __html: selectedEmail.body }}
                                />

                                {/* AI Agent Sidebar Section */}
                                <div className="mt-12 p-6 bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl border border-indigo-100 shadow-sm relative overflow-hidden group">
                                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                                        <Brain className="w-24 h-24" />
                                    </div>
                                    <div className="relative z-10">
                                        <div className="flex items-center gap-3 mb-4">
                                            <Badge variant="outline" className="bg-white/80 border-indigo-200 text-indigo-700 py-1">
                                                <Brain className="w-3 h-3 mr-1" /> AI Agent Analysis
                                            </Badge>
                                        </div>
                                        <p className="text-sm text-slate-700 mb-4 ">
                                            "The AI has analyzed this message. You can generate a smart reply based on candidates requirements and the job context."
                                        </p>

                                        {smartReply && (
                                            <div className="mb-4 p-4 bg-white/50 rounded-xl border border-indigo-100 text-sm text-slate-700 animate-in slide-in-from-top-2">
                                                <div className="font-bold text-xs text-indigo-600 mb-2  ">Suggested Reply:</div>
                                                {smartReply}
                                            </div>
                                        )}

                                        <div className="flex gap-2 mt-2">
                                            {canAccess("communications:moderate") && (
                                                <Button
                                                    size="sm"
                                                    className="bg-[#7C3AED] hover:bg-[#6D28D9] font-black text-xs shadow-lg shadow-indigo-100"
                                                    onClick={handleSmartReply}
                                                    disabled={isGenerating}
                                                >
                                                    {isGenerating ? 'Analyzing...' : smartReply ? 'Regenerate Draft' : 'Draft Smart Reply'}
                                                </Button>
                                            )}
                                            
                                            {canAccess("communications:create") && smartReply && (
                                                <Button 
                                                    size="sm" 
                                                    variant="secondary" 
                                                    className="bg-white border-indigo-200 text-indigo-700 hover:bg-indigo-50"
                                                    onClick={() => {
                                                        const cleanReply = smartReply.replace(/Suggested Reply:\s*/, "");
                                                        setComposeData({
                                                            to: selectedEmail.direction === 'INBOUND' ? selectedEmail.sender_email : selectedEmail.recipient_email,
                                                            subject: `Re: ${selectedEmail.subject}`,
                                                            body: cleanReply
                                                        });
                                                        setIsComposeOpen(true);
                                                    }}
                                                >
                                                    Apply to Reply
                                                </Button>
                                            )}

                                            <Button 
                                                size="sm" 
                                                variant="ghost" 
                                                className="text-indigo-600"
                                                onClick={() => {
                                                    alert("Candidate Fit Analysis: \n- AI Score: 85/100 \n- Strong Skills: Project Management, Communication \n- Recommendation: Proceed to Interview Round");
                                                }}
                                            >
                                                View Candidate Fit
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-300">
                        <Mail className="w-16 h-16 mb-4 opacity-20" />
                        <p className="text-slate-400 font-medium">Select an email to read the conversation</p>
                    </div>
                )}
            </div>

            {/* Compose Modal */}
            {isComposeOpen && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300">
                    <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col">
                        <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                            <h3 className="font-bold text-slate-800 flex items-center gap-2">
                                <Mail className="w-4 h-4 text-indigo-600" /> New Message
                            </h3>
                            <button
                                onClick={() => setIsComposeOpen(false)}
                                className="w-8 h-8 flex items-center justify-center rounded-full text-slate-400 hover:bg-slate-200 hover:text-slate-600 transition-all"
                            >
                                <X className="w-4 h-4" />
                            </button>
                        </div>

                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400   mb-1.5">Recipient Email</label>
                                <Input
                                    placeholder="e.g. candidate@example.com"
                                    value={composeData.to}
                                    onChange={(e) => setComposeData({ ...composeData, to: e.target.value })}
                                    className="h-10 text-sm font-medium border-slate-100 bg-slate-50/50"
                                />
                            </div>

                            <div>
                                <label className="block text-[10px] font-black text-slate-400   mb-1.5">Subject</label>
                                <Input
                                    placeholder="Enter subject..."
                                    value={composeData.subject}
                                    onChange={(e) => setComposeData({ ...composeData, subject: e.target.value })}
                                    className="h-10 text-sm font-medium border-slate-100 bg-slate-50/50"
                                />
                            </div>

                            <div>
                                <label className="block text-[10px] font-black text-slate-400   mb-1.5">Message Content</label>
                                <textarea
                                    className="w-full h-64 p-4 rounded-xl border border-slate-100 bg-slate-50/50 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all resize-none"
                                    placeholder="Type your message here..."
                                    value={composeData.body}
                                    onChange={(e) => setComposeData({ ...composeData, body: e.target.value })}
                                />
                            </div>
                        </div>

                        <div className="p-4 bg-slate-50 border-t border-slate-200 flex justify-end gap-3">
                            <Button variant="ghost" onClick={() => setIsComposeOpen(false)}>Cancel</Button>
                            <Button
                                className="bg-[#7C3AED] hover:bg-[#6D28D9] px-8 font-black text-xs"
                                onClick={handleSendEmail}
                                disabled={isSending || !composeData.to || !composeData.subject || !composeData.body}
                            >
                                {isSending ? 'Sending...' : 'Send Message'}
                                <Send className="w-4 h-4 ml-2" />
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

interface SidebarItemProps {
    icon: React.ReactNode;
    label: string;
    active?: boolean;
    onClick?: () => void;
    count?: number;
}

const SidebarItem = ({ icon, label, active, onClick, count }: SidebarItemProps) => (
    <button
        onClick={onClick}
        className={`flex items-center justify-between w-full h-11 px-4 rounded-xl transition-all ${active ? 'bg-indigo-50 text-[#7C3AED] font-black' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800 font-bold'}`}
    >
        <div className="flex items-center gap-3">
            <div className={`transition-colors ${active ? 'text-[#7C3AED]' : 'text-slate-400'}`}>
                {icon}
            </div>
            <span className="text-xs">{label}</span>
        </div>
        {count ? (
            <span className="bg-[#7C3AED] text-white text-[9px] font-black px-1.5 py-0.5 rounded-lg min-w-[20px] shadow-sm shadow-indigo-200">
                {count}
            </span>
        ) : null}
    </button>
);

export default MailboxPage;

"use client";

import { useState, useEffect, useRef } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";

interface Message {
    role: "user" | "assistant" | "system";
    content: string;
}

interface Report {
    communication_score?: number;
    empathy_score?: number;
    problem_solving_score?: number;
    strengths?: string[];
    areas_for_improvement?: string[];
}

interface Scenario {
    title: string;
    difficulty: string;
    character_name: string;
    character_role: string;
}

interface Session {
    status: string;
    report?: Report;
    feedback?: string;
    scenario: Scenario;
    conversation?: Message[];
}

interface SimulationChatProps {
    sessionId: string;
    onComplete?: (report: Report) => void;
    onClose?: () => void;
}

export default function SimulationChat({ sessionId, onComplete, onClose }: SimulationChatProps) {
    const { token } = useAuth();
    const [session, setSession] = useState<Session | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState("");
    const [loading, setLoading] = useState(true);
    const [sending, setSending] = useState(false);
    const [completing, setCompleting] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        fetchSession();
    }, [sessionId, token]);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const fetchSession = async () => {
        try {
            const headers: Record<string, string> = {};
            if (token) headers['Authorization'] = `Bearer ${token}`;
            
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/sessions/${sessionId}`, {
                headers
            });
            const data = await res.json();
            setSession(data);
            setMessages(data.conversation?.filter((m: Message) => m.role !== "system") || []);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || sending) return;

        const userMsg = input.trim();
        setInput("");
        setMessages(prev => [...prev, { role: "user", content: userMsg }]);
        setSending(true);

        try {
            const headers: Record<string, string> = { 'Content-Type': 'application/json' };
            if (token) headers['Authorization'] = `Bearer ${token}`;

            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/sessions/${sessionId}/chat`, {
                method: 'POST',
                headers,
                body: JSON.stringify({ message: userMsg })
            });
            const data = await res.json();
            setMessages(prev => [...prev, { role: "assistant", content: data.reply }]);
        } catch (error) {
            console.error(error);
        } finally {
            setSending(false);
        }
    };

    const handleComplete = async () => {
        setCompleting(true);
        try {
            const headers: Record<string, string> = {};
            if (token) headers['Authorization'] = `Bearer ${token}`;

            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/simulations/sessions/${sessionId}/complete`, {
                method: 'POST',
                headers
            });
            const data = await res.json();
            if (onComplete) onComplete(data);
            // After completion, the UI will switch to the results screen handled below
            await fetchSession();
        } catch (error) {
            console.error(error);
        } finally {
            setCompleting(false);
        }
    };

    if (loading) return (
        <div className="h-screen w-screen bg-[#202123] flex flex-col items-center justify-center text-white/50">
            <div className="w-12 h-12 border-4 border-white/10 border-t-indigo-500 rounded-full animate-spin mb-6"></div>
            <p className="text-[10px] font-black  tracking-[0.5em] animate-pulse">Initializing Behavioral Neural Link</p>
        </div>
    );

    if (session?.status === "COMPLETED") {
        return (
            <div className="h-screen w-screen bg-[#fafafa] flex flex-col items-center overflow-y-auto py-12 px-6 animate-in fade-in duration-700">
                <div className="max-w-[900px] w-full space-y-12">
                    <header className="flex flex-col items-center gap-6 text-center">
                        <div className="tracking-tighter py-4">
                            <span className="text-6xl font-black bg-gradient-to-r from-[#7C3AED] to-[#D946EF] bg-clip-text text-transparent  tracking-tighter">CROAR.AI</span>
                        </div>
                        <div>
                            <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-2 ">Neural Audit Complete</h2>
                            <p className="text-slate-400 font-bold  tracking-[0.3em] text-[10px]">Strategic behavioral performance calibrated</p>
                        </div>
                    </header>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        {[
                            { label: 'Communication', score: session.report?.communication_score, icon: 'record_voice_over', color: 'indigo' },
                            { label: 'Empathy', score: session.report?.empathy_score, icon: 'favorite', color: 'rose' },
                            { label: 'Problem Solving', score: session.report?.problem_solving_score, icon: 'psychology', color: 'emerald' }
                        ].map((m, i) => (
                            <div key={i} className="bg-white p-8 rounded-2xl border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col items-center gap-4 group hover:border-indigo-200 transition-all">
                                <span className={`material-symbols-rounded text-${m.color}-500 text-3xl group-hover:scale-125 transition-transform`}>{m.icon}</span>
                                <div className="text-3xl font-black text-slate-900 tracking-tighter">{m.score || 0}/10</div>
                                <span className="text-[10px] font-black text-slate-400  ">{m.label}</span>
                            </div>
                        ))}
                    </div>

                    <div className="bg-indigo-600 p-12 rounded-2xl text-white space-y-6 shadow-2xl shadow-indigo-100 relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-full h-full bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10 pointer-events-none"></div>
                        <h3 className="text-xs font-black  tracking-[0.4em] flex items-center gap-3 opacity-70">
                            <span className="material-symbols-rounded">neurology</span>
                            Executive Feedback
                        </h3>
                        <p className="text-2xl font-bold leading-tight ">&quot;{session.feedback}&quot;</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                        <section className="space-y-6">
                            <h4 className="text-[10px] font-black text-emerald-600  tracking-[0.5em] px-2 flex items-center gap-2">
                                <span className="material-symbols-rounded text-sm">stars</span> Behavioral Strengths
                            </h4>
                            <div className="space-y-3">
                                {session.report?.strengths?.map((s: string, i: number) => (
                                    <div key={i} className="bg-white p-5 rounded-xl border border-emerald-50 shadow-sm flex gap-4 items-center group hover:border-emerald-200 transition-all">
                                        <div className="w-8 h-8 rounded-xl bg-emerald-50 text-emerald-500 flex items-center justify-center shrink-0">
                                            <span className="material-symbols-rounded text-lg">check_circle</span>
                                        </div>
                                        <span className="text-sm font-bold text-slate-700">{s}</span>
                                    </div>
                                ))}
                            </div>
                        </section>
                        <section className="space-y-6">
                            <h4 className="text-[10px] font-black text-rose-600  tracking-[0.5em] px-2 flex items-center gap-2">
                                <span className="material-symbols-rounded text-sm">trending_up</span> Growth Vector
                            </h4>
                            <div className="space-y-3">
                                {session.report?.areas_for_improvement?.map((s: string, i: number) => (
                                    <div key={i} className="bg-white p-5 rounded-xl border border-rose-50 shadow-sm flex gap-4 items-center group hover:border-rose-200 transition-all">
                                        <div className="w-8 h-8 rounded-xl bg-rose-50 text-rose-500 flex items-center justify-center shrink-0">
                                            <span className="material-symbols-rounded text-lg">bolt</span>
                                        </div>
                                        <span className="text-sm font-bold text-slate-700">{s}</span>
                                    </div>
                                ))}
                            </div>
                        </section>
                    </div>

                    <div className="flex justify-center pb-20">
                        <button 
                            onClick={onClose}
                            className="px-16 py-6 bg-slate-900 text-white rounded-2xl font-black text-xs  tracking-[0.4em] hover:bg-indigo-600 transition-all shadow-2xl active:scale-95 group"
                        >
                            <span className="flex items-center gap-3">
                                Return to Hub
                                <span className="material-symbols-rounded group-hover:translate-x-1 transition-transform">arrow_forward</span>
                            </span>
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="flex h-screen w-screen bg-white overflow-hidden text-slate-800 animate-in fade-in duration-1000">
            {/* Sidebar - ChatGPT Style */}
            <aside className="w-[280px] bg-[#202123] text-white flex flex-col p-4 shrink-0 transition-all">
                <div className="py-8 px-4 mb-4 tracking-tighter">
                    <span className="text-4xl font-black  bg-gradient-to-r from-[#7C3AED] to-[#D946EF] bg-clip-text text-transparent tracking-tighter">CROAR.AI</span>
                </div>
                
                <button 
                    onClick={onClose}
                    className="flex items-center gap-3 w-full p-4 mb-8 border border-white/20 rounded-xl hover:bg-white/5 transition-colors text-sm font-bold text-white/50"
                >
                    <span className="material-symbols-rounded">arrow_back</span>
                    Exit Simulation
                </button>

                <div className="flex-1 space-y-8 px-2">
                    <div>
                        <h3 className="text-[10px] font-black text-white/30  tracking-[0.3em] mb-4">Current Lab</h3>
                        <div className="p-4 bg-indigo-600/20 border border-indigo-500/30 rounded-xl">
                            <h4 className="text-sm font-black text-indigo-400 mb-1 leading-tight">{session.scenario.title}</h4>
                            <p className="text-[9px] font-bold text-white/40  ">{session.scenario.difficulty} LEVEL</p>
                        </div>
                    </div>

                    <div>
                        <h3 className="text-[10px] font-black text-white/30  tracking-[0.3em] mb-4">Neural Persona</h3>
                        <div className="flex flex-col gap-4">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center shadow-lg">
                                    <span className="material-symbols-rounded">smart_toy</span>
                                </div>
                                <div>
                                    <div className="text-xs font-black text-white">{session.scenario.character_name}</div>
                                    <div className="text-[9px] font-bold text-white/40   leading-none mt-1">{session.scenario.character_role}</div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="pt-8">
                        <div className="p-6 border border-white/10 rounded-xl bg-white/5 text-[10px] font-bold text-white/60 leading-relaxed ">
                            &quot;A behavioral mirror designed for high-fidelity interactive role-play.&quot;
                        </div>
                    </div>
                </div>

                <div className="p-2 pt-6 border-t border-white/10">
                    <button 
                        onClick={handleComplete}
                        disabled={completing || messages.length < 2}
                        className="w-full py-5 bg-white text-slate-900 rounded-xl font-black text-[10px]  tracking-[0.2em] hover:bg-rose-500 hover:text-white transition-all disabled:opacity-20 flex items-center justify-center gap-2 group shadow-xl"
                    >
                        {completing ? 'Analyzing...' : (
                            <>
                                <span>Finalize Evaluation</span>
                                <span className="material-symbols-rounded text-sm group-hover:rotate-12 transition-transform">analytics</span>
                            </>
                        )}
                    </button>
                </div>
            </aside>

            {/* Main Chat Area */}
            <main className="flex-1 flex flex-col relative h-full bg-white transition-all overflow-hidden">
                {/* Chat Flow */}
                <div ref={scrollRef} className="flex-1 overflow-y-auto w-full scroll-smooth pt-20">
                    <div className="max-w-[800px] mx-auto px-6 space-y-0 py-10">
                        {messages.map((m, i) => (
                            <div 
                                key={i} 
                                className={`group py-12 border-b border-slate-50 flex gap-8 items-start animate-in slide-in-from-bottom-4 duration-500 ${m.role === 'assistant' ? 'bg-[#f7f7f8]/50 -mx-6 px-12 rounded-xl' : ''}`}
                            >
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-md grow-0 shrink-0 ${m.role === 'assistant' ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-white'}`}>
                                    <span className="material-symbols-rounded text-xl">
                                        {m.role === 'assistant' ? 'smart_toy' : 'person'}
                                    </span>
                                </div>
                                <div className="flex-1 pt-1">
                                    <div className="text-xs font-black text-slate-400   mb-3 flex items-center gap-3">
                                        {m.role === 'assistant' ? session.scenario.character_name : 'You / Employee'}
                                        {m.role === 'assistant' && <span className="px-2 py-0.5 bg-indigo-50 text-indigo-500 text-[8px] rounded  font-black">AI Persona</span>}
                                    </div>
                                    <div className="text-base font-bold text-slate-700 leading-relaxed whitespace-pre-wrap selection:bg-indigo-100 ">
                                        {m.content}
                                    </div>
                                </div>
                            </div>
                        ))}

                        {sending && (
                            <div className="py-12 flex gap-8 items-start animate-pulse">
                                <div className="w-10 h-10 rounded-xl bg-indigo-600 text-white flex items-center justify-center shadow-md">
                                    <span className="material-symbols-rounded text-xl">smart_toy</span>
                                </div>
                                <div className="flex gap-2 p-4">
                                    <div className="w-1.5 h-1.5 bg-indigo-200 rounded-full animate-bounce"></div>
                                    <div className="w-1.5 h-1.5 bg-indigo-200 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                                    <div className="w-1.5 h-1.5 bg-indigo-200 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                                </div>
                            </div>
                        )}
                        <div className="h-40"></div>
                    </div>
                </div>

                {/* Floating Input Area */}
                <div className="absolute bottom-0 w-full bg-gradient-to-t from-white via-white to-transparent pt-20 pb-10 flex justify-center">
                    <form 
                        onSubmit={handleSend}
                        className="max-w-[800px] w-[90%] bg-white border border-slate-200 rounded-2xl shadow-2xl flex items-end p-2 pr-4 pl-8 group focus-within:border-indigo-500/50 transition-all hover:shadow-indigo-100"
                    >
                        <textarea 
                            rows={1}
                            className="flex-1 py-4 bg-transparent outline-none text-sm font-bold text-slate-700 resize-none max-h-40 placeholder:text-slate-300"
                            placeholder="Shift-click or Type your strategic response..."
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={(e) => {
                                if (e.key === 'Enter' && !e.shiftKey) {
                                    handleSend(e as unknown as React.FormEvent);
                                }
                            }}
                            disabled={sending}
                        />
                        <button 
                            type="submit"
                            disabled={!input.trim() || sending}
                            className={`w-12 h-12 mb-1 rounded-xl flex items-center justify-center transition-all ${!input.trim() || sending ? 'bg-slate-50 text-slate-300' : 'bg-indigo-600 text-white shadow-xl hover:rotate-6 active:scale-90 hover:bg-slate-900 shadow-indigo-100'}`}
                        >
                            <span className="material-symbols-rounded text-2xl font-black">arrow_upward</span>
                        </button>
                    </form>
                </div>
            </main>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";

interface Stats {
    active_jobs: number;
    total_candidates: number;
    total_applications: number;
    interviews_scheduled: number;
    agent_name: string;
    high_value_matches: number;
}

export default function EnterpriseDashboard() {
    const { user, token, role, canAccess, isLoading: isAuthLoading } = useAuth();
    const [greeting, setGreeting] = useState("");
    const [stats, setStats] = useState<Stats>({
        active_jobs: 0,
        total_candidates: 0,
        total_applications: 0,
        interviews_scheduled: 0,
        agent_name: "COMMANDER",
        high_value_matches: 0
    });
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const hour = new Date().getHours();
        if (hour < 12) setGreeting("Good Morning");
        else if (hour < 18) setGreeting("Good Afternoon");
        else setGreeting("Good Evening");

        if (token) {
            fetchStats();
        }
    }, [token]);

    const fetchStats = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/dashboard/stats`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setStats(data);
            }
        } catch (error) {
            console.error("Error fetching stats:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const modules = [
        {
            title: "Manage Jobs",
            description: "Create and track job openings for your team.",
            icon: "business_center",
            path: "/enterprise/jobs",
            badge: "Active",
            color: "purple",
            features: ["AI Job Description", "Job Boards", "Hiring Budget"],
            permission: "jobs:read"
        },
        {
            title: "Candidates",
            description: "View and manage all candidates in your hiring process.",
            icon: "psychology",
            path: "/enterprise/candidates/kanban",
            badge: "AI Screening",
            color: "indigo",
            features: ["Auto-Sync", "Background Check", "Group Actions"],
            permission: "candidates:read"
        },
        {
            title: "360 Feedback",
            description: "Manage performance reviews and multi-rater feedback.",
            icon: "360",
            path: "/enterprise/assessments-360",
            badge: "Performance",
            color: "emerald",
            features: ["Reports", "Reviews", "Comparisons"],
            permission: "assessments:read"
        },
        {
            title: "Surveys",
            description: "Send engagement surveys and culture pulse checks.",
            icon: "poll",
            path: "/enterprise/surveys",
            badge: "Insights",
            color: "rose",
            features: ["Engagement", "Culture", "Analytics"],
            permission: "surveys:read"
        }
    ];

    interface ColorClasses {
        border: string;
        bg: string;
        text: string;
        dot: string;
    }

    const getColorClasses = (color: string): ColorClasses => {
        const colors: Record<string, ColorClasses> = {
            indigo: { border: "border-indigo-100", bg: "bg-indigo-50/30", text: "text-indigo-600", dot: "bg-indigo-400" },
            purple: { border: "border-[#7C3AED]/10", bg: "bg-[#7C3AED]/5", text: "text-[#7C3AED]", dot: "bg-[#7C3AED]" },
            rose: { border: "border-rose-100", bg: "bg-rose-50/30", text: "text-rose-600", dot: "bg-rose-400" },
            emerald: { border: "border-emerald-100", bg: "bg-emerald-50/30", text: "text-emerald-600", dot: "bg-emerald-400" },
        };
        return colors[color] || { border: "border-slate-100", bg: "bg-slate-50", text: "text-slate-600", dot: "bg-slate-400" };
    };

    return (
        <div className="p-4 space-y-4 animate-in fade-in duration-500 overflow-hidden">
            {/* Tactical Command Header */}
            <section className="bg-slate-900 rounded-2xl p-6 md:p-8 text-white flex flex-col lg:flex-row items-center justify-between gap-8 relative overflow-hidden shadow-2xl">
                <div className="relative z-10 flex-1 space-y-6">
                    <div>
                        <div className="inline-flex items-center gap-2.5 px-3 py-1.5 rounded-xl bg-white/5 border border-white/10 text-[9px] font-black   mb-4">
                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></span>
                            Dashboard
                        </div>
                        <h2 className="text-2xl md:text-4xl font-black tracking-tighter leading-none mb-3 ">
                            {greeting}, <span className="text-indigo-400">{isLoading ? 'COMMANDER' : stats.agent_name}</span>.
                        </h2>
                        <p className="text-slate-400 text-[11px] max-w-sm font-bold   leading-relaxed opacity-70">
                            AI found <span className="text-white bg-indigo-500/50 px-1 rounded">{isLoading ? '---' : stats.high_value_matches}</span> recommended candidates for you. Take a look at them now.
                        </p>
                    </div>

                    <div className="flex flex-wrap gap-3">
                        {canAccess("jobs:create") && (
                            <Link href="/enterprise/jobs/create" className="px-6 py-3 bg-white text-slate-900 rounded-xl text-[10px] font-black   hover:bg-indigo-400 hover:text-white transition-all shadow-xl active:scale-95 flex items-center gap-2">
                                <span className="material-symbols-rounded text-lg">add_box</span>
                                Post New Job
                            </Link>
                        )}
                        {canAccess("candidates:read") && (
                            <Link href="/enterprise/candidates/kanban" className="px-6 py-3 bg-white/10 border border-white/10 text-white rounded-xl text-[10px] font-black   hover:bg-white/20 transition-all active:scale-95 flex items-center gap-2">
                                <span className="material-symbols-rounded text-lg">grid_goldenratio</span>
                                Manage Pipeline
                            </Link>
                        )}
                    </div>
                </div>

                {/* Performance HUD Elements */}
                <div className="relative z-10 grid grid-cols-2 gap-4 w-full lg:w-auto">
                    {[
                        { label: "Active Jobs", value: stats.active_jobs, icon: "rocket_launch", color: "text-indigo-400", bg: "bg-indigo-500/10" },
                        { label: "Total Candidates", value: stats.total_candidates, icon: "sensor_occupied", color: "text-emerald-400", bg: "bg-emerald-500/10" },
                        { label: "Total Applications", value: stats.total_applications, icon: "conversion_path", color: "text-rose-400", bg: "bg-rose-500/10" },
                        { label: "Scheduled Interviews", value: stats.interviews_scheduled, icon: "videocam", color: "text-amber-400", bg: "bg-amber-500/10" },
                    ].map((stat) => (
                        <div key={stat.label} className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-4 min-w-[140px] flex flex-col gap-2 group hover:bg-white/10 transition-all border-b-4 border-b-transparent hover:border-b-white/20">
                            <div className="flex items-center justify-between">
                                <span className={`material-symbols-rounded text-xl ${stat.color}`}>{stat.icon}</span>
                                <div className="flex flex-col items-end">
                                    <span className="text-[7px] font-black text-white/30  tracking-[0.2em]">Live Feed</span>
                                    <div className="w-4 h-1 bg-white/10 rounded-full overflow-hidden mt-1">
                                        <div className="h-full bg-emerald-400 w-2/3 animate-[shimmer_2s_infinite]"></div>
                                    </div>
                                </div>
                            </div>
                            <div>
                                <span className="text-[9px] font-black text-white/40   block mb-1">{stat.label}</span>
                                <span className="text-2xl font-black tracking-tighter leading-none">
                                    {isLoading ? '---' : stat.value}
                                </span>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-indigo-600/20 rounded-full blur-[120px] -mr-64 -mt-64"></div>
            </section>

            {/* Tactical Grid Modules */}
            <section className="grid grid-cols-1 lg:grid-cols-12 gap-6 pt-4">
                {/* Core Modules List */}
                <div className="lg:col-span-8 grid grid-cols-1 md:grid-cols-2 gap-5">
                    {modules.filter(m => canAccess(m.permission)).map((module) => (
                        <Link href={module.path} key={module.title} className="group">
                            <div className={`relative ${getColorClasses(module.color).bg} border ${getColorClasses(module.color).border} p-5 rounded-xl shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 h-full overflow-hidden flex flex-col justify-between`}>
                                <div>
                                    <div className="flex justify-between items-start mb-6">
                                        <div className={`w-10 h-10 rounded-xl bg-white border border-slate-50 ${getColorClasses(module.color).text} flex items-center justify-center transition-all group-hover:scale-110 group-hover:rotate-6 shadow-sm`}>
                                            <span className="material-symbols-rounded text-xl">{module.icon}</span>
                                        </div>
                                        <span className={`px-3 py-1.5 rounded-xl text-[8px] font-black   bg-white/50 border border-slate-50 text-slate-400 group-hover:bg-white group-hover:text-[#7C3AED] transition-all`}>
                                            {module.badge}
                                        </span>
                                    </div>

                                    <div className="space-y-2">
                                        <h3 className="text-sm font-black text-slate-900  tracking-tighter group-hover:text-[#7C3AED] transition-colors">
                                            {module.title}
                                        </h3>
                                        <p className="text-[11px] text-slate-500 font-bold leading-relaxed  opacity-70 mb-6">
                                            {module.description}
                                        </p>
                                    </div>
                                </div>

                                <div className="flex flex-wrap gap-1.5 pt-4 border-t border-slate-100/50 mt-4">
                                    {module.features.map((feature, idx) => (
                                        <span key={idx} className="px-2.5 py-1 bg-white border border-slate-50 text-slate-400 rounded-lg text-[8px] font-black  tracking-tight group-hover:border-indigo-100/50 transition-all">
                                            {feature}
                                        </span>
                                    ))}
                                </div>

                                <div className="absolute -bottom-2 -right-2 w-16 h-16 bg-white border border-slate-100/50 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 translate-y-4 group-hover:translate-y-0 transition-all scale-50 group-hover:scale-100">
                                    <span className="material-symbols-rounded text-[#7C3AED]">arrow_forward</span>
                                </div>
                            </div>
                        </Link>
                    ))}
                </div>

                {/* Strategic Side-Ops */}
                <div className="lg:col-span-4 space-y-5">
                    <div className="bg-white border border-slate-100 p-6 rounded-3xl shadow-sm h-full flex flex-col">
                        <div className="flex items-center justify-between mb-6">
                            <span className="text-[10px] font-black text-slate-900  ">Hiring Performance</span>
                            <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse border-4 border-emerald-50"></div>
                        </div>

                        <div className="flex-1 flex flex-col items-center justify-center py-6">
                            <div className="relative w-40 h-40 group">
                                <svg viewBox="0 0 100 100" className="w-full h-full overflow-visible drop-shadow-2xl">
                                    {[0.2, 0.4, 0.6, 0.8, 1].map((step, i) => (
                                        <circle key={i} cx="50" cy="50" r={50 * step} className="fill-none stroke-slate-50 stroke-[0.5]" />
                                    ))}
                                    <line x1="50" y1="50" x2="50" y2="0" className="stroke-slate-50 stroke-[0.5]" />
                                    <line x1="50" y1="50" x2="100" y2="50" className="stroke-slate-50 stroke-[0.5]" />
                                    <line x1="50" y1="50" x2="50" y2="100" className="stroke-slate-50 stroke-[0.5]" />
                                    <line x1="50" y1="50" x2="0" y2="50" className="stroke-slate-50 stroke-[0.5]" />

                                    <polygon
                                        points="50,15 85,40 60,80 20,50"
                                        className="fill-[#7C3AED]/10 stroke-[#7C3AED] stroke-[3] transition-all duration-1000 group-hover:fill-[#7C3AED]/20"
                                    />
                                    <circle cx="50" cy="15" r="2" className="fill-[#7C3AED]" />
                                    <circle cx="85" cy="40" r="2" className="fill-indigo-400" />
                                    <circle cx="60" cy="80" r="2" className="fill-emerald-400" />
                                    <circle cx="20" cy="50" r="2" className="fill-rose-400" />
                                </svg>

                                <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-6 text-[8px] font-black text-slate-400  ">Velocity</div>
                                <div className="absolute top-1/2 right-0 translate-x-10 -translate-y-1/2 text-[8px] font-black text-slate-400  ">Accuracy</div>
                                <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-6 text-[8px] font-black text-slate-400  ">Volume</div>
                                <div className="absolute top-1/2 left-0 -translate-x-10 -translate-y-1/2 text-[8px] font-black text-slate-400  ">Precision</div>
                            </div>
                        </div>

                        <div className="mt-6">
                            <div className="p-5 rounded-xl bg-slate-50 border border-slate-100 relative group overflow-hidden">
                                <div className="absolute top-0 left-0 w-1 h-full bg-[#7C3AED]"></div>
                                <p className="text-[10px] font-bold text-slate-500 leading-relaxed  tracking-tight">
                                    AI Suggestion: Hiring speed is <span className="text-[#7C3AED]">14% faster</span> than last month.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { apiClient, BACKEND_URL } from "@/utils/api";
import ConfirmationModal from "@/components/common/ConfirmationModal";

interface Department {
    id: string;
    name: string;
}

interface Employee {
    id: string;
    employee_id: string;
    first_name: string;
    last_name: string;
    email: string;
    designation: string;
    status: string;
    hire_date: string;
    department?: Department;
}

export default function EmployeesPage() {
    const { token, canAccess } = useAuth();
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [statusFilter, setStatusFilter] = useState("all");
    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
    const [employeeToDelete, setEmployeeToDelete] = useState<string | null>(null);

    useEffect(() => {
        if (token) {
            fetchEmployees();
        }
    }, [token]);

    const fetchEmployees = async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get("/api/v1/enterprise/employees/");
            if (res.ok) {
                const data = await res.json();
                setEmployees(data);
            }
        } catch (error) {
            console.error("Error fetching employees:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async () => {
        if (!employeeToDelete) return;
        try {
            const res = await apiClient.delete(`/api/v1/enterprise/employees/${employeeToDelete}`);
            if (res.ok) fetchEmployees();
            else alert("Failed to delete employee");
        } catch (e) {
            console.error(e);
        } finally {
            setIsConfirmModalOpen(false);
            setEmployeeToDelete(null);
        }
    };

    const filteredEmployees = employees.filter(emp => {
        const matchesSearch = (emp.first_name + " " + emp.last_name).toLowerCase().includes(searchQuery.toLowerCase()) ||
                             emp.employee_id.toLowerCase().includes(searchQuery.toLowerCase()) ||
                             emp.email.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesStatus = statusFilter === "all" || emp.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    return (
        <div className="p-6 space-y-8 animate-in fade-in duration-500 bg-[#F8FAFC] min-h-screen">
            {/* Header */}
            <div>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                    <div className="flex items-start gap-4">
                        <div className="w-12 h-12 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center shrink-0 shadow-sm shadow-[#7C3AED]/5">
                            <span className="material-symbols-rounded text-[#7C3AED] text-2xl">badge</span>
                        </div>
                        <div>
                            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">Employee Directory</h1>
                            <p className="text-slate-500 text-[13px] font-medium mt-1">
                                Manage your workforce, departments, and employee records in one place.
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-3">
                        {canAccess("employees:create") && (
                            <Link
                                href="/enterprise/employees/add"
                                className="flex items-center gap-2 px-5 h-11 bg-[#7C3AED] text-white rounded-lg text-xs font-black hover:bg-[#6d28d9] transition-all shadow-lg shadow-[#7C3AED]/20 active:scale-95"
                            >
                                <span className="material-symbols-rounded text-lg">add</span>
                                ADD EMPLOYEE
                            </Link>
                        )}
                    </div>
                </div>

                {/* Stats Section */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    {[
                        { label: "Total Employees", value: employees.length, icon: "groups", color: "indigo" },
                        { label: "Active Workforce", value: employees.filter(e => e.status === 'Active').length, icon: "verified", color: "emerald" },
                        { label: "Departments", value: new Set(employees.filter(e => e.department).map(e => e.department?.id)).size, icon: "domain", color: "amber" },
                        { label: "New Hires", value: employees.filter(e => e.hire_date && new Date(e.hire_date) > new Date(new Date().getFullYear(), new Date().getMonth(), 1)).length, icon: "person_add", color: "purple" }
                    ].map((stat, i) => (
                        <div key={i} className="group bg-white p-5 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-[#7C3AED]/20 transition-all duration-300">
                            <div className="flex items-start justify-between mb-4">
                                <div className={`w-10 h-10 rounded-lg flex items-center justify-center transition-transform group-hover:scale-110 ${
                                    stat.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
                                    stat.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
                                    stat.color === 'amber' ? 'bg-amber-50 text-amber-600' :
                                    'bg-purple-50 text-purple-600'
                                }`}>
                                    <span className="material-symbols-rounded text-xl">{stat.icon}</span>
                                </div>
                                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Live</span>
                            </div>
                            <p className="text-2xl font-black text-slate-900 mb-0.5 tracking-tight">{stat.value}</p>
                            <p className="text-[11px] font-bold text-slate-400 capitalize">{stat.label}</p>
                        </div>
                    ))}
                </div>
            </div>

            {/* Interaction Bar */}
            <div className="flex flex-col md:flex-row items-center gap-4">
                <div className="flex-1 relative w-full group">
                    <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg transition-colors group-focus-within:text-[#7C3AED]">search</span>
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search by name, ID, or email..."
                        className="w-full h-12 bg-white border border-slate-200 rounded-xl pl-12 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none shadow-sm"
                    />
                </div>

                <div className="flex items-center gap-2 bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm min-w-[200px]">
                    <span className="material-symbols-rounded text-slate-400 ml-2 text-lg">filter_list</span>
                    <select
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        className="w-full bg-transparent border-none text-[11px] font-black text-slate-700 focus:outline-none focus:ring-0 cursor-pointer uppercase tracking-wider"
                    >
                        <option value="all">All Workforce</option>
                        <option value="Active">Active Only</option>
                        <option value="Inactive">Inactive</option>
                    </select>
                </div>
            </div>

            {/* Content Table */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col min-h-[calc(100vh-12rem)] overflow-hidden">
                {isLoading ? (
                    <div className="p-6 space-y-4 flex-1">
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                            <div key={i} className="bg-slate-50 h-16 rounded-xl animate-pulse"></div>
                        ))}
                    </div>
                ) : filteredEmployees.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-20 text-center">
                        <div className="w-16 h-16 bg-slate-50 rounded-xl flex items-center justify-center mx-auto mb-4 border border-slate-100">
                            <span className="material-symbols-rounded text-3xl text-slate-300">badge</span>
                        </div>
                        <h3 className="text-sm font-bold text-slate-900 mb-1">No Employees Found</h3>
                        <p className="text-xs text-slate-500 mb-6 max-w-xs mx-auto">
                            Add your first employee or convert an onboarded candidate.
                        </p>
                        <Link href="/enterprise/onboarding" className="px-4 py-2 bg-indigo-50 text-[#7C3AED] font-bold text-xs rounded-xl hover:bg-slate-200 transition-all">Go to Onboarding Hub</Link>
                    </div>
                ) : (
                    <div className="overflow-x-auto overflow-y-auto max-h-[calc(100vh-16rem)]">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-50 border-b border-slate-100 sticky top-0 z-10">
                                    <th className="px-3 py-1.5 text-[10px] font-bold text-slate-500  ">Employee</th>
                                    <th className="px-3 py-1.5 text-[10px] font-bold text-slate-500  ">Designation</th>
                                    <th className="px-3 py-1.5 text-[10px] font-bold text-slate-500  ">Department</th>
                                    <th className="px-3 py-1.5 text-[10px] font-bold text-slate-500  ">Hire Date</th>
                                    <th className="px-3 py-1.5 text-[10px] font-bold text-slate-500  ">Status</th>
                                    <th className="px-3 py-1.5 text-[10px] font-bold text-slate-500   text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filteredEmployees.map((emp) => (
                                    <tr key={emp.id} className="hover:bg-slate-50/50 transition-all group">
                                        <td className="px-3 py-1.5">
                                            <div className="flex flex-col">
                                                <span className="text-xs font-bold text-slate-800 leading-tight">{emp.first_name} {emp.last_name}</span>
                                                <span className="text-[9px] font-semibold text-slate-500">{emp.employee_id} • {emp.email}</span>
                                            </div>
                                        </td>
                                        <td className="px-3 py-1.5">
                                            <span className="text-xs font-semibold text-slate-600">{emp.designation || "N/A"}</span>
                                        </td>
                                        <td className="px-3 py-1.5">
                                            <span className="text-xs font-semibold text-slate-600">{emp.department?.name || "N/A"}</span>
                                        </td>
                                        <td className="px-3 py-1.5">
                                            <span className="text-xs font-semibold text-slate-600">{emp.hire_date ? new Date(emp.hire_date).toLocaleDateString() : "N/A"}</span>
                                        </td>
                                        <td className="px-3 py-1.5">
                                            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold border  tracking-wide ${
                                                emp.status === 'Active' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-100 text-slate-500 border-slate-200'
                                            }`}>
                                                <span className={`w-1 h-1 rounded-full ${emp.status === 'Active' ? 'bg-emerald-500' : 'bg-slate-400'}`}></span>
                                                {emp.status}
                                            </span>
                                        </td>
                                        <td className="px-3 py-1.5 text-right">
                                            <div className="flex items-center justify-end gap-1">
                                                {canAccess("employees:update") && (
                                                    <Link
                                                        href={`/enterprise/employees/${emp.id}`}
                                                        className="w-8 h-8 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-[#7C3AED]/5 border border-transparent hover:border-[#7C3AED]/10 flex items-center justify-center transition-all"
                                                        title="Edit Employee"
                                                    >
                                                        <span className="material-symbols-rounded text-lg">edit</span>
                                                    </Link>
                                                )}
                                                {canAccess("employees:delete") && (
                                                    <button
                                                        onClick={() => {
                                                            setEmployeeToDelete(emp.id);
                                                            setIsConfirmModalOpen(true);
                                                        }}
                                                        className="w-8 h-8 rounded-xl text-slate-400 hover:text-rose-500 hover:bg-rose-50 border border-transparent hover:border-rose-100 flex items-center justify-center transition-all"
                                                        title="Delete Employee"
                                                    >
                                                        <span className="material-symbols-rounded text-lg">delete</span>
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <ConfirmationModal
                isOpen={isConfirmModalOpen}
                onClose={() => setIsConfirmModalOpen(false)}
                onConfirm={handleDelete}
                title="Delete Employee?"
                message="Are you sure you want to delete this employee? This action is permanent and all associated records will be removed."
                confirmLabel="Yes, Delete"
                cancelLabel="No"
                isDestructive={true}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { useRouter, useParams } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import JobEditor from "@/components/enterprise/JobEditor";
import { 
    ArrowLeft, 
    ArrowRight, 
    CircleCheck, 
    Building2, 
    MapPin, 
    Rocket, 
    Sparkles, 
    RefreshCcw, 
    CirclePlus, 
    Network, 
    ClipboardList, 
    Settings,
    X,
    LayoutDashboard,
    Eye,
    Users,
    Brain,
    Calculator,
    ShieldCheck,
    ChevronUp,
    ChevronDown,
    ListPlus,
    Pin,
    FileText,
    AtSign,
    Mail,
    Search
} from "lucide-react";

interface ApplicationField {
    id: string;
    label: string;
    type: 'text' | 'number' | 'boolean' | 'file' | 'email';
    icon: string;
    is_required: boolean;
}

interface WorkflowStage {
    id: string;
    name: string;
    type: string;
    icon: string;
    email_template_id?: string;
}

const DEFAULT_APPLICATION_FIELDS: ApplicationField[] = [
    { id: '1', label: 'Full Name', type: 'text', icon: 'person', is_required: true },
    { id: '2', label: 'Email Address', type: 'email', icon: 'mail', is_required: true },
    { id: '3', label: 'Phone Number', type: 'text', icon: 'call', is_required: false },
    { id: '4', label: 'Resume / CV', type: 'file', icon: 'description', is_required: true },
    { id: '5', label: 'Portfolio URL', type: 'text', icon: 'link', is_required: false }
];

const DEFAULT_WORKFLOW_STAGES: WorkflowStage[] = [
    { id: '1', name: 'Initial Screening', type: 'Screening', icon: 'search' }
];

export default function EditJobPage() {
    const { token } = useAuth();
    const router = useRouter();
    const params = useParams();
    const jobId = params.id as string;

    const [isLoading, setIsLoading] = useState(true);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isGeneratingAI, setIsGeneratingAI] = useState(false);
    const [showSuccessModal, setShowSuccessModal] = useState(false);
    const [currentStep, setCurrentStep] = useState(1);

    const [formData, setFormData] = useState({
        title: "",
        job_type: "Full Time",
        work_mode: "On-Site",
        location: "",
        department: "Human Resources",
        salary_currency: "INR",
        salary_frequency: "Yearly",
        salary_min: "",
        salary_max: "",
        experience_min: "0",
        experience_max: "5",
        description: "",
        required_skills: "",
        auto_fit_analysis: false,
        status_id: 2,
        company_id: "",
        application_fields: DEFAULT_APPLICATION_FIELDS,
        workflow_stages: DEFAULT_WORKFLOW_STAGES,
    });

    interface Company {
        id: string;
        name: string;
    }

    interface EmailTemplate {
        id: string;
        name: string;
    }

    const [companies, setCompanies] = useState<Company[]>([]);
    const [emailTemplates, setEmailTemplates] = useState<EmailTemplate[]>([]);

    const steps = [
        { id: 1, name: "Job Details", icon: "ClipboardList" },
        { id: 2, name: "Application", icon: "Settings" },
        { id: 3, name: "Workflow", icon: "Network" }
    ];

    useEffect(() => {
        if (token && jobId) {
            fetchJobDetails();
            fetchCompanies();
            fetchEmailTemplates();
        }
    }, [token, jobId]);

    const fetchEmailTemplates = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setEmailTemplates(data);
            }
        } catch (e) {
            console.error(e);
        }
    };

    const fetchCompanies = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/company/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setCompanies(data);
            }
        } catch (error) {
            console.error(error);
        }
    };

    const fetchJobDetails = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/${jobId}`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setFormData({
                    title: data.title || "",
                    job_type: data.job_type || "Full Time",
                    work_mode: data.work_mode || "On-Site",
                    location: data.location || "",
                    department: data.department || "Human Resources",
                    salary_currency: data.salary_currency || "INR",
                    salary_frequency: data.salary_frequency || "Yearly",
                    salary_min: data.salary_min?.toString() || "",
                    salary_max: data.salary_max?.toString() || "",
                    experience_min: data.experience_min?.toString() || "0",
                    experience_max: data.experience_max?.toString() || "5",
                    description: data.description || "",
                    required_skills: data.required_skills?.join(", ") || "",
                    auto_fit_analysis: data.auto_fit_analysis || false,
                    status_id: data.status_id || 2,
                    company_id: data.company_id || "",
                    application_fields: (data.application_fields && data.application_fields.length > 0) ? data.application_fields : DEFAULT_APPLICATION_FIELDS,
                    workflow_stages: (data.workflow_stages && data.workflow_stages.length > 0) ? data.workflow_stages : DEFAULT_WORKFLOW_STAGES
                });
            }
        } catch (error) {
            console.error("Error fetching job:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSubmit = async () => {
        setIsSubmitting(true);
        try {
            const payload = {
                title: formData.title,
                job_type: formData.job_type,
                work_mode: formData.work_mode,
                location: formData.location,
                department: formData.department,
                salary_currency: formData.salary_currency,
                salary_frequency: formData.salary_frequency,
                salary_min: formData.salary_min ? parseFloat(formData.salary_min) : null,
                salary_max: formData.salary_max ? parseFloat(formData.salary_max) : null,
                experience_min: formData.experience_min ? parseInt(formData.experience_min) : 0,
                experience_max: formData.experience_max ? parseInt(formData.experience_max) : 5,
                description: formData.description,
                required_skills: formData.required_skills.split(",").map(s => s.trim()).filter(s => s),
                auto_fit_analysis: formData.auto_fit_analysis,
                status_id: formData.status_id,
                company_id: formData.company_id,
                application_fields: formData.application_fields,
                workflow_stages: formData.workflow_stages
            };

            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/${jobId}`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify(payload),
            });

            if (res.ok) {
                setShowSuccessModal(true);
            } else {
                const error = await res.json();
                alert(error.detail || "Failed to update job");
            }
        } catch (error) {
            alert("Network error. Please try again.");
        } finally {
            setIsSubmitting(false);
        }
    };
    const generateAIDescription = async () => {
        if (!formData.title) {
            alert("Please enter a job title first");
            return;
        }

        setIsGeneratingAI(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/generate-jd`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({
                    title: formData.title,
                    existing_description: formData.description,
                    location: formData.location,
                    experience_min: formData.experience_min,
                    experience_max: formData.experience_max
                }),
            });

            if (res.ok) {
                const data = await res.json();
                setFormData({
                    ...formData,
                    description: data.description,
                    salary_min: data.salary_min?.toString() || formData.salary_min,
                    salary_max: data.salary_max?.toString() || formData.salary_max,
                    required_skills: data.skills?.join(", ") || formData.required_skills
                });
            } else {
                alert("AI generation failed. Please try again.");
            }
        } catch (error) {
            console.error("Error generating JD:", error);
            alert("Network error during AI generation.");
        } finally {
            setIsGeneratingAI(false);
        }
    };

    const isExperienceInvalid = parseInt(formData.experience_max) < parseInt(formData.experience_min);
    const isSalaryInvalid = formData.salary_min && formData.salary_max && parseFloat(formData.salary_max) < parseFloat(formData.salary_min);

    const STAGE_TYPES = [
        { name: 'Screening', icon: 'Search' },
        { name: 'Aptitude', icon: 'Brain' },
        { name: 'Coding', icon: 'Code' },
        { name: 'Technical Interview', icon: 'Zap' },
        { name: 'HR Interview', icon: 'Users' },
        { name: 'Final Selection', icon: 'ShieldCheck' }
    ];

    const canGoNext = () => currentStep === 1 ? (formData.title && !isExperienceInvalid && !isSalaryInvalid) : true;




    if (isLoading) {
        return (
            <div className="h-screen w-full flex items-center justify-center bg-[#FDFDFF]">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-12 h-12 border-4 border-indigo-600/20 border-t-indigo-600 rounded-full animate-spin"></div>
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">Loading Details...</span>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full min-h-screen bg-[#FDFDFF] flex flex-col p-4 animate-in fade-in duration-700 overflow-hidden relative">
            {/* Ultra-Compact Header */}
            <div className="flex items-center justify-between mb-6 px-1 shrink-0">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.back()} className="w-10 h-10 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-rose-500 transition-all shadow-sm active:scale-95">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none  ">Edit Job</h1>
                        <p className="text-[9px] text-slate-400 font-bold  tracking-[0.2em] mt-1.5 opacity-60">Job Details</p>
                    </div>
                </div>

                <div className="hidden lg:flex items-center bg-slate-100/40 p-1 rounded-xl border border-slate-200/50 backdrop-blur-sm">
                    {steps.map((step) => (
                        <button
                            key={step.id}
                            disabled={step.id > currentStep && !canGoNext()}
                            onClick={() => canGoNext() && setCurrentStep(step.id)}
                            className={`flex items-center gap-2 px-4 py-1.5 rounded-xl transition-all ${currentStep === step.id ? "bg-white text-indigo-600 shadow-sm border border-slate-100" : "text-slate-600 hover:text-slate-800"}`}
                        >
                            <span className={`text-[8px] font-black w-4 h-4 flex items-center justify-center rounded-xl border ${currentStep === step.id ? "border-indigo-200 bg-indigo-50 text-indigo-600" : "border-slate-300 bg-slate-200 text-slate-600"}`}>{step.id}</span>
                            <span className="text-[9px] font-black  ">{step.name}</span>
                        </button>
                    ))}
                </div>

                <button
                    disabled={!canGoNext()}
                    className="h-11 px-6 rounded-xl bg-indigo-600 text-white text-[10px] font-black   shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2 group disabled:opacity-40"
                    onClick={() => currentStep < 3 ? setCurrentStep(currentStep + 1) : handleSubmit()}
                >
                    {isSubmitting ? "Saving..." : currentStep === 3 ? "Save Changes" : "Next Step"}
                    <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </button>
            </div>

            <div className="flex-1 bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden flex flex-col relative">
                <AnimatePresence mode="wait">
                    {currentStep === 1 && (
                        <motion.div key="step1" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="flex-1 bg-slate-50/50 overflow-y-auto p-4 md:p-8 no-scrollbar relative">
                            <div className="mx-auto max-w-[1400px] grid grid-cols-1 lg:grid-cols-12 gap-6 w-full">
                                {/* Left Form Column */}
                                <div className="lg:col-span-4 space-y-6 flex flex-col">
                                    {/* Core Details Card */}
                                    <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-6 space-y-5 relative overflow-hidden group">
                                        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-bl-full -z-10 transition-transform group-hover:scale-110"></div>
                                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                                            <div className="w-10 h-10 rounded-xl bg-indigo-50 text-indigo-600 flex items-center justify-center">
                                                <ClipboardList className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Job Profile</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Core listing details</p>
                                            </div>
                                        </div>
                                        
                                        <div className="space-y-4 pt-1">
                                            <div className="space-y-1.5 relative">
                                                <label className="text-[11px] font-bold text-slate-500 ml-1">Job Title <span className="text-rose-500">*</span></label>
                                                <input type="text" placeholder="e.g. Senior Frontend Engineer" className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} />
                                            </div>

                                            {companies.length > 0 && (
                                                <div className="space-y-1.5 relative">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Company</label>
                                                    <select className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-800 font-semibold text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none cursor-pointer" value={formData.company_id} onChange={e => setFormData({ ...formData, company_id: e.target.value })}>
                                                        {companies.map(c => (<option key={c.id} value={c.id}>{c.name}</option>))}
                                                    </select>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    {/* Work Mode Card */}
                                    <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-6 space-y-5 relative overflow-hidden group">
                                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                                            <div className="w-10 h-10 rounded-xl bg-teal-50 text-teal-600 flex items-center justify-center">
                                                <MapPin className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Work Arrangement</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Work mode & location</p>
                                            </div>
                                        </div>
                                        
                                        <div className="space-y-4 pt-1">
                                            <div className="grid grid-cols-2 gap-4">
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Type</label>
                                                    <select className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-800 font-semibold text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none cursor-pointer" value={formData.job_type} onChange={e => setFormData({ ...formData, job_type: e.target.value })}>
                                                        <option>Full Time</option><option>Part Time</option><option>Contract</option>
                                                    </select>
                                                </div>
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Mode</label>
                                                    <select className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-800 font-semibold text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none cursor-pointer" value={formData.work_mode} onChange={e => setFormData({ ...formData, work_mode: e.target.value })}>
                                                        <option>On-Site</option><option>Remote</option><option>Hybrid</option>
                                                    </select>
                                                </div>
                                            </div>
                                            <div className="space-y-1.5 relative">
                                                <label className="text-[11px] font-bold text-slate-500 ml-1">Location</label>
                                                <input type="text" placeholder="e.g. San Francisco, CA" className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300" value={formData.location} onChange={e => setFormData({ ...formData, location: e.target.value })} />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Requirements Card */}
                                    <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-6 space-y-5 relative overflow-hidden group">
                                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                                            <div className="w-10 h-10 rounded-xl bg-orange-50 text-orange-600 flex items-center justify-center">
                                                <Calculator className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Requirements</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Experience & compensation</p>
                                            </div>
                                        </div>
                                        
                                        <div className="space-y-4 pt-1">
                                            <div className="grid grid-cols-2 gap-4">
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Min Exp (Yrs)</label>
                                                    <input type="number" min="0" className={`w-full px-4 py-3 rounded-xl border ${isExperienceInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none`} value={formData.experience_min} onChange={e => setFormData({ ...formData, experience_min: e.target.value })} />
                                                </div>
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Max Exp (Yrs)</label>
                                                    <input type="number" min="0" className={`w-full px-4 py-3 rounded-xl border ${isExperienceInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none`} value={formData.experience_max} onChange={e => setFormData({ ...formData, experience_max: e.target.value })} />
                                                </div>
                                            </div>
                                            <div className="grid grid-cols-2 gap-4">
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Min Salary (LPA)</label>
                                                    <input type="number" min="0" placeholder="5" className={`w-full px-4 py-3 rounded-xl border ${isSalaryInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300`} value={formData.salary_min} onChange={e => setFormData({ ...formData, salary_min: e.target.value })} />
                                                </div>
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Max Salary (LPA)</label>
                                                    <input type="number" min="0" placeholder="15" className={`w-full px-4 py-3 rounded-xl border ${isSalaryInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300`} value={formData.salary_max} onChange={e => setFormData({ ...formData, salary_max: e.target.value })} />
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Right Description Area */}
                                <div className="lg:col-span-8 flex flex-col min-h-[600px] bg-white rounded-2xl border border-slate-200/80 shadow-sm overflow-hidden">
                                    <div className="px-6 py-5 border-b border-slate-100 flex justify-between items-center bg-white z-10 shrink-0">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-xl bg-purple-50 text-purple-600 flex items-center justify-center">
                                                <FileText className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Job Description & Skills</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Outline the responsibilities and tech stack</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-3">
                                            <select
                                                value={formData.status_id}
                                                onChange={(e) => setFormData({ ...formData, status_id: parseInt(e.target.value) })}
                                                className={`px-4 py-2.5 rounded-xl border text-[10px] font-black outline-none cursor-pointer transition-all appearance-none text-center shadow-sm hover:shadow-md ${formData.status_id === 2
                                                        ? "bg-emerald-50 text-emerald-600 border-emerald-100"
                                                        : formData.status_id === 3
                                                            ? "bg-rose-50 text-rose-500 border-rose-100"
                                                            : "bg-slate-50 text-slate-500 border-slate-100"
                                                    }`}
                                            >
                                                <option value={1}>DRAFT</option>
                                                <option value={2}>ACTIVE</option>
                                                <option value={3}>CLOSED</option>
                                            </select>
                                            <button onClick={generateAIDescription} disabled={isGeneratingAI} className="px-4 py-2 rounded-xl bg-gradient-to-r from-indigo-600 to-purple-600 text-white text-[11px] font-bold shadow-md shadow-indigo-200 hover:shadow-lg hover:-translate-y-0.5 active:translate-y-0 transition-all flex items-center gap-2 disabled:opacity-70 disabled:hover:translate-y-0 disabled:shadow-none">
                                                {isGeneratingAI ? <RefreshCcw className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                                                {isGeneratingAI ? 'Generating...' : 'Auto Draft with AI'}
                                            </button>
                                        </div>
                                    </div>

                                    <div className="flex-1 flex flex-col border-b border-slate-200 overflow-y-auto">
                                        <JobEditor content={formData.description} onChange={(content) => setFormData({ ...formData, description: content })} placeholder="Detail the role, responsibilities, and ideal candidate profile here..." />
                                    </div>

                                    <div className="p-6 bg-slate-50 shrink-0">
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 ml-1">Required Tech Stack <span className="font-medium opacity-60">(Comma Separated)</span></label>
                                            <div className="relative">
                                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                                                    <AtSign className="w-4 h-4" />
                                                </div>
                                                <input type="text" className="w-full pl-11 pr-5 py-3 rounded-xl border border-slate-200/80 outline-none font-semibold text-slate-800 text-sm bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-sm placeholder:text-slate-300" placeholder="e.g. React, Node.js, Python, AWS" value={formData.required_skills} onChange={e => setFormData({ ...formData, required_skills: e.target.value })} />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {currentStep === 2 && (
                        <motion.div key="step2" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="flex-1 grid grid-cols-12 overflow-hidden h-full">
                            <div className="col-span-4 border-r border-slate-100 p-8 bg-slate-50/30 overflow-y-auto no-scrollbar flex flex-col gap-6">
                                {/* Header */}
                                <div>
                                    <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-2">Application Form</h1>
                                    <p className="text-[11px] text-slate-400 font-medium leading-relaxed">Design the form candidates will fill out when applying for this role.</p>
                                </div>

                                {/* Add Question Button */}
                                <button onClick={() => {
                                    const newField: ApplicationField = { id: Date.now().toString(), label: 'New Question', type: 'text', icon: 'Type', is_required: false };
                                    setFormData(prev => ({ ...prev, application_fields: [...prev.application_fields, newField] }));
                                }} className="w-full py-3.5 rounded-xl bg-indigo-600 text-white text-[11px] font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95">
                                    <CirclePlus className="w-4 h-4" />
                                    Add Question
                                </button>

                                {/* Form Stats */}
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="bg-white rounded-xl border border-slate-200 p-4 text-center shadow-sm">
                                        <div className="text-2xl font-black text-indigo-600">{formData.application_fields.length}</div>
                                        <div className="text-[10px] font-bold text-slate-400 mt-0.5 uppercase tracking-wide">Total Fields</div>
                                    </div>
                                    <div className="bg-white rounded-xl border border-slate-200 p-4 text-center shadow-sm">
                                        <div className="text-2xl font-black text-emerald-600">{formData.application_fields.filter(f => f.is_required).length}</div>
                                        <div className="text-[10px] font-bold text-slate-400 mt-0.5 uppercase tracking-wide">Required</div>
                                    </div>
                                </div>

                                {/* Field Types Guide */}
                                <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4 space-y-3">
                                    <p className="text-[11px] font-bold text-slate-600 uppercase tracking-wider">Field Types</p>
                                    {[
                                        { type: 'Text', color: 'bg-blue-50 text-blue-600', desc: 'Short or long text answers' },
                                        { type: 'Email', color: 'bg-purple-50 text-purple-600', desc: 'Validated email address' },
                                        { type: 'Number', color: 'bg-orange-50 text-orange-600', desc: 'Numeric value input' },
                                        { type: 'File', color: 'bg-teal-50 text-teal-600', desc: 'Document or resume upload' },
                                        { type: 'Boolean', color: 'bg-rose-50 text-rose-600', desc: 'Yes / No toggle' },
                                    ].map(item => (
                                        <div key={item.type} className="flex items-center gap-3">
                                            <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${item.color} shrink-0 w-14 text-center`}>{item.type}</span>
                                            <span className="text-[11px] text-slate-400 font-medium">{item.desc}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            <div className="col-span-8 p-8 overflow-y-auto no-scrollbar">
                                <div className="flex flex-col gap-3 max-w-3xl mx-auto pb-10">
                                    {formData.application_fields.map((field) => (
                                        <div key={field.id} className="p-3.5 bg-white rounded-xl border border-slate-100 shadow-sm flex items-center justify-between group hover:border-indigo-500/30 transition-all">
                                            <div className="flex items-center gap-4 flex-1">
                                                <div className="w-9 h-9 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 group-hover:text-indigo-600 group-hover:bg-indigo-50 transition-all shadow-inner"><Pin className="w-4 h-4" /></div>
                                                <div className="flex-1 grid grid-cols-2 gap-4 items-center">
                                                    <input type="text" className="bg-transparent border-none outline-none text-[13px] font-black text-slate-800 p-0 focus:text-indigo-600 transition-colors  " value={field.label} onChange={(e) => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.map(f => f.id === field.id ? { ...f, label: e.target.value } : f) }))} />
                                                    <select className="bg-slate-50 border-none outline-none text-[9px] font-black text-slate-400  px-3 py-1.5 rounded-xl cursor-pointer hover:bg-slate-100 transition-all w-32" value={field.type} onChange={(e) => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.map(f => f.id === field.id ? { ...f, type: e.target.value as ApplicationField['type'] } : f) }))}>
                                                        <option value="text">Text</option><option value="email">Email</option><option value="number">Number</option><option value="boolean">Boolean</option><option value="file">File</option>
                                                    </select>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-4 ml-6">
                                                <button onClick={() => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.map(f => f.id === field.id ? { ...f, is_required: !f.is_required } : f) }))} className={`px-2.5 py-1 rounded-xl text-[8px] font-black   border transition-all ${field.is_required ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-slate-50 text-slate-300 border-slate-100'}`}>{field.is_required ? 'Required' : 'Optional'}</button>
                                                <button onClick={() => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.filter(f => f.id !== field.id) }))} className="w-8 h-8 rounded-xl hover:bg-rose-50 text-slate-200 hover:text-rose-500 transition-all flex items-center justify-center active:scale-90"><X className="w-4 h-4" /></button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {currentStep === 3 && (
                        <motion.div key="step3" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="flex-1 grid grid-cols-12 overflow-hidden h-full">
                            <div className="col-span-4 border-r border-slate-100 p-8 bg-slate-50/30 overflow-y-auto no-scrollbar flex flex-col gap-6">
                                {/* Header */}
                                <div>
                                    <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-2">Hiring Process</h1>
                                    <p className="text-[11px] text-slate-400 font-medium leading-relaxed">Define the stages candidates go through from application to final selection.</p>
                                </div>

                                {/* Add Stage Button */}
                                <button onClick={() => {
                                    const maxId = Math.max(0, ...formData.workflow_stages.map(s => parseInt(s.id) || 0));
                                    const newStage: WorkflowStage = { id: (maxId + 1).toString(), name: `Stage ${maxId + 1}`, type: 'Technical Interview', icon: 'Zap' };
                                    setFormData(prev => ({ ...prev, workflow_stages: [...prev.workflow_stages, newStage] }));
                                }} className="w-full py-3.5 rounded-xl bg-indigo-600 text-white text-[11px] font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95">
                                    <ListPlus className="w-4 h-4" />
                                    Add Stage
                                </button>

                                {/* Stage Stats */}
                                <div className="bg-white rounded-xl border border-slate-200 p-4 text-center shadow-sm">
                                    <div className="text-2xl font-black text-indigo-600">{formData.workflow_stages.length}</div>
                                    <div className="text-[10px] font-bold text-slate-400 mt-0.5 uppercase tracking-wide">Total Stages</div>
                                </div>

                                {/* Stage Types Guide */}
                                <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4 space-y-3">
                                    <p className="text-[11px] font-bold text-slate-600 uppercase tracking-wider">Stage Types</p>
                                    {[
                                        { type: 'Screening', color: 'bg-blue-50 text-blue-600', desc: 'Initial candidate filtering' },
                                        { type: 'Aptitude', color: 'bg-purple-50 text-purple-600', desc: 'Cognitive & reasoning tests' },
                                        { type: 'Coding', color: 'bg-orange-50 text-orange-600', desc: 'Technical coding assessment' },
                                        { type: 'Tech Interview', color: 'bg-teal-50 text-teal-600', desc: 'Deep technical evaluation' },
                                        { type: 'HR Interview', color: 'bg-rose-50 text-rose-600', desc: 'Culture & fit discussion' },
                                        { type: 'Final Selection', color: 'bg-emerald-50 text-emerald-600', desc: 'Final hiring decision' },
                                    ].map(item => (
                                        <div key={item.type} className="flex items-center gap-3">
                                            <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${item.color} shrink-0 w-20 text-center`}>{item.type}</span>
                                            <span className="text-[11px] text-slate-400 font-medium">{item.desc}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            <div className="col-span-8 p-8 overflow-y-auto no-scrollbar flex flex-col items-center">
                                <div className="w-full max-w-lg space-y-3 pb-10">
                                    {formData.workflow_stages.map((node, idx) => (
                                        <div key={node.id} className="group relative flex items-center gap-4 bg-white p-3.5 rounded-xl border border-slate-100 shadow-sm border-l-4 border-l-indigo-600 hover:shadow-lg transition-all">
                                            <div className="flex flex-col gap-1 items-center opacity-0 group-hover:opacity-100 transition-opacity absolute -left-8">
                                                <button disabled={idx === 0} onClick={() => {
                                                    const newStages = [...formData.workflow_stages];
                                                    [newStages[idx], newStages[idx - 1]] = [newStages[idx - 1], newStages[idx]];
                                                    setFormData(prev => ({ ...prev, workflow_stages: newStages }));
                                                }} className="w-6 h-6 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-300 hover:text-indigo-600 disabled:opacity-10 transition-all"><ChevronUp className="w-4 h-4" /></button>
                                                <button disabled={idx === formData.workflow_stages.length - 1} onClick={() => {
                                                    const newStages = [...formData.workflow_stages];
                                                    [newStages[idx], newStages[idx + 1]] = [newStages[idx + 1], newStages[idx]];
                                                    setFormData(prev => ({ ...prev, workflow_stages: newStages }));
                                                }} className="w-6 h-6 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-300 hover:text-indigo-600 disabled:opacity-10 transition-all"><ChevronDown className="w-4 h-4" /></button>
                                            </div>
                                            <div className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center text-[10px] font-black  shrink-0 shadow-lg">#0{idx + 1}</div>
                                            <div className="flex-1 space-y-2">
                                                <input type="text" className="w-full bg-transparent border-none outline-none text-[13px] font-black text-slate-800 p-0 focus:text-indigo-600 transition-colors  " value={node.name} onChange={(e) => setFormData(prev => ({ ...prev, workflow_stages: prev.workflow_stages.map(s => s.id === node.id ? { ...s, name: e.target.value } : s) }))} />
                                                <div className="flex items-center gap-4">
                                                    <select className="bg-slate-50 border-none outline-none text-[9px] font-black text-slate-400  px-2.5 py-1 rounded-xl cursor-pointer hover:bg-slate-100 transition-all font-mono" value={node.type} onChange={(e) => setFormData(prev => ({ ...prev, workflow_stages: prev.workflow_stages.map(s => s.id === node.id ? { ...s, type: e.target.value } : s) }))}>
                                                        {STAGE_TYPES.map(t => (<option key={t.name} value={t.name}>{t.name}</option>))}
                                                    </select>
                                                </div>
                                            </div>
                                            <button onClick={() => setFormData(prev => ({ ...prev, workflow_stages: prev.workflow_stages.filter(s => s.id !== node.id) }))} className="w-8 h-8 rounded-xl hover:bg-rose-50 text-slate-200 hover:text-rose-500 transition-all flex items-center justify-center active:scale-95"><X className="w-4 h-4" /></button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            <AnimatePresence>
                {showSuccessModal && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-6">
                        <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-white w-full max-w-md rounded-2xl p-10 text-center shadow-2xl relative overflow-hidden border border-slate-100">
                            <div className="w-16 h-16 bg-emerald-500 text-white rounded-xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-emerald-500/20"><CircleCheck className="w-10 h-10" /></div>
                            <h2 className="text-2xl font-black text-slate-900 tracking-tight mb-2   leading-none">Job Updated</h2>
                            <p className="text-[10px] text-slate-400 font-bold   leading-relaxed mb-8 opacity-60">The job details have been updated successfully.</p>
                            <div className="flex flex-col gap-2">
                                <button onClick={() => router.push("/enterprise/jobs")} className="w-full py-4 bg-indigo-600 text-white rounded-xl font-black text-[10px]   hover:bg-indigo-700 transition-all shadow-xl flex items-center justify-center gap-2">
                                    <LayoutDashboard className="w-4 h-4" />
                                    View Job Board
                                </button>
                                <button onClick={() => window.open(`${window.location.origin}/jobs/${jobId}`, '_blank')} className="w-full py-4 border border-slate-100 rounded-xl text-slate-400 font-black text-[10px]   hover:bg-slate-50 transition-all flex items-center justify-center gap-2">
                                    <Eye className="w-4 h-4" />
                                    View Job Application
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { 
    BarChart, 
    Bar, 
    XAxis, 
    YAxis, 
    CartesianGrid, 
    Tooltip as RechartsTooltip, 
    ResponsiveContainer, 
    Cell
} from 'recharts';

interface JobStage {
    id: number;
    name: string;
    count: number;
}

interface JobMetrics {
    pipeline: number;
    submitted: number;
    end_client: number;
    interviews: number;
    confirmations: number;
    rejected: number;
    onboarded: number;
}

interface Application {
    id: string;
    candidate: {
        id: string;
        full_name: string;
        email: string;
        skills: string[];
    };
    current_stage: number;
    ai_match_score?: number;
    applied_at: string;
}

interface Job {
    id: string;
    title: string;
    description: string;
    location: string;
    created_at: string;
    status_id: number;
    salary_min?: number;
    salary_max?: number;
    salary_currency?: string;
    salary_frequency?: string;
    experience_min?: number;
    experience_max?: number;
    job_type?: string;
    work_mode?: string;
    department?: string;
    required_skills?: string[];
    client_job_id?: string;
    customer_type?: string;
    customer?: string;
    metrics?: JobMetrics;
    stages?: JobStage[];
}

const STATIC_LEADING_TABS = [
    { id: "overview", label: "Overview", count: undefined },
    { id: "info", label: "Info", count: undefined },
    { id: "onboarding_tab", label: "Onboarding", count: undefined },
];

export default function JobDetailPage() {
    const params = useParams();
    const router = useRouter();
    const { id } = params;
    const { token, canAccess } = useAuth();

    const [job, setJob] = useState<Job | null>(null);
    const [applications, setApplications] = useState<Application[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [activeTab, setActiveTab] = useState("overview");
    const [onboardings, setOnboardings] = useState<any[]>([]);
    const [isOnboardingLoading, setIsOnboardingLoading] = useState(false);

    useEffect(() => {
        if (id && token) {
            fetchJobDetails();
            fetchApplications();
            fetchOnboardings();
        }
    }, [id, token]);

    const fetchJobDetails = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/${id}`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setJob(data);
            }
        } catch (error) {
            console.error("Error fetching job:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const fetchApplications = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/applications?job_id=${id}`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setApplications(data);
            }
        } catch (error) {
            console.error("Error fetching applications:", error);
        }
    };

    const fetchOnboardings = async () => {
        setIsOnboardingLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding?job_id=${id}`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setOnboardings(data);
            }
        } catch (error) {
            console.error("Error fetching onboardings:", error);
        } finally {
            setIsOnboardingLoading(false);
        }
    };

    const getOnboardingStatusColor = (status: string) => {
        switch (status) {
            case "In Progress": return "bg-blue-50 text-blue-600 border-blue-100";
            case "Awaiting Confirmation": return "bg-amber-50 text-amber-600 border-amber-100";
            case "Completed": return "bg-emerald-50 text-emerald-600 border-emerald-100";
            case "Discontinued": return "bg-rose-50 text-rose-600 border-rose-100";
            default: return "bg-slate-50 text-slate-600 border-slate-100";
        }
    };

    if (isLoading) {
        return (
            <div className="p-8 flex items-center justify-center min-h-[400px]">
                <div className="animate-spin material-symbols-rounded text-indigo-600 text-4xl">sync</div>
            </div>
        );
    }

    if (!job) {
        return (
             <div className="p-8 text-center">
                <h1 className="text-xl font-bold text-slate-900">Job Not Found</h1>
                <Link href="/enterprise/jobs" className="text-indigo-600 hover:underline mt-4 inline-block">Back to Jobs</Link>
             </div>
        );
    }

    const { metrics } = job;

    const getStatusLabel = (statusId: number) => {
        switch (statusId) {
            case 1: return "Active";
            case 2: return "Draft";
            case 3: return "Closed";
            default: return "Active";
        }
    };

    // Prepare pipeline data for the chart
    const pipelineData = (job.stages || []).map(s => {
        return {
            name: s.name,
            count: applications.filter(app => app.current_stage === s.id).length
        };
    });

    const totalCandidates = applications.length;

    return (
        <div className="min-h-screen bg-[#F8FAFC] pb-20">
            {/* Top Navigation Bar */}
            <div className="bg-white border-b border-slate-200 px-6 py-3 flex items-center justify-between sticky top-0 z-40">
                <div className="flex items-center gap-4">
                    <button 
                        onClick={() => router.back()}
                        className="w-8 h-8 flex items-center justify-center rounded-xl border border-slate-200 text-slate-600 hover:bg-slate-50 transition-all"
                    >
                        <span className="material-symbols-rounded text-xl">arrow_back</span>
                    </button>
                    <div>
                        <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400   mb-0.5">
                            <Link href="/enterprise/jobs" className="hover:text-indigo-600">Jobs</Link>
                            <span>/</span>
                            <span>{job.id.slice(0, 8)}</span>
                        </div>
                        <h1 className="text-sm font-black text-slate-900 flex items-center gap-2">
                            {job.title}
                            <span className="px-2 py-0.5 bg-emerald-50 text-emerald-600 text-[10px] font-black rounded-xl border border-emerald-100  tracking-wide">
                                {getStatusLabel(job.status_id)}
                            </span>
                        </h1>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button className="w-8 h-8 flex items-center justify-center rounded-xl border border-slate-200 text-slate-400 hover:text-indigo-600 hover:border-indigo-100 transition-all shadow-sm">
                        <span className="material-symbols-rounded text-xl">share</span>
                    </button>
                    {canAccess("jobs:update") && (
                        <Link 
                            href={`/enterprise/jobs/${id}/edit`}
                            className="px-4 py-1.5 flex items-center justify-center gap-1.5 rounded-xl bg-indigo-600 text-white text-[11px] font-black hover:bg-indigo-700 transition-all active:scale-95 shadow-lg shadow-indigo-100"
                        >
                            <span className="material-symbols-rounded text-[14px]">edit</span>
                            Edit
                        </Link>
                    )}
                </div>
            </div>

            <div className="p-6 space-y-6">
                {/* Header Stats Info */}
                <div className="flex flex-wrap items-end justify-between gap-6 pb-2">
                    <div className="space-y-1">
                        <h2 className="text-3xl font-black text-slate-900 tracking-tight">{job.title}</h2>
                        <div className="flex items-center gap-2 text-indigo-500 font-bold text-xs  tracking-tight">
                            <span className="material-symbols-rounded text-sm">location_on</span>
                            {job.location}
                        </div>
                    </div>
                    
                    <div></div>
                </div>

                {/* Metric Cards */}
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-3">
                    {[
                        { label: "PIPELINE", value: metrics?.pipeline || 0, icon: "account_tree", color: "text-[#7C3AED]", bg: "bg-[#7C3AED]/5" },
                        { label: "SUBMITTED", value: metrics?.submitted || 0, icon: "assignment_ind", color: "text-pink-500", bg: "bg-pink-50" },
                        { label: "INTERVIEWS", value: metrics?.interviews || 0, icon: "groups", color: "text-purple-400", bg: "bg-purple-50" },
                        { label: "REJECTED", value: metrics?.rejected || 0, icon: "block", color: "text-slate-400", bg: "bg-slate-100" },
                        { label: "ONBOARDED", value: metrics?.onboarded || 0, icon: "person_add", color: "text-fuchsia-400", bg: "bg-fuchsia-50" },
                    ].map((card, i) => (
                        <div key={i} className="bg-white border border-slate-200 rounded-xl p-4 shadow-sm hover:shadow-md transition-all group">
                            <div className="flex items-center justify-between mb-2">
                                <span className="text-[10px] font-black text-slate-400  transition-colors group-hover:text-slate-600">{card.label}</span>
                                <div className={`w-8 h-8 rounded-xl ${card.bg} flex items-center justify-center ${card.color}`}>
                                    <span className="material-symbols-rounded text-lg">{card.icon}</span>
                                </div>
                            </div>
                            <div className="text-2xl font-black text-slate-900">{card.value}</div>
                        </div>
                    ))}
                </div>

                {/* Tabs & Content */}
                <div className="space-y-6">
                    {/* Tabs Navigation */}
                    <div className="flex border-b border-slate-200 gap-8 overflow-x-auto no-scrollbar">
                        {[
                            ...STATIC_LEADING_TABS,
                            ...(job.stages || []).map(s => {
                                const dynamicCount = applications.filter(app => app.current_stage === s.id).length;
                                return { 
                                    id: s.name.toLowerCase().replace(/\s+/g, '_'), 
                                    label: s.name, 
                                    count: dynamicCount 
                                };
                            })
                        ].map((tab) => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id)}
                                className={`pb-4 px-1 text-sm font-bold whitespace-nowrap transition-all relative ${
                                    activeTab === tab.id ? "text-[#7C3AED]" : "text-slate-500 hover:text-slate-700"
                                }`}
                            >
                                {tab.label}
                                {tab.count !== undefined && <span className="ml-1 text-xs">({tab.count})</span>}
                                {activeTab === tab.id && (
                                    <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#7C3AED] rounded-full"></div>
                                )}
                            </button>
                        ))}
                    </div>


                    {/* Active Tab Content (Overview) */}
                    {activeTab === "overview" && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                                {/* Pipeline Visualization */}
                                <div className="lg:col-span-2 bg-white rounded-xl border border-slate-200 shadow-sm p-6 overflow-hidden">
                                     <div className="flex items-center justify-between mb-8">
                                        <div>
                                            <h3 className="text-sm font-black text-slate-900  tracking-tight">Recruitment Pipeline</h3>
                                            <p className="text-[10px] font-bold text-slate-400   mt-0.5">Distribution across rounds</p>
                                        </div>
                                        <div className="flex items-center gap-1.5 px-2.5 py-1 bg-slate-50 border border-slate-100 rounded-xl">
                                            <span className="w-2 h-2 rounded-full bg-[#7C3AED]"></span>
                                            <span className="text-[10px] font-black text-slate-600  tracking-tight">{totalCandidates} TOTAL</span>
                                        </div>
                                    </div>

                                    <div className="h-[300px] w-full">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <BarChart data={pipelineData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                                <XAxis 
                                                    dataKey="name" 
                                                    axisLine={false} 
                                                    tickLine={false} 
                                                    tick={{ fontSize: 10, fontWeight: 700, fill: '#64748b' }} 
                                                    dy={10}
                                                />
                                                <YAxis 
                                                    axisLine={false} 
                                                    tickLine={false} 
                                                    tick={{ fontSize: 10, fontWeight: 700, fill: '#cbd5e1' }}
                                                />
                                                <RechartsTooltip 
                                                    cursor={{ fill: '#f8fafc' }}
                                                    content={({ active, payload }) => {
                                                        if (active && payload && payload.length) {
                                                            return (
                                                                <div className="bg-slate-900 border border-slate-800 rounded-xl p-3 shadow-xl">
                                                                    <p className="text-[10px] font-black text-slate-400   leading-none mb-1">{payload[0].payload.name}</p>
                                                                    <p className="text-xs font-black text-white">{payload[0].value} Candidates</p>
                                                                </div>
                                                            );
                                                        }
                                                        return null;
                                                    }}
                                                />
                                                <Bar dataKey="count" radius={[6, 6, 0, 0]} barSize={40}>
                                                    {pipelineData.map((entry, index) => (
                                                        <Cell key={`cell-${index}`} fill={index % 2 === 0 ? "#7C3AED" : "#A78BFA"} fillOpacity={1 - (index * 0.1)} />
                                                    ))}
                                                </Bar>
                                            </BarChart>
                                        </ResponsiveContainer>
                                    </div>
                                </div>

                                {/* Summary Sidebar */}
                                <div className="space-y-6">
                                    <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
                                        <h3 className="text-xs font-black text-slate-900   mb-4">Stage Efficiency</h3>
                                        <div className="space-y-4">
                                            {pipelineData.map((stage, i) => (
                                                <div key={i} className="flex flex-col gap-1.5">
                                                    <div className="flex items-center justify-between">
                                                        <span className="text-[10px] font-black text-slate-500  tracking-tight">{stage.name}</span>
                                                        <span className="text-[10px] font-black text-slate-900 ">{Math.round((stage.count / (totalCandidates || 1)) * 100)}%</span>
                                                    </div>
                                                    <div className="w-full h-1.5 bg-slate-50 rounded-full overflow-hidden border border-slate-100">
                                                        <div 
                                                            className="h-full bg-[#7C3AED] transition-all duration-1000"
                                                            style={{ width: `${(stage.count / (totalCandidates || 1)) * 100}%`, opacity: 1 - (i * 0.15) }}
                                                        ></div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                    
                                    <div className="bg-[#7C3AED] rounded-xl p-6 shadow-lg shadow-indigo-200">
                                        <div className="w-10 h-10 rounded-xl bg-white/20 flex items-center justify-center text-white mb-4">
                                            <span className="material-symbols-rounded text-white">trending_up</span>
                                        </div>
                                        <h4 className="text-sm font-black text-white  tracking-tight">Quick Insight</h4>
                                        <p className="text-white/80 text-[11px] font-medium leading-relaxed mt-1">
                                            Most candidates are currently in the <strong>{pipelineData.length > 0 ? pipelineData.reduce((prev, current) => (prev.count > current.count) ? prev : current).name : "initial"}</strong> stage. 
                                            Consider reviewing this pipeline to speed up the hiring process.
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Active Tab Content (Info) */}
                    {activeTab === "info" && (
                        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <button className="w-full px-6 py-4 flex items-center justify-between bg-slate-50/50 border-b border-slate-100 hover:bg-slate-50 transition-colors group">
                                <h3 className="text-sm font-black text-slate-900  tracking-tight">Job Details</h3>
                                <span className="material-symbols-rounded text-slate-400 group-hover:text-slate-600">expand_more</span>
                            </button>
                            
                            <div className="p-10">
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-y-12 gap-x-12">
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Client Job ID</p>
                                        <p className="text-xs font-bold text-slate-800">{job.client_job_id || "-"}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Job ID</p>
                                        <p className="text-xs font-bold text-slate-800">EXAIN-{job.id.slice(0, 8).toUpperCase()}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Status</p>
                                        <p className="text-xs font-bold text-slate-800">{getStatusLabel(job.status_id)}</p>
                                    </div>
                                    
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Job Title</p>
                                        <p className="text-xs font-bold text-slate-800">{job.title}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Customer Type</p>
                                        <p className="text-xs font-bold text-slate-800">{job.customer_type || "Internal"}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Customer</p>
                                        <p className="text-xs font-bold text-slate-800">{job.customer || "Internal"}</p>
                                    </div>

                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Experience</p>
                                        <p className="text-xs font-bold text-slate-800">
                                            {job.experience_min !== undefined && job.experience_max !== undefined 
                                                ? `${job.experience_min} - ${job.experience_max} Years`
                                                : job.experience_min !== undefined ? `${job.experience_min}+ Years` : "Not Specified"}
                                        </p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Salary Range</p>
                                        <p className="text-xs font-bold text-slate-800">
                                            {job.salary_min && job.salary_max 
                                                ? `${job.salary_currency || "INR"} ${job.salary_min.toLocaleString()} - ${job.salary_max.toLocaleString()} / ${job.salary_frequency || "Yearly"}`
                                                : "Not Specified"}
                                        </p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400  ">Work Mode</p>
                                        <p className="text-xs font-bold text-slate-800">{job.work_mode || "On-site"}</p>
                                    </div>

                                    <div className="space-y-1 md:col-span-3">
                                        <p className="text-[10px] font-black text-slate-400  ">Required Skills</p>
                                        <div className="flex flex-wrap gap-2 mt-2">
                                            {job.required_skills?.map((skill, i) => (
                                                <span key={i} className="px-2 py-1 bg-slate-100 text-slate-600 text-[10px] font-bold rounded-xl  tracking-tight">
                                                    {skill.trim()}
                                                </span>
                                            ))}
                                            {(!job.required_skills || job.required_skills.length === 0) && (
                                                <span className="text-xs font-bold text-slate-400 ">No skills specified</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                    
                    {/* Onboarding Tab Content */}
                    {activeTab === "onboarding_tab" && (
                        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden min-h-[400px] animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
                                <h3 className="text-xs font-black text-slate-900  ">Onboarding Candidates</h3>
                            </div>
                            <div className="overflow-x-auto">
                                <table className="w-full text-left border-collapse">
                                    <thead>
                                        <tr className="bg-slate-50/50">
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400  ">Code</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400  ">Candidate</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400   text-center">Status</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400   text-right">Actions</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100">
                                        {onboardings.map((ob) => (
                                            <tr key={ob.id} className="hover:bg-slate-50/50 transition-colors group cursor-pointer" onClick={() => router.push(`/enterprise/onboarding/${ob.id}`)}>
                                                <td className="px-6 py-4">
                                                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded ">
                                                        {ob.onboarding_code}
                                                    </span>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center gap-3">
                                                        <div className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center font-bold text-xs ">
                                                            {ob.application?.candidate?.full_name?.charAt(0)}
                                                        </div>
                                                        <div>
                                                            <p className="text-xs font-black text-slate-900 leading-tight">
                                                                {ob.application?.candidate?.full_name}
                                                            </p>
                                                            <p className="text-[10px] font-bold text-slate-400">
                                                                {ob.application?.candidate?.email}
                                                            </p>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-4 text-center">
                                                    {ob.status && (
                                                        <span className={`text-[10px] font-black px-3 py-1 rounded-full border  tracking-tighter ${getOnboardingStatusColor(ob.status.name)}`}>
                                                            {ob.status.name}
                                                        </span>
                                                    )}
                                                </td>
                                                <td className="px-6 py-4 text-right">
                                                    <button className="h-7 px-3 rounded-xl bg-slate-100 text-slate-500 text-[9px] font-black   hover:bg-slate-200 transition-all">
                                                        Track
                                                    </button>
                                                </td>
                                            </tr>
                                        ))}
                                        {onboardings.length === 0 && !isOnboardingLoading && (
                                            <tr>
                                                <td colSpan={4} className="px-6 py-20 text-center">
                                                    <div className="flex flex-col items-center gap-3">
                                                        <div className="w-12 h-12 rounded-full bg-slate-50 flex items-center justify-center text-slate-300">
                                                            <span className="material-symbols-rounded text-2xl">person_add</span>
                                                        </div>
                                                        <p className="text-xs font-bold text-slate-400">No onboarding processes for this job yet.</p>
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {/* Candidate List Content (for stage tabs) */}
                    {!STATIC_LEADING_TABS.some(t => t.id === activeTab) && (
                        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden min-h-[400px]">
                            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
                                <h3 className="text-xs font-black text-slate-900  ">Candidates</h3>
                                <div className="flex items-center gap-2">
                                    <div className="relative">
                                        <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">search</span>
                                        <input type="text" placeholder="Search..." className="pl-9 pr-4 py-1.5 bg-slate-50 border-none rounded-xl text-xs font-medium focus:ring-1 focus:ring-indigo-500 w-48" />
                                    </div>
                                </div>
                            </div>
                            <div className="overflow-x-auto">
                                <table className="w-full text-left">
                                    <thead>
                                        <tr className="bg-slate-50/50">
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400  ">Candidate</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400   text-center">Match Score</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400  ">Status</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400  ">Applied</th>
                                            <th className="px-6 py-3 text-[10px] font-black text-slate-400  "></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100">
                                        {applications
                                            .filter(app => {
                                                const stage = job.stages?.find(s => s.name.toLowerCase().replace(/\s+/g, '_') === activeTab);
                                                return stage ? app.current_stage === stage.id : false;
                                            })
                                            .map((app) => (
                                                <tr key={app.id} className="hover:bg-slate-50/50 transition-colors group cursor-pointer">
                                                    <td className="px-6 py-4">
                                                        <div className="flex items-center gap-3">
                                                            <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-xs">
                                                                {app.candidate.full_name?.charAt(0)}
                                                            </div>
                                                            <div>
                                                                <p className="text-xs font-black text-slate-900">{app.candidate.full_name}</p>
                                                                <p className="text-[10px] font-bold text-slate-400">{app.candidate.email}</p>
                                                            </div>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4">
                                                        <div className="flex flex-col items-center">
                                                            <div className={`text-xs font-black ${
                                                                (app.ai_match_score || 0) > 80 ? "text-emerald-600" : 
                                                                (app.ai_match_score || 0) > 60 ? "text-indigo-600" : "text-slate-500"
                                                            }`}>
                                                                {app.ai_match_score ? `${Math.round(app.ai_match_score)}%` : "-"}
                                                            </div>
                                                            <div className="w-16 h-1 bg-slate-100 rounded-full mt-1 overflow-hidden">
                                                                <div 
                                                                    className={`h-full rounded-full ${
                                                                        (app.ai_match_score || 0) > 80 ? "bg-emerald-500" : 
                                                                        (app.ai_match_score || 0) > 60 ? "bg-indigo-500" : "bg-slate-300"
                                                                    }`}
                                                                    style={{ width: `${app.ai_match_score || 0}%` }}
                                                                ></div>
                                                            </div>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4">
                                                        <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-black rounded-xl border border-indigo-100  tracking-wide">
                                                            In Progress
                                                        </span>
                                                    </td>
                                                    <td className="px-6 py-4 text-[10px] font-bold text-slate-500 ">
                                                        {new Date(app.applied_at).toLocaleDateString()}
                                                    </td>
                                                    <td className="px-6 py-4 text-right">
                                                        <button className="text-slate-300 hover:text-indigo-600 transition-colors">
                                                            <span className="material-symbols-rounded text-lg">arrow_forward</span>
                                                        </button>
                                                    </td>
                                                </tr>
                                            ))}
                                        {applications.filter(app => {
                                            const stage = job.stages?.find(s => s.name.toLowerCase().replace(/\s+/g, '_') === activeTab);
                                            return stage ? app.current_stage === stage.id : false;
                                        }).length === 0 && (
                                            <tr>
                                                <td colSpan={5} className="px-6 py-20 text-center">
                                                    <div className="flex flex-col items-center gap-3">
                                                        <div className="w-12 h-12 rounded-full bg-slate-50 flex items-center justify-center text-slate-300">
                                                            <span className="material-symbols-rounded text-2xl">person_search</span>
                                                        </div>
                                                        <p className="text-xs font-bold text-slate-400">No candidates found in this stage.</p>
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}
                </div>

                {/* Footer Actions Removed */}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import JobEditor from "@/components/enterprise/JobEditor";
import { 
    ArrowLeft, 
    ArrowRight, 
    CircleCheck, 
    Building2, 
    MapPin, 
    Rocket, 
    Sparkles, 
    RefreshCcw, 
    CirclePlus, 
    Network, 
    ClipboardList, 
    Settings,
    X,
    LayoutDashboard,
    Eye,
    Users,
    Brain,
    Calculator,
    ShieldCheck,
    ChevronUp,
    ChevronDown,
    ListPlus,
    Pin,
    FileText,
    AtSign,
    ToggleRight,
    Type, 
    Link as LinkIcon,
    Mail
} from "lucide-react";

interface ApplicationField {
    id: string;
    label: string;
    type: 'text' | 'number' | 'boolean' | 'file' | 'email';
    icon: string;
    is_required: boolean;
}

interface WorkflowStage {
    id: string;
    name: string;
    type: string;
    icon: string;
    email_template_id?: string;
}

const DEFAULT_APPLICATION_FIELDS: ApplicationField[] = [
    { id: '1', label: 'Full Name', type: 'text', icon: 'person', is_required: true },
    { id: '2', label: 'Email Address', type: 'email', icon: 'mail', is_required: true },
    { id: '3', label: 'Phone Number', type: 'text', icon: 'call', is_required: false },
    { id: '4', label: 'Resume / CV', type: 'file', icon: 'description', is_required: true },
    { id: '5', label: 'Portfolio URL', type: 'text', icon: 'link', is_required: false }
];

const DEFAULT_WORKFLOW_STAGES: WorkflowStage[] = [
    { id: '1', name: 'Initial Screening', type: 'Screening', icon: 'search' }
];

interface Company {
    id: string;
    name: string;
}

interface EmailTemplate {
    id: string;
    name: string;
}

export default function CreateJobPage() {
    const { token } = useAuth();
    const router = useRouter();
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isGeneratingAI, setIsGeneratingAI] = useState(false);
    const [currentStep, setCurrentStep] = useState(1);
    const [showSuccessModal, setShowSuccessModal] = useState(false);
    const [createdJobId, setCreatedJobId] = useState("");
    const [companies, setCompanies] = useState<Company[]>([]);
    const [emailTemplates, setEmailTemplates] = useState<EmailTemplate[]>([]);

    const [formData, setFormData] = useState({
        title: "",
        job_type: "Full Time",
        work_mode: "On-Site",
        location: "",
        department: "Human Resources",
        salary_currency: "INR",
        salary_frequency: "Yearly",
        salary_min: "",
        salary_max: "",
        experience_min: "0",
        experience_max: "5",
        description: "",
        required_skills: "",
        auto_fit_analysis: false,
        status_id: 2,
        company_id: "",
        application_fields: DEFAULT_APPLICATION_FIELDS,
        workflow_stages: DEFAULT_WORKFLOW_STAGES
    });

    const fetchEmailTemplates = useCallback(async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setEmailTemplates(data);
            }
        } catch (error) {
            console.error("Failed to fetch email templates:", error);
        }
    }, [token]);

    const fetchCompanies = useCallback(async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/company/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setCompanies(data);
                if (data.length > 0) {
                    setFormData(prev => ({ ...prev, company_id: data[0].id }));
                }
            }
        } catch (error) {
            console.error("Failed to fetch companies:", error);
        }
    }, [token]);

    useEffect(() => {
        if (token) {
            fetchCompanies();
            fetchEmailTemplates();
        }
    }, [token, fetchCompanies, fetchEmailTemplates]);


    const steps = [
        { id: 1, name: "Job Details", icon: "ClipboardList" },
        { id: 2, name: "Application", icon: "Settings" },
        { id: 3, name: "Workflow", icon: "Network" }
    ];

    const handleSubmit = async () => {
        if (isExperienceInvalid || isSalaryInvalid) return;
        setIsSubmitting(true);
        try {
            const payload = {
                ...formData,
                salary_min: formData.salary_min ? parseFloat(formData.salary_min) : null,
                salary_max: formData.salary_max ? parseFloat(formData.salary_max) : null,
                experience_min: parseInt(formData.experience_min),
                experience_max: parseInt(formData.experience_max),
                required_skills: formData.required_skills.split(",").map(s => s.trim()).filter(s => s)
            };
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, {
                method: "POST",
                headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
                body: JSON.stringify(payload)
            });
            if (res.ok) {
                const data = await res.json();
                setCreatedJobId(data.id);
                setShowSuccessModal(true);
            }
        } catch (error) {
            console.error("Failed to submit job:", error);
        } finally {
            setIsSubmitting(false);
        }
    };

    const generateAIDescription = async () => {
        if (!formData.title) return;
        setIsGeneratingAI(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/generate-jd`, {
                method: "POST",
                headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
                body: JSON.stringify({ title: formData.title, existing_description: formData.description, location: formData.location, experience_min: formData.experience_min, experience_max: formData.experience_max })
            });
            if (res.ok) {
                const data = await res.json();
                setFormData({ ...formData, description: data.description, required_skills: data.skills?.join(", ") || formData.required_skills });
            }
        } catch (error) {
            console.error("Failed to generate AI description:", error);
        } finally {
            setIsGeneratingAI(false);
        }
    };

    const isExperienceInvalid = parseInt(formData.experience_max) < parseInt(formData.experience_min);
    const isSalaryInvalid = formData.salary_min && formData.salary_max && parseFloat(formData.salary_max) < parseFloat(formData.salary_min);

    const STAGE_TYPES = [
        { name: 'Screening', icon: 'Search' },
        { name: 'Aptitude', icon: 'Brain' },
        { name: 'Coding', icon: 'Code' },
        { name: 'Technical Interview', icon: 'Zap' },
        { name: 'HR Interview', icon: 'Users' },
        { name: 'Final Selection', icon: 'ShieldCheck' }
    ];

    const canGoNext = () => currentStep === 1 ? (formData.title && !isExperienceInvalid && !isSalaryInvalid) : true;

    return (
        <div className="h-full min-h-screen bg-[#FDFDFF] flex flex-col p-4 animate-in fade-in duration-700 overflow-hidden relative">
            {/* Ultra-Compact Header */}
            <div className="flex items-center justify-between mb-6 px-1 shrink-0">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.back()} className="w-10 h-10 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-rose-500 transition-all shadow-sm active:scale-95">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none  ">Create Job</h1>
                        <p className="text-[9px] text-slate-400 font-bold  tracking-[0.2em] mt-1.5 opacity-60">Job Details</p>
                    </div>
                </div>

                <div className="hidden lg:flex items-center bg-slate-100/40 p-1 rounded-xl border border-slate-200/50 backdrop-blur-sm">
                    {steps.map((step) => (
                        <button
                            key={step.id}
                            disabled={step.id > currentStep && !canGoNext()}
                            onClick={() => canGoNext() && setCurrentStep(step.id)}
                            className={`flex items-center gap-2 px-4 py-1.5 rounded-xl transition-all ${currentStep === step.id ? "bg-white text-indigo-600 shadow-sm border border-slate-100" : "text-slate-600 hover:text-slate-800"}`}
                        >
                            <span className={`text-[8px] font-black w-4 h-4 flex items-center justify-center rounded-xl border ${currentStep === step.id ? "border-indigo-200 bg-indigo-50 text-indigo-600" : "border-slate-300 bg-slate-200 text-slate-600"}`}>{step.id}</span>
                            <span className="text-[9px] font-black  ">{step.name}</span>
                        </button>
                    ))}
                </div>

                <button
                    disabled={!canGoNext()}
                    className="h-11 px-6 rounded-xl bg-indigo-600 text-white text-[10px] font-black   shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2 group disabled:opacity-40"
                    onClick={() => currentStep < 3 ? setCurrentStep(currentStep + 1) : handleSubmit()}
                >
                    {isSubmitting ? "Saving..." : currentStep === 3 ? "Create Job" : "Next Step"}
                    <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </button>
            </div>

            <div className="flex-1 bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden flex flex-col relative">
                <AnimatePresence mode="wait">
                    {currentStep === 1 && (
                        <motion.div key="step1" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="flex-1 bg-slate-50/50 overflow-y-auto p-4 md:p-8 no-scrollbar relative">
                            <div className="mx-auto max-w-[1400px] grid grid-cols-1 lg:grid-cols-12 gap-6 w-full">
                                {/* Left Form Column */}
                                <div className="lg:col-span-4 space-y-6 flex flex-col">
                                    {/* Core Details Card */}
                                    <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-6 space-y-5 relative overflow-hidden group">
                                        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-bl-full -z-10 transition-transform group-hover:scale-110"></div>
                                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                                            <div className="w-10 h-10 rounded-xl bg-indigo-50 text-indigo-600 flex items-center justify-center">
                                                <ClipboardList className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Job Profile</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Core listing details</p>
                                            </div>
                                        </div>
                                        
                                        <div className="space-y-4 pt-1">
                                            <div className="space-y-1.5 relative">
                                                <label className="text-[11px] font-bold text-slate-500 ml-1">Job Title <span className="text-rose-500">*</span></label>
                                                <input type="text" placeholder="e.g. Senior Frontend Engineer" className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} />
                                            </div>

                                            {companies.length > 0 && (
                                                <div className="space-y-1.5 relative">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Company</label>
                                                    <select className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-800 font-semibold text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none cursor-pointer" value={formData.company_id} onChange={e => setFormData({ ...formData, company_id: e.target.value })}>
                                                        {companies.map(c => (<option key={c.id} value={c.id}>{c.name}</option>))}
                                                    </select>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    {/* Logistics Card */}
                                    <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-6 space-y-5 relative overflow-hidden group">
                                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                                            <div className="w-10 h-10 rounded-xl bg-teal-50 text-teal-600 flex items-center justify-center">
                                                <MapPin className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Work Arrangement</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Work mode & location</p>
                                            </div>
                                        </div>
                                        
                                        <div className="space-y-4 pt-1">
                                            <div className="grid grid-cols-2 gap-4">
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Type</label>
                                                    <select className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-800 font-semibold text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none cursor-pointer" value={formData.job_type} onChange={e => setFormData({ ...formData, job_type: e.target.value })}>
                                                        <option>Full Time</option><option>Part Time</option><option>Contract</option>
                                                    </select>
                                                </div>
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Mode</label>
                                                    <select className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-800 font-semibold text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none cursor-pointer" value={formData.work_mode} onChange={e => setFormData({ ...formData, work_mode: e.target.value })}>
                                                        <option>On-Site</option><option>Remote</option><option>Hybrid</option>
                                                    </select>
                                                </div>
                                            </div>
                                            <div className="space-y-1.5 relative">
                                                <label className="text-[11px] font-bold text-slate-500 ml-1">Location</label>
                                                <input type="text" placeholder="e.g. San Francisco, CA" className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300" value={formData.location} onChange={e => setFormData({ ...formData, location: e.target.value })} />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Requirements Card */}
                                    <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-6 space-y-5 relative overflow-hidden group">
                                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                                            <div className="w-10 h-10 rounded-xl bg-orange-50 text-orange-600 flex items-center justify-center">
                                                <Calculator className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Requirements</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Experience & compensation</p>
                                            </div>
                                        </div>
                                        
                                        <div className="space-y-4 pt-1">
                                            <div className="grid grid-cols-2 gap-4">
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Min Exp (Yrs)</label>
                                                    <input type="number" min="0" className={`w-full px-4 py-3 rounded-xl border ${isExperienceInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none`} value={formData.experience_min} onChange={e => setFormData({ ...formData, experience_min: e.target.value })} />
                                                </div>
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Max Exp (Yrs)</label>
                                                    <input type="number" min="0" className={`w-full px-4 py-3 rounded-xl border ${isExperienceInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none`} value={formData.experience_max} onChange={e => setFormData({ ...formData, experience_max: e.target.value })} />
                                                </div>
                                            </div>
                                            <div className="grid grid-cols-2 gap-4">
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Min Salary (LPA)</label>
                                                    <input type="number" min="0" placeholder="5" className={`w-full px-4 py-3 rounded-xl border ${isSalaryInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300`} value={formData.salary_min} onChange={e => setFormData({ ...formData, salary_min: e.target.value })} />
                                                </div>
                                                <div className="space-y-1.5">
                                                    <label className="text-[11px] font-bold text-slate-500 ml-1">Max Salary (LPA)</label>
                                                    <input type="number" min="0" placeholder="15" className={`w-full px-4 py-3 rounded-xl border ${isSalaryInvalid ? 'border-rose-300 bg-rose-50 text-rose-700' : 'border-slate-200 bg-slate-50/50 hover:bg-slate-50 focus:bg-white'} font-semibold text-slate-800 text-sm focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none placeholder:text-slate-300`} value={formData.salary_max} onChange={e => setFormData({ ...formData, salary_max: e.target.value })} />
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Right Description Area */}
                                <div className="lg:col-span-8 flex flex-col min-h-[600px] bg-white rounded-2xl border border-slate-200/80 shadow-sm overflow-hidden">
                                    <div className="px-6 py-5 border-b border-slate-100 flex justify-between items-center bg-white z-10 shrink-0">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-xl bg-purple-50 text-purple-600 flex items-center justify-center">
                                                <FileText className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h3 className="text-sm font-bold text-slate-800">Job Description & Skills</h3>
                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mt-0.5">Outline the responsibilities and tech stack</p>
                                            </div>
                                        </div>
                                        <button onClick={generateAIDescription} disabled={isGeneratingAI} className="px-4 py-2 rounded-xl bg-gradient-to-r from-indigo-600 to-purple-600 text-white text-[11px] font-bold shadow-md shadow-indigo-200 hover:shadow-lg hover:-translate-y-0.5 active:translate-y-0 transition-all flex items-center gap-2 disabled:opacity-70 disabled:hover:translate-y-0 disabled:shadow-none">
                                            {isGeneratingAI ? <RefreshCcw className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                                            {isGeneratingAI ? 'Generating...' : 'Auto Draft with AI'}
                                        </button>
                                    </div>

                                    <div className="flex-1 flex flex-col border-b border-slate-200 overflow-y-auto">
                                        <JobEditor content={formData.description} onChange={(content) => setFormData({ ...formData, description: content })} placeholder="Detail the role, responsibilities, and ideal candidate profile here..." />
                                    </div>

                                    <div className="p-6 bg-slate-50 shrink-0">
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 ml-1">Required Tech Stack <span className="font-medium opacity-60">(Comma Separated)</span></label>
                                            <div className="relative">
                                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                                                    <AtSign className="w-4 h-4" />
                                                </div>
                                                <input type="text" className="w-full pl-11 pr-5 py-3 rounded-xl border border-slate-200/80 outline-none font-semibold text-slate-800 text-sm bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-sm placeholder:text-slate-300" placeholder="e.g. React, Node.js, Python, AWS" value={formData.required_skills} onChange={e => setFormData({ ...formData, required_skills: e.target.value })} />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {currentStep === 2 && (
                        <motion.div key="step2" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="flex-1 grid grid-cols-12 overflow-hidden h-full">
                            <div className="col-span-4 border-r border-slate-100 p-8 bg-slate-50/30 overflow-y-auto no-scrollbar flex flex-col gap-6">
                                {/* Header */}
                                <div>
                                    <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-2">Application Form</h1>
                                    <p className="text-[11px] text-slate-400 font-medium leading-relaxed">Design the form candidates will fill out when applying for this role.</p>
                                </div>

                                {/* Add Question Button */}
                                <button onClick={() => {
                                    const newField: ApplicationField = { id: Date.now().toString(), label: 'New Question', type: 'text', icon: 'Type', is_required: false };
                                    setFormData(prev => ({ ...prev, application_fields: [...prev.application_fields, newField] }));
                                }} className="w-full py-3.5 rounded-xl bg-indigo-600 text-white text-[11px] font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95">
                                    <CirclePlus className="w-4 h-4" />
                                    Add Question
                                </button>

                                {/* Form Stats */}
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="bg-white rounded-xl border border-slate-200 p-4 text-center shadow-sm">
                                        <div className="text-2xl font-black text-indigo-600">{formData.application_fields.length}</div>
                                        <div className="text-[10px] font-bold text-slate-400 mt-0.5 uppercase tracking-wide">Total Fields</div>
                                    </div>
                                    <div className="bg-white rounded-xl border border-slate-200 p-4 text-center shadow-sm">
                                        <div className="text-2xl font-black text-emerald-600">{formData.application_fields.filter(f => f.is_required).length}</div>
                                        <div className="text-[10px] font-bold text-slate-400 mt-0.5 uppercase tracking-wide">Required</div>
                                    </div>
                                </div>

                                {/* Field Types Guide */}
                                <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4 space-y-3">
                                    <p className="text-[11px] font-bold text-slate-600 uppercase tracking-wider">Field Types</p>
                                    {[
                                        { type: 'Text', color: 'bg-blue-50 text-blue-600', desc: 'Short or long text answers' },
                                        { type: 'Email', color: 'bg-purple-50 text-purple-600', desc: 'Validated email address' },
                                        { type: 'Number', color: 'bg-orange-50 text-orange-600', desc: 'Numeric value input' },
                                        { type: 'File', color: 'bg-teal-50 text-teal-600', desc: 'Document or resume upload' },
                                        { type: 'Boolean', color: 'bg-rose-50 text-rose-600', desc: 'Yes / No toggle' },
                                    ].map(item => (
                                        <div key={item.type} className="flex items-center gap-3">
                                            <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${item.color} shrink-0 w-14 text-center`}>{item.type}</span>
                                            <span className="text-[11px] text-slate-400 font-medium">{item.desc}</span>
                                        </div>
                                    ))}
                                </div>


                            </div>
                            <div className="col-span-8 p-8 overflow-y-auto no-scrollbar">
                                <div className="flex flex-col gap-3 max-w-3xl mx-auto pb-10">
                                    {formData.application_fields.map((field) => (
                                        <div key={field.id} className="p-3.5 bg-white rounded-xl border border-slate-100 shadow-sm flex items-center justify-between group hover:border-indigo-500/30 transition-all">
                                            <div className="flex items-center gap-4 flex-1">
                                                <div className="w-9 h-9 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 group-hover:text-indigo-600 group-hover:bg-indigo-50 transition-all shadow-inner"><Pin className="w-4 h-4" /></div>
                                                <div className="flex-1 grid grid-cols-2 gap-4 items-center">
                                                    <input type="text" className="bg-transparent border-none outline-none text-[13px] font-black text-slate-800 p-0 focus:text-indigo-600 transition-colors  " value={field.label} onChange={(e) => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.map(f => f.id === field.id ? { ...f, label: e.target.value } : f) }))} />
                                                    <select className="bg-slate-50 border-none outline-none text-[9px] font-black text-slate-400  px-3 py-1.5 rounded-xl cursor-pointer hover:bg-slate-100 transition-all w-32" value={field.type} onChange={(e) => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.map(f => f.id === field.id ? { ...f, type: e.target.value as ApplicationField['type'] } : f) }))}>
                                                        <option value="text">Text</option><option value="email">Email</option><option value="number">Number</option><option value="boolean">Boolean</option><option value="file">File</option>
                                                    </select>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-4 ml-6">
                                                <button onClick={() => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.map(f => f.id === field.id ? { ...f, is_required: !f.is_required } : f) }))} className={`px-2.5 py-1 rounded-xl text-[8px] font-black   border transition-all ${field.is_required ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-slate-50 text-slate-300 border-slate-100'}`}>{field.is_required ? 'Required' : 'Optional'}</button>
                                                <button onClick={() => setFormData(prev => ({ ...prev, application_fields: prev.application_fields.filter(f => f.id !== field.id) }))} className="w-8 h-8 rounded-xl hover:bg-rose-50 text-slate-200 hover:text-rose-500 transition-all flex items-center justify-center active:scale-90"><X className="w-4 h-4" /></button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {currentStep === 3 && (
                        <motion.div key="step3" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="flex-1 grid grid-cols-12 overflow-hidden h-full">
                            <div className="col-span-4 border-r border-slate-100 p-8 bg-slate-50/30 overflow-y-auto no-scrollbar flex flex-col gap-6">
                                {/* Header */}
                                <div>
                                    <h1 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-2">Hiring Process</h1>
                                    <p className="text-[11px] text-slate-400 font-medium leading-relaxed">Define the stages candidates go through from application to final selection.</p>
                                </div>

                                {/* Add Stage Button */}
                                <button onClick={() => {
                                    const maxId = Math.max(0, ...formData.workflow_stages.map(s => parseInt(s.id) || 0));
                                    const newStage: WorkflowStage = { id: (maxId + 1).toString(), name: `Stage ${maxId + 1}`, type: 'Technical Interview', icon: 'Zap' };
                                    setFormData(prev => ({ ...prev, workflow_stages: [...prev.workflow_stages, newStage] }));
                                }} className="w-full py-3.5 rounded-xl bg-indigo-600 text-white text-[11px] font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95">
                                    <ListPlus className="w-4 h-4" />
                                    Add Stage
                                </button>

                                {/* Stage Stats */}
                                <div className="bg-white rounded-xl border border-slate-200 p-4 text-center shadow-sm">
                                    <div className="text-2xl font-black text-indigo-600">{formData.workflow_stages.length}</div>
                                    <div className="text-[10px] font-bold text-slate-400 mt-0.5 uppercase tracking-wide">Total Stages</div>
                                </div>

                                {/* Stage Types Guide */}
                                <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4 space-y-3">
                                    <p className="text-[11px] font-bold text-slate-600 uppercase tracking-wider">Stage Types</p>
                                    {[
                                        { type: 'Screening', color: 'bg-blue-50 text-blue-600', desc: 'Initial candidate filtering' },
                                        { type: 'Aptitude', color: 'bg-purple-50 text-purple-600', desc: 'Cognitive & reasoning tests' },
                                        { type: 'Coding', color: 'bg-orange-50 text-orange-600', desc: 'Technical coding assessment' },
                                        { type: 'Tech Interview', color: 'bg-teal-50 text-teal-600', desc: 'Deep technical evaluation' },
                                        { type: 'HR Interview', color: 'bg-rose-50 text-rose-600', desc: 'Culture & fit discussion' },
                                        { type: 'Final Selection', color: 'bg-emerald-50 text-emerald-600', desc: 'Final hiring decision' },
                                    ].map(item => (
                                        <div key={item.type} className="flex items-center gap-3">
                                            <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${item.color} shrink-0 w-20 text-center`}>{item.type}</span>
                                            <span className="text-[11px] text-slate-400 font-medium">{item.desc}</span>
                                        </div>
                                    ))}
                                </div>


                            </div>
                            <div className="col-span-8 p-8 overflow-y-auto no-scrollbar flex flex-col items-center">
                                <div className="w-full max-w-lg space-y-3 pb-10">
                                    {formData.workflow_stages.map((node, idx) => (
                                        <div key={node.id} className="group relative flex items-center gap-4 bg-white p-3.5 rounded-xl border border-slate-100 shadow-sm border-l-4 border-l-indigo-600 hover:shadow-lg transition-all">
                                            <div className="flex flex-col gap-1 items-center opacity-0 group-hover:opacity-100 transition-opacity absolute -left-8">
                                                <button disabled={idx === 0} onClick={() => {
                                                    const newStages = [...formData.workflow_stages];
                                                    [newStages[idx], newStages[idx - 1]] = [newStages[idx - 1], newStages[idx]];
                                                    setFormData(prev => ({ ...prev, workflow_stages: newStages }));
                                                }} className="w-6 h-6 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-300 hover:text-indigo-600 disabled:opacity-10 transition-all"><ChevronUp className="w-4 h-4" /></button>
                                                <button disabled={idx === formData.workflow_stages.length - 1} onClick={() => {
                                                    const newStages = [...formData.workflow_stages];
                                                    [newStages[idx], newStages[idx + 1]] = [newStages[idx + 1], newStages[idx]];
                                                    setFormData(prev => ({ ...prev, workflow_stages: newStages }));
                                                }} className="w-6 h-6 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-300 hover:text-indigo-600 disabled:opacity-10 transition-all"><ChevronDown className="w-4 h-4" /></button>
                                            </div>
                                            <div className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center text-[10px] font-black  shrink-0 shadow-lg">#0{idx + 1}</div>
                                            <div className="flex-1 space-y-2">
                                                <input type="text" className="w-full bg-transparent border-none outline-none text-[13px] font-black text-slate-800 p-0 focus:text-indigo-600 transition-colors  " value={node.name} onChange={(e) => setFormData(prev => ({ ...prev, workflow_stages: prev.workflow_stages.map(s => s.id === node.id ? { ...s, name: e.target.value } : s) }))} />
                                                <div className="flex items-center gap-4">
                                                    <select className="bg-slate-50 border-none outline-none text-[9px] font-black text-slate-400  px-2.5 py-1 rounded-xl cursor-pointer hover:bg-slate-100 transition-all font-mono" value={node.type} onChange={(e) => setFormData(prev => ({ ...prev, workflow_stages: prev.workflow_stages.map(s => s.id === node.id ? { ...s, type: e.target.value } : s) }))}>
                                                        {STAGE_TYPES.map(t => (<option key={t.name} value={t.name}>{t.name}</option>))}
                                                    </select>
                                                </div>
                                            </div>
                                            <button onClick={() => setFormData(prev => ({ ...prev, workflow_stages: prev.workflow_stages.filter(s => s.id !== node.id) }))} className="w-8 h-8 rounded-xl hover:bg-rose-50 text-slate-200 hover:text-rose-500 transition-all flex items-center justify-center active:scale-95"><X className="w-4 h-4" /></button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            <AnimatePresence>
                {showSuccessModal && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-6">
                        <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-white w-full max-w-md rounded-2xl p-10 text-center shadow-2xl relative overflow-hidden border border-slate-100">
                            <div className="w-16 h-16 bg-emerald-500 text-white rounded-xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-emerald-500/20"><CircleCheck className="w-10 h-10" /></div>
                            <h2 className="text-2xl font-black text-slate-900 tracking-tight mb-2   leading-none">Job Created</h2>
                            <p className="text-[10px] text-slate-400 font-bold   leading-relaxed mb-8 opacity-60">The new job has been created and is now live.</p>
                            <div className="flex flex-col gap-2">
                                <button onClick={() => router.push("/enterprise/jobs")} className="w-full py-4 bg-indigo-600 text-white rounded-xl font-black text-[10px]   hover:bg-indigo-700 transition-all shadow-xl flex items-center justify-center gap-2">
                                    <LayoutDashboard className="w-4 h-4" />
                                    View Job Board
                                </button>
                                <button onClick={() => window.open(`${window.location.origin}/jobs/${createdJobId}`, '_blank')} className="w-full py-4 border border-slate-100 rounded-xl text-slate-400 font-black text-[10px]   hover:bg-slate-50 transition-all flex items-center justify-center gap-2">
                                    <Eye className="w-4 h-4" />
                                    View Job Application
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";

interface JobPosting {
    platform: string;
    status: string;
}

interface Company {
    id: string;
    name: string;
}

interface Job {
    id: string;
    title: string;
    description: string;
    location: string;
    created_at: string;
    status_id: number;
    salary_min: number;
    salary_max: number;
    experience_min: number;
    experience_max: number;
    job_type?: string;
    postings: JobPosting[];
    company_id?: string;
}

type TabStatus = "ALL" | "ACTIVE" | "DRAFTS" | "CLOSED";

export default function EnterpriseJobsPage() {
    const { token } = useAuth();
    const [jobs, setJobs] = useState<Job[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [activeTab, setActiveTab] = useState<TabStatus>("ALL");
    const [companies, setCompanies] = useState<Company[]>([]);
    const [selectedCompanyId, setSelectedCompanyId] = useState<string>("ALL");
    const [selectedLocation, setSelectedLocation] = useState<string>("ALL");
    const [selectedType, setSelectedType] = useState<string>("ALL");

    useEffect(() => {
        if (token) {
            fetchJobs();
            fetchCompanies();
        }
    }, [token]);

    const fetchCompanies = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/company/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setCompanies(data);
            }
        } catch (error) {
            console.error("Error fetching companies:", error);
        }
    };

    const fetchJobs = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                setJobs(data);
            }
        } catch (error) {
            console.error("Error fetching jobs:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const companyFilteredJobs = jobs.filter(j => selectedCompanyId === "ALL" || j.company_id === selectedCompanyId);

    const stats = {
        total: companyFilteredJobs.length,
        active: companyFilteredJobs.filter(j => j.status_id === 2).length,
        drafts: companyFilteredJobs.filter(j => j.status_id === 1).length,
        closed: companyFilteredJobs.filter(j => j.status_id === 3).length
    };

    const filteredJobs = jobs.filter(job => {
        const matchesSearch = job.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            job.location?.toLowerCase().includes(searchQuery.toLowerCase());

        const matchesTab = activeTab === "ALL" ||
            (activeTab === "ACTIVE" && job.status_id === 2) ||
            (activeTab === "DRAFTS" && job.status_id === 1) ||
            (activeTab === "CLOSED" && job.status_id === 3);

        const matchesCompany = selectedCompanyId === "ALL" || job.company_id === selectedCompanyId;
        const matchesLocation = selectedLocation === "ALL" || (job.location && job.location === selectedLocation);
        const matchesType = selectedType === "ALL" || job.job_type === selectedType;

        return matchesSearch && matchesTab && matchesCompany && matchesLocation && matchesType;
    });

    const locations = Array.from(new Set(jobs.map(j => j.location).filter(Boolean)));
    const jobTypes = Array.from(new Set(jobs.map(j => j.job_type).filter(Boolean)));

    const tabs: { id: TabStatus, label: string, count: number }[] = [
        { id: "ALL", label: "All Jobs", count: stats.total },
        { id: "ACTIVE", label: "Active", count: stats.active },
        { id: "DRAFTS", label: "Drafts", count: stats.drafts },
        { id: "CLOSED", label: "Closed", count: stats.closed },
    ];

    return (
        <div className="p-6 space-y-4 pt-2 animate-in fade-in duration-500">
            {/* Ultra-Compact Command Bar */}
            <div className="flex items-center gap-3 px-4 py-3 bg-white rounded-xl border border-slate-200 shadow-sm sticky top-0 z-30 overflow-x-auto no-scrollbar">

                {/* Search */}
                <div className="relative group min-w-[200px] flex-1">
                    <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-lg group-focus-within:text-[#7C3AED] transition-colors">search</span>
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search jobs..."
                        className="w-full bg-slate-50 border border-slate-200 rounded-xl py-2 pl-10 pr-4 text-[11px] font-bold placeholder:text-slate-400 focus:outline-none focus:ring-4 focus:ring-[#7C3AED]/5 focus:bg-white focus:border-[#7C3AED] transition-all"
                    />
                </div>

                <div className="h-6 w-px bg-slate-200 mx-1 flex-shrink-0"></div>

                {/* Company Filter */}
                <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 border border-slate-100 rounded-xl hover:bg-white hover:border-indigo-100 transition-all flex-shrink-0">
                    <span className="material-symbols-rounded text-slate-400 text-lg">corporate_fare</span>
                    <select
                        value={selectedCompanyId}
                        onChange={(e) => setSelectedCompanyId(e.target.value)}
                        className="bg-transparent text-[10px] font-black text-slate-600  tracking-tight outline-none cursor-pointer pr-1"
                    >
                        <option value="ALL">All Clients</option>
                        {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                </div>

                {/* Location Filter */}
                <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 border border-slate-100 rounded-xl hover:bg-white hover:border-indigo-100 transition-all flex-shrink-0">
                    <span className="material-symbols-rounded text-slate-400 text-lg">location_on</span>
                    <select
                        value={selectedLocation}
                        onChange={(e) => setSelectedLocation(e.target.value)}
                        className="bg-transparent text-[10px] font-black text-slate-600  tracking-tight outline-none cursor-pointer pr-1"
                    >
                        <option value="ALL">All Locations</option>
                        {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
                    </select>
                </div>

                {/* Type Filter */}
                <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 border border-slate-100 rounded-xl hover:bg-white hover:border-indigo-100 transition-all flex-shrink-0">
                    <span className="material-symbols-rounded text-slate-400 text-lg">category</span>
                    <select
                        value={selectedType}
                        onChange={(e) => setSelectedType(e.target.value)}
                        className="bg-transparent text-[10px] font-black text-slate-600  tracking-tight outline-none cursor-pointer pr-1"
                    >
                        <option value="ALL">All Types</option>
                        {jobTypes.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                </div>

                {/* Status Filter (Dropdown instead of tabs to save space) */}
                <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 border border-slate-100 rounded-xl hover:bg-white hover:border-indigo-100 transition-all flex-shrink-0">
                    <span className="material-symbols-rounded text-slate-400 text-lg">filter_list</span>
                    <select
                        value={activeTab}
                        onChange={(e) => setActiveTab(e.target.value as TabStatus)}
                        className="bg-transparent text-[10px] font-black text-slate-600  tracking-tight outline-none cursor-pointer pr-1"
                    >
                        {tabs.map(tab => (
                            <option key={tab.id} value={tab.id}>{tab.label} ({tab.count})</option>
                        ))}
                    </select>
                </div>

                <div className="h-6 w-px bg-slate-200 mx-1 flex-shrink-0"></div>

                <Link
                    href="/enterprise/jobs/create"
                    className="bg-[#7C3AED] text-white px-5 py-2.5 rounded-xl font-black text-[10px]   hover:bg-[#6D28D9] shadow-lg shadow-indigo-100 transition-all flex items-center gap-2 active:scale-95 whitespace-nowrap flex-shrink-0"
                >
                    <span className="material-symbols-rounded text-lg">add</span>
                    Create_Job
                </Link>
            </div>

            {/* Content Table */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col min-h-[calc(100vh-12rem)]">
                {isLoading ? (
                    <div className="p-6 space-y-4 flex-1">
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                            <div key={i} className="bg-slate-50 h-16 rounded-xl animate-pulse"></div>
                        ))}
                    </div>
                ) : filteredJobs.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-20 text-center">
                        <div className="w-16 h-16 bg-slate-50 rounded-xl flex items-center justify-center mx-auto mb-4 border border-slate-100">
                            <span className="material-symbols-rounded text-3xl text-slate-300">work_off</span>
                        </div>
                        <h3 className="text-sm font-bold text-slate-900 mb-1">No Jobs Found</h3>
                        <p className="text-xs text-slate-500 mb-6 max-w-xs mx-auto">
                            There are no jobs matching your current filters.
                        </p>
                        { (searchQuery || selectedCompanyId !== "ALL" || selectedLocation !== "ALL" || selectedType !== "ALL" || activeTab !== "ALL") && (
                            <button 
                                onClick={() => {
                                    setSearchQuery("");
                                    setSelectedCompanyId("ALL");
                                    setSelectedLocation("ALL");
                                    setSelectedType("ALL");
                                    setActiveTab("ALL");
                                }} 
                                className="px-5 py-2.5 bg-slate-900 text-white font-bold text-xs rounded-xl hover:bg-black shadow-xl shadow-slate-100 transition-all active:scale-95 flex items-center gap-2"
                            >
                                <span className="material-symbols-rounded text-lg">filter_list_off</span>
                                Reset All Filters
                            </button>
                        )}
                    </div>
                ) : (
                    <div>
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-50 border-b border-slate-100">
                                    <th className="px-6 py-4 text-xs font-bold text-slate-500  ">Job Title</th>
                                    <th className="px-6 py-4 text-xs font-bold text-slate-500  ">Location</th>
                                    <th className="px-6 py-4 text-xs font-bold text-slate-500  ">Experience</th>
                                    <th className="px-6 py-4 text-xs font-bold text-slate-500  ">Status</th>
                                    <th className="px-6 py-4 text-xs font-bold text-slate-500   text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filteredJobs.map((job, index) => (
                                    <tr key={job.id} className="hover:bg-slate-50/50 transition-all group">
                                        <td className="px-6 py-4">
                                            <Link href={`/enterprise/jobs/${job.id}`}>
                                                <span className="text-sm font-bold text-slate-800 hover:text-[#7C3AED] transition-colors cursor-pointer">{job.title}</span>
                                            </Link>
                                        </td>

                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-1.5">
                                                <span className="material-symbols-rounded text-sm text-slate-400">location_on</span>
                                                <span className="text-xs font-semibold text-slate-600">{job.location || "Remote"}</span>
                                            </div>
                                        </td>

                                        <td className="px-6 py-4">
                                            <span className="text-xs font-semibold text-slate-600 bg-slate-100 px-2.5 py-1 rounded-xl border border-slate-200">
                                                {job.experience_min || 0}-{job.experience_max || '5'} Yrs
                                            </span>
                                        </td>

                                        <td className="px-6 py-4">
                                            {job.status_id === 2 ? (
                                                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-50 text-emerald-600 text-[10px] font-bold border border-emerald-100  tracking-wide">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
                                                    Active
                                                </span>
                                            ) : job.status_id === 1 ? (
                                                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-slate-100 text-slate-500 text-[10px] font-bold border border-slate-200  tracking-wide">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-slate-400"></span>
                                                    Draft
                                                </span>
                                            ) : (
                                                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-rose-50 text-rose-500 text-[10px] font-bold border border-rose-100  tracking-wide">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-rose-400"></span>
                                                    Closed
                                                </span>
                                            )}
                                        </td>

                                        <td className="px-6 py-4 text-right">
                                            <div className="flex items-center justify-end gap-1">
                                                <Link
                                                    href={`/enterprise/jobs/${job.id}/edit`}
                                                    className="w-8 h-8 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-[#7C3AED]/5 border border-transparent hover:border-[#7C3AED]/10 flex items-center justify-center transition-all"
                                                    title="Edit Job"
                                                >
                                                    <span className="material-symbols-rounded text-lg">edit</span>
                                                </Link>
                                                {job.status_id === 2 && (
                                                    <Link
                                                        href={`/jobs/${job.id}`}
                                                        target="_blank"
                                                        className="w-8 h-8 rounded-xl text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 border border-transparent hover:border-emerald-100 flex items-center justify-center transition-all"
                                                        title="View Public Page"
                                                    >
                                                        <span className="material-symbols-rounded text-lg">open_in_new</span>
                                                    </Link>
                                                )}

                                                <div className="relative group/menu">
                                                    <button className="w-8 h-8 rounded-xl text-slate-400 hover:text-slate-700 hover:bg-slate-100 border border-transparent hover:border-slate-200 flex items-center justify-center transition-all">
                                                        <span className="material-symbols-rounded text-lg">more_vert</span>
                                                    </button>
                                                    <div className={`absolute right-0 w-48 bg-white rounded-xl shadow-xl border border-slate-100 py-2 z-50 invisible group-hover/menu:visible opacity-0 group-hover/menu:opacity-100 transition-all scale-95 group-hover/menu:scale-100 flex flex-col ${index >= filteredJobs.length - 2 ? "bottom-full mb-1 origin-bottom-right" : "top-full mt-1 origin-top-right"}`}>
                                                        <button
                                                            onClick={(e) => {
                                                                e.preventDefault();
                                                                const url = `${window.location.origin}/jobs/${job.id}`;
                                                                navigator.clipboard.writeText(url);
                                                                alert("Link copied to clipboard.");
                                                            }}
                                                            className="w-full flex items-center gap-2 px-4 py-2.5 text-xs font-semibold text-slate-600 hover:bg-slate-50 hover:text-[#7C3AED] transition-colors"
                                                        >
                                                            <span className="material-symbols-rounded text-base">link</span>
                                                            Copy Link
                                                        </button>
                                                        <div className="h-px bg-slate-50 mx-3 my-1"></div>
                                                        <button
                                                            onClick={async (e) => {
                                                                e.preventDefault();
                                                                if (confirm("Are you sure you want to delete this job?")) {
                                                                    try {
                                                                        const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/${job.id}`, {
                                                                            method: "DELETE",
                                                                            headers: {
                                                                                "Authorization": `Bearer ${token}`
                                                                            }
                                                                        });
                                                                        if (res.ok) fetchJobs();
                                                                    } catch (e) { console.error(e); }
                                                                }
                                                            }}
                                                            className="w-full flex items-center gap-2 px-4 py-2.5 text-xs font-semibold text-rose-500 hover:bg-rose-50 transition-colors"
                                                        >
                                                            <span className="material-symbols-rounded text-base">delete</span>
                                                            Delete Job
                                                        </button>
                                                    </div>
                                                </div>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { 
    Briefcase, 
    CheckCircle2, 
    FileEdit, 
    Archive, 
    LayoutGrid,
    Search,
    Building2,
    MapPin,
    Tag,
    Filter,
    Plus,
    Clock,
    Zap,
    List,
    ChevronDown,
    Building,
    Copy,
    Check
} from "lucide-react";
import { motion } from "framer-motion";

interface JobPosting {
    platform: string;
    status: string;
}

interface Company {
    id: string;
    name: string;
}

interface Job {
    id: string;
    title: string;
    description: string;
    location: string;
    created_at: string;
    status_id: number;
    salary_min: number;
    salary_max: number;
    experience_min: number;
    experience_max: number;
    job_type?: string;
    postings: JobPosting[];
    company_id?: string;
}

type TabStatus = "ALL" | "ACTIVE" | "DRAFTS" | "CLOSED";

export default function EnterpriseJobsPage() {
    const { token, canAccess } = useAuth();
    const [jobs, setJobs] = useState<Job[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [activeTab, setActiveTab] = useState<TabStatus>("ALL");
    const [companies, setCompanies] = useState<Company[]>([]);
    const [selectedCompanyId, setSelectedCompanyId] = useState<string>("ALL");
    const [selectedLocation, setSelectedLocation] = useState<string>("ALL");
    const [selectedType, setSelectedType] = useState<string>("ALL");
    const [copiedJobId, setCopiedJobId] = useState<string | null>(null);

    useEffect(() => {
        if (token) {
            fetchJobs();
            fetchCompanies();
        }
    }, [token]);

    const fetchCompanies = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/company/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data: Company[] = await res.json();
                setCompanies(data);
            }
        } catch (error) {
            console.error("Error fetching companies:", error);
        }
    };

    const fetchJobs = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            });
            if (res.ok) {
                const data: Job[] = await res.json();
                setJobs(data);
            }
        } catch (error) {
            console.error("Error fetching jobs:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const statsJobs = jobs.filter(job => {
        const matchesSearch = job.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            job.location?.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesCompany = selectedCompanyId === "ALL" || job.company_id === selectedCompanyId;
        const matchesLocation = selectedLocation === "ALL" || (job.location && job.location === selectedLocation);
        const matchesType = selectedType === "ALL" || job.job_type === selectedType;

        return matchesSearch && matchesCompany && matchesLocation && matchesType;
    });

    const stats = {
        total: statsJobs.length,
        active: statsJobs.filter(j => j.status_id === 2).length,
        drafts: statsJobs.filter(j => j.status_id === 1).length,
        closed: statsJobs.filter(j => j.status_id === 3).length
    };

    const filteredJobs = jobs.filter(job => {
        const matchesSearch = job.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            job.location?.toLowerCase().includes(searchQuery.toLowerCase());

        const matchesTab = activeTab === "ALL" ||
            (activeTab === "ACTIVE" && job.status_id === 2) ||
            (activeTab === "DRAFTS" && job.status_id === 1) ||
            (activeTab === "CLOSED" && job.status_id === 3);

        const matchesCompany = selectedCompanyId === "ALL" || job.company_id === selectedCompanyId;
        const matchesLocation = selectedLocation === "ALL" || (job.location && job.location === selectedLocation);
        const matchesType = selectedType === "ALL" || job.job_type === selectedType;

        return matchesSearch && matchesTab && matchesCompany && matchesLocation && matchesType;
    });

    const locations = Array.from(new Set(jobs.map(j => j.location).filter(Boolean)));
    const jobTypes = Array.from(new Set(jobs.map(j => j.job_type).filter(Boolean)));

    const tabs: { id: TabStatus, label: string, count: number }[] = [
        { id: "ALL", label: "All Jobs", count: stats.total },
        { id: "ACTIVE", label: "Active", count: stats.active },
        { id: "DRAFTS", label: "Drafts", count: stats.drafts },
        { id: "CLOSED", label: "Closed", count: stats.closed },
    ];

    return (
        <div className="p-8 space-y-8 animate-in fade-in duration-500 bg-[#F8FAFC] min-h-screen">
            {/* Header Section */}
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight leading-none mb-2">Job Board</h1>
                    <p className="text-sm font-medium text-slate-400">Manage your pipeline & open positions</p>
                </div>
                {canAccess("jobs:create") && (
                    <Link
                        href="/enterprise/jobs/create"
                        className="bg-[#7C3AED] text-white px-6 py-3 rounded-xl font-black text-xs hover:bg-[#6D28D9] shadow-xl shadow-indigo-100 transition-all flex items-center gap-2 active:scale-95"
                    >
                        <Plus className="w-4 h-4" />
                        Create New Position
                    </Link>
                )}
            </div>

            {/* Stat Cards Section */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {/* Total Positions */}
                <motion.div 
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    onClick={() => setActiveTab("ALL")}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all cursor-pointer group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest transition-colors group-hover:text-indigo-400">Total Positions</span>
                        <div className="w-12 h-12 rounded-xl bg-indigo-50/50 text-indigo-500 flex items-center justify-center transition-all group-hover:scale-110 group-hover:bg-indigo-50">
                            <Briefcase className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {stats.total}
                    </div>
                </motion.div>

                {/* Active Jobs */}
                <motion.div 
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ delay: 0.1 }}
                    onClick={() => setActiveTab("ACTIVE")}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all cursor-pointer group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest transition-colors group-hover:text-emerald-500">Active Jobs</span>
                        <div className="w-12 h-12 rounded-xl bg-emerald-50/50 text-emerald-500 flex items-center justify-center transition-all group-hover:scale-110 group-hover:bg-emerald-50">
                            <Zap className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {stats.active}
                    </div>
                </motion.div>

                {/* Draft Postings */}
                <motion.div 
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ delay: 0.2 }}
                    onClick={() => setActiveTab("DRAFTS")}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all cursor-pointer group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest transition-colors group-hover:text-amber-500">Draft Postings</span>
                        <div className="w-12 h-12 rounded-xl bg-amber-50/50 text-amber-500 flex items-center justify-center transition-all group-hover:scale-110 group-hover:bg-amber-50">
                            <Clock className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {stats.drafts}
                    </div>
                </motion.div>

                {/* Closed/Filled */}
                <motion.div 
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ delay: 0.3 }}
                    onClick={() => setActiveTab("CLOSED")}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all cursor-pointer group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest transition-colors group-hover:text-rose-500">Closed/Filled</span>
                        <div className="w-12 h-12 rounded-xl bg-rose-50/50 text-rose-500 flex items-center justify-center transition-all group-hover:scale-110 group-hover:bg-rose-50">
                            <CheckCircle2 className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {stats.closed}
                    </div>
                </motion.div>
            </div>

            {/* Filter Bar */}
            <div className="flex items-center gap-4">
                {/* Search Bar */}
                <div className="flex-1 relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-[#7C3AED] transition-colors" />
                    <input 
                        type="text" 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search by title, location or keywords..."
                        className="w-full bg-white border border-slate-100 rounded-2xl py-3.5 pl-12 pr-4 text-sm font-semibold text-slate-700 placeholder:text-slate-400 focus:outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-[#7C3AED] transition-all shadow-sm"
                    />
                </div>

                {/* Grid/List Toggle */}
                <div className="flex items-center p-1.5 bg-slate-50 border border-slate-100 rounded-2xl">
                    <button className="w-10 h-10 flex items-center justify-center rounded-xl bg-white text-[#7C3AED] shadow-sm">
                        <LayoutGrid className="w-5 h-5" />
                    </button>
                    <button className="w-10 h-10 flex items-center justify-center rounded-xl text-slate-400 hover:bg-white/50 transition-all">
                        <List className="w-5 h-5" />
                    </button>
                </div>

                {/* Dropdowns */}
                <div className="flex items-center gap-2">
                    <div className="relative">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                            <Building2 className="w-4 h-4" />
                        </div>
                        <select 
                            value={selectedCompanyId}
                            onChange={(e) => setSelectedCompanyId(e.target.value)}
                            className="bg-slate-50 border border-slate-100 rounded-2xl py-3 pl-9 pr-10 text-xs font-bold text-slate-600 outline-none appearance-none cursor-pointer hover:bg-white transition-all shadow-sm min-w-[140px]"
                        >
                            <option value="ALL">All Clients</option>
                            {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                    </div>

                    <div className="relative">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                            <Filter className="w-4 h-4" />
                        </div>
                        <select 
                            value={activeTab}
                            onChange={(e) => setActiveTab(e.target.value as TabStatus)}
                            className="bg-slate-50 border border-slate-100 rounded-2xl py-3 pl-9 pr-10 text-xs font-bold text-slate-600 outline-none appearance-none cursor-pointer hover:bg-white transition-all shadow-sm min-w-[140px]"
                        >
                            <option value="ALL">Any Status</option>
                            <option value="ACTIVE">Active</option>
                            <option value="DRAFTS">Draft</option>
                            <option value="CLOSED">Closed</option>
                        </select>
                        <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                    </div>
                </div>
            </div>

            {/* Content Table */}
            <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/20 overflow-hidden min-h-[500px]">
                {isLoading ? (
                    <div className="p-8 space-y-4">
                        {[1, 2, 3, 4, 5].map(i => (
                            <div key={i} className="h-16 bg-slate-50 rounded-2xl animate-pulse" />
                        ))}
                    </div>
                ) : filteredJobs.length === 0 ? (
                    <div className="flex flex-col items-center justify-center p-20 text-center">
                        <div className="w-20 h-20 bg-slate-50 rounded-3xl flex items-center justify-center mb-6">
                            <Briefcase className="w-10 h-10 text-slate-300" />
                        </div>
                        <h3 className="text-xl font-black text-slate-900 mb-2">No jobs available</h3>
                        <p className="text-slate-500 max-w-xs mx-auto mb-8">Try adjusting your filters or search terms to find what you&apos;re looking for.</p>
                        <button onClick={() => { setSearchQuery(""); setActiveTab("ALL"); setSelectedCompanyId("ALL"); }} className="px-6 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm">Clear All Filters</button>
                    </div>
                ) : (
                    <table className="w-full border-collapse">
                        <thead>
                            <tr className="bg-slate-50/50">
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Position Name</th>
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Location</th>
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Experience</th>
                                <th className="px-6 py-4 text-left text-[11px] font-black text-slate-400 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-4 text-right text-[11px] font-black text-slate-400 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                            {filteredJobs.map((job, index) => (
                                <tr key={job.id} className="hover:bg-slate-50/30 transition-all group">
                                    <td className="px-6 py-5">
                                        <Link href={`/enterprise/jobs/${job.id}`}>
                                            <div className="flex flex-col">
                                                <span className="text-sm font-black text-slate-900 group-hover:text-[#7C3AED] transition-all cursor-pointer">{job.title}</span>
                                                <span className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-tight">#{job.id.substring(0, 8)}</span>
                                            </div>
                                        </Link>
                                    </td>
                                    <td className="px-6 py-5">
                                        <div className="flex items-center gap-2 text-slate-500">
                                            <MapPin className="w-4 h-4" />
                                            <span className="text-xs font-bold">{job.location || "Remote"}</span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-5">
                                        <span className="text-[11px] font-black text-slate-600 bg-slate-100 px-3 py-1.5 rounded-lg border border-slate-200">
                                            {job.experience_min || 0}-{job.experience_max || '5'} YRS
                                        </span>
                                    </td>
                                    <td className="px-6 py-5">
                                        {job.status_id === 2 ? (
                                            <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-emerald-50 text-emerald-600 text-[10px] font-black border border-emerald-100">
                                                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
                                                ACTIVE
                                            </span>
                                        ) : job.status_id === 1 ? (
                                            <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-slate-50 text-slate-500 text-[10px] font-black border border-slate-200">
                                                <span className="w-1.5 h-1.5 bg-slate-400 rounded-full"></span>
                                                DRAFT
                                            </span>
                                        ) : (
                                            <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-rose-50 text-rose-500 text-[10px] font-black border border-rose-100">
                                                <span className="w-1.5 h-1.5 bg-rose-500 rounded-full"></span>
                                                CLOSED
                                            </span>
                                        )}
                                    </td>
                                    <td className="px-6 py-5 text-right">
                                        <div className="flex items-center justify-end gap-3">
                                            {/* Copy Link Button */}
                                            <button 
                                                onClick={async () => {
                                                    const url = `${window.location.origin}/jobs/${job.id}`;
                                                    try {
                                                        if (navigator.clipboard && window.isSecureContext) {
                                                            await navigator.clipboard.writeText(url);
                                                        } else {
                                                            const textArea = document.createElement("textarea");
                                                            textArea.value = url;
                                                            textArea.style.position = "fixed";
                                                            textArea.style.left = "-9999px";
                                                            document.body.appendChild(textArea);
                                                            textArea.select();
                                                            document.execCommand("copy");
                                                            textArea.remove();
                                                        }
                                                        setCopiedJobId(job.id);
                                                        setTimeout(() => setCopiedJobId(null), 2000);
                                                    } catch (err) {
                                                        console.error("Failed to copy: ", err);
                                                    }
                                                }}
                                                className={`w-9 h-9 flex items-center justify-center rounded-xl transition-all border border-transparent ${copiedJobId === job.id ? "bg-emerald-50 text-emerald-600 border-emerald-100" : "text-slate-400 hover:bg-slate-50 hover:text-slate-600 hover:border-slate-200"}`}
                                                title="Copy JD Link"
                                            >
                                                {copiedJobId === job.id ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                                            </button>

                                            {canAccess("jobs:update") && (
