"use client";

import { useAuth } from "@/context/AuthContext";
import { useRouter, usePathname } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import Image from "next/image";

export default function EnterprisePortalLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const { role, token, user, isLoading, logout, permissions, canAccess } = useAuth();
    const router = useRouter();
    const pathname = usePathname();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    // List of allowed roles for the Enterprise Portal
    const ALLOWED_ENTERPRISE_ROLES = ["ADMIN", "RECRUITER", "SUPER_ADMIN", "CONSULTANCY", "RESTRICTED_ACCESS"];

    // Skip layout for login, portal and assessment pages
    const isLoginPage = 
        pathname === "/enterprise/login" || 
        pathname === "/enterprise/login/" || 
        pathname.startsWith("/enterprise/assessments-360/portal") ||
        pathname.startsWith("/enterprise/surveys/fill") ||
        pathname.startsWith("/enterprise/ai-training/portal") ||
        (/^\/enterprise\/assessments-360\/[0-9a-f-]{36}$/i).test(pathname);

    useEffect(() => {
        if (!isLoading && !isLoginPage) {
            // 1. Check basic authentication
            if (!role || !token) {
                router.push("/enterprise/login");
                return;
            } 
            
            // 2. Check Role Whitelist
            if (!ALLOWED_ENTERPRISE_ROLES.includes(role)) {
                console.warn(`[AUTH] Unauthorized access attempt. Role: "${role}" is not in whitelist:`, ALLOWED_ENTERPRISE_ROLES);
                router.push("/enterprise/login?error=unauthorized");
                return;
            }

            // 3. Granular Route Guard
            // Define mapping of route prefixes to required permissions
            const routePermissions: Record<string, string> = {
                "/enterprise/jobs": "jobs:read",
                "/enterprise/candidates": "candidates:read",
                "/enterprise/communication": "communications:read",
                "/enterprise/automation": "automation:read",
                "/enterprise/employees": "employees:read",
                "/enterprise/projects": "projects:read",
                "/enterprise/tasks": "tasks:read",
                "/enterprise/assessments-360": "assessments:read",
                "/enterprise/surveys": "surveys:read",
                "/enterprise/team": "organization:moderate",
                "/enterprise/ai-training": "ai_training:read"
            };

            // Find matching prefix
            const matchedRoute = Object.keys(routePermissions).find(prefix => pathname.startsWith(prefix));
            if (matchedRoute && !canAccess(routePermissions[matchedRoute])) {
                console.warn(`[AUTH] Access Denied for route: ${pathname}. Missing permission: ${routePermissions[matchedRoute]}`);
                router.push("/enterprise/dashboard?error=access_denied");
                return;
            }

            console.log(`[AUTH] Authorized access granted for role: ${role}`);
        }
    }, [role, token, isLoading, router, pathname, isLoginPage, canAccess]);

    useEffect(() => {
        setIsMobileMenuOpen(prev => prev ? false : prev);
    }, [pathname]);

    if (isLoginPage) {
        return <>{children}</>;
    }

    if (isLoading || !role) {
        return (
            <div className="flex justify-center items-center h-screen bg-slate-50">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-slate-500 font-medium">Loading Enterprise Portal...</p>
                </div>
            </div>
        );
    }


    const navGroups = [
        {
            title: "Hiring Hub",
            items: [
                { label: "Dashboard", icon: "grid_view", path: "/enterprise/dashboard", permission: "organization:read" },
                { label: "Jobs", icon: "business_center", path: "/enterprise/jobs", permission: "jobs:read" },
                { label: "Pipeline", icon: "filter_list", path: "/enterprise/candidates/kanban", permission: "candidates:read" },
                { label: "Mail", icon: "alternate_email", path: "/enterprise/communication", permission: "communications:read" },
            ]
        },
        {
            title: "Talent Search",
            items: [
                { label: "Candidate Search", icon: "person_search", path: "/enterprise/candidates", permission: "candidates:read" },
            ]
        },
        {
            title: "Automation",
            items: [
                { label: "Automation Canvas", icon: "account_tree", path: "/enterprise/automation", permission: "automation:read" },
                { label: "Mail Automation", icon: "mark_email_unread", path: "/enterprise/automation/mail", permission: "communications:moderate" },
                { label: "Assessment Automation", icon: "psychology", path: "/enterprise/automation/assessment", permission: "assessments:moderate" },
                { label: "Interview Automation", icon: "event_available", path: "/enterprise/automation/interview", permission: "interviews:moderate" },
                { label: "Onboarding Automation", icon: "person_add", path: "/enterprise/automation/onboarding", permission: "onboarding:moderate" },
            ]
        },
        {
            title: "Post Onboarding",
            items: [
                { label: "Employees", icon: "badge", path: "/enterprise/employees", permission: "employees:read" },
                { label: "Projects", icon: "account_tree", path: "/enterprise/projects", permission: "projects:read" },
                { label: "Tasks", icon: "checklist", path: "/enterprise/tasks", permission: "tasks:read" },
                { label: "360 Assessments", icon: "360", path: "/enterprise/assessments-360", permission: "assessments:read" },
                { label: "HR Surveys", icon: "poll", path: "/enterprise/surveys", permission: "surveys:read" },
            ]
        },
        {
            title: "AI & Training",
            items: [
                { label: "Scenario Architect", icon: "architecture", path: "/enterprise/ai-training/scenarios", permission: "ai_training:read" },
            ]
        },
        {
            title: "General",
            items: [
                { label: "Settings", icon: "business", path: "/enterprise/settings", permission: "organization:read" },
                { label: "Team", icon: "groups", path: "/enterprise/team", permission: "organization:moderate" },
                { label: "Permissions", icon: "security", path: "/enterprise/settings/roles", permission: "organization:moderate" },
                { label: "Partners", icon: "corporate_fare", path: "/enterprise/companies", permission: "platform:read" },
                { label: "Email Templates", icon: "mail", path: "/enterprise/settings/templates", permission: "communications:read" },
                { label: "Assessment Templates", icon: "quiz", path: "/enterprise/settings/assessments", permission: "assessments:read" },
                { label: "Interview Templates", icon: "psychology", path: "/enterprise/settings/interview-templates", permission: "interviews:read" },
                { label: "Onboarding Hub", icon: "person_add", path: "/enterprise/onboarding", permission: "onboarding:read" },
                { label: "Onboarding Templates", icon: "rule", path: "/enterprise/settings/onboarding-templates", permission: "onboarding:read" },
            ]
        }
    ];

    // Filter navGroups and items based on permissions
    const accessibleNavGroups = navGroups
        .map(group => ({
            ...group,
            items: group.items.filter(item => canAccess(item.permission))
        }))
        .filter(group => group.items.length > 0);

    const navLinkClass = (path: string) => {
        // Collect all possible navigation paths to find the most specific match
        const allPaths = accessibleNavGroups.flatMap(g => g.items.map(i => i.path));

        // A path is active if:
        // 1. It's an exact match
        // 2. The current pathname starts with this path AND there isn't a more specific registered path that also matches
        let isActive = pathname === path;

        if (!isActive && pathname.startsWith(path + "/")) {
            const hasBetterMatch = allPaths.some(p =>
                p !== path &&
                pathname.startsWith(p) &&
                p.length > path.length
            );
            if (!hasBetterMatch) {
                isActive = true;
            }
        }

        // Exception: "Candidate Search" should NOT be active if we are on "Applicant Pipeline"
        if (path === "/enterprise/candidates" && pathname.startsWith("/enterprise/candidates/kanban")) {
            isActive = false;
        }

        return `group flex items-center gap-3 px-3 py-1.5 rounded-lg transition-all duration-200 ${isActive
            ? "bg-[#7C3AED]/10 text-[#7C3AED]"
            : "text-slate-500 hover:bg-[#7C3AED]/5 hover:text-[#7C3AED]"
            }`;
    };

    return (
        <div className="flex w-full h-screen bg-[#F8FAFC] overflow-hidden font-sans">
            {/* Mobile Overlay */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-slate-900/40 z-40 md:hidden backdrop-blur-sm"
                    onClick={() => setIsMobileMenuOpen(false)}
                />
            )}

            {/* Sidebar */}
            <aside className={`
                fixed inset-y-0 left-0 z-50 w-52 bg-white border-r border-slate-100 flex flex-col transition-transform duration-300 ease-in-out md:translate-x-0 md:sticky md:top-0 md:h-screen
                ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
            `}>
                <div className="p-4 flex-1 overflow-y-auto no-scrollbar flex flex-col">
                    {/* Logo Section (Standard Student Portal Logo) */}
                    <div className="p-4 flex items-center justify-between shrink-0 mb-4 border-b border-slate-50">
                        <Link href="/enterprise/dashboard" className="flex items-center gap-2 tracking-tighter">
                            <span className="text-2xl font-black bg-gradient-to-r from-[#7C3AED] to-[#D946EF] bg-clip-text text-transparent">Croar.ai</span>
                        </Link>
                    </div>

                    {/* Navigation Groups */}
                    <nav className="space-y-4 px-1">
                        {accessibleNavGroups.map((group) => (
                            <div key={group.title}>
                                <p className="text-[11px] font-bold text-slate-400 mb-2 px-3">{group.title}</p>
                                <div className="space-y-0.5">
                                    {group.items.map((item) => (
                                        <Link key={item.path} href={item.path} className={navLinkClass(item.path)}>
                                            <span className="material-symbols-rounded text-xl">{item.icon}</span>
                                            <span className="text-[10px] font-bold whitespace-nowrap">{item.label}</span>
                                        </Link>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </nav>
                </div>

                {/* Sidebar Footer User Info (Student Portal Style) */}
                <div className="p-3 border-t border-slate-50 shrink-0">
                    <div className="flex items-center gap-2 mb-4 px-2">
                        <div className="w-8 h-8 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold text-xs shadow-md">
                            {user ? user.charAt(0).toUpperCase() : 'R'}
                        </div>
                        <div className="flex-1 min-w-0">
                            <p className="text-[10px] font-bold text-slate-700 truncate">{user || "recruiter@techcorp.com"}</p>
                            <p className="text-[10px] font-medium text-slate-400">{role ? role.charAt(0) + role.slice(1).toLowerCase() : 'Recruiter'}</p>
                        </div>
                    </div>

                    <button
                        onClick={logout}
                        className="w-full flex items-center gap-2.5 px-3 py-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-all duration-200 group"
                    >
                        <span className="material-symbols-rounded text-slate-500 text-[20px]">logout</span>
                        <span className="text-[10px] font-bold">Logout</span>
                    </button>
                </div>
            </aside>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden w-full">
                {/* Mobile Top Bar */}
                <header className="h-16 bg-white border-b border-slate-100 flex items-center justify-between px-6 md:hidden shrink-0">
                    <div className="flex items-center gap-3">
                        <button
                            onClick={() => setIsMobileMenuOpen(true)}
                            className="w-10 h-10 rounded-xl hover:bg-slate-50 flex items-center justify-center transition-colors"
                        >
                            <span className="material-icons-outlined text-slate-600">menu</span>
                        </button>
                        <span className="text-xl font-black bg-gradient-to-r from-[#7C3AED] to-[#D946EF] bg-clip-text text-transparent tracking-tighter">Croar.ai</span>
                    </div>
                </header>

                {/* Content */}
                <main className="flex-1 w-full overflow-y-auto bg-[#F8FAFC] custom-scrollbar">
                    {children}
                </main>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { format } from "date-fns";

interface OnboardingDocument {
    id: string;
    name: string;
    status: string;
    file_path?: string;
}

interface OnboardingActivity {
    id: string;
    action: string;
    description?: string;
    performed_by: string;
    timestamp: string;
}

interface OnboardingField {
    name: string;
    label: string;
    type: string;
}

interface OnboardingSection {
    id: string;
    title: string;
    fields: OnboardingField[];
}

interface Onboarding {
    id: string;
    onboarding_code: string;
    initiation_date: string;
    status: { name: string };
    application: {
        candidate_id: string;
        candidate: {
            full_name: string;
        };
    };
    template: {
        form_config: {
            sections: OnboardingSection[];
        };
    };
    form_data: Record<string, any>;
    documents: OnboardingDocument[];
    activities: OnboardingActivity[];
}

export default function OnboardingDetailsPage() {
    const params = useParams();
    const router = useRouter();
    const { id } = params;
    const { token, canAccess } = useAuth();

    const [onboarding, setOnboarding] = useState<Onboarding | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isProcessing, setIsProcessing] = useState(false);
    const [activeTab, setActiveTab] = useState("Employee");
    const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set(["Job Information", "Personal Information"]));

    const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
    const [rejectReason, setRejectReason] = useState("");
    const [rejectedDocIds, setRejectedDocIds] = useState<Set<string>>(new Set());
    const [rejectedFieldNames, setRejectedFieldNames] = useState<Set<string>>(new Set());

    useEffect(() => {
        if (token && id) {
            fetchOnboardingDetails();
        }
    }, [token, id]);

    const fetchOnboardingDetails = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/${id}`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setOnboarding(data);
            }
        } catch (error) {
            console.error("Error fetching onboarding details:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const toggleSection = (title: string) => {
        setExpandedSections(prev => {
            const next = new Set(prev);
            if (next.has(title)) next.delete(title);
            else next.add(title);
            return next;
        });
    };

    const handleApproveHire = async () => {
        if (!window.confirm("Are you sure you want to approve this onboarding and hire the candidate?")) return;
        
        setIsProcessing(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/${id}/approve`, {
                method: "POST",
                headers: { 
                    "Authorization": `Bearer ${token}`,
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ notes: "Approved via dashboard" })
            });
            if (res.ok) {
                alert("Candidate has been hired successfully!");
                fetchOnboardingDetails();
            } else {
                const err = await res.json();
                alert(`Error: ${err.detail || "Failed to approve"}`);
            }
        } catch (error) {
            console.error("Error approving onboarding:", error);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleConfirmResubmit = async () => {
        if (!rejectReason.trim()) {
            alert("Please provide a reason for the correction request.");
            return;
        }

        setIsProcessing(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/${id}/resubmit`, {
                method: "POST",
                headers: { 
                    "Authorization": `Bearer ${token}`,
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ 
                    reason: rejectReason,
                    rejected_document_ids: Array.from(rejectedDocIds),
                    rejected_fields: Array.from(rejectedFieldNames)
                })
            });
            if (res.ok) {
                alert("Correction request sent to candidate.");
                setIsRejectModalOpen(false);
                setRejectReason("");
                setRejectedDocIds(new Set());
                setRejectedFieldNames(new Set());
                fetchOnboardingDetails();
            } else {
                const err = await res.json();
                alert(`Error: ${err.detail || "Failed to request correction"}`);
            }
        } catch (error) {
            console.error("Error requesting correction:", error);
        } finally {
            setIsProcessing(false);
        }
    };

    const toggleDocRejection = (docId: string) => {
        setRejectedDocIds(prev => {
            const next = new Set(prev);
            if (next.has(docId)) next.delete(docId);
            else next.add(docId);
            return next;
        });
    };

    const toggleFieldRejection = (fieldName: string) => {
        setRejectedFieldNames(prev => {
            const next = new Set(prev);
            if (next.has(fieldName)) next.delete(fieldName);
            else next.add(fieldName);
            return next;
        });
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-screen bg-slate-50/30">
                <div className="w-10 h-10 border-4 border-[#7C3AED] border-t-transparent rounded-full animate-spin"></div>
            </div>
        );
    }

    if (!onboarding) return null;

    const tabs = ["Employee", "Documents", "Activity Log"];

    // Combine template sections with potentially missing data sections
    const templateSections = onboarding.template?.form_config?.sections || [];
    
    return (
        <div className="min-h-screen bg-[#F8F9FA] font-sans">
            {/* Top Navigation Bar */}
            <div className="bg-white border-b border-slate-100 px-8 py-4 flex items-center justify-between shadow-sm">
                <div className="flex items-center gap-4">
                    <button 
                        onClick={() => router.back()} 
                        className="w-10 h-10 flex items-center justify-center hover:bg-slate-50 rounded-xl text-slate-400 transition-all border border-transparent hover:border-slate-200"
                    >
                        <span className="material-symbols-rounded">arrow_back</span>
                    </button>
                    <h1 className="text-xl font-black text-slate-800 tracking-tight">Onboarding</h1>
                </div>
                <div className="flex items-center gap-3">
                    {canAccess("onboarding:moderate") && onboarding.status?.name !== 'Completed' && (
                        <>
                            <button 
                                onClick={() => setIsRejectModalOpen(true)}
                                disabled={isProcessing}
                                className="px-5 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 text-xs font-black   hover:bg-slate-50 transition-all disabled:opacity-50"
                            >
                                Reject / Request Correction
                            </button>
                            <button 
                                onClick={handleApproveHire}
                                disabled={isProcessing}
                                className="px-5 py-2 bg-[#7C3AED] hover:bg-[#6D28D9] text-white rounded-xl text-xs font-black   shadow-lg shadow-[#7C3AED]/20 transition-all disabled:opacity-50"
                            >
                                {isProcessing ? "Processing..." : "Approve & Hire"}
                            </button>
                        </>
                    )}
                    {canAccess("employees:create") && onboarding.status?.name === 'Completed' && (
                        <button 
                            onClick={() => router.push(`/enterprise/employees/add?candidateId=${onboarding.application?.candidate_id}`)}
                            className="px-5 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl text-xs font-black   shadow-lg shadow-emerald-200 transition-all flex items-center gap-2"
                        >
                            <span className="material-symbols-rounded text-sm">badge</span>
                            Convert to Employee
                        </button>
                    )}
                </div>
            </div>

            <div className="max-w-5xl mx-auto p-8 space-y-6">
                {/* Profile Header Card */}
                <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50/50 rounded-full blur-3xl -mr-32 -mt-32"></div>
                    
                    <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-4">
                        <div className="flex items-center gap-5">
                            <div className="w-14 h-14 rounded-xl bg-indigo-600 flex items-center justify-center text-white text-xl font-black shadow-lg shadow-indigo-200">
                                {onboarding.application?.candidate?.full_name?.[0]?.toUpperCase() || "C"}
                            </div>
                            <div>
                                <h2 className="text-xl font-black text-slate-900 tracking-tight">
                                    {onboarding.application?.candidate?.full_name} <span className="text-slate-300 font-medium ml-1.5">({onboarding.onboarding_code})</span>
                                </h2>
                                <div className="flex items-center gap-2 mt-1">
                                    <span className={`px-2 py-0.5 rounded-full text-[9px] font-black   ${
                                        onboarding.status?.name === 'Completed' ? 'bg-emerald-100 text-emerald-600' :
                                        onboarding.status?.name === 'Action Required' || onboarding.status?.name === 'Rejected' ? 'bg-rose-100 text-rose-600' :
                                        'bg-blue-100 text-blue-600'
                                    }`}>
                                        {onboarding.status?.name}
                                    </span>
                                </div>
                            </div>
                        </div>
                        <div className="flex flex-col items-end gap-1 text-right">
                            <span className="text-[9px] font-black text-slate-400  tracking-[0.2em]">Initiated On</span>
                            <span className="text-xs font-black text-slate-700">{format(new Date(onboarding.initiation_date), "MMMM dd, yyyy")}</span>
                        </div>
                    </div>

                    {/* Horizontal Tabs */}
                    <div className="flex items-center gap-8 mt-8 border-b border-slate-100 relative z-10">
                        {tabs.map(tab => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`pb-4 text-xs font-black  tracking-[0.1em] transition-all relative ${activeTab === tab ? "text-[#7C3AED]" : "text-slate-400 hover:text-slate-600"}`}
                            >
                                {tab}
                                {activeTab === tab && (
                                    <motion.div 
                                        layoutId="activeTab" 
                                        className="absolute bottom-0 h-1 bg-[#7C3AED] rounded-full w-full"
                                    />
                                )}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Content Section */}
                <div className="space-y-6">
                    {activeTab === "Employee" && (
                        <div className="space-y-4">
                            {templateSections.length > 0 ? (
                                templateSections.map((section: OnboardingSection) => (
                                    <div key={section.id} className="bg-white rounded-xl border border-slate-100 shadow-sm overflow-hidden group">
                                        <button 
                                            onClick={() => toggleSection(section.title)}
                                            className="w-full px-6 py-4 flex items-center justify-between text-left hover:bg-slate-50 transition-all"
                                        >
                                            <h3 className="text-sm font-black text-slate-800 tracking-tight">{section.title}</h3>
                                            <span className={`material-symbols-rounded transition-transform duration-300 ${expandedSections.has(section.title) ? "rotate-180" : ""}`}>
                                                keyboard_arrow_down
                                            </span>
                                        </button>
                                        <AnimatePresence initial={false}>
                                            {expandedSections.has(section.title) && (
                                                <motion.div
                                                    initial={{ height: 0, opacity: 0 }}
                                                    animate={{ height: "auto", opacity: 1 }}
                                                    exit={{ height: 0, opacity: 0 }}
                                                    transition={{ duration: 0.3, ease: "easeInOut" }}
                                                >
                                                    <div className="px-8 pb-8 pt-2 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-12 gap-y-6 border-t border-slate-50">
                                                        {section.fields?.map((field: OnboardingField) => (
                                                            <div key={field.name} className="space-y-1 relative group/field">
                                                                <div className="flex items-center justify-between">
                                                                    <p className="text-[10px] font-black text-slate-400  ">{field.label}</p>
                                                                    {canAccess("onboarding:moderate") && onboarding.status?.name !== 'Completed' && (
                                                                        <button 
                                                                            onClick={() => toggleFieldRejection(field.name)}
                                                                            className={`w-6 h-6 flex items-center justify-center rounded-xl transition-all opacity-0 group-hover/field:opacity-100 ${
                                                                                rejectedFieldNames.has(field.name) 
                                                                                    ? "bg-rose-500 text-white opacity-100" 
                                                                                    : "bg-slate-50 text-slate-400 hover:bg-rose-100 hover:text-rose-600"
                                                                            }`}
                                                                            title={rejectedFieldNames.has(field.name) ? "Selected for correction" : "Request correction for this field"}
                                                                        >
                                                                            <span className="material-symbols-rounded text-xs">{rejectedFieldNames.has(field.name) ? "close" : "edit_square"}</span>
                                                                        </button>
                                                                    )}
                                                                </div>
                                                                <p className={`text-sm font-bold break-words ${rejectedFieldNames.has(field.name) ? "text-rose-600" : "text-slate-800"}`}>
                                                                    {(() => {
                                                                        const val = onboarding.form_data?.[section.id]?.[field.name] || 
                                                                                    onboarding.form_data?.[field.name];
                                                                        
                                                                        if (!val) return <span className="text-slate-200  font-medium">Not provided</span>;
                                                                        
                                                                        if (field.type === 'file') {
                                                                            return (
                                                                                <button 
                                                                                    onClick={() => window.open(`${BACKEND_URL.replace('/api/v1', '')}/${val.replace(/\\/g, '/')}`, '_blank')}
                                                                                    className="flex items-center gap-2 text-[#7C3AED] hover:underline"
                                                                                >
                                                                                    <span className="material-symbols-rounded text-sm">attach_file</span>
                                                                                    <span className="text-xs">View Upload</span>
                                                                                </button>
                                                                            );
                                                                        }
                                                                        
                                                                        return String(val);
                                                                    })()}
                                                                </p>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </motion.div>
                                            )}
                                        </AnimatePresence>
                                    </div>
                                ))
                            ) : (
                                <div className="text-center py-20 bg-white rounded-xl border border-dashed border-slate-200">
                                    <span className="material-symbols-rounded text-4xl text-slate-200 mb-4">description</span>
                                    <p className="text-slate-400 text-xs font-black  ">No Profile Data Available</p>
                                </div>
                            )}
                        </div>
                    )}

                    {activeTab === "Documents" && (
                         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {onboarding.documents?.map((doc: OnboardingDocument) => (
                                <div key={doc.id} className="bg-white border border-slate-100 rounded-2xl p-6 flex items-center justify-between hover:border-[#7C3AED]/30 hover:shadow-xl hover:shadow-[#7C3AED]/5 transition-all group">
                                    <div className="flex items-center gap-4 text-left">
                                        <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${doc.status === "Received" ? "bg-emerald-50 text-emerald-600" : "bg-slate-50 text-slate-400"}`}>
                                            <span className="material-symbols-rounded">{doc.status === "Received" ? "check_circle" : "file_present"}</span>
                                        </div>
                                        <div>
                                            <h4 className="text-sm font-black text-slate-800">{doc.name}</h4>
                                            <p className={`text-[10px] font-black   ${doc.status === "Received" ? "text-emerald-500" : "text-slate-400"}`}>{doc.status}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        {canAccess("onboarding:moderate") && onboarding.status?.name !== 'Completed' && doc.status === "Received" && (
                                            <button 
                                                onClick={() => toggleDocRejection(doc.id)}
                                                className={`w-10 h-10 flex items-center justify-center rounded-xl border transition-all ${
                                                    rejectedDocIds.has(doc.id) 
                                                        ? "bg-rose-500 border-rose-500 text-white" 
                                                        : "bg-white border-slate-200 text-rose-500 hover:bg-rose-50"
                                                }`}
                                                title={rejectedDocIds.has(doc.id) ? "Marked for rejection" : "Reject this document"}
                                            >
                                                <span className="material-symbols-rounded text-lg">
                                                    {rejectedDocIds.has(doc.id) ? "close" : "error"}
                                                </span>
                                            </button>
                                        )}
                                        {doc.status === "Received" && doc.file_path && (
                                            <button 
                                                onClick={() => window.open(`${BACKEND_URL.replace('/api/v1', '')}/${doc.file_path.replace(/\\/g, '/')}`, '_blank')}
                                                className="w-10 h-10 flex items-center justify-center rounded-xl bg-[#7C3AED]/5 text-[#7C3AED] hover:bg-[#7C3AED] hover:text-white transition-all shadow-sm"
                                            >
                                                <span className="material-symbols-rounded text-lg">visibility</span>
                                            </button>
                                        )}
                                    </div>
                                </div>
                            ))}
                         </div>
                    )}

                    {activeTab === "Activity Log" && (
                        <div className="bg-white border border-slate-100 rounded-2xl p-10 shadow-sm relative overflow-hidden">
                            <div className="space-y-8 relative before:absolute before:left-5 before:top-2 before:bottom-2 before:w-px before:bg-slate-100">
                                {onboarding.activities?.map((act: OnboardingActivity) => (
                                    <div key={act.id} className="relative pl-12 group/act">
                                        <div className="absolute left-0 top-1.5 w-10 h-10 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 z-10 transition-colors group-hover/act:border-[#7C3AED] group-hover/act:text-[#7C3AED]">
                                            <span className="material-symbols-rounded text-base">history</span>
                                        </div>
                                        <div>
                                            <h4 className="text-sm font-black text-slate-800">{act.action}</h4>
                                            <p className="text-xs font-medium text-slate-400 mt-1">{act.description || `Action performed by ${act.performed_by}`}</p>
                                            <p className="text-[10px] font-black text-[#7C3AED] bg-[#7C3AED]/5 inline-block px-2 py-1 rounded-xl   mt-3">
                                                {act.timestamp ? format(new Date(act.timestamp), "MMM dd, HH:mm") : "N/A"}
                                            </p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Reject/Correction Modal */}
            <AnimatePresence>
                {isRejectModalOpen && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                        <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setIsRejectModalOpen(false)}
                            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
                        />
                        <motion.div 
                            initial={{ opacity: 0, scale: 0.95, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 20 }}
                            className="bg-white rounded-2xl w-full max-w-lg overflow-hidden shadow-2xl relative z-10"
                        >
                            <div className="p-8">
                                <div className="flex items-center justify-between mb-6">
                                    <h3 className="text-xl font-black text-slate-900 tracking-tight">Request Correction</h3>
                                    <button 
                                        onClick={() => setIsRejectModalOpen(false)}
                                        className="w-10 h-10 flex items-center justify-center hover:bg-slate-50 rounded-xl text-slate-400"
                                    >
                                        <span className="material-symbols-rounded">close</span>
                                    </button>
                                </div>

                                <div className="space-y-6">
                                    {(rejectedDocIds.size > 0 || rejectedFieldNames.size > 0) && (
                                        <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl max-h-48 overflow-y-auto">
                                            {rejectedDocIds.size > 0 && (
                                                <div className="mb-4">
                                                    <p className="text-[10px] font-black text-rose-600   mb-2">Documents Rejection ({rejectedDocIds.size})</p>
                                                    <div className="flex flex-wrap gap-2">
                                                        {Array.from(rejectedDocIds).map(id => {
                                                            const doc = onboarding.documents.find((d: OnboardingDocument) => d.id === id);
                                                            return (
                                                                <span key={id} className="px-3 py-1 bg-white border border-rose-200 text-rose-600 text-[10px] font-bold rounded-xl flex items-center gap-2">
                                                                    {doc?.name}
                                                                    <button onClick={() => toggleDocRejection(id)} className="material-symbols-rounded text-xs hover:text-rose-800">close</button>
                                                                </span>
                                                            );
                                                        })}
                                                    </div>
                                                </div>
                                            )}

                                            {rejectedFieldNames.size > 0 && (
                                                <div>
                                                    <p className="text-[10px] font-black text-indigo-600   mb-2">Form Fields Rejection ({rejectedFieldNames.size})</p>
                                                    <div className="flex flex-wrap gap-2">
                                                        {Array.from(rejectedFieldNames).map(name => (
                                                            <span key={name} className="px-3 py-1 bg-white border border-indigo-200 text-indigo-600 text-[10px] font-bold rounded-xl flex items-center gap-2">
                                                                {name.replace(/_/g, ' ').toUpperCase()}
                                                                <button onClick={() => toggleFieldRejection(name)} className="material-symbols-rounded text-xs hover:text-indigo-800">close</button>
                                                            </span>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    )}

                                    <div>
                                        <label className="text-[10px] font-black text-slate-400   block mb-2">Feedback / Reason for Correction</label>
                                        <textarea 
                                            value={rejectReason}
                                            onChange={(e) => setRejectReason(e.target.value)}
                                            placeholder="Explain what needs to be changed or why specific documents were rejected..."
                                            className="w-full h-32 p-4 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-800 focus:ring-2 focus:ring-[#7C3AED]/20 focus:border-[#7C3AED] outline-none transition-all resize-none"
                                        />
                                    </div>
                                </div>

                                <div className="flex gap-4 mt-8">
                                    <button 
                                        onClick={() => setIsRejectModalOpen(false)}
                                        className="flex-1 py-4 bg-slate-50 hover:bg-slate-100 text-slate-600 rounded-xl text-xs font-black   transition-all"
                                    >
                                        Cancel
                                    </button>
                                    <button 
                                        onClick={handleConfirmResubmit}
                                        disabled={isProcessing || !rejectReason.trim()}
                                        className="flex-1 py-4 bg-rose-500 hover:bg-rose-600 text-white rounded-xl text-xs font-black   shadow-lg shadow-rose-200 transition-all disabled:opacity-50"
                                    >
                                        {isProcessing ? "Sending..." : "Send Request"}
                                    </button>
                                </div>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useMemo } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { format } from "date-fns";
import { 
    User, 
    Briefcase, 
    Calendar, 
    ArrowRight, 
    Search, 
    RefreshCcw, 
    ChevronRight,
    Users,
    Activity,
    ShieldCheck,
    AlertCircle,
    UserCircle,
    ClipboardList
} from "lucide-react";

interface OnboardingStatus {
    id: number;
    name: string;
    description?: string;
}

interface Onboarding {
    id: string;
    onboarding_code: string;
    status_id: number;
    status?: OnboardingStatus;
    initiation_date: string;
    completed_at?: string;
    candidate_email?: string;
    job_title?: string;
    application?: any;
}

const getStatusColor = (statusName: string) => {
    switch (statusName) {
        case "In Progress": return "bg-indigo-50 text-indigo-700 border-indigo-200";
        case "Awaiting Confirmation": return "bg-amber-50 text-amber-700 border-amber-200";
        case "Completed": return "bg-emerald-50 text-emerald-700 border-emerald-200";
        case "Discontinued": return "bg-slate-50 text-slate-700 border-slate-200";
        case "Washed Away": return "bg-rose-50 text-rose-700 border-rose-200";
        case "Pending Approvals": return "bg-purple-50 text-purple-700 border-purple-200";
        default: return "bg-slate-50 text-slate-700 border-slate-200";
    }
};

export default function OnboardingDashboard() {
    const { token } = useAuth();
    const router = useRouter();
    const [onboardings, setOnboardings] = useState<Onboarding[]>([]);
    const [jobs, setJobs] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [selectedJobId, setSelectedJobId] = useState<string>("all");

    useEffect(() => {
        if (token) {
            fetchOnboardings();
            fetchJobs();
        }
    }, [token]);

    const fetchJobs = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/jobs/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setJobs(data);
            }
        } catch (error) {
            console.error("Error fetching jobs:", error);
        }
    };

    const fetchOnboardings = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setOnboardings(data);
            }
        } catch (error) {
            console.error("Error fetching onboardings:", error);
        } finally {
            setTimeout(() => setIsLoading(false), 800);
        }
    };

    const filteredOnboardings = useMemo(() => {
        return onboardings.filter(o => {
            const matchesSearch = o.onboarding_code.toLowerCase().includes(searchQuery.toLowerCase()) ||
                (o.application?.candidate?.full_name || "").toLowerCase().includes(searchQuery.toLowerCase());
            
            const matchesJob = selectedJobId === "all" || o.application?.job_requirement_id === selectedJobId;
            
            return matchesSearch && matchesJob;
        });
    }, [onboardings, searchQuery, selectedJobId]);

    if (isLoading) {
        return (
            <div className="p-8 lg:p-12 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-500">
                <div className="h-32 bg-slate-900 rounded-2xl relative overflow-hidden flex items-center px-10 shadow-2xl">
                    <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-white/5 rounded-xl animate-pulse" />
                        <div className="space-y-2">
                            <div className="w-48 h-6 bg-white/10 rounded-xl animate-pulse" />
                            <div className="w-32 h-3 bg-white/5 rounded-xl animate-pulse" />
                        </div>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="bg-white h-80 rounded-2xl border border-slate-100 animate-pulse shadow-sm" />
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pb-20 animate-in fade-in duration-700 relative">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">person_add</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Onboarding Hub</h1>
                        <p className="text-slate-500 text-[10px] font-medium   ">Talent integration and workflows</p>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row items-center gap-3">
                    <div className="flex bg-slate-50 border border-slate-100 rounded-xl p-1 shrink-0">
                        <select 
                            value={selectedJobId}
                            onChange={(e) => setSelectedJobId(e.target.value)}
                            className="bg-transparent border-none py-1.5 px-3 text-[10px] font-bold text-slate-600   outline-none cursor-pointer appearance-none min-w-[120px]"
                        >
                            <option value="all">All Pipelines</option>
                            {jobs.map(job => (
                                <option key={job.id} value={job.id}>{job.title}</option>
                            ))}
                        </select>
                    </div>

                    <div className="relative group shrink-0">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-3.5 h-3.5 group-focus-within:text-[#7C3AED] transition-colors" />
                        <input
                            type="text"
                            placeholder="Find candidate..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="bg-slate-50 border border-slate-100 rounded-xl py-2 pl-9 pr-4 text-[11px] font-bold text-slate-900 placeholder:text-slate-400 focus:outline-none focus:bg-white focus:border-[#7C3AED] transition-all w-full sm:w-40"
                        />
                    </div>

                    <button 
                        onClick={fetchOnboardings}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 hover:border-violet-100 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {/* Hub List */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                <AnimatePresence mode="popLayout">
                    {filteredOnboardings.map((ob, i) => (
                        <motion.div 
                            layout
                            key={ob.id}
                            className="group bg-white rounded-xl border border-slate-200/60 shadow-sm hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-1 transition-all duration-300 relative overflow-hidden cursor-pointer"
                            onClick={() => router.push(`/enterprise/onboarding/${ob.id}`)}
                        >
                            <div className="p-6 pb-2 space-y-6">
                                <div className="flex justify-between items-start">
                                    <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                                        <User className="w-6 h-6 stroke-[1.5]" />
                                    </div>
                                    <div className="flex flex-col items-end gap-2 text-right">
                                        <span className="text-[10px] font-bold text-indigo-500 bg-indigo-50 px-2.5 py-1 rounded-xl  ">
                                            {ob.onboarding_code}
                                        </span>
                                        {ob.status && (
                                            <span className={`text-[9px] font-bold px-3 py-1 rounded-full border   ${getStatusColor(ob.status.name)}`}>
                                                {ob.status.name}
                                            </span>
                                        )}
                                    </div>
                                </div>

                                <div className="space-y-1">
                                    <h3 className="text-xl font-bold text-slate-900 group-hover:text-indigo-600 transition-colors truncate">
                                        {ob.application?.candidate?.full_name || "Unknown Candidate"}
                                    </h3>
                                    <p className="text-sm text-slate-400 font-medium truncate">
                                        {ob.candidate_email}
                                    </p>
                                </div>

                                <div className="bg-slate-50/50 rounded-xl p-4 space-y-4 border border-slate-100/50 group-hover:bg-indigo-50/30 group-hover:border-indigo-100/50 transition-all">
                                    <div className="flex items-center gap-4">
                                        <div className="w-9 h-9 rounded-xl bg-white flex items-center justify-center shadow-sm border border-slate-100">
                                            <Briefcase className="w-4 h-4 text-indigo-500" />
                                        </div>
                                        <div>
                                            <p className="text-xs font-bold text-slate-800 leading-none truncate max-w-[140px]">
                                                {ob.job_title || "Unspecified Role"}
                                            </p>
                                            <p className="text-[9px] font-bold text-slate-400   mt-1">Hired Role</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <div className="w-9 h-9 rounded-xl bg-white flex items-center justify-center shadow-sm border border-slate-100">
                                            <Calendar className="w-4 h-4 text-emerald-500" />
                                        </div>
                                        <div>
                                            <p className="text-xs font-bold text-slate-800 leading-none">
                                                {format(new Date(ob.initiation_date), "MMM dd, yyyy")}
                                            </p>
                                            <p className="text-[9px] font-bold text-slate-400   mt-1">Start Date</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            
                            <div className="px-6 py-4 flex items-center justify-between bg-slate-50/50 border-t border-slate-100/50 rounded-b-3xl">
                                <div className="flex items-center gap-2 text-slate-400">
                                    <Activity className="w-4 h-4" />
                                    <span className="text-[10px] font-bold  ">Active Cycle</span>
                                </div>
                                <div className="text-indigo-400 group-hover:text-indigo-600 transition-colors flex items-center gap-1.5 translate-x-1 group-hover:translate-x-0">
                                    <span className="text-[10px] font-bold  ">Details</span>
                                    <ArrowRight className="w-4 h-4 text-indigo-500" />
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>
            
            {filteredOnboardings.length === 0 && (
                <div className="py-32 flex flex-col items-center justify-center text-center bg-white rounded-2xl border border-dashed border-slate-200">
                    <div className="w-20 h-20 bg-slate-50 text-slate-200 rounded-xl flex items-center justify-center mb-6">
                        <ClipboardList className="w-10 h-10" />
                    </div>
                    <h4 className="text-xl font-bold text-slate-900">No Onboarding Records</h4>
                    <p className="text-sm text-slate-400 font-medium max-w-[280px] mt-2 leading-relaxed">Candidate records will appear here once they begin the onboarding process.</p>
                </div>
            )}
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";
import ProjectForm from "@/components/enterprise/ProjectForm";

export default function ProjectDetailsPage() {
    const params = useParams();
    const { token } = useAuth();
    const [project, setProject] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(true);

    const id = params.id as string;

    useEffect(() => {
        if (token && id) {
            fetchProject();
        }
    }, [token, id]);

    const fetchProject = async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get(`/api/v1/enterprise/projects/${id}`);
            if (res.ok) {
                setProject(await res.json());
            }
        } catch (error) {
            console.error("Error fetching project:", error);
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex justify-center items-center h-[calc(100vh-4rem)] bg-slate-50/10">
                <div className="w-10 h-10 border-4 border-[#7C3AED] border-t-transparent rounded-full animate-spin"></div>
            </div>
        );
    }

    if (!project) {
        return (
            <div className="flex flex-col items-center justify-center h-[calc(100vh-4rem)] text-center p-10">
                <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mb-4 transition-transform hover:scale-110">
                    <span className="material-symbols-rounded text-slate-400 text-3xl">error</span>
                </div>
                <h2 className="text-xl font-black text-slate-800 tracking-tight">Project Not Found</h2>
                <p className="text-sm font-medium text-slate-500 max-w-sm mt-2">The project you are looking for does not exist or has been deleted.</p>
                <button 
                    onClick={() => window.history.back()}
                    className="mt-8 px-8 py-3 bg-white border border-slate-200 rounded-xl font-black text-[10px]   text-slate-600 hover:bg-slate-50 hover:border-slate-300 transition-all active:scale-95"
                >Go Back</button>
            </div>
        );
    }

    return (
        <div className="min-h-full bg-slate-50/30">
            <ProjectForm projectId={id} initialData={project} />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import ConfirmationModal from "@/components/common/ConfirmationModal";
import ProjectCard from "@/components/enterprise/ProjectCard";

interface Member {
    first_name: string;
    last_name: string;
}

interface Project {
    id: string;
    name: string;
    description: string;
    status: string;
    start_date: string;
    end_date: string;
    members: Member[];
}

export default function ProjectsPage() {
    const { token, canAccess } = useAuth();
    const [projects, setProjects] = useState<Project[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [statusFilter, setStatusFilter] = useState("all");
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [projectToDelete, setProjectToDelete] = useState<{ id: string; name: string } | null>(null);

    useEffect(() => {
        if (token) {
            fetchProjects();
        }
    }, [token]);

    const fetchProjects = async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get("/api/v1/enterprise/projects/");
            if (res.ok) {
                const data = await res.json();
                setProjects(data);
            }
        } catch (error) {
            console.error("Error fetching projects:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async () => {
        if (!projectToDelete) return;
        try {
            const res = await apiClient.delete(`/api/v1/enterprise/projects/${projectToDelete.id}`);
            if (res.ok) fetchProjects();
        } catch (e) {
            console.error(e);
        } finally {
            setIsDeleteModalOpen(false);
            setProjectToDelete(null);
        }
    };

    const filteredProjects = projects.filter(proj => 
        (statusFilter === "all" || proj.status === statusFilter) &&
        (proj.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (proj.description && proj.description.toLowerCase().includes(searchQuery.toLowerCase())))
    );

    return (
        <div className="p-6 space-y-8 animate-in fade-in duration-500 bg-[#F8FAFC] min-h-screen">
            {/* Header */}
            <div>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                    <div className="flex items-start gap-4">
                        <div className="w-12 h-12 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center shrink-0 shadow-sm shadow-[#7C3AED]/5">
                            <span className="material-symbols-rounded text-[#7C3AED] text-2xl">account_tree</span>
                        </div>
                        <div>
                            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">Project Management</h1>
                            <p className="text-slate-500 text-[13px] font-medium mt-1">
                                Track project milestones, manage team resources, and monitor deployment progress.
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-3">
                        {canAccess("projects:moderate") && (
                            <Link
                                href="/enterprise/projects/add"
                                className="flex items-center gap-2 px-5 h-11 bg-[#7C3AED] text-white rounded-lg text-xs font-black hover:bg-[#6d28d9] transition-all shadow-lg shadow-[#7C3AED]/20 active:scale-95"
                            >
                                <span className="material-symbols-rounded text-lg">add_circle</span>
                                NEW PROJECT
                            </Link>
                        )}
                    </div>
                </div>

                {/* Stats Section */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    {[
                        { label: "Total Projects", value: projects.length, icon: "rule", color: "indigo" },
                        { label: "Active Missions", value: projects.filter(p => p.status === 'Active').length, icon: "rocket_launch", color: "emerald" },
                        { label: "Completed", value: projects.filter(p => p.status === 'Completed').length, icon: "task_alt", color: "amber" },
                        { label: "Resources", value: projects.reduce((acc, p) => acc + (p.members?.length || 0), 0), icon: "groups", color: "purple" }
                    ].map((stat, i) => (
                        <div key={i} className="group bg-white p-5 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-[#7C3AED]/20 transition-all duration-300">
                            <div className="flex items-start justify-between mb-4">
                                <div className={`w-10 h-10 rounded-lg flex items-center justify-center transition-transform group-hover:scale-110 ${
                                    stat.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
                                    stat.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
                                    stat.color === 'amber' ? 'bg-amber-50 text-amber-600' :
                                    'bg-purple-50 text-purple-600'
                                }`}>
                                    <span className="material-symbols-rounded text-xl">{stat.icon}</span>
                                </div>
                                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Live</span>
                            </div>
                            <p className="text-2xl font-black text-slate-900 mb-0.5 tracking-tight">{stat.value}</p>
                            <p className="text-[11px] font-bold text-slate-400 capitalize">{stat.label}</p>
                        </div>
                    ))}
                </div>
            </div>

            {/* Interaction Bar */}
            <div className="flex flex-col md:flex-row items-center gap-4">
                <div className="flex-1 relative w-full group">
                    <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-lg transition-colors group-focus-within:text-[#7C3AED]">search</span>
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search projects by name or description..."
                        className="w-full h-12 bg-white border border-slate-200 rounded-xl pl-12 pr-4 text-[13px] font-bold text-slate-700 placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none shadow-sm"
                    />
                </div>
                
                <div className="flex items-center gap-2 bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm min-w-[200px]">
                    <span className="material-symbols-rounded text-slate-400 ml-2 text-lg">filter_list</span>
                    <select
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        className="w-full bg-transparent border-none text-[11px] font-black text-slate-700 focus:outline-none focus:ring-0 cursor-pointer uppercase tracking-wider"
                    >
                        <option value="all">All Statuses</option>
                        <option value="Active">Active Missions</option>
                        <option value="Completed">Completed</option>
                        <option value="On Hold">On Hold</option>
                    </select>
                </div>
            </div>

            {/* Content Table */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
                {isLoading ? (
                    <div className="p-6 space-y-4">
                        {[1, 2, 3, 4, 5].map((i) => (
                            <div key={i} className="bg-slate-50 h-16 rounded-xl animate-pulse"></div>
                        ))}
                    </div>
                ) : filteredProjects.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-32 text-center">
                        <div className="w-20 h-20 bg-slate-50 rounded-xl flex items-center justify-center mx-auto mb-6">
                            <span className="material-symbols-rounded text-4xl text-slate-100">account_tree</span>
                        </div>
                        <h3 className="text-xl font-black text-slate-800  tracking-tight">No Active Projects</h3>
                        <p className="text-xs text-slate-400 font-medium max-w-xs mx-auto mt-2">Initialize your first multi-member project mission to begin tracking progress.</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-50 border-b border-slate-100">
                                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-widest">Project Details</th>
                                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-widest">Timeline</th>
                                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-widest">Team</th>
                                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filteredProjects.map((proj) => (
                                    <tr key={proj.id} className="hover:bg-slate-50/50 transition-all group">
                                        <td className="px-6 py-4">
                                            <Link href={`/enterprise/projects/${proj.id}`} className="flex flex-col group/title">
                                                <span className="text-sm font-bold text-slate-900 group-hover/title:text-[#7C3AED] transition-colors">{proj.name}</span>
                                                <span className="text-xs text-slate-500 line-clamp-1">{proj.description || "No description provided"}</span>
                                            </Link>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-1">
                                                <div className="flex items-center gap-1.5 text-[11px] font-bold text-slate-600">
                                                    <span className="material-symbols-rounded text-sm text-slate-400">calendar_today</span>
                                                    {proj.start_date ? new Date(proj.start_date).toLocaleDateString() : "TBA"} - {proj.end_date ? new Date(proj.end_date).toLocaleDateString() : "TBA"}
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-black border uppercase tracking-wider ${
                                                proj.status === 'Active' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                                                proj.status === 'Completed' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' :
                                                'bg-slate-100 text-slate-500 border-slate-200'
                                            }`}>
                                                <span className={`w-1.5 h-1.5 rounded-full ${
                                                    proj.status === 'Active' ? 'bg-emerald-500' :
                                                    proj.status === 'Completed' ? 'bg-indigo-500' :
                                                    'bg-slate-400'
                                                }`}></span>
                                                {proj.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-2">
                                                <div className="flex -space-x-2">
                                                    {(proj.members || []).slice(0, 3).map((m: Member, i: number) => (
                                                        <div key={i} className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white flex items-center justify-center text-[10px] font-bold text-slate-600 uppercase">
                                                            {m.first_name?.[0]}{m.last_name?.[0]}
                                                        </div>
                                                    ))}
                                                    {(proj.members || []).length > 3 && (
                                                        <div className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[10px] font-bold text-slate-400">
                                                            +{(proj.members || []).length - 3}
                                                        </div>
                                                    )}
                                                </div>
                                                <span className="text-[11px] font-bold text-slate-400">{(proj.members || []).length} Members</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                {canAccess("projects:moderate") && (
                                                    <Link
                                                        href={`/enterprise/projects/${proj.id}/edit`}
                                                        className="w-9 h-9 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-[#7C3AED]/5 flex items-center justify-center transition-all"
                                                        title="Edit Project"
                                                    >
                                                        <span className="material-symbols-rounded text-lg">edit</span>
                                                    </Link>
                                                )}
                                                {canAccess("projects:delete") && (
                                                    <button
                                                        onClick={() => {
                                                            setProjectToDelete({ id: proj.id, name: proj.name });
                                                            setIsDeleteModalOpen(true);
                                                        }}
                                                        className="w-9 h-9 rounded-xl text-slate-400 hover:text-rose-500 hover:bg-rose-50 flex items-center justify-center transition-all"
                                                        title="Delete Project"
                                                    >
                                                        <span className="material-symbols-rounded text-lg">delete</span>
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <ConfirmationModal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                onConfirm={handleDelete}
                title="Terminate Mission Deployment?"
                message={`Are you sure you want to delete "${projectToDelete?.name}"? All associated task nodes and timeline data will be permanently wiped.`}
                confirmLabel="Yes, Terminate"
                cancelLabel="No"
                isDestructive={true}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect, useCallback, Suspense } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { 
    Trash2, 
    Settings2, 
    Mic2, 
    Video, 
    Clock, 
    Search, 
    RefreshCcw, 
    MessagesSquare,
    Calendar,
    ArrowRight
} from "lucide-react";
import TemplateBuilder from "@/app/enterprise/automation/interview/TemplateBuilder";
import ConfirmationModal from "@/components/common/ConfirmationModal";

interface InterviewTemplate {
    id: string;
    title: string;
    topic: string;
    duration: number;
    difficulty: string;
    require_video: boolean;
    type: string;
    created_at: string;
    plan?: Record<string, unknown>;
}

function InterviewTemplatesContent() {
    const { token, canAccess } = useAuth();
    const [templates, setTemplates] = useState<InterviewTemplate[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [showBuilder, setShowBuilder] = useState(false);
    const [editingTemplate, setEditingTemplate] = useState<InterviewTemplate | null>(null);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [templateToDelete, setTemplateToDelete] = useState<{ id: string; name: string } | null>(null);
    const [interviewSearch, setInterviewSearch] = useState("");
    const [difficultyFilter, setDifficultyFilter] = useState("ALL");

    const fetchTemplates = useCallback(async () => {
        if (!token) return;
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-templates/`, {
                headers: {
                    "Authorization": `Bearer ${token}`
                },
            });
            if (res.ok) {
                const data = await res.json();
                setTemplates(data);
            }
        } catch (error) {
            console.error("Failed to fetch interview templates:", error);
        } finally {
            setTimeout(() => setIsLoading(false), 600);
        }
    }, [token]);

    useEffect(() => {
        if (token) {
            fetchTemplates();
        }
    }, [token, fetchTemplates]);

    const handleDelete = async () => {
        if (!templateToDelete) return;
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/interview-templates/${templateToDelete.id}`, {
                method: "DELETE",
                headers: {
                    "Authorization": `Bearer ${token}`
                },
            });
            if (res.ok) {
                setTemplates((prev) => prev.filter((t) => t.id !== templateToDelete.id));
            }
        } catch (error) {
            console.error("Failed to delete interview template:", error);
        } finally {
            setIsDeleteModalOpen(false);
            setTemplateToDelete(null);
        }
    };

    if (isLoading && templates.length === 0) {
        return (
            <div className="p-8 lg:p-12 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-500">
                <div className="h-32 bg-slate-900 rounded-2xl relative overflow-hidden flex items-center px-10 shadow-2xl">
                    <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-white/5 rounded-xl animate-pulse" />
                        <div className="space-y-2">
                            <div className="w-48 h-6 bg-white/10 rounded-xl animate-pulse" />
                            <div className="w-32 h-3 bg-white/5 rounded-xl animate-pulse" />
                        </div>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="bg-white h-64 rounded-2xl border border-slate-100 animate-pulse shadow-sm" />
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pb-20 animate-in fade-in duration-700 relative">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">psychology</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Interview Templates</h1>
                        <p className="text-slate-500 text-[10px] font-medium   ">Design AI behavioral screening</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {canAccess("interviews:moderate") && (
                        <button 
                            onClick={() => {
                                setEditingTemplate(null);
                                setShowBuilder(true);
                            }}
                            className="px-6 py-2.5 bg-[#7C3AED] text-white rounded-xl hover:bg-[#6D28D9] transition-all font-black text-[9px] uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-100"
                        >
                            <span className="material-symbols-rounded text-base">add</span>
                            New Template
                        </button>
                    )}
                    <button 
                        onClick={fetchTemplates}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {/* Stat Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-[#7C3AED]">Total Templates</span>
                        <div className="w-12 h-12 rounded-xl bg-violet-50 text-[#7C3AED] flex items-center justify-center transition-all group-hover:scale-110">
                            <MessagesSquare className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-blue-500">Video Calls</span>
                        <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Video className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.filter(t => t.require_video).length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-emerald-500">Audio Only</span>
                        <div className="w-12 h-12 rounded-xl bg-emerald-50 text-emerald-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Mic2 className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.filter(t => !t.require_video).length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-amber-500">Avg Duration</span>
                        <div className="w-12 h-12 rounded-xl bg-amber-50 text-amber-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Clock className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.length ? Math.round(templates.reduce((acc, t) => acc + t.duration, 0) / templates.length) : 0}
                        <span className="text-sm font-bold text-slate-400 ml-2">min</span>
                    </div>
                </motion.div>
            </div>

            {/* Search and Filter Bar */}
            <div className="flex flex-col md:flex-row items-center gap-4">
                <div className="relative flex-1 group">
                    <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#7C3AED] transition-colors">search</span>
                    <input 
                        type="text"
                        placeholder="Search interview templates by title or topic..."
                        className="w-full h-12 pl-12 pr-6 bg-white border border-slate-200 rounded-xl outline-none focus:border-violet-300 focus:ring-4 focus:ring-violet-50 transition-all font-medium text-sm"
                        value={interviewSearch}
                        onChange={(e) => setInterviewSearch(e.target.value)}
                    />
                </div>
                <div className="flex items-center gap-2 bg-white border border-slate-200 p-1.5 rounded-xl shadow-sm">
                    <span className="material-symbols-rounded text-slate-400 pl-2">filter_list</span>
                    <select 
                        className="bg-transparent text-[10px] font-black uppercase tracking-widest text-slate-600 outline-none pr-4 cursor-pointer"
                        value={difficultyFilter}
                        onChange={(e) => setDifficultyFilter(e.target.value)}
                    >
                        <option value="ALL">All Difficulties</option>
                        <option value="Entry">Entry</option>
                        <option value="Intermediate">Intermediate</option>
                        <option value="Advanced">Advanced</option>
                        <option value="Expert">Expert</option>
                    </select>
                </div>
            </div>

            {templates.length === 0 ? (
                <div className="text-center py-32 bg-white rounded-2xl border border-dashed border-slate-200">
                    <div className="w-20 h-20 bg-slate-50 text-slate-200 rounded-xl flex items-center justify-center mx-auto mb-6">
                        <MessagesSquare className="w-10 h-10" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-900 tracking-tight">No Templates Found</h3>
                    <p className="text-sm text-slate-400 font-medium mt-2 max-w-[280px] mx-auto leading-relaxed">Create your first interview template to automate candidate screening.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {templates.filter(t => {
                        const matchesSearch = (t.title + t.topic).toLowerCase().includes(interviewSearch.toLowerCase());
                        const matchesDiff = difficultyFilter === "ALL" || t.difficulty === difficultyFilter;
                        return matchesSearch && matchesDiff;
                    }).map(template => (
                        <motion.div
                            layout
                            key={template.id}
                            className="group bg-white rounded-xl border border-slate-200/60 shadow-sm hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-1 transition-all duration-300 relative overflow-hidden cursor-pointer"
                            onClick={() => {
                                if (canAccess("interviews:moderate")) {
                                    setEditingTemplate(template);
                                    setShowBuilder(true);
                                }
                            }}
                        >
                            <div className="p-6 pb-2 space-y-6">
                                <div className="flex justify-between items-start">
                                    <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                                        {template.require_video ? <Video className="w-6 h-6 stroke-[1.5]" /> : <Mic2 className="w-6 h-6 stroke-[1.5]" />}
                                    </div>
                                    <div className="flex items-center gap-2">
                                        {canAccess("interviews:moderate") && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setEditingTemplate(template);
                                                    setShowBuilder(true);
                                                }}
                                                className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-[#7C3AED] hover:bg-violet-50 rounded-xl transition-all"
                                            >
                                                <span className="material-symbols-rounded text-lg">edit</span>
                                            </button>
                                        )}
                                        {canAccess("interviews:delete") && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTemplateToDelete({ id: template.id, name: template.title });
                                                    setIsDeleteModalOpen(true);
                                                }}
                                                className="p-2 bg-rose-50 text-rose-300 hover:bg-rose-500 hover:text-white transition-all rounded-xl"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                </div>
                                
                                <div className="space-y-3">
                                    <div className="flex items-center justify-between">
                                        <span className="text-[10px] font-bold text-indigo-500 bg-indigo-50 px-3 py-1 rounded-full  ">{template.topic}</span>
                                        <span className="text-[10px] font-bold text-slate-400  ">{template.difficulty}</span>
                                    </div>
                                    <h3 className="text-lg font-bold text-slate-900 group-hover:text-indigo-600 transition-colors truncate">{template.title}</h3>
                                </div>

                                <div className="grid grid-cols-2 gap-3 pt-4 border-t border-slate-200/50">
                                   <div className="bg-slate-50 p-4 rounded-xl border border-slate-100/50 group-hover:bg-white group-hover:border-slate-200 transition-all">
                                      <p className="text-[9px] font-bold text-slate-400   mb-1">Duration</p>
                                      <p className="text-xs font-bold text-slate-700">{template.duration} mins</p>
                                   </div>
                                   <div className="bg-slate-50 p-4 rounded-xl border border-slate-100/50 group-hover:bg-white group-hover:border-slate-200 transition-all">
                                      <p className="text-[9px] font-bold text-slate-400   mb-1">Interface</p>
                                      <p className="text-xs font-bold text-slate-700 truncate">{template.require_video ? "Video" : "Audio Only"}</p>
                                   </div>
                                </div>
                            </div>
                            
                            <div className="px-6 py-4 flex items-center justify-between bg-slate-50/50 border-t border-slate-200/50 rounded-b-3xl mt-auto">
                                <div className="flex items-center gap-2 text-slate-300">
                                    <Calendar className="w-3.5 h-3.5" />
                                    <span className="text-[10px] font-bold  ">{new Date(template.created_at).toLocaleDateString()}</span>
                                </div>
                                <div className="w-8 h-8 rounded-lg bg-white border border-slate-100 flex items-center justify-center text-slate-300 group-hover:text-indigo-600 group-hover:border-indigo-100 transition-all">
                                    <ArrowRight className="w-4 h-4" />
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            )}

            <AnimatePresence>
                {showBuilder && (
                    <TemplateBuilder
                        token={token || ""}
                        backendUrl={BACKEND_URL}
                        initialData={editingTemplate}
                        onClose={() => {
                            setShowBuilder(false);
                            setEditingTemplate(null);
                        }}
                        onSave={() => {
                            fetchTemplates();
                            setShowBuilder(false);
                            setEditingTemplate(null);
                        }}
                    />
                )}
            </AnimatePresence>

            <ConfirmationModal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                onConfirm={handleDelete}
                title="Delete Template?"
                message={`Are you sure you want to delete "${templateToDelete?.name}"? This will remove all associated interview logic.`}
                confirmLabel="Delete Template"
                cancelLabel="Cancel"
                isDestructive={true}
            />
        </div>
    );
}

const Edit3 = ({ className }: { className: string }) => <Settings2 className={className} />;

export default function InterviewTemplatesPage() {
    return (
        <Suspense fallback={
            <div className="flex items-center justify-center h-screen bg-slate-50">
                <div className="flex flex-col items-center gap-6">
                    <div className="w-16 h-16 bg-slate-900 rounded-xl flex items-center justify-center animate-pulse shadow-xl">
                        <MessagesSquare className="w-8 h-8 text-indigo-400 animate-spin" />
                    </div>
                    <div className="text-center">
                        <p className="text-xs font-bold   text-slate-900">Loading Interview Templates</p>
                    </div>
                </div>
            </div>
        }>
            <InterviewTemplatesContent />
        </Suspense>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import OnboardingTemplateForm from "@/components/enterprise/OnboardingTemplateForm";
import { BACKEND_URL } from "@/utils/api";
import { useAuth } from "@/context/AuthContext";
import Link from "next/link";

export default function EditOnboardingTemplatePage() {
    const { id } = useParams();
    const { token } = useAuth();
    const [template, setTemplate] = useState(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        if (id && token) {
            fetchTemplate();
        }
    }, [id, token]);

    const fetchTemplate = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/${id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setTemplate(data);
            }
        } catch (error) {
            console.error("Error fetching template:", error);
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex justify-center items-center h-screen bg-[#FDFDFF]">
                <div className="animate-spin material-icons-outlined text-indigo-500 text-6xl">sync</div>
            </div>
        );
    }

    if (!template) {
        return (
            <div className="flex flex-col items-center justify-center h-screen text-center p-10 bg-[#FDFDFF]">
                <div className="w-24 h-24 bg-white rounded-2xl flex items-center justify-center shadow-xl shadow-slate-200 mb-6">
                    <span className="material-icons-outlined text-5xl text-rose-500">error_outline</span>
                </div>
                <div>
                    <h4 className="text-xl font-black text-slate-900">Template Not Found</h4>
                    <Link href="/enterprise/settings/onboarding-templates" className="text-indigo-600 hover:underline mt-4 inline-block font-black text-xs  ">Back to Templates</Link>
                </div>
            </div>
        );
    }

    return (
        <div className="p-8 max-w-7xl mx-auto min-h-screen bg-[#FDFDFF] font-sans">
            {/* Header */}
            <div className="flex items-center gap-6 mb-10">
                <Link 
                    href="/enterprise/settings/onboarding-templates"
                    className="w-12 h-12 flex items-center justify-center bg-white border border-slate-100 rounded-xl text-slate-400 hover:text-indigo-600 hover:border-indigo-100 transition-all shadow-sm"
                >
                    <span className="material-icons-outlined">arrow_back</span>
                </Link>
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight">Edit Template</h1>
                    <p className="text-slate-500 font-medium text-sm mt-1">Update your custom onboarding flow.</p>
                </div>
            </div>

            <OnboardingTemplateForm template={template} />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { BACKEND_URL } from "@/utils/api";
import { useAuth } from "@/context/AuthContext";
import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { 
    Plus, 
    Trash2, 
    Edit3, 
    Search,
    ChevronRight,
    Cpu,
    RefreshCcw,
    Layers,
    History,
    ArrowRight,
    ClipboardList,
    Layout
} from "lucide-react";
import ConfirmationModal from "@/components/common/ConfirmationModal";

interface OnboardingField {
    name: string;
    label: string;
    type: "text" | "number" | "date" | "select" | "email" | "phone" | "file";
    required: boolean;
    options?: string[];
}

interface Section {
    id: string;
    title: string;
    fields: OnboardingField[];
}

interface OnboardingTemplate {
    id: string;
    name: string;
    description?: string;
    sections: string[];
    form_config: { sections: Section[] };
    created_at: string;
}

export default function OnboardingTemplatesPage() {
    const [templates, setTemplates] = useState<OnboardingTemplate[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const { token, canAccess } = useAuth();
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [templateToDelete, setTemplateToDelete] = useState<{ id: string; name: string } | null>(null);
    const [onboardingSearch, setOnboardingSearch] = useState("");

    const fetchTemplates = useCallback(async () => {
        if (!token) return;
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setTemplates(data);
            }
        } catch (error) {
            console.error("Error fetching templates:", error);
        } finally {
            setTimeout(() => setIsLoading(false), 600);
        }
    }, [token]);

    useEffect(() => {
        fetchTemplates();
    }, [fetchTemplates]);


    const handleDelete = async () => {
        if (!templateToDelete) return;
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/${templateToDelete.id}`, {
                method: "DELETE",
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) fetchTemplates();
        } catch (error) {
            console.error("Error deleting template:", error);
        } finally {
            setIsDeleteModalOpen(false);
            setTemplateToDelete(null);
        }
    };

    if (isLoading) {
        return (
            <div className="p-8 lg:p-12 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-500">
                <div className="h-32 bg-slate-900 rounded-2xl relative overflow-hidden flex items-center px-10 shadow-2xl">
                    <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-white/5 rounded-xl animate-pulse" />
                        <div className="space-y-2">
                            <div className="w-48 h-6 bg-white/10 rounded-xl animate-pulse" />
                            <div className="w-32 h-3 bg-white/5 rounded-xl animate-pulse" />
                        </div>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="bg-white h-80 rounded-2xl border border-slate-100 animate-pulse shadow-sm" />
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pb-20 animate-in fade-in duration-700 relative">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">rule</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Onboarding Templates</h1>
                        <p className="text-slate-500 text-[10px] font-medium   ">Design integration sequences</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {canAccess("onboarding:moderate") && (
                        <Link 
                            href="/enterprise/settings/onboarding-templates/create"
                            className="px-6 py-2.5 bg-[#7C3AED] text-white rounded-xl hover:bg-[#6D28D9] transition-all font-black text-[9px] uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-100"
                        >
                            <span className="material-symbols-rounded text-base">add</span>
                            New Template
                        </Link>
                    )}
                    <button 
                        onClick={fetchTemplates}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {/* Stat Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-[#7C3AED]">Active Flows</span>
                        <div className="w-12 h-12 rounded-xl bg-violet-50 text-[#7C3AED] flex items-center justify-center transition-all group-hover:scale-110">
                            <Layers className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-blue-500">Total Sections</span>
                        <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <ClipboardList className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.reduce((acc, t) => acc + (t.form_config?.sections?.length || 0), 0)}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-emerald-500">Form Fields</span>
                        <div className="w-12 h-12 rounded-xl bg-emerald-50 text-emerald-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Cpu className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.reduce((acc, t) => acc + (t.form_config?.sections?.reduce((sAcc, s) => sAcc + (s.fields?.length || 0), 0) || 0), 0)}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-amber-500">Avg Steps</span>
                        <div className="w-12 h-12 rounded-xl bg-amber-50 text-amber-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Layout className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.length ? Math.round(templates.reduce((acc, t) => acc + (t.form_config?.sections?.length || 0), 0) / templates.length) : 0}
                    </div>
                </motion.div>
            </div>

            {/* Search Bar */}
            <div className="relative group">
                <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#7C3AED] transition-colors">search</span>
                <input 
                    type="text"
                    placeholder="Search onboarding templates by name..."
                    className="w-full h-12 pl-12 pr-6 bg-white border border-slate-200 rounded-xl outline-none focus:border-violet-300 focus:ring-4 focus:ring-violet-50 transition-all font-medium text-sm"
                    value={onboardingSearch}
                    onChange={(e) => setOnboardingSearch(e.target.value)}
                />
            </div>

            {/* Template List */}
            {templates.length === 0 ? (
                <div className="text-center py-32 bg-white rounded-2xl border border-dashed border-slate-200">
                    <div className="w-20 h-20 bg-slate-50 text-slate-200 rounded-xl flex items-center justify-center mx-auto mb-6">
                        <ClipboardList className="w-10 h-10" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-900 tracking-tight">No Templates Found</h3>
                    <p className="text-sm text-slate-400 font-medium mt-2 max-w-[280px] mx-auto leading-relaxed">Synthesize your first onboarding sequence to standardize the cultural handshake.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {templates.filter(t => t.name.toLowerCase().includes(onboardingSearch.toLowerCase())).map((t) => (
                        <motion.div 
                            layout
                            key={t.id}
                            className="group bg-white rounded-xl border border-slate-200/60 shadow-sm hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-1 transition-all duration-300 relative overflow-hidden flex flex-col cursor-pointer"
                        >
                            <div className="p-6 pb-2 space-y-6 flex-1">
                                <div className="flex justify-between items-start">
                                    <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                                        <Layers className="w-6 h-6 stroke-[1.5]" />
                                    </div>
                                    <div className="flex items-center gap-2">
                                        {canAccess("onboarding:moderate") && (
                                            <>
                                                <Link 
                                                    href={`/enterprise/settings/onboarding-templates/${t.id}/edit`}
                                                    className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-[#7C3AED] hover:bg-violet-50 rounded-xl transition-all"
                                                    onClick={(e) => e.stopPropagation()}
                                                >
                                                    <Edit3 className="w-4 h-4" />
                                                </Link>
                                                <button 
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        setTemplateToDelete({ id: t.id, name: t.name });
                                                        setIsDeleteModalOpen(true);
                                                    }} 
                                                    className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                                                >
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            </>
                                        )}
                                    </div>
                                </div>

                                <div className="space-y-1">
                                    <h3 className="text-xl font-bold text-slate-900 group-hover:text-indigo-600 transition-colors truncate">{t.name}</h3>
                                    <p className="text-sm text-slate-400 font-medium whitespace-nowrap overflow-hidden text-ellipsis">Onboarding flow architect</p>
                                </div>

                                <p className="text-sm text-slate-400 line-clamp-2 leading-relaxed h-10 font-medium">
                                    {t.description || "Standard organizational integration workflow."}
                                </p>
                                
                                <div className="bg-slate-50/50 rounded-xl p-4 border border-slate-100/50 group-hover:bg-indigo-50/30 group-hover:border-indigo-100/50 transition-all">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <p className="text-[10px] font-bold text-slate-800  ">
                                                {(t.form_config?.sections || []).length} Sections Defined
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            
                            <div className="px-6 py-4 flex items-center justify-between bg-slate-50/50 border-t border-slate-200/50 rounded-b-3xl mt-auto">
                                <div className="flex items-center gap-2 text-slate-300">
                                    <History className="w-3.5 h-3.5" />
                                    <span className="text-[10px] font-bold  ">{new Date(t.created_at).toLocaleDateString()}</span>
                                </div>
                                <Link 
                                    href={`/enterprise/settings/onboarding-templates/${t.id}/edit`}
                                    className="w-8 h-8 rounded-lg bg-white border border-slate-100 flex items-center justify-center text-slate-300 group-hover:text-indigo-600 group-hover:border-indigo-100 transition-all"
                                    onClick={(e) => e.stopPropagation()}
                                >
                                    <ArrowRight className="w-4 h-4" />
                                </Link>
                            </div>
                        </motion.div>
                    ))}
                </div>
            )}

            <ConfirmationModal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                onConfirm={handleDelete}
                title="Delete Template?"
                message={`Are you sure you want to delete "${templateToDelete?.name}"? This will remove all associated onboarding logic.`}
                confirmLabel="Delete Template"
                cancelLabel="Cancel"
                isDestructive={true}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { 
    Building2, 
    Upload, 
    MapPin, 
    Globe, 
    ExternalLink, 
    CheckCircle2, 
    AlertCircle,
    Save,
    Camera,
    Zap,
    Shield,
    RefreshCcw,
    Activity
} from "lucide-react";

interface CompanyProfile {
    id: string;
    name: string;
    logo_url?: string;
    industry?: string;
    location?: string;
}

export default function OrganizationProfilePage() {
    const { token, canAccess } = useAuth();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [profile, setProfile] = useState<CompanyProfile | null>(null);

    // Form Stats
    const [name, setName] = useState("");
    const [logoUrl, setLogoUrl] = useState("");
    const [industry, setIndustry] = useState("");
    const [location, setLocation] = useState("");
    const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

    useEffect(() => {
        if (token) {
            fetchProfile();
        }
    }, [token]);

    const showToast = (msg: string, type: "success" | "error" = "success") => {
        setToast({ msg, type });
        setTimeout(() => setToast(null), 3000);
    };

    const fetchProfile = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/company/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                const primary = Array.isArray(data) ? data[0] : data;
                if (!primary) {
                    setIsLoading(false);
                    return;
                }
                setProfile(primary);
                setName(primary.name || "");
                setLogoUrl(primary.logo_url || "");
                setIndustry(primary.industry || "");
                setLocation(primary.location || "");
            }
        } catch (e) {
            console.error("Failed to fetch profile", e);
        } finally {
            setTimeout(() => setIsLoading(false), 600);
        }
    };

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !token) return;

        setIsUploading(true);
        const formData = new FormData();
        formData.append("file", file);

        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/upload/logo`, {
                method: "POST",
                headers: { "Authorization": `Bearer ${token}` },
                body: formData
            });

            if (res.ok) {
                const data = await res.json();
                const fullUrl = data.url.startsWith("http") ? data.url : `${BACKEND_URL}${data.url}`;
                setLogoUrl(fullUrl);
                showToast("Logo updated successfully.");
            } else {
                showToast("Upload failed.", "error");
            }
        } catch (err) {
            console.error("Upload error:", err);
            showToast("Connection error.", "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleSave = async () => {
        setIsSaving(true);
        try {
            const isUpdate = !!profile?.id;
            const url = isUpdate 
                ? `${BACKEND_URL}/api/v1/enterprise/company/${profile.id}`
                : `${BACKEND_URL}/api/v1/enterprise/company/`;
            
            const method = isUpdate ? "PATCH" : "POST";

            const res = await fetch(url, {
                method,
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({ name, logo_url: logoUrl, industry, location })
            });

            if (res.ok) {
                const data = await res.json();
                setProfile(data);
                showToast(isUpdate ? "Profile successfully updated" : "Organization profile created");
            } else {
                const errData = await res.json().catch(() => ({}));
                showToast(errData.detail || "Save failed.", "error");
            }
        } catch (e) {
            console.error("Error saving profile", e);
            showToast("Server error.", "error");
        } finally {
            setIsSaving(false);
        }
    };

    const hasChanges = 
        name !== (profile?.name || "") ||
        logoUrl !== (profile?.logo_url || "") ||
        industry !== (profile?.industry || "") ||
        location !== (profile?.location || "");

    if (isLoading) {
        return (
            <div className="p-8 lg:p-12 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-500">
                <div className="h-32 bg-slate-900 rounded-xl relative overflow-hidden flex items-center px-10 shadow-xl shadow-indigo-100/50">
                    <div className="flex items-center gap-6 text-white/20">
                        <div className="w-16 h-16 bg-white/10 rounded-xl animate-pulse" />
                        <div className="space-y-3">
                            <div className="w-64 h-8 bg-white/10 rounded-xl animate-pulse" />
                            <div className="w-40 h-4 bg-white/5 rounded-xl animate-pulse" />
                        </div>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
                    <div className="md:col-span-4 h-96 bg-white rounded-xl border border-slate-100 animate-pulse" />
                    <div className="md:col-span-8 h-96 bg-white rounded-xl border border-slate-100 animate-pulse" />
                </div>
            </div>
        );
    }

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pt-2 animate-in fade-in duration-700">
            {/* Toast */}
            <AnimatePresence>
                {toast && (
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }} 
                        animate={{ opacity: 1, y: 0 }} 
                        exit={{ opacity: 0, y: -20 }} 
                        className={`fixed bottom-10 right-10 z-[500] px-6 py-4 rounded-xl shadow-2xl font-semibold text-sm flex items-center gap-3 border border-slate-100 backdrop-blur-md ${toast.type === "success" ? "bg-white text-slate-900" : "bg-rose-50 text-rose-600 border-rose-100"}`}
                    >
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center ${toast.type === "success" ? "bg-emerald-50 text-emerald-500" : "bg-rose-100 text-rose-500"}`}>
                            {toast.type === "success" ? <CheckCircle2 className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
                        </div>
                        {toast.msg}
                    </motion.div>
                )}
            </AnimatePresence>

            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">business</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Organization Profile</h1>
                        <p className="text-slate-500 text-[10px] font-medium   ">Manage your global brand presence</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {canAccess("enterprise:moderate") && (
                        <button
                            onClick={handleSave}
                            disabled={isSaving || !hasChanges}
                            className="px-6 py-2.5 bg-[#7C3AED] text-white rounded-xl hover:bg-[#6D28D9] transition-all font-black text-[9px]   flex items-center gap-2 shadow-xl shadow-indigo-100 disabled:opacity-30 disabled:cursor-not-allowed"
                        >
                            {isSaving ? (
                                <RefreshCcw className="w-3 h-3 animate-spin" />
                            ) : (
                                <Save className="w-3 h-3" />
                            )}
                            Update Profile
                        </button>
                    )}
                    
                    <button 
                        onClick={fetchProfile}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 hover:border-violet-100 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                {/* Left Side: Brand Preview */}
                <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.1 }}
                    className="lg:col-span-4 space-y-6"
                >
                    <div className="bg-white rounded-xl p-8 border border-slate-100 shadow-sm hover:shadow-lg transition-all duration-500 overflow-hidden relative group">
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 to-purple-500 opacity-0 group-hover:opacity-100 transition-opacity" />
                        
                        <div className="text-center space-y-8">
                            <div className="relative w-40 h-40 mx-auto group/logo">
                                <div className="absolute inset-0 bg-slate-50 rounded-2xl border border-slate-100 overflow-hidden flex items-center justify-center p-8 shadow-inner transition-transform group-hover/logo:scale-95">
                                    {logoUrl ? (
                                        <img src={logoUrl} alt="Logo" className="w-full h-full object-contain" />
                                    ) : (
                                        <Building2 className="w-16 h-16 text-slate-200" />
                                    )}
                                </div>
                                {canAccess("enterprise:moderate") && (
                                    <button 
                                        onClick={() => fileInputRef.current?.click()}
                                        className="absolute -bottom-2 -right-2 w-12 h-12 bg-slate-900 text-white rounded-xl flex items-center justify-center shadow-2xl hover:bg-indigo-600 transition-all scale-0 group-hover/logo:scale-100"
                                    >
                                        <Camera className="w-5 h-5" />
                                    </button>
                                )}
                                <input type="file" ref={fileInputRef} className="hidden" onChange={handleLogoUpload} accept="image/*" />
                                {isUploading && (
                                    <div className="absolute inset-0 bg-white/80 backdrop-blur-sm rounded-2xl flex flex-col items-center justify-center gap-2">
                                         <RefreshCcw className="w-6 h-6 text-indigo-600 animate-spin" />
                                         <span className="text-[10px] font-bold text-slate-500 ">Updating</span>
                                    </div>
                                )}
                            </div>

                            <div className="space-y-4">
                                <div className="space-y-1">
                                    <p className="text-[10px] font-bold text-indigo-600  ">{industry || "Brand Identity"}</p>
                                    <h2 className="text-2xl font-bold text-slate-900 tracking-tight leading-tight  truncate">{name || "Your Company"}</h2>
                                </div>
                                <div className="flex items-center justify-center gap-2 text-slate-400">
                                    <MapPin className="w-4 h-4" />
                                    <span className="text-sm font-medium">{location || "Location not set"}</span>
                                </div>
                            </div>

                            <div className="pt-4 grid grid-cols-2 gap-3">
                                <div className="px-4 py-3 bg-slate-50 rounded-xl border border-slate-100 flex flex-col items-center gap-1.5">
                                    <Shield className="w-4 h-4 text-emerald-500" />
                                    <span className="text-[10px] font-bold text-slate-500">Verified</span>
                                </div>
                                <div className="px-4 py-3 bg-slate-50 rounded-xl border border-slate-100 flex flex-col items-center gap-1.5">
                                    <Zap className="w-4 h-4 text-indigo-500" />
                                    <span className="text-[10px] font-bold text-slate-500">Premium</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="bg-slate-50/50 border border-slate-100 p-8 rounded-xl space-y-6">
                        <div className="flex items-center justify-between">
                            <h3 className="text-xs font-bold text-slate-900  ">Health Status</h3>
                            <Activity className="w-4 h-4 text-indigo-500" />
                        </div>
                        <div className="space-y-5">
                            {[
                                { label: "Candidate Portals", status: "Optimal" },
                                { label: "Brand Propagation", status: "Syncing" }
                            ].map((item, idx) => (
                                <div key={idx} className="space-y-2">
                                    <div className="flex justify-between text-[10px] font-bold ">
                                        <span className="text-slate-500">{item.label}</span>
                                        <span className="text-indigo-600">{item.status}</span>
                                    </div>
                                    <div className="h-1 bg-slate-200 rounded-full overflow-hidden">
                                        <div className="h-full bg-indigo-500 w-full animate-pulse" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </motion.div>

                {/* Right Side: Configuration */}
                <motion.div 
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.2 }}
                    className="lg:col-span-8"
                >
                    <div className="bg-white border border-slate-100 rounded-xl shadow-sm p-8 lg:p-12 space-y-12">
                        {/* Section: Basic Information */}
                        <section className="space-y-8">
                            <div className="flex items-center gap-4">
                                <div className="w-1.5 h-6 bg-indigo-600 rounded-full" />
                                <h3 className="text-lg font-bold text-slate-900">Basic Information</h3>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-slate-500 ml-1">Company Name</label>
                                    <input 
                                        value={name}
                                        onChange={e => setName(e.target.value)}
                                        readOnly={!canAccess("enterprise:moderate")}
                                        className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-4 text-slate-900 font-semibold focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-50 transition-all outline-none"
                                        placeholder="Enter your legal company name"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-slate-500 ml-1">Industry</label>
                                    <input 
                                        value={industry}
                                        onChange={e => setIndustry(e.target.value)}
                                        readOnly={!canAccess("enterprise:moderate")}
                                        className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-4 text-slate-900 font-semibold focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-50 transition-all outline-none"
                                        placeholder="e.g. Technology, Healthcare"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-500 ml-1">Location / Headquarters</label>
                                <div className="relative">
                                    <input 
                                        value={location}
                                        onChange={e => setLocation(e.target.value)}
                                        readOnly={!canAccess("enterprise:moderate")}
                                        className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-12 text-slate-900 font-semibold focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-50 transition-all outline-none"
                                        placeholder="e.g. London, United Kingdom"
                                    />
                                    <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                                </div>
                            </div>
                        </section>

                        {/* Section: Brand Assets */}
                        <section className="space-y-8">
                            <div className="flex items-center gap-4">
                                <div className="w-1.5 h-6 bg-indigo-600 rounded-full" />
                                <h3 className="text-lg font-bold text-slate-900">Brand Assets</h3>
                            </div>

                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-slate-500 ml-1">Logo URL</label>
                                    <div className="flex gap-4">
                                        <div className="relative flex-1">
                                            <input 
                                                value={logoUrl}
                                                onChange={e => setLogoUrl(e.target.value)}
                                                readOnly={!canAccess("enterprise:moderate")}
                                                className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-4 text-slate-700 font-medium focus:bg-white focus:border-indigo-600 transition-all outline-none text-sm"
                                                placeholder="https://your-domain.com/logo.png"
                                            />
                                        </div>
                                        {canAccess("enterprise:moderate") && (
                                            <button 
                                                onClick={() => fileInputRef.current?.click()}
                                                className="h-12 px-6 bg-slate-900 text-white font-bold text-xs rounded-xl hover:bg-slate-800 transition-all flex items-center gap-2 shadow-lg"
                                            >
                                                <Upload className="w-4 h-4" />
                                                Upload
                                            </button>
                                        )}
                                    </div>
                                </div>
                                
                                <div className="p-6 bg-indigo-50/50 border border-indigo-100 rounded-xl flex gap-4">
                                    <Shield className="w-5 h-5 text-indigo-500 shrink-0 mt-0.5" />
                                    <p className="text-sm text-indigo-900/70 leading-relaxed font-medium">
                                        Your logo will be used across all candidate-facing materials, including job boards, email templates, and career portals.
                                    </p>
                                </div>
                            </div>
                        </section>
                    </div>
                </motion.div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, Suspense } from "react";
import { apiClient } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { 
    ShieldHalf, 
    Plus, 
    Settings2, 
    Search, 
    X, 
    Trash2, 
    Lock, 
    ShieldCheck, 
    ChevronRight,
    RefreshCcw,
    Zap,
    LayoutGrid,
    Shield
} from "lucide-react";

interface Permission {
    id: string;
    module: string;
    resource: string;
    action: string;
}

interface Role {
    id: string;
    name: string;
    description?: string;
    is_system?: boolean;
    permissions: Permission[];
}

function EnterpriseRolesContent() {
    const [roles, setRoles] = useState<Role[]>([]);
    const [permissions, setPermissions] = useState<Permission[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [permSearch, setPermSearch] = useState("");
    
    // UI State
    const [isEditing, setIsEditing] = useState(false);
    const [selectedRole, setSelectedRole] = useState<Role | null>(null);
    
    // Form State
    const [name, setName] = useState("");
    const [description, setDescription] = useState("");
    const [selectedPermIds, setSelectedPermIds] = useState<string[]>([]);
    const [roleSearch, setRoleSearch] = useState("");
    const [typeFilter, setTypeFilter] = useState("ALL");

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const [rolesRes, permsRes] = await Promise.all([
                apiClient.get("/api/v1/enterprise/team/roles"),
                apiClient.get("/api/v1/enterprise/team/permissions")
            ]);
            
            if (rolesRes.ok) {
                const rolesData = await rolesRes.json();
                setRoles(rolesData);
            }
            if (permsRes.ok) {
                const permsData = await permsRes.json();
                setPermissions(permsData);
            }
        } catch (e) {
            console.error("Failed to fetch RBAC data", e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleOpenCreate = () => {
        setSelectedRole(null);
        setName("");
        setDescription("");
        setSelectedPermIds([]);
        setIsEditing(true);
    };

    const handleOpenEdit = (role: Role) => {
        setSelectedRole(role);
        setName(role.name);
        setDescription(role.description || "");
        setSelectedPermIds(role.permissions.map((p: Permission) => p.id));
        setIsEditing(true);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const payload = {
                name,
                description,
                permission_ids: selectedPermIds
            };

            const res = selectedRole 
                ? await apiClient.put(`/api/v1/enterprise/team/roles/${selectedRole.id}`, payload)
                : await apiClient.post("/api/v1/enterprise/team/roles", payload);

            if (res.ok) {
                setIsEditing(false);
                fetchData();
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (id: string) => {
        try {
            const res = await apiClient.delete(`/api/v1/enterprise/team/roles/${id}`);
            if (res.ok) fetchData();
        } catch (e) {
            console.error(e);
        }
    };

    const togglePermission = (id: string) => {
        setSelectedPermIds(prev => 
            prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]
        );
    };

    const filteredPermissions = permissions.filter(p => 
        (p.resource?.toLowerCase() || "").includes(permSearch.toLowerCase()) || 
        (p.module?.toLowerCase() || "").includes(permSearch.toLowerCase())
    );

    const groupedPermissions = filteredPermissions.reduce((acc: Record<string, Permission[]>, perm: Permission) => {
        if (!acc[perm.module]) acc[perm.module] = [];
        acc[perm.module].push(perm);
        return acc;
    }, {});

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pb-20 animate-in fade-in duration-700 relative">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">security</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Roles & Permissions</h1>
                        <p className="text-slate-500 text-[10px] font-medium uppercase tracking-widest mt-0.5">Define access policies and roles</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {!isEditing && (
                        <button 
                            onClick={handleOpenCreate}
                            className="px-6 py-2.5 bg-[#7C3AED] text-white rounded-xl hover:bg-[#6D28D9] transition-all font-black text-[9px] uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-100"
                        >
                            <span className="material-symbols-rounded text-base">add</span>
                            Create Role
                        </button>
                    )}
                    <button 
                        onClick={fetchData}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {!isEditing && (
                <>
                    {/* Stat Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                        >
                            <div className="flex justify-between items-start">
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-[#7C3AED]">Total Roles</span>
                                <div className="w-12 h-12 rounded-xl bg-violet-50 text-[#7C3AED] flex items-center justify-center transition-all group-hover:scale-110">
                                    <Shield className="w-6 h-6" />
                                </div>
                            </div>
                            <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                                {roles.length}
                            </div>
                        </motion.div>

                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.1 }}
                            className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                        >
                            <div className="flex justify-between items-start">
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-blue-500">System Roles</span>
                                <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-500 flex items-center justify-center transition-all group-hover:scale-110">
                                    <Lock className="w-6 h-6" />
                                </div>
                            </div>
                            <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                                {roles.filter(r => r.is_system).length}
                            </div>
                        </motion.div>

                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.2 }}
                            className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                        >
                            <div className="flex justify-between items-start">
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-emerald-500">Total Permissions</span>
                                <div className="w-12 h-12 rounded-xl bg-emerald-50 text-emerald-500 flex items-center justify-center transition-all group-hover:scale-110">
                                    <ShieldCheck className="w-6 h-6" />
                                </div>
                            </div>
                            <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                                {permissions.length}
                            </div>
                        </motion.div>

                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.3 }}
                            className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                        >
                            <div className="flex justify-between items-start">
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-amber-500">Security Health</span>
                                <div className="w-12 h-12 rounded-xl bg-amber-50 text-amber-500 flex items-center justify-center transition-all group-hover:scale-110">
                                    <ShieldHalf className="w-6 h-6" />
                                </div>
                            </div>
                            <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                                100%
                            </div>
                        </motion.div>
                    </div>

                    {/* Search and Filter Bar */}
                    <div className="flex flex-col md:flex-row items-center gap-4">
                        <div className="relative flex-1 group">
                            <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#7C3AED] transition-colors">search</span>
                            <input 
                                type="text"
                                placeholder="Search roles by name or description..."
                                className="w-full h-12 pl-12 pr-6 bg-white border border-slate-200 rounded-xl outline-none focus:border-violet-300 focus:ring-4 focus:ring-violet-50 transition-all font-medium text-sm"
