"use client";

import React, { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { BACKEND_URL } from "@/utils/api";
import { motion, AnimatePresence } from "framer-motion";
import { 
    Mail, 
    Plus, 
    Trash2, 
    Edit3, 
    Sparkles, 
    Zap, 
    X, 
    Save, 
    ArrowRight,
    FileText,
    History,
    ChevronDown,
    RefreshCcw,
    Layout
} from "lucide-react";
import ConfirmationModal from "@/components/common/ConfirmationModal";

interface Template {
    id: string;
    name: string;
    subject: string;
    body: string;
    category: string;
    variables: string[];
    created_at?: string;
    updated_at?: string;
}

export default function EmailTemplatesPage() {
    const { token, canAccess } = useAuth();
    const [templates, setTemplates] = useState<Template[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingTemplate, setEditingTemplate] = useState<Template | null>(null);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [templateToDelete, setTemplateToDelete] = useState<{ id: string; name: string } | null>(null);
    const [templateSearch, setTemplateSearch] = useState("");
    const [categoryFilter, setCategoryFilter] = useState("ALL");

    // Form State
    const [name, setName] = useState("");
    const [subject, setSubject] = useState("");
    const [body, setBody] = useState("");
    const [category, setCategory] = useState("GENERAL");

    // AI Generator State
    const [isAiMode, setIsAiMode] = useState(false);
    const [aiPurpose, setAiPurpose] = useState("");
    const [aiTone, setAiTone] = useState("professional");
    const [isGenerating, setIsGenerating] = useState(false);

    useEffect(() => {
        if (token) {
            fetchTemplates();
        }
    }, [token]);

    const formatDate = (dateString?: string) => {
        if (!dateString) return "Never";
        const date = new Date(dateString);
        return date.toLocaleString('en-US', {
            month: 'short',
            day: 'numeric',
            year: 'numeric'
        });
    };

    const fetchTemplates = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setTemplates(data);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setTimeout(() => setIsLoading(false), 600);
        }
    };

    const handleOpenModal = (template?: Template) => {
        setIsAiMode(false);
        setAiPurpose("");
        if (template) {
            setEditingTemplate(template);
            setName(template.name);
            setSubject(template.subject);
            setBody(template.body);
            setCategory(template.category || "GENERAL");
        } else {
            setEditingTemplate(null);
            setName("");
            setSubject("");
            setBody("");
            setCategory("GENERAL");
        }
        setIsModalOpen(true);
    };

    const handleAiGenerate = async () => {
        if (!aiPurpose.trim()) return;
        setIsGenerating(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/generate-template`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({
                    purpose: aiPurpose,
                    tone: aiTone
                })
            });

            const data = await res.json();

            if (res.ok) {
                let parsed;
                if (data.content) {
                    let cleanedContent = data.content;
                    if (cleanedContent.includes("```")) {
                        cleanedContent = cleanedContent.replace(/```json/g, "").replace(/```/g, "");
                    }
                    try {
                        parsed = JSON.parse(cleanedContent);
                    } catch (e) {
                        parsed = { body: cleanedContent };
                    }
                } else {
                    parsed = data;
                }

                if (parsed) {
                    if (typeof parsed === 'string') {
                        try { parsed = JSON.parse(parsed); } catch (e) { parsed = { body: parsed }; }
                    } else if (parsed.content && typeof parsed.content === 'string') {
                        try { parsed = JSON.parse(parsed.content); } catch (e) { }
                    }

                    let bodyContent = parsed.body || "";
                    if (bodyContent.startsWith("```html")) {
                        bodyContent = bodyContent.replace("```html", "").replace("```", "");
                    }

                    setName(parsed.name || `Template: ${aiPurpose.substring(0, 20)}...`);
                    setSubject(parsed.subject || "");
                    setBody(bodyContent);
                    setIsAiMode(false);
                }
            }
        } catch (e: any) {
            console.error(e);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleDelete = async () => {
        if (!templateToDelete) return;

        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates/${templateToDelete.id}`, {
                method: "DELETE",
                headers: { "Authorization": `Bearer ${token}` }
            });

            if (res.ok) {
                setTemplates(prev => prev.filter(t => t.id !== templateToDelete.id));
            }
        } catch (e: any) {
            console.error(e);
        } finally {
            setIsDeleteModalOpen(false);
            setTemplateToDelete(null);
        }
    };

    const handleSave = async () => {
        try {
            const url = editingTemplate
                ? `${BACKEND_URL}/api/v1/enterprise/communication/templates/${editingTemplate.id}`
                : `${BACKEND_URL}/api/v1/enterprise/communication/templates`;

            const method = editingTemplate ? "PATCH" : "POST";

            const res = await fetch(url, {
                method,
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({ name, subject, body, category, variables: [] })
            });

            if (res.ok) {
                fetchTemplates();
                setIsModalOpen(false);
            }
        } catch (e: any) {
            console.error(e);
        }
    };

    if (isLoading) {
        return (
            <div className="p-8 lg:p-12 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-500">
                <div className="h-32 bg-slate-900 rounded-2xl relative overflow-hidden flex items-center px-10 shadow-2xl">
                    <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-white/5 rounded-xl animate-pulse" />
                        <div className="space-y-2">
                            <div className="w-48 h-6 bg-white/10 rounded-xl animate-pulse" />
                            <div className="w-32 h-3 bg-white/5 rounded-xl animate-pulse" />
                        </div>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="bg-white h-64 rounded-2xl border border-slate-100 animate-pulse shadow-sm" />
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="p-4 sm:p-5 max-w-7xl mx-auto space-y-6 pb-20 animate-in fade-in duration-700 relative">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white rounded-xl border border-slate-100 p-2 shadow-lg shadow-slate-200/20">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-9 h-9 bg-violet-50 text-[#7C3AED] rounded-xl flex items-center justify-center">
                        <span className="material-symbols-rounded">mail</span>
                    </div>
                    <div>
                        <h1 className="text-lg font-black text-slate-900 tracking-tight">Email Templates</h1>
                        <p className="text-slate-500 text-[10px] font-medium   ">Standardize organizational outreach</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {canAccess("communications:moderate") && (
                        <button 
                            onClick={() => handleOpenModal()}
                            className="px-6 py-2.5 bg-[#7C3AED] text-white rounded-xl hover:bg-[#6D28D9] transition-all font-black text-[9px] uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-100"
                        >
                            <span className="material-symbols-rounded text-base">add</span>
                            New Template
                        </button>
                    )}
                    <button 
                        onClick={fetchTemplates}
                        className="w-10 h-10 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-[#7C3AED] hover:bg-slate-50 transition-all flex items-center justify-center shadow-sm"
                    >
                        <RefreshCcw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {/* Stat Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-[#7C3AED]">Total Templates</span>
                        <div className="w-12 h-12 rounded-xl bg-violet-50 text-[#7C3AED] flex items-center justify-center transition-all group-hover:scale-110">
                            <Mail className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-blue-500">Recruitment</span>
                        <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Zap className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.filter(t => t.category === 'INTERVIEW' || t.category === 'ASSESSMENT').length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-emerald-500">Onboarding</span>
                        <div className="w-12 h-12 rounded-xl bg-emerald-50 text-emerald-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Layout className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.filter(t => t.category === 'ONBOARDING').length}
                    </div>
                </motion.div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl transition-all group flex flex-col justify-between min-h-[140px]"
                >
                    <div className="flex justify-between items-start">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-amber-500">Dynamic Vars</span>
                        <div className="w-12 h-12 rounded-xl bg-amber-50 text-amber-500 flex items-center justify-center transition-all group-hover:scale-110">
                            <Sparkles className="w-6 h-6" />
                        </div>
                    </div>
                    <div className="text-4xl font-black text-slate-900 mt-auto leading-none">
                        {templates.reduce((acc, t) => acc + (t.variables?.length || 0), 0)}
                    </div>
                </motion.div>
            </div>

            {/* Search and Filter Bar */}
            <div className="flex flex-col md:flex-row items-center gap-4">
                <div className="relative flex-1 group">
                    <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#7C3AED] transition-colors">search</span>
                    <input 
                        type="text"
                        placeholder="Search templates by name or subject..."
                        className="w-full h-12 pl-12 pr-6 bg-white border border-slate-200 rounded-xl outline-none focus:border-violet-300 focus:ring-4 focus:ring-violet-50 transition-all font-medium text-sm"
                        value={templateSearch}
                        onChange={(e) => setTemplateSearch(e.target.value)}
                    />
                </div>
                <div className="flex items-center gap-2 bg-white border border-slate-200 p-1.5 rounded-xl shadow-sm">
                    <span className="material-symbols-rounded text-slate-400 pl-2">filter_list</span>
                    <select 
                        className="bg-transparent text-[10px] font-black uppercase tracking-widest text-slate-600 outline-none pr-4 cursor-pointer"
                        value={categoryFilter}
                        onChange={(e) => setCategoryFilter(e.target.value)}
                    >
                        <option value="ALL">All Categories</option>
                        <option value="GENERAL">General</option>
                        <option value="ASSESSMENT">Assessments</option>
                        <option value="INTERVIEW">Interviews</option>
                        <option value="ONBOARDING">Onboarding</option>
                    </select>
                </div>
            </div>

            {templates.length === 0 ? (
                <div className="text-center py-32 bg-white rounded-2xl border border-dashed border-slate-200">
                    <div className="w-20 h-20 bg-slate-50 text-slate-200 rounded-xl flex items-center justify-center mx-auto mb-6">
                        <Mail className="w-10 h-10" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-900 tracking-tight">No Templates Found</h3>
                    <p className="text-sm text-slate-400 font-medium mt-2 max-w-[280px] mx-auto leading-relaxed">Create your first email template to standardize candidate communication.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {templates.filter(t => {
                        const matchesSearch = (t.name + t.subject).toLowerCase().includes(templateSearch.toLowerCase());
                        const matchesCat = categoryFilter === "ALL" || t.category === categoryFilter;
                        return matchesSearch && matchesCat;
                    }).map((template) => (
                        <motion.div
                            layout
                            key={template.id}
                            className="group bg-white rounded-xl border border-slate-200/60 shadow-sm hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-1 transition-all duration-300 relative overflow-hidden cursor-pointer"
                            onClick={() => handleOpenModal(template)}
                        >
                            <div className="p-6 space-y-6">
                                <div className="flex justify-between items-start">
                                    <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                                        <FileText className="w-6 h-6 stroke-[1.5]" />
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); handleOpenModal(template); }}
                                            className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-[#7C3AED] hover:bg-violet-50 rounded-xl transition-all"
                                        >
                                            <span className="material-symbols-rounded text-lg">edit</span>
                                        </button>
                                        {canAccess("communications:delete") && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTemplateToDelete({ id: template.id, name: template.name });
                                                    setIsDeleteModalOpen(true);
                                                }}
                                                className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                                            >
                                                <span className="material-symbols-rounded text-lg">delete</span>
                                            </button>
                                        )}
                                    </div>
                                </div>

                                <div className="space-y-1">
                                    <div className="flex items-center gap-2 mb-2">
                                        <span className={`text-[10px] font-bold   px-3 py-1 rounded-lg ${
                                            template.category === 'ASSESSMENT' ? 'bg-purple-50 text-purple-600 border border-purple-100' :
                                            template.category === 'INTERVIEW' ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' :
                                            template.category === 'ONBOARDING' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                                            'bg-slate-100 text-slate-500'
                                        }`}>
                                            {template.category || 'General'}
                                        </span>
                                    </div>
                                    <h3 className="text-lg font-bold text-slate-900 group-hover:text-indigo-600 transition-colors truncate">{template.name}</h3>
                                    <p className="text-[10px] text-slate-400 font-medium tracking-tight">Template ID: {template.id.slice(0, 8)}</p>
                                </div>
                            </div>
                            
                            <div className="px-6 py-4 flex items-center justify-between bg-slate-50/50 border-t border-slate-200/50 rounded-b-3xl mt-auto">
                                <div className="flex items-center gap-2 text-slate-300">
                                    <History className="w-3.5 h-3.5" />
                                    <span className="text-[10px] font-bold  ">{formatDate(template.updated_at || template.created_at)}</span>
                                </div>
                                <div className="w-8 h-8 rounded-lg bg-white border border-slate-100 flex items-center justify-center text-slate-300 group-hover:text-indigo-600 group-hover:border-indigo-100 transition-all">
                                    <ArrowRight className="w-4 h-4" />
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            )}

            {/* Template Drawer */}
            <AnimatePresence>
                {isModalOpen && (
                    <div className="fixed inset-0 z-[200] flex justify-end overflow-hidden">
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/10 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
                        <motion.div initial={{ x: "100%" }} animate={{ x: 0 }} exit={{ x: "100%" }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="relative w-full max-w-2xl bg-white shadow-3xl h-full flex flex-col pointer-events-auto">
                            
                            {/* Drawer Header */}
                            <div className="flex items-center justify-between px-10 py-8 border-b border-slate-50 shrink-0">
                                <div className="flex items-center gap-6">
                                    <div className="w-14 h-14 rounded-xl bg-slate-900 flex items-center justify-center text-white shadow-xl">
                                        <Layout className="w-8 h-8 text-indigo-400" />
                                    </div>
                                    <div>
                                        <h2 className="text-2xl font-bold text-slate-900 tracking-tight leading-none">{isAiMode ? "AI Generation" : (editingTemplate ? "Edit Template" : "New Template")}</h2>
                                        <p className="text-sm text-slate-400 font-medium mt-2">Communication design and configuration</p>
                                    </div>
                                </div>
                                <button onClick={() => setIsModalOpen(false)} className="w-12 h-12 rounded-xl hover:bg-slate-50 flex items-center justify-center text-slate-400 transition-colors">
                                    <X className="w-6 h-6" />
                                </button>
                            </div>

                            {/* Drawer Body */}
                            <div className="flex-1 overflow-y-auto px-10 py-10 space-y-12 no-scrollbar">
                                
                                {!isAiMode && canAccess("communications:moderate") && (
                                    <div className="bg-indigo-600 rounded-xl p-8 text-white relative overflow-hidden shadow-xl shadow-indigo-100">
                                        <div className="relative z-10 flex items-center justify-between gap-6">
                                            <div className="space-y-1">
                                                <div className="flex items-center gap-3">
                                                    <Sparkles className="w-5 h-5 text-indigo-200" />
                                                    <span className="text-sm font-bold">Auto-generate with AI?</span>
                                                </div>
                                                <p className="text-xs text-indigo-100 font-medium">Let AI draft a professional template for you based on a few details.</p>
                                            </div>
                                            <button
                                                onClick={() => setIsAiMode(true)}
                                                className="px-6 h-12 bg-white text-indigo-600 rounded-xl font-bold text-xs hover:bg-slate-100 transition-all active:scale-95 shadow-xl"
                                            >
                                                Try AI Generator
                                            </button>
                                        </div>
                                    </div>
                                )}

                                {isAiMode ? (
                                    <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                                        <div className="space-y-3">
                                            <label className="text-xs font-bold text-slate-500 ml-1">Template Purpose</label>
                                            <textarea
                                                value={aiPurpose}
                                                onChange={e => setAiPurpose(e.target.value)}
                                                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-6 py-6 text-sm font-medium text-slate-800 outline-none focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-50 transition-all shadow-inner h-40 leading-relaxed"
                                                placeholder="e.g. Reject candidate for backend role but offer future talent pool inclusion..."
                                            />
                                        </div>
                                        <div className="grid grid-cols-2 gap-4 pt-4">
                                            <button onClick={() => setIsAiMode(false)} className="h-14 rounded-xl border border-slate-100 text-slate-400 font-bold text-xs hover:bg-slate-50 transition-all">Cancel</button>
                                            <button 
                                                onClick={handleAiGenerate}
                                                disabled={isGenerating || !aiPurpose.trim()}
                                                className="h-14 bg-slate-900 text-white rounded-xl font-bold text-xs hover:bg-indigo-600 transition-all active:scale-95 disabled:opacity-20 shadow-2xl flex items-center justify-center gap-3"
                                            >
                                                {isGenerating ? <RefreshCcw className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4 text-indigo-400" />}
                                                Generate Template
                                            </button>
                                        </div>
                                    </div>
                                ) : (
                                        <form id="template-form" onSubmit={e => { e.preventDefault(); handleSave(); }} className="space-y-10">
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                                <div className="space-y-2 group">
                                                    <label className="text-xs font-bold text-slate-500 ml-1 group-focus-within:text-indigo-600 transition-colors">Template Name</label>
                                                    <input
                                                        type="text"
                                                        value={name}
                                                        onChange={e => setName(e.target.value)}
                                                        className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-4 text-sm font-bold text-slate-900 outline-none focus:bg-white focus:border-indigo-600 transition-all shadow-inner"
                                                        placeholder="e.g. Assessment Invitation"
                                                        required
                                                        readOnly={!canAccess("communications:moderate")}
                                                    />
                                                </div>

                                                <div className="space-y-2 group">
                                                    <label className="text-xs font-bold text-slate-500 ml-1 group-focus-within:text-indigo-600 transition-colors">Category</label>
                                                    <select
                                                        value={category}
                                                        onChange={e => setCategory(e.target.value)}
                                                        className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-4 text-sm font-bold text-slate-900 outline-none focus:bg-white focus:border-indigo-600 transition-all shadow-inner cursor-pointer"
                                                        disabled={!canAccess("communications:moderate")}
                                                    >
                                                        <option value="GENERAL">General Communication</option>
                                                        <option value="ASSESSMENT">Assessment Invitation</option>
                                                        <option value="INTERVIEW">Interview Invitation</option>
                                                        <option value="ONBOARDING">Onboarding Invitation</option>
                                                    </select>
                                                </div>
                                            </div>
 
                                            <div className="space-y-2 group">
                                                <label className="text-xs font-bold text-slate-500 ml-1 group-focus-within:text-indigo-600 transition-colors">Email Subject</label>
                                                <input
                                                    type="text"
                                                    value={subject}
                                                    onChange={e => setSubject(e.target.value)}
                                                    className="w-full h-12 bg-slate-50 border border-slate-100 rounded-xl px-4 text-sm font-bold text-slate-900 outline-none focus:bg-white focus:border-indigo-600 transition-all shadow-inner"
                                                    placeholder="Subject line of the email"
                                                    required
                                                    readOnly={!canAccess("communications:moderate")}
                                                />
                                            </div>

                                            <div className="space-y-2 group">
                                                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 px-1 pb-2">
                                                        <label className="text-xs font-bold text-slate-500 group-focus-within:text-indigo-600 transition-colors">Email Body Content</label>
                                                        <div className="flex items-center gap-3">
                                                            <div className="relative group/insert">
                                                                <select 
                                                                    className="appearance-none bg-indigo-50 border border-indigo-100 rounded-xl px-4 py-1.5 pr-8 text-[10px] font-bold text-indigo-600   outline-none cursor-pointer hover:bg-white transition-all shadow-sm"
                                                                    onChange={(e) => {
                                                                        if (!e.target.value) return;
                                                                        const val = `{{${e.target.value}}}`;
                                                                        const textarea = document.getElementById('base-editor') as HTMLTextAreaElement;
                                                                        if (textarea) {
                                                                            const start = textarea.selectionStart;
                                                                            const end = textarea.selectionEnd;
                                                                            const text = textarea.value;
                                                                            const before = text.substring(0, start);
                                                                            const after = text.substring(end, text.length);
                                                                            setBody(before + val + after);
                                                                            
                                                                            setTimeout(() => {
                                                                                textarea.focus();
                                                                                textarea.setSelectionRange(start + val.length, start + val.length);
                                                                            }, 0);
                                                                        } else {
                                                                            setBody(prev => prev + val);
                                                                        }
                                                                        e.target.value = "";
                                                                    }}
                                                                >
                                                                <option value="">Quick Insert Link/Var</option>
                                                                <optgroup label="General">
                                                                    <option value="candidate_name">Candidate Name</option>
                                                                    <option value="job_title">Job Title</option>
                                                                    <option value="company_name">Company Name</option>
                                                                    <option value="recruiter_name">Recruiter Name</option>
                                                                </optgroup>
                                                                {category === 'ASSESSMENT' && (
                                                                    <optgroup label="Assessment">
                                                                        <option value="assessment_link">Assessment Link</option>
                                                                        <option value="test_duration">Test Duration</option>
                                                                        <option value="test_topic">Test Topic</option>
                                                                    </optgroup>
                                                                )}
                                                                {category === 'INTERVIEW' && (
                                                                    <optgroup label="Interview">
                                                                        <option value="interview_link">Interview Link</option>
                                                                        <option value="interview_time">Interview Time</option>
                                                                        <option value="interview_topic">Interview Topic</option>
                                                                    </optgroup>
                                                                )}
                                                                {category === 'ONBOARDING' && (
                                                                    <optgroup label="Onboarding">
                                                                        <option value="onboarding_link">Onboarding Link</option>
                                                                        <option value="onboarding_code">Onboarding Code</option>
                                                                    </optgroup>
                                                                )}
                                                            </select>
                                                            <ChevronDown className="w-3 h-3 text-indigo-400 absolute right-2.5 top-1/2 -translate-y-1/2 pointer-events-none" />
                                                        </div>
                                                    </div>
                                                </div>
                                                <textarea
                                                    id="base-editor"
                                                    value={body}
                                                    onChange={e => setBody(e.target.value)}
                                                    className="w-full h-[400px] bg-slate-50 border border-slate-100 rounded-xl px-8 py-8 text-sm font-medium text-slate-700 outline-none focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-50 transition-all shadow-inner leading-relaxed"
                                                    placeholder="Write your email content here. Use {{variable_name}} for dynamic data."
                                                    required
                                                    readOnly={!canAccess("communications:moderate")}
                                                />
                                            </div>
                                        </form>
                                )}
                            </div>

                            {/* Drawer Footer */}
                            {!isAiMode && canAccess("communications:moderate") && (
                                <div className="p-10 border-t border-slate-50 flex items-center justify-between gap-6 shrink-0">
                                    <p className="text-xs font-semibold text-slate-400 leading-relaxed max-w-[240px]">This template will be available for all automated campaigns and manual outreach.</p>
                                    <button 
                                        form="template-form"
                                        type="submit"
                                        className="px-10 h-14 bg-slate-900 text-white rounded-xl font-bold text-sm tracking-wide hover:bg-indigo-600 transition-all active:scale-[0.98] shadow-2xl flex items-center gap-3"
                                    >
                                        <Save className="w-4 h-4" />
                                        Save Template
                                    </button>
                                </div>
                            )}
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            <ConfirmationModal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                onConfirm={handleDelete}
                title="Delete Template?"
                message={`Are you sure you want to delete "${templateToDelete?.name}"? This action cannot be undone.`}
                confirmLabel="Delete Template"
                cancelLabel="Cancel"
                isDestructive={true}
            />
        </div>
    );
}

"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface AIAnalysis {
    summary: string;
    performance_score: number;
    strengths: string[];
    weaknesses: string[];
    recommendations: string[];
}

interface QuestionData {
    question_id: string;
    question_text: string;
    question_type: "RATING" | "TEXT" | "MCQ";
    average_score?: number;
    distribution: Record<string, number>;
    response_count: number;
    text_responses: string[];
}

interface Report {
    instance_name: string;
    total_invites: number;
    completed_invites: number;
    questions: QuestionData[];
}

export default function SurveyReport({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const { token } = useAuth();
    const router = useRouter();
    const [report, setReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);
    const [analyzing, setAnalyzing] = useState(false);
    const [aiAnalysis, setAiAnalysis] = useState<AIAnalysis | null>(null);

    useEffect(() => {
        const fetchReport = async () => {
            try {
                const res = await apiClient.get(`/api/v1/enterprise/surveys/report/${id}`);
                if (res.ok) {
                    setReport(await res.json());
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchReport();
    }, [id]);

    const generateAIInsights = async () => {
        setAnalyzing(true);
        try {
            const res = await apiClient.post(`/api/v1/enterprise/surveys/report/${id}/ai-analysis`, {});
            if (res.ok) {
                const data = await res.json();
                setAiAnalysis(data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setAnalyzing(false);
        }
    };

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center p-8 bg-slate-50">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    if (!report) return <div className="p-8 text-center text-slate-500 font-medium">Report data unavailable or unauthorized.</div>;

    const completionRate = report.total_invites > 0 ? (report.completed_invites / report.total_invites) * 100 : 0;

    return (
        <div className="p-6 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-20">
            <header className="flex justify-between items-center pb-8 border-b border-slate-100">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.push('/enterprise/surveys')} className="w-10 h-10 rounded-xl bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all flex items-center justify-center">
                        <span className="material-symbols-rounded text-xl">arrow_back</span>
                    </button>
                    <div>
                        <h1 className="text-3xl font-black text-slate-900 tracking-tight leading-none mb-2">{report.instance_name}</h1>
                        <p className="text-slate-400 font-black   text-[10px] flex items-center gap-2">
                            <span className="material-symbols-rounded text-sm text-indigo-500">analytics</span>
                            Aggregated Sentiment Analysis & Participation Data
                        </p>
                    </div>
                </div>
                <div className="flex gap-4">
                    {report.completed_invites < report.total_invites && (
                        <button 
                            onClick={() => {
                                apiClient.post(`/api/v1/enterprise/surveys/instances/${id}/notify`, {})
                                    .then(() => alert("Reminders sent to all pending participants!"))
                                    .catch(() => alert("Failed to send reminders."));
                            }}
                            className="px-6 py-3 bg-white border border-slate-200 text-slate-900 rounded-xl font-black text-[10px]  tracking-[0.2em] flex items-center gap-2 hover:bg-slate-50 transition-all"
                        >
                            <span className="material-symbols-rounded text-lg">campaign</span>
                            Remind Pending
                        </button>
                    )}
                </div>
            </header>

            {/* AI Strategic Intelligence Section */}
            <section className="relative overflow-hidden bg-slate-900 rounded-2xl p-10 md:p-14 text-white shadow-2xl shadow-indigo-200/20 group">
                {/* Decorative Elements */}
                <div className="absolute top-0 right-0 w-[40%] h-full bg-gradient-to-l from-indigo-500/10 to-transparent pointer-events-none"></div>
                <div className="absolute -top-24 -right-24 w-64 h-64 bg-indigo-500/20 rounded-full blur-[80px] group-hover:bg-indigo-500/30 transition-all duration-1000"></div>

                {!aiAnalysis && !analyzing ? (
                    <div className="flex flex-col md:flex-row items-center justify-between gap-12 relative z-10">
                        <div className="space-y-4 text-center md:text-left">
                            <h2 className="text-3xl font-black tracking-tight leading-none">Strategic AI Intelligence</h2>
                            <p className="text-slate-400 text-lg font-medium max-w-xl leading-relaxed">Let AI evaluate the organizational pulse, detect hidden risks, and suggest actionable strategic improvements based on this feedback.</p>
                        </div>
                        <button 
                            onClick={generateAIInsights}
                            className="px-10 py-5 bg-indigo-600 text-white rounded-xl font-black text-xs  tracking-[0.3em] flex items-center gap-3 hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-900/40 shrink-0"
                        >
                            <span className="material-symbols-rounded">psychology</span>
                            Generate Insights
                        </button>
                    </div>
                ) : analyzing ? (
                    <div className="flex flex-col items-center justify-center py-10 space-y-8 animate-pulse relative z-10">
                        <div className="w-16 h-16 border-4 border-indigo-400 border-t-white rounded-full animate-spin"></div>
                        <div className="text-center space-y-2">
                            <h3 className="text-xl font-black  ">Analyzing Pulse...</h3>
                            <p className="text-slate-400 font-black text-[10px] tracking-[0.3em]">PROCESSING AGGREGATED FEEDBACK VIA GPT-4o</p>
                        </div>
                    </div>
                ) : (
                    <div className="space-y-12 relative z-10 animate-in fade-in slide-in-from-bottom-8 duration-1000">
                        <header className="flex flex-col md:flex-row items-start justify-between gap-8 pb-10 border-b border-white/10">
                            <div className="space-y-4">
                                <div className="flex items-center gap-3">
                                    <span className="bg-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full  ">Strategic Insight</span>
                                    <span className="text-slate-500 font-black text-[10px]  ">Generated by Croar AI</span>
                                </div>
                                <h2 className="text-4xl font-black tracking-tighter leading-none">{report.instance_name} Summary</h2>
                                <p className="text-slate-300 text-lg font-medium max-w-3xl leading-relaxed ">"{aiAnalysis.summary}"</p>
                            </div>
                            <div className="bg-white/5 border border-white/10 p-8 rounded-2xl text-center min-w-[220px] backdrop-blur-xl shrink-0">
                                <p className="text-[10px] font-black text-indigo-400   mb-1">Health Score</p>
                                <div className="text-6xl font-black tracking-tighter text-indigo-100">{aiAnalysis.performance_score}</div>
                                <div className="w-full h-1.5 bg-white/5 rounded-full mt-4 overflow-hidden">
                                    <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${aiAnalysis.performance_score}%` }}></div>
                                </div>
                            </div>
                        </header>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                            <div className="space-y-6">
                                <h4 className="text-[10px] font-black text-indigo-400  tracking-[0.3em] px-2">Cultural Strengths</h4>
                                <ul className="space-y-3">
                                    {aiAnalysis.strengths.map((s: string, idx: number) => (
                                        <li key={idx} className="flex items-center gap-4 bg-white/5 p-5 rounded-xl border border-white/5 group hover:border-emerald-500/50 transition-all">
                                            <span className="material-symbols-rounded text-emerald-500">task_alt</span>
                                            <span className="text-sm font-bold text-slate-100">{s}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>
                            <div className="space-y-6">
                                <h4 className="text-[10px] font-black text-rose-400  tracking-[0.3em] px-2">Detected Risks</h4>
                                <ul className="space-y-3">
                                    {aiAnalysis.weaknesses.map((w: string, idx: number) => (
                                        <li key={idx} className="flex items-center gap-4 bg-white/5 p-5 rounded-xl border border-white/5 group hover:border-rose-500/50 transition-all">
                                            <span className="material-symbols-rounded text-rose-500">warning</span>
                                            <span className="text-sm font-bold text-slate-100">{w}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        </div>

                        <div className="pt-10 border-t border-white/10 space-y-6">
                            <h4 className="text-[10px] font-black text-indigo-400  tracking-[0.3em] px-2">AI Strategic Recommendations</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                {aiAnalysis.recommendations.map((r: string, idx: number) => (
                                    <div key={idx} className="bg-indigo-600/10 border border-indigo-500/20 p-8 rounded-2xl flex gap-5 group items-start hover:bg-indigo-600 transition-all duration-500">
                                        <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shrink-0 shadow-lg group-hover:bg-white group-hover:text-indigo-600 transition-all">
                                            <span className="material-symbols-rounded text-lg">lightbulb</span>
                                        </div>
                                        <p className="text-sm font-bold leading-relaxed text-slate-100 group-hover:text-white">{r}</p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </section>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/30">
                    <p className="text-slate-400 text-[9px] font-black   mb-1">Total Audience</p>
                    <p className="text-3xl font-black text-slate-900">{report.total_invites}</p>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/30">
                    <p className="text-slate-400 text-[9px] font-black   mb-1">Total Returns</p>
                    <p className="text-3xl font-black text-emerald-600">{report.completed_invites}</p>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/30 md:col-span-2">
                    <div className="flex justify-between items-end mb-2">
                        <p className="text-slate-400 text-[9px] font-black   leading-none">Participation Rate</p>
                        <p className="text-2xl font-black text-indigo-600 tracking-tight leading-none">{completionRate.toFixed(1)}%</p>
                    </div>
                    <div className="h-3 bg-slate-50 rounded-full overflow-hidden border border-slate-100 mt-2">
                        <div className="h-full bg-indigo-600 rounded-full transition-all duration-1000" style={{ width: `${completionRate}%` }}></div>
                    </div>
                </div>
            </div>

            <div className="space-y-6">
                <h2 className="text-[10px] font-black text-slate-400  tracking-[0.2em] px-1">Detailed Findings</h2>
                <div className="grid grid-cols-1 gap-6">
                    {report.questions.map((q: QuestionData) => (
                        <div key={q.question_id} className="bg-white p-8 rounded-2xl border border-slate-100 shadow-xl shadow-slate-100/20 space-y-8 group transition-all duration-500 hover:border-indigo-600">
                            <div className="flex gap-4 items-start">
                                <div className="w-8 h-8 rounded-xl bg-slate-50 text-slate-400 font-black text-xs flex items-center justify-center shrink-0 border border-slate-100 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm">
                                    <span className="material-symbols-rounded text-sm">question_mark</span>
                                </div>
                                <h3 className="text-xl font-black text-slate-900 tracking-tight leading-snug">{q.question_text}</h3>
                            </div>

                            {q.question_type === 'RATING' && (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center px-2">
                                    <div>
                                        <div className="flex justify-between items-end mb-4 pr-1">
                                            <p className="text-slate-400 text-[9px] font-black  ">Score Distribution</p>
                                            <p className="text-base font-black text-slate-900 font-mono ">AVG. {q.average_score?.toFixed(1) || '0.0'}</p>
                                        </div>
                                        <div className="space-y-4">
                                            {['5', '4', '3', '2', '1'].map(val => (
                                                <div key={val} className="flex items-center gap-4">
                                                    <span className="text-[10px] font-black text-slate-400 w-2 text-right">{val}</span>
                                                    <div className="flex-1 h-2 bg-slate-50 rounded-full overflow-hidden">
                                                        <div 
                                                            className="h-full bg-indigo-600/60 rounded-full transition-all duration-1000" 
                                                            style={{ width: `${(q.distribution[val] || 0) / q.response_count * 100}%` }}
                                                        ></div>
                                                    </div>
                                                    <span className="text-[9px] font-bold text-slate-400 font-mono w-6 text-right">{q.distribution[val] || 0}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                    <div className="flex items-center justify-center relative py-10">
                                        <div className="text-center space-y-2 relative z-10">
                                            <p className="text-7xl font-black text-slate-900 tracking-tighter leading-none">{q.average_score?.toFixed(1) || '0.0'}</p>
                                            <p className="text-[9px] font-black text-slate-400   bg-slate-50 px-3 py-1.5 rounded-full inline-block">Organizational Pulse</p>
                                        </div>
                                        <div className="absolute inset-0 flex items-center justify-center opacity-[0.03] select-none pointer-events-none">
                                            <span className="material-symbols-rounded text-[180px]">trending_up</span>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {q.question_type === 'TEXT' && (
                                <div className="space-y-4 max-h-[400px] overflow-y-auto no-scrollbar pr-2 pt-2">
                                    {q.text_responses.length > 0 ? q.text_responses.map((resp: string, idx: number) => (
                                        <div key={idx} className="bg-slate-50/50 p-6 rounded-xl border border-slate-100 text-sm font-medium text-slate-600  leading-relaxed hover:bg-white hover:shadow-lg hover:shadow-slate-100 transition-all border-l-4 border-l-indigo-600/30">
                                            "{resp}"
                                        </div>
                                    )) : (
                                        <p className="text-slate-300 font-black   text-[9px] text-center py-10 ">No textual entries were submitted for this item</p>
                                    )}
                                </div>
                            )}

                            {q.question_type === 'MCQ' && (
                                <div className="space-y-4">
                                    {Object.entries(q.distribution).map(([opt, count]) => (
                                        <div key={opt} className="space-y-2">
                                            <div className="flex justify-between text-[10px] font-black  ">
                                                <span className="text-slate-600">{opt}</span>
                                                <span className="text-indigo-600">{count} Choices</span>
                                            </div>
                                            <div className="h-2 bg-slate-50 rounded-full overflow-hidden">
                                                <div 
                                                    className="h-full bg-indigo-600/60 rounded-full" 
                                                    style={{ width: `${(count / q.response_count) * 100}%` }}
                                                ></div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface Template {
    id: string;
    title: string;
    description: string;
    survey_type: { name: string };
}

interface Employee {
    id: string;
    first_name: string;
    last_name: string;
    designation: string;
}

export default function LaunchSurvey() {
    const { token } = useAuth();
    const router = useRouter();
    const [templates, setTemplates] = useState<Template[]>([]);
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    
    // Form State
    const [formData, setFormData] = useState({
        template_id: "",
        name: "",
        start_date: new Date().toISOString().split('T')[0],
        end_date: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        target_group: "ALL" as "ALL" | "CUSTOM",
        employee_ids: [] as string[]
    });

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [tplRes, empRes] = await Promise.all([
                    apiClient.get('/api/v1/enterprise/surveys/templates'),
                    apiClient.get('/api/v1/enterprise/employees/')
                ]);
                if (tplRes.ok) setTemplates(await tplRes.json());
                if (empRes.ok) setEmployees(await empRes.json());
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const toggleEmployee = (id: string) => {
        setFormData(prev => {
            const ids = prev.employee_ids.includes(id) 
                ? prev.employee_ids.filter(e => e !== id) 
                : [...prev.employee_ids, id];
            return { ...prev, employee_ids: ids };
        });
    };

    const handleLaunch = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            const res = await apiClient.post('/api/v1/enterprise/surveys/launch', formData);
            if (res.ok) {
                alert("Survey campaign launched successfully!");
                router.push('/enterprise/surveys');
            } else {
                const error = await res.json();
                alert(`Failed to launch survey: ${error.message || "Unknown error"}`);
            }
        } catch (error) {
            console.error(error);
            alert("An error occurred while launching. Please try again.");
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) return <div className="p-8 text-center text-slate-400 font-bold   text-xs ">Syncing with personnel database...</div>;

    return (
        <div className="p-6 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700">
            <header className="flex justify-between items-center pb-6 border-b border-slate-100">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.push('/enterprise/surveys')} className="w-10 h-10 rounded-xl bg-white shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all flex items-center justify-center text-xl">
                        <span className="material-symbols-rounded">arrow_back</span>
                    </button>
                    <div>
                        <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-none mb-1">Launch Survey Campaign</h1>
                        <p className="text-slate-400 font-black   text-[9px]">Select target audience and deploy feedback framework</p>
                    </div>
                </div>
            </header>

            <form onSubmit={handleLaunch} className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
                <div className="lg:col-span-4 space-y-6">
                    <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/10 space-y-8">
                        <div>
                            <label className="block text-[10px] font-black text-slate-400   mb-3 px-1">Campaign Name</label>
                            <input 
                                className="w-full px-5 py-4 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-700"
                                value={formData.name}
                                onChange={(e) => setFormData({...formData, name: e.target.value})}
                                placeholder="e.g. Annual Engagement Survey"
                                required
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400   mb-3 px-1">Start Date</label>
                                <input 
                                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-xs font-bold text-slate-700"
                                    type="date"
                                    value={formData.start_date}
                                    onChange={(e) => setFormData({...formData, start_date: e.target.value})}
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-400   mb-3 px-1">End Date</label>
                                <input 
                                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-xs font-bold text-slate-700"
                                    type="date"
                                    value={formData.end_date}
                                    onChange={(e) => setFormData({...formData, end_date: e.target.value})}
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-slate-400   mb-4 px-1">Selected Framework</label>
                            <div className="space-y-2">
                                {templates.map(tpl => (
                                    <div 
                                        key={tpl.id}
                                        onClick={() => setFormData({...formData, template_id: tpl.id})}
                                        className={`p-4 border-2 rounded-xl cursor-pointer transition-all flex items-center justify-between gap-4 ${formData.template_id === tpl.id ? 'border-indigo-600 bg-indigo-50/30' : 'border-slate-50 bg-slate-50 hover:border-slate-200'}`}
                                    >
                                        <div className="min-w-0">
                                            <p className="text-[10px] font-black text-indigo-600  tracking-tighter mb-0.5">{tpl.survey_type.name}</p>
                                            <h4 className="font-black text-slate-900 text-xs truncate leading-tight">{tpl.title}</h4>
                                        </div>
                                        {formData.template_id === tpl.id && <span className="material-symbols-rounded text-indigo-600 text-lg">check_circle</span>}
                                    </div>
                                ))}
                            </div>
                        </div>

                        <button 
                            type="submit"
                            disabled={submitting || !formData.template_id || (formData.target_group === 'CUSTOM' && formData.employee_ids.length === 0)}
                            className="w-full py-5 bg-slate-900 text-white rounded-xl font-black text-[10px]  tracking-[0.2em] shadow-xl shadow-slate-100 hover:bg-indigo-600 transition-all flex items-center justify-center gap-2"
                        >
                            {submitting ? 'Launching...' : 'DEPLOY SURVEY'}
                        </button>
                    </div>
                </div>

                <div className="lg:col-span-8 bg-white p-6 rounded-xl border border-slate-100 shadow-xl shadow-slate-100/10 h-full flex flex-col relative overflow-hidden">
                    <div className="flex justify-between items-center mb-6 px-1 border-b border-slate-50 pb-6  tracking-[0.1em] font-black">
                        <div>
                            <h3 className="text-xl text-slate-900">Configure Audience</h3>
                            <p className="text-slate-400 text-[9px] mt-1">Select target employees for this campaign</p>
                        </div>
                        <div className="flex gap-2">
                            <button 
                                type="button" 
                                onClick={() => setFormData({...formData, target_group: 'ALL'})}
                                className={`px-4 py-2 rounded-xl text-[9px] font-black transition-all ${formData.target_group === 'ALL' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}
                            >
                                Entire Organization
                            </button>
                            <button 
                                type="button" 
                                onClick={() => setFormData({...formData, target_group: 'CUSTOM'})}
                                className={`px-4 py-2 rounded-xl text-[9px] font-black transition-all ${formData.target_group === 'CUSTOM' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}
                            >
                                Custom Selection
                            </button>
                        </div>
                    </div>

                    <div className={`grid grid-cols-2 lg:grid-cols-3 gap-3 overflow-y-auto pr-2 custom-scrollbar transition-opacity ${formData.target_group === 'ALL' ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                        {employees.map(emp => (
                            <div 
                                key={emp.id}
                                onClick={() => toggleEmployee(emp.id)}
                                className={`p-4 border-2 rounded-xl cursor-pointer transition-all flex items-center gap-3 ${formData.employee_ids.includes(emp.id) ? 'border-indigo-600 bg-indigo-50/30' : 'border-slate-50 bg-slate-50 hover:border-slate-200'}`}
                            >
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-[11px] transition-all border ${formData.employee_ids.includes(emp.id) ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-400 border-slate-100 shadow-sm'}`}>
                                    {formData.employee_ids.includes(emp.id) ? <span className="material-symbols-rounded text-sm font-black">check</span> : emp.first_name[0]}
                                </div>
                                <div className="min-w-0">
                                    <p className="text-[11px] font-black text-slate-900 truncate leading-tight">{emp.first_name} {emp.last_name}</p>
                                    <p className="text-[9px] font-black text-slate-400  tracking-tighter truncate">{emp.designation || 'Specialist'}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                    {formData.target_group === "ALL" && (
                        <div className="absolute inset-0 bg-white/60 backdrop-blur-[2px] z-10 flex items-center justify-center p-12 text-center pointer-events-none">
                            <div className="bg-white p-10 rounded-2xl shadow-2xl shadow-indigo-100 border border-slate-50 animate-in zoom-in duration-500 max-w-sm">
                                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center mx-auto mb-6">
                                    <span className="material-symbols-rounded text-4xl">public</span>
                                </div>
                                <h3 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-3">Organization Wide</h3>
                                <p className="text-[10px] font-black text-slate-400   leading-loose">
                                    Survey will be dispatched to <span className="text-indigo-600 font-black">all {employees.length} employees</span> in the personnel database.
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            </form>
        </div>
    );
}

"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";

interface SurveyType {
    id: string;
    name: string;
    description: string;
}

interface Question {
    text: string;
    type: "RATING" | "TEXT" | "MCQ";
    scale_min: number;
    scale_max: number;
    options?: string; // stringified JSON array
}

export default function EditTemplate({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const { token } = useAuth();
    const router = useRouter();
    const [types, setTypes] = useState<SurveyType[]>([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    
    // AI Wizard State
    const [isAiModalOpen, setIsAiModalOpen] = useState(false);
    const [industryNature, setIndustryNature] = useState("");
    const [generatingAi, setGeneratingAi] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        survey_type_id: "",
        title: "",
        description: "",
        questions: [] as Question[]
    });

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [typesRes, tplRes] = await Promise.all([
                    apiClient.get('/api/v1/enterprise/surveys/types'),
                    apiClient.get(`/api/v1/enterprise/surveys/templates/${id}`)
                ]);
                
                if (typesRes.ok) setTypes(await typesRes.json());
                if (tplRes.ok) {
                    const tpl = await tplRes.json();
                    setFormData({
                        survey_type_id: tpl.survey_type_id,
                        title: tpl.title,
                        description: tpl.description || "",
                        questions: tpl.questions.map((q: { text: string; type: Question["type"]; scale_min?: number; scale_max?: number; options?: string }) => ({
                            text: q.text,
                            type: q.type,
                            scale_min: q.scale_min || 1,
                            scale_max: q.scale_max || 5,
                            options: q.options || JSON.stringify(["Option 1", "Option 2"])
                        }))
                    });
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [id]);

    const addQuestion = () => {
        setFormData(prev => ({
            ...prev,
            questions: [...prev.questions, { text: "", type: "RATING", scale_min: 1, scale_max: 5, options: JSON.stringify(["Option 1", "Option 2"]) }]
        }));
    };

    const removeQuestion = (idx: number) => {
        setFormData(prev => ({
            ...prev,
            questions: prev.questions.filter((_, i) => i !== idx)
        }));
    };

    const updateQuestion = (idx: number, field: keyof Question, value: string | number) => {
        setFormData(prev => {
            const qs = [...prev.questions];
            qs[idx] = { ...qs[idx], [field]: value };
            return { ...prev, questions: qs };
        });
    };

    const handleOptionChange = (qIdx: number, optIdx: number, val: string) => {
        const q = formData.questions[qIdx];
        const opts = JSON.parse(q.options || "[]");
        opts[optIdx] = val;
        updateQuestion(qIdx, "options", JSON.stringify(opts));
    };

    const addOption = (qIdx: number) => {
        const q = formData.questions[qIdx];
        const opts = JSON.parse(q.options || "[]");
        opts.push(`Option ${opts.length + 1}`);
        updateQuestion(qIdx, "options", JSON.stringify(opts));
    };

    const removeOption = (qIdx: number, optIdx: number) => {
        const q = formData.questions[qIdx];
        const opts = JSON.parse(q.options || "[]").filter((_: string, i: number) => i !== optIdx);
        updateQuestion(qIdx, "options", JSON.stringify(opts));
    };

    const generateWithAi = async () => {
        if (!formData.survey_type_id || !industryNature) return;
        setGeneratingAi(true);
        try {
            const res = await apiClient.post('/api/v1/enterprise/surveys/ai-generate-questions', {
                survey_type_id: formData.survey_type_id,
                industry_nature: industryNature,
                count: 5
            });
            if (res.ok) {
                const aiQuestions = await res.json();
                const formatted = aiQuestions.map((q: { text: string; type: Question["type"]; options?: string[] }) => ({
                    text: q.text,
                    type: q.type,
                    scale_min: 1,
                    scale_max: 5,
                    options: q.options ? JSON.stringify(q.options) : JSON.stringify(["Option 1", "Option 2"])
                }));
                setFormData(prev => ({
                    ...prev,
                    questions: [...prev.questions, ...formatted]
                }));
                setIsAiModalOpen(false);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setGeneratingAi(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            const res = await apiClient.put(`/api/v1/enterprise/surveys/templates/${id}`, formData);
            if (res.ok) {
                alert("Framework updated successfully!");
                router.push('/enterprise/surveys/templates');
            } else {
                alert("Failed to update framework.");
            }
        } catch (error) {
            console.error(error);
            alert("An error occurred while saving.");
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center p-8 bg-slate-50">
            <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50/50">
            {/* Cleaner Header */}
            <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200 py-4 px-8 flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.push('/enterprise/surveys/templates')} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">
                        <span className="material-symbols-rounded">arrow_back</span>
                    </button>
                    <div>
                        <h1 className="text-xl font-bold text-slate-900 tracking-tight leading-none mb-1">Edit Framework</h1>
                        <p className="text-slate-500 text-xs font-medium">Refine your systematic question stacks</p>
                    </div>
                </div>
                <div className="flex gap-3">
                    <button 
                        type="button"
                        onClick={() => router.push('/enterprise/surveys/templates')}
                        className="px-5 py-2.5 text-slate-600 font-semibold text-xs hover:bg-slate-100 rounded-xl transition-all"
                    >
                        Discard
                    </button>
                    <button 
                        form="template-form"
                        type="submit"
                        disabled={submitting || !formData.survey_type_id || !formData.title || formData.questions.length === 0 || formData.questions.some(q => !q.text.trim())}
                        className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-semibold text-xs hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100 disabled:opacity-50 disabled:shadow-none"
                    >
                        {submitting ? 'Saving Changes...' : 'Save Framework'}
                    </button>
                </div>
            </header>

            <main className="max-w-4xl mx-auto p-8 lg:p-12 space-y-12 animate-in fade-in duration-700">
                <form id="template-form" onSubmit={handleSave} className="space-y-12">
                    {/* Simplified Strategy Block */}
                    <section className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-8">
                        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
                            <span className="material-symbols-rounded text-indigo-500">settings</span>
                            <h3 className="text-sm font-bold text-slate-900  ">Framework Configuration</h3>
                        </div>
                        
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-400   px-1">Survey Category</label>
                                <div className="relative">
                                    <select 
                                        className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-semibold text-slate-700 appearance-none transition-all"
                                        value={formData.survey_type_id}
                                        onChange={(e) => setFormData({...formData, survey_type_id: e.target.value})}
                                        required
                                    >
                                        <option value="">Select Target Type</option>
                                        {types.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                                    </select>
                                    <span className="material-symbols-rounded absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none text-lg">expand_more</span>
                                </div>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-400   px-1">Framework Title</label>
                                <input 
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-semibold text-slate-700 placeholder:text-slate-300 transition-all"
                                    value={formData.title}
                                    onChange={(e) => setFormData({...formData, title: e.target.value})}
                                    placeholder="e.g. Employee Engagement Q4"
                                    required
                                />
                            </div>
                            <div className="md:col-span-2 space-y-2">
                                <label className="text-[10px] font-bold text-slate-400   px-1">Executive Instructions</label>
                                <textarea 
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-semibold text-slate-700 placeholder:text-slate-300 min-h-[100px] transition-all leading-relaxed"
                                    value={formData.description}
                                    onChange={(e) => setFormData({...formData, description: e.target.value})}
                                    placeholder="Summary or instructions for employees..."
                                />
                            </div>
                        </div>
                    </section>

                    {/* Structured Question Pool */}
                    <section className="space-y-6">
                        <div className="flex justify-between items-center px-1">
                            <div className="flex items-center gap-3">
                                <h3 className="text-sm font-bold text-slate-900  ">Question Stack</h3>
                                <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-xl border border-indigo-100">
                                    {formData.questions.length} Items
                                </span>
                            </div>
                            <div className="flex gap-3">
                                <button 
                                    type="button" 
                                    onClick={() => setIsAiModalOpen(true)}
                                    disabled={!formData.survey_type_id}
                                    className="bg-slate-900 text-white text-[10px] font-bold   flex items-center gap-2 hover:bg-indigo-600 px-5 py-2.5 rounded-xl transition-all disabled:opacity-30"
                                >
                                    <span className="material-symbols-rounded text-lg">psychology</span>
                                    AI Wizard
                                </button>
                                <button 
                                    type="button" 
                                    onClick={addQuestion}
                                    className="bg-white border border-slate-200 text-slate-900 text-[10px] font-bold   flex items-center gap-2 hover:bg-slate-50 px-5 py-2.5 rounded-xl transition-all"
                                >
                                    <span className="material-symbols-rounded text-lg">add</span>
                                    Add Question
                                </button>
                            </div>
                        </div>
                        
                        <div className="space-y-6">
                            {formData.questions.map((q, i) => (
                                <div key={i} className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm flex flex-col gap-8 transition-all relative group animate-in slide-in-from-bottom-2 duration-300">
                                    <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button 
                                            type="button" 
                                            onClick={() => removeQuestion(i)}
                                            className="p-2 text-slate-400 hover:text-rose-600 bg-slate-50 hover:bg-rose-50 rounded-xl transition-all"
                                        >
                                            <span className="material-symbols-rounded text-xl">delete</span>
                                        </button>
                                    </div>
                                    
                                    <div className="flex gap-6 items-start">
                                        <div className="w-10 h-10 bg-slate-100 text-slate-400 font-bold rounded-xl flex items-center justify-center shrink-0 border border-slate-200">{i+1}</div>
                                        <div className="flex-1 space-y-6">
                                            <input 
                                                className="w-full bg-transparent border-none focus:ring-0 text-slate-900 font-bold text-xl placeholder:text-slate-100 p-0"
                                                value={q.text}
                                                onChange={(e) => updateQuestion(i, "text", e.target.value)}
                                                placeholder="Enter question text..."
                                                required
                                            />
                                            <div className="flex flex-wrap gap-2">
                                                {(["RATING", "TEXT", "MCQ"] as const).map(type => (
                                                    <button
                                                        key={type}
                                                        type="button"
                                                        onClick={() => updateQuestion(i, "type", type)}
                                                        className={`px-6 py-2 rounded-xl text-[10px] font-bold   transition-all border ${q.type === type ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' : 'bg-slate-50 border-slate-100 text-slate-400 hover:text-slate-600 hover:bg-slate-100'}`}
                                                    >
                                                        {type === 'RATING' ? 'Rating' : type === 'TEXT' ? 'Descriptive' : 'Multi-Choice'}
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                    </div>

                                    {q.type === 'MCQ' && (
                                        <div className="ml-16 space-y-4 animate-in fade-in duration-400">
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                {JSON.parse(q.options || "[]").map((opt: string, optIdx: number) => (
                                                    <div key={optIdx} className="flex gap-2 items-center group/opt">
                                                        <div className="w-8 h-8 rounded-xl bg-slate-50 flex items-center justify-center text-[10px] font-bold text-slate-300 group-hover/opt:bg-indigo-50 transition-colors shrink-0">{String.fromCharCode(65 + optIdx)}</div>
                                                        <input 
                                                            className="flex-1 px-4 py-2 bg-slate-50 border border-slate-100 rounded-xl text-sm font-semibold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500/20"
                                                            value={opt}
                                                            onChange={(e) => handleOptionChange(i, optIdx, e.target.value)}
                                                            required
                                                        />
                                                        <button 
                                                            type="button"
                                                            onClick={() => removeOption(i, optIdx)}
                                                            className="p-1 px-2 text-slate-300 hover:text-rose-500 transition-colors"
                                                        >
                                                            <span className="material-symbols-rounded text-lg">close</span>
                                                        </button>
                                                    </div>
                                                ))}
                                                <button 
                                                    type="button" 
                                                    onClick={() => addOption(i)}
                                                    className="px-6 py-2.5 border border-dashed border-slate-200 rounded-xl text-[10px] font-bold text-slate-400   hover:border-indigo-200 hover:text-indigo-600 transition-all flex items-center justify-center gap-2 bg-slate-50/20"
                                                >
                                                    <span className="material-symbols-rounded text-lg">add_circle</span>
                                                    Add Choice
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    </section>

                    <div className="pt-8 flex flex-col items-center border-t border-slate-100 pb-20">
                        <button 
                            type="submit"
                            disabled={submitting || !formData.survey_type_id || !formData.title || formData.questions.length === 0 || formData.questions.some(q => !q.text.trim())}
                            className="px-16 py-4 bg-indigo-600 text-white rounded-xl font-bold text-sm   shadow-xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-[1.01] transition-all disabled:opacity-30 disabled:shadow-none"
                        >
                            {submitting ? 'Saving Changes...' : 'Save Framework'}
                        </button>
                    </div>
                </form>
            </main>

            {/* Simplified AI Wizard Modal */}
            {isAiModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white rounded-xl w-full max-w-md shadow-2xl overflow-hidden animate-in zoom-in duration-200">
                        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                            <div className="flex items-center gap-3">
                                <span className="material-symbols-rounded text-indigo-600">psychology</span>
                                <h2 className="text-lg font-bold text-slate-900">AI Strategy Wizard</h2>
                            </div>
                            <button onClick={() => setIsAiModalOpen(false)} className="text-slate-400 hover:text-rose-500 transition-colors">
                                <span className="material-symbols-rounded">close</span>
                            </button>
                        </div>
                        <div className="p-8 space-y-6">
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-400   px-1">Describe Your Industry</label>
                                <input 
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-semibold text-slate-700 transition-all"
                                    value={industryNature}
                                    onChange={(e) => setIndustryNature(e.target.value)}
                                    placeholder="e.g. Fintech, Healthcare..."
                                    autoFocus
                                />
                                <p className="text-[10px] text-slate-400 font-medium px-1 ">Generated questions will reflect industry nuances.</p>
                            </div>
                            <button 
                                onClick={generateWithAi}
                                disabled={generatingAi || !industryNature}
                                className="w-full py-3.5 bg-slate-900 text-white rounded-xl font-bold text-xs   flex items-center justify-center gap-2 hover:bg-indigo-600 transition-all disabled:opacity-30"
                            >
                                {generatingAi ? (
                                    <>
                                        <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                        Generating...
                                    </>
                                ) : (
                                    <>
                                        <span className="material-symbols-rounded text-lg">magic_button</span>
                                        Generate Strategy
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

