                                        </label>
                                        <button
                                            type="button"
                                            onClick={() => setShowPassword(!showPassword)}
                                            className="absolute right-4 top-4 text-slate-400 hover:text-slate-600 transition-colors"
                                        >
                                            <span className="material-icons-outlined text-xl">
                                                {showPassword ? "visibility_off" : "visibility"}
                                            </span>
                                        </button>
                                    </div>
                                </div>

                                {error && (
                                    <div className="p-3 rounded-lg bg-slate-100 border border-slate-200 flex items-center gap-2">
                                        <span className="material-icons-outlined text-slate-500 text-lg">error_outline</span>
                                        <span className="text-xs font-bold text-slate-600">{error}</span>
                                    </div>
                                )}

                                <button
                                    type="submit"
                                    className="w-full py-5 bg-[var(--color-primary)] hover:bg-[var(--color-primary-dark)] text-white font-bold rounded-xl shadow-xl shadow-slate-200 transition-all active:scale-95 flex items-center justify-center gap-2"
