                                            <span className="material-icons-outlined text-sm">refresh</span>
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            ) : (
                /* -------------------------------------------------------------------------- */
                /*                               List View                                    */
                /* -------------------------------------------------------------------------- */
