                                                    {line.startsWith('✗') && <span className="material-icons-outlined text-[14px]">cancel</span>}
                                                    <span>{line.startsWith('✓') || line.startsWith('✗') ? line.slice(2) : line}</span>
                                                </div>
                                            ))}
                                            {Object.values(executingTests).some(v => v) && (
