}

const transformTestResults = (apiResult: AnalysisResult, questionId: string) => {
    if (!apiResult || !apiResult.test_results) return {};

    const map: { [key: string]: TransformedTestResult } = {};

    apiResult.test_results.forEach((r: TestResult, idx: number) => {
        const caseIndex = (r.case_id !== undefined && r.case_id !== null) ? r.case_id : idx;
        const testId = `${questionId}_${caseIndex}`;
        map[testId] = {
            passed: r.passed,
            actual: r.actual_output,
            expected: r.expected_output,
            message: r.message
        };
    });

    return map;
};

"use client";

import { useState, useRef, useEffect } from "react";
import { useSearchParams, useParams } from "next/navigation";
import Link from "next/link";
import { apiClient } from "@/utils/api";

export default function CommunicationDetail() {
    const params = useParams();
    const searchParams = useSearchParams();
    const title = searchParams.get("title");
    const prompt = searchParams.get("prompt");

    const [isRecording, setIsRecording] = useState(false);
    const [audioURL, setAudioURL] = useState<string | null>(null);
    const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
    const [analyzing, setAnalyzing] = useState(false);
    const [feedback, setFeedback] = useState<any | null>(null);
    const [error, setError] = useState<string | null>(null);

    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const chunksRef = useRef<Blob[]>([]);

    // Check for HTTPS/Secure Context
    useEffect(() => {
        if (typeof window !== 'undefined' && !window.isSecureContext) {
            setError("Microphone access requires HTTPS or localhost. Please enable SSL or use localhost.");
        }
    }, []);

    const startRecording = async () => {
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
            setError("Microphone not supported. Please use HTTPS or localhost.");
            return;
        }

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaRecorderRef.current = new MediaRecorder(stream);
            chunksRef.current = [];

            // Clear previous recording state
            setAudioURL(null);
            setAudioBlob(null);

            mediaRecorderRef.current.ondataavailable = (e) => {
                if (e.data.size > 0) {
                    chunksRef.current.push(e.data);
                }
            };

            mediaRecorderRef.current.onstop = () => {
                const blob = new Blob(chunksRef.current, { type: "audio/webm" });
                const url = URL.createObjectURL(blob);
                setAudioURL(url);
                setAudioBlob(blob);

                // Stop all tracks to turn off the microphone hardware
                stream.getTracks().forEach((track) => {
                    track.stop();
                    console.log("Track stopped:", track.label);
                });
            };

            mediaRecorderRef.current.start();
            setIsRecording(true);
            setFeedback(null);
            setError(null);
        } catch (err) {
            console.error("Error accessing microphone:", err);
            setError("Microphone access denied or not available.");
        }
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
        }
    };

    const submitRecording = async () => {
        // Safety check: Stop recording if it's still running
        if (isRecording) {
            stopRecording();
        }

        if (!audioBlob) return;

        setAnalyzing(true);
        setError(null);

        const formData = new FormData();
        formData.append("file", audioBlob, "recording.webm");

        // Pass scenario_id from URL params if available (it comes from [id])
        if (params && params.id) {
            formData.append("scenario_id", params.id as string);
        }

        try {
            // apiClient handles FormData automatically
            const res = await apiClient.post(`/api/v1/coach/analyze`, formData);

            if (!res.ok) {
                throw new Error("Analysis failed");
            }

            const data = await res.json();
            setFeedback(data);

