"use client";

import { useState, useEffect } from "react";
import { apiClient } from "@/utils/api";
import Link from "next/link";

// ─── Types ────────────────────────────────────────────────────────────────────

interface ResumeTemplate {
    id: string;
    name: string;
    extracted_fields?: {
        sections?: Record<string, unknown>[];
    };
}

interface ResumeSubmission {
    id: number;
    template_id: string;
    created_at: string;
}

export default function ResumeBuilderStudent() {
    const [templates, setTemplates] = useState<ResumeTemplate[]>([]);
    const [submissions, setSubmissions] = useState<ResumeSubmission[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const load = async () => {
            await Promise.all([fetchTemplates(), fetchSubmissions()]);
            setIsLoading(false);
        };
        load();
    }, []);

    const fetchTemplates = async () => {
        try {
            const res = await apiClient.get(`/api/v1/resume/builder/templates`);
            if (res.ok) {
                setTemplates(await res.json());
            }
        } catch (err) { console.error(err); }
    };

    const fetchSubmissions = async () => {
        try {
            const res = await apiClient.get(`/api/v1/resume/builder/submissions/my`);
            if (res.ok) {
                setSubmissions(await res.json());
            }
        } catch (err) { console.error(err); }
    };

    const handleDeleteSubmission = async (id: number) => {
        if (!confirm("Delete this resume?")) return;
        try {
            const res = await apiClient.delete(`/api/v1/resume/builder/submission/${id}`);
            if (res.ok) fetchSubmissions();
        } catch (err) { console.error(err); }
    };

    if (isLoading) return <div className="p-8 text-center text-slate-500 font-bold">Loading...</div>;

    return (
        <div className="max-w-7xl mx-auto space-y-12">
            {/* Hero Section */}
            <section className="relative overflow-hidden rounded-[1.5rem] bg-orange-600 p-6 text-white shadow-lg">
                <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div className="space-y-3">
                        <h2 className="text-2xl font-black  tracking-tight">Resume Builder</h2>
                        <p className="text-slate-100 text-xs max-w-sm font-medium leading-relaxed">
                            Choose a professional template approved by your institution.
                            Our system will guide you through the required fields to build a perfect resume.
                        </p>
                    </div>
                    <div className="flex items-center gap-4 bg-white/10 p-4 rounded-xl backdrop-blur-md border border-white/20 min-w-[140px]">
                        <div className="w-12 h-12 bg-white/20 rounded-lg flex items-center justify-center text-white">
                            <span className="material-icons-outlined text-2xl">build</span>
                        </div>
                    </div>
                </div>
                <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/4 w-64 h-64 bg-white/5 rounded-full blur-3xl"></div>
                <div className="absolute bottom-0 left-0 translate-y-1/2 -translate-x-1/4 w-48 h-48 bg-slate-500/10 rounded-full blur-2xl"></div>
            </section>

            {submissions.length > 0 && (
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                        <span className="material-icons-outlined text-slate-600">history</span>
                        My Resumes
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {submissions.map((s: ResumeSubmission) => {
                            const tmpl = templates.find((t: ResumeTemplate) => t.id === s.template_id);
                            return (
                                <div key={s.id} className="bg-orange-50/50 p-6 rounded-xl border border-orange-100 shadow-sm hover:shadow-md transition-shadow">
                                    <div className="flex items-start justify-between mb-2">
                                        <h3 className="font-bold text-slate-800">{tmpl?.name || "Resume"}</h3>
                                        <span className="text-[10px] font-bold bg-slate-100 text-slate-600 px-2 py-1 rounded-full border border-slate-200">COMPLETED</span>
                                    </div>
                                    <p className="text-xs text-slate-400 font-medium mb-4">
                                        Created on {new Date(s.created_at).toLocaleDateString()}
                                    </p>
                                    <div className="flex gap-2">
                                        <Link href={`/practice/resume-builder/submission/${s.id}`} className="flex-1 flex items-center justify-center text-xs font-bold text-slate-600 bg-slate-100 px-3 py-2 rounded-lg hover:bg-slate-200 transition-colors">
                                            View
                                        </Link>
                                        <Link href={`/practice/resume-builder/${s.template_id}?sub=${s.id}`} className="flex items-center justify-center px-3 py-2 bg-slate-50 text-slate-500 rounded-lg hover:bg-slate-100 transition-colors" title="Edit Data">
                                            <span className="material-icons-outlined text-sm">edit</span>
                                        </Link>
                                        <button
                                            onClick={() => handleDeleteSubmission(s.id)}
                                            className="flex items-center justify-center px-3 py-2 bg-slate-50 text-slate-500 rounded-lg hover:bg-slate-100 transition-colors"
                                            title="Delete Resume"
                                        >
                                            <span className="material-icons-outlined text-sm">delete</span>
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            <div>
                <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                    <span className="material-icons-outlined text-slate-600">add_circle_outline</span>
                    Create New Resume
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    {templates.map((t: ResumeTemplate) => (
                        <Link key={t.id} href={`/practice/resume-builder/${t.id}`} className="group relative bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-xl hover:-translate-y-1 transition-all duration-300 h-full flex flex-col">
                            <div className="h-40 bg-slate-50 flex items-center justify-center group-hover:bg-slate-100 transition-colors">
                                <span className="material-icons-outlined text-6xl text-slate-300 group-hover:text-slate-500 transition-colors">description</span>
                            </div>
                            <div className="p-6 flex-1">
                                <h3 className="text-lg font-bold text-slate-900 group-hover:text-slate-600 transition-colors">{t.name}</h3>
                                <p className="text-xs text-slate-400 mt-2 font-bold  ">{t.extracted_fields?.sections?.length || 0} Sections</p>
                            </div>
                            <div className="absolute top-4 right-4 h-8 w-8 rounded-full bg-white flex items-center justify-center shadow text-slate-600 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                                <span className="material-icons-outlined text-sm">arrow_forward</span>
                            </div>
                        </Link>
                    ))}

                    {templates.length === 0 && (
                        <div className="col-span-full py-20 text-center">
                            <div className="inline-block p-4 rounded-full bg-slate-100 mb-4">
                                <span className="material-icons-outlined text-2xl text-slate-400">inventory_2</span>
                            </div>
                            <h3 className="text-lg font-bold text-slate-600">No Templates Available</h3>
                            <p className="text-sm text-slate-400">Check back later when admin uploads new resume templates.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { apiClient } from "@/utils/api";
import { useParams } from "next/navigation";
import Link from "next/link";
import Handlebars from "handlebars";

interface ResumeSubmission {
    id: string;
    template_id: string;
    data: Record<string, any>;
}

interface ResumeTemplate {
    id: string;
    html_template?: string;
    extracted_fields?: {
        sections: {
            title: string;
            label?: string;
            type?: 'list' | 'text';
        }[];
    };
}

export default function ResumeViewer() {
    const { id } = useParams();
    const [submission, setSubmission] = useState<ResumeSubmission | null>(null);
    const [template, setTemplate] = useState<ResumeTemplate | null>(null);
    const [loading, setLoading] = useState(true);
    const resumeRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (id) fetchSubmission();
    }, [id]);

    const fetchSubmission = async () => {
        try {
            const res = await apiClient.get(`/api/v1/resume/builder/submission/${id}`);
            if (res.ok) {
                const sub = await res.json();
                setSubmission(sub);
                const resT = await apiClient.get(`/api/v1/resume/builder/template/${sub.template_id}`);
                if (resT.ok) {
                    setTemplate(await resT.json());
                }
            }
        } catch (e) { console.error(e); }
        finally { setLoading(false); }
    };

    const handlePrint = () => {
        window.print();
    };

    if (loading) return <div className="p-10 text-center">Loading resume...</div>;
    if (!submission || !template) return <div className="p-10 text-center">Resume not found</div>;

    const { data } = submission;

    // Render Logic
    const renderContent = () => {
        // 1. Try HTML Template (Handlebars)
        if (template.html_template) {
            let templateStr = template.html_template;
            try {
                // Register helper if needed (e.g. format dates?)
                // Fix potential single-brace syntax from LLM (e.g. Svelte style)



                // 0. Ultra-robust normalization: Force collapse ANY sequence of 2+ braces
                // We use multiple strategies to ensure zero "triple brace" leaks.
                templateStr = templateStr
                    .replace(/\{{2,}/g, '{{')
                    .replace(/\}{2,}/g, '}}');

                // 1. Fix blocks with spaces: {{ #each ... }} -> {{#each ...}}
                // This is the specific fix for the user's reported error.
                templateStr = templateStr.replace(/\{\{\s+#([a-z1-9_]+)/gi, '{{#$1');
                templateStr = templateStr.replace(/\{\{\s+\/([a-z1-9_]+)/gi, '{{/$1');

                // 2. Fix trailing partial braces: some_text}}{{ or some_text}}{{{
                templateStr = templateStr.replace(/\}\}\{{1,3}$/g, '}}');
                templateStr = templateStr.replace(/\}\}\{\{\s*$/g, '}}');

                // 3. Fix single-brace blocks: {#each ...} -> {{#each ...}}
                templateStr = templateStr.replace(/(?<!\{)\{#([a-z1-9_]+)\s+([^}]+)\}(?!\})/gi, '{{#$1 $2}}');
                templateStr = templateStr.replace(/(?<!\{)\{\/([a-z1-9_]+)\}(?!\})/gi, '{{/$1}}');

                // 4. Fix single-brace variables: {var} -> {{var}}
                templateStr = templateStr.replace(/(?<!\{)\{([a-zA-Z0-9_\.]+)\}(?!\})/g, '{{$1}}');

                const compiled = Handlebars.compile(templateStr);
                return <div dangerouslySetInnerHTML={{ __html: compiled(data) }} className="resume-html" />;
            } catch (e) {
                console.error("Handlebars Template Error", {
                    message: (e as Error).message,
                    template: templateStr,
                });
                return (
                    <div className="text-red-500 p-4 border border-red-200 bg-red-50 rounded">
                        <strong>Template Rendering Error (v6):</strong> Invalid resume template. Please fix syntax errors.
                    </div>
                );
            }
        }

        // 2. Fallback: Heuristic Rendering
        const { sections } = template.extracted_fields || { sections: [] };
        return (
            <>
                {sections.map((section: any) => {
                    const sectionData = data[section.title];
                    if (!sectionData) return null;

                    const isPersonal = section.title.includes("personal") || section.title.includes("contact");
                    const isList = section.type === 'list';

                    if (isPersonal) {
                        return (
                            <div key={section.title} className="mb-8 border-b-2 border-slate-800 pb-6 text-center">
                                <h1 className="text-4xl font-black text-slate-900 mb-2  tracking-tight">
                                    {sectionData.name || sectionData.full_name || sectionData.first_name + " " + sectionData.last_name || "Name"}
                                </h1>
                                <div className="flex flex-wrap justify-center gap-4 text-sm text-slate-600 font-medium">
                                    {Object.entries(sectionData).map(([k, v]) => {
                                        if (k.includes("name") || !v) return null;
                                        return <span key={k}>{String(v)}</span>;
                                    })}
                                </div>
                            </div>
                        );
                    }

                    return (
                        <div key={section.title} className="mb-6">
                            <h2 className="text-lg font-bold text-slate-900   mb-3 border-b border-slate-900 pb-1">
                                {section.label || section.title}
                            </h2>

                            {isList && Array.isArray(sectionData) ? (
                                <div className="space-y-4">
                                    {sectionData.map((item: any, idx) => (
                                        <div key={idx} className="mb-2">
                                            <div className="flex justify-between items-baseline mb-1">
                                                <h3 className="font-bold text-slate-800 text-md">
                                                    {item.title || item.role || item.position || item.degree || item.university || item.company || Object.values(item)[0]}
                                                </h3>
                                                <span className="text-sm text-slate-500 font-bold whitespace-nowrap">
                                                    {item.date || item.duration || item.year || ""}
                                                </span>
                                            </div>
                                            {(item.company || item.university) && (item.company !== item.title && item.university !== item.title) && (
                                                <p className="text-sm text-slate-600 font-semibold mb-1 ">
                                                    {item.company || item.university} {item.location ? `· ${item.location}` : ''}
                                                </p>
                                            )}
                                            <div className="text-sm text-slate-600 leading-relaxed text-justify">
                                                {item.description || item.summary || item.details ||
                                                    Object.entries(item).map(([k, v]) => {
                                                        if (['title', 'role', 'date', 'year', 'company', 'university', 'location'].includes(k)) return null;
                                                        return <div key={k}>{String(v)}</div>
                                                    })
                                                }
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-sm text-slate-700 leading-relaxed text-justify whitespace-pre-line">
                                    {sectionData.description || sectionData.summary || Object.values(sectionData).join(" ")}
                                </div>
                            )}
                        </div>
                    );
                })}
            </>
        )
    };

    return (
        <div className="max-w-5xl mx-auto pb-20 print:p-0 print:max-w-none">
            <div className="flex justify-between items-center mb-8 print:hidden">
                <Link href="/practice/resume-builder" className="text-sm font-bold text-slate-500 hover:text-slate-900 transition-colors">← Back to Dashboard</Link>
                <div className="flex gap-4">
                    <Link
                        href={`/practice/resume-builder/${submission.template_id}?sub=${submission.id}`}
                        className="flex items-center gap-2 bg-slate-100 text-slate-700 px-6 py-2.5 rounded-xl font-bold hover:bg-slate-200 transition-colors"
                    >
                        <span className="material-icons-outlined">edit</span>
                        Edit Data
                    </Link>
                    <button
                        onClick={handlePrint}
                        className="flex items-center gap-2 bg-slate-900 text-white px-6 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-colors shadow-lg"
                    >
                        <span className="material-icons-outlined">print</span>
                        Download / Print PDF
                    </button>
                </div>
            </div>

            <div ref={resumeRef} className="bg-white shadow-2xl print:shadow-none p-12 min-h-[1100px] w-full mx-auto rounded-none print:w-full text-left">
                {renderContent()}
            </div>

            <style jsx global>{`
                @media print {
                    @page { margin: 0; size: auto; }
                    body { background: white; }
                    nav, header, footer, aside, .no-print { display: none !important; }
                    .print\\:hidden { display: none !important; }
                    .print\\:p-0 { padding: 0 !important; }
                    .print\\:w-full { width: 100% !important; max-width: none !important; }
                    .print\\:shadow-none { box-shadow: none !important; }
                }
            `}</style>
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { Document, Page, pdfjs } from "react-pdf";
import { apiClient } from "@/utils/api";
import AIGenerationOverlay from "@/components/ui/AIGenerationOverlay";
import "react-pdf/dist/Page/TextLayer.css";
import "react-pdf/dist/Page/AnnotationLayer.css";

// Set worker source
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

interface ResumeConfig {
    id: number;
    name: string;
}

interface Feedback {
    quote: string;
    issue: string;
    improvement: string;
    suggested_fix?: string;
    severity: string;
    bboxes?: {
        page: number;
        x: number;
        y: number;
        w: number;
        h: number;
        page_width: number;
        page_height: number;
    }[];
}

interface ResumeResult {
    id: number;
    score: number;
    ai_feedback: Feedback[];
    file_url: string; // In real app, this would be a public URL or blobs
    parsed_text: string;
}

export default function StudentResumeScorerPage() {
    const [configs, setConfigs] = useState<ResumeConfig[]>([]);
    const [selectedConfig, setSelectedConfig] = useState<string>("");
    const [file, setFile] = useState<File | null>(null);
    const [analyzing, setAnalyzing] = useState(false);
    const [result, setResult] = useState<ResumeResult | null>(null);
    const [error, setError] = useState("");
    const [numPages, setNumPages] = useState<number>(0);
    const [containerWidth, setContainerWidth] = useState<number>(600);
    const containerRef = useRef<HTMLDivElement>(null);

    // Initial load
    useEffect(() => {
        fetchConfigs();
    }, []);

    // Resize observer for responsive PDF
    useEffect(() => {
        if (!containerRef.current) return;
        const resizeObserver = new ResizeObserver((entries) => {
            const { width } = entries[0].contentRect;
            setContainerWidth(width);
        });
        resizeObserver.observe(containerRef.current);
        return () => resizeObserver.disconnect();
    }, [result]); // Re-bind if result changes (showing PDF)

    const fetchConfigs = async () => {
        try {
            const res = await apiClient.get(`/api/v1/resume/config`);
            if (res.ok) {
                const data = await res.json();
                setConfigs(data);
                if (data.length > 0) setSelectedConfig(data[0].id.toString());
            }
        } catch (e) {
            console.error(e);
        }
    };

    const handleUpload = async () => {
        if (!file || !selectedConfig) return;
        setAnalyzing(true);
        setError("");

        const formData = new FormData();
        formData.append("file", file);

        try {
            // Note: The backend expects query param config_id, not form data
            const res = await apiClient.post(`/api/v1/resume/scan?config_id=${selectedConfig}`, formData);

            if (res.ok) {
                const data = await res.json();
                setResult(data);
            } else {
                setError("Failed to analyze resume. Please try again.");
            }
        } catch (e) {
            console.error(e);
            setError("Network error. Please try again.");
        } finally {
            setAnalyzing(false);
        }
    };

    const [pdfDocument, setPdfDocument] = useState<pdfjs.PDFDocumentProxy | null>(null);

    const onDocumentLoadSuccess = (pdf: pdfjs.PDFDocumentProxy) => {
        setNumPages(pdf.numPages);
        setPdfDocument(pdf);
    };

    // Process feedback to find text coordinates on the frontend
    useEffect(() => {
        if (!result || !pdfDocument) return;

        const processText = async () => {
            const newFeedback = JSON.parse(JSON.stringify(result.ai_feedback));

            for (let i = 0; i < newFeedback.length; i++) {
                const item = newFeedback[i];
                const cleanQuote = item.quote ? item.quote.replace(/\s+/g, ' ').trim().toLowerCase() : "";
                if (!cleanQuote) continue;

                // Search through pages
                const bboxes = [];
                for (let p = 1; p <= pdfDocument.numPages; p++) {
                    try {
                        const page = await pdfDocument.getPage(p);
                        const textContent = await page.getTextContent();
                        const viewport = page.getViewport({ scale: 1 });

                        let pageText = "";
                        const itemMap: { start: number; end: number; box: any }[] = []; // Maps char index to item box

                        // Build page text and coordinate map
                        textContent.items.forEach((item: any) => {
                            const str = item.str;
                            // PDF coordinates are (x, y) from bottom-left
                            // viewport helps convert. But usually raw TextContent has transform
                            // item.transform [scaleX, skewY, skewX, scaleY, x, y]
                            const tx = item.transform;
                            const x = tx[4];
                            const y = tx[5]; // bottom-left y
                            const w = item.width;
                            const h = item.height || (tx[3]); // Approx height from scaleY

                            // Store standard coord system (top-left based for simplified rendering?)
                            // Actually, let's keep PDF raw coords and normalize later, or use page dimensions
                            // pdfplumber used (x, top, w, h). 
                            // PDFJS gives (x, y=bottom-left). We need to flip y.
                            // y_top = page_height - y_bottom - height

                            const pageHeight = viewport.height / viewport.scale; // clean height
                            const pageWidth = viewport.width / viewport.scale;

                            // We need real PDF coords. item.transform gives them.
                            // Convert to Top-Left based standard
                            // y in PDF is from bottom.

                            // Let's just store the item and process match
                            const startIdx = pageText.length;
                            pageText += str + " "; // Add space separator
                            const endIdx = pageText.length;

                            itemMap.push({
                                start: startIdx,
                                end: endIdx,
                                box: {
                                    page: p,
                                    x: x,
                                    y: pageHeight - y - h, // Convert bottom-left y to top-left y. 
                                    // Note: This y might be baseline. 
                                    // Usually y is baseline. top = pageHeight - y - extra?
                                    // Let's try standard bbox logic.
                                    w: w,
                                    h: h,
                                    page_width: pageWidth,
                                    page_height: pageHeight
                                }
                            });
                        });

                        const cleanPageText = pageText.replace(/\s+/g, ' ').toLowerCase();
                        // Find quote
                        // Note: The spaces logic makes index alignmen tricky.
                        // Simple search:
                        const matchIdx = cleanPageText.indexOf(cleanQuote);

                        if (matchIdx !== -1) {
                            // Found match on this page!
                            // Find which items overlap with this range
                            // This is approximate due to normalization, but "GOOD ENOUGH" for highlighting usually.
                            // Getting items corresponding vaguely to the match.

                            // Since we normalized spaces, direct index mapping is hard.
                            // Fallback: Check each item string validity?
                            // Better: Just use the text items that contain words from the quote.

                            const quoteWords = cleanQuote.split(' ');
                            const matchedItems = textContent.items.filter((t: any) => {
                                const tStr = t.str.toLowerCase();
                                return quoteWords.some((qw: string) => tStr.includes(qw) && qw.length > 3);
                            });

                            // This is too loose. It highlights all occurrences of "Experience".
                            // But usually a quote is unique-ish long sentence.

                            // Let's rely on the backend provided bboxes if this is too complex?
                            // User explicitly said "instead of axes check text".
                            // Okay, let's assume the quote is unique.

                            // Let's loop items and substring check "loosely".
                            // Actually, let's just highlight the Backend BBoxes but with better logic?
                            // No, user assumes backend boxes are wrong.

                            // Let's stick to the simple plan: Text Layer + CSS.
                            // Changing code to enable Text Layer and highlight using DOM.
                            // That is easiest.
                        }
                    } catch (e) { console.error(e); }
                }
            }
            // setProcessedFeedback(newFeedback);
        };
        // processText();
    }, [result, pdfDocument]);

    // ... Keeping old logic for now but switching to Render Highlights v2

    const renderHighlights = (pageIndex: number) => {
