            </main>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Plus_Jakarta_Sans } from "next/font/google";
import Link from "next/link";
import { BACKEND_URL } from "@/utils/api";

const plusJakartaSans = Plus_Jakarta_Sans({ subsets: ["latin"] });

export default function StudentLoginPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setIsLoading(true);

        try {
            // Placeholder for student login logic
            // In a real scenario, this would call a student-specific login endpoint
            const formData = new URLSearchParams();
            formData.append('username', email);
            formData.append('password', password);

            const res = await fetch(`${BACKEND_URL}/api/v1/student/auth/token`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/x-www-form-urlencoded",
                },
                body: formData,
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.detail || "Invalid credentials");
            }

            const data = await res.json();
            // Assuming we use a similar token/role structure
            localStorage.setItem("token", data.access_token);
            localStorage.setItem("role", "STUDENT");

            router.push("/student/dashboard");
        } catch (err) {
            const error = err as Error;
            setError(error.message || "Invalid email or password");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={`flex min-h-screen transition-colors duration-300 bg-white dark:bg-slate-950 ${plusJakartaSans.className}`}>
            <div className="hidden lg:flex lg:w-[60%] relative overflow-hidden">
                <img
                    alt="Student education"
                    className="absolute inset-0 w-full h-full object-cover"
                    src="https://images.unsplash.com/photo-1523240795612-9a054b0db644?auto=format&fit=crop&q=80"
                />
                <div className="absolute inset-0 bg-indigo-600/90 flex flex-col justify-center px-20">
                    <div className="max-w-lg">
                        <div className="w-16 h-1 w-24 bg-white/30 mb-8 rounded-full"></div>
                        <h2 className="text-5xl font-extrabold text-white leading-tight mb-6">
                            Start your learning journey today.
                        </h2>
                        <p className="text-white/80 text-lg font-light tracking-wide ">
                            Dedicated portal for students to excel and grow.
                        </p>
                    </div>
                </div>
            </div>

            <div className="w-full lg:w-[40%] flex flex-col items-center justify-center p-8 md:p-12 lg:p-16 bg-white dark:bg-slate-950">
                <div className="max-w-md w-full">
                    <div className="mb-10 text-center lg:text-left">
                        <div className="flex items-center justify-center lg:justify-start gap-3 mb-10">
                            <img src="/Academik_logo.png" alt="Academik.ai" className="h-10 object-contain" />
                            <span className="bg-indigo-50 dark:bg-indigo-900/30 text-[10px] font-black px-2 py-1 rounded-lg text-indigo-500  border border-indigo-100 dark:border-indigo-800">STUDENT</span>
                        </div>
                        <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Student Login</h1>
                        <p className="text-slate-500 dark:text-slate-400">
                            Access your personalized student dashboard
                        </p>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700 dark:text-slate-300" htmlFor="email">
                                    Student Email
                                </label>
                                <input
                                    className="block w-full px-4 py-3 text-slate-900 dark:text-white bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-xl focus:border-indigo-600 focus:ring-0 transition-all outline-none"
                                    id="email"
                                    placeholder="Enter your email"
                                    required
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700 dark:text-slate-300" htmlFor="password">
                                    Password
                                </label>
                                <div className="relative">
                                    <input
                                        className="block w-full px-4 py-3 text-slate-900 dark:text-white bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-xl focus:border-indigo-600 focus:ring-0 transition-all outline-none"
                                        id="password"
                                        placeholder="Enter your password"
                                        required
                                        type={showPassword ? "text" : "password"}
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword(!showPassword)}
                                        className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                                    >
                                        <span className="material-icons-outlined text-xl">
                                            {showPassword ? "visibility_off" : "visibility"}
                                        </span>
                                    </button>
                                </div>
                            </div>
                        </div>

                        {error && (
                            <div className="p-3 rounded-lg bg-rose-50 border border-rose-100 flex items-center gap-2 text-rose-600">
                                <span className="material-icons-outlined text-lg">error_outline</span>
                                <span className="text-xs font-bold">{error}</span>
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={isLoading}
                            className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-extrabold  text-xs  rounded-xl shadow-lg shadow-indigo-200 dark:shadow-none transition-all active:scale-95 flex items-center justify-center gap-2"
                        >
                            {isLoading ? "Signing in..." : "Login to Dashboard"}
                            <span className="material-icons-outlined text-sm">login</span>
                        </button>

                        <div className="text-center pt-6">
                            <p className="text-sm text-slate-500 dark:text-slate-400">
                                Don&apos;t have a student account?{" "}
                                <Link href="/student/register" className="text-indigo-600 font-bold hover:underline">
                                    Register Now
                                </Link>
                            </p>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Plus_Jakarta_Sans } from "next/font/google";
import Link from "next/link";
import { BACKEND_URL } from "@/utils/api";

const plusJakartaSans = Plus_Jakarta_Sans({ subsets: ["latin"] });

export default function StudentRegisterPage() {
    const [fullName, setFullName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [error, setError] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");

        if (password !== confirmPassword) {
            setError("Passwords do not match");
            return;
        }

        setIsLoading(true);

        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/student/auth/register`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    full_name: fullName,
                    email: email,
                    password: password,
                }),
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.detail || "Registration failed");
            }

            router.push("/student/login?registered=true");
        } catch (err: any) {
            setError(err.message || "Registration failed. Please try again.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={`flex min-h-screen transition-colors duration-300 bg-white dark:bg-slate-950 ${plusJakartaSans.className}`}>
            <div className="hidden lg:flex lg:w-[50%] relative overflow-hidden">
                <img
                    alt="Education"
                    className="absolute inset-0 w-full h-full object-cover"
                    src="https://images.unsplash.com/photo-1517486808906-6ca8b3f04846?auto=format&fit=crop&q=80"
                />
                <div className="absolute inset-0 bg-indigo-600/90 flex flex-col justify-center px-16">
                    <div className="max-w-md text-white">
                        <h2 className="text-4xl font-bold mb-6">Join Academik Student Portal</h2>
                        <ul className="space-y-4">
                            {[
                                "Access personalized learning paths",
                                "Track your progress in real-time",
                                "Prepare for corporate placements",
                                "AI-driven mock interviews"
                            ].map((text, i) => (
                                <li key={i} className="flex items-center gap-3">
                                    <span className="material-icons-outlined text-indigo-300">check_circle</span>
                                    <span>{text}</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                </div>
            </div>

            <div className="w-full lg:w-[50%] flex flex-col items-center justify-center p-8 bg-white dark:bg-slate-950">
                <div className="max-w-md w-full">
                    <div className="mb-8">
                        <Link href="/" className="inline-flex items-center gap-2 text-slate-400 hover:text-indigo-600 transition-colors mb-8">
                            <span className="material-icons-outlined text-sm">arrow_back</span>
                            <span className="text-xs font-bold  ">Back to Home</span>
                        </Link>
                        <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Create Account</h1>
                        <p className="text-slate-500 dark:text-slate-400">Join the next generation of students.</p>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-5">
                        <div className="space-y-4">
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500  ">Full Name</label>
                                <input
                                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl focus:border-indigo-600 outline-none transition-all"
                                    placeholder="Enter your full name"
                                    required
                                    value={fullName}
                                    onChange={(e) => setFullName(e.target.value)}
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500  ">Email Address</label>
                                <input
                                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl focus:border-indigo-600 outline-none transition-all"
                                    type="email"
                                    placeholder="your@email.com"
                                    required
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-xs font-bold text-slate-500  ">Password</label>
                                    <input
                                        className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl focus:border-indigo-600 outline-none transition-all"
                                        type="password"
                                        placeholder="Min. 8 chars"
                                        required
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs font-bold text-slate-500  ">Confirm</label>
                                    <input
                                        className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl focus:border-indigo-600 outline-none transition-all"
                                        type="password"
                                        placeholder="Repeat password"
                                        required
                                        value={confirmPassword}
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                    />
                                </div>
                            </div>
                        </div>

                        {error && (
                            <div className="text-rose-500 text-xs font-bold bg-rose-50 p-3 rounded-lg flex items-center gap-2">
                                <span className="material-icons-outlined text-sm">error</span>
                                {error}
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={isLoading}
                            className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl transition-all active:scale-95 disabled:opacity-50"
                        >
                            {isLoading ? "Creating Account..." : "Create Account"}
                        </button>

                        <div className="text-center pt-4">
                            <p className="text-sm text-slate-500">
                                Already have an account?{" "}
                                <Link href="/student/login" className="text-indigo-600 font-bold hover:underline">
                                    Login instead
                                </Link>
                            </p>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, use } from "react";
import { apiClient } from "@/utils/api";
import Link from "next/link";

interface Admin {
    id: number;
    first_name: string;
    last_name: string;
    email: string;
    username: string;
    role: string;
    is_active: boolean;
}

export default function ManageCollegeAdmins({ params }: { params: Promise<{ id: string }> }) {
    const { id: collegeId } = use(params);
    const [admins, setAdmins] = useState<Admin[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isCreating, setIsCreating] = useState(false);

    // Form state
    const [firstName, setFirstName] = useState("");
    const [lastName, setLastName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    useEffect(() => {
        fetchAdmins();
    }, [collegeId]);

    const fetchAdmins = async () => {
        try {
            const res = await apiClient.get(`/api/v1/super-admin/tenants/${collegeId}/admins`);
            if (res.ok) {
                setAdmins(await res.json());
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsCreating(true);
        try {
            const res = await apiClient.post(`/api/v1/super-admin/tenants/${collegeId}/admins`, {
                first_name: firstName,
                last_name: lastName,
                email,
                password
            });
            if (res.ok) {
                await fetchAdmins();
                setFirstName("");
                setLastName("");
                setEmail("");
                setPassword("");
            } else {
                const err = await res.json();
                alert(err.detail || "Failed to create admin");
            }
        } catch (e) {
            console.error(e);
            alert("An error occurred");
        } finally {
            setIsCreating(false);
        }
    };

    const handleDelete = async (adminId: number) => {
        if (!confirm("Are you sure you want to purge this administrator? This will revoke all access immediately.")) return;
        try {
            const res = await apiClient.delete(`/api/v1/super-admin/tenants/${collegeId}/admins/${adminId}`);
            if (res.ok || res.status === 204) {
                setAdmins(prev => prev.filter(a => a.id !== adminId));
            }
        } catch (e) {
            console.error(e);
        }
    };

    const handleEdit = async (admin: Admin) => {
        const newFirstName = prompt("Enter new First Name:", admin.first_name);
        if (newFirstName === null) return;
        const newLastName = prompt("Enter new Last Name:", admin.last_name);
        if (newLastName === null) return;

        try {
            const res = await apiClient.put(`/api/v1/super-admin/tenants/${collegeId}/admins/${admin.id}`, {
                first_name: newFirstName,
                last_name: newLastName
            });
            if (res.ok) {
                fetchAdmins();
            }
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="flex-1 overflow-y-auto bg-slate-50 dark:bg-[#0f172a] p-4 md:p-12">
            <div className="max-w-6xl mx-auto space-y-8">
                <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-200 dark:border-slate-800 pb-8">
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <Link href="/super-admin/colleges/list" className="text-blue-600 hover:text-blue-700 font-bold flex items-center gap-1">
                                <span className="material-icons-outlined text-sm">arrow_back</span>
                                <span className="text-[10px]  ">Back to List</span>
                            </Link>
                        </div>
                        <h1 className="text-4xl font-black tracking-tighter  leading-none">
                            Admin <span className="text-blue-600">Personnel</span>
                        </h1>
                        <p className="text-slate-500 text-xs font-bold   opacity-70 mt-1">Manage College Administration Staff</p>
                    </div>
                </header>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Create Form */}
                    <aside className="lg:col-span-1">
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-xl shadow-blue-500/5 relative overflow-hidden">
                            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 to-indigo-600"></div>
                            <h2 className="text-sm font-black   mb-6 flex items-center gap-2">
                                <span className="material-icons-outlined text-blue-500">person_add</span>
                                Add New Admin
                            </h2>
                            <form onSubmit={handleCreate} className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-black text-slate-400   ml-1">First Name</label>
                                        <input
                                            className="w-full bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 p-4 rounded-2xl text-xs font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                                            value={firstName} onChange={e => setFirstName(e.target.value)} required
                                        />
                                    </div>
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-black text-slate-400   ml-1">Last Name</label>
                                        <input
                                            className="w-full bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 p-4 rounded-2xl text-xs font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                                            value={lastName} onChange={e => setLastName(e.target.value)} required
                                        />
                                    </div>
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">Email / Username</label>
                                    <input
                                        type="email"
                                        className="w-full bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 p-4 rounded-2xl text-xs font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                                        value={email} onChange={e => setEmail(e.target.value)} required
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">Secure Password</label>
                                    <input
                                        type="password"
                                        className="w-full bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 p-4 rounded-2xl text-xs font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                                        value={password} onChange={e => setPassword(e.target.value)} required
                                    />
                                </div>
                                <button
                                    disabled={isCreating}
                                    className="w-full mt-4 bg-slate-900 dark:bg-blue-600 text-white p-5 rounded-3xl text-xs font-black   hover:scale-[1.02] active:scale-95 transition-all shadow-lg shadow-blue-500/20 flex items-center justify-center gap-2"
                                >
                                    {isCreating ? 'Provisioning...' : 'Add Administrator'}
                                    <span className="material-icons-outlined text-sm">shield</span>
                                </button>
                            </form>
                        </div>
                    </aside>

                    {/* Admin List */}
                    <main className="lg:col-span-2 space-y-4">
                        <h2 className="text-sm font-black   text-slate-400">Current Administrative Staff</h2>
                        {isLoading ? (
                            <div className="p-12 text-center text-slate-400  tracking-[0.3em] font-black animate-pulse">Syncing Staff Records...</div>
                        ) : admins.length === 0 ? (
                            <div className="bg-white dark:bg-slate-900 border-2 border-dashed border-slate-200 dark:border-slate-800 p-12 rounded-[3rem] text-center">
                                <p className="text-slate-400 text-sm font-medium">No secondary administrators identified for this college.</p>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {admins.map(admin => (
                                    <div key={admin.id} className="group relative bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 p-6 rounded-[2.5rem] shadow-sm flex items-center gap-4 hover:shadow-xl hover:shadow-blue-500/5 transition-all">
                                        <div className="w-14 h-14 bg-slate-50 dark:bg-slate-800 rounded-2xl flex items-center justify-center border border-slate-100 dark:border-slate-700">
                                            <span className="material-icons-outlined text-2xl text-slate-400">person</span>
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <h3 className="text-sm font-black  tracking-tight truncate">{admin.first_name} {admin.last_name}</h3>
                                            <p className="text-[10px] text-slate-400 font-bold truncate">{admin.email}</p>
                                            <span className="inline-block mt-2 px-2 py-0.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 text-[8px] font-black   rounded-full">
                                                Active_{admin.role}
                                            </span>
                                        </div>
                                        <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button onClick={() => handleEdit(admin)} className="p-2 bg-slate-50 hover:bg-blue-50 text-slate-400 hover:text-blue-600 rounded-xl transition-all">
                                                <span className="material-icons-outlined text-sm">edit</span>
                                            </button>
                                            <button onClick={() => handleDelete(admin.id)} className="p-2 bg-slate-50 hover:bg-rose-50 text-slate-400 hover:text-rose-600 rounded-xl transition-all">
                                                <span className="material-icons-outlined text-sm">delete</span>
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </main>
                </div>
            </div>
        </div>
    );
}

import Link from "next/link";

interface College {
    id: string;
    name: string;
    slug: string;
    db_name: string;
    admin_email: string;
    admin_profile_image?: string;
    is_active: boolean;
}

interface Division {
    id: number;
    name: string;
    slug: string;
}

export default function SuperAdminDivisions({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const [divisions, setDivisions] = useState<Division[]>([]);
    const [college, setCollege] = useState<College | null>(null);
    const [name, setName] = useState("");
    const [slug, setSlug] = useState("");
    const [isLoading, setIsLoading] = useState(false);

    useEffect(() => {
        fetchCollege();
        fetchDivisions();
    }, [id]);

    const fetchCollege = async () => {
        try {
            const res = await apiClient.get(`/api/v1/super-admin/tenants/${id}`);
            if (res.ok) setCollege(await res.json());
        } catch (e) { console.error(e); }
    };

    const fetchDivisions = async () => {
        try {
            const res = await apiClient.get(`/api/v1/super-admin/tenants/${id}/divisions`);
            if (res.ok) setDivisions(await res.json());
        } catch (e) { console.error(e); }
    };

    const handleAddDivision = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const res = await apiClient.post(`/api/v1/super-admin/tenants/${id}/divisions`, {
                name,
                slug
            });
            if (res.ok) {
                setName("");
                setSlug("");
                fetchDivisions();
            }
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    };

    return (
        <div className="flex-1 overflow-y-auto bg-slate-50 p-12">
            <div className="max-w-4xl mx-auto space-y-8">
                <header className="flex justify-between items-center border-b border-slate-200 pb-8">
                    <div>
                        <h1 className="text-3xl font-black  tracking-tight">
                            {college?.name || 'Loading...'} <span className="text-blue-600">Divisions</span>
                        </h1>
                        <Link href="/super-admin/colleges/list" className="text-slate-400 text-xs font-bold   hover:text-slate-900 transition-colors">
                            &larr; Back to List
                        </Link>
                    </div>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <aside className="md:col-span-1">
                        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-blue-500/5">
                            <h2 className="text-xs font-black   mb-6 border-b border-slate-50 pb-4">Add Division</h2>
                            <form onSubmit={handleAddDivision} className="space-y-4">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-black text-slate-400  ">Name</label>
                                    <input
                                        className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl text-xs font-medium focus:ring-2 focus:ring-blue-500 outline-none"
                                        placeholder="e.g. Arts & Science"
                                        value={name} onChange={e => { setName(e.target.value); setSlug(e.target.value.toLowerCase().replace(/ /g, '-')); }} required
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-black text-slate-400  ">Slug</label>
                                    <input
                                        className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl text-xs font-medium focus:ring-2 focus:ring-blue-500 outline-none"
                                        placeholder="e.g. arts-science"
                                        value={slug} onChange={e => setSlug(e.target.value)} required
                                    />
                                </div>
                                <button
                                    disabled={isLoading}
                                    className="w-full bg-slate-900 text-white p-4 rounded-2xl text-xs font-black   shadow-lg"
                                >
                                    {isLoading ? 'Adding...' : 'Add Division'}
                                </button>
                            </form>
                        </div>
                    </aside>

                    <main className="md:col-span-2 space-y-4">
                        <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm">
                            <table className="min-w-full divide-y divide-slate-100">
                                <thead className="bg-slate-50/50">
                                    <tr>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400  ">Division Name</th>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400  ">Slug</th>
                                        <th className="px-6 py-4"></th>
                                    </tr>
                                </thead>
                                <tbody className="bg-white divide-y divide-slate-100">
                                    {divisions.map((d) => (
                                        <tr key={d.id} className="hover:bg-slate-50 transition-colors">
                                            <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-slate-900  tracking-tight">{d.name}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-[10px] font-mono text-slate-400">{d.slug}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right">
                                                {/* Add delete/edit if needed */}
                                            </td>
                                        </tr>
                                    ))}
                                    {divisions.length === 0 && (
                                        <tr>
                                            <td colSpan={3} className="px-6 py-8 text-center text-slate-400 text-xs font-bold  ">No divisions found.</td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </main>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";
import { useRouter, useParams } from "next/navigation";

interface User {
    id: number;
    first_name: string;
    last_name: string;
    email: string;
    role: string;
    is_active: boolean;
}

export default function CollegeUserManagement() {
    const { id } = useParams();
    const router = useRouter();
    const [users, setUsers] = useState<User[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    // New User State
    const [newUser, setNewUser] = useState({
        first_name: "",
        last_name: "",
        email: "",
        password: "",
        role: "STUDENT"
    });

    useEffect(() => {
        fetchUsers();
    }, [id]);

    const fetchUsers = async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get(`/api/v1/super-admin/tenants/${id}/users`);
            if (res.ok) {
                setUsers(await res.json());
            }
        } catch (e) {
            console.error("Failed to fetch users", e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreateUser = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await apiClient.post(`/api/v1/super-admin/tenants/${id}/users`, newUser);
            if (res.ok) {
                setShowModal(false);
                fetchUsers();
                setNewUser({ first_name: "", last_name: "", email: "", password: "", role: "STUDENT" });
            } else {
                alert("Failed to create user");
            }
        } catch (e) {
            console.error(e);
        }
    };

    const handleDelete = async (userId: number) => {
        if (!confirm("Are you sure?")) return;
        try {
            const res = await apiClient.delete(`/api/v1/super-admin/tenants/${id}/users/${userId}`);
            if (res.ok) {
                fetchUsers();
            }
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="flex-1 overflow-y-auto bg-slate-50 dark:bg-[#0f172a] p-8">
            <div className="max-w-6xl mx-auto space-y-8">
                <header className="flex justify-between items-center bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm">
                    <div className="flex items-center gap-4">
                        <button onClick={() => router.back()} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                            <span className="material-icons-outlined text-slate-500">arrow_back</span>
                        </button>
                        <div>
                            <h1 className="text-2xl font-black  tracking-tighter text-slate-900">User Management</h1>
                            <p className="text-xs font-bold text-slate-400  ">Connect ID: {id}</p>
                        </div>
                    </div>
                    <button
                        onClick={() => setShowModal(true)}
                        className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-xs font-black   hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
                    >
                        Add User
                    </button>
                </header>

                {isLoading ? (
                    <div className="flex justify-center p-12"><div className="w-8 h-8 rounded-full border-4 border-indigo-600 border-t-transparent animate-spin"></div></div>
                ) : (
                    <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
                        <table className="w-full text-left">
                            <thead className="bg-slate-50 dark:bg-slate-800/50">
                                <tr>
                                    <th className="p-6 text-[10px] font-black   text-slate-400">Name</th>
                                    <th className="p-6 text-[10px] font-black   text-slate-400">Email</th>
                                    <th className="p-6 text-[10px] font-black   text-slate-400">Role</th>
                                    <th className="p-6 text-[10px] font-black   text-slate-400">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                {users.map(u => (
                                    <tr key={u.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                        <td className="p-6">
                                            <div className="font-bold text-slate-700">{u.first_name} {u.last_name}</div>
                                        </td>
                                        <td className="p-6 text-sm font-medium text-slate-500">{u.email}</td>
                                        <td className="p-6">
                                            <span className={`px-3 py-1 rounded-full text-[10px] font-black   ${u.role === 'ADMIN' ? 'bg-purple-50 text-purple-600' :
                                                u.role === 'SUPER_ADMIN' ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'
                                                }`}>
                                                {u.role}
                                            </span>
                                        </td>
                                        <td className="p-6">
                                            <button onClick={() => handleDelete(u.id)} className="text-rose-400 hover:text-rose-600 transition-colors">
                                                <span className="material-icons-outlined text-lg">delete</span>
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        {users.length === 0 && (
                            <div className="p-12 text-center text-slate-400 font-medium text-sm ">No users found for this college.</div>
                        )}
                    </div>
                )}
            </div>

            {/* Create Modal */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
                    <div className="w-full max-w-md bg-white rounded-3xl p-8 animate-in zoom-in-95">
                        <h3 className="text-xl font-black  tracking-tight mb-6">Create User</h3>
                        <form onSubmit={handleCreateUser} className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <input placeholder="First Name" className="p-3 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:border-indigo-500" value={newUser.first_name} onChange={e => setNewUser({ ...newUser, first_name: e.target.value })} required />
                                <input placeholder="Last Name" className="p-3 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:border-indigo-500" value={newUser.last_name} onChange={e => setNewUser({ ...newUser, last_name: e.target.value })} required />
                            </div>
                            <input type="email" placeholder="Email" className="w-full p-3 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:border-indigo-500" value={newUser.email} onChange={e => setNewUser({ ...newUser, email: e.target.value })} required />
                            <input type="password" placeholder="Password" className="w-full p-3 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:border-indigo-500" value={newUser.password} onChange={e => setNewUser({ ...newUser, password: e.target.value })} required />
                            <select className="w-full p-3 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:border-indigo-500 bg-white" value={newUser.role} onChange={e => setNewUser({ ...newUser, role: e.target.value })}>
                                <option value="STUDENT">Student</option>
                                <option value="ADMIN">Admin</option>
                                <option value="FACULTY">Faculty</option>
                            </select>
                            <div className="flex gap-4 pt-4">
                                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-3 bg-slate-100 text-slate-600 rounded-xl font-black   text-[10px]">Cancel</button>
                                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black   text-[10px]">Create</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import Link from "next/link";

interface College {
    id: string;
    name: string;
    slug: string;
    db_name: string;
    admin_email: string;
    admin_profile_image?: string;
    is_active: boolean;
}

export default function DeployedNodesList() {
    const [colleges, setColleges] = useState<College[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        fetchColleges();
    }, []);

    const fetchColleges = async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get("/api/v1/super-admin/tenants");
            if (res.ok) {
                setColleges(await res.json());
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (id: number) => {
        if (!confirm("Are you sure you want to decommission this node? This action cannot be undone.")) return;
        try {
            const res = await apiClient.delete(`/api/v1/super-admin/tenants/${id}`);
            if (res.ok || res.status === 204) {
                fetchColleges();
            }
        } catch (e) {
            console.error(e);
        }
    };

    const toggleStatus = async (college: College) => {
        try {
            await apiClient.put(`/api/v1/super-admin/tenants/${college.id}`, { is_active: !college.is_active });
            fetchColleges();
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="p-6 lg:p-8 max-w-7xl mx-auto space-y-8">
            {/* Page Title */}
            <div className="flex items-center justify-between mb-8">
                <h1 className="text-xs font-black text-slate-400  tracking-[0.2em]">Platform Inventory</h1>
                <Link href="/super-admin/colleges" className="flex items-center gap-2 text-indigo-600 hover:text-indigo-700 transition-colors">
                    <span className="material-symbols-rounded text-lg">add_box</span>
                    <span className="text-[10px] font-black  ">Provision Tenant</span>
                </Link>
            </div>
                <div className="max-w-7xl mx-auto">
                    <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                        <div className="p-5 border-b border-slate-100 flex justify-between items-center">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-900">
                                    <span className="material-icons-outlined text-lg">view_list</span>
                                </div>
                                <h2 className="text-xs font-black   text-slate-900">Active Deployments ({colleges.length})</h2>
                            </div>
                            <Link href="/super-admin/colleges" className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-black   hover:bg-slate-800 transition-colors flex items-center gap-2">
                                <span className="material-icons-outlined text-sm">add</span>
                                New Node
                            </Link>
                        </div>

                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead className="bg-slate-50 border-b border-slate-100">
                                    <tr>
                                        <th className="px-5 py-3 text-[10px] font-black   text-slate-400">Organization Name</th>
                                        <th className="px-5 py-3 text-[10px] font-black   text-slate-400">Slug / URL</th>
                                        <th className="px-5 py-3 text-[10px] font-black   text-slate-400">Database</th>
                                        <th className="px-5 py-3 text-[10px] font-black   text-slate-400">Status</th>
                                        <th className="px-5 py-3 text-[10px] font-black   text-slate-400 text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {colleges.map((c: College) => (
                                        <tr key={c.id} className="hover:bg-slate-50/50 transition-colors group">
                                            <td className="px-5 py-3">
                                                <div className="flex items-center gap-2">
                                                    <div className="w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center">
                                                        {c.admin_profile_image ? (
                                                            <img src={c.admin_profile_image} className="w-full h-full object-cover rounded-lg" alt="" />
                                                        ) : (
                                                            <span className="text-[10px] font-bold text-slate-500">{c.name.charAt(0)}</span>
                                                        )}
                                                    </div>
                                                    <span className="text-xs font-bold text-slate-700">{c.name}</span>
                                                </div>
                                            </td>
                                            <td className="px-5 py-3">
                                                <span className="px-2 py-0.5 rounded bg-slate-50 border border-slate-200 text-[10px] font-mono text-slate-500">
                                                    {c.slug}.{FRONTEND_DOMAIN}
                                                </span>
                                            </td>
                                            <td className="px-5 py-3">
                                                <span className="text-[10px] font-mono text-slate-400">{c.db_name}</span>
                                            </td>
                                            <td className="px-5 py-3">
                                                <button
                                                    onClick={() => toggleStatus(c)}
                                                    className={`px-2 py-0.5 rounded-full text-[8px] font-black   border transition-all cursor-pointer ${c.is_active ? 'bg-emerald-50 text-emerald-600 border-emerald-100 hover:bg-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100 dashed hover:bg-slate-100'}`}
                                                >
                                                    {c.is_active ? 'Active' : 'Offline'}
                                                </button>
                                            </td>
                                            <td className="px-5 py-3 text-right">
                                                <div className="flex items-center justify-end gap-2">
                                                    <Link href={`/super-admin/colleges?edit=${c.id}`} className="p-2 rounded-lg text-slate-400 hover:text-slate-900 hover:bg-slate-100 transition-colors" title="Edit Configuration">
                                                        <span className="material-icons-outlined text-lg">edit</span>
                                                    </Link>
                                                    <Link href={`/super-admin/colleges/${c.id}/admins`} className="p-2 rounded-lg text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition-colors" title="Manage Admins">
                                                        <span className="material-icons-outlined text-lg">manage_accounts</span>
                                                    </Link>
                                                    <Link href={`/super-admin/colleges/${c.id}/divisions`} className="p-2 rounded-lg text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition-colors" title="Manage Divisions">
                                                        <span className="material-icons-outlined text-lg">account_balance</span>
                                                    </Link>
                                                    <button onClick={() => handleDelete(c.id)} className="p-2 rounded-lg text-slate-400 hover:text-rose-600 hover:bg-rose-50 transition-colors" title="Delete">
                                                        <span className="material-icons-outlined text-lg">delete</span>
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                    {colleges.length === 0 && !isLoading && (
                                        <tr>
                                            <td colSpan={5} className="px-6 py-12 text-center text-slate-400 text-xs font-bold  ">
                                                No tenants provisioned yet
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
        </div>
    );
}

import Link from "next/link";

interface College {
    id: string;
    name: string;
    slug: string;
    db_name: string;
    admin_email: string;
    admin_profile_image?: string;
    is_active: boolean;
}

function SuperAdminCollegesContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const editId = searchParams.get('edit');

    const [colleges, setColleges] = useState<College[]>([]);
    const [name, setName] = useState<string>("");
    const [slug, setSlug] = useState<string>("");
    const [dbName, setDbName] = useState<string>("");
    const [adminEmail, setAdminEmail] = useState<string>("");
    const [adminPassword, setAdminPassword] = useState<string>("");
    const [adminProfileImage, setAdminProfileImage] = useState<string>("");
    const [uploadMode, setUploadMode] = useState<'url' | 'file'>('url');
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedCollege, setSelectedCollege] = useState<College | null>(null);

    // Fetch colleges just to find the one to edit if ID is present
    // Optimization: In a real app we might fetching a single item by ID, but list is small.
    useEffect(() => {
        fetchColleges();
    }, []);

    // Watch for editId changes
    useEffect(() => {
        if (editId) {
            fetchCollegeDetail(editId as string);
        } else {
            resetForm();
        }
    }, [editId]);

    // Auto-generate DB name from slug
    useEffect(() => {
        if (!selectedCollege && slug) {
            // Simple sanitization: lowercase, replace non-alphanumeric with underscore
            const sanitized = slug.toLowerCase().replace(/[^a-z0-9]/g, '_');
            setDbName(`talixo_${sanitized}`);
        }
    }, [slug, selectedCollege]);

    const fetchCollegeDetail = async (id: string) => {
        setIsLoading(true);
        try {
            const res = await apiClient.get(`/api/v1/super-admin/tenants/${id}`);
            if (res.ok) {
                const college = await res.json();
                loadCollege(college);
            } else {
                console.error("Failed to fetch college details");
                router.replace('/super-admin/colleges');
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const fetchColleges = async () => {
        try {
            const res = await apiClient.get("/api/v1/super-admin/tenants");
            if (res.ok) {
                setColleges(await res.json());
            }
        } catch (e) {
            console.error(e);
        }
    };

    // Reset form to Create Mode
    const resetForm = () => {
        setSelectedCollege(null);
        setName("");
        setSlug("");
        setDbName("");
        setAdminEmail("");
        setAdminPassword("");
        setAdminProfileImage("");
        setUploadMode('url');
        setSelectedFile(null);
        // Clear query param if present
        if (searchParams.get('edit')) {
            router.replace('/super-admin/colleges', { scroll: false });
        }
    };

    // Load college into form for Edit Mode
    const loadCollege = (college: College) => {
        setSelectedCollege(college);
        setName(college.name || "");
        setSlug(college.slug || "");
        setDbName(college.db_name || "");
        setAdminEmail(college.admin_email || "");
        setAdminPassword("");
        setAdminProfileImage(college.admin_profile_image || "");
    };

    const handleCreateOrUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            let finalImageUrl = adminProfileImage;

            if (uploadMode === 'file' && selectedFile) {
                const formData = new FormData();
                formData.append('file', selectedFile);

                try {
                    const uploadRes = await fetch(`${process.env.NEXT_PUBLIC_BACKEND_URL || ''}/api/v1/common/upload`, {
                        method: 'POST',
                        body: formData,
                    });

                    if (uploadRes.ok) {
                        const uploadData = await uploadRes.json();
                        finalImageUrl = uploadData.url;
                    } else {
                        throw new Error("Image upload failed");
                    }
                } catch (err) {
                    console.error("Upload error:", err);
                    alert("Failed to upload image. Please try again or use a URL.");
                    setIsLoading(false);
                    return;
                }
            }

            if (selectedCollege) {
                // UPDATE logic
                await apiClient.put(`/api/v1/super-admin/tenants/${selectedCollege.id}`, {
                    name,
                    slug,
                    admin_email: adminEmail,
                    ...(adminPassword ? { admin_password: adminPassword } : {}),
                    admin_profile_image: finalImageUrl,
                });
            } else {
                // CREATE logic
                await apiClient.post("/api/v1/super-admin/tenants", {
                    name,
                    slug,
                    db_name: dbName,
                    admin_email: adminEmail,
                    admin_password: adminPassword,
                    admin_profile_image: finalImageUrl,
                    is_active: true
                });
            }

            // After success, maybe redirect to list? Or just clear?
            // User flow: If editing, stay or go back. If creating, clear form.
            if (selectedCollege) {
                alert("Updated successfully");
                router.push('/super-admin/colleges/list'); // Redirect to list after edit
            } else {
                alert("Deployed successfully");
                // Clear form but stay here to add more?
                resetForm();
            }
            await fetchColleges();

        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to decommission this node? this will just delete it from listing, database remains.")) return;
        try {
            const res = await apiClient.delete(`/api/v1/super-admin/tenants/${id}`);
            if (res.ok || res.status === 204) {
                router.push('/super-admin/colleges/list');
            }
        } catch (e) {
            console.error(e);
        }
    };

    const toggleStatus = async (college: College) => {
        try {
            await apiClient.put(`/api/v1/super-admin/tenants/${college.id}`, { is_active: !college.is_active });
            // Refresh local state if current
            if (selectedCollege && selectedCollege.id === college.id) {
                loadCollege({ ...college, is_active: !college.is_active });
            }
            fetchColleges();
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="p-6 lg:p-8 max-w-7xl mx-auto space-y-8 text-center sm:text-left">
            {/* Page Title */}
            <div className="flex items-center justify-between mb-8">
                <h1 className="text-[10px] font-black text-slate-400  tracking-[0.2em]">
                    {selectedCollege ? `Manage Tenant` : "Tenant Provisioning Console"}
                </h1>
                <Link href="/super-admin/colleges/list" className="flex items-center gap-2 text-indigo-600 hover:text-indigo-700 transition-colors">
                    <span className="material-symbols-rounded text-lg">list_alt</span>
                    <span className="text-[9px] font-black  ">View Inventory</span>
                </Link>
            </div>

            <div className="w-full animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm relative overflow-hidden">
                    {selectedCollege && (
                        <div className="absolute top-0 right-0 p-6 flex gap-2">
                            <Link href={`/super-admin/colleges/${selectedCollege.id}/admins`} className="p-1.5 rounded-lg bg-slate-50 text-slate-400 hover:bg-slate-900 hover:text-white transition-colors" title="Manage Admins">
                                <span className="material-icons-outlined text-base">manage_accounts</span>
                            </Link>
                            <Link href={`/super-admin/colleges/${selectedCollege.id}/divisions`} className="p-1.5 rounded-lg bg-slate-50 text-slate-400 hover:bg-slate-900 hover:text-white transition-colors" title="Manage Divisions">
                                <span className="material-icons-outlined text-base">account_balance</span>
                            </Link>
                            <button onClick={() => toggleStatus(selectedCollege)} className={`p-1.5 rounded-lg transition-colors ${selectedCollege.is_active ? 'bg-emerald-50 text-emerald-500 hover:bg-rose-50 hover:text-rose-500' : 'bg-slate-50 text-slate-400 hover:bg-emerald-50 hover:text-emerald-500'}`} title="Toggle Status">
                                <span className="material-icons-outlined text-base">{selectedCollege.is_active ? 'toggle_on' : 'toggle_off'}</span>
                            </button>
                            <button onClick={() => handleDelete(selectedCollege.id)} className="p-1.5 rounded-lg bg-rose-50 text-rose-400 hover:bg-rose-500 hover:text-white transition-colors" title="Delete">
                                <span className="material-icons-outlined text-base">delete</span>
                            </button>
                        </div>
                    )}

                    <div className="flex items-center gap-3 mb-6 pb-5 border-b border-slate-100">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-lg ${selectedCollege ? 'bg-indigo-600 shadow-indigo-200' : 'bg-slate-900 shadow-slate-200'}`}>
                            <span className="material-icons-outlined text-xl">{selectedCollege ? 'settings_applications' : 'add_business'}</span>
                        </div>
                        <div>
                            <h2 className="text-lg font-black  tracking-tight text-slate-900">{selectedCollege ? 'Configuration' : 'Initialize New Tenant'}</h2>
                            <p className="text-[10px] text-slate-400 font-medium mt-0.5">
                                {selectedCollege ? `Update settings for ${selectedCollege.slug}` : 'Deploy a new dedicated environment to the cluster.'}
                            </p>
                        </div>
                    </div>

                        <form onSubmit={handleCreateOrUpdate} className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div>
                                    <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block">Organization Name</label>
                                    <input
                                        className="w-full bg-slate-50 border border-slate-200 p-4 rounded-xl text-sm font-bold text-slate-700 focus:border-slate-900 focus:ring-4 focus:ring-slate-100 outline-none transition-all placeholder:text-slate-300"
                                        placeholder="e.g. Stanford University"
                                        value={name} onChange={e => setName(e.target.value)} required
                                    />
                                </div>
                                <div>
                                    <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block">Url Slug</label>
                                    <input
