"use client";

import SuperAdminSidebar from "@/components/super-admin/Sidebar";
import { usePathname, useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { useEffect, useState } from "react";
import Link from "next/link";

export default function SuperAdminLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const pathname = usePathname();
    const router = useRouter();
    const { role, token, isLoading } = useAuth();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    
    const isLoginPage = pathname?.startsWith("/super-admin/login");

    useEffect(() => {
        if (!isLoading && !isLoginPage) {
            // Require SUPER_ADMIN role for any page under /super-admin/
            if (!token || role !== "SUPER_ADMIN") {
                console.warn("Unauthorized access to Super Admin dashboard. Redirecting to login.");
                router.push("/super-admin/login");
            }
        }
        setIsMobileMenuOpen(prev => prev ? false : prev);
    }, [role, token, isLoading, isLoginPage, router, pathname]);

    if (isLoginPage) {
        return <>{children}</>;
    }

    if (isLoading || (!role && !isLoginPage)) {
        return (
            <div className="flex h-screen items-center justify-center bg-slate-50">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-slate-500 font-medium">Verifying Platform Authority...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="flex w-full h-screen bg-[#FDFDFF] overflow-hidden font-sans">
            {/* Mobile Overlay */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-slate-900/40 z-40 md:hidden backdrop-blur-sm"
                    onClick={() => setIsMobileMenuOpen(false)}
                />
            )}

            {/* Sidebar with Responsive Visibility */}
            <div className={`
                fixed inset-y-0 left-0 z-50 transition-transform duration-300 ease-in-out md:translate-x-0 md:sticky md:top-0 md:h-screen
                ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
            `}>
                <SuperAdminSidebar />
            </div>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden w-full">
                {/* Mobile Top Bar */}
                <header className="h-16 bg-white border-b border-slate-100 flex items-center justify-between px-6 md:hidden shrink-0">
                    <div className="flex items-center gap-3">
                        <button
                            onClick={() => setIsMobileMenuOpen(true)}
                            className="w-10 h-10 rounded-lg hover:bg-slate-50 flex items-center justify-center transition-colors"
                        >
                            <span className="material-icons-outlined text-slate-600">menu</span>
                        </button>
                        <span className="text-xl font-black bg-gradient-to-r from-[#7C3AED] to-[#D946EF] bg-clip-text text-transparent tracking-tighter">Croar.ai</span>
                    </div>
                </header>

                {/* Content */}
                <main className="flex-1 w-full overflow-y-auto bg-[#FDFDFF] custom-scrollbar">
                    {children}
                </main>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import { Plus_Jakarta_Sans } from "next/font/google";
import { BACKEND_URL, FRONTEND_DOMAIN } from "@/utils/api";

const plusJakartaSans = Plus_Jakarta_Sans({ subsets: ["latin"] });

export default function SuperAdminLoginPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const { login } = useAuth();
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setIsLoading(true);

        try {
            const formData = new URLSearchParams();
            formData.append('username', email);
            formData.append('password', password);

            const res = await fetch(`${BACKEND_URL}/api/v1/auth/token`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/x-www-form-urlencoded",
                },
                body: formData,
            });

            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.detail || "Invalid credentials");
            }

            const data = await res.json();

            if (data.role !== "SUPER_ADMIN") {
                throw new Error("Access Denied: Super Admin role required");
            }

            login(data.access_token, data.role);
            router.push("/super-admin");
        } catch (err: any) {
            setError(err.message || "Invalid email or password");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={`flex min-h-screen bg-[#020617] text-slate-200 ${plusJakartaSans.className}`}>
            {/* Ambient Background Elements */}
            <div className="fixed inset-0 overflow-hidden pointer-events-none">
                <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-900/20 blur-[120px] rounded-full"></div>
                <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-900/20 blur-[120px] rounded-full"></div>
                <div className="absolute top-[20%] right-[10%] w-[20%] h-[20%] bg-purple-900/10 blur-[80px] rounded-full"></div>
            </div>

            <div className="w-full flex flex-col items-center justify-center p-6 relative z-10">
                <div className="max-w-md w-full">
                    {/* Brand/Logo */}
                    <div className="text-center mb-12">
                        <div className="inline-flex items-center justify-center w-20 h-20 bg-slate-900 border border-slate-800 rounded-3xl mb-6 shadow-2xl shadow-blue-500/10">
                            <span className="material-icons-outlined text-4xl text-blue-500">terminal</span>
                        </div>
                        <h1 className="text-4xl font-black tracking-tighter  mb-2">
                            {FRONTEND_DOMAIN.split('.').slice(0, 2).join('.')}.<span className="text-blue-600">{FRONTEND_DOMAIN.split('.').slice(2).join('.')}</span>
                        </h1>
                        <p className="text-slate-500 text-[10px] font-black  tracking-[0.3em]">Institutional Platform Architecture</p>
                    </div>

                    {/* Login Card */}
                    <div className="bg-slate-900/50 backdrop-blur-xl border border-slate-800 p-8 md:p-10 rounded-[2.5rem] shadow-2xl shadow-black/50">
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="space-y-4">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black text-slate-500   ml-1">Universal Identity</label>
                                    <div className="relative group">
                                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                            <span className="material-icons-outlined text-sm text-slate-500 group-focus-within:text-blue-500 transition-colors">alternate_email</span>
                                        </div>
                                        <input
                                            type="email"
                                            required
                                            value={email}
                                            onChange={(e) => setEmail(e.target.value)}
                                            className="w-full bg-slate-950 border border-slate-800 p-4 pl-11 rounded-2xl text-sm focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-700"
                                            placeholder={`root@${FRONTEND_DOMAIN}`}
                                        />
                                    </div>
                                </div>

                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black text-slate-500   ml-1">Access Protocol</label>
                                    <div className="relative group">
                                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                            <span className="material-icons-outlined text-sm text-slate-500 group-focus-within:text-blue-500 transition-colors">lock</span>
                                        </div>
                                        <input
                                            type="password"
                                            required
                                            value={password}
                                            onChange={(e) => setPassword(e.target.value)}
                                            className="w-full bg-slate-950 border border-slate-800 p-4 pl-11 rounded-2xl text-sm focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-700"
                                            placeholder="••••••••••••"
                                        />
                                    </div>
                                </div>
                            </div>

                            {error && (
                                <div className="bg-rose-500/10 border border-rose-500/20 p-4 rounded-2xl flex items-center gap-3 animate-shake">
                                    <span className="material-icons-outlined text-rose-500 text-lg">security_update_warning</span>
                                    <span className="text-xs font-bold text-rose-500">{error}</span>
                                </div>
                            )}

                            <button
                                type="submit"
                                disabled={isLoading}
                                className="w-full py-5 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-black  text-xs  rounded-3xl shadow-xl shadow-blue-600/20 transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                                {isLoading ? (
                                    <>
                                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                        Authenticating...
                                    </>
                                ) : (
                                    <>
                                        Establish Connection
                                        <span className="material-icons-outlined text-sm">vpn_key</span>
                                    </>
                                )}
                            </button>
                        </form>
                    </div>

                    {/* Footer */}
                    <div className="mt-12 text-center">
                        <p className="text-slate-600 text-[10px] font-bold  ">
                            Authorized Access Only. All operations are logged.
                        </p>
                    </div>
                </div>
            </div>

            <style jsx>{`
                @keyframes shake {
                    0%, 100% { transform: translateX(0); }
                    25% { transform: translateX(-4px); }
                    75% { transform: translateX(4px); }
                }
                .animate-shake {
                    animation: shake 0.2s ease-in-out 0s 2;
                }
            `}</style>
        </div>
    );
}

import Link from "next/link";

interface Organization {
    id: string;
    name: string;
    email: string;
    website: string;
    is_active: boolean;
}

function OrganizationsContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const [organizations, setOrganizations] = useState<Organization[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    
    // Form State
    const [name, setName] = useState("");
    const [email, setEmail] = useState("");
    const [website, setWebsite] = useState("");
    const [adminEmail, setAdminEmail] = useState("");
    const [adminPassword, setAdminPassword] = useState("");
    const [isCreating, setIsCreating] = useState(false);

    useEffect(() => {
        fetchOrganizations();
    }, []);

    const fetchOrganizations = async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get("/api/v1/super-admin/tenants");
            if (res.ok) {
                setOrganizations(await res.json());
            }
        } catch (e) {
            console.error("Failed to fetch organizations", e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreateOrganization = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const res = await apiClient.post("/api/v1/super-admin/tenants", {
                org_data: {
                    name,
                    email,
                    website,
                    is_active: true
                },
                admin_email: adminEmail,
                admin_password: adminPassword
            });

            if (res.ok) {
                alert("Organization created successfully.");
                setName("");
                setEmail("");
                setWebsite("");
                setAdminEmail("");
                setAdminPassword("");
                setIsCreating(false);
                fetchOrganizations();
            } else {
                const err = await res.json();
                alert(`Error: ${err.detail || "Failed to create organization"}`);
            }
        } catch (e) {
            console.error(e);
            alert("An unexpected error occurred.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="p-6 lg:p-8 max-w-7xl mx-auto space-y-8">
            {/* Page Title */}
            <div className="flex items-center justify-between mb-8">
                <h1 className="text-xs font-black text-slate-400  tracking-[0.2em]">Platform Organizations</h1>
                <button 
                    onClick={() => setIsCreating(!isCreating)}
                    className="bg-slate-900 text-white px-4 py-2 rounded-xl text-xs font-black   hover:bg-slate-800 transition-all shadow-lg"
                >
                    {isCreating ? "View Inventory" : "Register Organization"}
                </button>
            </div>

                {isCreating ? (
                    <div className="w-full animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                            <div className="flex items-center gap-3 mb-6 pb-5 border-b border-slate-100">
                                <div className="w-12 h-12 rounded-2xl bg-indigo-600 flex items-center justify-center text-white shadow-lg shadow-indigo-100">
                                    <span className="material-icons-outlined text-2xl">corporate_fare</span>
                                </div>
                                <div>
                                    <h2 className="text-xl font-black  tracking-tight text-slate-900">New Organization</h2>
                                    <p className="text-xs text-slate-400 font-medium mt-1">Spin up a new dedicated environment and admin account.</p>
                                </div>
                            </div>

                            <form onSubmit={handleCreateOrganization} className="space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block text-left">Company Name</label>
                                        <input
                                            className="w-full bg-slate-50 border border-slate-200 p-4 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-slate-900"
                                            placeholder="Acme Corp"
                                            value={name} onChange={e => setName(e.target.value)} required
                                        />
                                    </div>
                                    <div>
                                        <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block text-left">Contact Email</label>
                                        <input
                                            className="w-full bg-slate-50 border border-slate-200 p-4 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-slate-900"
                                            placeholder="contact@acme.com"
                                            type="email"
                                            value={email} onChange={e => setEmail(e.target.value)} required
                                        />
                                    </div>
                                </div>
                                
                                <div>
                                    <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block text-left">Website</label>
                                    <input
                                        className="w-full bg-slate-50 border border-slate-200 p-4 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-slate-900"
                                        placeholder="https://acme.corp"
                                        type="url"
                                        value={website} onChange={e => setWebsite(e.target.value)}
                                    />
                                </div>

                                <div className="pt-4 border-t border-slate-100">
                                    <h3 className="text-[10px] font-black text-slate-900  tracking-[0.2em] mb-4">Organization Admin Account</h3>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        <div>
                                            <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block text-left">Admin Email</label>
                                            <input
                                                className="w-full bg-slate-50 border border-slate-200 p-4 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-slate-900"
                                                placeholder="admin@acme.com"
                                                type="email"
                                                value={adminEmail} onChange={e => setAdminEmail(e.target.value)} required
                                            />
                                        </div>
                                        <div>
                                            <label className="text-[10px] font-black text-slate-400   ml-1 mb-1.5 block text-left">Temp Password</label>
                                            <input
                                                className="w-full bg-slate-50 border border-slate-200 p-4 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-slate-900"
                                                placeholder="••••••••"
                                                type="password"
                                                value={adminPassword} onChange={e => setAdminPassword(e.target.value)} required
                                            />
                                        </div>
                                    </div>
                                </div>

                                <button
                                    disabled={isLoading}
                                    className="w-full text-white p-4 rounded-xl text-xs font-black   bg-slate-900 hover:bg-slate-800 shadow-xl transition-all"
                                >
                                    {isLoading ? "Creating..." : "Create Organization"}
                                </button>
                            </form>
                        </div>
                    </div>
                ) : (
                    <div className="max-w-6xl mx-auto space-y-5">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
                            {organizations.map((org: Organization) => (
                                <div key={org.id} className="bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl transition-all group overflow-hidden relative">
                                    <div className="flex items-start justify-between mb-4">
                                        <div className="w-12 h-12 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-600 transition-colors group-hover:bg-indigo-600 group-hover:text-white">
                                            <span className="material-icons-outlined">corporate_fare</span>
