"use client";

import React, { useState, useRef } from "react";

interface Feedback {
    fluency: number;
    grammar: number;
    confidence: number;
    relevance: number;
    feedback: string;
    transcription?: string;
}

export default function AudioRecorder() {
    const [recording, setRecording] = useState(false);
    const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
    const [feedback, setFeedback] = useState<Feedback | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const chunksRef = useRef<Blob[]>([]);

    const startRecording = async () => {
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
            setError("Microphone not supported. Please use HTTPS or localhost.");
            return;
        }

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            streamRef.current = stream;
            const mediaRecorder = new MediaRecorder(stream);
            mediaRecorderRef.current = mediaRecorder;
            chunksRef.current = [];

            mediaRecorder.ondataavailable = (e) => {
                if (e.data.size > 0) {
                    chunksRef.current.push(e.data);
                }
            };

            mediaRecorder.onstop = () => {
                const blob = new Blob(chunksRef.current, { type: "audio/webm" });
                setAudioBlob(blob);
                // Explicitly get tracks from the stream captured at start to ensure hardware release
                stream.getTracks().forEach((track) => {
                    track.stop();
                    console.log("AudioRecorder track stopped:", track.label);
                });
            };

            mediaRecorder.start();
            setRecording(true);
            setError(null);
            setFeedback(null);
            setAudioBlob(null); // Clear previous blob when starting new recording
        } catch (err) {
            console.error("Error accessing microphone:", err);
            setError("Could not access microphone.");
        }
    };

    // Robust cleanup on unmount
    React.useEffect(() => {
        return () => {
            if (streamRef.current) {
                streamRef.current.getTracks().forEach(track => {
                    track.stop();
                    console.log("AudioRecorder track stopped on unmount:", track.label);
                });
                streamRef.current = null;
            }
            if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
                try { mediaRecorderRef.current.stop(); } catch (e) { }
            }
        };
    }, []);

    const stopRecording = () => {
        if (mediaRecorderRef.current && recording) {
            mediaRecorderRef.current.stop();
            setRecording(false);
        }
    };

    const analyzeRecording = async () => {
        if (!audioBlob) return;
        setLoading(true);
        setError(null);

        const formData = new FormData();
        formData.append("file", audioBlob, "recording.webm");

        try {
            const res = await fetch(`${process.env.NEXT_PUBLIC_BACKEND_URL}/api/v1/coach/analyze`, {
                method: "POST",
                body: formData,
            });

            if (!res.ok) {
                throw new Error(`Server error: ${res.statusText}`);
            }

            const data: Feedback = await res.json();
            setFeedback(data);
        } catch (err) {
            console.error("Analysis failed:", err);
            setError("Analysis failed. Ensure backend is running.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex flex-col items-center gap-6 p-6 w-full max-w-2xl mx-auto">
            <div className="w-full bg-white dark:bg-zinc-900 rounded-2xl shadow-lg border border-zinc-200 dark:border-zinc-800 p-8">

                {/* Recording Controls */}
                <div className="flex flex-col items-center justify-center gap-4 mb-8">
                    <div className={`relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-300 ${recording ? 'bg-red-100 dark:bg-red-900/30 animate-pulse' : 'bg-zinc-100 dark:bg-zinc-800'}`}>
                        <button
                            onClick={recording ? stopRecording : startRecording}
                            className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-200 shadow-md ${recording
                                ? "bg-red-500 hover:bg-red-600 scale-90"
                                : "bg-blue-600 hover:bg-blue-700 hover:scale-105"
                                }`}
                        >
                            {recording ? (
                                <div className="w-6 h-6 bg-white rounded-sm" />
                            ) : (
                                <svg className="w-8 h-8 text-white ml-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                                </svg>
                            )}
                        </button>
                    </div>
                    <p className="text-sm font-medium text-zinc-500 dark:text-zinc-400">
                        {recording ? "Listening..." : audioBlob ? "Recording ready" : "Tap to speak"}
                    </p>
                </div>

                {/* Action Buttons */}
                {audioBlob && !recording && !feedback && (
                    <button
                        onClick={analyzeRecording}
                        disabled={loading}
                        className="w-full py-3 px-6 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 font-semibold rounded-lg hover:opacity-90 transition-all disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                        {loading ? (
                            <>
                                <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                                Analyzing Response...
                            </>
                        ) : (
                            "Analyze Answer"
                        )}
                    </button>
                )}

                {error && (
                    <div className="mt-4 p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm rounded-lg border border-red-100 dark:border-red-900/50">
                        {error}
                    </div>
                )}
            </div>

            {/* Feedback Section */}
            {feedback && (
                <div className="w-full bg-white dark:bg-zinc-900 rounded-2xl shadow-lg border border-zinc-200 dark:border-zinc-800 p-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <h3 className="text-xl font-bold mb-6 text-zinc-900 dark:text-white">AI Coach Feedback</h3>

                    <div className="grid grid-cols-2 gap-4 mb-8">
                        <ScoreCard label="Fluency" score={feedback.fluency} />
                        <ScoreCard label="Grammar" score={feedback.grammar} />
                        <ScoreCard label="Confidence" score={feedback.confidence} />
                        <ScoreCard label="Relevance" score={feedback.relevance} />
                    </div>

                    <div className="space-y-4">
                        <div className="p-4 bg-zinc-50 dark:bg-zinc-800/50 rounded-xl">
                            <h4 className="text-sm font-semibold text-zinc-500 dark:text-zinc-400 mb-2  tracking-wide">Transcript</h4>
                            <p className="text-zinc-700 dark:text-zinc-300 ">&quot;{feedback.transcription}&quot;</p>
                        </div>

                        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-900/30">
                            <h4 className="text-sm font-semibold text-blue-600 dark:text-blue-400 mb-2  tracking-wide">Coach&apos;s Tips</h4>
                            <p className="text-zinc-700 dark:text-zinc-300 whitespace-pre-line">{feedback.feedback}</p>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

function ScoreCard({ label, score }: { label: string; score: number }) {
    const getColor = (s: number) => {
        if (s >= 8) return "text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800";
        if (s >= 5) return "text-yellow-600 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-900/20 border-yellow-200 dark:border-yellow-800";
        return "text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800";
    };

    return (
        <div className={`flex flex-col items-center justify-center p-4 rounded-xl border ${getColor(score)}`}>
            <span className="text-3xl font-bold mb-1">{score}/10</span>
            <span className="text-sm font-medium opacity-80">{label}</span>
        </div>
    );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { apiClient } from "@/utils/api";
import { useDivision } from "@/context/DivisionContext";
import { useAuth } from "@/context/AuthContext";

interface Department {
    id: number;
    name: string;
}

export default function DepartmentSelector() {
    const { role, departmentId, divisionId } = useAuth();
    const { selectedDivisionId, setSelectedDivisionId, selectedDepartmentId, setSelectedDepartmentId } = useDivision();
    const [departments, setDepartments] = useState<Department[]>([]);
    const [loading, setLoading] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const [showAll, setShowAll] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const INITIAL_DISPLAY_COUNT = 5;

    useEffect(() => {
        // For HOD/Staff, auto-set their department and division and don't load list
        if (role === "SUB_ADMIN" || role === "STAFF") {
            if (divisionId) setSelectedDivisionId(divisionId);
            if (departmentId) setSelectedDepartmentId(departmentId);
            return;
        }

        if (selectedDivisionId) {
            fetchDepartments(selectedDivisionId);
        } else {
            setDepartments([]);
            setSelectedDepartmentId(null);
        }
    }, [selectedDivisionId, role, departmentId, divisionId]);

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                setShowAll(false);
            }
        };

        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const fetchDepartments = async (divId: number) => {
        setLoading(true);
        try {
            const res = await apiClient.get(`/api/v1/hierarchy/departments?division_id=${divId}`);
            if (res.ok) {
                const data = await res.json();
                setDepartments(data);
            }
        } catch (e) {
            console.error("Failed to fetch departments", e);
        } finally {
            setLoading(false);
        }
    };

    const handleSelectDepartment = (deptId: number | null) => {
        setSelectedDepartmentId(deptId);
        setIsOpen(false);
        setShowAll(false);
    };

    // Show if a division is selected (either by global filter or inherently by Division Admin role)
    // BUT hide for HOD/Staff as they are locked to one department
    if (!selectedDivisionId || role === "SUB_ADMIN" || role === "STAFF") return null;

    const selectedDept = departments.find(d => d.id === selectedDepartmentId);
    const displayedDepartments = showAll ? departments : departments.slice(0, INITIAL_DISPLAY_COUNT);
    const hasMore = departments.length > INITIAL_DISPLAY_COUNT;

    return (
        <div className="flex items-center gap-2">
            <div className="h-8 w-[1px] bg-slate-200 mx-2"></div>
            <div className="relative" ref={dropdownRef}>
                <button
                    onClick={() => setIsOpen(!isOpen)}
                    className={`flex items-center gap-2 bg-slate-50 border border-slate-200 text-slate-700 text-xs font-bold rounded-xl px-3 py-2.5 outline-none hover:border-slate-300 focus:border-slate-500 focus:ring-1 focus:ring-slate-500 transition-all cursor-pointer min-w-[200px] ${loading ? 'opacity-50' : ''}`}
                    disabled={loading}
                >
                    <span className="material-icons-outlined text-sm text-slate-400">domain</span>
                    <span className="flex-1 text-left truncate">
                        {selectedDept ? selectedDept.name : "All Departments"}
                    </span>
                    <span className="material-icons-outlined text-sm text-slate-400">
                        {isOpen ? "expand_less" : "expand_more"}
                    </span>
                </button>

                {isOpen && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-slate-200 rounded-xl shadow-xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                        <div className="max-h-[300px] overflow-y-auto">
                            {/* All Departments Option */}
                            <button
                                onClick={() => handleSelectDepartment(null)}
                                className={`w-full text-left px-4 py-2.5 text-xs font-bold hover:bg-slate-50 transition-colors flex items-center gap-2 ${!selectedDepartmentId ? "bg-slate-100 text-slate-900" : "text-slate-600"
                                    }`}
                            >
                                <span className="material-icons-outlined text-sm">apps</span>
                                All Departments
                            </button>

                            {/* Department List */}
                            {displayedDepartments.map((dept) => (
                                <button
                                    key={dept.id}
                                    onClick={() => handleSelectDepartment(dept.id)}
                                    className={`w-full text-left px-4 py-2.5 text-xs font-bold hover:bg-slate-50 transition-colors flex items-center gap-2 ${selectedDepartmentId === dept.id ? "bg-slate-100 text-slate-900" : "text-slate-600"
                                        }`}
                                >
                                    <span className="material-icons-outlined text-sm">school</span>
                                    {dept.name}
                                </button>
                            ))}

                            {/* More Button */}
                            {hasMore && !showAll && (
                                <button
                                    onClick={() => setShowAll(true)}
                                    className="w-full text-left px-4 py-2.5 text-xs font-black   text-slate-400 hover:bg-slate-50 hover:text-slate-900 transition-colors border-t border-slate-100 flex items-center gap-2"
                                >
                                    <span className="material-icons-outlined text-sm">expand_more</span>
                                    More ({departments.length - INITIAL_DISPLAY_COUNT} more)
                                </button>
                            )}

                            {/* Show Less Button */}
                            {showAll && hasMore && (
                                <button
                                    onClick={() => setShowAll(false)}
                                    className="w-full text-left px-4 py-2.5 text-xs font-black   text-slate-400 hover:bg-slate-50 hover:text-slate-900 transition-colors border-t border-slate-100 flex items-center gap-2"
                                >
                                    <span className="material-icons-outlined text-sm">expand_less</span>
                                    Show Less
                                </button>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { apiClient } from "@/utils/api";
import { useDivision } from "@/context/DivisionContext";
import { useAuth } from "@/context/AuthContext";

interface Division {
    id: number;
    name: string;
    slug: string;
}

export default function DivisionSelector() {
    const { role, divisionId } = useAuth();
    const { selectedDivisionId, setSelectedDivisionId } = useDivision();
    const [divisions, setDivisions] = useState<Division[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (divisionId) {
            // Division Admin: Force selection and don't load list
            setSelectedDivisionId(divisionId);
            setLoading(false);
            return;
        }

        // Only fetch if admin (assuming only admins can switch divs)
        if (role === "ADMIN") {
            fetchDivisions();
        } else {
            setLoading(false);
        }
    }, [role, divisionId]);

    const fetchDivisions = async () => {
        try {
            const res = await apiClient.get("/api/v1/hierarchy/divisions");
            if (res.ok) {
                const data = await res.json();
                setDivisions(data);
            }
        } catch (e) {
            console.error("Failed to fetch divisions", e);
        } finally {
            setLoading(false);
        }
    };

    if (role !== "ADMIN" || loading) return null;

    // If divisionId is set (Division Admin), we don't show the selector (or we could show it disabled)
    // The user wants "in the filter there should be dep of their division".
    // If we hide this, only DepartmentSelector will show. That seems correct.
    if (divisionId) return null;

    return (
        <div className="flex items-center gap-2">
            <div className="relative group">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 material-icons-outlined text-sm pointer-events-none">
                    account_balance
                </span>
                <select
                    value={selectedDivisionId || ""}
                    onChange={(e) => {
                        const val = e.target.value;
                        setSelectedDivisionId(val ? Number(val) : null);
                    }}
                    className="appearance-none bg-slate-50 border border-slate-200 text-slate-700 text-xs font-bold rounded-xl pl-9 pr-8 py-2.5 outline-none hover:border-slate-300 focus:border-slate-500 focus:ring-1 focus:ring-slate-500 transition-all cursor-pointer min-w-[200px]"
                >
                    <option value="" className="text-slate-500 font-bold">All Divisions</option>
                    {divisions.map((div) => (
                        <option key={div.id} value={div.id}>
                            {div.name}
                        </option>
                    ))}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none flex items-center">
                    <span className="material-icons-outlined text-slate-400 text-sm">expand_more</span>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { apiClient } from "@/utils/api";
import AIGenerationOverlay from "@/components/ui/AIGenerationOverlay";
import { useAuth } from "@/context/AuthContext";
import { useDivision } from "@/context/DivisionContext";

interface TestCase {
    input: string;
    output: string;
}

interface Question {
    id?: string;
    type: string;
    topic: string;
    difficulty: string;
    content: {
        question?: string;
        scenario?: string;
        initial_code?: { python: string };
        test_cases?: TestCase[];
        options?: {
            A: string;
            B: string;
            C: string;
            D: string;
        };
        min_words?: number;
        max_words?: number;
    };
    correct_answer: {
        answer: string;
        explanation: string;
    };
    department_id?: number | null;
    batch?: string | null;
}

interface QuestionFormProps {
    onSuccess: (newQuestion: Question) => void;
    onCancel: () => void;
    initialType?: string;
    lockType?: boolean;
    initialData?: Question;
    departmentId?: number | null;
}

export default function QuestionForm({ onSuccess, onCancel, initialType = "APTITUDE", lockType = false, initialData, departmentId }: QuestionFormProps) {
    const { batch: creatorBatch } = useAuth();
    const { selectedBatch } = useDivision();
    const [type, setType] = useState(initialData?.type || initialType);
    const [topic, setTopic] = useState(initialData?.topic || "");
    const [customTopic, setCustomTopic] = useState("");
    const [difficulty, setDifficulty] = useState(initialData?.difficulty || "EASY");
    const [questionText, setQuestionText] = useState(initialData?.content?.question || "");
    const [initialCode, setInitialCode] = useState(initialData?.content?.initial_code?.python || "");
    const [optionA, setOptionA] = useState(initialData?.content?.options?.A || "");
    const [optionB, setOptionB] = useState(initialData?.content?.options?.B || "");
    const [optionC, setOptionC] = useState(initialData?.content?.options?.C || "");
    const [optionD, setOptionD] = useState(initialData?.content?.options?.D || "");
    const [correctOption, setCorrectOption] = useState(initialData?.correct_answer?.answer || "A");
    const [explanation, setExplanation] = useState(initialData?.correct_answer?.explanation || initialData?.correct_answer?.answer || "");
    const [minWords, setMinWords] = useState(initialData?.content?.min_words || 0);
    const [maxWords, setMaxWords] = useState(initialData?.content?.max_words || 500);
    const [loading, setLoading] = useState(false);
    const [generating, setGenerating] = useState(false);
    const [testCases, setTestCases] = useState<TestCase[]>(initialData?.content?.test_cases || []);
    const [availableTopics, setAvailableTopics] = useState<string[]>([]);
    // If we have initialData.batch, we use it, otherwise we use the globally selected batch or the creator's batch
    const [batch, setBatch] = useState(initialData?.batch || selectedBatch || creatorBatch || "");

    useEffect(() => {
        const fetchTopics = async () => {
            try {
                const res = await apiClient.get(`/api/v1/content/questions/topics?type=${type}`);
                if (res.ok) {
                    const data = await res.json();
                    setAvailableTopics(data);
                }
            } catch (e) {
                console.error("Failed to fetch topics", e);
            }
        };
        fetchTopics();
    }, [type]);

    const handleGenerateAI = async () => {
        if (!topic) return alert("Please enter a topic first");
        setGenerating(true);
        try {
            const res = await apiClient.post(`/api/v1/evaluator/generate`, { topic, difficulty });

            if (res.ok) {
                const data = await res.json();
                setQuestionText(data.question);
                setExplanation(data.model_answer);
            } else {
                alert("Failed to generate question");
            }
        } catch (e) {
            console.error(e);
            alert("Error generating question");
        } finally {
            setGenerating(false);
        }
    };


    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        const finalTopic = topic;

        let payload;
        if (type === "CODING") {
            if (!questionText.trim()) return alert("Please enter a problem description");
            if (testCases.length === 0) return alert("Please add at least one test case");
            if (testCases.some(tc => !tc.input.trim() || !tc.output.trim())) {
                return alert("All test cases must have both input and output");
            }
            payload = {
                type: "CODING",
                topic: finalTopic,
                difficulty,
                content: {
                    question: questionText,
                    initial_code: { python: initialCode },
                    test_cases: testCases
                },
                correct_answer: {
                    answer: "N/A",
                    explanation: explanation || "Coding Problem"
                },
                department_id: departmentId,
                batch: batch || null
            };
        } else if (type === "COMMUNICATION") {
            payload = {
                type: "COMMUNICATION",
                topic: finalTopic,
                difficulty,
                content: {
                    question: questionText,
                    scenario: questionText
                },
                correct_answer: {
                    answer: "ORAL_RESPONSE",
                    explanation: "AI Evaluated"
                },
                department_id: departmentId,
                batch: batch || null
            };
        } else if (type === "SUBJECTIVE") {
            payload = {
                type: "SUBJECTIVE",
                topic: finalTopic,
                difficulty,
                content: {
                    question: questionText,
                    min_words: minWords,
                    max_words: maxWords,
                },
                correct_answer: {
                    answer: explanation, // Store sample/target answer here
                    explanation: "AI Evaluated Subjective Task"
                },
                department_id: departmentId,
                batch: batch || null
            };
        } else if (type === "PERSONALITY" || type === "BEHAVIORAL") {
            payload = {
                type: type,
                topic: finalTopic,
                difficulty,
                content: {
                    question: questionText,
                    options: {
                        A: optionA,
                        B: optionB,
                        C: optionC,
                        D: optionD
                    }
                },
                correct_answer: {
                    answer: correctOption,
                    explanation
                },
                department_id: departmentId,
                batch: batch || null
            };
        } else {
            payload = {
                type: "APTITUDE",
                topic: finalTopic,
                difficulty,
                content: {
                    question: questionText,
                    options: {
                        A: optionA,
                        B: optionB,
                        C: optionC,
                        D: optionD
                    }
                },
                correct_answer: {
                    answer: correctOption,
                    explanation
                },
                department_id: departmentId,
                batch: batch || null
            };
        }

        try {
            const url = initialData?.id
                ? `/api/v1/content/questions/${initialData.id}`
                : `/api/v1/content/questions`;

            const res = initialData?.id
                ? await apiClient.put(url, payload)
                : await apiClient.post(url, payload);

            if (res.ok) {
                const newQ = await res.json();
                onSuccess(newQ);
            } else {
                alert(`Failed to ${initialData?.id ? 'update' : 'create'} question`);
            }
        } catch (e) {
            console.error(e);
            alert("Error creating question");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-white rounded-3xl p-0">
            <AIGenerationOverlay isOpen={generating} title="Synchronizing Neural Link" />
            <form onSubmit={handleSubmit} className="space-y-4">
                {!lockType && (
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-lg font-bold text-gray-900  tracking-tight">Add Custom Question</h3>
                        <button
                            type="button"
                            onClick={onCancel}
                            className="text-gray-400 hover:text-gray-600"
                        >
                            <span className="material-symbols-rounded">close</span>
                        </button>
                    </div>
                )}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {!lockType && (
                        <div>
                            <label className="block text-[10px] font-black text-gray-400   mb-1">Category</label>
                            <select
                                value={type}
                                onChange={(e) => setType(e.target.value)}
                                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-xs font-black text-slate-900 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 transition-all outline-none"
                            >
                                <option value="APTITUDE">Aptitude (MCQ)</option>
                                <option value="CODING">Coding</option>
                                <option value="COMMUNICATION">Communication</option>
                                <option value="PERSONALITY">Personality Test</option>
                                <option value="BEHAVIORAL">Behavioral &amp; Emotional</option>
                                <option value="SUBJECTIVE">Subjective (AI Evaluator)</option>
                            </select>
                        </div>
                    )}
                    <div className={lockType ? "col-span-2" : ""}>
                        <label className="block text-[10px] font-black text-gray-400   mb-1">{type === "SUBJECTIVE" ? "Domain / Topic" : "Topic"}</label>
                        <input
                            type="text"
                            list="topic-suggestions"
                            value={topic}
                            onChange={(e) => setTopic(e.target.value)}
                            className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-xs font-black text-slate-900 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 transition-all outline-none placeholder:text-slate-300"
                            placeholder={type === "SUBJECTIVE" ? "e.g., System Design" : "e.g., Leadership style"}
                        />
                        <datalist id="topic-suggestions">
                            {availableTopics.map(t => (
                                <option key={t} value={t} />
                            ))}
                        </datalist>
                        {type === "SUBJECTIVE" && (
                            <button
                                type="button"
                                onClick={handleGenerateAI}
                                disabled={generating || !topic}
                                className="mt-2 text-[10px] font-black   text-slate-600 hover:text-slate-700 flex items-center gap-1 disabled:opacity-50"
                            >
                                <span className="material-icons-outlined text-sm">auto_awesome</span>
                                Generate with AI
                            </button>
                        )}
                    </div>
                    <div>
                        <label className="block text-[10px] font-black text-gray-400   mb-1">Difficulty</label>
                        <select
                            value={difficulty}
                            onChange={(e) => setDifficulty(e.target.value)}
                            className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-xs font-black text-slate-900 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 transition-all outline-none"
                        >
                            <option value="EASY">Easy</option>
                            <option value="MEDIUM">Medium</option>
                            <option value="HARD">Hard</option>
                        </select>
                    </div>
                </div>

                <div>
                    <label className="block text-[10px] font-black text-gray-400   mb-1">
                        {type === "CODING" ? "Problem Description" : type === "COMMUNICATION" ? "Scenario Prompt" : type === "SUBJECTIVE" ? "Scenario / Task Instructions" : "Question Text"}
                    </label>
                    <textarea
                        value={questionText}
                        onChange={(e) => setQuestionText(e.target.value)}
                        required
                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-xs font-medium text-slate-700 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 transition-all outline-none placeholder:text-slate-300 min-h-[120px]"
                        rows={3}
                        placeholder={type === "SUBJECTIVE" ? "Describe the task or scenario for the candidate..." : "Enter your question here..."}
                    />
                </div>

                {type === "SUBJECTIVE" && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-in fade-in duration-700">
                        <div>
                            <label className="block text-[10px] font-black text-gray-400   mb-1">Min Word Limit</label>
                            <input name="min_words" type="number" value={minWords} onChange={e => setMinWords(parseInt(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400   mb-1">Max Word Limit</label>
                            <input name="max_words" type="number" value={maxWords} onChange={e => setMaxWords(parseInt(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900" />
                        </div>
                    </div>
                )}

                {(type === "APTITUDE" || type === "PERSONALITY" || type === "BEHAVIORAL") && (
                    <>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-black text-gray-400   mb-1">Option A</label>
                                <input type="text" value={optionA} onChange={(e) => setOptionA(e.target.value)} required className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400   mb-1">Option B</label>
                                <input type="text" value={optionB} onChange={(e) => setOptionB(e.target.value)} required className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400   mb-1">Option C</label>
                                <input type="text" value={optionC} onChange={(e) => setOptionC(e.target.value)} required className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400   mb-1">Option D</label>
                                <input type="text" value={optionD} onChange={(e) => setOptionD(e.target.value)} required className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900" />
                            </div>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-black text-gray-400   mb-1">Correct Answer</label>
                                <select value={correctOption} onChange={(e) => setCorrectOption(e.target.value)} className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-bold text-gray-900">
                                    <option value="A">Option A</option>
                                    <option value="B">Option B</option>
                                    <option value="C">Option C</option>
                                    <option value="D">Option D</option>
                                </select>
                            </div>
                        </div>
                    </>
                )}

                {type === "CODING" && (
                    <div className="space-y-4">
                        <div>
                            <label className="block text-[10px] font-black text-gray-400   mb-1">Initial Code (Python)</label>
                            <textarea
                                value={initialCode}
                                onChange={(e) => setInitialCode(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-xs font-mono text-slate-50"
                                rows={4}
                                placeholder="def solution():\n    pass"
                            />
                        </div>
                        <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
                            <div className="flex justify-between items-center mb-3">
                                <label className="block text-[10px] font-black text-gray-400  ">Test Cases</label>
                                <button
                                    type="button"
                                    onClick={() => setTestCases([...testCases, { input: "", output: "" }])}
                                    className="text-[10px] font-black   text-slate-800 hover:text-slate-600"
                                >
                                    + Add Test Case
                                </button>
                            </div>
                            <div className="space-y-3">
                                {testCases.map((tc, idx) => (
                                    <div key={idx} className="flex gap-2 items-start bg-white p-3 rounded-lg border border-gray-100 relative group">
                                        <div className="flex-1">
                                            <span className="text-[8px] font-black text-gray-400  block mb-1">Input</span>
                                            <textarea
                                                value={tc.input}
                                                onChange={(e) => {
                                                    const next = [...testCases];
                                                    next[idx].input = e.target.value;
                                                    setTestCases(next);
                                                }}
                                                className="w-full bg-slate-50 border-0 rounded text-[10px] font-mono p-2 focus:ring-1 focus:ring-slate-500"
                                                rows={2}
                                            />
                                        </div>
                                        <div className="flex-1">
                                            <span className="text-[8px] font-black text-gray-400  block mb-1">Output</span>
                                            <textarea
                                                value={tc.output}
                                                onChange={(e) => {
                                                    const next = [...testCases];
                                                    next[idx].output = e.target.value;
                                                    setTestCases(next);
                                                }}
                                                className="w-full bg-slate-50 border-0 rounded text-[10px] font-mono p-2 focus:ring-1 focus:ring-slate-500"
                                                rows={2}
                                            />
                                        </div>
                                        <button
                                            type="button"
                                            onClick={() => setTestCases(testCases.filter((_, i) => i !== idx))}
                                            className="p-1 text-gray-300 hover:text-slate-900 transition-colors"
                                        >
                                            <span className="material-icons-outlined text-sm">delete</span>
                                        </button>
                                    </div>
                                ))}
                                {testCases.length === 0 && (
                                    <p className="text-[10px] text-gray-400  text-center py-2">No test cases added yet.</p>
                                )}
                            </div>
                        </div>
                    </div>
                )}

                {(type === "APTITUDE" || type === "PERSONALITY" || type === "BEHAVIORAL" || type === "SUBJECTIVE") && (
                    <div className={type === "SUBJECTIVE" && !explanation ? "hidden" : "animate-in slide-in-from-top-4 duration-700 delay-100"}>
                        <label className="block text-[10px] font-black text-gray-400   mb-1">{type === "SUBJECTIVE" ? "Target Answer (Sample Response for AI Reference)" : "Explanation"}</label>
                        <textarea
                            value={explanation}
                            onChange={(e) => setExplanation(e.target.value)}
                            className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 text-xs font-medium text-gray-900 focus:ring-2 focus:ring-slate-500"
                            rows={3}
                            placeholder={type === "SUBJECTIVE" ? "Enter the ideal response that AI should look for..." : "Explain why the answer is correct..."}
                        />
                    </div>
                )}

                <div className="flex justify-end gap-3 pt-4">
                    <button
                        type="button"
                        onClick={onCancel}
                        className="px-6 py-3 border border-slate-200 text-slate-400 text-[10px] font-black  tracking-[0.2em] rounded-xl hover:bg-slate-50 transition-all"
                    >
                        Cancel
                    </button>
                    <button
                        type="submit"
                        disabled={loading}
                        className="px-8 py-3 bg-slate-900 text-white text-[10px] font-black  tracking-[0.2em] rounded-xl hover:bg-slate-800 transition-all shadow-xl shadow-slate-100 disabled:opacity-50 active:scale-95"
                    >
                        {loading ? 'Processing...' : 'Save Configuration'}
                    </button>
                </div>
            </form>
        </div >
    );
}

"use client";

import React from 'react';

interface Line {
    x1: number;
    y1: number;
    x2: number;
    y2: number;
}

interface Pattern {
    lines: Line[];
}

interface SpotOnQuestionEditorProps {
    target: any; // Could be { lines: Line[] } or just Line[]
    options: any[];
    correctIndex: number;
    onUpdate: (data: any) => void;
}

export default function SpotOnQuestionEditor({ target, options, correctIndex, onUpdate }: SpotOnQuestionEditorProps) {
    const renderPattern = (lines: Line[], size: number = 100) => {
        if (!Array.isArray(lines)) return null;
        return (
            <svg viewBox="0 0 100 100" className="w-full h-full" style={{ maxWidth: size, maxHeight: size }}>
                <circle cx="50" cy="50" r="48" fill="none" stroke="#e2e8f0" strokeWidth="1" />
                {lines.map((line, i) => (
                    <line
                        key={i}
                        x1={line.x1}
                        y1={line.y1}
                        x2={line.x2}
                        y2={line.y2}
                        stroke="#1e293b"
                        strokeWidth="2"
                        strokeLinecap="round"
                    />
                ))}
            </svg>
        );
    };

    return (
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm space-y-6">
            <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-400  ">Question Preview</h3>
                <span className="px-2 py-1 bg-slate-100 text-slate-600 text-[10px] font-black rounded-lg ">Type: Spot On</span>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Target Pattern */}
                <div className="flex flex-col items-center justify-center p-6 bg-slate-50 rounded-2xl border border-slate-100">
                    <span className="text-[10px] font-black text-slate-400   mb-4">Target Pattern</span>
                    <div className="w-32 h-32 bg-white rounded-full p-4 shadow-sm border border-slate-200 flex items-center justify-center">
                        {renderPattern(Array.isArray(target) ? target : target?.lines)}
                    </div>
                </div>

                {/* Options Grid */}
                <div className="space-y-4">
                    <span className="text-[10px] font-black text-slate-400  ">Options</span>
                    <div className="grid grid-cols-2 gap-4">
                        {options?.map((opt, idx) => {
                            const lines = Array.isArray(opt) ? opt : opt?.lines;
                            return (
                                <div
                                    key={idx}
                                    className={`relative p-4 rounded-xl border-2 flex items-center justify-center transition-all ${idx === correctIndex
                                        ? 'border-gray-500 bg-gray-50/50'
                                        : 'border-slate-100 bg-white'
                                        }`}
                                >
                                    <div className="w-16 h-16">
                                        {renderPattern(lines)}
                                    </div>
                                    <div className={`absolute top-2 right-2 w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-black ${idx === correctIndex ? 'bg-gray-500 text-white' : 'bg-slate-200 text-slate-500'
                                        }`}>
                                        {idx + 1}
                                    </div>
                                    {idx === correctIndex && (
                                        <span className="absolute -bottom-2 px-2 py-0.5 bg-gray-500 text-white text-[8px] font-black rounded ">Correct</span>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState } from "react";
import Editor from "@monaco-editor/react";
import { LANGUAGE_CONFIG } from "@/utils/languages";

interface CodeQuestionProps {
    questionId: string | number;
    code: string;
    onCodeChange?: (value: string) => void;
    language: string;
    onLanguageChange?: (lang: string) => void;
    isDark?: boolean;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    testCases?: any[];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    testResults?: { [key: string]: any };
    executingTests?: { [key: string]: boolean };
    onRunTest?: (index: number) => void;
    customInput?: string;
    onCustomInputChange?: (value: string) => void;
    onRunCustomTest?: () => void;
    executingCustomTest?: boolean;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    customTestResult?: any;
    rightPaneHeight?: number;
    onResizeRightPane?: (e: React.MouseEvent) => void;
    isTransitioning?: boolean;
    transitionDirection?: 'next' | 'prev';
    readOnly?: boolean;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    feedback?: any; // Can be object with test_cases or string
    consoleOutput?: string | string[];
}

export default function CodeQuestion({
    questionId,
    code,
    onCodeChange,
    language,
    onLanguageChange,
    isDark,
    testCases,
    testResults,
    executingTests,
    onRunTest,
    customInput,
    onCustomInputChange,
    onRunCustomTest,
    executingCustomTest,
    customTestResult,
    rightPaneHeight = 60,
    onResizeRightPane,
    isTransitioning,
    transitionDirection,
    readOnly = false,
    feedback,
    consoleOutput
}: CodeQuestionProps) {
    const [activeTab, setActiveTab] = useState<'test_cases' | 'custom_input'>('test_cases');
    const [expandedTests, setExpandedTests] = useState<{ [key: number]: boolean }>({});
    const [showLanguageDropdown, setShowLanguageDropdown] = useState(false);

    const toggleTestExpand = (index: number) => {
        setExpandedTests(prev => ({
            ...prev,
            [index]: !prev[index]
        }));
    };

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const _unused = transitionDirection;

    // Switch to console tab if output arrives and we are not on it, or user just ran custom test?
    // Let parent control this or user manually switch.

    return (
        <>
            {/* IDE Top Pane (Editor) */}
            <div style={{ height: `${rightPaneHeight}%`, minHeight: '20%', maxHeight: '90%' }} className="flex flex-col relative shrink-0">
                {/* IDE Header */}
                <div className={`h-12 border-b flex items-center justify-between px-4 z-20 ${isDark ? 'bg-[#1e1f23] border-[#2d2e32]' : 'bg-white border-slate-200'}`}>
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2">
                            <span className={`material-icons-outlined text-[16px] ${isDark ? 'text-blue-400' : 'text-blue-600'}`}>code</span>
                            <span className={`text-[11px] font-black   ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Editor</span>
                        </div>
                        <div className={`w-px h-4 ${isDark ? 'bg-[#2d2e32]' : 'bg-slate-200'}`} />

                        {readOnly ? (
                            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border ${isDark ? 'bg-[#2d2e32] border-[#3f4147] text-slate-300' : 'bg-slate-100 border-slate-200 text-slate-600'}`}>
                                <span className="text-[10px] font-black  ">{LANGUAGE_CONFIG[language]?.name || language}</span>
                            </div>
                        ) : (
                            <div className="relative">
                                <button
                                    onClick={() => setShowLanguageDropdown(!showLanguageDropdown)}
                                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border transition-all ${isDark
                                        ? 'bg-[#2d2e32] border-[#3f4147] text-slate-300 hover:bg-[#3f4147] hover:text-white'
                                        : 'bg-slate-50 border-slate-200 text-slate-600 hover:bg-white hover:border-indigo-200 hover:text-indigo-600'
                                        }`}
                                >
                                    <span className="text-[10px] font-black  ">{LANGUAGE_CONFIG[language]?.name || language}</span>
                                    <span className="material-icons-outlined text-[14px]">expand_more</span>
                                </button>
                                {showLanguageDropdown && (
                                    <>
                                        <div className="fixed inset-0 z-10" onClick={() => setShowLanguageDropdown(false)} />
                                        <div className={`absolute top-full left-0 mt-2 w-48 rounded-xl border shadow-xl overflow-hidden z-20 ${isDark ? 'bg-[#1e1f23] border-[#2d2e32]' : 'bg-white border-slate-100'}`}>
                                            {Object.keys(LANGUAGE_CONFIG).map((lang) => (
                                                <button
                                                    key={lang}
                                                    onClick={() => {
                                                        if (onLanguageChange) onLanguageChange(lang);
                                                        setShowLanguageDropdown(false);
                                                    }}
                                                    className={`w-full text-left px-4 py-3 text-[11px] font-bold   transition-colors ${language === lang
                                                        ? isDark ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700'
                                                        : isDark ? 'text-slate-400 hover:bg-[#2d2e32] hover:text-white' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900'
                                                        }`}
                                                >
                                                    {LANGUAGE_CONFIG[lang].name}
                                                </button>
                                            ))}
                                        </div>
                                    </>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex-1 overflow-hidden relative group">
                    <div className={`absolute inset-0 transition-opacity duration-300 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}>
                        <Editor
                            height="100%"
                            language={language}
                            theme={isDark ? "vs-dark" : "light"}
                            value={code}
                            onChange={(value) => !readOnly && onCodeChange && onCodeChange(value || "")}
                            options={{
                                minimap: { enabled: false },
                                fontSize: 13,
                                lineHeight: 22,
                                fontFamily: 'JetBrains Mono, monospace',
                                fontLigatures: true,
                                scrollBeyondLastLine: false,
                                automaticLayout: true,
                                padding: { top: 20, bottom: 20 },
                                readOnly: readOnly,
                                domReadOnly: readOnly,
                                renderValidationDecorations: readOnly ? "off" : "on",
                                cursorStyle: readOnly ? 'line-thin' : 'line',
                                renderLineHighlight: readOnly ? 'none' : 'all',
                                selectionHighlight: !readOnly,
                                occurrencesHighlight: "off",
                                hideCursorInOverviewRuler: readOnly,
                            }}
                        />
                    </div>
                </div>
            </div>

            {/* Horizontal Drag Handle */}
            <div
                onMouseDown={!readOnly ? onResizeRightPane : undefined}
                className={`h-1 z-20 group flex items-center justify-center transition-colors ${readOnly ? 'cursor-default' : 'cursor-row-resize hover:bg-indigo-500/20'} ${isDark ? 'bg-[#111214]' : 'bg-slate-50'}`}
            >
                <div className={`h-[1px] w-full transition-colors ${isDark ? 'bg-[#2d2e32]' : 'bg-slate-200'} ${!readOnly && 'group-hover:bg-indigo-500/50'}`} />
            </div>

            {/* IDE Bottom Pane (Tests/Custom Input/Feedback) */}
            <div style={{ height: `${100 - rightPaneHeight}%`, minHeight: '10%' }} className={`flex flex-col overflow-hidden ${isDark ? 'bg-[#0d0f11]' : 'bg-[#f8fafc]'}`}>
                {/* Tabs */}
                <div className="flex border-b border-[#2d2e32]/50 px-4">
                    <button
                        onClick={() => setActiveTab('test_cases')}
                        className={`px-4 py-3 text-[10px] font-black   border-b-2 transition-all ${activeTab === 'test_cases'
                            ? isDark ? 'border-indigo-500 text-white' : 'border-indigo-600 text-indigo-600'
                            : 'border-transparent text-slate-500 hover:text-slate-400'
                            }`}
                    >
                        {readOnly ? 'Evaluation Results' : 'Test Cases'}
                    </button>

                    {(!readOnly && onRunCustomTest) && (
                        <button
                            onClick={() => setActiveTab('custom_input')}
                            className={`px-4 py-3 text-[10px] font-black   border-b-2 transition-all ${activeTab === 'custom_input'
                                ? isDark ? 'border-indigo-500 text-white' : 'border-indigo-600 text-indigo-600'
                                : 'border-transparent text-slate-500 hover:text-slate-400'
                                }`}
                        >
                            Custom Input
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto p-4 relative">
                    <div className={`absolute inset-0 p-4 transition-all duration-300 ${isTransitioning ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>

                        {/* VIEW 1: TEST CASES / FEEDBACK */}
                        {activeTab === 'test_cases' && (
                            <div className="space-y-3">
                                {readOnly && feedback ? (
                                    /* READ-ONLY FEEDBACK VIEW */
                                    <div className="space-y-4">
                                        {feedback.test_cases && Array.isArray(feedback.test_cases) ? (
                                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                            feedback.test_cases.map((tc: any, i: number) => (
                                                <div key={i} className={`rounded-xl border p-4 ${tc.passed
                                                    ? isDark ? 'bg-emerald-500/10 border-emerald-500/20' : 'bg-emerald-50 border-emerald-100'
                                                    : isDark ? 'bg-rose-500/10 border-rose-500/20' : 'bg-rose-50 border-rose-100'
                                                    }`}>
                                                    <div className="flex items-center justify-between mb-2">
                                                        <span className={`text-[10px] font-black   ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Test Case {i + 1}</span>
                                                        <span className={`text-[10px] font-black px-2 py-0.5 rounded   ${tc.passed
                                                            ? isDark ? 'bg-emerald-500/20 text-emerald-400' : 'bg-emerald-100 text-emerald-700'
                                                            : isDark ? 'bg-rose-500/20 text-rose-400' : 'bg-rose-100 text-rose-700'
                                                            }`}>
                                                            {tc.passed ? 'Passed' : 'Failed'}
                                                        </span>
                                                    </div>
                                                    {!tc.passed && tc.message && (
                                                        <p className={`text-xs mt-2 font-mono ${isDark ? 'text-rose-300' : 'text-rose-700'}`}>{tc.message}</p>
                                                    )}
                                                </div>
                                            ))
                                        ) : (
                                            <div className={`p-4 rounded-xl border ${isDark ? 'bg-[#1e1f23] border-[#2d2e32]' : 'bg-white border-slate-200'}`}>
                                                <pre className={`text-xs font-mono whitespace-pre-wrap ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
                                                    {typeof feedback === 'string' ? feedback : JSON.stringify(feedback, null, 2)}
                                                </pre>
                                            </div>
                                        )}
                                        {feedback.suggestions && (
                                            <div className={`mt-4 p-4 rounded-xl text-sm leading-relaxed border ${isDark ? 'bg-indigo-500/10 border-indigo-500/20 text-indigo-300' : 'bg-indigo-50 border-indigo-100 text-indigo-800'}`}>
                                                <div className="flex items-center gap-2 mb-2 font-bold   text-[10px] opacity-70">
                                                    <span className="material-icons-outlined text-sm">lightbulb</span>
                                                    Suggestions
                                                </div>
                                                <ul className="list-disc list-inside space-y-1">
                                                    {Array.isArray(feedback.suggestions) ? feedback.suggestions.map((s: string, i: number) => (
                                                        <li key={i}>{s}</li>
                                                    )) : <li>{String(feedback.suggestions)}</li>}
                                                </ul>
                                            </div>
                                        )}
                                    </div>
                                ) : (
                                    /* INTERACTIVE TEST RUNNER VIEW */
                                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                    testCases?.map((testCase: any, index: number) => {
                                        const testId = `${questionId}_${index}`;
                                        const result = testResults?.[testId];
                                        const isRunning = executingTests?.[testId];
                                        const isExpanded = expandedTests[index];

                                        return (
                                            <div key={index} className={`rounded-xl border transition-all duration-300 overflow-hidden ${isDark ? 'bg-[#1e1f23] border-[#2d2e32]' : 'bg-white border-slate-200'}`}>
                                                <div
                                                    onClick={() => toggleTestExpand(index)}
                                                    className={`p-3 flex items-center justify-between cursor-pointer hover:bg-opacity-80 transition-colors ${isDark ? 'hover:bg-[#25272c]' : 'hover:bg-slate-50'}`}
                                                >
                                                    <div className="flex items-center gap-3">
                                                        {/* Status Icon */}
                                                        <div className={`w-6 h-6 rounded-md flex items-center justify-center border ${isRunning
                                                            ? isDark ? 'bg-amber-500/10 border-amber-500/20 text-amber-500' : 'bg-amber-50 border-amber-200 text-amber-600'
                                                            : result
                                                                ? result.passed
                                                                    ? isDark ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-emerald-50 border-emerald-200 text-emerald-600'
                                                                    : isDark ? 'bg-rose-500/10 border-rose-500/20 text-rose-500' : 'bg-rose-50 border-rose-200 text-rose-600'
                                                                : isDark ? 'bg-[#2d2e32] border-[#3f4147] text-slate-500' : 'bg-slate-100 border-slate-200 text-slate-400'
                                                            }`}>
                                                            {isRunning ? (
                                                                <span className="material-icons-outlined text-[14px] animate-spin">sync</span>
                                                            ) : result ? (
                                                                <span className="material-icons-outlined text-[14px]">{result.passed ? 'check' : 'close'}</span>
                                                            ) : (
                                                                <span className="text-[10px] font-bold">{index + 1}</span>
                                                            )}
                                                        </div>
                                                        <span className={`text-[12px] font-medium ${isDark ? 'text-slate-300' : 'text-slate-700'}`}>
                                                            Test Case {index + 1}
                                                        </span>
                                                    </div>

                                                    <div className="flex items-center gap-3">
                                                        {(!result && !isRunning && onRunTest) && (
                                                            <button
                                                                onClick={(e) => {
                                                                    e.stopPropagation();
                                                                    onRunTest(index);
                                                                }}
                                                                className={`px-3 py-1 rounded-lg text-[10px] font-black   transition-all active:scale-95 ${isDark
                                                                    ? 'bg-indigo-600 text-white hover:bg-indigo-500'
                                                                    : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                                                                    }`}
                                                            >
                                                                Run
                                                            </button>
                                                        )}
                                                        <span className={`material-icons-outlined text-lg transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''} ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>
                                                            expand_more
                                                        </span>
                                                    </div>
                                                </div>

                                                {/* Expanded Details */}
                                                <div className={`transition-all duration-300 ease-in-out border-t overflow-hidden ${isExpanded ? 'max-h-[500px] opacity-100' : 'max-h-0 opacity-0'} ${isDark ? 'border-[#2d2e32] bg-[#111214]' : 'border-slate-100 bg-slate-50/50'}`}>
                                                    <div className="p-4 space-y-4 font-mono text-[11px]">
                                                        <div>
                                                            <span className={` text-[9px] font-black  block mb-1.5 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Input</span>
                                                            <div className={`p-3 rounded-lg border ${isDark ? 'bg-[#1e1f23] border-[#2d2e32] text-slate-300' : 'bg-white border-slate-200 text-slate-600'}`}>
                                                                {testCase.input}
                                                            </div>
                                                        </div>
                                                        {result && !result.passed && (
                                                            <>
                                                                <div>
                                                                    <span className={` text-[9px] font-black  block mb-1.5 text-rose-500`}>Expected Output</span>
                                                                    <div className={`p-3 rounded-lg border ${isDark ? 'bg-rose-500/5 border-rose-500/20 text-rose-400' : 'bg-rose-50 border-rose-100 text-rose-700'}`}>
                                                                        {result.expected}
                                                                    </div>
                                                                </div>
                                                                <div>
                                                                    <span className={` text-[9px] font-black  block mb-1.5 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Actual Output</span>
                                                                    <div className={`p-3 rounded-lg border whitespace-pre-wrap ${isDark ? 'bg-[#1e1f23] border-[#2d2e32] text-slate-300' : 'bg-white border-slate-200 text-slate-600'}`}>
                                                                        {result.actual || <span className="text-slate-500 ">No output</span>}
                                                                    </div>
                                                                </div>
                                                            </>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })
                                )}
                            </div>
                        )}



                        {/* VIEW 3: CUSTOM INPUT */}
                        {activeTab === 'custom_input' && !readOnly && (
                            <div className="space-y-4 h-full flex flex-col">
                                <div className="space-y-2">
                                    <label className={`text-[10px] font-black   ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Input Data</label>
                                    <textarea
                                        value={customInput}
                                        onChange={(e) => onCustomInputChange && onCustomInputChange(e.target.value)}
                                        className={`w-full h-32 rounded-xl border p-4 font-mono text-xs resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all ${isDark
                                            ? 'bg-[#1e1f23] border-[#2d2e32] text-slate-300 placeholder:text-slate-600'
                                            : 'bg-white border-slate-200 text-slate-700 placeholder:text-slate-300'
                                            }`}
                                        placeholder="Enter your custom test input here..."
                                    />
                                </div>

                                <div className="flex items-center justify-end">
                                    <button
                                        onClick={onRunCustomTest}
                                        disabled={!customInput || executingCustomTest}
                                        className={`px-5 py-2.5 rounded-xl text-[11px] font-black   transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${isDark
                                            ? 'bg-indigo-600 text-white hover:bg-indigo-500'
                                            : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg shadow-indigo-200'
                                            }`}
                                    >
                                        {executingCustomTest ? 'Running...' : 'Run Code'}
                                    </button>
                                </div>

                                {customTestResult && (
                                    <div className={`flex-1 rounded-xl border overflow-hidden flex flex-col ${isDark ? 'bg-[#1e1f23] border-[#2d2e32]' : 'bg-white border-slate-200'}`}>
                                        <div className={`px-4 py-2 border-b text-[10px] font-black   flex items-center gap-2 ${customTestResult.status === 'error'
                                            ? isDark ? 'bg-rose-500/10 border-rose-500/20 text-rose-400' : 'bg-rose-50 border-rose-100 text-rose-600'
                                            : isDark ? 'bg-[#25272c] border-[#2d2e32] text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-500'
                                            }`}>
                                            <span>Output</span>
                                        </div>
                                        <div className={`p-4 font-mono text-xs overflow-y-auto whitespace-pre-wrap ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
                                            {customTestResult.actual || customTestResult.message || "Execution finished."}
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div >
        </>
    );
}

"use client";

import React, { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { apiClient, BACKEND_URL } from "@/utils/api";
import { useAuth } from "@/context/AuthContext";

interface EmployeeFormProps {
    employeeId?: string;
    candidateId?: string;
}

interface Department {
    id: string;
    name: string;
}

interface Company {
    id: string;
    name: string;
}

interface Dependent {
    name: string;
    relationship: string;
    date_of_birth?: string;
}

interface EducationDetail {
    degree: string;
    institution: string;
    year_of_passing: string;
}

interface EmergencyContact {
    name: string;
    relationship: string;
    phone: string;
}

interface PaymentInfo {
    bank_name: string;
    account_number: string;
    ifsc_code: string;
}

interface EmployeeFormData {
    employee_id: string;
    first_name: string;
    middle_name: string;
    last_name: string;
    email: string;
    mobile: string;
    phone_number: string;
    designation: string;
    status: string;
    employment_type: string;
    hire_date: string;
    original_hire_date: string;
    probation_end_date: string;
    source: string;
    notice_period: number;
    about_yourself: string;
    pan_card_number: string;
    aadhar_card_number: string;
    passport_number: string;
    date_of_birth: string;
    gender: string;
    marital_status: string;
    blood_group: string;
    address_line_1: string;
    address_line_2: string;
    city: string;
    state: string;
    country: string;
    pincode: string;
    company_id: string;
    department_id: string;
    reporting_to_id: string;
    dependents: Dependent[];
    educational_details: EducationDetail[];
    emergency_contacts: EmergencyContact[];
    social_profiles: Record<string, string>;
    payment_information: PaymentInfo[];
    roles_responsibilities: string;
    skills: string[];
    documents: { name: string; file_path: string }[];
}

export default function EmployeeForm({ employeeId, candidateId }: EmployeeFormProps) {
    const router = useRouter();
    const { token } = useAuth();
    const [activeTab, setActiveTab] = useState("job");
    const [isLoading, setIsLoading] = useState(false);
    const [departments, setDepartments] = useState<Department[]>([]);
    const [companies, setCompanies] = useState<Company[]>([]);
    const [isDeptModalOpen, setIsDeptModalOpen] = useState(false);
    const [newDeptName, setNewDeptName] = useState("");
    
    const [formData, setFormData] = useState<EmployeeFormData>({
        employee_id: "",
        first_name: "",
        middle_name: "",
        last_name: "",
        email: "",
        mobile: "",
        phone_number: "",
        designation: "",
        status: "Active",
        employment_type: "",
        hire_date: "",
        original_hire_date: "",
        probation_end_date: "",
        source: "Direct Sourcing",
        notice_period: 0,
        about_yourself: "",
        pan_card_number: "",
        aadhar_card_number: "",
        passport_number: "",
        date_of_birth: "",
        gender: "",
        marital_status: "",
        blood_group: "",
        address_line_1: "",
        address_line_2: "",
        city: "",
        state: "",
        country: "India",
        pincode: "",
        company_id: "",
        department_id: "",
        reporting_to_id: "",
        dependents: [],
        educational_details: [],
        emergency_contacts: [],
        social_profiles: {},
        payment_information: [],
        roles_responsibilities: "",
        skills: [],
        documents: []
    });

    const fetchEmployeeData = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await apiClient.get(`/api/v1/enterprise/employees/${employeeId}`);
            if (res.ok) {
                const data = await res.json();
                setFormData((prev) => {
                    const sanitized = Object.keys(data).reduce((acc: Record<string, unknown>, key) => {
                        if (data[key] === null) {
                            const defaultVal = Array.isArray(prev[key as keyof EmployeeFormData]) ? [] : "";
                            acc[key] = defaultVal;
                        } else {
                            acc[key] = data[key];
                        }
                        return acc;
                    }, {});
                    return { ...prev, ...sanitized as Partial<EmployeeFormData> };
                });
            }
        } catch (error) {
            console.error("Error fetching employee:", error);
        } finally {
            setIsLoading(false);
        }
    }, [employeeId]);

    const prefillFromCandidate = useCallback(async () => {
        setIsLoading(true);
        try {
            const [candRes, onbRes] = await Promise.all([
                apiClient.get(`/api/v1/enterprise/candidates/${candidateId}`),
                apiClient.get(`/api/v1/enterprise/onboarding/?candidate_id=${candidateId}`)
            ]);
            
            if (candRes.ok) {
                const cand = await candRes.json();
                const onbList = onbRes.ok ? await onbRes.json() : [];
                const onb = onbList[0] || {};
                
                const job_info = onb.job_info || {};
                const personal_info = onb.personal_info || {};
                
                setFormData((prev) => ({
                    ...prev,
                    first_name: personal_info.first_name || cand.full_name?.split(" ")[0] || "",
                    last_name: personal_info.last_name || cand.full_name?.split(" ").slice(1).join(" ") || "",
                    email: cand.email || "",
                    mobile: cand.phone || "",
                    designation: job_info.designation || onb.job_title || "",
                    source: cand.source_platform || "Recruitment",
                    skills: cand.skills || [],
                    company_id: onb.application?.job_requirement?.company_id || "",
                }));
            }
        } catch (error) {
            console.error("Error prefilling candidate:", error);
        } finally {
            setIsLoading(false);
        }
    }, [candidateId]);

    const fetchInitialData = useCallback(async () => {
        try {
            const [deptRes, compRes] = await Promise.all([
                apiClient.get("/api/v1/enterprise/employees/departments"),
                apiClient.get("/api/v1/enterprise/company/")
            ]);
            if (deptRes.ok) setDepartments(await deptRes.json());
            if (compRes.ok) setCompanies(await compRes.json());
        } catch (error) {
            console.error("Error fetching initial data:", error);
        }
    }, []);

    useEffect(() => {
        fetchInitialData();
        if (employeeId) {
            fetchEmployeeData();
        } else if (candidateId) {
            prefillFromCandidate();
        }
    }, [employeeId, candidateId, fetchInitialData, fetchEmployeeData, prefillFromCandidate]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const url = employeeId 
                ? `/api/v1/enterprise/employees/${employeeId}`
                : `/api/v1/enterprise/employees/`;
            const method = employeeId ? "PATCH" : "POST";
            
            const res = await apiClient.request(url, {
                method,
                body: JSON.stringify(formData)
            });
            
            if (res.ok) {
                router.push("/enterprise/employees");
            } else {
                const err = await res.json();
                let errMsg = "Failed to save employee";
                if (err.detail) {
                    if (Array.isArray(err.detail)) {
                        errMsg = err.detail.map((e: { loc?: string[]; msg: string }) => `${e.loc?.slice(-1)[0] || 'Field'}: ${e.msg}`).join('\n');
                    } else {
                        errMsg = err.detail;
                    }
                }
                alert(errMsg);
            }
        } catch (error) {
            console.error("Error saving employee:", error);
            alert("An error occurred");
        } finally {
            setIsLoading(false);
        }
    };

    const handleAddDepartment = async () => {
        if (!newDeptName || !formData.company_id) {
            alert("Please select a company and enter a department name");
            return;
        }
        try {
            const res = await apiClient.request("/api/v1/enterprise/employees/departments", {
                method: "POST",
                body: JSON.stringify({
                    name: newDeptName,
                    company_id: formData.company_id
                })
            });
            if (res.ok) {
                const newDept = await res.json();
                setDepartments(prev => [...prev, newDept]);
                setFormData((prev) => ({ ...prev, department_id: newDept.id }));
                setIsDeptModalOpen(false);
                setNewDeptName("");
            } else {
                const err = await res.json();
                alert(err.detail || "Failed to create department");
            }
        } catch (error) {
            console.error("Error adding department:", error);
        }
    };

    const tabs = [
        { id: "job", label: "Job Information", icon: "work" },
        { id: "personal", label: "Personal Information", icon: "person" },
        { id: "contact", label: "Contact Info", icon: "location_on" },
        { id: "documents", label: "Documents & Others", icon: "folder" },
    ];

    if (isLoading && !formData.first_name) {
        return <div className="p-10 text-center font-bold text-slate-400 animate-pulse">Loading form...</div>;
    }

    return (
        <form onSubmit={handleSubmit} className="p-6 space-y-6 max-w-5xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-2xl font-black text-slate-900 tracking-tight">{employeeId ? "Edit Employee" : "Add New Employee"}</h1>
                    <p className="text-slate-500 text-xs font-semibold mt-1">Fill in all the details to {employeeId ? "update" : "create"} the employee record.</p>
                </div>
                <div className="flex gap-3">
                    <button 
                        type="button"
                        onClick={() => router.back()}
                        className="px-6 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-black text-[10px]   hover:bg-slate-50 transition-all"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit"
                        disabled={isLoading}
                        className="bg-[#7C3AED] text-white px-8 py-2.5 rounded-xl font-black text-[10px]   hover:bg-[#6D28D9] shadow-lg shadow-indigo-100 transition-all active:scale-95 disabled:opacity-50"
                    >
                        {isLoading ? "Saving..." : employeeId ? "Update Employee" : "Create Employee"}
                    </button>
                </div>
            </div>

            {/* Tab Navigation */}
            <div className="flex gap-2 p-1.5 bg-slate-100/50 rounded-2xl w-fit">
                {tabs.map(tab => (
                    <button
                        key={tab.id}
                        type="button"
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-[10px] font-black   transition-all ${
                            activeTab === tab.id 
                            ? "bg-white text-[#7C3AED] shadow-sm" 
                            : "text-slate-400 hover:text-slate-600"
                        }`}
                    >
                        <span className="material-symbols-rounded text-lg">{tab.icon}</span>
                        {tab.label}
                    </button>
                ))}
            </div>

            <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/40 p-10">
                {activeTab === "job" && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Employee ID*</label>
                                <input name="employee_id" value={formData.employee_id} onChange={handleChange} required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" placeholder="EMP-1001" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Designation</label>
                                <input name="designation" value={formData.designation} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" placeholder="Software Engineer" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Employment Type</label>
                                <select name="employment_type" value={formData.employment_type} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all">
                                    <option value="">Select</option>
                                    <option value="Full-time">Full-time</option>
                                    <option value="Part-time">Part-time</option>
                                    <option value="Contract">Contract</option>
                                    <option value="Intern">Intern</option>
                                </select>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Company*</label>
                                <select name="company_id" value={formData.company_id} onChange={handleChange} required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all">
                                    <option value="">Select Company</option>
                                    {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                </select>
                            </div>
                            <div className="space-y-2">
                                <div className="flex items-center justify-between ml-1">
                                    <label className="text-[10px] font-black text-slate-400  ">Department</label>
                                    <button 
                                        type="button" 
                                        onClick={() => setIsDeptModalOpen(true)}
                                        className="text-[9px] font-black text-[#7C3AED]  tracking-tighter hover:underline"
                                    >
                                        + Add New
                                    </button>
                                </div>
                                <select name="department_id" value={formData.department_id} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all">
                                    <option value="">Select Department</option>
                                    {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                </select>
                            </div>
                             <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Status</label>
                                <select name="status" value={formData.status} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all">
                                    <option value="Active">Active</option>
                                    <option value="Inactive">Inactive</option>
                                    <option value="On Leave">On Leave</option>
                                    <option value="Terminated">Terminated</option>
                                </select>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Hire Date</label>
                                <input type="date" name="hire_date" value={formData.hire_date} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Probation End Date</label>
                                <input type="date" name="probation_end_date" value={formData.probation_end_date} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Notice Period (Days)</label>
                                <input type="number" name="notice_period" value={formData.notice_period} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400   ml-1">About Yourself</label>
                            <textarea name="about_yourself" value={formData.about_yourself} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all min-h-[100px]" placeholder="Brief professional summary..." />
                        </div>
                    </div>
                )}

                {activeTab === "personal" && (
                     <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
                         <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">First Name*</label>
                                <input name="first_name" value={formData.first_name} onChange={handleChange} required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Middle Name</label>
                                <input name="middle_name" value={formData.middle_name} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Last Name*</label>
                                <input name="last_name" value={formData.last_name} onChange={handleChange} required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                             <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Email*</label>
                                <input type="email" name="email" value={formData.email} onChange={handleChange} required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Mobile</label>
                                <input name="mobile" value={formData.mobile} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Phone Number</label>
                                <input name="phone_number" value={formData.phone_number} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Date of Birth</label>
                                <input type="date" name="date_of_birth" value={formData.date_of_birth} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all" />
