                )}

                {activeTab === "contact" && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400   ml-1">Address Line 1</label>
