                        </div>
                    </div>
                )}

                {activeTab === "documents" && (
                    <div className="space-y-10 animate-in fade-in slide-in-from-right-4 duration-300">
                         <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400   ml-1">Roles & Responsibilities</label>
                            <textarea name="roles_responsibilities" value={formData.roles_responsibilities} onChange={handleChange} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all min-h-[120px]" placeholder="List key roles and responsibilities..." />
                        </div>

                         <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                            <div className="space-y-4">
                                <h3 className="text-sm font-bold text-slate-800">Skills</h3>
                                <p className="text-[10px] text-slate-500 font-semibold ">Employee skills will be managed here. (Currently viewing as text list)</p>
                                <div className="flex flex-wrap gap-2">
                                    {formData.skills.map((skill: string, idx: number) => (
                                        <span key={idx} className="bg-indigo-50 text-[#7C3AED] px-3 py-1.5 rounded-lg text-[10px] font-bold border border-indigo-100  tracking-tight">{skill}</span>
                                    ))}
                                    {formData.skills.length === 0 && <span className="text-xs text-slate-400">No skills added.</span>}
                                </div>
                            </div>
                            <div className="space-y-4">
                                <h3 className="text-sm font-bold text-slate-800">Documents</h3>
                                <p className="text-[10px] text-slate-500 font-semibold  md:pr-4 leading-relaxed">Onboarding documents and related details are managed entirely through the Candidate Onboarding Portal. Records here are read-only references synced securely from their onboarding session.</p>
                                <div className="space-y-2">
                                    {formData.documents.map((doc, idx) => (
                                        <a key={idx} href={doc.file_path} target="_blank" className="flex items-center justify-between p-3 bg-slate-50 rounded-xl hover:bg-white hover:shadow-sm border border-slate-200 transition-all">
                                            <span className="text-[11px] font-bold text-slate-600">{doc.name}</span>
                                            <span className="material-symbols-rounded text-lg text-slate-400">download</span>
                                        </a>
                                    ))}
                                    {formData.documents.length === 0 && <span className="text-xs text-slate-400">No documents found.</span>}
                                </div>
                            </div>
                        </div>

                        <div className="bg-slate-50 rounded-[32px] p-8 space-y-4 border border-slate-100">
                             <h3 className="text-xs font-black text-slate-400  ">Other Records</h3>
                             <p className="text-[10px] text-slate-500 font-semibold">Dependents, Education, Emergency Contacts, and Payment Info are currently stored as encrypted JSON data.</p>
                             <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                                 <div className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm text-center">
                                     <p className="text-[10px] font-black text-slate-400   mb-1">Dependents</p>
                                     <p className="text-sm font-black text-[#7C3AED]">{formData.dependents.length}</p>
                                 </div>
                                 <div className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm text-center">
                                     <p className="text-[10px] font-black text-slate-400   mb-1">Education</p>
                                     <p className="text-sm font-black text-[#7C3AED]">{formData.educational_details.length}</p>
                                 </div>
                                 <div className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm text-center">
                                     <p className="text-[10px] font-black text-slate-400   mb-1">Emergency</p>
                                     <p className="text-sm font-black text-[#7C3AED]">{formData.emergency_contacts.length}</p>
                                 </div>
                                 <div className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm text-center">
                                     <p className="text-[10px] font-black text-slate-400   mb-1">Payment info</p>
                                     <p className="text-sm font-black text-emerald-600">{formData.payment_information.length > 0 ? "Linked" : "Missing"}</p>
                                 </div>
                             </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Department Modal */}
            {isDeptModalOpen && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300">
                    <div className="bg-white rounded-[2.5rem] p-10 w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200 border border-slate-100">
                        <div className="mb-8">
                            <h3 className="text-xl font-black text-slate-900 tracking-tight  ">Add Department Node</h3>
                            <p className="text-[10px] font-black text-slate-400   mt-1">Hierarchical Synchronization</p>
                        </div>
                        <div className="space-y-8">
                            <div className="space-y-2 group">
                                <label className="text-[10px] font-black text-slate-400   ml-1 group-focus-within:text-slate-900 transition-colors">Department Designation</label>
                                <input 
                                    value={newDeptName}
                                    onChange={(e) => setNewDeptName(e.target.value)}
                                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm font-black outline-none focus:border-[#0F172A] focus:bg-white transition-all shadow-inner"
                                    placeholder="E.G. TECHNICAL OPERATIONS"
                                />
                            </div>
                            <div className="flex gap-4">
                                <button 
                                    type="button"
                                    onClick={() => setIsDeptModalOpen(false)}
                                    className="flex-1 px-6 py-4 rounded-2xl border border-slate-200 text-slate-400 font-black text-[10px]  tracking-[0.2em] hover:bg-slate-50 hover:text-slate-900 transition-all active:scale-95"
                                >
                                    Cancel
                                </button>
                                <button 
                                    type="button"
                                    onClick={handleAddDepartment}
                                    className="flex-1 bg-[#0F172A] text-white px-6 py-4 rounded-2xl font-black text-[10px]  tracking-[0.2em] hover:bg-slate-800 shadow-xl shadow-slate-200 transition-all active:scale-95"
                                >
                                    Sync Node
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </form>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { BACKEND_URL } from "@/utils/api";
import { useAuth } from "@/context/AuthContext";
import { motion, AnimatePresence } from "framer-motion";
import { useRouter } from "next/navigation";

interface OnboardingField {
    name: string;
    label: string;
    type: "text" | "number" | "date" | "select" | "email" | "phone" | "file";
    required: boolean;
    options?: string[];
}

interface Section {
    id: string;
    title: string;
    fields: OnboardingField[];
}

interface OnboardingTemplate {
    id: string;
    name: string;
    description?: string;
    sections: string[];
    form_config: { sections: Section[] };
}

interface OnboardingTemplateFormProps {
    template?: OnboardingTemplate | null;
}

export default function OnboardingTemplateForm({ template }: OnboardingTemplateFormProps) {
    const router = useRouter();
    const { token, canAccess } = useAuth();

    // Form State
    const [name, setName] = useState("");
    const [description, setDescription] = useState("");
    const [sections, setSections] = useState<Section[]>([]);
    const [newSectionTitle, setNewSectionTitle] = useState("");

    // Field Builder State
    const [activeSectionId, setActiveSectionId] = useState<string | null>(null);
    const [newFieldName, setNewFieldName] = useState("");
    const [newFieldLabel, setNewFieldLabel] = useState("");
    const [newFieldType, setNewFieldType] = useState<OnboardingField["type"]>("text");
    const [newFieldRequired, setNewFieldRequired] = useState(false);
    const [newFieldOptions, setNewFieldOptions] = useState("");

    useEffect(() => {
        if (template) {
            setTimeout(() => {
                setName(template.name);
                setDescription(template.description || "");
                setSections(template.form_config?.sections || []);
                if (template.form_config?.sections?.length > 0) {
                    setActiveSectionId(template.form_config.sections[0].id);
                }
            }, 0);
        }
    }, [template]);

    const handleSave = async () => {
        if (!name) return alert("Template name is required");
        if (sections.length === 0) return alert("At least one section is required");

        const payload = {
            name,
            description,
            sections: sections.map(s => s.id),
            form_config: { sections }
        };

        const url = template 
            ? `${BACKEND_URL}/api/v1/enterprise/onboarding/templates/${template.id}`
            : `${BACKEND_URL}/api/v1/enterprise/onboarding/templates/`;
        
        try {
            const res = await fetch(url, {
                method: template ? "PUT" : "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                router.push("/enterprise/settings/onboarding-templates");
            } else {
                const err = await res.json();
                alert(err.detail || "Failed to save template");
            }
        } catch (error) {
            console.error("Error saving template:", error);
        }
    };

    const addSection = () => {
        if (!newSectionTitle.trim()) {
            alert("Please enter a section title first.");
            return;
        }
        const newSec: Section = {
            id: `sec_${Date.now()}`,
            title: newSectionTitle.trim(),
            fields: []
        };
        setSections([...sections, newSec]);
        setNewSectionTitle("");
        setActiveSectionId(newSec.id);
    };

    const removeSection = (id: string) => {
        setSections(sections.filter(s => s.id !== id));
        if (activeSectionId === id) setActiveSectionId(null);
    };

    const addField = () => {
        if (!activeSectionId) {
            alert("Please select or create a section first.");
            return;
        }
        if (!newFieldLabel.trim()) {
            alert("Field label is required.");
            return;
        }

        const fieldIdentifier = newFieldName.trim() || newFieldLabel.trim().toLowerCase().replace(/\s+/g, "_");
        
        const newField: OnboardingField = {
            name: fieldIdentifier,
            label: newFieldLabel.trim(),
            type: newFieldType,
            required: newFieldRequired,
            options: newFieldType === "select" ? newFieldOptions.split(",").map(o => o.trim()).filter(Boolean) : undefined
        };

        setSections(sections.map(s => s.id === activeSectionId ? { ...s, fields: [...s.fields, newField] } : s));

        setNewFieldName("");
        setNewFieldLabel("");
        setNewFieldType("text");
        setNewFieldRequired(false);
        setNewFieldOptions("");
    };

    const removeField = (sectionId: string, index: number) => {
        setSections(sections.map(s => s.id === sectionId ? { ...s, fields: s.fields.filter((_, i) => i !== index) } : s));
    };

    return (
        <div className="animate-in fade-in duration-500">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                <div className="lg:col-span-1 space-y-10">
                    {/* Basic Info */}
                    <div className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400   ml-1">Template Name</label>
                            <input 
                                type="text" 
                                className="w-full bg-slate-50 border border-slate-100 rounded-[20px] px-6 py-4 text-slate-900 font-bold text-sm outline-none focus:border-indigo-500 focus:bg-white transition-all shadow-sm"
                                placeholder="e.g. Executive Onboarding"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                readOnly={!canAccess("onboarding:moderate")}
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400   ml-1">Overall Description</label>
                            <textarea 
                                className="w-full bg-slate-50 border border-slate-100 rounded-[20px] px-6 py-4 text-slate-900 font-bold text-sm outline-none focus:border-indigo-500 focus:bg-white transition-all shadow-sm min-h-[120px]"
                                placeholder="Purpose of this flow..."
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                readOnly={!canAccess("onboarding:moderate")}
                            />
                        </div>
                    </div>

                    {/* Section Management */}
                    <div className="space-y-6">
                        <label className="text-[10px] font-black text-slate-400   ml-1 block">Define Sections</label>
                        <div className="space-y-3">
                            {sections.map((s, idx) => (
                                <div 
                                    key={s.id}
                                    onClick={() => setActiveSectionId(s.id)}
                                    className={`group flex items-center justify-between p-5 rounded-[24px] border transition-all cursor-pointer ${activeSectionId === s.id ? "bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-200" : "bg-white border-slate-100 text-slate-600 hover:border-indigo-200 hover:bg-indigo-50/30"}`}
                                >
                                    <div className="flex items-center gap-4">
                                        <span className="text-xs font-black opacity-40">{idx + 1}</span>
                                        <span className="text-sm font-black">{s.title}</span>
                                    </div>
                                     {canAccess("onboarding:moderate") && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); removeSection(s.id); }}
                                            className={`p-2 rounded-lg transition-colors ${activeSectionId === s.id ? "hover:bg-indigo-500 text-indigo-200 hover:text-white" : "hover:bg-red-50 text-slate-300 hover:text-red-500"}`}
                                        >
                                            <span className="material-icons-outlined text-lg">delete</span>
                                        </button>
                                    )}
                                </div>
                            ))}
                        </div>
                         {canAccess("onboarding:moderate") && (
                            <div className="pt-4 flex gap-3">
                                <input 
                                    type="text" 
                                    className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-5 py-3 text-sm font-bold outline-none focus:border-indigo-500"
                                    placeholder="New Section Title..."
                                    value={newSectionTitle}
                                    onChange={(e) => setNewSectionTitle(e.target.value)}
                                    onKeyPress={(e) => e.key === 'Enter' && addSection()}
                                />
                                <button 
                                    onClick={addSection}
                                    className="w-12 h-12 bg-slate-900 text-white rounded-xl flex items-center justify-center hover:bg-black transition-all"
                                >
                                    <span className="material-icons-outlined">add</span>
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Field Builder Column */}
                <div className="lg:col-span-2 bg-slate-50 rounded-[48px] p-10 border border-slate-100 min-h-[500px]">
                    {activeSectionId ? (
                        <motion.div 
                            key={activeSectionId} 
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="space-y-10"
                        >
                            <div className="flex justify-between items-center">
                                <div>
                                    <h4 className="text-2xl font-black text-slate-900 tracking-tight">
                                        {sections.find(s => s.id === activeSectionId)?.title}
                                    </h4>
                                    <p className="text-slate-500 text-xs font-medium mt-1">Configure fields for this section.</p>
                                </div>
                                <span className="px-4 py-2 bg-indigo-100 text-indigo-600 rounded-xl text-[10px] font-black  ">
                                    {(sections.find(s => s.id === activeSectionId)?.fields || []).length} Fields
                                </span>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {(sections.find(s => s.id === activeSectionId)?.fields || []).map((field, idx) => (
                                    <div key={idx} className="p-6 bg-white rounded-[28px] border border-slate-100 flex items-center justify-between group/field shadow-sm hover:shadow-md transition-all">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 group-hover/field:bg-indigo-50 group-hover/field:text-indigo-600 transition-colors">
                                                <span className="material-icons-outlined text-lg">
                                                    {field.type === "text" ? "input" : field.type === "date" ? "event" : field.type === "select" ? "list" : field.type === "file" ? "upload_file" : "contact_phone"}
                                                </span>
                                            </div>
                                            <div>
                                                <p className="text-sm font-black text-slate-800">{field.label}</p>
                                                <p className="text-[9px] font-black text-slate-400  ">{field.type} • {field.required ? "Required" : "Optional"}</p>
                                            </div>
                                        </div>
                                         {canAccess("onboarding:moderate") && (
                                            <button 
                                                onClick={() => removeField(activeSectionId, idx)}
                                                className="opacity-0 group-hover/field:opacity-100 p-2 text-red-500 hover:bg-red-50 rounded-lg transition-all"
                                            >
                                                <span className="material-icons-outlined text-lg">close</span>
                                            </button>
                                        )}
                                    </div>
                                ))}
                            </div>

                             {/* Add New Field Box */}
                            {canAccess("onboarding:moderate") && (
                                <div className="bg-white p-8 rounded-[36px] border border-slate-200 shadow-xl shadow-slate-200/40 space-y-6">
                                    <h5 className="text-xs font-black   text-slate-400">Add New Field</h5>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        <div className="space-y-2">
                                            <label className="text-[9px] font-black text-slate-500   ml-1">Field Label (Display)</label>
                                            <input 
                                                type="text" 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 text-xs font-bold focus:border-indigo-500 outline-none"
                                                placeholder="e.g. Your Mobile Number"
                                                value={newFieldLabel}
                                                onChange={(e) => {
                                                    setNewFieldLabel(e.target.value);
                                                    if (!newFieldName) {
                                                        setNewFieldName(e.target.value.toLowerCase().replace(/\s+/g, "_"));
                                                    }
                                                }}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[9px] font-black text-slate-500   ml-1">Field Type</label>
                                            <select 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 text-xs font-bold focus:border-indigo-500 outline-none"
                                                value={newFieldType}
                                                onChange={(e) => setNewFieldType(e.target.value as any)}
                                            >
                                                <option value="text">Text Input</option>
                                                <option value="email">Email Address</option>
                                                <option value="phone">Phone Number</option>
                                                <option value="number">Number</option>
                                                <option value="date">Date Picker</option>
                                                <option value="select">Dropdown (Select)</option>
                                                <option value="file">File Upload</option>
                                            </select>
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[9px] font-black text-slate-500   ml-1">Unique Identifier</label>
                                            <input 
                                                type="text" 
                                                className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 text-xs font-bold focus:border-indigo-500 outline-none"
                                                placeholder="e.g. mobile_number"
                                                value={newFieldName}
                                                onChange={(e) => setNewFieldName(e.target.value)}
                                            />
                                        </div>
                                        {newFieldType === "select" && (
                                            <div className="space-y-2">
                                                <label className="text-[9px] font-black text-slate-500   ml-1">Options (Comma Separated)</label>
                                                <input 
                                                    type="text" 
                                                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 text-xs font-bold focus:border-indigo-500 outline-none"
                                                    placeholder="e.g. Option 1, Option 2, Option 3"
                                                    value={newFieldOptions}
                                                    onChange={(e) => setNewFieldOptions(e.target.value)}
                                                />
                                            </div>
                                        )}
                                        <div className="flex items-end pb-1 gap-3">
                                            <div 
                                                onClick={() => setNewFieldRequired(!newFieldRequired)}
                                                className={`flex items-center gap-3 cursor-pointer p-3 rounded-xl border transition-all ${newFieldRequired ? "bg-indigo-50 border-indigo-200 text-indigo-700" : "bg-white border-slate-100 text-slate-400"}`}
                                            >
                                                <span className="material-icons-outlined text-lg">{newFieldRequired ? "check_box" : "check_box_outline_blank"}</span>
                                                <span className="text-[10px] font-black  ">Mark as Required</span>
                                            </div>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={addField}
                                        className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px]   hover:bg-black transition-all shadow-lg"
                                    >
                                        Add Field to {sections.find(s => s.id === activeSectionId)?.title}
                                    </button>
                                </div>
                            )}
                        </motion.div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-center p-10 space-y-6">
                            <div className="w-24 h-24 bg-white rounded-[32px] flex items-center justify-center shadow-xl shadow-slate-200">
                                <span className="material-icons-outlined text-5xl text-indigo-500 animate-pulse">layers</span>
                            </div>
                            <div>
                                <h4 className="text-xl font-black text-slate-900">Select a Section</h4>
                                <p className="text-slate-500 text-xs font-medium max-w-[240px] mx-auto mt-2 leading-relaxed">
                                    Add or select a section from the left column to start building your custom form.
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="mt-12 flex gap-4">
                <button 
                    onClick={() => router.push("/enterprise/settings/onboarding-templates")}
                    className="px-8 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-black text-xs   transition-all"
                >
                    Cancel
                </button>
                {canAccess("onboarding:moderate") && (
                    <button 
                        onClick={handleSave}
                        className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-xs   transition-all shadow-2xl shadow-indigo-500/40"
                    >
                        {template ? "Update Template" : "Save Template"}
                    </button>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/utils/api";
import ProjectKanban from "./ProjectKanban";
import { Reorder } from "framer-motion";

interface Employee {
    id: string;
    first_name: string;
    last_name: string;
    designation?: string;
}

interface Company {
    id: string;
    name: string;
}

interface Task {
    id: string;
    title: string;
    description: string;
    column: string;
    status: string;
    due_date?: string | null;
    assignee?: Employee;
    employee_id?: string | null;
}

interface ProjectData {
    id?: string;
    name: string;
    description: string;
    status: string;
    start_date: string;
    end_date: string;
    company_id: string;
    members: Employee[];
    tasks: Task[];
    kanban_columns: string[];
}

interface ProjectFormProps {
    projectId?: string;
    initialData?: ProjectData;
}

export default function ProjectForm({ projectId, initialData }: ProjectFormProps) {
    const router = useRouter();
    const { token } = useAuth();
    const [isLoading, setIsLoading] = useState(false);
    const [activeTab, setActiveTab] = useState("basic");
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [companies, setCompanies] = useState<Company[]>([]);
    
    const [formData, setFormData] = useState<ProjectData>({
        name: "",
        description: "",
        status: "Active",
        start_date: "",
        end_date: "",
        company_id: "",
        members: [],
        tasks: [],
        kanban_columns: ["Planning", "Development", "Testing", "Done"]
    });

    const [newColumnName, setNewColumnName] = useState("");

    useEffect(() => {
        if (initialData) {
            setFormData({
                ...initialData,
                start_date: initialData.start_date ? initialData.start_date.split('T')[0] : "",
                end_date: initialData.end_date ? initialData.end_date.split('T')[0] : "",
                kanban_columns: initialData.kanban_columns || ["Planning", "Development", "Testing", "Done"]
            });
        }
    }, [initialData]);

    const fetchProjectData = async () => {
        if (!projectId) return;
        try {
            const res = await apiClient.get(`/api/v1/enterprise/projects/${projectId}`);
            if (res.ok) {
                const data = await res.json();
                setFormData({
                    ...data,
                    start_date: data.start_date ? data.start_date.split('T')[0] : "",
                    end_date: data.end_date ? data.end_date.split('T')[0] : "",
                });
            }
        } catch (e) { console.error(e); }
    };

    useEffect(() => {
        fetchCompanies();
        fetchEmployees();
    }, []);

    const fetchCompanies = async () => {
        try {
            const res = await apiClient.get("/api/v1/enterprise/company/");
            if (res.ok) setCompanies(await res.json());
        } catch (e) { console.error(e); }
    };

    const fetchEmployees = async () => {
        try {
            const res = await apiClient.get("/api/v1/enterprise/employees/");
            if (res.ok) setEmployees(await res.json());
        } catch (e) { console.error(e); }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const url = projectId ? `/api/v1/enterprise/projects/${projectId}` : "/api/v1/enterprise/projects/";
            const method = projectId ? "PATCH" : "POST";
            
            const res = await apiClient.request(url, {
                method,
                body: JSON.stringify({
                    name: formData.name,
                    description: formData.description,
                    status: formData.status,
                    start_date: formData.start_date || null,
                    end_date: formData.end_date || null,
                    company_id: formData.company_id,
                    kanban_columns: formData.kanban_columns
                })
            });

            if (res.ok) {
                const data = await res.json();
                if (!projectId) {
                    router.push(`/enterprise/projects/${data.id}`);
                } else {
                    fetchProjectData();
                    alert("Project updated successfully!");
                    router.push("/enterprise/projects");
                }
            } else {
                const err = await res.json();
                alert(err.detail || "Something went wrong");
            }
        } catch (error) {
            console.error("Error saving project:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleAddMember = async (employeeId: string) => {
        if (!projectId) {
            alert("Please save the project basics first before adding members.");
            return;
        }
        try {
            const res = await apiClient.request(`/api/v1/enterprise/projects/${projectId}/members`, {
                method: "POST",
                body: JSON.stringify({ employee_id: employeeId })
            });
            if (res.ok) {
                const updated = await res.json();
                setFormData(updated);
            }
        } catch (e) { console.error(e); }
    };

    const handleRemoveMember = async (employeeId: string) => {
        try {
            const res = await apiClient.delete(`/api/v1/enterprise/projects/${projectId}/members/${employeeId}`);
            if (res.ok) {
                const updated = await res.json();
                setFormData(updated);
            }
        } catch (e) { console.error(e); }
    };

    const handleAddColumn = () => {
        if (!newColumnName.trim()) return;
        if (formData.kanban_columns.includes(newColumnName.trim())) {
            alert("Column already exists");
            return;
        }
        setFormData((prev) => ({
            ...prev,
            kanban_columns: [...prev.kanban_columns, newColumnName.trim()]
        }));
        setNewColumnName("");
    };

    const handleRemoveColumn = (col: string) => {
        if (formData.tasks.some((t) => t.column === col)) {
            alert("Cannot remove column while it has tasks. Move or delete tasks first.");
            return;
        }
        setFormData((prev) => ({
            ...prev,
            kanban_columns: prev.kanban_columns.filter((c: string) => c !== col)
        }));
    };

    return (
        <div className="p-6 space-y-6 max-w-7xl mx-auto pb-20">
            <div className="flex items-center justify-between mb-2">
                <div>
                    <h2 className="text-2xl font-black text-slate-900 tracking-tight">
                        {projectId ? "Project Console" : "New Project"}
                    </h2>
                    <p className="text-xs font-bold text-slate-400  ">
                        {projectId ? formData.name : "Fill in the basic project information"}
                    </p>
                </div>
                <div className="flex gap-2">
                    <button
                        onClick={handleSubmit}
                        disabled={isLoading}
                        className="bg-[#7C3AED] text-white px-8 py-3 rounded-2xl font-black text-[11px]   hover:bg-[#6D28D9] shadow-xl shadow-indigo-100 transition-all flex items-center gap-2 active:scale-95 disabled:opacity-50"
                    >
                        {isLoading ? "Saving..." : projectId ? "Save Changes" : "Create Project"}
                    </button>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex gap-4 p-1.5 bg-slate-100/50 rounded-2xl w-fit">
                <button
                    type="button"
                    onClick={() => setActiveTab("basic")}
                    className={`px-6 py-2.5 rounded-xl font-black text-[10px]   transition-all ${
                        activeTab === "basic" ? "bg-white text-[#7C3AED] shadow-sm" : "text-slate-500 hover:text-slate-700"
                    }`}
                >Settings</button>
                <button
                    type="button"
                    onClick={() => setActiveTab("members")}
                    className={`px-6 py-2.5 rounded-xl font-black text-[10px]   transition-all ${
                        activeTab === "members" ? "bg-white text-[#7C3AED] shadow-sm" : "text-slate-500 hover:text-slate-700"
                    }`}
                >Team</button>
                {projectId && (
                    <button
                        type="button"
                        onClick={() => setActiveTab("tasks")}
                        className={`px-6 py-2.5 rounded-xl font-black text-[10px]   transition-all ${
                            activeTab === "tasks" ? "bg-white text-[#7C3AED] shadow-sm" : "text-slate-500 hover:text-slate-700"
                        }`}
                    >Tasks & Board</button>
                )}
            </div>

            <div className="bg-white rounded-[20px] p-10 border border-slate-100 shadow-sm border-t-4 border-t-[#7C3AED] animate-in fade-in slide-in-from-bottom-4 duration-500 min-h-[600px]">
                {activeTab === "basic" && (
                    <div className="space-y-10 animate-in fade-in zoom-in-95 duration-300">
                        {/* Basic Info Section */}
                        <div className="space-y-6">
                            <h4 className="text-[10px] font-black text-slate-400   ml-1 bg-slate-50 w-fit px-3 py-1 rounded-full">General Information</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">Project Name*</label>
                                    <input
                                        name="name"
                                        value={formData.name}
                                        onChange={handleChange}
                                        required
                                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all"
                                        placeholder="Enter project name"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">Company*</label>
                                    <select
                                        name="company_id"
                                        value={formData.company_id}
                                        onChange={handleChange}
                                        required
                                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all"
                                    >
                                        <option value="">Select Company</option>
                                        {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                    </select>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400   ml-1">Description</label>
                                <textarea
                                    name="description"
                                    value={formData.description}
                                    onChange={handleChange}
                                    rows={3}
                                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all resize-none"
                                    placeholder="Describe the project goals..."
                                />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">Status</label>
                                    <select
                                        name="status"
                                        value={formData.status}
                                        onChange={handleChange}
                                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all"
                                    >
                                        <option value="Active">Active</option>
                                        <option value="Completed">Completed</option>
                                        <option value="On Hold">On Hold</option>
                                    </select>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">Start Date</label>
                                    <input
                                        type="date"
                                        name="start_date"
                                        value={formData.start_date}
                                        onChange={handleChange}
                                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-slate-400   ml-1">End Date</label>
                                    <input
                                        type="date"
                                        name="end_date"
                                        value={formData.end_date}
                                        onChange={handleChange}
                                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-sm font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all"
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Kanban Workflow Configuration */}
                        <div className="space-y-6 pt-6 border-t border-slate-100">
                            <div>
                                <h4 className="text-[10px] font-black text-slate-400   ml-1 bg-slate-50 w-fit px-3 py-1 rounded-full">Kanban Workflow</h4>
                                <p className="text-[10px] text-slate-400 font-bold ml-1 mt-1">Define the custom stages for your project&apos;s task board.</p>
                            </div>
                            <div className="flex flex-wrap gap-3">
                                <Reorder.Group 
                                    axis="x" 
                                    values={formData.kanban_columns} 
                                    onReorder={(newOrder) => setFormData((prev) => ({ ...prev, kanban_columns: newOrder }))}
                                    className="flex flex-wrap gap-3"
                                >
                                    {formData.kanban_columns?.map((col: string, idx: number) => (
                                        <Reorder.Item 
                                            key={col} 
                                            value={col}
                                            className="flex items-center gap-2 bg-indigo-50/50 border border-indigo-100/50 px-4 py-2 rounded-xl group cursor-grab active:cursor-grabbing hover:bg-indigo-100/50 transition-colors animate-in fade-in slide-in-from-left-2 duration-300"
                                            style={{ animationDelay: `${idx * 50}ms` }}
                                        >
                                            <span className="material-symbols-rounded text-slate-400 text-sm">drag_indicator</span>
                                            <span className="text-xs font-black text-indigo-600  ">{col}</span>
                                            <button 
                                                type="button" 
                                                onClick={() => handleRemoveColumn(col)}
                                                className="text-indigo-300 hover:text-rose-500 transition-colors"
                                            >
                                                <span className="material-symbols-rounded text-base font-black">close</span>
                                            </button>
                                        </Reorder.Item>
                                    ))}
                                </Reorder.Group>
                                <div className="flex gap-2">
                                    <input
                                        value={newColumnName}
                                        onChange={(e) => setNewColumnName(e.target.value)}
                                        onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddColumn())}
                                        placeholder="Add new stage..."
                                        className="bg-slate-50 border border-dashed border-slate-200 rounded-xl px-4 py-2 text-xs font-bold outline-none focus:border-[#7C3AED] focus:bg-white transition-all w-40"
                                    />
                                    <button
                                        type="button"
                                        onClick={handleAddColumn}
                                        className="w-10 h-10 rounded-xl bg-slate-100 text-slate-400 hover:bg-[#7C3AED] hover:text-white transition-all flex items-center justify-center"
                                    >
                                        <span className="material-symbols-rounded">add</span>
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === "members" && (
                    <div className="space-y-8 animate-in fade-in zoom-in-95 duration-300">
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                            {/* Current Members */}
                            <div className="space-y-4">
                                <h4 className="text-[10px] font-black text-slate-400   ml-1 bg-slate-50 w-fit px-3 py-1 rounded-full">Project Team</h4>
                                <div className="grid gap-3">
                                    {(formData.members || []).length === 0 ? (
                                        <div className="p-10 border-2 border-dashed border-slate-100 rounded-[20px] text-center">
                                            <p className="text-xs font-bold text-slate-400">No members assigned yet.</p>
                                        </div>
                                    ) : (
                                        formData.members.map((m) => (
                                            <div key={m.id} className="flex items-center justify-between p-4 bg-slate-50/50 rounded-2xl border border-slate-100 animate-in fade-in slide-in-from-bottom-2 duration-300">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-full bg-slate-900 text-white flex items-center justify-center font-black text-xs  shadow-sm uppercase">
                                                        {m.first_name[0]}{m.last_name[0]}
                                                    </div>
                                                    <div>
                                                        <p className="text-sm font-black text-slate-800 tracking-tight capitalize">{m.first_name} {m.last_name}</p>
                                                        <p className="text-[9px] font-black text-slate-400  ">{m.designation || "Project Member"}</p>
                                                    </div>
                                                </div>
                                                <button 
                                                    type="button"
                                                    onClick={() => handleRemoveMember(m.id)}
                                                    className="w-9 h-9 rounded-xl text-slate-300 hover:text-rose-500 hover:bg-rose-50 transition-all flex items-center justify-center"
                                                >
                                                    <span className="material-symbols-rounded text-xl">delete</span>
                                                </button>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>

                            {/* Add Members */}
                            <div className="space-y-4">
                                <h4 className="text-[10px] font-black text-slate-400   ml-1 bg-slate-50 w-fit px-3 py-1 rounded-full">Assign Talent</h4>
                                <div className="max-h-[500px] overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                                    {employees
                                        .filter(emp => !(formData.members || []).some((m) => m.id === emp.id))
                                        .map((emp) => (
                                            <div key={emp.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl hover:border-[#7C3AED]/20 hover:bg-slate-50/50 transition-all group">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-full bg-slate-100 text-slate-400 group-hover:bg-[#7C3AED]/10 group-hover:text-[#7C3AED] flex items-center justify-center font-black text-xs  transition-all shadow-sm uppercase">
                                                        {emp.first_name[0]}{emp.last_name[0]}
                                                    </div>
                                                    <div>
                                                        <p className="text-sm font-black text-slate-800 tracking-tight capitalize">{emp.first_name} {emp.last_name}</p>
                                                        <p className="text-[9px] font-black text-slate-400  ">{emp.designation || "Available"}</p>
                                                    </div>
                                                </div>
                                                <button 
                                                    type="button"
                                                    onClick={() => handleAddMember(emp.id)}
                                                    className="px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-[9px] font-black   text-slate-500 hover:text-[#7C3AED] hover:border-[#7C3AED] hover:bg-white transition-all shadow-sm"
                                                >
                                                    Assign
                                                </button>
                                            </div>
                                        ))
                                    }
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === "tasks" && (
                    <div className="animate-in fade-in slide-in-from-right-4 duration-500">
                        <ProjectKanban 
                            projectId={projectId!}
                            columns={formData.kanban_columns}
                            tasks={formData.tasks || []}
                            members={formData.members || []}
                            onRefresh={fetchProjectData}
                        />
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { BACKEND_URL } from "@/utils/api";

interface AssessmentTemplate {
    id: string;
    name: string;
    type: string;
    topic: string;
    question_count: number;
    email_template_id?: string;
    email_template_name?: string;
}

interface SendAssessmentModalProps {
    isOpen: boolean;
    onClose: () => void;
    applicationIds: string[];
    token: string;
}

export default function SendAssessmentModal({ isOpen, onClose, applicationIds, token }: SendAssessmentModalProps) {
    const [templates, setTemplates] = useState<AssessmentTemplate[]>([]);
    const [selectedTemplateId, setSelectedTemplateId] = useState<string>("");
    const [isLoading, setIsLoading] = useState(false);
    const [isSending, setIsSending] = useState(false);

    useEffect(() => {
        if (isOpen && token) {
            fetchTemplates();
        }
    }, [isOpen, token]);

    const fetchTemplates = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/assessment-templates/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setTemplates(data);
                if (data.length > 0) {
                    setSelectedTemplateId(data[0].id);
                }
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSend = async () => {
        if (!selectedTemplateId) return;
        setIsSending(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/assessment-templates/bulk-send`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify({
                    application_ids: applicationIds,
                    template_id: selectedTemplateId
                })
            });

            if (res.ok) {
                alert("Assessment sent successfully!");
                onClose();
            } else {
                alert("Failed to send assessment.");
            }
        } catch (e) {
            console.error(e);
            alert("Error sending assessment.");
        } finally {
            setIsSending(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4" onClick={onClose}>
            <motion.div
                initial={{ scale: 0.95, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.95, opacity: 0 }}
                className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden"
                onClick={e => e.stopPropagation()}
            >
                <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h2 className="text-lg font-black text-slate-800 tracking-tight flex items-center gap-2">
                        <span className="material-icons text-indigo-600">psychology</span>
                        SEND ASSESSMENT
                    </h2>
                    <button onClick={onClose} className="w-8 h-8 rounded-full hover:bg-slate-200/50 flex items-center justify-center text-slate-400">
                        <span className="material-icons-outlined">close</span>
                    </button>
                </div>

                <div className="p-6">
                    <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl mb-6">
                        <p className="text-xs font-bold text-indigo-900 leading-relaxed">
                            Sending assessment to <span className="text-indigo-600">{applicationIds.length} candidate(s)</span>. 
                            They will receive an email with the test link.
                        </p>
                    </div>

                    <label className="block text-[10px] font-black   text-slate-500 mb-2">Select Assessment Template</label>
                    {isLoading ? (
                        <div className="py-4 flex justify-center">
                            <div className="w-6 h-6 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                        </div>
                    ) : templates.length === 0 ? (
                        <div className="py-4 text-center">
                            <p className="text-sm text-slate-400 font-medium">No templates found. Go to settings to create one.</p>
                        </div>
                    ) : (
                        <div className="space-y-3 max-h-60 overflow-y-auto pr-2">
                            {templates.map(template => (
                                <div
                                    key={template.id}
                                    onClick={() => setSelectedTemplateId(template.id)}
                                    className={`p-4 rounded-xl border-2 transition-all cursor-pointer ${
                                        selectedTemplateId === template.id
                                            ? "border-indigo-600 bg-indigo-50/50"
                                            : "border-slate-100 hover:border-slate-200"
                                    }`}
                                >
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{template.name}</h4>
                                            <p className="text-[10px] font-bold text-slate-400   mt-0.5">
                                                {template.type} • {template.topic}
                                            </p>
                                        </div>
                                        {selectedTemplateId === template.id && (
                                            <span className="material-icons text-indigo-600 text-sm">check_circle</span>
                                        )}
                                    </div>
                                    <div className="mt-3 flex flex-wrap gap-2">
                                        <div className="flex items-center gap-1 text-[10px] font-bold text-slate-500 bg-white border border-slate-100 px-2 py-0.5 rounded">
                                            <span className="material-icons text-[12px]">list</span>
                                            {template.question_count} Qs
                                        </div>
                                        {template.email_template_name && (
                                            <div className="flex items-center gap-1 text-[10px] font-bold text-[#7C3AED] bg-[#7C3AED]/5 border border-[#7C3AED]/10 px-2 py-0.5 rounded">
                                                <span className="material-icons text-[12px]">email</span>
                                                {template.email_template_name}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-5 py-2 text-xs font-bold text-slate-500 hover:bg-slate-100 rounded-lg transition-colors"
                    >
                        CANCEL
                    </button>
                    <button
                        onClick={handleSend}
                        disabled={isSending || !selectedTemplateId}
                        className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-black   rounded-lg shadow-lg shadow-indigo-200 transition-all flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {isSending ? (
                            <>
                                <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                SENDING...
                            </>
                        ) : (
                            <>
                                <span className="material-icons text-[14px]">send</span>
                                SEND NOW
                            </>
                        )}
                    </button>
                </div>
            </motion.div>
        </div>
    );
}

import React, { useState, useEffect } from "react";
import { BACKEND_URL } from "@/utils/api";

interface SendEmailModalProps {
    isOpen: boolean;
    onClose: () => void;
    candidateIds: string[];
    jobId?: string | null;
    token: string;
}

interface EmailTemplate {
    id: string;
    name: string;
    subject: string;
    body: string;
}

interface SenderContext {
    company_name?: string;
    recruiter_name?: string;
}

export default function SendEmailModal({ isOpen, onClose, candidateIds, jobId, token }: SendEmailModalProps) {
    const slug = "default"; // Added to fix "Cannot find name 'slug'" error
    const [templates, setTemplates] = useState<EmailTemplate[]>([]);
    const [selectedTemplateId, setSelectedTemplateId] = useState<string>("");
    const [subject, setSubject] = useState("");
    const [body, setBody] = useState("");
    const [isDrafting, setIsDrafting] = useState(false);
    const [isSending, setIsSending] = useState(false);

    // AI Inputs
    const [aiPurpose, setAiPurpose] = useState("schedule an interview");
    const [aiTone, setAiTone] = useState("professional");

    const [senderContext, setSenderContext] = useState<SenderContext | null>(null);
    const [customVars, setCustomVars] = useState<string[]>([]);
    const [customVarValues, setCustomVarValues] = useState<Record<string, string>>({});

    useEffect(() => {
        if (isOpen) {
            fetchTemplates();
            fetchSenderContext();
        }
    }, [isOpen, jobId]);

    // Extract variables
    useEffect(() => {
        const text = subject + " " + body;
        const regex = /\{\{([^}]+)\}\}/g;
        const found = new Set<string>();
        let match;
        while ((match = regex.exec(text)) !== null) {
            const varName = match[1].trim();
            // Filter out standard ones
            if (!["candidate_name", "job_title", "company_name", "recruiter_name", "name"].includes(varName)) {
                found.add(varName);
            }
        }
        setCustomVars(Array.from(found));
    }, [subject, body]);

    const fetchSenderContext = async () => {
        try {
            const url = new URL(`${BACKEND_URL}/api/v1/enterprise/communication/context`);
            if (jobId) url.searchParams.append("job_id", jobId);

            const res = await fetch(url.toString(), {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setSenderContext(data);

                // Pre-fill company name if missing in DB but user wants to override
                if (!data.company_name) {
                    setCustomVarValues(prev => ({ ...prev, "{{company_name}}": "" }));
                }
            }
        } catch (e) {
            console.error(e);
        }
    };

    const fetchTemplates = async () => {
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/templates`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setTemplates(data);
            }
        } catch (e) {
            console.error(e);
        }
    };

    const handleTemplateSelect = (id: string) => {
        setSelectedTemplateId(id);
        const t = templates.find(t => t.id === id);
        if (t) {
            setSubject(t.subject);
            setBody(t.body);
        } else {
            setSubject("");
            setBody("");
        }
    };

    const handleAiDraft = async () => {
        setIsDrafting(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/draft`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`,
                    "X-Tenant-Slug": slug
                },
                body: JSON.stringify({
                    purpose: aiPurpose,
                    tone: aiTone
                })
            });
            const data = await res.json();

            // Handle different variations of response (mock vs real)
            if (data.content) {
                try {
                    const parsed = JSON.parse(data.content);
                    setSubject(parsed.subject || "");
                    setBody(parsed.body || "");
                } catch (e) {
                    // If content is just string (not JSON)
                    setBody(data.content);
                }
            } else if (data.subject || data.body) {
                setSubject(data.subject || "");
                setBody(data.body || "");
            }

        } catch (e) {
            alert("Failed to draft email");
        } finally {
            setIsDrafting(false);
        }
    };

    const handleSend = async () => {
        setIsSending(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/communication/send`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`,
                    "X-Tenant-Slug": slug
                },
                body: JSON.stringify({
                    recipient_ids: candidateIds,
                    template_id: selectedTemplateId || null,
                    job_id: jobId || null,
                    subject: subject,
                    body: body,
                    custom_variables: customVarValues
                })
            });

            if (res.ok) {
                const result = await res.json();
                alert(result.message || "Emails sent successfully!");
                onClose();
            } else {
                alert("Failed to send emails.");
            }
        } catch (e) {
            alert("Error sending emails.");
        } finally {
            setIsSending(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={onClose}>
            <div className="bg-white rounded-2xl w-full max-w-2xl p-8 shadow-2xl flex flex-col max-h-[95vh]" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-6 shrink-0">
                    <h2 className="text-2xl font-black text-slate-800">EMAIL CAMPAIGN ({candidateIds.length})</h2>
                    <button onClick={onClose} className="p-2 hover:bg-slate-50 rounded-full text-slate-400 hover:text-slate-600 transition-colors">
                        <span className="material-icons-outlined">close</span>
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto [&::-webkit-scrollbar]:hidden [-ms-overflow-style:'none'] [scrollbar-width:'none']">

                    {/* Template Selection */}
                    <div className="mb-6">
                        <label className="block text-xs font-bold   text-slate-500 mb-2">Load Template</label>
                        <select
                            className="w-full p-3 border border-slate-200 rounded-xl text-slate-900 bg-white font-medium focus:ring-2 focus:ring-indigo-100 outline-none"
                            value={selectedTemplateId}
                            onChange={(e) => handleTemplateSelect(e.target.value)}
                        >
                            <option value="" className="text-slate-900 bg-white">-- Custom Email --</option>
                            {templates.map(t => (
                                <option key={t.id} value={t.id} className="text-slate-900 bg-white">{t.name}</option>
                            ))}
                        </select>
                    </div>

                    {/* AI Drafter - Only for Custom Emails */}
                    {!selectedTemplateId && (
                        <div className="mb-6 bg-indigo-50 p-4 rounded-xl border border-indigo-100 flex gap-3 items-center">
                            <div className="flex-1">
                                <input
                                    placeholder="Email purpose (e.g. Schedule and invite for technical interview)..."
                                    className="w-full p-2.5 rounded-lg border border-indigo-100 text-sm focus:ring-2 focus:ring-indigo-200 outline-none"
                                    value={aiPurpose}
                                    onChange={e => setAiPurpose(e.target.value)}
                                />
                            </div>
                            <button
                                onClick={handleAiDraft}
                                disabled={isDrafting}
                                className="bg-indigo-600 text-white px-4 py-2.5 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200"
                            >
                                {isDrafting ? <span className="animate-spin material-icons text-sm">refresh</span> : <span className="material-icons text-sm">auto_awesome</span>}
                                AI DRAFT
                            </button>
                        </div>
                    )}

                    {/* Content */}
                    <div className="space-y-4">
                        <input
                            className="w-full p-3 border border-slate-200 rounded-xl font-bold text-slate-800 placeholder:text-slate-400 focus:ring-2 focus:ring-indigo-100 outline-none"
                            placeholder="Subject Line"
                            value={subject}
                            onChange={e => setSubject(e.target.value)}
                        />
                        <textarea
                            className="w-full p-4 border border-slate-200 rounded-xl h-64 font-mono text-sm text-slate-600 placeholder:text-slate-400 focus:ring-2 focus:ring-indigo-100 outline-none resize-none"
                            placeholder="Write your email here... (Supports HTML)"
                            value={body}
                            onChange={e => setBody(e.target.value)}
                        />

                        {/* Variable Dashboard */}
                        <div className="bg-slate-50 border border-slate-200 rounded-xl p-4">
                            <h4 className="text-xs font-bold   text-slate-500 mb-3">Detected Variables</h4>

                            <div className="space-y-3">
                                {/* Standard Variables */}
                                <div className="grid grid-cols-2 gap-2 text-xs">
                                    <VariableStatus
                                        label="Candidate Name"
                                        code="{{candidate_name}}"
                                        status="Available"
                                        statusColor="text-green-600"
                                    />
                                    <VariableStatus
                                        label="Job Title"
                                        code="{{job_title}}"
                                        status="Auto-Detected"
                                        statusColor="text-green-600"
                                    />
                                    <VariableStatus
                                        label="Company Name"
                                        code="{{company_name}}"
                                        status={customVarValues["{{company_name}}"] ? "Overridden" : (senderContext?.company_name ? "Available" : "Missing")}
                                        statusColor={customVarValues["{{company_name}}"] ? "text-blue-600" : (senderContext?.company_name ? "text-green-600" : "text-red-500")}
                                    />
                                    <VariableStatus
                                        label="Recruiter Name"
                                        code="{{recruiter_name}}"
                                        status={customVarValues["{{recruiter_name}}"] ? "Overridden" : (senderContext?.recruiter_name ? "Available" : "Missing")}
                                        statusColor={customVarValues["{{recruiter_name}}"] ? "text-blue-600" : (senderContext?.recruiter_name ? "text-green-600" : "text-red-500")}
                                    />
                                </div>

                                {/* Custom/Missing Global Variables Input */}
                                {customVars.map(v => (
                                    <div key={v} className="flex items-center gap-3">
                                        <span className="bg-indigo-100 text-indigo-700 font-mono text-xs px-2 py-1 rounded">{`{{${v}}}`}</span>
                                        <input
                                            placeholder={`Value for ${v}...`}
                                            className="flex-1 p-2 border border-slate-200 rounded-lg text-sm outline-none focus:border-indigo-300"
                                            value={customVarValues[v] || ""}
                                            onChange={e => setCustomVarValues({ ...customVarValues, [v]: e.target.value })}
                                        />
                                    </div>
                                ))}
                                {/* Show input for missing global vars if needed */}
                                {!senderContext?.company_name && (
                                    <div className="flex items-center gap-3">
                                        <span className="bg-red-50 text-red-600 font-mono text-xs px-2 py-1 rounded">{"{{company_name}}"}</span>
                                        <input
                                            placeholder="Enter Company Name override..."
                                            className="flex-1 p-2 border border-red-200 rounded-lg text-sm outline-none focus:border-red-300"
                                            value={customVarValues["{{company_name}}"] || ""}
                                            onChange={e => setCustomVarValues({ ...customVarValues, "{{company_name}}": e.target.value })}
                                        />
                                    </div>
                                )}
                                {!senderContext?.recruiter_name && (
                                    <div className="flex items-center gap-3">
                                        <span className="bg-red-50 text-red-600 font-mono text-xs px-2 py-1 rounded">{"{{recruiter_name}}"}</span>
                                        <input
                                            placeholder="Enter Recruiter Name override..."
                                            className="flex-1 p-2 border border-red-200 rounded-lg text-sm outline-none focus:border-red-300"
                                            value={customVarValues["{{recruiter_name}}"] || ""}
                                            onChange={e => setCustomVarValues({ ...customVarValues, "{{recruiter_name}}": e.target.value })}
                                        />
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                </div>
                <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-slate-100 shrink-0">
                    <button onClick={onClose} className="px-6 py-3 font-bold text-slate-500 hover:bg-slate-50 rounded-xl transition-colors">CANCEL</button>
                    <button
                        onClick={handleSend}
                        disabled={isSending}
                        className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {isSending ? (
                            <>
                                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                SENDING...
                            </>
                        ) : (
                            <>
                                <span className="material-icons text-sm">send</span>
                                SEND EMAIL
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div >
    );
}

function VariableStatus({ label, code, status, statusColor }: { label: string, code: string, status: string, statusColor: string }) {
    return (
        <div className="flex items-center justify-between bg-white p-2 rounded border border-slate-100">
            <div className="flex flex-col">
                <span className="font-bold text-slate-700">{label}</span>
                <span className="font-mono text-[10px] text-slate-400">{code}</span>
            </div>
            <span className={`font-bold ${statusColor}`}>{status}</span>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { BACKEND_URL } from "@/utils/api";

interface OnboardingTemplate {
    id: string;
    name: string;
    description?: string;
}

interface SendOnboardingModalProps {
    isOpen: boolean;
    onClose: () => void;
    applicationIds: string[];
    token: string;
}

export default function SendOnboardingModal({ isOpen, onClose, applicationIds, token }: SendOnboardingModalProps) {
    const [templates, setTemplates] = useState<OnboardingTemplate[]>([]);
    const [selectedTemplateId, setSelectedTemplateId] = useState<string>("");
    const [isLoading, setIsLoading] = useState(false);
    const [isSending, setIsSending] = useState(false);

    useEffect(() => {
        if (isOpen && token) {
            fetchTemplates();
        }
    }, [isOpen, token]);

    const fetchTemplates = async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/templates/`, {
                headers: { "Authorization": `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setTemplates(data);
                if (data.length > 0) {
                    setSelectedTemplateId(data[0].id);
                }
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSend = async () => {
        if (!selectedTemplateId) return;
        setIsSending(true);
        let successCount = 0;
        try {
            // Check if there's a bulk endpoint, otherwise loop
            for (const id of applicationIds) {
                const res = await fetch(`${BACKEND_URL}/api/v1/enterprise/onboarding/initiate`, {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        "Authorization": `Bearer ${token}`
                    },
                    body: JSON.stringify({ 
                        application_id: id,
                        template_id: selectedTemplateId
                    })
                });
                if (res.ok) successCount++;
            }
            alert(`Onboarding initiated successfully for ${successCount} candidates!`);
            onClose();
            // Refresh parent state if needed (user might need to refresh manually or we can trigger a refresh)
            window.location.reload(); 
        } catch (e) {
            console.error(e);
            alert("Error initiating onboarding.");
        } finally {
            setIsSending(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4" onClick={onClose}>
            <motion.div
                initial={{ scale: 0.95, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.95, opacity: 0 }}
                className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden"
                onClick={e => e.stopPropagation()}
            >
                <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h2 className="text-lg font-black text-slate-800 tracking-tight flex items-center gap-2">
                        <span className="material-icons text-indigo-600">person_add</span>
                        INITIATE ONBOARDING
                    </h2>
                    <button onClick={onClose} className="w-8 h-8 rounded-full hover:bg-slate-200/50 flex items-center justify-center text-slate-400">
                        <span className="material-icons-outlined">close</span>
                    </button>
                </div>

                <div className="p-6">
                    <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl mb-6">
                        <p className="text-xs font-bold text-indigo-900 leading-relaxed">
                            Initiating onboarding for <span className="text-indigo-600">{applicationIds.length} candidate(s)</span>. 
                            Please select a template to use.
                        </p>
                    </div>

                    <label className="block text-[10px] font-black   text-slate-500 mb-2">Select Onboarding Template</label>
                    {isLoading ? (
                        <div className="py-4 flex justify-center">
                            <div className="w-6 h-6 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                        </div>
                    ) : templates.length === 0 ? (
                        <div className="py-4 text-center">
                            <p className="text-sm text-slate-400 font-medium">No templates found. Go to settings to create one.</p>
                        </div>
                    ) : (
                        <div className="space-y-3 max-h-60 overflow-y-auto pr-2">
                            {templates.map(template => (
                                <div
                                    key={template.id}
                                    onClick={() => setSelectedTemplateId(template.id)}
                                    className={`p-4 rounded-xl border-2 transition-all cursor-pointer ${
                                        selectedTemplateId === template.id
                                            ? "border-indigo-600 bg-indigo-50/50"
                                            : "border-slate-100 hover:border-slate-200"
                                    }`}
                                >
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{template.name}</h4>
                                            {template.description && (
                                                <p className="text-[10px] font-bold text-slate-400   mt-0.5">
                                                    {template.description}
                                                </p>
                                            )}
                                        </div>
                                        {selectedTemplateId === template.id && (
                                            <span className="material-icons text-indigo-600 text-sm">check_circle</span>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-5 py-2 text-xs font-bold text-slate-500 hover:bg-slate-100 rounded-lg transition-colors"
                    >
                        CANCEL
                    </button>
                    <button
                        onClick={handleSend}
                        disabled={isSending || !selectedTemplateId}
                        className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-black   rounded-lg shadow-lg shadow-indigo-200 transition-all flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {isSending ? (
                            <>
                                <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                INITIATING...
                            </>
                        ) : (
                            <>
                                <span className="material-icons text-[14px]">bolt</span>
                                INITIATE NOW
                            </>
                        )}
                    </button>
                </div>
            </motion.div>
        </div>
    );
}

