import { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface Option {
    value: number;
}

interface Question {
    id: number;
    text: string;
    target?: { type?: 'MATH' | 'PATTERN' };
    options: Option[];
    correct_index: number;
}

interface Answer {
    question_id: number;
    user_response: number;
    correct: boolean;
}

interface NumeroProps {
    questions: Question[];
    onComplete: (score: number, answers: Answer[]) => void;
}

const BG_COLORS = [
    'bg-[#A4437B]', // The purple/pink from the image
    'bg-[#5C4B99]', // Indigo/Purple
    'bg-[#3D8361]', // Green
    'bg-[#D65A31]', // Orange
    'bg-[#2C3333]', // Dark Grey
    'bg-[#0F4C75]', // Blue
];

export default function Numero({ questions, onComplete }: NumeroProps) {
    // Game Config
    const TOTAL_TIME = 120;

    // State
    const [started, setStarted] = useState(false);
    const [timeLeft, setTimeLeft] = useState(TOTAL_TIME);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [answers, setAnswers] = useState<Answer[]>([]);

    // Refs
    const containerRef = useRef<HTMLDivElement>(null);

    // Derived
    const currentQuestion = questions[currentIndex];
    const bgColor = BG_COLORS[currentIndex % BG_COLORS.length];

    useEffect(() => {
        if (started && timeLeft > 0) {
            const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
            return () => clearInterval(timer);
        } else if (timeLeft === 0 && started) {
            handleComplete();
        }
    }, [started, timeLeft]);

    const handleStart = async () => {
        const element = containerRef.current;
        if (element) {
            try {
                const el = element as HTMLElement & {
                    webkitRequestFullscreen?: () => Promise<void>;
                };
                if (el.requestFullscreen) {
                    await el.requestFullscreen();
                } else if (el.webkitRequestFullscreen) {
                    await el.webkitRequestFullscreen();
                }
            } catch (err) { console.error(err); }
        }
        setStarted(true);
    };

    const handleAnswer = (selectedVal: number) => {
        const correctIdx = currentQuestion.correct_index;
        const options = currentQuestion.options || [];
        const correctValue = options[correctIdx]?.value;
        const isCorrect = selectedVal === correctValue;

        const newAnswer: Answer = {
            question_id: currentQuestion.id,
            user_response: selectedVal,
            correct: isCorrect
        };

        const newAnswers = [...answers, newAnswer];
        setAnswers(newAnswers);

        if (currentIndex < questions.length - 1) {
            setCurrentIndex(prev => prev + 1);
        } else {
            handleComplete(newAnswers);
        }
    };

    const handleComplete = (finalAnswers?: Answer[]) => {
        const answersToSubmit = finalAnswers || answers;
        const correctCount = answersToSubmit.filter(a => a.correct).length;
        const total = questions.length || 1;
        const normalizedScore = (correctCount / total) * 10;

        onComplete(normalizedScore * 10, answersToSubmit);
    };

    if (!started) {
        return (
            <div ref={containerRef} className="fixed inset-0 z-[9999] bg-[#A4437B] flex items-center justify-center font-sans text-white">
                <div className="max-w-2xl text-center space-y-8 p-12">
                    <div className="w-24 h-24 bg-white/20 rounded-3xl mx-auto flex items-center justify-center shadow-lg backdrop-blur-sm">
                        <span className="material-icons-outlined text-5xl text-white">calculate</span>
                    </div>
                    <div className="space-y-2">
                        <h1 className="text-5xl font-black tracking-tight">NUMERICAL</h1>
                        <p className="text-xl text-white/80 max-w-lg mx-auto leading-relaxed font-medium">
                            Speed & Pattern Challenge
                        </p>
                    </div>

                    <button
                        onClick={handleStart}
                        className="px-12 py-5 bg-white text-[#A4437B] rounded-full text-lg font-black   hover:scale-105 transition-all shadow-xl shadow-black/20"
                    >
                        Start Game
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div ref={containerRef} className={`fixed inset-0 z-[9999] transition-colors duration-500 ease-out ${bgColor} flex flex-col font-sans text-white overflow-hidden`}>

            {/* Header */}
            <div className="flex items-center justify-between px-6 pt-8 pb-4">
                <button className="w-10 h-10 flex items-center justify-center rounded-full border-2 border-white/30 text-white/80 hover:bg-white/10 transition-colors">
                    <span className="material-icons-outlined text-xl">info</span>
                </button>

                <div className="px-6 py-2 bg-black/20 backdrop-blur-md rounded-full border border-white/10">
                    <span className="text-sm font-bold  opacity-90">
                        {String(currentIndex + 1).padStart(2, '0')}/{String(questions.length).padStart(2, '0')}
                    </span>
                </div>

                <div className="px-6 py-2 bg-white rounded-full flex items-center gap-2 shadow-lg">
                    <span className="material-icons-outlined text-rose-500 text-lg">timer</span>
                    <span className="text-rose-500 font-bold font-mono text-lg">
                        {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
                    </span>
                </div>
            </div>

            <div className="text-center pb-4">
                <h2 className="text-lg font-bold text-white/90 drop-shadow-md">
                    {currentQuestion.target?.type === 'PATTERN' ? 'Complete the Pattern' : 'Solve the Equation'}
                </h2>
            </div>

            {/* Main Game Area */}
            <div className="flex-1 flex flex-col items-center justify-center p-6 relative max-w-md mx-auto w-full space-y-8">

                <AnimatePresence mode='wait'>
                    <motion.div
                        key={currentIndex}
                        initial={{ opacity: 0, scale: 0.9, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: -20 }}
                        transition={{ duration: 0.2 }} // Faster transition
                        className="w-full space-y-8 relative"
                    >
                        {/* Question "Card" */}
                        <div className="relative aspect-square md:aspect-video w-full bg-white/20 backdrop-blur-md rounded-[2.5rem] flex flex-col items-center justify-center border-2 border-white/30 shadow-2xl shadow-black/10 p-8 overflow-hidden">
                            <div className="text-center space-y-2">
                                <span className="text-xs font-black  tracking-[0.2em] text-white/60">Problem</span>
                                <div className="text-5xl md:text-6xl font-black text-white drop-shadow-lg leading-tight break-words word-break">
                                    {currentQuestion.text}
                                </div>
                            </div>

                            <div className="absolute -bottom-6 left-1/2 -translate-x-1/2">
                                <button
                                    onClick={() => handleAnswer(-99999)}
                                    className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-lg hover:scale-110 active:scale-95 transition-all text-[#A4437B]"
                                >
                                    <span className="material-icons-outlined text-2xl font-bold">close</span>
                                </button>
                            </div>
                        </div>

                        {/* Options Grid */}
                        <div className="grid grid-cols-2 gap-4 mt-8">
                            {(currentQuestion.options || []).map((opt, idx: number) => (
                                <button
                                    key={idx}
                                    onClick={() => handleAnswer(opt.value)}
                                    className="h-24 rounded-2xl bg-white/20 border-2 border-white/20 hover:bg-white/30 hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center backdrop-blur-sm shadow-lg shadow-black/5 group"
                                >
                                    <span className="text-3xl font-black text-white group-hover:text-white drop-shadow-md">
                                        {opt.value}
                                    </span>
                                </button>
                            ))}
                        </div>

                    </motion.div>
                </AnimatePresence>

            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface Pipe {
    r: number;
    c: number;
    type: 'STRAIGHT' | 'CURVE' | 'EMPTY';
    rotation: number; // 0, 90, 180, 270
    isFixed?: boolean;
    nodeType: 'START' | 'END' | 'PIPE';
    isActive?: boolean;
}

interface PipelinePuzzleProps {
    level: {
        text: string;
        grid: Pipe[];
        rows: number;
        cols: number;
    };
    onComplete: (score: number) => void;
}

const PipelinePuzzle: React.FC<PipelinePuzzleProps> = ({ level, onComplete }) => {
    const [grid, setGrid] = useState<Pipe[]>([]);
    const [isWon, setIsWon] = useState(false);
    const [moves, setMoves] = useState(0);

    // Initialize grid when level changes
    useEffect(() => {
        if (level && level.grid) {
            const initialGrid = level.grid.map(p => ({
                ...p,
                // Ensure Start/End nodes are always rotatable in the frontend
                isFixed: p.nodeType === 'PIPE' ? p.isFixed : false
            }));
            setTimeout(() => setGrid(initialGrid), 0);
        }
    }, [level]);

    // Connection Ports mapping based on type and rotation
    const getPorts = useCallback((pipe: Pipe) => {
        const r = pipe.rotation % 360;

        // Start and End nodes always have exactly ONE connection point
        if (pipe.nodeType !== 'PIPE') {
            if (r === 0) return ['top'];
            if (r === 90) return ['right'];
            if (r === 180) return ['bottom'];
            if (r === 270) return ['left'];
        }

        if (pipe.type === 'STRAIGHT') {
            return r === 0 || r === 180 ? ['top', 'bottom'] : ['left', 'right'];
        }
        if (pipe.type === 'CURVE') {
            if (r === 0) return ['top', 'right'];
            if (r === 90) return ['right', 'bottom'];
            if (r === 180) return ['bottom', 'left'];
            if (r === 270) return ['left', 'top'];
        }
        return [];
    }, []);

    // Pathfinding to determine which pipes are active (derived state)
    const activeGrid = useMemo(() => {
        if (grid.length === 0) return [];

        const startNode = grid.find(p => p.nodeType === 'START');
        if (!startNode) return grid.map(p => ({ ...p, isActive: false }));

        const activeSet = new Set<string>();
        const queue: Pipe[] = [startNode];
        const visited = new Set<string>();

        while (queue.length > 0) {
            const curr = queue.shift()!;
            const key = `${curr.r},${curr.c}`;
            if (visited.has(key)) continue;
            visited.add(key);
            activeSet.add(key);

            const currPorts = getPorts(curr);

            // Check neighbors
            const neighbors = [
                { r: curr.r - 1, c: curr.c, port: 'top', opposite: 'bottom' },
                { r: curr.r + 1, c: curr.c, port: 'bottom', opposite: 'top' },
                { r: curr.r, c: curr.c - 1, port: 'left', opposite: 'right' },
                { r: curr.r, c: curr.c + 1, port: 'right', opposite: 'left' },
            ];

            for (const n of neighbors) {
                if (currPorts.includes(n.port)) {
                    const neighborNode = grid.find(p => p.r === n.r && p.c === n.c);
                    if (neighborNode) {
                        const nPorts = getPorts(neighborNode);
                        if (nPorts.includes(n.opposite)) {
                            queue.push(neighborNode);
                        }
                    }
                }
            }
        }

        return grid.map(p => ({
            ...p,
            isActive: activeSet.has(`${p.r},${p.c}`)
        }));
    }, [grid, getPorts]);

    // Check win condition based on derived state
    useEffect(() => {
        const endNode = activeGrid.find(p => p.nodeType === 'END');
        if (endNode?.isActive && !isWon) {
            setTimeout(() => {
                setIsWon(true);
            }, 0);
            const finalScore = Math.max(1, 10 - Math.floor(moves / 5));
            const timer = setTimeout(() => onComplete(finalScore), 2000);
            return () => clearTimeout(timer);
        }
    }, [activeGrid, isWon, moves, onComplete]);

    const handleRotate = (r: number, c: number) => {
        if (isWon) return;
        setGrid(prev => prev.map(p => {
            if (p.r === r && p.c === c && !p.isFixed) {
                return { ...p, rotation: (p.rotation + 90) % 360 };
            }
            return p;
        }));
        setMoves(m => m + 1);
    };

    return (
        <div className="relative w-full min-h-screen flex flex-col items-center justify-center bg-[#0a0a1a] overflow-hidden font-sans p-6 text-white">
            {/* Background Atmosphere */}
            <div className="absolute inset-0 overflow-hidden opacity-10">
                <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-teal-600/20 blur-[120px] rounded-full animate-pulse" />
                <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-emerald-600/20 blur-[120px] rounded-full animate-pulse gap-delay-2000" />
            </div>

            {/* HUD Header */}
            <div className="relative z-10 p-8 text-center">
                <motion.div
                    initial={{ opacity: 0, y: -20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="inline-block px-4 py-1 rounded-full bg-teal-500/10 border border-teal-500/20 text-teal-400 text-[9px] font-black  tracking-[0.3em] mb-4"
                >
                    Bio-Link Calibration
                </motion.div>
                <h1 className="text-4xl font-black text-white  tracking-tighter mb-2 ">
                    Neural <span className="text-teal-400">Flow</span>
                </h1>
                <p className="text-slate-400 text-[11px] max-w-sm mx-auto font-bold   opacity-60">
                    {level.text}
                </p>
            </div>

            {/* Grid Area - Wrapped for centering */}
            <div className="flex-1 flex items-center justify-center w-full z-10 px-4">
                <div
                    className="p-5 rounded-[2.5rem] bg-slate-900/60 border border-white/5 backdrop-blur-3xl shadow-2xl"
                    style={{
                        display: 'grid',
                        gridTemplateColumns: `repeat(${level.cols || 6}, clamp(40px, 10vmin, 60px))`,
                        gridTemplateRows: `repeat(${level.rows || 6}, clamp(40px, 10vmin, 60px))`,
                        gap: '12px'
                    }}
                >
                    {activeGrid.map((pipe) => (
                        <motion.div
                            key={`${pipe.r}-${pipe.c}`}
                            whileHover={!pipe.isFixed && !isWon ? { scale: 1.05, zIndex: 10 } : {}}
                            whileTap={!pipe.isFixed && !isWon ? { scale: 0.95 } : {}}
                            onClick={() => handleRotate(pipe.r, pipe.c)}
                            className={`relative w-full aspect-square rounded-lg border transition-all duration-300 cursor-pointer overflow-hidden
                                ${pipe.nodeType !== 'PIPE' ? 'bg-[#3d4451] border-white/10' : 'bg-[#4fd1c5] border-[#4fd1c5]'}
                                ${pipe.isActive && pipe.nodeType === 'PIPE' ? 'shadow-[0_0_15px_rgba(255,255,255,0.3)]' : ''}
                            `}
                        >
                            <motion.svg
                                viewBox="0 0 100 100"
                                animate={{ rotate: pipe.rotation }}
                                transition={{ type: 'spring', stiffness: 260, damping: 20 }}
                                className="w-full h-full"
                            >
                                {/* SVG Pipe Definitions centered in the lane */}
                                {pipe.nodeType === 'PIPE' ? (
                                    <>
                                        {pipe.type === 'STRAIGHT' && (
                                            <line
                                                x1="50" y1="0" x2="50" y2="100"
                                                stroke="white"
                                                strokeWidth="28"
                                                strokeLinecap="butt"
                                                className={`transition-all duration-500 ${pipe.isActive ? 'stroke-[34] opacity-100' : 'opacity-80'}`}
                                            />
                                        )}
                                        {pipe.type === 'CURVE' && (
                                            <path
                                                d="M 50 0 L 50 50 L 100 50"
                                                fill="none"
                                                stroke="white"
                                                strokeWidth="28"
                                                strokeLinejoin="round"
                                                strokeLinecap="round"
                                                className={`transition-all duration-500 ${pipe.isActive ? 'stroke-[34] opacity-100' : 'opacity-80'}`}
                                            />
                                        )}
                                    </>
                                ) : (
                                    <>
                                        {/* Terminal Node: Exactly one connection stub */}
                                        <line
                                            x1="50" y1="0" x2="50" y2="50"
                                            stroke="white"
                                            strokeWidth="28"
                                            strokeLinecap="butt"
                                            className={`transition-all duration-500 ${pipe.isActive ? 'stroke-[34] opacity-100' : 'opacity-80'}`}
                                        />
                                        <circle cx="50" cy="50" r="22" fill="white" className="drop-shadow-sm" />
                                    </>
                                )}
                            </motion.svg>

                            {/* Glow effect for active pipes */}
                            {pipe.isActive && (
                                <motion.div
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: [0.1, 0.3, 0.1] }}
                                    transition={{ duration: 2, repeat: Infinity }}
                                    className="absolute inset-0 bg-white pointer-events-none"
                                />
                            )}
                        </motion.div>
                    ))}
                </div>
            </div>

            {/* HUD Footer */}
            <div className="relative z-10 pb-12 flex gap-12 items-center">
                <div className="text-center">
                    <span className="text-[9px] font-black text-slate-500  tracking-[0.3em] mb-1 block">Entropy_Moves</span>
                    <span className="text-2xl font-black text-white  leading-none">{moves}</span>
                </div>
                <div className="w-px h-8 bg-white/10" />
                <div className="text-center">
                    <span className="text-[9px] font-black text-slate-500  tracking-[0.3em] mb-1 block">Link_Stability</span>
