};

export default PipelinePuzzle;

import { useEffect, useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { exitFullScreen } from '@/utils/fullscreen';
import { motion } from 'framer-motion';

interface FeedbackData {
    overallScore: number;
    maxScore: number;
    status: string;
    role: string;
    submittedOn: string;
    timeTaken: string;
    summary: string;
    skills: { name: string; score: number; feedback: string }[];
    niceToHave: { name: string; score: number; feedback: string }[];
    integrityScore: number;
    offTabActivity: number;
}

interface BackendResults {
    overall_score?: number;
    detailed_feedback?: string;
    strengths?: string[];
    weaknesses?: string[];
}

interface InterviewFeedbackProps {
    transcript?: { role: 'ai' | 'user'; text: string }[];
    offTabCount?: number;
    isSaving?: boolean;
    backendResults?: BackendResults;
}

const DonutChart = ({ score, max, color = "text-slate-900", size = 60, strokeWidth = 6 }: { score: number, max: number, color?: string, size?: number, strokeWidth?: number }) => {
    const radius = (size - strokeWidth) / 2;
    const circumference = radius * 2 * Math.PI;
    const progress = (score / max) * circumference;

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg width={size} height={size} className="transform -rotate-90">
                <circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    fill="transparent"
                    className="stroke-slate-200 dark:stroke-slate-700"
                    strokeWidth={strokeWidth}
                />
                <motion.circle
                    initial={{ strokeDashoffset: circumference }}
                    animate={{ strokeDashoffset: circumference - progress }}
                    transition={{ duration: 1, ease: "easeOut" }}
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    fill="transparent"
                    className={`${color} stroke-current`}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeLinecap="round"
                />
            </svg>
            <span className="absolute text-[10px] font-black text-slate-900">
                {score}
            </span>
        </div>
    );
};

const BellCurve = ({ percentile }: { percentile: number }) => {
    return (
        <div className="relative h-32 w-full flex items-end justify-center">
            <div className="absolute inset-x-0 bottom-0 h-32 flex items-end opacity-20">
                <svg viewBox="0 0 100 50" preserveAspectRatio="none" className="w-full h-full fill-slate-300">
                    <path d="M0,50 Q25,50 35,30 T50,5 T65,30 T100,50 Z" />
                </svg>
            </div>

            <div className="w-full h-full flex items-end relative overflow-hidden">
                <div className="w-1/3 h-full border-r border-dashed border-slate-300 relative group">
                    <div className="absolute bottom-2 left-1/2 -translate-x-1/2 text-[10px] text-slate-400 font-bold  tracking-tighter">Low</div>
                </div>
                <div className="w-1/3 h-full border-r border-dashed border-slate-300 relative group bg-slate-100">
                    <div className="absolute bottom-2 left-1/2 -translate-x-1/2 text-[10px] text-slate-400 font-bold  tracking-tighter">Average</div>
                </div>
                <div className="w-1/3 h-full relative group bg-slate-200">
                    <div className="absolute bottom-2 left-1/2 -translate-x-1/2 text-[10px] text-slate-400 font-bold  tracking-tighter">High</div>
                </div>

                <motion.div
                    initial={{ opacity: 0, scale: 0, left: '50%' }}
                    animate={{ opacity: 1, scale: 1, left: `${Math.max(5, Math.min(95, percentile))}%` }}
                    transition={{ delay: 0.5, duration: 1.2, ease: "backOut" }}
                    className="absolute bottom-16 w-5 h-5 bg-slate-900 rounded-full border-2 border-white shadow-xl -translate-x-1/2 flex items-center justify-center"
                >
                    <div className="w-1 h-1 bg-white rounded-full animate-ping"></div>
                </motion.div>
            </div>
        </div>
    );
};

export default function InterviewFeedback({
    transcript = [],
    offTabCount = 0,
    isSaving = false,
    backendResults = undefined
}: InterviewFeedbackProps) {
    const router = useRouter();

    const feedback = useMemo<FeedbackData | null>(() => {
        // PRIORITIZE BACKEND RESULTS
        if (backendResults) {
            return {
                overallScore: backendResults.overall_score || 0,
                maxScore: 100,
                status: (backendResults.overall_score || 0) >= 80 ? "Recommended" : (backendResults.overall_score || 0) >= 50 ? "Average" : "Not Recommended",
                role: "Software Engineer",
                submittedOn: new Date().toLocaleString(),
                timeTaken: "10 minutes",
                summary: backendResults.detailed_feedback || "Analysis completed successfully.",
                skills: (backendResults.strengths || []).map((s: string) => ({ name: s, score: 9, feedback: "Strategic strength identified." })),
                niceToHave: (backendResults.weaknesses || []).map((w: string) => ({ name: w, score: 6, feedback: "Area for growth." })),
                integrityScore: Math.max(0, 100 - (offTabCount * 25)),
                offTabActivity: offTabCount
            };
        }

        if (!transcript || transcript.length === 0) {
            return {
                overallScore: 0,
                maxScore: 10,
                status: "Not Attempted",
                role: "Software Engineer",
                submittedOn: new Date().toLocaleString(),
                timeTaken: "0 minutes",
                summary: "No interview data was recorded.",
                skills: [],
                niceToHave: [],
                integrityScore: 100,
                offTabActivity: 0
            };
        }

        const qaPairs: { question: string; answer: string }[] = [];
        let lastQuestion = "";
        transcript.forEach((msg) => {
            if (msg.role === 'ai') {
                if (!msg.text.includes("steady") && !msg.text.includes("focused")) {
                    lastQuestion = msg.text;
                }
            } else if (msg.role === 'user') {
                qaPairs.push({
                    question: lastQuestion || "General Introduction",
                    answer: msg.text
                });
            }
        });

        const aiQuestions = transcript.filter(m =>
            m.role === 'ai' &&
            !m.text.includes("steady") &&
            !m.text.includes("focused") &&
            m.text.length > 20
        );

        const questionScores = aiQuestions.map(q => {
            const pair = qaPairs.find(p => p.question === q.text);
            const answer = pair ? pair.answer : "";
            const words = answer.trim().split(/\s+/).filter(w => w.length > 0);
            const count = words.length;

            let score = 0;
            if (count === 0) score = 0;
            else if (count < 5) score = 2.0;
            else if (count < 15) score = 4.5;
            else if (count < 30) score = 7.0;
            else score = 9.5;

            let category = "General Communication";
            const lowerQ = q.text.toLowerCase();
            if (lowerQ.includes("project") || lowerQ.includes("technical") || lowerQ.includes("code") || lowerQ.includes("experience")) {
                if (!lowerQ.includes("hello") && !lowerQ.includes("welcome")) {
                    category = "Technical Depth";
                }
            }
            if (lowerQ.includes("challenge") || lowerQ.includes("problem") || lowerQ.includes("solve")) category = "Problem Solving";
            if (lowerQ.includes("team") || lowerQ.includes("conflict") || lowerQ.includes("behavioral")) category = "Behavioral &amp; Ethics";

            return { name: category, score, answerLength: count };
        });

        const uniqueSkillsMap = new Map<string, { scores: number[] }>();
        questionScores.forEach(s => {
            const existing = uniqueSkillsMap.get(s.name) || { scores: [] };
            uniqueSkillsMap.set(s.name, { scores: [...existing.scores, s.score] });
        });

        const finalSkills = Array.from(uniqueSkillsMap.entries()).map(([name, data]) => {
            const avg = data.scores.reduce((a, b) => a + b, 0) / data.scores.length;
            let feedbackText = "Detailed and well-articulated.";
            if (avg === 0) feedbackText = "No response was recorded.";
            else if (avg < 4) feedbackText = "Answers were too brief.";
            else if (avg < 7) feedbackText = "Clear communication but lacked depth.";

            return {
                name,
                score: Math.round(avg * 10) / 10,
                feedback: feedbackText
            };
        });

        const hasEngagement = questionScores.some(s => s.answerLength > 0);
        const overallRaw = finalSkills.length > 0 ? finalSkills.reduce((a, b) => a + b.score, 0) / finalSkills.length : 0;
        const overallScore = hasEngagement ? Math.round(overallRaw * 10) / 10 : 0;
        const integrityScore = Math.max(0, 100 - (offTabCount * 25));

        return {
            overallScore,
            maxScore: 10,
            status: !hasEngagement ? "N/A" : overallScore >= 7 ? "Recommended" : overallScore >= 5 ? "Average" : "Not Recommended",
            role: "Software Engineer",
            submittedOn: new Date().toLocaleString(),
            timeTaken: "10 minutes",
            summary: "Analysis completed.",
            skills: finalSkills,
            niceToHave: hasEngagement ? [
                { name: "Resilience", score: Math.round(overallScore * 0.9 * 10) / 10, feedback: "Handled pressure well." },
                { name: "Cultural Fit", score: 8.5, feedback: "Professional etiquette." }
            ] : [],
            integrityScore,
            offTabActivity: offTabCount
        };
    }, [transcript, offTabCount, backendResults]);


    if (isSaving || !feedback) return (
        <div className="fixed inset-0 bg-white flex items-center justify-center flex-col gap-4">
            <div className="w-12 h-12 border-4 border-slate-200 border-t-slate-800 rounded-full animate-spin"></div>
            <p className="text-slate-500 font-black   text-[10px]">
                {isSaving ? "Finalizing & Saving Interview Analysis..." : "Generating accurate analysis..."}
            </p>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50/50 dark:bg-black p-4 md:p-6 font-sans overflow-x-hidden">
            <div className="max-w-6xl mx-auto space-y-6">

                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col md:flex-row justify-between gap-6"
                >
                    <div className="space-y-3">
                        <div className="space-y-1">
                            <h1 className="text-2xl font-black text-slate-900  tracking-tight">Analysis Report</h1>
                            <p className="text-[10px] font-bold text-slate-400  ">Candidate_ID: TAL-8293</p>
                        </div>
                        <div className="flex flex-wrap gap-4 text-xs text-slate-500">
                            <div className="flex items-center gap-2">
                                <span className="material-symbols-rounded text-lg">calendar_today</span>
                                {feedback.submittedOn}
                            </div>
                            <div className="flex items-center gap-2">
                                <span className="material-symbols-rounded text-lg">timer</span>
                                {feedback.timeTaken}
                            </div>
                        </div>
                    </div>

                    <div className="flex flex-col items-end gap-3">
                        <div className="flex items-center gap-4 bg-slate-50 px-4 py-3 rounded-2xl border border-slate-100">
                            <div className="flex items-baseline gap-1">
                                <span className="text-3xl font-black text-slate-900">{feedback.overallScore}</span>
                                <span className="text-slate-400 font-bold mb-1">/10</span>
                            </div>
                            <div className="text-right">
                                <div className="flex items-center gap-2 font-black text-[11px]   mb-1 text-slate-900">
                                    <span className="material-symbols-rounded text-sm">stars</span>
                                    {feedback.status}
                                </div>
                                <div className="text-[9px] text-slate-400 font-bold   font-mono">{feedback.role}</div>
                            </div>
                        </div>
                    </div>
                </motion.div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: 0.2 }}
                        className="lg:col-span-2 bg-white rounded-3xl p-6 border border-slate-200 shadow-sm"
                    >
                        <h2 className="text-sm font-black text-slate-900   mb-4 border-b border-slate-100 pb-3">Performance_Insights</h2>
                        <div className="flex flex-col md:flex-row gap-6 items-center">
                            <div className="w-full md:w-1/2">
                                <BellCurve percentile={feedback.overallScore * 10} />
                            </div>
                            <div className="w-full md:w-1/2 text-[11px] font-medium leading-relaxed text-slate-500 bg-slate-50 p-4 rounded-2xl border border-slate-100 ">
                                <span className="material-symbols-rounded text-slate-400 mr-2 align-bottom text-base">psychology</span>
                                {feedback.summary}
                            </div>
                        </div>
                    </motion.div>

                    <motion.div
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: 0.3 }}
                        className="bg-white rounded-3xl p-6 border border-slate-200 shadow-sm flex flex-col justify-between"
                    >
                        <div>
                            <h2 className="text-sm font-black text-slate-900   mb-4">Integrity_Panel</h2>
                            <div className="space-y-3">
                                <div className="flex items-center justify-between p-3 rounded-2xl bg-slate-50">
                                    <span className="text-slate-400 text-[10px] font-black  ">Integrity Score</span>
                                    <span className="font-black text-slate-900">
                                        {feedback.integrityScore}%
                                    </span>
                                </div>
                                <div className="flex items-center justify-between p-3 border border-slate-100 dark:border-slate-800 rounded-2xl">
                                    <span className="text-slate-500 text-sm">Window Switches</span>
                                    <span className={`font-bold ${feedback.offTabActivity > 0 ? 'text-red-500' : 'text-slate-900 dark:text-white'}`}>
                                        {feedback.offTabActivity}
                                    </span>
                                </div>
                            </div>
                        </div>
                        <button
                            onClick={() => {
                                exitFullScreen();
                                router.push('/practice/interviews');
                            }}
                            className="w-full mt-6 bg-slate-900 text-white py-3 rounded-xl font-black  tracking-[0.2em] text-[10px] hover:bg-black transition-all shadow-lg active:scale-95 flex items-center justify-center gap-2"
                        >
                            Finalize_Session
                        </button>
                    </motion.div>
                </div>

                <div className="space-y-4">
                    <h2 className="text-lg font-black text-slate-900  tracking-tight ml-2">Competency Breakdown</h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {feedback.skills.map((skill, idx) => (
                            <motion.div
                                key={idx}
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                transition={{ delay: 0.1 * idx }}
                                className="bg-white p-4 rounded-3xl border border-slate-200 shadow-sm hover:border-slate-900 transition-colors group"
                            >
                                <div className="flex items-start justify-between mb-3">
                                    <div className="p-2.5 bg-slate-50 rounded-2xl text-slate-400 group-hover:bg-slate-900 group-hover:text-white transition-all">
                                        <span className="material-symbols-rounded">analytics</span>
                                    </div>
                                    <DonutChart score={skill.score} max={10} color="stroke-slate-900" />
                                </div>
                                <h3 className="font-black text-[11px] text-slate-900  tracking-tight mb-1">{skill.name}</h3>
                                <p className="text-[10px] text-slate-400 font-medium line-clamp-3 leading-relaxed ">
                                    {skill.feedback}
                                </p>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';

interface InterviewLobbyProps {
    onJoin: () => void;
    mediaState: {
        stream: MediaStream | null;
        setStream: (stream: MediaStream | null) => void;
        isMicEnabled: boolean;
        setIsMicEnabled: (val: boolean) => void;
        isCameraEnabled: boolean;
        setIsCameraEnabled: (val: boolean) => void;
    };
}

export default function InterviewLobby({ onJoin, mediaState }: InterviewLobbyProps) {
    const videoRef = useRef<HTMLVideoElement>(null);
    const [hasPermissions, setHasPermissions] = useState<boolean>(false);
    const [micLevel, setMicLevel] = useState<number>(0);
    const [hasMicActivity, setHasMicActivity] = useState<boolean>(false);
    const audioContextRef = useRef<AudioContext | null>(null);
    const analyserRef = useRef<AnalyserNode | null>(null);
    const animationFrameRef = useRef<number | null>(null);

    useEffect(() => {
        const initMedia = async () => {
            if (mediaState.stream) {
                setHasPermissions(true);
                return;
            }

            try {
                const stream = await navigator.mediaDevices.getUserMedia({
                    video: true,
                    audio: true
                });
                mediaState.setStream(stream);
                setHasPermissions(true);
            } catch (err) {
                console.error("Error accessing media devices:", err);
                setHasPermissions(false);
            }
        };

        const timer = setTimeout(() => {
            initMedia();
        }, 500);

        return () => clearTimeout(timer);
    }, [mediaState.stream]);

    useEffect(() => {
        if (videoRef.current && mediaState.stream) {
            videoRef.current.srcObject = mediaState.stream;
        }
    }, [mediaState.stream]);

    useEffect(() => {
        if (mediaState.stream) {
            mediaState.stream.getAudioTracks().forEach(track => {
                track.enabled = mediaState.isMicEnabled;
            });
            mediaState.stream.getVideoTracks().forEach(track => {
                track.enabled = mediaState.isCameraEnabled;
            });

            // Audio Visualization logic
            if (mediaState.isMicEnabled) {
                if (!audioContextRef.current) {
                    audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
                }
                const audioContext = audioContextRef.current;
                const source = audioContext.createMediaStreamSource(mediaState.stream);
                const analyser = audioContext.createAnalyser();
                analyser.fftSize = 256;
                source.connect(analyser);
                analyserRef.current = analyser;

                const bufferLength = analyser.frequencyBinCount;
                const dataArray = new Uint8Array(bufferLength);

                const updateLevel = () => {
                    if (!analyserRef.current) return;
                    analyserRef.current.getByteFrequencyData(dataArray);

                    let sum = 0;
                    for (let i = 0; i < bufferLength; i++) {
                        sum += dataArray[i];
                    }
                    const average = sum / bufferLength;
                    const level = Math.min(100, Math.round((average / 128) * 100));
                    setMicLevel(level);
                    if (level > 10) setHasMicActivity(true);

                    animationFrameRef.current = requestAnimationFrame(updateLevel);
                };

                updateLevel();
            } else {
                setTimeout(() => setMicLevel(0), 0);
                if (animationFrameRef.current) {
                    cancelAnimationFrame(animationFrameRef.current);
                }
            }
        }

        return () => {
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
            if (audioContextRef.current) {
                audioContextRef.current.close();
                audioContextRef.current = null;
            }
        };
    }, [mediaState.isMicEnabled, mediaState.isCameraEnabled, mediaState.stream]);

    return (
        <div className="min-h-screen bg-black text-white py-8 px-4 flex items-center justify-center transition-colors duration-300">
            <div className="max-w-4xl w-full grid grid-cols-1 lg:grid-cols-2 gap-8 items-center">

                {/* Left Side: Video Preview */}
                <div className="space-y-4">
                    <div className="relative aspect-video bg-slate-900 rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/5">
                        {!mediaState.isCameraEnabled && (
                            <div className="absolute inset-0 flex items-center justify-center bg-slate-900 z-10">
                                <div className="text-center">
                                    <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
                                        <span className="material-symbols-rounded text-3xl text-slate-500 font-bold">videocam_off</span>
                                    </div>
                                    <p className="text-slate-500 text-[10px] font-black  ">Camera_Disabled</p>
                                </div>
                            </div>
                        )}
                        <video
                            ref={videoRef}
                            autoPlay
                            muted
                            playsInline
                            className={`w-full h-full object-cover transform scale-x-[-1] transition-opacity duration-500 ${!mediaState.isCameraEnabled ? 'opacity-0' : 'opacity-100'}`}
                        />

                        {/* Control Overlays */}
                        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 px-6 py-3 bg-black/40 backdrop-blur-xl rounded-2xl border border-white/10 z-20">
                            <button
                                onClick={() => mediaState.setIsMicEnabled(!mediaState.isMicEnabled)}
                                className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${mediaState.isMicEnabled ? 'bg-white/10 text-white hover:bg-white/20' : 'bg-white text-slate-900'}`}
                            >
                                <span className="material-symbols-rounded text-xl">
                                    {mediaState.isMicEnabled ? 'mic' : 'mic_off'}
                                </span>
                            </button>
                            <button
                                onClick={() => mediaState.setIsCameraEnabled(!mediaState.isCameraEnabled)}
                                className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${mediaState.isCameraEnabled ? 'bg-white/10 text-white hover:bg-white/20' : 'bg-white text-slate-900'}`}
                            >
                                <span className="material-symbols-rounded text-xl">
                                    {mediaState.isCameraEnabled ? 'videocam' : 'videocam_off'}
                                </span>
                            </button>
                        </div>

                        {/* Mic Level Indicator Overlay */}
                        {mediaState.isMicEnabled && (
                            <div className="absolute bottom-4 left-4 right-4 h-1 bg-white/10 rounded-full overflow-hidden z-20 pointer-events-none">
                                <div
                                    className="h-full bg-white transition-all duration-75"
                                    style={{ width: `${micLevel}%` }}
                                />
                            </div>
                        )}
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="space-y-3">
                        <h1 className="text-3xl font-black text-white  tracking-tight leading-tight">
                            Check your <span className="text-slate-400 ">setup</span> before we begin
                        </h1>
                        <p className="text-slate-500 text-xs font-medium leading-relaxed">
                            Ensure your face is clearly visible and your microphone is picking up your voice clearly.
                        </p>
                    </div>

                    <div className="bg-slate-900/50 backdrop-blur-xl rounded-[2.5rem] p-8 border border-white/10 shadow-2xl space-y-4">
                        <div className={`flex items-center gap-4 text-[10px] font-black   p-4 rounded-2xl transition-all border ${!mediaState.isCameraEnabled ? 'bg-white/5 text-slate-400 border-white/10' :
                            !hasMicActivity ? 'bg-white/5 text-slate-400 border-white/10' :
                                'bg-white text-slate-900 border-white font-black'
                            }`}>
                            <span className="material-symbols-rounded text-xl">
                                {!mediaState.isCameraEnabled ? 'warning' : !hasMicActivity ? 'record_voice_over' : 'verified'}
                            </span>
                            {!mediaState.isCameraEnabled ? "Please turn on your camera" :
                                !hasMicActivity ? "Please say something to test mic" :
                                    "Hardware diagnostics passed"}
                        </div>

                        <div className="space-y-3">
                            <button
